window.PLANT_DATA = [{"id":1,"zh":"无油樟","en":"Amborella trichopoda","sci":"Amborella trichopoda","order_en":"Amborellales","order_zh":"无油樟目","family_en":"Amborellaceae","family_zh":"无油樟科","iucn":"LC","langs":38,"desc_zh":"无油樟（学名：Amborella trichopoda）又名互叶梅，自成一目、一科、一属，只生长在新喀里多尼亚，是一种孑遗植物。 无油樟是现存被子植物中已知最早和其它被子植物分开演化的，因而倍受植物学家注目。","desc_en":"Amborella is a monotypic genus of understory shrubs or small trees endemic to the main island, Grande Terre, of New Caledonia in the southwest Pacific Ocean.","img":"images/1.jpg","thumb":"images/t/1.jpg","file":"Amborella trichopoda 1.jpg","ar":1.311,"py":"wuyouzhang wyz","cr_by":"Stan Shebs","cr_lic":"CC BY-SA 3.0","cr_licurl":"https://creativecommons.org/licenses/by-sa/3.0","habit":"乔木","origin":["大洋洲"]},{"id":2,"zh":"白睡莲","en":"Nymphaea alba","sci":"Nymphaea alba","order_en":"Nymphaeales","order_zh":"睡莲目","family_en":"Nymphaeaceae","family_zh":"睡莲科","iucn":"LC","langs":64,"desc_zh":"白睡莲（ 学名：Nymphaea alba）又名欧洲白睡莲，是一种源自于欧洲的睡莲属植物。其种加词“alba”意为“白色的”。","desc_en":"Nymphaea alba – commonly called the white water lily, European white water lily, or white nenuphar ( NEN-yuu-far) – is an aquatic flowering plant in the family Nymphaeaceae.","img":"images/2.jpg","thumb":"images/t/2.jpg","file":"Nymphaea alba in Duisburg.jpg","ar":1.471,"py":"baishuilian bsl","cr_by":"DerHexer","cr_lic":"CC BY-SA 3.0","cr_licurl":"https://creativecommons.org/licenses/by-sa/3.0","habit":null,"origin":["亚洲","欧洲","非洲"]},{"id":3,"zh":"欧亚萍蓬草","en":"Nuphar lutea","sci":"Nuphar lutea","order_en":"Nymphaeales","order_zh":"睡莲目","family_en":"Nymphaeaceae","family_zh":"睡莲科","iucn":"LC","langs":58,"desc_zh":"欧亚萍蓬草（学名：Nuphar lutea）（又名：青荷根、大荷根、荷根、荷根草、露特萍蓬草），是睡莲科萍蓬草属的植物。分布于伊朗、欧洲、中亚、俄罗斯、西伯利亚以及中国大陆的新疆等地，见于池沼，目前尚未由人工引种栽培。","desc_en":"Nuphar lutea, the yellow water-lily, is an aquatic plant of the family Nymphaeaceae, native to northern temperate and some subtropical regions of Europe, northwest Africa, and western Asia.","img":"images/3.jpg","thumb":"images/t/3.jpg","file":"Nuphar lutea (habitus).jpg","ar":1.333,"py":"ouyapingpengcao oyppc","cr_by":"Hans Hillewaert","cr_lic":"CC BY-SA 3.0","cr_licurl":"https://creativecommons.org/licenses/by-sa/3.0","habit":null,"origin":["亚洲","欧洲","非洲"]},{"id":4,"zh":"王莲","en":"Victoria amazonica","sci":"Victoria amazonica","order_en":"Nymphaeales","order_zh":"睡莲目","family_en":"Nymphaeaceae","family_zh":"睡莲科","iucn":null,"langs":45,"desc_zh":"亚马逊王莲（学名：Victoria amazonica），又称亚马逊皇莲或皇家睡莲，是王莲属下的一种，是睡莲科最大的植物。 它原产于亚马逊河盆地，被圭亚那当作国花。 亚马逊王莲的叶子直径可达三米，茎长可达七至八米。刚开的花呈白色，但一夜之间就会变成粉色。花的直径也有40厘米。 刚开花时，白色花瓣散发浓烈香味，将强力吸引金龟子(或其他昆虫)前来授粉，当金龟子飞来时，花朵会轻轻阖上，让包裹在花瓣中的金龟全身沾满睡莲的花粉。","desc_en":"Victoria amazonica (\"giant water lily\") is a species of flowering plant, the second largest in the water lily family Nymphaeaceae. It is called Vitória-Régia or Iaupê-Jaçanã (\"the jacana's waterlily\") in Brazil and Atun Sisac (\"great flower\") in Inca (Quechua)…","img":"images/4.jpg","thumb":"images/t/4.jpg","file":"Victoria amazonica edit 1.jpg","ar":0.833,"py":"wanglian wl","cr_by":"Bilby","cr_lic":"CC BY 3.0","cr_licurl":"https://creativecommons.org/licenses/by/3.0","habit":null,"origin":["南美洲"]},{"id":5,"zh":"芡","en":"Euryale ferox","sci":"Euryale ferox","order_en":"Nymphaeales","order_zh":"睡莲目","family_en":"Nymphaeaceae","family_zh":"睡莲科","iucn":"LC","langs":40,"desc_zh":"芡（学名：Euryale ferox），又名䓈，民间俗称“鸡头莲”，是属于睡莲科芡属的水生植物，芡属是个单型属，只有这一物种。芡的种子称为“芡实”或“芡米”、“鸡头米”。芡实磨成“芡粉”后可用于“勾芡”。产于广东省肇庆的芡实可被标记为“肇实”，如同山药中“淮山”。","desc_en":"Euryale ferox, commonly known as prickly waterlily, makhānā, or Gorgon plant, is a species of water lily found in southern and eastern Asia, and the only extant member of the genus Euryale.","img":"images/5.jpg","thumb":"images/t/5.jpg","file":"Euryale ferox.jpg","ar":1.268,"py":"qian q","cr_by":"John Sims","cr_lic":"Public domain","cr_licurl":null,"habit":null,"origin":["亚洲"]},{"id":6,"zh":"齿叶睡莲","en":"Nymphaea lotus","sci":"Nymphaea lotus","order_en":"Nymphaeales","order_zh":"睡莲目","family_en":"Nymphaeaceae","family_zh":"睡莲科","iucn":"LC","langs":38,"desc_zh":"齿叶睡莲（学名：Nymphaea lotus）为睡莲科睡莲属下的一个种。","desc_en":"Nymphaea lotus, the white Egyptian lotus, tiger lotus, white lotus, or Egyptian water-lily, is a flowering plant of the family Nymphaeaceae.","img":"images/6.jpg","thumb":"images/t/6.jpg","file":"Curtis's botanical magazine (No. 797) (8470978436).jpg","ar":1.166,"py":"chiyeshuilian cysl","cr_by":"Bentham-Moxon Trust.; Curtis, William; Curtis's botanical magazine dedications, 1827-1927 : portraits and biographical n","cr_lic":"Public domain","cr_licurl":null,"habit":null,"origin":null},{"id":7,"zh":"八角","en":"Illicium verum","sci":"Illicium verum","order_en":"Austrobaileyales","order_zh":"木兰藤目","family_en":"Schisandraceae","family_zh":"五味子科","iucn":null,"langs":76,"desc_zh":"八角（学名：Illicium verum），又称八角茴香、大料和大茴香（在某些地方、场合，大茴香指的是茴芹种子），是木兰藤目五味子科八角属的一种植物。其同名的干燥果实是中国菜和东南亚地区烹饪的调味料之一。","desc_en":"Illicium verum (star anise or badian, Chinese star anise, star anise seed, star aniseed and star of anise) is a medium-sized evergreen tree native to South China and northeast Vietnam.","img":"images/7.jpg","thumb":"images/t/7.jpg","file":"Illicium verum 4zz.jpg","ar":1.504,"py":"bajiao bj","cr_by":"Photo by David J. Stang","cr_lic":"CC BY-SA 4.0","cr_licurl":"https://creativecommons.org/licenses/by-sa/4.0","habit":"乔木","origin":["亚洲"]},{"id":8,"zh":"五味子","en":"Schisandra chinensis","sci":"Schisandra chinensis","order_en":"Austrobaileyales","order_zh":"木兰藤目","family_en":"Schisandraceae","family_zh":"五味子科","iucn":null,"langs":38,"desc_zh":"五味子（学名：Schisandra chinensis），又称作五味、北五味子、山五味、山花椒、荎藸（拼音：chíchú），六亭剂、为五味子科五味子属下的一种植物。唐朝《新修本草》载“五味皮肉甘酸，核中辛苦，都有咸味”，所以得名。","desc_en":"Schisandra chinensis, whose fruit is called schisandra, magnolia berry or five-flavor fruit, is a vine plant native to forests of Northern China, the Russian Far East, Korea, and Japan. It is hardy in USDA Zones 4-8.","img":"images/8.jpg","thumb":"images/t/8.jpg","file":"Schisandra sinensis.jpg","ar":0.665,"py":"wuweizi wwz","cr_by":"Doronenko","cr_lic":"CC BY 2.5","cr_licurl":"https://creativecommons.org/licenses/by/2.5","habit":"藤本","origin":["亚洲"]},{"id":9,"zh":"荷花玉兰","en":"Magnolia grandiflora","sci":"Magnolia grandiflora","order_en":"Magnoliales","order_zh":"木兰目","family_en":"Magnoliaceae","family_zh":"木兰科","iucn":"LC","langs":54,"desc_zh":"荷花玉兰（学名：Magnolia grandiflora），又名洋玉兰（中国树木分类学）、广玉兰（上海），为木兰科木兰属的植物，原产美洲，北美洲以及中国大陆的长江流域及其以南有栽培，北方如北京、兰州等地有引种。供观赏，花含芳香油。 种名grandiflora意为“大花的”。","desc_en":"Magnolia grandiflora, commonly known as the southern magnolia or bull bay, is a tree of the family Magnoliaceae native to the Southeastern United States coastal plain, from Virginia to central Florida, and west to East Texas. Reaching 27.","img":"images/9.jpg","thumb":"images/t/9.jpg","file":"Magnolia flower Duke campus.jpg","ar":1.6,"py":"hehuayulan hhyl","cr_by":"DavetheMage","cr_lic":"CC BY 3.0","cr_licurl":"https://creativecommons.org/licenses/by/3.0","habit":"乔木","origin":["北美洲"]},{"id":10,"zh":"北美鹅掌楸","en":"Liriodendron tulipifera","sci":"Liriodendron tulipifera","order_en":"Magnoliales","order_zh":"木兰目","family_en":"Magnoliaceae","family_zh":"木兰科","iucn":"LC","langs":44,"desc_zh":"北美鹅掌楸（学名：Liriodendron tulipifera）为木兰科鹅掌楸属下的一个种。分布在北美东部。","desc_en":"Liriodendron tulipifera—known as the tulip tree, American tulip tree, tulipwood, tuliptree, tulip poplar, whitewood, fiddletree, lynn-tree, hickory-poplar, and yellow-poplar—is the North American representative of the two-species genus Liriodendron (the other…","img":"images/10.jpg","thumb":"images/t/10.jpg","file":"Liriodendron tulipifera JPG5a.jpg","ar":0.667,"py":"beimeiezhangqiu bmezq","cr_by":"Jean-Pol GRANDMONT","cr_lic":"CC BY 3.0","cr_licurl":"https://creativecommons.org/licenses/by/3.0","habit":"乔木","origin":["北美洲"]},{"id":11,"zh":"黄玉兰","en":"Magnolia champaca","sci":"Magnolia champaca","order_en":"Magnoliales","order_zh":"木兰目","family_en":"Magnoliaceae","family_zh":"木兰科","iucn":"LC","langs":44,"desc_zh":"黄玉兰（学名：Michelia champaca），俗称南洋乌心石，为木兰科含笑属下的一个种。原产地为喜马拉雅山、中国南部、印度、爪哇岛和菲律宾，台湾在1800年间引进，目前各地有零星栽培。小乔木或灌木，高及蓬径3－6米，叶革质，翠绿色，达16厘米长；花芬芳，橙黄色或乳白色，春季开花，可提取精油用于制作香水。 《中国植物志》认为《植物名实图考》的“黄兰”为此种，但从描述和绘图来看“黄兰”也可能是小依兰。","desc_en":"Magnolia champaca, known in English as champak (), is a large evergreen tree in the family Magnoliaceae. It was previously classified as Michelia champaca. It is known for its fragrant flowers, and its timber used in woodworking.","img":"images/11.jpg","thumb":"images/t/11.jpg","file":"Michelia champaca Blanco1.191-cropped.jpg","ar":0.899,"py":"huangyulan hyl","cr_by":"Francisco Manuel Blanco (O.S.A.)","cr_lic":"Public domain","cr_licurl":null,"habit":"乔木","origin":null},{"id":12,"zh":"日本辛夷","en":"Magnolia kobus","sci":"Magnolia kobus","order_en":"Magnoliales","order_zh":"木兰目","family_en":"Magnoliaceae","family_zh":"木兰科","iucn":"DD","langs":32,"desc_zh":"日本辛夷（学名：Magnolia kobus，又名日本玉兰）属于木兰科木兰属，是一种原产于日本的玉兰，落叶小乔木，生长率低，但株高可达7.6公尺，树干直径可达10.7公尺。1920年代引种至中国青岛。","desc_en":"Magnolia kobus, known as mokryeon, kobus magnolia, or kobushi magnolia, is a species of Magnolia native to Japan (Kyushu, Honshu, and Hokkaido) and Korea and occasionally cultivated in temperate areas.","img":"images/12.jpg","thumb":"images/t/12.jpg","file":"Magnolia kobus borealis.jpg","ar":1.174,"py":"ribenxinyi rbxy","cr_by":"Bruce Marlin","cr_lic":"CC BY-SA 3.0","cr_licurl":"https://creativecommons.org/licenses/by-sa/3.0","habit":"乔木","origin":["亚洲"]},{"id":13,"zh":"玉兰","en":"Magnolia denudata","sci":"Magnolia denudata","order_en":"Magnoliales","order_zh":"木兰目","family_en":"Magnoliaceae","family_zh":"木兰科","iucn":"LC","langs":31,"desc_zh":"玉兰（学名：Magnolia denudata），别名白玉兰、望春花、玉兰花，原产中国中部山野，现于世界各地庭园常见栽培。玉兰是上海市市花。中文中惯称含笑属的白兰（学名：Michelia x alba）为「玉兰花」，但实际上两者为不同种不同属的植物。","desc_en":"Magnolia denudata, the lilytree or Yulan magnolia (simplified Chinese: 玉兰花; traditional Chinese: 玉蘭花; pinyin: yùlánhuā; lit. 'jade orchid/lily'), is native to central and eastern China. It has been cultivated in Chinese Buddhist temple gardens since 600 AD.","img":"images/13.jpg","thumb":"images/t/13.jpg","file":"Yulan 1.JPG","ar":1.333,"py":"yulan yl","cr_by":"The original uploader was Yongxinge at English Wikipedia .","cr_lic":"CC BY-SA 3.0","cr_licurl":"http://creativecommons.org/licenses/by-sa/3.0/","habit":null,"origin":["亚洲"]},{"id":14,"zh":"白背玉兰","en":"Magnolia virginiana","sci":"Magnolia virginiana","order_en":"Magnoliales","order_zh":"木兰目","family_en":"Magnoliaceae","family_zh":"木兰科","iucn":"LC","langs":31,"desc_zh":null,"desc_en":"Magnolia virginiana, most commonly known as sweetbay magnolia, or merely sweetbay (also laurel magnolia, swampbay, swamp magnolia, white bay, or beaver tree), is a member of the magnolia family, Magnoliaceae.","img":"images/14.jpg","thumb":"images/t/14.jpg","file":"Sweetbay Magnolia Magnolia virginiana Comparison 4400px.jpg","ar":2.085,"py":"baibeiyulan bbyl","cr_by":"Photo by and (c)2008 Derek Ramsey ( Ram-Man ). Co-attribution must be given to the Chanticleer Garden.","cr_lic":"CC BY-SA 3.0","cr_licurl":"http://creativecommons.org/licenses/by-sa/3.0/","habit":"乔木","origin":null},{"id":15,"zh":"星花木兰","en":"Magnolia stellata","sci":"Magnolia stellata","order_en":"Magnoliales","order_zh":"木兰目","family_en":"Magnoliaceae","family_zh":"木兰科","iucn":"EN","langs":30,"desc_zh":"星花木兰（学名：Magnolia stellata），又名日本毛木兰，为木兰科木兰属的植物。分布于日本以及中国大陆的青岛、南京等地，目前已由人工引种栽培。星花兰木的原产地为日本，因为开花的时间开得比较早，所以被视为春天的开始。《二如亭群芳谱》中记载着「玉兰，花九瓣，色白，微碧，香味似兰，故名。丛生，一干一花皆著木末，绝无柔条。隆冬结蕾，三月盛开。」，星花木兰清香扑鼻，颜色鲜艳，是春季最具代表的观赏花之一，深受花迷的喜欢。","desc_en":"Magnolia stellata, the star magnolia, is a slow-growing deciduous shrub or small tree native to Japan. It bears large, showy white or pink flowers in early spring, before its leaves open.","img":"images/15.jpg","thumb":"images/t/15.jpg","file":"Magnolia stellata fleurs.jpg","ar":1.18,"py":"xinghuamulan xhml","cr_by":"Myrabella","cr_lic":"CC BY-SA 3.0","cr_licurl":"https://creativecommons.org/licenses/by-sa/3.0","habit":"乔木","origin":["亚洲"]},{"id":16,"zh":"紫玉兰","en":"Magnolia liliiflora","sci":"Magnolia liliiflora","order_en":"Magnoliales","order_zh":"木兰目","family_en":"Magnoliaceae","family_zh":"木兰科","iucn":"DD","langs":29,"desc_zh":"紫玉兰（学名：Magnolia liliiflora），木兰科木兰属，又名木兰、辛夷（江苏）、木笔（花镜）、望春、女郎花，为中国特有植物，分布在中国大陆的云南、福建、湖北、四川等地，生长于海拔300米至1,600米的地区，一般生长在山坡林缘。紫玉兰花朵艳丽怡人，芳香淡雅，“紫苞红焰，作莲及兰花香”，故唐代裴迪有诗：“况有辛夷花，色与芙蓉乱。","desc_en":"Magnolia liliiflora is a shrub or small tree native to southern China (including Sichuan and Yunnan), but cultivated for centuries elsewhere in China and also Japan.","img":"images/16.jpg","thumb":"images/t/16.jpg","file":"Magnolienbluete freiburg.jpg","ar":1.333,"py":"ziyulan zyl","cr_by":"Thilo Machotta (Benutzer: thiloma)","cr_lic":"CC BY-SA 2.0 de","cr_licurl":"https://creativecommons.org/licenses/by-sa/2.0/de/deed.en","habit":"乔木","origin":["亚洲"]},{"id":17,"zh":"二乔木兰","en":"Magnolia × soulangeana","sci":"Magnolia ×soulangeana","order_en":"Magnoliales","order_zh":"木兰目","family_en":"Magnoliaceae","family_zh":"木兰科","iucn":null,"langs":27,"desc_zh":"二乔木兰（学名：Magnolia × soulangeana）是木兰科木兰属的植物，分布于中国大陆的广州、杭州、昆明等地，是由玉兰（Magnolia denudata）和紫玉兰（Magnolia liliiflora）自然杂交得到，花朵颜色介于两亲本之间，花被片外面上端为白色，基部呈紫色，花内面白色。3种玉兰的组织培养实验表明二乔木兰是再生能力最强的，由此可以看出二乔木兰是易于栽培的木兰。花期为2~3月，果期为9~10月。","desc_en":"Magnolia × soulangeana (Magnolia denudata × Magnolia liliiflora), the saucer magnolia or sometimes the tulip tree, is a hybrid flowering plant in the genus Magnolia and family Magnoliaceae.","img":"images/17.jpg","thumb":"images/t/17.jpg","file":"Magnolia x soulangeana 2 (Piotr Kuczynski).jpg","ar":1.333,"py":"erqiaomulan eqml","cr_by":"Piotr Kuczynski","cr_lic":"CC BY-SA 3.0","cr_licurl":"http://creativecommons.org/licenses/by-sa/3.0/","habit":"乔木","origin":["欧洲"]},{"id":18,"zh":"日本厚朴","en":"Magnolia obovata","sci":"Magnolia obovata","order_en":"Magnoliales","order_zh":"木兰目","family_en":"Magnoliaceae","family_zh":"木兰科","iucn":"LC","langs":26,"desc_zh":"日本厚朴（学名：Magnolia obovata）为木兰科木兰属的植物。分布于日本千岛群岛以南以及中国大陆的东北、广州、青岛、北京等地，目前已由人工引种栽培。","desc_en":"Magnolia obovata, the Japanese cucumber tree, Japanese bigleaf magnolia, or Japanese whitebark magnolia, is a species of Magnolia, native to Japan and the adjacent Kurile Islands. It grows from near sea level up to 1,800 m elevation in mixed broadleaf forests.","img":"images/18.jpg","thumb":"images/t/18.jpg","file":"Magnolia hypoleuca 2.jpg","ar":0.838,"py":"ribenhoupo rbhp","cr_by":"Sphl","cr_lic":"CC BY-SA 3.0","cr_licurl":"http://creativecommons.org/licenses/by-sa/3.0/","habit":"乔木","origin":["亚洲"]},{"id":19,"zh":"刺果番荔枝","en":"Annona muricata","sci":"Annona muricata","order_en":"Magnoliales","order_zh":"木兰目","family_en":"Annonaceae","family_zh":"番荔枝科","iucn":"LC","langs":82,"desc_zh":"刺果番荔枝（学名：Annona muricata），新马一带俗称红毛榴梿（马来语：durian belanda），一种热带水果，属番荔枝科番荔枝属。虽然别名里有「榴梿」二字，但不具臭味，分类上与台湾所产的释迦（即番荔枝）相近。果肉呈乳白色，酸甜多汁，种子黑色，散在果肉纹理中。 原产于美洲热带地区，现广泛引种于世界各地。中国大陆产区为海南、云南、广西等气温较高地区。","desc_en":"Soursop (also called graviola, guyabano, and in Hispanic America guanábana) is the fruit of Annona muricata, a broadleaf, flowering, evergreen tree. It is native to the tropical Americas and is widely propagated.","img":"images/19.jpg","thumb":"images/t/19.jpg","file":"Annona muricata 1.jpg","ar":0.75,"py":"ciguofanlizhi cgflz","cr_by":"Damien Boilley from suburbs of Paris, France","cr_lic":"CC BY 2.0","cr_licurl":"https://creativecommons.org/licenses/by/2.0","habit":"乔木","origin":null},{"id":20,"zh":"番荔枝","en":"Annona squamosa","sci":"Annona squamosa","order_en":"Magnoliales","order_zh":"木兰目","family_en":"Annonaceae","family_zh":"番荔枝科","iucn":"LC","langs":77,"desc_zh":"番荔枝（学名：Annona squamosa），又称释迦、佛头果、佛果、释迦果、亚大菓子（指其果实）、亚大树（指果树）、林檎（广东潮汕地区）、唛螺陀（广西）、洋菠萝（广西龙州）、假菠萝（广西凭祥，因其外形与结构都酷似广西盛产的菠萝蜜）、番鬼荔枝（广东粤语区、香港、澳门）、麻窝楂（云南德宏）或蜜檎（印尼西加里曼丹省）等，为番荔枝科番荔枝属多年生半落叶性小乔木植物。多种植做经济作物，果肉白而甜。","desc_en":"Annona squamosa is a small, well-branched tree or shrub from the family Annonaceae that bears edible fruits called sugar apples or sweetsops or custard apples.","img":"images/20.jpg","thumb":"images/t/20.jpg","file":"Pomme cannelle ou zato.jpg","ar":1.333,"py":"fanlizhi flz","cr_by":"Chirocca77","cr_lic":"CC BY-SA 4.0","cr_licurl":"https://creativecommons.org/licenses/by-sa/4.0","habit":"乔木","origin":["亚洲"]},{"id":21,"zh":"依兰","en":"Cananga odorata","sci":"Cananga odorata","order_en":"Magnoliales","order_zh":"木兰目","family_en":"Annonaceae","family_zh":"番荔枝科","iucn":"LC","langs":64,"desc_zh":"依兰（学名：Cananga odorata）是番荔枝科依兰属的植物。原产于东南亚的爪哇、马来西亚、菲律宾。一般生于热带地区，分布在印度尼西亚、菲律宾、台湾、缅甸、马来西亚以及中国大陆的广东、四川、云南、福建、广西等地。目前已由人工引种栽培，在亚洲的热带地区广泛种植。花可提炼香精，可制造高级香水。","desc_en":"Cananga odorata, commonly known as ylang-ylang (), Macassar oil tree, perfume tree or cananga, is a species of plant in the custard apple family Annonaceae.","img":"images/21.jpg","thumb":"images/t/21.jpg","file":"Cananga odorata flowers-cropped.jpg","ar":1,"py":"yilan yl","cr_by":"User:B.navez","cr_lic":"CC BY-SA 3.0","cr_licurl":"http://creativecommons.org/licenses/by-sa/3.0/","habit":"乔木","origin":["亚洲","大洋洲"]},{"id":22,"zh":"秘鲁番荔枝","en":"Annona cherimola","sci":"Annona cherimola","order_en":"Magnoliales","order_zh":"木兰目","family_en":"Annonaceae","family_zh":"番荔枝科","iucn":"LC","langs":58,"desc_zh":"秘鲁番荔枝（学名：Annona cherimola），别名毛叶番荔枝、冷子番荔枝，是一种番荔枝科的植物。它是一种常绿约三至九米高的枝叶密集的树或者灌木。原产于秘鲁、厄瓜多尔及智利。","desc_en":"The cherimoya (Annona cherimola), also spelled cherimoyer and chirimoya, and called chirimuya by the Quechua people, is a species of edible fruit-bearing plant in the genus Annona, within the family Annonaceae, which also includes the closely related sweetsop…","img":"images/22.jpg","thumb":"images/t/22.jpg","file":"Annona cherimola fruit, Pedra Bela, Brazil.jpg","ar":1.333,"py":"bilufanlizhi blflz","cr_by":"Marcelo RosaMelo","cr_lic":"CC0","cr_licurl":"http://creativecommons.org/publicdomain/zero/1.0/deed.en","habit":null,"origin":["北美洲","南美洲"]},{"id":23,"zh":"牛心番荔枝","en":"Annona reticulata","sci":"Annona reticulata","order_en":"Magnoliales","order_zh":"木兰目","family_en":"Annonaceae","family_zh":"番荔枝科","iucn":"LC","langs":55,"desc_zh":"牛心番荔枝（学名：Annona reticulata）又叫牛心果、牛心梨，是番荔枝科番荔枝属的植物。分布在亚洲、美洲、台湾以及中国大陆的云南、广东、福建、广西等地，目前已由人工引种养培。 果皮光滑淡绿色，成熟后颜色呈鲜红色，果肉香甜。果树高大约达三层楼建筑高度，产季整颗树上果实累累。 其种加词“reticuluma”意为“网纹的”。","desc_en":"Annona reticulata is a small deciduous or semi-evergreen tree in the plant family Annonaceae. It is best known for its fruit, called custard apple, a common name shared with fruits of several other species in the same genus: A. cherimola and A. squamosa.","img":"images/23.jpg","thumb":"images/t/23.jpg","file":"Annona reticulata Blanco1.197-cropped.jpg","ar":0.663,"py":"niuxinfanlizhi nxflz","cr_by":"Francisco Manuel Blanco (O.S.A.)","cr_lic":"Public domain","cr_licurl":null,"habit":"乔木","origin":null},{"id":24,"zh":"波波树","en":"Asimina triloba","sci":"Asimina triloba","order_en":"Magnoliales","order_zh":"木兰目","family_en":"Annonaceae","family_zh":"番荔枝科","iucn":"LC","langs":47,"desc_zh":"泡泡果（学名：Asimina triloba）又名巴婆果、泡泡树，皆音译自其英文名称“pawpaw”，为番荔枝科泡泡属的物种，是一种原产于美国东部和加拿大的小落叶树，高35英尺（11米），直径8—12英寸（20—30厘米）。其果实为黄绿色至棕色。泡泡果和释迦、刺果番荔枝等同属番荔枝科，其果实是美国本土原产的水果中最大的可食用水果。果实味道具甜味，通常生吃，但也可用来制作冰淇淋。","desc_en":"Asimina triloba, the American papaw, pawpaw, paw paw, or paw-paw, among many regional names, is a species of small deciduous tree. It has large leaves and produces a large, yellowish-green to brown fruit.","img":"images/24.jpg","thumb":"images/t/24.jpg","file":"Asimina triloba3.jpg","ar":1.52,"py":"boboshu bbs","cr_by":"Scott Bauer, USDA","cr_lic":"Public domain","cr_licurl":null,"habit":"乔木","origin":["北美洲"]},{"id":25,"zh":"圆滑番荔枝","en":"Annona glabra","sci":"Annona glabra","order_en":"Magnoliales","order_zh":"木兰目","family_en":"Annonaceae","family_zh":"番荔枝科","iucn":"LC","langs":29,"desc_zh":"圆滑番荔枝（学名：Annona glabra）为番荔枝科番荔枝属的植物。分布于美洲、亚洲、台湾岛以及中国大陆的云南、浙江、广西、广东等地，目前已由人工引种栽培。","desc_en":"Annona glabra is a tropical fruit tree in the family Annonaceae, in the same genus as the soursop and cherimoya. Common names include pond apple, alligator apple (so called because American alligators often eat the fruit), swamp apple, corkwood, bobwood, and m…","img":"images/25.jpg","thumb":"images/t/25.jpg","file":"Annona glabra FL.jpg","ar":1.333,"py":"yuanhuafanlizhi yhflz","cr_by":"CiXeL at English Wikipedia","cr_lic":"CC BY-SA 3.0","cr_licurl":"https://creativecommons.org/licenses/by-sa/3.0","habit":"乔木","origin":["非洲","北美洲","南美洲"]},{"id":26,"zh":"肉豆蔻","en":"Myristica fragrans","sci":"Myristica fragrans","order_en":"Magnoliales","order_zh":"木兰目","family_en":"Myristicaceae","family_zh":"肉豆蔻科","iucn":"DD","langs":63,"desc_zh":"肉豆蔻（学名：Myristica fragrans），又名肉蔻、肉果、玉果、麻醉果，是一种重要的香料、药用植物。其种加词fragrans意为“芳香的”。肉豆蔻生长于热带地区的常绿植物，常见于东南亚、澳洲及加勒比海地区，尤以印度尼西亚和格林纳达产量最大。肉豆蔻的果实是肉豆蔻（英语：nutmeg；肉豆蔻的种子）和肉豆蔻皮/肉豆蔻衣/肉豆蔻花（英语：mace；肉豆蔻的假种皮）的来源，二者都是常见的香料，用于食品、菜肴的调味，前者可制作香精油。","desc_en":"Myristica fragrans, commonly known as the nutmeg tree, is an evergreen species indigenous to the Maluku Islands of Indonesia. This aromatic tree is economically significant as the primary source of two distinct spices: nutmeg, derived from its seed, and mace,…","img":"images/26.jpg","thumb":"images/t/26.jpg","file":"Myristica fragrans at Elmina West in Seksyen U15, Shah Alam 20231126 100924.jpg","ar":0.75,"py":"roudoukou rdk","cr_by":"Wiki Farazi","cr_lic":"CC0","cr_licurl":"http://creativecommons.org/publicdomain/zero/1.0/deed.en","habit":"乔木","origin":["亚洲"]},{"id":27,"zh":"刺茎肉荳蔻","en":"Virola surinamensis","sci":"Virola surinamensis","order_en":"Magnoliales","order_zh":"木兰目","family_en":"Myristicaceae","family_zh":"肉豆蔻科","iucn":"LC","langs":15,"desc_zh":null,"desc_en":"Virola surinamensis, known commonly as baboonwood, ucuuba, ucuhuba and chalviande, is a species of flowering plant in the family Myristicaceae. It is found in Bolivia, northern and central Brazil, Colombia, Ecuador, French Guiana, Guyana, Peru, Suriname, Trini…","img":"images/27.jpg","thumb":"images/t/27.jpg","file":"Virola surinamensis (Wild nutmeg) Paramin Trinidad 2.jpg","ar":1.06,"py":"cijingroudoukou cjrdk","cr_by":"Feroze Omardeen","cr_lic":"CC BY 2.0","cr_licurl":"https://creativecommons.org/licenses/by/2.0","habit":"乔木","origin":["南美洲"]},{"id":28,"zh":"鳄梨","en":"Persea americana","sci":"Persea americana","order_en":"Laurales","order_zh":"樟目","family_en":"Lauraceae","family_zh":"樟科","iucn":"LC","langs":145,"desc_zh":"鳄梨（学名：Persea americana，港澳称为牛油果，台湾称为酪梨，又称油梨或樟梨），是樟科鳄梨属的常绿乔木，果实可食用。鳄梨原产于中美洲，从墨西哥中部的高地森林到哥伦比亚西北部的雨林均有其自然分布地。考古证据显示，早在约一万年前（公元前8000–7000年），墨西哥等地的中美洲原住民就已开始食用本种，而出现时间更晚的一些遗址（距今6000 - 4800年）中发现的鳄梨种子则体积更大，表明当时的人类可能已经开始人工选择鳄梨。","desc_en":"The avocado, alligator pear or avocado pear (Persea americana) is an evergreen tree in the laurel family (Lauraceae). It is native to the Americas, with archaeological evidence of early human avocado use dating back thousands of years across various regions of…","img":"images/28.jpg","thumb":"images/t/28.jpg","file":"Persea americana fruit 2.JPG","ar":0.8,"py":"eli el","cr_by":"B.navez","cr_lic":"CC BY-SA 3.0","cr_licurl":"https://creativecommons.org/licenses/by-sa/3.0","habit":"乔木","origin":["南美洲"]},{"id":29,"zh":"月桂","en":"Laurus nobilis","sci":"Laurus nobilis","order_en":"Laurales","order_zh":"樟目","family_en":"Lauraceae","family_zh":"樟科","iucn":"LC","langs":86,"desc_zh":"月桂（学名：Laurus nobilis），又称月桂树、桂冠树、甜月桂、月桂冠，是调味料月桂叶的来源。原产于地中海沿岸及小亚细亚一带灌木岩石区，现已遍布世界各地。 叶片深绿色，椭圆形，革质，味苦，清香。干燥后，苦味减少，香气增强，可以用作调料，即“香叶”。 古代希腊人用月桂的小枝条编织成桂冠，授予皮提亚运动会的胜利者，象征荣耀与胜利。","desc_en":"Laurus nobilis is an aromatic evergreen tree or large shrub with green, glabrous (smooth) leaves. It is in the flowering plant family Lauraceae. According to Muer, Jahn, & Sauerbier, the stem can be 1 metre in diameter and the tree can be as high as 20 metres.","img":"images/29.jpg","thumb":"images/t/29.jpg","file":"Laurier.jpg","ar":1.333,"py":"yuegui yg","cr_by":null,"cr_lic":"CC BY-SA 3.0","cr_licurl":"http://creativecommons.org/licenses/by-sa/3.0/","habit":"乔木","origin":["欧洲"]},{"id":30,"zh":"樟树","en":"Cinnamomum camphora","sci":"Cinnamomum camphora","order_en":"Laurales","order_zh":"樟目","family_en":"Lauraceae","family_zh":"樟科","iucn":"LC","langs":72,"desc_zh":"樟树（学名：Camphora officinarum）是樟科常绿大乔木，别名香樟、本樟、乌樟、栳樟、樟仔，以往为制造樟脑的经济树种，因天然熬樟已没落而改用化工合成樟油，目前只作景观园林或防风树种。 “樟”的由来有两种说法：一是李时珍《本草纲目》记载，「其木理多纹章，故谓之樟」；二是其有香味，类似发散香气的动物「獐」而得名。","desc_en":"Camphora officinarum is a species of evergreen tree indigenous to warm temperate to subtropical regions of East Asia, including countries such as China, Taiwan, Vietnam, Korea, Japan and India.","img":"images/30.jpg","thumb":"images/t/30.jpg","file":"Cinnamomum camphora20050314.jpg","ar":1.267,"py":"zhangshu zs","cr_by":null,"cr_lic":"CC BY-SA 3.0","cr_licurl":"http://creativecommons.org/licenses/by-sa/3.0/","habit":"乔木","origin":["亚洲"]},{"id":31,"zh":"锡兰肉桂","en":"Cinnamomum verum","sci":"Cinnamomum verum","order_en":"Laurales","order_zh":"樟目","family_en":"Lauraceae","family_zh":"樟科","iucn":"VU","langs":63,"desc_zh":"锡兰肉桂（学名：Cinnamomum verum）是樟科肉桂属植物，原产斯里兰卡，在中国广东、海南、广西、台湾均有栽培。其树皮，亦称锡兰肉桂。 在欧美，英文所称 Cinnamon 多指此类。","desc_en":"Cinnamomum verum (synonym Cinnamomum zeylanicum), also known as true cinnamon or Ceylon cinnamon, is a small evergreen tree belonging to the family Lauraceae, native to Sri Lanka.","img":"images/31.jpg","thumb":"images/t/31.jpg","file":"Cinnamomum verum1.jpg","ar":1.548,"py":"xilanrougui xlrg","cr_by":null,"cr_lic":"Public domain","cr_licurl":null,"habit":"乔木","origin":["亚洲"]},{"id":32,"zh":"肉桂","en":"Cinnamomum cassia","sci":"Cinnamomum cassia","order_en":"Laurales","order_zh":"樟目","family_en":"Lauraceae","family_zh":"樟科","iucn":null,"langs":47,"desc_zh":"肉桂（学名：Cinnamomum cassia，英语：Cinnamon），又称作官桂、桂心、简桂、玉桂、牡桂，为樟科常绿乔木。还有另一品种锡兰肉桂。两种皆含有微量香豆素，摄取过多肉桂，可能引发副作用。","desc_en":"Cinnamomum cassia, called Chinese cassia, cassia cinnamon, or Chinese cinnamon, is an evergreen tree originating in southern China and widely cultivated there and elsewhere in South and Southeast Asia.","img":"images/32.jpg","thumb":"images/t/32.jpg","file":"Cinnamomum aromaticum - Köhler–s Medizinal-Pflanzen-039 cropped.jpg","ar":0.844,"py":"rougui rg","cr_by":"Franz Eugen Köhler, Köhler's Medizinal-Pflanzen","cr_lic":"Public domain","cr_licurl":null,"habit":"乔木","origin":["亚洲"]},{"id":33,"zh":"柴桂","en":"Cinnamomum tamala","sci":"Cinnamomum tamala","order_en":"Laurales","order_zh":"樟目","family_en":"Lauraceae","family_zh":"樟科","iucn":"LC","langs":30,"desc_zh":"柴桂（学名：Cinnamomum tamala）是樟科肉桂属的植物。分布在不丹、尼泊尔、印度以及中国大陆的云南等地，生长于海拔1,180米至1,930米的地区，多生于山坡、谷地的常绿阔叶林中或水边。","desc_en":"Cinnamomum tamala, Indian bay leaf, also known as tejpat, tejapatta, Malabar leaf, Indian bark, Indian cassia, or malabathrum, is a tree in the family Lauraceae that is native to northern India (Assam and the Western Himalayas), Bangladesh, Nepal, Myanmar, Lao…","img":"images/33.jpg","thumb":"images/t/33.jpg","file":"Indian bay leaf - tejpatta - indisches Lorbeerblatt.jpg","ar":1.333,"py":"chaigui cg","cr_by":"Sonja Pauen","cr_lic":"Public domain","cr_licurl":null,"habit":"乔木","origin":["亚洲"]},{"id":34,"zh":"亚速尔月桂","en":"Laurus azorica","sci":"Laurus azorica","order_en":"Laurales","order_zh":"樟目","family_en":"Lauraceae","family_zh":"樟科","iucn":"LC","langs":25,"desc_zh":null,"desc_en":"Laurus azorica, the Azores laurel or Macaronesian laurel, is a small, evergreen tree in the laurel family (Lauraceae), found only on the Azores island group in the North Atlantic.","img":"images/34.jpg","thumb":"images/t/34.jpg","file":"Laurus azorica (Flowers).jpg","ar":1.333,"py":"yasueryuegui yseyg","cr_by":"Ixitixel","cr_lic":"CC BY-SA 3.0","cr_licurl":"http://creativecommons.org/licenses/by-sa/3.0/","habit":"乔木","origin":null},{"id":35,"zh":"北美檫树","en":"Sassafras albidum","sci":"Sassafras albidum","order_en":"Laurales","order_zh":"樟目","family_en":"Lauraceae","family_zh":"樟科","iucn":"LC","langs":25,"desc_zh":"北美檫树（学名：Sassafras albidum）或称美国檫树、美洲檫木、白檫、红檫、黄樟等，为樟科檫树属，原产于北美洲东部，以美国缅因州、加拿大安大略省为北界，南至佛罗里达州，西至爱荷华州及德克萨斯州东部，常见于海拔1500公尺左右的落叶林中，北美檫树原本曾是威斯康辛州的原生植物，但现今此树种已于该地区消失。","desc_en":"Sassafras albidum (sassafras, white sassafras, red sassafras, or silky sassafras) is a species of Sassafras native to eastern North America. It has a number of culinary and other uses.","img":"images/35.jpg","thumb":"images/t/35.jpg","file":"Sassafras7.jpg","ar":0.75,"py":"beimeichashu bmcs","cr_by":"Wowbobwow12 at English Wikipedia","cr_lic":"CC BY-SA 3.0","cr_licurl":"http://creativecommons.org/licenses/by-sa/3.0/","habit":null,"origin":["北美洲"]},{"id":36,"zh":"无根藤","en":"Cassytha filiformis","sci":"Cassytha filiformis","order_en":"Laurales","order_zh":"樟目","family_en":"Lauraceae","family_zh":"樟科","iucn":null,"langs":22,"desc_zh":"无根藤 （学名：Cassytha filiformis），或称为无根草，为樟科植物中少数的藤本寄生植物，属于泛热带地区分布的种类。某些地区用全草作为利尿剂；由于植株具黏液，亦供作造纸工业里的胶使用。","desc_en":"Cassytha filiformis or love-vine is an orangish, wiry, parasitic vine in the family Lauraceae. It is found in coastal forests of warm tropical regions worldwide including the Americas, Indomalaya, Australasia, Polynesia and tropical Africa.","img":"images/36.jpg","thumb":"images/t/36.jpg","file":"Cassytha filiformis 1.jpg","ar":0.608,"py":"wugenteng wgt","cr_by":"Carl Friedrich Philipp von Martius","cr_lic":"Public domain","cr_licurl":null,"habit":"藤本","origin":["亚洲","非洲","大洋洲"]},{"id":37,"zh":"加州月桂","en":"Umbellularia californica","sci":"Umbellularia californica","order_en":"Laurales","order_zh":"樟目","family_en":"Lauraceae","family_zh":"樟科","iucn":"LC","langs":21,"desc_zh":"加州月桂（学名：Umbellularia californica），又名伞桂，是属于樟科加州月桂属的一种大乔木。其种加词“californica”意为“美国加利福尼亚的”。原产于美国加利福尼亚州的海岸森林，小部分延伸至俄勒冈州内，在俄勒冈州称它为俄勒冈香桃木（Oregon Myrtle）。 加州月桂属，又名伞桂属，是一个单种属，属内只有加州月桂一个种。","desc_en":"Umbellularia californica is a large hardwood tree native to coastal forests and the Sierra foothills of California, and extending into the coastal forests southwestern Oregon and the mountains of northwestern Baja California.","img":"images/37.jpg","thumb":"images/t/37.jpg","file":"Umbellularia californica 02.jpg","ar":1.334,"py":"jiazhouyuegui jzyg","cr_by":null,"cr_lic":"Public domain","cr_licurl":null,"habit":"乔木","origin":["北美洲"]},{"id":38,"zh":"山鸡椒","en":"Litsea cubeba","sci":"Litsea cubeba","order_en":"Laurales","order_zh":"樟目","family_en":"Lauraceae","family_zh":"樟科","iucn":"LC","langs":20,"desc_zh":"山胡椒（学名：Litsea cubeba），又名山苍树、山胡椒、木姜子、豆豉姜，是樟科木姜子属的一种落叶或常绿灌木至小乔木。本种由葡萄牙植物学家若昂·德·洛雷罗于1790年以 Laurus cubeba 之名首次发表，刊载于《Flora Cochinchinensis》第1卷第252页；1806年，荷兰真菌学家克里斯蒂安·亨德里克·佩尔松将其转移至木姜子属，建立现行学名组合。","desc_en":"Litsea cubeba is a species of evergreen tree in the family Lauraceae. It is a shrub that grows up to 5–12 meters high. It is sometimes referred to by the common names the aromatic litsea, may chang, mountain pepper (山胡椒; pinyin: shānhújiāo), mujiangzi (木姜子; pi…","img":"images/38.jpg","thumb":"images/t/38.jpg","file":"Litseacubebaflowers.jpg","ar":0.669,"py":"shanjijiao sjj","cr_by":"LiChieh Pan / Flickr user: plj.johnny ( https://www.flickr.com/photos/plj/ )","cr_lic":"CC BY 2.0","cr_licurl":"https://creativecommons.org/licenses/by/2.0","habit":"乔木","origin":null},{"id":39,"zh":"蜡梅","en":"Chimonanthus praecox","sci":"Chimonanthus praecox","order_en":"Laurales","order_zh":"樟目","family_en":"Calycanthaceae","family_zh":"蜡梅科","iucn":"LC","langs":22,"desc_zh":"蜡梅（学名：Chimonanthus praecox）是蜡梅科蜡梅属的植物。原产地中国，生长于海拔300米至700米的地区，常生于山地林中。","desc_en":"Chimonanthus praecox, also known as wintersweet and Japanese allspice, is a species of flowering plant in the genus Chimonanthus of the family Calycanthaceae. The plant is native to China and is known as làméi (蠟梅) in Chinese.","img":"images/39.jpg","thumb":"images/t/39.jpg","file":"Frutti Chimonanthus praecox.jpg","ar":1.333,"py":"lamei lm","cr_by":"Luigi Chiesa","cr_lic":"CC BY-SA 3.0","cr_licurl":"http://creativecommons.org/licenses/by-sa/3.0/","habit":"灌木","origin":["亚洲"]},{"id":40,"zh":"奇子树","en":"Idiospermum australiense","sci":"Idiospermum australiense","order_en":"Laurales","order_zh":"樟目","family_en":"Calycanthaceae","family_zh":"蜡梅科","iucn":null,"langs":20,"desc_zh":"奇子树是奇子树属（又名澳樟属）中的唯一种，生长在澳大利亚昆士兰州热带雨林中，一般为10-100株一起聚居在雨林中低洼潮湿区域，是1亿2千万年前出现的原始被子植物。 奇子树是常绿乔木，一般为20-30米高；单叶对生或3-4个螺旋排列，12-25厘米长，5-9厘米宽；花的直径为4-5厘米，花萼红色，虫媒，两性，但有半数的花没有雌蕊；果实为核果，直径8厘米，分为3-4瓣，有毒。","desc_en":"Idiospermum is a monotypic genus (that is, a genus that contains only one species) in the family Calycanthaceae. The sole included species is Idiospermum australiense − commonly known as ribbonwood, dinosaur tree, or the misnomer idiotfruit − which is found on…","img":"images/40.jpg","thumb":"images/t/40.jpg","file":"CSIRO ScienceImage 1104 Idiospermum australiense.jpg","ar":0.915,"py":"qizishu qzs","cr_by":"division, CSIRO","cr_lic":"CC BY 3.0","cr_licurl":"https://creativecommons.org/licenses/by/3.0","habit":"乔木","origin":["大洋洲"]},{"id":41,"zh":"胡椒","en":"black pepper","sci":"Piper nigrum","order_en":"Piperales","order_zh":"胡椒目","family_en":"Piperaceae","family_zh":"胡椒科","iucn":null,"langs":136,"desc_zh":"胡椒（学名：Piper nigrum），又名黑川，是胡椒属的开花藤本植物，果实在晒干后通常可作为香料和调味料使用，称为黑胡椒。同样的果实还是白胡椒（果实去皮）、红胡椒与绿胡椒（未成熟果实）的制作原料。胡椒原产于南印度，在当地和其他热带地区都有着广泛的种植。胡椒的果实在熟透时会呈现黑红色，并包含一粒种子；果实在晒干后会成为直径5毫米的胡椒子核果。 干燥的“胡椒粉”是欧洲菜的常用香料，自古以来，胡椒就因其在调味与医学上的双重价值而备受珍视。","desc_en":"Black pepper (Piper nigrum) is a flowering vine in the family Piperaceae, cultivated for its fruit (the peppercorn), which is usually dried and used as a spice and seasoning.","img":"images/41.jpg","thumb":"images/t/41.jpg","file":"Piper nigrum - Köhler–s Medizinal-Pflanzen-107.jpg","ar":0.783,"py":"hujiao hj","cr_by":"Franz Eugen Köhler, Köhler's Medizinal-Pflanzen","cr_lic":"Public domain","cr_licurl":null,"habit":"藤本","origin":["亚洲"]},{"id":42,"zh":"蒌叶","en":"betel","sci":"Piper betle","order_en":"Piperales","order_zh":"胡椒目","family_en":"Piperaceae","family_zh":"胡椒科","iucn":null,"langs":81,"desc_zh":"蒌叶（学名：Piper betle），又名荖藤，俗称蒌子、蒟子、蒟酱、芙畱、荖叶、荜茇、槟榔叶，是一种胡椒科多年生藤本植物，茎为蔓生，全株无毛，叶子呈椭圆形，花为绿色，有香味。原产地是印尼；中国大陆在南方和台湾均有种植。","desc_en":"Betel (Piper betle) is a species of flowering plant in the pepper family Piperaceae, native to Southeast Asia. It is an evergreen, dioecious vine, with glossy heart-shaped leaves and white catkins.","img":"images/42.jpg","thumb":"images/t/42.jpg","file":"Betel leaves for selling in the market 01.jpg","ar":1.333,"py":"louye ly","cr_by":"Suyash Dwivedi","cr_lic":"CC BY-SA 4.0","cr_licurl":"https://creativecommons.org/licenses/by-sa/4.0","habit":"藤本","origin":["亚洲"]},{"id":43,"zh":"卡瓦胡椒","en":"Piper methysticum","sci":"Piper methysticum","order_en":"Piperales","order_zh":"胡椒目","family_en":"Piperaceae","family_zh":"胡椒科","iucn":null,"langs":51,"desc_zh":"卡瓦醉椒（英语：kava 或 kava-kava；学名：Piper methysticum），亦译为卡瓦胡椒、毒椒等，卡瓦的其他名称包括' awa（夏威夷），' waava（萨摩亚），yaqona（斐济），sakau（波纳佩）和 malok 或 malogu（瓦努阿图的部分地区）。为胡椒科灌木，主产于西太平洋地区。从美拉尼西亚至波利尼西亚之间广阔的地域——斐济、汤加、萨摩亚等地均为常见的嗜好品。","desc_en":"Kava or kava kava (Piper methysticum: Latin 'pepper' and Latinized Greek 'intoxicating') is a plant in the pepper family, native to the Pacific Islands. The name kava is from Tongan and Marquesan, meaning 'bitter'.","img":"images/43.jpg","thumb":"images/t/43.jpg","file":"Starr 040318-0058 Piper methysticum.jpg","ar":0.75,"py":"kawahujiao kwhj","cr_by":"Forest & Kim Starr","cr_lic":"CC BY 3.0","cr_licurl":"https://creativecommons.org/licenses/by/3.0","habit":null,"origin":["大洋洲"]},{"id":44,"zh":"荜拔","en":"Piper longum","sci":"Piper longum","order_en":"Piperales","order_zh":"胡椒目","family_en":"Piperaceae","family_zh":"胡椒科","iucn":null,"langs":47,"desc_zh":"荜拔（学名：Piper longum）是胡椒科胡椒属的植物。分布在斯里兰卡、马来西亚、印度、尼泊尔、越南以及中国大陆的福建、云南、广西、广东等地，生长于海拔580米的地区，多生在疏荫杂木林中，目前尚未由人工引种栽培。","desc_en":"Long pepper (Piper longum), sometimes called Indian long pepper or pippali, is a flowering vine in the family Piperaceae, cultivated for its fruit, which is usually dried and used as a spice and seasoning.","img":"images/44.jpg","thumb":"images/t/44.jpg","file":"Piper longum.jpg","ar":1.269,"py":"biba bb","cr_by":null,"cr_lic":"CC BY-SA 3.0","cr_licurl":"http://creativecommons.org/licenses/by-sa/3.0/","habit":"藤本","origin":["亚洲"]},{"id":45,"zh":"荜澄茄","en":"Piper cubeba","sci":"Piper cubeba","order_en":"Piperales","order_zh":"胡椒目","family_en":"Piperaceae","family_zh":"胡椒科","iucn":null,"langs":45,"desc_zh":"荜澄茄（学名：Piper cubeba），又名尾胡椒（英语：tailed pepper），是胡椒属的一种植物，被栽培以获取其果实与精油。它主要生长于爪哇岛与苏门答腊岛地区，因此有时也被叫做爪哇胡椒。其果实在成熟之前被采集，并被仔细地加以干燥处理。荜澄茄的贸易由其干燥的浆果组成，干浆果在外观上类似于黑胡椒，但比黑胡椒多了梗柄——即“尾胡椒”的“尾巴”。在干燥过程中，果皮会产生褶皱，颜色也会从灰棕色变为黑色。","desc_en":"Piper cubeba, cubeb or tailed pepper is a plant in the genus Piper, cultivated for its fruit and essential oil. It is mostly grown in Java and Sumatra, hence sometimes called Java pepper. The fruits are gathered before they are ripe, and carefully dried.","img":"images/45.jpg","thumb":"images/t/45.jpg","file":"Piper cubeba muda.jpg","ar":0.75,"py":"bichengqie bcq","cr_by":"Kembangraps","cr_lic":"CC BY-SA 3.0","cr_licurl":"http://creativecommons.org/licenses/by-sa/3.0/","habit":null,"origin":null},{"id":46,"zh":"草胡椒","en":"Peperomia pellucida","sci":"Peperomia pellucida","order_en":"Piperales","order_zh":"胡椒目","family_en":"Piperaceae","family_zh":"胡椒科","iucn":null,"langs":25,"desc_zh":"草胡椒（学名：Peperomia pellucida）为胡椒科草胡椒属下的一个种。马来西亚亦称为软骨草。其种加词“pellucida”意为“透明的”。一年生，高可达40厘米。在南美洲和菲律宾等地被用作草药。","desc_en":"Peperomia pellucida (also known by common names pepper elder, shining bush plant, crab claw herb, and man to man) is an annual, shallow-rooted herb, usually growing to a height of about 15 to 45 cm (6 to 18 inches), it is characterized by succulent stems, shin…","img":"images/46.jpg","thumb":"images/t/46.jpg","file":"(arya) Peperomia pellucida (suruhan) in Pilangsari 2019 4.jpg","ar":1,"py":"caohujiao chj","cr_by":"Aris riyanto","cr_lic":"CC BY-SA 4.0","cr_licurl":"https://creativecommons.org/licenses/by-sa/4.0","habit":"多肉","origin":null},{"id":47,"zh":"欧细辛","en":"Asarum europaeum","sci":"Asarum europaeum","order_en":"Piperales","order_zh":"胡椒目","family_en":"Aristolochiaceae","family_zh":"马兜铃科","iucn":null,"langs":46,"desc_zh":null,"desc_en":"Asarum europaeum, known as asarabacca, European wild ginger, hazelwort, and wild spikenard, historically cabarick, is a species of flowering plant in the birthwort family Aristolochiaceae, native to parts of temperate Europe, and also cultivated in gardens.","img":"images/47.jpg","thumb":"images/t/47.jpg","file":"Asarum europaeum 170406.jpg","ar":0.75,"py":"ouxixin oxx","cr_by":"Bernd Haynold","cr_lic":"CC BY 2.5","cr_licurl":"https://creativecommons.org/licenses/by/2.5","habit":"草本","origin":["欧洲"]},{"id":48,"zh":"欧洲马兜铃","en":"Aristolochia clematitis","sci":"Aristolochia clematitis","order_en":"Piperales","order_zh":"胡椒目","family_en":"Aristolochiaceae","family_zh":"马兜铃科","iucn":null,"langs":42,"desc_zh":"铁线莲状马兜铃（Aristolochia clematitis，又称欧洲催生草）是马兜铃科缠绕草本植物，原产于欧洲。铁线莲状马兜铃叶心形，具淡黄色管状花，通过缠绕其他植物向光生长。","desc_en":"Aristolochia clematitis, or European birthwort, is a twining herbaceous plant in the family Aristolochiaceae, which is native to most of central and southern Europe and parts of western Asia, and naturalised further north in Europe.","img":"images/48.jpg","thumb":"images/t/48.jpg","file":"Aristolochia clematitis 20041007 2546.jpg","ar":0.75,"py":"ouzhoumadouling ozmdl","cr_by":"Georg Slickers","cr_lic":"CC BY-SA 4.0","cr_licurl":"https://creativecommons.org/licenses/by-sa/4.0","habit":"藤本","origin":["亚洲","欧洲"]},{"id":49,"zh":"非洲白鹭花","en":"Hydnora africana","sci":"Hydnora africana","order_en":"Piperales","order_zh":"胡椒目","family_en":"Aristolochiaceae","family_zh":"马兜铃科","iucn":null,"langs":24,"desc_zh":"非洲白鹭花（学名：Hydnora africana）是一种寄生于大戟科根部的植物，，并取其营养维生，分布于非洲南部。全株无叶绿素，长年只在泥中生长，只有散发含硫化物，气味如粪的肉质花会在暴雨后露出地面，以吸引粪金龟和葬甲科甲虫到花中。花内设有「陷阱」去暂时囚禁甲虫，以增加为其传播花粉的机会。果实长于土内，需要两年成熟，果内藏约二万籽，可食用，味道、口感如薯，亦可提炼成鱼网的收敛剂。 其种加词“africana”意为“非洲的”。","desc_en":"Hydnora africana is an achlorophyllous plant in the subfamily Hydnoroideae, native to southern Africa that is parasitic on the roots of members of the family Euphorbiaceae. It is also called jakkalskos or jackal food.","img":"images/49.jpg","thumb":"images/t/49.jpg","file":"HydnoraAfricanaKarasburgDistrictNamibia2002Musselman.jpg","ar":1.331,"py":"feizhoubailuhua fzblh","cr_by":"Lytton John Musselman","cr_lic":"CC BY-SA 3.0","cr_licurl":"http://creativecommons.org/licenses/by-sa/3.0/","habit":null,"origin":["非洲"]},{"id":50,"zh":"短蕊花","en":"Lactoris fernandeziana","sci":"Lactoris fernandeziana","order_en":"Piperales","order_zh":"胡椒目","family_en":"Aristolochiaceae","family_zh":"马兜铃科","iucn":null,"langs":20,"desc_zh":"囊粉花（学名：Lactoris fernandeziana）又名短蕊花，是囊粉花属的唯一种，属木兰藤目马兜铃科，仅生长在智利东海岸的胡安-费尔南德斯群岛，是当地的特有种。 囊粉花是一种含芳香油的灌木，单叶互生，叶片有腺点，有托叶；花小，花瓣3裂；核果3裂。 1981年的克朗奎斯特分类法将其放在木兰目中，自成一个囊粉花科（Lactoridaceae），1998年根据基因亲缘关系分类的APG 分类法认为应该分到胡椒目中，而APG II 分类…","desc_en":"Lactoris fernandeziana is a flowering shrub endemic to the cloud forest of Masatierra – Robinson Crusoe Island, of the Juan Fernández Islands archipelago of Chile. It is the only extant species in the genus Lactoris.","img":"images/50.jpg","thumb":"images/t/50.jpg","file":"Reportonscientif188501grea 1101.jpg","ar":0.753,"py":"duanruihua drh","cr_by":"Matilda Smith","cr_lic":"Public domain","cr_licurl":null,"habit":"灌木","origin":["南美洲"]},{"id":51,"zh":"鱼腥草","en":"Houttuynia cordata","sci":"Houttuynia cordata","order_en":"Piperales","order_zh":"胡椒目","family_en":"Saururaceae","family_zh":"三白草科","iucn":null,"langs":26,"desc_zh":"鱼腥草（学名：Houttuynia cordata），又名折耳根 、截儿根、猪鼻拱、䔃（zǔ）、蕺菜及臭草、岑草、臭臊草，客家话称之狗贴耳、臭臊草，台语称臭腥草，在分类学上属双子叶植物三白草科蕺菜属，是一种略带鱼腥味的草本植物。","desc_en":"Houttuynia cordata, also known as fish mint, fish leaf, rainbow plant, chameleon plant, heart leaf, fish wort, or Chinese lizard tail, is one of two species in the genus Houttuynia (the other being H. emeiensis).","img":"images/51.jpg","thumb":"images/t/51.jpg","file":"Houttuynia cordata Pstrolistka sercowata 2009-07-11 02.jpg","ar":1.001,"py":"yuxingcao yxc","cr_by":"Agnieszka Kwiecień, Nova","cr_lic":"CC BY-SA 4.0","cr_licurl":"https://creativecommons.org/licenses/by-sa/4.0","habit":null,"origin":["亚洲"]},{"id":52,"zh":"冬木","en":"Drimys winteri","sci":"Drimys winteri","order_en":"Canellales","order_zh":"白樟目","family_en":"Winteraceae","family_zh":"林仙科","iucn":"LC","langs":22,"desc_zh":null,"desc_en":"Drimys winteri, also known as Winter's bark, foye and canelo, is a slender species of tree in the family Winteraceae, growing up to 20 m (66 ft) tall. It is native to the Magellanic and Valdivian temperate forests of Chile and Argentina, where it is a dominant…","img":"images/52.jpg","thumb":"images/t/52.jpg","file":"Drimys winteri.jpg","ar":1.494,"py":"dongmu dm","cr_by":"Eric Hunt","cr_lic":"CC BY 2.5","cr_licurl":"https://creativecommons.org/licenses/by/2.5","habit":"乔木","origin":["南美洲"]},{"id":53,"zh":"菖蒲","en":"Acorus calamus","sci":"Acorus calamus","order_en":"Acorales","order_zh":"菖蒲目","family_en":"Acoraceae","family_zh":"菖蒲科","iucn":"LC","langs":94,"desc_zh":"菖蒲（学名：Acorus calamus），也叫做水菖蒲、白菖蒲、藏菖蒲，古名蒖、䒢，是一种菖蒲科的水生草本植物。菖蒲分布很广，整个温带基本都能找到它，中国各地也都有分布。 菖蒲可以提取芳香油；端午节有把菖蒲叶和艾草捆一起插于簷下的习俗；根茎可制香味料。亦称为尧韭。菖蒲油可用于医药、美容、香水、烹饪和家庭用途。","desc_en":"Acorus calamus (also called sweet flag, sway or muskrat root, among many other common names) is a species of flowering plant. It is a tall wetland monocot of the family Acoraceae, in the genus Acorus.","img":"images/53.jpg","thumb":"images/t/53.jpg","file":"Acorus calamus1.jpg","ar":0.75,"py":"changpu cp","cr_by":"J.F. Gaffard, Autoreille, France","cr_lic":"CC BY-SA 3.0","cr_licurl":"http://creativecommons.org/licenses/by-sa/3.0/","habit":null,"origin":null},{"id":54,"zh":"芋","en":"Colocasia esculenta","sci":"Colocasia esculenta","order_en":"Alismatales","order_zh":"泽泻目","family_en":"Araceae","family_zh":"天南星科","iucn":"LC","langs":111,"desc_zh":"芋（学名：Colocasia esculenta）或芋艿，俗称「芋头」，为天南星科芋属植物，其球状地下茎（块茎）可食用亦可入药，在大洋洲诸岛是玻里尼西亚人传统主要粮食；全年皆有产，花期在秋季。最早栽种的印度人约于西元前5,000年引入了来自马来西亚湿地的野生芋头，尔后又传到埃及。","desc_en":"Taro (; Colocasia esculenta) is a root vegetable. It is the most widely cultivated species of several plants in the family Araceae that are used as vegetables for their corms, leaves, stems and petioles.","img":"images/54.jpg","thumb":"images/t/54.jpg","file":"(MHNT) Colocasia esculenta - Les Martels, Giroussens Tarn.jpg","ar":1.485,"py":"yu y","cr_by":"Didier Descouens","cr_lic":"CC BY-SA 4.0","cr_licurl":"https://creativecommons.org/licenses/by-sa/4.0","habit":null,"origin":["亚洲","非洲"]},{"id":55,"zh":"巨花魔芋","en":"Amorphophallus titanum","sci":"Amorphophallus titanum","order_en":"Alismatales","order_zh":"泽泻目","family_en":"Araceae","family_zh":"天南星科","iucn":"EN","langs":57,"desc_zh":"巨花魔芋（学名：Amorphophallus titanum），又名尸花、泰坦魔芋，是天南星科魔芋属植物。 巨花魔芋具有世界上最大的不分支花序；还有世界最高的花，贝叶棕具有世界最大的花序；世界上最大的花朵则为大花草的花。巨花魔芋的印尼文名称叫做「bunga bangkai」，「bunga」意为「花」，「bangkai」意为「尸体」，巨花魔芋在开花的时候会散发一股类似尸臭的味道，因此又有「尸花」的别名。","desc_en":"Amorphophallus titanum, the titan arum, is a flowering plant in the family Araceae. It has a large unbranched inflorescence, a tall single leaf branched like a tree, and a heavy tuber which enables the plant to produce the inflorescence. A.","img":"images/55.jpg","thumb":"images/t/55.jpg","file":"Arum titan au jardin botanique de Nancy, floraison 2025.jpg","ar":0.665,"py":"juhuamoyu jhmy","cr_by":"Le Commissaire","cr_lic":"CC BY-SA 4.0","cr_licurl":"https://creativecommons.org/licenses/by-sa/4.0","habit":"乔木","origin":["亚洲"]},{"id":56,"zh":"绿萝","en":"Epipremnum aureum","sci":"Epipremnum aureum","order_en":"Alismatales","order_zh":"泽泻目","family_en":"Araceae","family_zh":"天南星科","iucn":null,"langs":50,"desc_zh":"绿萝（学名：Epipremnum aureum），又名黄金葛，是天南星科、麒麟叶属的一种多年生木质藤本植物，原产于法属波利尼西亚的莫雷阿岛，随着人类引进而在东南亚、南亚、华南、所罗门群岛、非洲、西印度群岛等地的热带及亚热带森林中归化，并在部分地区成为入侵物种，影响一些地方的生态平衡。喜荫蔽潮湿的环境，生命力极强，在黑暗无光的条件下亦能生存。","desc_en":"Epipremnum aureum is a species in the arum family Araceae, native to Mo'orea in the Society Islands of French Polynesia. The species is a popular houseplant in temperate regions, but has also become naturalised in tropical and sub-tropical forests worldwide, i…","img":"images/56.png","thumb":"images/t/56.png","file":"Epipremnum aurem flower.png","ar":0.506,"py":"lluo ll","cr_by":"Chiu-Yueh Hung, Jie Qiu, Ying-Hsuan Sun, Jianjun Chen, Farooqahmed S. Kittur, Richard J. Henny, Gulei Jin, Longjiang Fan","cr_lic":"CC BY-SA 4.0","cr_licurl":"https://creativecommons.org/licenses/by-sa/4.0","habit":"藤本","origin":["大洋洲"]},{"id":57,"zh":"大薸","en":"Pistia stratiotes","sci":"Pistia stratiotes","order_en":"Alismatales","order_zh":"泽泻目","family_en":"Araceae","family_zh":"天南星科","iucn":"LC","langs":49,"desc_zh":"大薸（学名：Pistia stratiotes），又名大萍、大蕊萍、大莲、水芙蓉，为天南星科大薸属的唯一物种。","desc_en":"Pistia is a genus of aquatic plants in the arum family, Araceae. It is the sole genus in the tribe Pistieae which reflects its systematic isolation within the family.","img":"images/57.jpg","thumb":"images/t/57.jpg","file":"Pistia stratiotes0.jpg","ar":1.333,"py":"dapiao dp","cr_by":"Kurt Stüber [1]","cr_lic":"CC BY-SA 3.0","cr_licurl":"http://creativecommons.org/licenses/by-sa/3.0/","habit":null,"origin":null},{"id":58,"zh":"浮萍","en":"Lemna minor","sci":"Lemna minor","order_en":"Alismatales","order_zh":"泽泻目","family_en":"Araceae","family_zh":"天南星科","iucn":"LC","langs":48,"desc_zh":"浮萍（学名：Lemna minor），别称青萍、水薸 ，是天南星科青萍属水生植物。广布于世界各地，池塘、湖泊内常见。 其种加词“minor”意为“较小的”。","desc_en":"Lemna minor, the common duckweed or lesser duckweed, is a species of aquatic freshwater plant in the subfamily Lemnoideae of the arum family Araceae. L. minor is used as animal fodder, bioremediator, for wastewater nutrient recovery, and other applications.","img":"images/58.jpg","thumb":"images/t/58.jpg","file":"Eendekroos dicht bijeen.JPG","ar":1.333,"py":"fuping fp","cr_by":null,"cr_lic":"CC BY-SA 3.0","cr_licurl":"http://creativecommons.org/licenses/by-sa/3.0/","habit":null,"origin":null},{"id":59,"zh":"水芋","en":"Calla palustris","sci":"Calla palustris","order_en":"Alismatales","order_zh":"泽泻目","family_en":"Araceae","family_zh":"天南星科","iucn":"LC","langs":48,"desc_zh":"水芋（学名：Calla palustris）为天南星科水芋属的唯一种。分布于美洲的北温带和亚北极地区、亚洲、欧洲以及中国大陆的内蒙古、吉林、辽宁、黑龙江等地，生长于海拔200米至1,100米的地区，见于草甸或沼泽等浅水域，目前尚未由人工引种栽培，含有含量非常高的草酸，属于有毒的草酸钙结晶。","desc_en":"Calla is a genus of flowering plant in the family Araceae, containing the single species Calla palustris (bog arum, marsh calla, wild calla, squaw claw, and water-arum). It is the only genus in the tribe Calleae of the subfamily Aroideae.","img":"images/59.jpg","thumb":"images/t/59.jpg","file":"Calla palustris2.jpg","ar":1.333,"py":"shuiyu sy","cr_by":"Kurt Stüber [1]","cr_lic":"CC BY-SA 3.0","cr_licurl":"http://creativecommons.org/licenses/by-sa/3.0/","habit":null,"origin":null},{"id":60,"zh":"斑叶疆南星","en":"Arum maculatum","sci":"Arum maculatum","order_en":"Alismatales","order_zh":"泽泻目","family_en":"Araceae","family_zh":"天南星科","iucn":null,"langs":47,"desc_zh":null,"desc_en":"Arum maculatum, commonly known as cuckoopint, jack-in-the-pulpit and other names (see common names), is a woodland flowering plant species in the family Araceae. It is native across most of Europe, as well as Eastern Turkey and the Caucasus.","img":"images/60.jpg","thumb":"images/t/60.jpg","file":"Arum maculatum 0 700.jpg","ar":0.913,"py":"banyejiangnanxing byjnx","cr_by":null,"cr_lic":"CC BY-SA 3.0","cr_licurl":"http://creativecommons.org/licenses/by-sa/3.0/","habit":null,"origin":["亚洲","欧洲"]},{"id":61,"zh":"龟背竹","en":"Monstera deliciosa","sci":"Monstera deliciosa","order_en":"Alismatales","order_zh":"泽泻目","family_en":"Araceae","family_zh":"天南星科","iucn":null,"langs":46,"desc_zh":"龟背芋（学名：Monstera deliciosa），又称为龟背竹、凤梨蕉、蓬莱蕉及电信兰，是天南星科龟背芋属植物。 龟背芋适应性强，性喜温暖，潮湿的环境，但也耐阴、耐阳及有一定的耐旱性，原产于墨西哥南部至危地马拉的热带雨林生境。为著名大型观赏植物。","desc_en":"Monstera deliciosa, the Swiss cheese plant or split-leaf philodendron, is a species of flowering plant. The common name \"Swiss cheese plant\" is also used for the related species from the same genus, Monstera adansonii.","img":"images/61.jpg","thumb":"images/t/61.jpg","file":"Monstera deliciosa2.jpg","ar":0.88,"py":"guibeizhu gbz","cr_by":null,"cr_lic":"CC BY-SA 3.0","cr_licurl":"http://creativecommons.org/licenses/by-sa/3.0/","habit":null,"origin":["北美洲"]},{"id":62,"zh":"疣柄魔芋","en":"Amorphophallus paeoniifolius","sci":"Amorphophallus paeoniifolius","order_en":"Alismatales","order_zh":"泽泻目","family_en":"Araceae","family_zh":"天南星科","iucn":"LC","langs":44,"desc_zh":"疣柄魔芋（学名：Amorphophallus paeoniifolius，英语：elephant foot yam）为天南星科魔芋属植物。分布于非洲、马达加斯加、大洋洲、新几内亚、南亚、东南亚、台湾、越南以及中国大陆的广西、云南、广东等地，生长于海拔180米至750米的地区，多生在灌丛、江边草坡及荒地。","desc_en":"Amorphophallus paeoniifolius, commonly known as the elephant foot yam or whitespot giant arum, is a tropical plant native to Island Southeast Asia. It is cultivated for its edible tubers in Southeast Asia, South Asia, Madagascar, New Guinea, and the Pacific is…","img":"images/62.jpg","thumb":"images/t/62.jpg","file":"ചേന.jpg","ar":1.333,"py":"youbingmoyu ybmy","cr_by":"Challiyan at Malayalam Wikipedia","cr_lic":"CC BY-SA 2.5","cr_licurl":"https://creativecommons.org/licenses/by-sa/2.5","habit":null,"origin":["亚洲"]},{"id":63,"zh":"蒟蒻","en":"Amorphophallus konjac","sci":"Amorphophallus konjac","order_en":"Alismatales","order_zh":"泽泻目","family_en":"Araceae","family_zh":"天南星科","iucn":null,"langs":41,"desc_zh":"蒟（jǔ）蒻（ruò），又名魔芋，是天南星科魔芋属的多年生宿根性块茎草本植物。","desc_en":"Amorphophallus konjac, commonly known as juruo (Chinese: 蒟蒻; pinyin: jǔruò), konnyaku or konjac, or moyu (Chinese: 魔芋; pinyin: móyù), is a species of flowering plant in the family Araceae.","img":"images/63.png","thumb":"images/t/63.png","file":"Amorphophallus konjac CBM.png","ar":0.815,"py":"juruo jr","cr_by":"Walter Hood Fitch","cr_lic":"Public domain","cr_licurl":null,"habit":"草本","origin":["亚洲"]},{"id":64,"zh":"意大利海芋","en":"Arum italicum","sci":"Arum italicum","order_en":"Alismatales","order_zh":"泽泻目","family_en":"Araceae","family_zh":"天南星科","iucn":null,"langs":37,"desc_zh":null,"desc_en":"Arum italicum is a species of flowering herbaceous perennial plant in the family Araceae, also known as Italian arum and Italian lords-and-ladies. It is native to the British Isles and much of the Mediterranean region, the Caucasus, Canary Islands, Madeira and…","img":"images/64.jpg","thumb":"images/t/64.jpg","file":"Cuckoo Pint Arum italicum Young Plant 2874px.jpg","ar":1.174,"py":"yidalihaiyu ydlhy","cr_by":"Photo by and (c)2007 Derek Ramsey ( Ram-Man )","cr_lic":"GFDL 1.2","cr_licurl":"http://www.gnu.org/licenses/old-licenses/fdl-1.2.html","habit":"草本","origin":["亚洲","欧洲","非洲"]},{"id":65,"zh":"美铁芋","en":"Zamioculcas zamiifolia","sci":"Zamioculcas zamiifolia","order_en":"Alismatales","order_zh":"泽泻目","family_en":"Araceae","family_zh":"天南星科","iucn":null,"langs":37,"desc_zh":"美铁芋（学名：Zamioculcas zamiifolia），又称金钱树、金币树、雪铁芋或泽米叶天南星，英语通称 ZZ plant，是天南星科美铁芋属（Zamioculcas）的多年生常绿草本植物。美铁芋属为单型属，本种原生于非洲东部至南部的季节性干燥热带地区。植株具有肉质地下块茎、粗壮叶柄与厚革质小叶，可储存水分；在干旱条件下还能增强景天酸代谢，以降低水分散失。","desc_en":"Zamioculcas is a genus of flowering plants in the family Araceae, containing the single species Zamioculcas zamiifolia. It is a tropical herbaceous perennial plant, and is native to eastern Africa, including Kenya, KwaZulu-Natal, Malawi, Mozambique, Tanzania,…","img":"images/65.jpg","thumb":"images/t/65.jpg","file":"Zamioculcas zamiifolia 1.jpg","ar":0.75,"py":"meitieyu mty","cr_by":"User:WeFt","cr_lic":"CC BY-SA 3.0","cr_licurl":"http://creativecommons.org/licenses/by-sa/3.0/","habit":"草本","origin":["非洲"]},{"id":66,"zh":"紫萍","en":"Spirodela polyrhiza","sci":"Spirodela polyrhiza","order_en":"Alismatales","order_zh":"泽泻目","family_en":"Araceae","family_zh":"天南星科","iucn":"LC","langs":35,"desc_zh":"紫萍（学名：Spirodela polyrhiza）又名水萍，为天南星科紫萍属下的一个种，过去曾被归类于浮萍属（Lemna）。","desc_en":"Spirodela polyrhiza (orth. var. S. polyrrhiza) is a species of duckweed known by the common names common duckmeat, greater duckweed, great duckmeat, common duckweed, giant duckweed, and duckmeat.","img":"images/66.jpg","thumb":"images/t/66.jpg","file":"Spirodela polyrrhiza marais poitevin.jpg","ar":1.5,"py":"ziping zp","cr_by":null,"cr_lic":"FAL","cr_licurl":"http://artlibre.org/licence/lal/en","habit":null,"origin":null},{"id":67,"zh":"泽泻","en":"Alisma plantago-aquatica","sci":"Alisma plantago-aquatica","order_en":"Alismatales","order_zh":"泽泻目","family_en":"Alismataceae","family_zh":"泽泻科","iucn":"LC","langs":49,"desc_zh":"泽泻（学名：Alisma plantago-aquatica），又名藚、水舄。为多年生沼生草木，属泽泻科。其根状茎较短，叶子呈长椭圆形，基生。泽泻夏季开白花，排成大型轮状分枝的圆锥花序；花两性；内外轮花被各三枚，内轮花被片花瓣状，比外轮小。瘦果侧扁，顶端有宿存花柱。野生泽泻一般生长在沼泽地，分布于中国、日本和印度等地。 泽泻的根状茎是传统中药之一。中医理论认为其性寒，具有利水渗湿的功能，主治小便不利、水肿腹满、泄泻、淋浊等症。","desc_en":"Alisma plantago-aquatica, also known as European water-plantain, common water-plantain or mad-dog weed, is a perennial flowering aquatic plant widespread across most of Europe and Asia, and apparently spread elsewhere in both the Old and New World.","img":"images/67.jpg","thumb":"images/t/67.jpg","file":"AlismaPlant1.jpg","ar":0.667,"py":"zexie zx","cr_by":"Christian Fischer","cr_lic":"CC BY-SA 3.0","cr_licurl":"https://creativecommons.org/licenses/by-sa/3.0","habit":"草本","origin":["亚洲","欧洲"]},{"id":68,"zh":"慈姑","en":"Sagittaria sagittifolia","sci":"Sagittaria sagittifolia","order_en":"Alismatales","order_zh":"泽泻目","family_en":"Alismataceae","family_zh":"泽泻科","iucn":"LC","langs":40,"desc_zh":"茨菰（学名：Sagittaria sagittifolia），又称葃菇、燕尾草、白地栗等，俗写做慈姑、慈菇，是泽泻科慈姑属的一种植物，球茎可食用。原产中国华中、华南等。分布于欧洲与亚洲、大洋洲、欧洲以及中国大陆的新疆阿勒泰等地的温带湿地，生长于海拔600米（2,000英尺）的地区，一般生长在水塘静水处、沼泽、湖边及缓流溪沟。","desc_en":"Sagittaria sagittifolia (also called arrowhead because of the shape of its leaves) is an Old World flowering plant in the family Alismataceae.","img":"images/68.jpg","thumb":"images/t/68.jpg","file":"SagittariaSagittifoliaInflorescence2.jpg","ar":0.739,"py":"cigu cg","cr_by":"Christian Fischer","cr_lic":"CC BY-SA 3.0","cr_licurl":"https://creativecommons.org/licenses/by-sa/3.0","habit":null,"origin":null},{"id":69,"zh":"水蕴藻","en":"Elodea canadensis","sci":"Elodea canadensis","order_en":"Alismatales","order_zh":"泽泻目","family_en":"Hydrocharitaceae","family_zh":"水鳖科","iucn":"LC","langs":38,"desc_zh":null,"desc_en":"Elodea canadensis (American waterweed or Canadian waterweed or pondweed) is a perennial aquatic plant, or submergent macrophyte, native to most of North America. It has been introduced widely to regions outside its native range.","img":"images/69.jpg","thumb":"images/t/69.jpg","file":"ElodeaCanadensis.jpg","ar":0.872,"py":"shuiyunzao syz","cr_by":"Christian Fischer","cr_lic":"CC BY-SA 3.0","cr_licurl":"https://creativecommons.org/licenses/by-sa/3.0","habit":"草本","origin":["北美洲"]},{"id":70,"zh":"大茨藻","en":"Najas marina","sci":"Najas marina","order_en":"Alismatales","order_zh":"泽泻目","family_en":"Hydrocharitaceae","family_zh":"水鳖科","iucn":"LC","langs":32,"desc_zh":"大茨藻（学名：Najas marina）为水鳖科茨藻属的植物。广泛分布于世界各地，生长于海拔700米至2,300米的地区，常生长在河谷、流水中、静水中、渠边、水中、湖边、湖中以及温泉中，目前尚未由人工引种栽培。","desc_en":"Najas marina is a species of aquatic plant known by the common names spiny water nymph, spiny naiad and holly-leaved naiad. It is an extremely widespread species, reported across Europe, Asia, Africa, Australia, the Americas and many oceanic islands.","img":"images/70.jpg","thumb":"images/t/70.jpg","file":"Najas marina.jpeg","ar":1.333,"py":"dacizao dcz","cr_by":"Kristian Peters -- Fabelfroh 08:57, 11 October 2006 (UTC)","cr_lic":"CC BY-SA 3.0","cr_licurl":"http://creativecommons.org/licenses/by-sa/3.0/","habit":null,"origin":null},{"id":71,"zh":"大叶藻","en":"Zostera marina","sci":"Zostera marina","order_en":"Alismatales","order_zh":"泽泻目","family_en":"Zosteraceae","family_zh":"大叶藻科","iucn":"LC","langs":40,"desc_zh":"大叶藻（学名：Zostera marina），又名鳗草，为大叶藻科大叶藻属下的一种海草，广泛分布于北美洲和欧亚大陆沿海海域。","desc_en":"Zostera marina is a flowering vascular plant species as one of many kinds of seagrass, with this species known primarily by the English name of eelgrass, with seawrack much less used, and refers to the plant after breaking loose from the submerged wetland soil…","img":"images/71.jpg","thumb":"images/t/71.jpg","file":"Zostera marina.jpeg","ar":0.75,"py":"dayezao dyz","cr_by":"Kristian Peters -- Fabelfroh 09:28, 16 September 2006 (UTC)","cr_lic":"CC BY-SA 3.0","cr_licurl":"http://creativecommons.org/licenses/by-sa/3.0/","habit":null,"origin":["亚洲","北美洲"]},{"id":72,"zh":"尾濑草","en":"Japanolirion","sci":"Japonolirion osense","order_en":"Petrosaviales","order_zh":"无叶莲目","family_en":"Petrosaviaceae","family_zh":"无叶莲科","iucn":null,"langs":18,"desc_zh":null,"desc_en":"Japonolirion is a genus of plants in the family Petrosaviaceae. There is only one known species, Japonolirion osense, endemic to Japan. It is found in grasslands, wetlands and alpine meadows.","img":"images/72.jpg","thumb":"images/t/72.jpg","file":"Japonolirion osense 1.JPG","ar":1.333,"py":"weilaicao wlc","cr_by":"Qwert1234","cr_lic":"CC BY-SA 3.0","cr_licurl":"https://creativecommons.org/licenses/by-sa/3.0","habit":null,"origin":["亚洲"]},{"id":73,"zh":"黑薯蓣","en":"Dioscorea communis","sci":"Dioscorea communis","order_en":"Dioscoreales","order_zh":"薯蓣目","family_en":"Dioscoreaceae","family_zh":"薯蓣科","iucn":null,"langs":50,"desc_zh":"黑薯苹（学名：Dioscorea communis或Tamus communis）是薯蓣科薯蓣属的一种开花植物，俗称女爵印章（lady's-seal）或黑旋花（black bindweed）。","desc_en":"Dioscorea communis or Tamus communis is a species of flowering plant in the yam family Dioscoreaceae and is commonly known as black bryony, lady's-seal or black bindweed.","img":"images/73.jpg","thumb":"images/t/73.jpg","file":"Tamus communis.jpg","ar":1.333,"py":"heishuyu hsy","cr_by":null,"cr_lic":"CC BY-SA 3.0","cr_licurl":"http://creativecommons.org/licenses/by-sa/3.0/","habit":null,"origin":null},{"id":74,"zh":"参薯","en":"Dioscorea alata","sci":"Dioscorea alata","order_en":"Dioscoreales","order_zh":"薯蓣目","family_en":"Dioscoreaceae","family_zh":"薯蓣科","iucn":null,"langs":49,"desc_zh":"参薯（学名：Dioscorea alata，台湾作大薯）又名香芋、紫薯、田薯、罐薯、银薯、脚板薯、云饼山药、土栾儿、香参、菜用土圞儿、地栗子、红牙芋，他加禄语及英文名称为 ube ，为薯蓣科薯蓣属的植物。 参薯的块茎内部呈鲜艳的深紫色，富含淀粉，可食用。其与甘薯（D. esculenta；即毛薯）、薯蓣（D. polystachya，即山药）、日本山芋（D. japonica）等同科，未经烹饪的块茎中均含有粘液。","desc_en":"Dioscorea alata – also called ube, ubi, uwhi, purple yam, or greater yam, among many other names – is a species of yam (a tuber). The tubers are usually a vivid violet-purple to bright lavender (hence the common name), but some range from creamy-white to plain…","img":"images/74.jpg","thumb":"images/t/74.jpg","file":"Starr 061106-1435 Dioscorea alata.jpg","ar":0.75,"py":"canshu cs","cr_by":"Forest & Kim Starr","cr_lic":"CC BY 3.0","cr_licurl":"https://creativecommons.org/licenses/by/3.0","habit":null,"origin":null},{"id":75,"zh":"黄独","en":"Dioscorea bulbifera","sci":"Dioscorea bulbifera","order_en":"Dioscoreales","order_zh":"薯蓣目","family_en":"Dioscoreaceae","family_zh":"薯蓣科","iucn":null,"langs":39,"desc_zh":"黄独（学名：Dioscorea bulbifera）为薯蓣科薯蓣属的植物。别名黄药、黄药子。","desc_en":"Dioscorea bulbifera (commonly known as the air potato, air yam, bitter yam, cheeky yam, potato yam, aerial yam, and parsnip yam) is a species of true yam in the yam family, Dioscoreaceae. It is native to Africa, Asia and northern Australia.","img":"images/75.jpg","thumb":"images/t/75.jpg","file":"Starr-090623-1534-Dioscorea bulbifera-bulbs and leaves-Nahiku-Maui (24966795025).jpg","ar":0.75,"py":"huangdu hd","cr_by":"Forest and Kim Starr","cr_lic":"CC BY 3.0 us","cr_licurl":"https://creativecommons.org/licenses/by/3.0/us/deed.en","habit":null,"origin":["亚洲","非洲","大洋洲"]},{"id":76,"zh":"长山药","en":"Dioscorea polystachya","sci":"Dioscorea polystachya","order_en":"Dioscoreales","order_zh":"薯蓣目","family_en":"Dioscoreaceae","family_zh":"薯蓣科","iucn":null,"langs":27,"desc_zh":"薯蓣（学名：Dioscorea polystachya）又称为「蒣」，是薯蓣科薯蓣属的一种植物。薯蓣的块茎称为山药，冬季采挖。原产地位于中国豫西北的焦作地区附近，古称怀庆府，因而也得名怀山药。","desc_en":"Dioscorea polystachya or Chinese yam (shānyào, simplified Chinese: 山药; traditional Chinese: 山藥), also called cinnamon-vine, is a species of flowering plant in the yam family. It is sometimes called Chinese potato or by its Korean name ma.","img":"images/76.jpg","thumb":"images/t/76.jpg","file":"Dioscorea polystachya (batatas).jpg","ar":1.434,"py":"changshanyao csy","cr_by":null,"cr_lic":"Public domain","cr_licurl":null,"habit":"藤本","origin":["亚洲"]},{"id":77,"zh":"露兜树","en":"Pandanus tectorius","sci":"Pandanus tectorius","order_en":"Pandanales","order_zh":"露兜树目","family_en":"Pandanaceae","family_zh":"露兜树科","iucn":"LC","langs":41,"desc_zh":"林投（学名：Pandanus tectorius），古作菻荼，别称露兜树、野菠萝、假菠萝、海菠萝等，为露兜树科露兜树属下的一个物种，原产于马来界，澳大利亚东部及太平洋三大岛群。林投具耐风、耐盐的特质，且繁殖容易，是台湾常见的海岸防风定砂植物。兰屿达悟族人称之为「Ango」；达悟族会使用林投的气生根烤或曝晒飞鱼，部分客家人则用林投气根替代麻绳制作草鞋。","desc_en":"Pandanus tectorius is a species of Pandanus (screwpine) that is native to Malesia, Papuasia, eastern Australia, and the Pacific Islands. It grows in the coastal lowlands typically near the edge of the ocean.","img":"images/77.jpg","thumb":"images/t/77.jpg","file":"Pandanus tectorius.jpg","ar":1.333,"py":"ludoushu lds","cr_by":"No machine-readable author provided. Marshman~commonswiki assumed (based on copyright claims).","cr_lic":"CC BY-SA 3.0","cr_licurl":"http://creativecommons.org/licenses/by-sa/3.0/","habit":"乔木","origin":["大洋洲"]},{"id":78,"zh":"七叶兰","en":"Pandanus amaryllifolius","sci":"Pandanus amaryllifolius","order_en":"Pandanales","order_zh":"露兜树目","family_en":"Pandanaceae","family_zh":"露兜树科","iucn":null,"langs":38,"desc_zh":"七叶兰（学名：Pandanus amaryllifolius），又名香露兜、香露兜树、斑兰叶（pandan）、香兰叶、香林投、碧血树、芳兰叶，是露兜树科露兜树属热带植物，常作为东南亚料理与糕点制作材料。野生七叶兰较为稀少，其多半为栽培作物。使用时多榨取其绿色汁液，混入面点之中，以增添绿色色泽，亦可用于食物的包装。","desc_en":"Pandanus amaryllifolius is a tropical plant in the Pandanus (screwpine) genus, which is commonly known as pandan (; Malay: [ˈpandan]). It has fragrant leaves that are used widely for flavouring in the cuisines of Southeast Asia.","img":"images/78.jpg","thumb":"images/t/78.jpg","file":"Chottola.jpg","ar":0.75,"py":"qiyelan qyl","cr_by":"Zuhairali","cr_lic":"CC BY-SA 3.0","cr_licurl":"https://creativecommons.org/licenses/by-sa/3.0","habit":null,"origin":["亚洲"]},{"id":79,"zh":"欧洲百合","en":"Lilium martagon","sci":"Lilium martagon","order_en":"Liliales","order_zh":"百合目","family_en":"Liliaceae","family_zh":"百合科","iucn":null,"langs":61,"desc_zh":"欧洲百合（学名：Lilium martagon）又名头巾百合，为百合科百合属的多年生草本植物，主要分布在欧洲、蒙古、朝鲜，西伯利亚、斯堪的纳维亚（归化）等地也有分布，是常用庭园花卉之一。欧洲百合的花朵有红、深紫、橙、白色，花瓣上分布有很多斑点，有芳香气味，每株生有数朵。","desc_en":"Lilium martagon, the martagon lily or Turk's cap lily, is a Eurasian species of lily. It has a widespread native region extending from Portugal east through Europe and Asia as far east as Mongolia.","img":"images/79.jpg","thumb":"images/t/79.jpg","file":"Lilium martagon a.jpg","ar":0.664,"py":"ouzhoubaihe ozbh","cr_by":"Schnobby","cr_lic":"CC BY-SA 3.0","cr_licurl":"https://creativecommons.org/licenses/by-sa/3.0","habit":null,"origin":["亚洲","欧洲"]},{"id":80,"zh":"圣母百合","en":"Lilium candidum","sci":"Lilium candidum","order_en":"Liliales","order_zh":"百合目","family_en":"Liliaceae","family_zh":"百合科","iucn":null,"langs":46,"desc_zh":"圣母百合（学名：Lilium candidum）是百合科百合属多年生草本植物，又名白百合、白花百合、玛丹娜百合（Madonna Lily）。原产于巴尔干半岛与西亚。种小名candidum是「纯白色」的意思，形容本种花瓣的颜色是纯白色的。纯白色的花被视为是纯洁的象征，中世纪时期的基督徒常拿这种百合花来敬礼圣母玛利亚，因此被称为圣母百合、玛丹娜百合。","desc_en":"Lilium candidum, the Madonna lily or white lily, is a plant in the true lily family. It is native to the Balkans and Middle East, and naturalized in other parts of Europe, including France, Italy, and Ukraine, and in North Africa, the Canary Islands, Mexico, a…","img":"images/80.jpg","thumb":"images/t/80.jpg","file":"Liliaceae - Lilium candidum-1.jpg","ar":0.75,"py":"shengmubaihe smbh","cr_by":"Hectonichus","cr_lic":"CC BY-SA 3.0","cr_licurl":"https://creativecommons.org/licenses/by-sa/3.0","habit":null,"origin":["亚洲","欧洲","非洲","北美洲"]},{"id":81,"zh":"花格贝母","en":"Fritillaria meleagris","sci":"Fritillaria meleagris","order_en":"Liliales","order_zh":"百合目","family_en":"Liliaceae","family_zh":"百合科","iucn":null,"langs":41,"desc_zh":"花格贝母（学名：Fritillaria meleagris）是百合科贝母属的植物，又名阿尔泰贝母、小贝母、珠鸡斑贝母、蛇头贝母。","desc_en":"Fritillaria meleagris is a Eurasian species of flowering plant in the lily family Liliaceae. Its common names include snake's head fritillary, snake's head (the original English name), chess flower, frog-cup, guinea-hen flower, guinea flower, leper lily (becau…","img":"images/81.jpg","thumb":"images/t/81.jpg","file":"Fritillaria meleagris LJ barje2.jpg","ar":0.723,"py":"huagebeimu hgbm","cr_by":"Yerpo","cr_lic":"CC BY-SA 3.0","cr_licurl":"https://creativecommons.org/licenses/by-sa/3.0","habit":"草本","origin":["欧洲"]},{"id":82,"zh":"花贝母","en":"Fritillaria imperialis","sci":"Fritillaria imperialis","order_en":"Liliales","order_zh":"百合目","family_en":"Liliaceae","family_zh":"百合科","iucn":null,"langs":38,"desc_zh":"花贝母（学名：Fritillaria imperialis），又名冠花贝母、皇冠贝母、帝王贝母、王贝母，百合科贝母属植物，种类繁多，分布全球各地，原产土耳其南部。是一种观赏类植物，中国各地种植较多，适用于庭院种植，布置花境或基础种植均可，矮生品种比较适合盆栽，观赏性很强。 其种加词“imperialis”意为“帝王的”。","desc_en":"Fritillaria imperialis, the crown imperial, imperial fritillary or Kaiser's crown, is a species of flowering plant in the lily family Liliaceae, native to a wide stretch of Asia including Turkey, Iran Iraq, Afghanistan, Pakistan, Northern India, and the Himala…","img":"images/82.jpg","thumb":"images/t/82.jpg","file":"Fritillaria imperialis.jpg","ar":0.75,"py":"huabeimu hbm","cr_by":"No machine-readable author provided. Magalhães assumed (based on copyright claims).","cr_lic":"Public domain","cr_licurl":null,"habit":null,"origin":["亚洲"]},{"id":83,"zh":"珠芽百合","en":"Lilium bulbiferum","sci":"Lilium bulbiferum","order_en":"Liliales","order_zh":"百合目","family_en":"Liliaceae","family_zh":"百合科","iucn":null,"langs":38,"desc_zh":"珠芽百合（学名：Lilium bulbiferum）是百合科百合属的一种有地下鳞茎的多年生草本植物。种小名bulbiferum的意思是「具有鳞茎的」，形容它的地上茎具有珠芽。","desc_en":"Lilium bulbiferum, common names orange lily, fire lily, Jimmy's Bane, tiger lily and St. John's Lily, is a herbaceous European lily with underground bulbs, belonging to the Liliaceae.","img":"images/83.jpg","thumb":"images/t/83.jpg","file":"0 Lilium bulbiferum - Samoëns (1).JPG","ar":1.27,"py":"zhuyabaihe zybh","cr_by":"Jean-Pol GRANDMONT","cr_lic":"CC BY-SA 3.0","cr_licurl":"https://creativecommons.org/licenses/by-sa/3.0","habit":"草本","origin":["欧洲"]},{"id":84,"zh":"猪牙花","en":"Erythronium dens-canis","sci":"Erythronium dens-canis","order_en":"Liliales","order_zh":"百合目","family_en":"Liliaceae","family_zh":"百合科","iucn":null,"langs":34,"desc_zh":null,"desc_en":"Erythronium dens-canis, the dog's-tooth-violet is a bulbous herbaceous perennial flowering plant in the family Liliaceae. It is native to central and southern Europe from Portugal to Ukraine, and locally naturalised north to Germany, Great Britain, and Ireland…","img":"images/84.jpg","thumb":"images/t/84.jpg","file":"Erythronium dens-canis (47351928761).jpg","ar":1.501,"py":"zhuyahua zyh","cr_by":"xulescu_g","cr_lic":"CC BY-SA 2.0","cr_licurl":"https://creativecommons.org/licenses/by-sa/2.0","habit":"草本","origin":["欧洲"]},{"id":85,"zh":"林生郁金香","en":"Tulipa sylvestris","sci":"Tulipa sylvestris","order_en":"Liliales","order_zh":"百合目","family_en":"Liliaceae","family_zh":"百合科","iucn":null,"langs":34,"desc_zh":null,"desc_en":"Tulipa sylvestris, the wild tulip or woodland tulip, is a Eurasian and North African species of wild tulip, a plant in the lily family. Its native range extends from Portugal and Morocco to western China, covering most of the Mediterranean and Black Sea Basins…","img":"images/85.jpg","thumb":"images/t/85.jpg","file":"Tulipa sylvestris 250406.jpg","ar":0.937,"py":"linshengyujinxiang lsyjx","cr_by":"Bernd Haynold","cr_lic":"CC BY 2.5","cr_licurl":"https://creativecommons.org/licenses/by/2.5","habit":null,"origin":["亚洲","欧洲","非洲"]},{"id":86,"zh":"郁金香","en":"Tulipa gesneriana","sci":"Tulipa gesneriana","order_en":"Liliales","order_zh":"百合目","family_en":"Liliaceae","family_zh":"百合科","iucn":null,"langs":33,"desc_zh":"郁金香（学名：Tulipa gesneriana）是百合科郁金香属的一个栽培种，又称洋荷花、旱荷花。绝大多数郁金香属栽培品种都属于本种，其起源地为中亚天山，可能起源于眼斑郁金香（学名：Tulipa agenensis）、亚美尼亚郁金香（学名：Tulipa armena）、准噶尔郁金香（学名：Tulipa suaveolens）等种的杂交。","desc_en":"Tulipa gesneriana, the Didier's tulip or garden tulip, is a species of plant in the lily family, cultivated as an ornamental in many countries because of its large, showy flowers.","img":"images/86.jpg","thumb":"images/t/86.jpg","file":"Tulipa gesneriana 001.jpg","ar":1.1,"py":"yujinxiang yjx","cr_by":"Katalinks (who is also \"Екатерина\"). Original uploader was Katalinks at ru.wikipedia","cr_lic":"Public domain","cr_licurl":null,"habit":null,"origin":null},{"id":87,"zh":"顶冰花","en":"Gagea lutea","sci":"Gagea lutea","order_en":"Liliales","order_zh":"百合目","family_en":"Liliaceae","family_zh":"百合科","iucn":null,"langs":31,"desc_zh":"顶冰花（学名：Gagea lutea）为百合科顶冰花属下的一个种。","desc_en":"Gagea lutea, known as the yellow star-of-Bethlehem, is a Eurasian flowering plant species in the family Liliaceae. It is widespread in central Europe with scattered populations in Great Britain, Spain, and Norway to Siberia and Japan.","img":"images/87.jpg","thumb":"images/t/87.jpg","file":"Gagea close-up.jpg","ar":0.75,"py":"dingbinghua dbh","cr_by":null,"cr_lic":"CC BY-SA 2.5","cr_licurl":"https://creativecommons.org/licenses/by-sa/2.5","habit":"草本","origin":["亚洲","欧洲"]},{"id":88,"zh":"秋水仙","en":"Colchicum autumnale","sci":"Colchicum autumnale","order_en":"Liliales","order_zh":"百合目","family_en":"Colchicaceae","family_zh":"秋水仙科","iucn":"LC","langs":61,"desc_zh":"秋水仙（学名：Colchicum autumnale），属于秋水仙科秋水仙属，生物碱秋水仙素就是因是从本植物首次萃取出而得名。","desc_en":"Colchicum autumnale, commonly known as autumn crocus, meadow saffron, naked boys or naked ladies, is a toxic autumn-blooming flowering plant that resembles the true crocuses, but is a member of the plant family Colchicaceae, unlike the true crocuses, which bel…","img":"images/88.jpg","thumb":"images/t/88.jpg","file":"Colchicum autumnale.jpg","ar":0.948,"py":"qiushuixian qsx","cr_by":"Stemonitis","cr_lic":"Public domain","cr_licurl":null,"habit":null,"origin":null},{"id":89,"zh":"嘉兰","en":"Gloriosa superba","sci":"Gloriosa superba","order_en":"Liliales","order_zh":"百合目","family_en":"Colchicaceae","family_zh":"秋水仙科","iucn":"LC","langs":45,"desc_zh":"嘉兰（学名：Gloriosa superba）为百合科嘉兰属下的一个种。","desc_en":"Gloriosa superba is a species of flowering plant in the family Colchicaceae. Common names include flame lily, climbing lily, creeping lily, glory lily, gloriosa lily, tiger claw, and fire lily.","img":"images/89.jpg","thumb":"images/t/89.jpg","file":"Gloriosa rothschildiana 01.jpg","ar":0.75,"py":"jialan jl","cr_by":"Jean-Jacques MILAN","cr_lic":"CC BY-SA 3.0","cr_licurl":"http://creativecommons.org/licenses/by-sa/3.0/","habit":"藤本","origin":null},{"id":90,"zh":"穗菝葜","en":"Smilax aspera","sci":"Smilax aspera","order_en":"Liliales","order_zh":"百合目","family_en":"Smilacaceae","family_zh":"菝葜科","iucn":null,"langs":34,"desc_zh":"穗菝葜（学名：Smilax aspera）为百合科菝葜属下的一个种。","desc_en":"Smilax aspera, with common names common smilax, rough bindweed, sarsaparille, and Mediterranean smilax, is a species of flowering vine in the greenbriar family.","img":"images/90.jpg","thumb":"images/t/90.jpg","file":"Smilax aspera.jpg","ar":0.75,"py":"suibaqia sbq","cr_by":null,"cr_lic":"CC BY-SA 3.0","cr_licurl":"http://creativecommons.org/licenses/by-sa/3.0/","habit":"藤本","origin":["欧洲"]},{"id":91,"zh":"菝葜","en":"Smilax china","sci":"Smilax china","order_en":"Liliales","order_zh":"百合目","family_en":"Smilacaceae","family_zh":"菝葜科","iucn":null,"langs":24,"desc_zh":"菝葜（bá qiā）（学名：Smilax china），也称金刚藤，菝葜科菝葜属，多年生藤本落叶攀附植物。生于山坡林下。分布于中国长江以南各地和日本。琉璃蛱蝶幼虫的主要食物之一就是菝葜。若种植可在3月播种。","desc_en":"Smilax china is a climbing plant species in the genus Smilax. It is native to China, Korea, Taiwan, Japan (including Ryukyu and Bonin Islands), Philippines, Vietnam, Thailand, Myanmar, and India.","img":"images/91.jpg","thumb":"images/t/91.jpg","file":"Smilax china (Montage s3).jpg","ar":1,"py":"baqia bq","cr_by":"Alpsdake","cr_lic":"CC BY-SA 4.0","cr_licurl":"https://creativecommons.org/licenses/by-sa/4.0","habit":"藤本","origin":["亚洲"]},{"id":92,"zh":"四叶重楼","en":"Paris quadrifolia","sci":"Paris quadrifolia","order_en":"Liliales","order_zh":"百合目","family_en":"Melanthiaceae","family_zh":"藜芦科","iucn":null,"langs":45,"desc_zh":"四叶重楼（学名：Paris quadrifolia）为黑药花科重楼属的植物。其种加词“quadrifolia”意为“四叶的”。分布于亚洲、欧洲以及中国大陆的新疆等地，目前尚未由人工引种栽培。","desc_en":"Paris quadrifolia, the herb Paris or true lover's knot, is a species of flowering plant in the family Melanthiaceae. It occurs in temperate and cool areas throughout Eurasia, from Spain to Yakutia, and from Iceland to Mongolia.","img":"images/92.jpg","thumb":"images/t/92.jpg","file":"Paris quadrifolia 2011 G2.jpg","ar":0.75,"py":"siyezhonglou syzl","cr_by":"George Chernilevsky","cr_lic":"Public domain","cr_licurl":null,"habit":"草本","origin":["亚洲","欧洲"]},{"id":93,"zh":"白藜芦","en":"Veratrum album","sci":"Veratrum album","order_en":"Liliales","order_zh":"百合目","family_en":"Melanthiaceae","family_zh":"藜芦科","iucn":null,"langs":42,"desc_zh":"白藜芦（学名：Veratrum album）是黑药花科藜芦属多年生草本植物，原产欧洲至西伯利亚。","desc_en":"Veratrum album, the false helleborine, white hellebore, European white hellebore, or white veratrum (syn. Veratrum lobelianum Bernh.) is a poisonous plant in the family Melanthiaceae.","img":"images/93.jpg","thumb":"images/t/93.jpg","file":"Veratrum album en Chartreuse.jpg","ar":0.75,"py":"baililu bll","cr_by":"Patrice78500","cr_lic":"CC BY-SA 3.0","cr_licurl":"https://creativecommons.org/licenses/by-sa/3.0","habit":null,"origin":["亚洲","欧洲"]},{"id":94,"zh":"杓兰","en":"Cypripedium calceolus","sci":"Cypripedium calceolus","order_en":"Asparagales","order_zh":"天门冬目","family_en":"Orchidaceae","family_zh":"兰科","iucn":"LC","langs":57,"desc_zh":"杓兰（学名：Cypripedium calceolus）为兰科杓兰属下的一个种。本来在英国广泛存在，但十九世纪时人们疯狂采集兰花，杓兰急剧减少，最后在1917年宣布其灭绝。","desc_en":"Cypripedium calceolus is a lady's-slipper orchid, and the type species of the genus Cypripedium. It is native to Europe and Asia.","img":"images/94.jpg","thumb":"images/t/94.jpg","file":"Cypripedium calceolus 03-09.jpg","ar":1.333,"py":"shaolan sl","cr_by":"No machine-readable author provided. Johan N assumed (based on copyright claims).","cr_lic":"Public domain","cr_licurl":null,"habit":null,"origin":["亚洲","欧洲"]},{"id":95,"zh":"香草","en":"Vanilla planifolia","sci":"Vanilla planifolia","order_en":"Asparagales","order_zh":"天门冬目","family_en":"Orchidaceae","family_zh":"兰科","iucn":"EN","langs":49,"desc_zh":"香荚兰（学名：Vanilla planifolia），又称香草、香子兰、香草兰、港澳地区音译作云呢拿，是香草 (香料)的一种，常用作甜品的香料。该词也指从本植物中提取的、或者人工合成的同种香料。 香荚兰的香味源自其种荚（香荚兰豆）里名为香草精的化合物。鲜豆荚没有什么香味，需要杀青、发酵、烘干、陈化等加工过程，然后才发出浓郁香气。上一年的11月份收获鲜豆荚，要到次年的5月才能完成加工过程，形成成品上市。","desc_en":"Vanilla planifolia is a species of vanilla orchid native to Mexico, Central America, Colombia, and Brazil. It is one of the primary sources for vanilla flavouring, due to its high vanillin content.","img":"images/95.jpg","thumb":"images/t/95.jpg","file":"Vanilla planifolia 1.jpg","ar":1.238,"py":"xiangcao xc","cr_by":"Everglades National Park","cr_lic":"Public domain","cr_licurl":null,"habit":null,"origin":["北美洲","南美洲"]},{"id":96,"zh":"蜂兰","en":"Ophrys apifera","sci":"Ophrys apifera","order_en":"Asparagales","order_zh":"天门冬目","family_en":"Orchidaceae","family_zh":"兰科","iucn":null,"langs":47,"desc_zh":"蜂兰（学名：Ophrys apifera），是蜂兰属下的一种植物，广泛分布于欧洲、北非和西亚，且是英国英格兰贝德福德郡的郡花。 此外也见于北美洲和东亚。 其种加词的意思是“有蜂的”，用以指代其蜂状的花瓣。 而这种花也会分泌利己素模仿雌蜂的气味，以吸引Tetralonia cressa和Eucera pulveraceae这两种蜂的雄蜂。 蜂兰上最像蜂的花也最有可能吸引到这些蜂，因此就会得到更高的授粉机率。","desc_en":"Ophrys apifera, known in Europe as the bee orchid, is a perennial herbaceous plant of the genus Ophrys, in the family of Orchidaceae. It serves as an example of sexually deceptive pollination and floral mimicry, a highly selective and highly evolved plant–poll…","img":"images/96.jpg","thumb":"images/t/96.jpg","file":"(MHNT) Ophrys apifera - Villeneuve-lès-Bouloc - Flower.jpg","ar":1.214,"py":"fenglan fl","cr_by":"Didier Descouens","cr_lic":"CC BY-SA 4.0","cr_licurl":"https://creativecommons.org/licenses/by-sa/4.0","habit":"草本","origin":["欧洲"]},{"id":97,"zh":"强壮红门兰","en":"Orchis mascula","sci":"Orchis mascula","order_en":"Asparagales","order_zh":"天门冬目","family_en":"Orchidaceae","family_zh":"兰科","iucn":null,"langs":45,"desc_zh":null,"desc_en":"Orchis mascula, the early-purple orchid, early spring orchis, is a species of flowering plant in the orchid family, Orchidaceae.","img":"images/97.jpg","thumb":"images/t/97.jpg","file":"Orchis mascula inflorescence - Keila.jpg","ar":0.667,"py":"qiangzhuanghongmenlan qzhml","cr_by":"Ivar Leidus","cr_lic":"CC BY-SA 4.0","cr_licurl":"https://creativecommons.org/licenses/by-sa/4.0","habit":null,"origin":null},{"id":98,"zh":"齿缘红门兰","en":"Anacamptis morio","sci":"Anacamptis morio","order_en":"Asparagales","order_zh":"天门冬目","family_en":"Orchidaceae","family_zh":"兰科","iucn":null,"langs":45,"desc_zh":"齿缘小红门兰（学名：Ponerorchis crenulata）也称齿缘红门兰，为兰科小红门兰属下的一个种，分布于欧洲和中东。","desc_en":"Anacamptis morio, the green-winged orchid or green-veined orchid (synonym Orchis morio), is a flowering plant of the orchid family, Orchidaceae. It usually has purple flowers, and is found in Europe, Northern Africa and western Asia.","img":"images/98.jpg","thumb":"images/t/98.jpg","file":"Anacamptis morio hampe.jpg","ar":0.633,"py":"chiyuanhongmenlan cyhml","cr_by":"Didier Desouens","cr_lic":"CC BY-SA 4.0","cr_licurl":"https://creativecommons.org/licenses/by-sa/4.0","habit":null,"origin":["亚洲","欧洲","非洲"]},{"id":99,"zh":"细距舌唇兰","en":"Platanthera bifolia","sci":"Platanthera bifolia","order_en":"Asparagales","order_zh":"天门冬目","family_en":"Orchidaceae","family_zh":"兰科","iucn":null,"langs":43,"desc_zh":"细距舌唇兰（学名：Platanthera bifolia）是舌唇兰属的一种植物，与红门兰属有著一定关系。它以往是被分类在玉凤花属中。它分布在欧洲及摩洛哥。其属名是来自希腊文，意思是「阔大的鹿角」，而种小名则意指「两块叶子」。","desc_en":"Platanthera bifolia, commonly known as the lesser butterfly-orchid, is a species of orchid in the genus Platanthera, having certain relations with the genus Orchis, where it was previously included and also with the genus Habenaria.","img":"images/99.jpg","thumb":"images/t/99.jpg","file":"Platanthera bifolia (flower).jpg","ar":0.75,"py":"xijushechunlan xjscl","cr_by":"Hans Hillewaert","cr_lic":"CC BY-SA 4.0","cr_licurl":"https://creativecommons.org/licenses/by-sa/4.0","habit":null,"origin":["非洲"]},{"id":100,"zh":"Dactylorhiza maculata","en":"Dactylorhiza maculata","sci":"Dactylorhiza maculata","order_en":"Asparagales","order_zh":"天门冬目","family_en":"Orchidaceae","family_zh":"兰科","iucn":null,"langs":41,"desc_zh":null,"desc_en":"Dactylorhiza maculata, known as the heath spotted-orchid or moorland spotted orchid, is a herbaceous perennial plant of the family Orchidaceae. It is widespread in mountainous regions across much of Europe from Portugal and Iceland east to Russia.","img":"images/100.jpg","thumb":"images/t/100.jpg","file":"Dactylorhiza maculata LC0232.jpg","ar":0.667,"py":"","cr_by":"Jörg Hempel","cr_lic":"CC BY-SA 3.0 de","cr_licurl":"https://creativecommons.org/licenses/by-sa/3.0/de/deed.en","habit":"草本","origin":["亚洲","欧洲"]},{"id":101,"zh":"手参","en":"Gymnadenia conopsea","sci":"Gymnadenia conopsea","order_en":"Asparagales","order_zh":"天门冬目","family_en":"Orchidaceae","family_zh":"兰科","iucn":"LC","langs":40,"desc_zh":"手参（学名：Gymnadenia conopsea）为兰科手参属下的一个种。","desc_en":"Gymnadenia conopsea, commonly known as the fragrant orchid or chalk fragrant orchid, is a herbaceous plant of the family Orchidaceae native to northern Europe.","img":"images/101.jpg","thumb":"images/t/101.jpg","file":"GymnadeniaConopsea.jpg","ar":0.466,"py":"shoucan sc","cr_by":"The original uploader was (Automated conversion) at English Wikipedia .","cr_lic":"CC BY-SA 3.0","cr_licurl":"http://creativecommons.org/licenses/by-sa/3.0/","habit":"草本","origin":["欧洲"]},{"id":102,"zh":"裂唇虎舌兰","en":"Epipogium aphyllum","sci":"Epipogium aphyllum","order_en":"Asparagales","order_zh":"天门冬目","family_en":"Orchidaceae","family_zh":"兰科","iucn":null,"langs":40,"desc_zh":"裂唇虎舌兰（学名：Epipogium aphyllum）为兰科虎舌兰属下的一个种。","desc_en":"Epipogium aphyllum, the ghost orchid, is a hardy mycoheterotrophic orchid lacking chlorophyll. In much of its range, it is a rare representative of family Orchidaceae.","img":"images/102.jpg","thumb":"images/t/102.jpg","file":"Epipogium aphyllum - Jõhvi- crop.jpg","ar":0.75,"py":"liechunhushelan lchsl","cr_by":"Ivar Leidus","cr_lic":"CC BY-SA 4.0","cr_licurl":"https://creativecommons.org/licenses/by-sa/4.0","habit":null,"origin":["亚洲","欧洲"]},{"id":103,"zh":"欧洲对叶兰","en":"Neottia ovata","sci":"Neottia ovata","order_en":"Asparagales","order_zh":"天门冬目","family_en":"Orchidaceae","family_zh":"兰科","iucn":null,"langs":40,"desc_zh":"欧洲对叶兰 (学名：Neottia ovata，旧称 Listera ovata)，又称卵叶对叶兰（eggleaf twayblade），是一种陆生兰花，广泛分布于欧洲和亚洲的许多地区。","desc_en":"Neottia ovata (formerly Listera ovata), the common twayblade or eggleaf twayblade, is a terrestrial orchid widespread across much of Europe and Asia.","img":"images/103.jpg","thumb":"images/t/103.jpg","file":"Listera ovata 230503.jpg","ar":0.698,"py":"ouzhouduiyelan ozdyl","cr_by":null,"cr_lic":"CC BY-SA 3.0","cr_licurl":"http://creativecommons.org/licenses/by-sa/3.0/","habit":null,"origin":["亚洲","欧洲"]},{"id":104,"zh":"小花火烧兰","en":"Epipactis helleborine","sci":"Epipactis helleborine","order_en":"Asparagales","order_zh":"天门冬目","family_en":"Orchidaceae","family_zh":"兰科","iucn":null,"langs":39,"desc_zh":"火烧兰（学名：Epipactis helleborine）为兰科火烧兰属下的一个种。","desc_en":"Epipactis helleborine, the broad-leaved helleborine, is a terrestrial species of orchid with a broad distribution. It is a long lived herb which varies morphologically with ability to self-pollinate.","img":"images/104.jpg","thumb":"images/t/104.jpg","file":"Epipactis helleborine flowers1 220703.jpg","ar":0.657,"py":"xiaohuahuoshaolan xhhsl","cr_by":null,"cr_lic":"CC BY-SA 3.0","cr_licurl":"http://creativecommons.org/licenses/by-sa/3.0/","habit":"草本","origin":null},{"id":105,"zh":"头蕊兰","en":"Cephalanthera longifolia","sci":"Cephalanthera longifolia","order_en":"Asparagales","order_zh":"天门冬目","family_en":"Orchidaceae","family_zh":"兰科","iucn":null,"langs":39,"desc_zh":"头蕊兰（学名：Cephalanthera longifolia），为兰科头蕊兰属下的一个植物种。","desc_en":"Cephalanthera longifolia, the narrow-leaved helleborine, sword-leaved helleborine or long-leaved helleborine, is a rhizomatous herbaceous perennial plant in the family Orchidaceae.","img":"images/105.jpg","thumb":"images/t/105.jpg","file":"Cephalanthera longifolia 300508.jpg","ar":0.75,"py":"touruilan trl","cr_by":"Bernd Haynold","cr_lic":"CC BY-SA 3.0","cr_licurl":"https://creativecommons.org/licenses/by-sa/3.0","habit":"草本","origin":["亚洲","欧洲","非洲"]},{"id":106,"zh":"Anacamptis pyramidalis","en":"Anacamptis pyramidalis","sci":"Anacamptis pyramidalis","order_en":"Asparagales","order_zh":"天门冬目","family_en":"Orchidaceae","family_zh":"兰科","iucn":null,"langs":39,"desc_zh":null,"desc_en":"Anacamptis pyramidalis, the pyramidal orchid, is a perennial herbaceous plant belonging to the genus Anacamptis of the family Orchidaceae. The scientific name Anacamptis derives from Greek ανακάμτειν 'anakamptein' meaning 'bend forward', while the Latin name p…","img":"images/106.jpg","thumb":"images/t/106.jpg","file":"(MHNT) Anacamptis pyramidalis - Inflorescence.jpg","ar":0.708,"py":"","cr_by":"Didier Descouens","cr_lic":"CC BY-SA 4.0","cr_licurl":"https://creativecommons.org/licenses/by-sa/4.0","habit":"草本","origin":null},{"id":107,"zh":"新疆火烧兰","en":"Epipactis palustris","sci":"Epipactis palustris","order_en":"Asparagales","order_zh":"天门冬目","family_en":"Orchidaceae","family_zh":"兰科","iucn":"LC","langs":38,"desc_zh":"新疆火烧兰（学名：Epipactis palustris）为兰科火烧兰属下的一个种。","desc_en":"Epipactis palustris, the marsh helleborine, is a species of orchid native to Europe and Asia.","img":"images/107.jpg","thumb":"images/t/107.jpg","file":"Epipactis palustris 230705.jpg","ar":0.639,"py":"xinjianghuoshaolan xjhsl","cr_by":"Bernd Haynold","cr_lic":"CC BY-SA 3.0","cr_licurl":"https://creativecommons.org/licenses/by-sa/3.0","habit":null,"origin":["亚洲","欧洲"]},{"id":108,"zh":"四裂红门兰","en":"Orchis militaris","sci":"Orchis militaris","order_en":"Asparagales","order_zh":"天门冬目","family_en":"Orchidaceae","family_zh":"兰科","iucn":null,"langs":38,"desc_zh":"四裂红门兰（学名：Orchis militaris）为兰科红门兰属下的一个种，分布于欧洲，花期为4至6月。","desc_en":"Orchis militaris, the military orchid, is a species of orchid native to Europe. It is the type species of the genus Orchis.","img":"images/108.jpg","thumb":"images/t/108.jpg","file":"Hall käpp - Orchis militaris.jpg","ar":0.749,"py":"siliehongmenlan slhml","cr_by":"Kristian Pikner","cr_lic":"CC BY-SA 4.0","cr_licurl":"https://creativecommons.org/licenses/by-sa/4.0","habit":null,"origin":["欧洲"]},{"id":109,"zh":"二叶舌唇兰","en":"Platanthera chlorantha","sci":"Platanthera chlorantha","order_en":"Asparagales","order_zh":"天门冬目","family_en":"Orchidaceae","family_zh":"兰科","iucn":null,"langs":37,"desc_zh":"二叶舌唇兰（学名：Platanthera chlorantha），为兰科舌唇兰属下的一个植物种。","desc_en":"Platanthera chlorantha, commonly known as greater butterfly-orchid, is a species of orchid in the genus Platanthera. It can be found throughout Europe and Morocco.","img":"images/109.jpg","thumb":"images/t/109.jpg","file":"Platanthera chlorantha LC0225.jpg","ar":0.677,"py":"eryeshechunlan eyscl","cr_by":"Jörg Hempel","cr_lic":"CC BY-SA 3.0 de","cr_licurl":"https://creativecommons.org/licenses/by-sa/3.0/de/deed.en","habit":"草本","origin":["亚洲","欧洲"]},{"id":110,"zh":"Neottia nidus-avis","en":"Neottia nidus-avis","sci":"Neottia nidus-avis","order_en":"Asparagales","order_zh":"天门冬目","family_en":"Orchidaceae","family_zh":"兰科","iucn":"LC","langs":37,"desc_zh":null,"desc_en":"Neottia nidus-avis, the bird's-nest orchid, is a non-photosynthetic orchid, native to Europe, Russia, with sporadic presence in North-Africa, and some parts of the Middle East.","img":"images/110.jpg","thumb":"images/t/110.jpg","file":"Neottia nidus-avis plants.jpg","ar":0.613,"py":"","cr_by":null,"cr_lic":"CC BY-SA 3.0","cr_licurl":"http://creativecommons.org/licenses/by-sa/3.0/","habit":null,"origin":["亚洲","欧洲","非洲"]},{"id":111,"zh":"Orchis simia","en":"Orchis simia","sci":"Orchis simia","order_en":"Asparagales","order_zh":"天门冬目","family_en":"Orchidaceae","family_zh":"兰科","iucn":null,"langs":36,"desc_zh":null,"desc_en":"Orchis simia, commonly known as the monkey orchid, is a greyish pink to reddish species of the genus Orchis. It gets its common name from its lobed lip which mimics the general shape of a monkey's body.","img":"images/111.jpg","thumb":"images/t/111.jpg","file":"Orchis simia ( άγρια ορχιδέα).jpg","ar":0.667,"py":"","cr_by":"Μεταξία Φωτίου","cr_lic":"CC BY-SA 4.0","cr_licurl":"https://creativecommons.org/licenses/by-sa/4.0","habit":null,"origin":null},{"id":112,"zh":"紫斑掌裂兰","en":"Common spotted orchid","sci":"Dactylorhiza fuchsii","order_en":"Asparagales","order_zh":"天门冬目","family_en":"Orchidaceae","family_zh":"兰科","iucn":null,"langs":35,"desc_zh":"紫斑掌裂兰（学名：Dactylorhiza fuchsii）为兰科掌裂兰属下的一个种。","desc_en":"Dactylorhiza fuchsii, the common spotted orchid, is a species of flowering plant in the orchid family Orchidaceae. It is one of Europe's most common wild orchids, and is widespread across much of Europe, with the range extending eastward into Siberia, Mongolia…","img":"images/112.jpg","thumb":"images/t/112.jpg","file":"Dactylorhiza fuchsii Mariazell 01.JPG","ar":0.667,"py":"zibanzhanglielan zbzll","cr_by":"Uoaei1","cr_lic":"CC BY-SA 4.0","cr_licurl":"https://creativecommons.org/licenses/by-sa/4.0","habit":null,"origin":["亚洲","欧洲"]},{"id":113,"zh":"珊瑚兰","en":"Corallorhiza trifida","sci":"Corallorhiza trifida","order_en":"Asparagales","order_zh":"天门冬目","family_en":"Orchidaceae","family_zh":"兰科","iucn":null,"langs":35,"desc_zh":"珊瑚兰（学名：Corallorhiza trifida）为兰科珊瑚兰属下的一个种。虽然有叶绿素，但属部分菌异营，即取真菌之营养助维生。","desc_en":"Corallorhiza trifida, commonly known as early coralroot, northern coralroot, or yellow coralroot, is a coralroot orchid native to North America and Eurasia, with a circumboreal distribution.","img":"images/113.jpg","thumb":"images/t/113.jpg","file":"Corallorrhiza trifida 05 mg-k.jpg","ar":0.642,"py":"shanhulan shl","cr_by":null,"cr_lic":"CC BY-SA 3.0","cr_licurl":"http://creativecommons.org/licenses/by-sa/3.0/","habit":null,"origin":["亚洲","北美洲"]},{"id":114,"zh":"丛宝兰","en":"Limodorum abortivum","sci":"Limodorum abortivum","order_en":"Asparagales","order_zh":"天门冬目","family_en":"Orchidaceae","family_zh":"兰科","iucn":null,"langs":35,"desc_zh":null,"desc_en":"Limodorum abortivum, also known as violet limodore or violet bird's-nest orchid, is a species of myco-heterotrophic, achlorophyllous orchid and is native to mainland Europe, western Asia and the Mediterranean area.","img":"images/114.jpg","thumb":"images/t/114.jpg","file":"Недоразвит лимодорум Limodorum abortivum.jpg","ar":1.333,"py":"congbaolan cbl","cr_by":"ABesheva","cr_lic":"CC BY-SA 4.0","cr_licurl":"https://creativecommons.org/licenses/by-sa/4.0","habit":"草本","origin":["亚洲","欧洲"]},{"id":115,"zh":"绿花凹舌兰","en":"Dactylorhiza viridis","sci":"Dactylorhiza viridis","order_en":"Asparagales","order_zh":"天门冬目","family_en":"Orchidaceae","family_zh":"兰科","iucn":null,"langs":34,"desc_zh":"绿花凹舌兰（学名：Coeloglossum viride）为兰科凹舌兰属下的一个种。","desc_en":"Dactylorhiza viridis, the frog orchid, is a species of flowering plant in the orchid family Orchidaceae. It has also been treated as the only species Coeloglossum viride of the monotypic genus Coeloglossum.","img":"images/115.jpg","thumb":"images/t/115.jpg","file":"Coeloglossum viride 04 mg-k.jpg","ar":0.776,"py":"lhuaaoshelan lhasl","cr_by":null,"cr_lic":"CC BY-SA 3.0","cr_licurl":"http://creativecommons.org/licenses/by-sa/3.0/","habit":null,"origin":null},{"id":116,"zh":"欧亚绶草","en":"Spiranthes spiralis","sci":"Spiranthes spiralis","order_en":"Asparagales","order_zh":"天门冬目","family_en":"Orchidaceae","family_zh":"兰科","iucn":null,"langs":34,"desc_zh":null,"desc_en":"Spiranthes spiralis, commonly known as autumn lady's-tresses, is an orchid that grows in Europe and adjacent North Africa and Asia. It is a small grey-green plant. It forms a rosette of four to five pointed, sessile, ovate leaves about 3 cm (1.2 in) in length.","img":"images/116.jpg","thumb":"images/t/116.jpg","file":"Spiranthes spiralis 120807.jpg","ar":0.428,"py":"ouyashoucao oysc","cr_by":"Bernd Haynold","cr_lic":"CC BY 2.5","cr_licurl":"https://creativecommons.org/licenses/by/2.5","habit":null,"origin":["亚洲","欧洲","非洲"]},{"id":117,"zh":"Cephalanthera rubra","en":"Cephalanthera rubra","sci":"Cephalanthera rubra","order_en":"Asparagales","order_zh":"天门冬目","family_en":"Orchidaceae","family_zh":"兰科","iucn":null,"langs":34,"desc_zh":null,"desc_en":"Cephalanthera rubra, known as red helleborine, is an orchid found in Europe, North Africa and southwest Asia. Although reasonably common in parts of its range, this Cephalanthera has always been one of the rarest orchids in Britain.","img":"images/117.jpg","thumb":"images/t/117.jpg","file":"Cephalanthera rubra 02 Luxemburg.jpg","ar":0.666,"py":"","cr_by":"Orchi","cr_lic":"CC BY-SA 3.0","cr_licurl":"http://creativecommons.org/licenses/by-sa/3.0/","habit":null,"origin":["亚洲","欧洲","非洲"]},{"id":118,"zh":"Neotinea ustulata","en":"Neotinea ustulata","sci":"Neotinea ustulata","order_en":"Asparagales","order_zh":"天门冬目","family_en":"Orchidaceae","family_zh":"兰科","iucn":null,"langs":34,"desc_zh":null,"desc_en":"Neotinea ustulata (syn. Orchis ustulata), the burnt orchid or burnt-tip orchid, is a European terrestrial orchid native to mountains in central and southern Europe, growing at up to 2,400 m (7,900 ft) elevation.","img":"images/118.jpg","thumb":"images/t/118.jpg","file":"Orchis ustulata wiki mg-k02.jpg","ar":0.622,"py":"","cr_by":null,"cr_lic":"CC BY-SA 3.0","cr_licurl":"http://creativecommons.org/licenses/by-sa/3.0/","habit":null,"origin":["欧洲"]},{"id":119,"zh":"Ophrys insectifera","en":"Ophrys insectifera","sci":"Ophrys insectifera","order_en":"Asparagales","order_zh":"天门冬目","family_en":"Orchidaceae","family_zh":"兰科","iucn":"LC","langs":34,"desc_zh":null,"desc_en":"Ophrys insectifera, the fly orchid, is a species of orchid and the type species of the genus Ophrys. It is remarkable as an example of the use of sexually deceptive pollination and floral mimicry, as well as a highly selective and highly evolved plant–pollinat…","img":"images/119.jpg","thumb":"images/t/119.jpg","file":"Ophrys insectifera flower.jpg","ar":0.797,"py":"","cr_by":"Bernd Haynold","cr_lic":"CC BY-SA 3.0","cr_licurl":"http://creativecommons.org/licenses/by-sa/3.0/","habit":null,"origin":null},{"id":120,"zh":"Orchis purpurea","en":"Orchis purpurea","sci":"Orchis purpurea","order_en":"Asparagales","order_zh":"天门冬目","family_en":"Orchidaceae","family_zh":"兰科","iucn":null,"langs":34,"desc_zh":null,"desc_en":"Orchis purpurea, the lady orchid, is a herbaceous plant belonging to the genus Orchis of the family Orchidaceae.","img":"images/120.jpg","thumb":"images/t/120.jpg","file":"Orchis purpurea6.jpg","ar":1.309,"py":"","cr_by":null,"cr_lic":"CC BY-SA 3.0","cr_licurl":"http://creativecommons.org/licenses/by-sa/3.0/","habit":"草本","origin":null},{"id":121,"zh":"南投斑叶兰","en":"Goodyera repens","sci":"Goodyera repens","order_en":"Asparagales","order_zh":"天门冬目","family_en":"Orchidaceae","family_zh":"兰科","iucn":null,"langs":33,"desc_zh":"南投斑叶兰（学名：Goodyera repens）为兰科斑叶兰属下的一个种。","desc_en":"Goodyera repens, a small forest orchid in the genus Goodyera. It is known by the common name creeping lady's-tresses in Anglophone Europe and dwarf rattlesnake plantain or lesser rattlesnake plantain in North America.","img":"images/121.jpg","thumb":"images/t/121.jpg","file":"Goodyera repens (habitus).jpg","ar":0.697,"py":"nantoubanyelan ntbyl","cr_by":"Hans Hillewaert","cr_lic":"CC BY-SA 3.0","cr_licurl":"https://creativecommons.org/licenses/by-sa/3.0","habit":null,"origin":["欧洲","北美洲"]},{"id":122,"zh":"大花头蕊兰","en":"Cephalanthera damasonium","sci":"Cephalanthera damasonium","order_en":"Asparagales","order_zh":"天门冬目","family_en":"Orchidaceae","family_zh":"兰科","iucn":null,"langs":33,"desc_zh":"大花头蕊兰（学名：Cephalanthera damasonium）为兰科头蕊兰属下的一个种。","desc_en":"Cephalanthera damasonium, the white helleborine, is a species of orchid. It is widespread across much of Europe and Asia. Cephalanthera damasonium is the type species of the genus Cephalanthera.","img":"images/122.jpg","thumb":"images/t/122.jpg","file":"Cephalanthera damasonium 050606.jpg","ar":0.651,"py":"dahuatouruilan dhtrl","cr_by":"Bernd Haynold","cr_lic":"CC BY 2.5","cr_licurl":"https://creativecommons.org/licenses/by/2.5","habit":null,"origin":["亚洲","欧洲"]},{"id":123,"zh":"石斛","en":"Dendrobium nobile","sci":"Dendrobium nobile","order_en":"Asparagales","order_zh":"天门冬目","family_en":"Orchidaceae","family_zh":"兰科","iucn":null,"langs":32,"desc_zh":"石斛（学名：Dendrobium nobile）为兰科石斛属下的一个种。 石斛（学名：Dendrobium nobile Lindl），又称作仙斛兰韵、不死草、还魂草、紫萦仙株、吊兰、林兰、禁生、金钗花、金钗石斛、金石斛、黄草、金丝斛。茎直立，肉质状肥厚，稍扁的圆柱形，长10~60厘米，粗达1.3厘米。药用植物，性味甘淡微咸，寒，归胃、肾，肺经。益胃生津，滋阴清热。用于阴伤津亏，口干烦渴，食少干呕，病后虚热，目暗不明。","desc_en":"Dendrobium nobile, also known as the noble dendrobium, is a member of the family Orchidaceae. It is one of the most widespread ornamental members of the orchid family. It is the state flower of the Indian state of Sikkim.","img":"images/123.jpg","thumb":"images/t/123.jpg","file":"Dendrobium nobile (12863000234).jpg","ar":1.448,"py":"shihu sh","cr_by":"Maja Dumat from Deutschland (Germany)","cr_lic":"CC BY 2.0","cr_licurl":"https://creativecommons.org/licenses/by/2.0","habit":null,"origin":["亚洲"]},{"id":124,"zh":"眉兰","en":"Ophrys sphegodes","sci":"Ophrys sphegodes","order_en":"Asparagales","order_zh":"天门冬目","family_en":"Orchidaceae","family_zh":"兰科","iucn":null,"langs":32,"desc_zh":null,"desc_en":"Ophrys sphegodes, commonly known as the early spider-orchid, is a species of sexually-deceptive orchid (through Pouyannian mimicry) native to Europe and the Middle East. It is a highly varied species with many subspecies recognised.","img":"images/124.jpg","thumb":"images/t/124.jpg","file":"Early Spider Orchid flowers - geograph.org.uk - 804520.jpg","ar":1.502,"py":"meilan ml","cr_by":"Ian Capper","cr_lic":"CC BY-SA 2.0","cr_licurl":"https://creativecommons.org/licenses/by-sa/2.0","habit":null,"origin":["亚洲","欧洲"]},{"id":125,"zh":"角盘兰","en":"Herminium monorchis","sci":"Herminium monorchis","order_en":"Asparagales","order_zh":"天门冬目","family_en":"Orchidaceae","family_zh":"兰科","iucn":null,"langs":32,"desc_zh":"角盘兰（学名：Herminium monorchis）为兰科角盘兰属下的一个种，广泛分布于欧洲和亚洲北部，是该属最常见的植物之一。可带根入药，其性甘、温，有滋阴补肾、养胃、调经的功效。","desc_en":"Herminium monorchis, the musk orchid, is a commonly occurring species of orchid. It is widespread across much of Europe and northern Asia from France to Japan, including China, Siberia, Mongolia, Ukraine, Germany, Italy, Scandinavia, etc.","img":"images/125.jpg","thumb":"images/t/125.jpg","file":"Herminium monorchis 230705.jpg","ar":0.426,"py":"jiaopanlan jpl","cr_by":"Bernd Haynold","cr_lic":"CC BY-SA 2.5","cr_licurl":"https://creativecommons.org/licenses/by-sa/2.5","habit":null,"origin":null},{"id":126,"zh":"罗氏羊耳蒜","en":"Liparis loeselii","sci":"Liparis loeselii","order_en":"Asparagales","order_zh":"天门冬目","family_en":"Orchidaceae","family_zh":"兰科","iucn":null,"langs":31,"desc_zh":null,"desc_en":"Liparis loeselii, the fen orchid, yellow widelip orchid, or bog twayblade, is a rare species of orchid. It is native to Europe, northern Asia, the eastern United States, and eastern Canada. It grows in fens, bogs and dune slacks.","img":"images/126.jpg","thumb":"images/t/126.jpg","file":"Liparis loeselii detail.jpeg","ar":1.333,"py":"luoshiyangersuan lsyes","cr_by":"Kristian Peters -- Fabelfroh 07:12, 30 October 2006 (UTC)","cr_lic":"CC BY-SA 3.0","cr_licurl":"http://creativecommons.org/licenses/by-sa/3.0/","habit":null,"origin":["亚洲","欧洲","北美洲"]},{"id":127,"zh":"人帽兰","en":"Orchis anthropophora","sci":"Orchis anthropophora","order_en":"Asparagales","order_zh":"天门冬目","family_en":"Orchidaceae","family_zh":"兰科","iucn":null,"langs":31,"desc_zh":"人帽兰（学名：Aceras anthropophorum）是兰科下的一种，有时被分类在近亲的红门兰属中。它取名人帽兰是因其花像人：花瓣及花萼像人头，而唇瓣则像人的四肢。","desc_en":"Orchis anthropophora (formerly Aceras anthropophorum), the man orchid, is a European species of orchid whose flowers resemble a human figure. The head is formed by the petals and sepals, and the suspended torso and limbs by the lobes of the labellum.","img":"images/127.jpg","thumb":"images/t/127.jpg","file":"Aceras anthropophorum flowers.jpg","ar":0.843,"py":"renmaolan rml","cr_by":null,"cr_lic":"CC BY-SA 3.0","cr_licurl":"http://creativecommons.org/licenses/by-sa/3.0/","habit":null,"origin":null},{"id":128,"zh":"Dactylorhiza sambucina","en":"Dactylorhiza sambucina","sci":"Dactylorhiza sambucina","order_en":"Asparagales","order_zh":"天门冬目","family_en":"Orchidaceae","family_zh":"兰科","iucn":"LC","langs":31,"desc_zh":null,"desc_en":"Dactylorhiza sambucina, the elder-flowered orchid, is an herbaceous plant belonging to the family Orchidaceae. It is quite common and widespread throughout much of Europe from Portugal east to Finland and Ukraine.","img":"images/128.jpg","thumb":"images/t/128.jpg","file":"Dactylorhiza sambucina - Flickr 003.jpg","ar":0.75,"py":"","cr_by":"Kriko L from Finland","cr_lic":"CC BY 2.0","cr_licurl":"https://creativecommons.org/licenses/by/2.0","habit":"草本","origin":["欧洲"]},{"id":129,"zh":"Neottia cordata","en":"Neottia cordata","sci":"Neottia cordata","order_en":"Asparagales","order_zh":"天门冬目","family_en":"Orchidaceae","family_zh":"兰科","iucn":"LC","langs":31,"desc_zh":null,"desc_en":"Neottia cordata, the lesser twayblade or heartleaf twayblade, is an orchid of upland bogs and mires. It was formerly placed in the genus Listera, but molecular phylogenetic studies have shown that Neottia nidus-avis, the bird's-nest orchid, evolved within the…","img":"images/129.jpg","thumb":"images/t/129.jpg","file":"Listera cordata 130506.jpg","ar":0.756,"py":"","cr_by":"Bernd Haynold","cr_lic":"CC BY 2.5","cr_licurl":"https://creativecommons.org/licenses/by/2.5","habit":null,"origin":null},{"id":130,"zh":"Dark red helleborine","en":"Dark red helleborine","sci":"Epipactis atrorubens","order_en":"Asparagales","order_zh":"天门冬目","family_en":"Orchidaceae","family_zh":"兰科","iucn":null,"langs":31,"desc_zh":null,"desc_en":"Epipactis atrorubens, the dark-red helleborine or royal helleborine, is an herbaceous plant in the orchid family, Orchidaceae. As with many other species of orchids, the species is legally protected in some countries.","img":"images/130.jpg","thumb":"images/t/130.jpg","file":"Epipactis atrorubens flowers.jpg","ar":0.91,"py":"","cr_by":null,"cr_lic":"CC BY-SA 3.0","cr_licurl":"http://creativecommons.org/licenses/by-sa/3.0/","habit":"草本","origin":null},{"id":131,"zh":"肉色掌裂兰","en":"early marsh-orchid","sci":"Dactylorhiza incarnata","order_en":"Asparagales","order_zh":"天门冬目","family_en":"Orchidaceae","family_zh":"兰科","iucn":null,"langs":30,"desc_zh":null,"desc_en":"Dactylorhiza incarnata, the early marsh-orchid, is a perennial, temperate-climate species of orchid generally found growing in wet meadows, and generally on base-rich soils, up to about 2100m asl.","img":"images/131.jpg","thumb":"images/t/131.jpg","file":"Dactylorhiza incarnata 150508.jpg","ar":0.602,"py":"rousezhanglielan rszll","cr_by":"Bernd Haynold","cr_lic":"CC BY-SA 3.0","cr_licurl":"https://creativecommons.org/licenses/by-sa/3.0","habit":"草本","origin":["亚洲","欧洲"]},{"id":132,"zh":"南洋白花蝴蝶兰","en":"Phalaenopsis amabilis","sci":"Phalaenopsis amabilis","order_en":"Asparagales","order_zh":"天门冬目","family_en":"Orchidaceae","family_zh":"兰科","iucn":null,"langs":30,"desc_zh":"南洋白花蝴蝶兰（学名：Phalaenopsis amabilis；印尼语：anggrek bulan，意为“月光兰花”），中文正式名为美丽蝴蝶兰，又因种小名“amabilis”谐音“阿嬷”，俗称阿嬷蝴蝶兰。 南洋白花蝴蝶兰为蝴蝶兰属的模式种，原产于东印度群岛和澳大利亚，现已成为常见的观赏栽培花卉，并与茉莉、大花草并列为印度尼西亚的三种国花之一。 与南洋白花蝴蝶兰同为蝴蝶兰属的另一物种——台湾蝴蝶兰也常被误称为阿嬷蝴蝶兰。","desc_en":"Phalaenopsis amabilis, commonly known as moon orchid, moth orchid, or mariposa orchid, is a species of flowering plant in the orchid family Orchidaceae. It is widely cultivated as a decorative houseplant.","img":"images/132.jpg","thumb":"images/t/132.jpg","file":"Phalaenopsis amabilis Orchi 03.jpg","ar":1.333,"py":"nanyangbaihuahudielan nybhhdl","cr_by":"Orchi","cr_lic":"CC BY-SA 3.0","cr_licurl":"http://creativecommons.org/licenses/by-sa/3.0/","habit":"草本","origin":["亚洲","大洋洲"]},{"id":133,"zh":"三齿兰","en":"Neotinea tridentata","sci":"Neotinea tridentata","order_en":"Asparagales","order_zh":"天门冬目","family_en":"Orchidaceae","family_zh":"兰科","iucn":null,"langs":30,"desc_zh":"三齿兰（学名：Neotinea tridentata）是一个在欧洲南部生长的兰花品种，分布区域包括西班牙、土耳其、黎巴嫩，向北到克里米亚、波兰和德国。这种兰花喜欢在草地、林地和灌木地带生长。 其种加词“tridentata”意为“三齿的”。","desc_en":"Neotinea tridentata, the three-toothed orchid, is a species of orchid found in southern Europe from Spain to Turkey; northwards to the Crimea, Poland and Germany. This orchid favours grassy places, woodland, scrub and maquis.","img":"images/133.jpg","thumb":"images/t/133.jpg","file":"Dreizähniges Knabenkraut in Wacholderheide.jpg","ar":1.333,"py":"sanchilan scl","cr_by":"Kookaburra91156","cr_lic":"CC BY-SA 4.0","cr_licurl":"https://creativecommons.org/licenses/by-sa/4.0","habit":null,"origin":["欧洲"]},{"id":134,"zh":"沼兰","en":"Malaxis monophyllos","sci":"Malaxis monophyllos","order_en":"Asparagales","order_zh":"天门冬目","family_en":"Orchidaceae","family_zh":"兰科","iucn":null,"langs":29,"desc_zh":"单叶软叶兰（学名：Malaxis monophyllos）为兰科小柱兰属下的一个种。","desc_en":"Malaxis monophyllos, the white adder's mouth, is a terrestrial species of orchid. It is widespread across much of Europe (Germany, Italy, Poland, Scandinavia, Ukraine, etc.), Asia (China, Japan, Russia, Nepal, Philippines, etc.), and much of southern Canada.","img":"images/134.jpg","thumb":"images/t/134.jpg","file":"Malaxis monophyllos 140706.jpg","ar":0.851,"py":"zhaolan zl","cr_by":"Bernd Haynold","cr_lic":"CC BY 2.5","cr_licurl":"https://creativecommons.org/licenses/by/2.5","habit":null,"origin":["欧洲"]},{"id":135,"zh":"布袋兰","en":"Calypso bulbosa","sci":"Calypso bulbosa","order_en":"Asparagales","order_zh":"天门冬目","family_en":"Orchidaceae","family_zh":"兰科","iucn":null,"langs":29,"desc_zh":"布袋兰属（学名：Calypso）是兰科下的一个属，为陆生兰。该属仅有布袋兰（Calypso bulbosa）一种，分布于北温带。","desc_en":"Calypso is a genus of orchids containing one species, Calypso bulbosa, known as the calypso orchid, fairy slipper or Venus's slipper. It is a perennial member of the orchid family found in undisturbed northern and montane forests.","img":"images/135.jpg","thumb":"images/t/135.jpg","file":"Calypso bulbosa Nordens Flora 416.jpg","ar":0.544,"py":"budailan bdl","cr_by":"Carl Axel Magnus Lindman","cr_lic":"Public domain","cr_licurl":null,"habit":"草本","origin":null},{"id":136,"zh":"Anacamptis palustris","en":"Anacamptis palustris","sci":"Anacamptis palustris","order_en":"Asparagales","order_zh":"天门冬目","family_en":"Orchidaceae","family_zh":"兰科","iucn":"LC","langs":28,"desc_zh":null,"desc_en":"Anacamptis palustris is a species of orchid. It is found in Europe, North Africa and western Asia. This orchid is native to Western and Central Europe, the Mediterranean region, the Balearic Islands, Turkey, Western Asia, Algeria and Tunisia in North Africa, a…","img":"images/136.jpg","thumb":"images/t/136.jpg","file":"Mgk d0802127.jpg","ar":0.662,"py":"","cr_by":"Mg-k","cr_lic":"CC BY-SA 3.0","cr_licurl":"https://creativecommons.org/licenses/by-sa/3.0","habit":"草本","origin":["亚洲","欧洲","非洲"]},{"id":137,"zh":"Epipactis purpurata","en":"Epipactis purpurata","sci":"Epipactis purpurata","order_en":"Asparagales","order_zh":"天门冬目","family_en":"Orchidaceae","family_zh":"兰科","iucn":"LC","langs":28,"desc_zh":null,"desc_en":"Epipactis purpurata, the violet helleborine, is an orchid widely distributed in Europe.","img":"images/137.jpg","thumb":"images/t/137.jpg","file":"Epipactis purpurata 300707.jpg","ar":0.629,"py":"","cr_by":"Bernd Haynold","cr_lic":"CC BY 2.5","cr_licurl":"https://creativecommons.org/licenses/by/2.5","habit":null,"origin":["欧洲"]},{"id":138,"zh":"夏绶草","en":"Summer lady's-tresses","sci":"Spiranthes aestivalis","order_en":"Asparagales","order_zh":"天门冬目","family_en":"Orchidaceae","family_zh":"兰科","iucn":null,"langs":26,"desc_zh":"夏绶草（学名：Spiranthes aestivalis）是兰科绶草属的多年生宿根性草本植物，是一种较为稀有的原生兰，分布于欧洲中部和南部以及欧洲北部的荷兰、英格兰南部，南至摩洛哥，生长在海拔1,800米以下的地区，常见于在贫瘠的沼泽和荒野上。","desc_en":"Spiranthes aestivalis, commonly called the summer lady's-tresses, is a species of orchid found in western Europe, Turkey, Russia, and North Africa. The specific epithet, aestivalis, is derived from Latin and means \"pertaining to the summer\".","img":"images/138.jpg","thumb":"images/t/138.jpg","file":"Spiranthes aestivalis Blütenstand.jpg","ar":0.654,"py":"xiashoucao xsc","cr_by":null,"cr_lic":"CC BY-SA 3.0","cr_licurl":"http://creativecommons.org/licenses/by-sa/3.0/","habit":null,"origin":["欧洲","非洲"]},{"id":139,"zh":"沼泽兰花","en":"Dactylorhiza majalis","sci":"Dactylorhiza majalis","order_en":"Asparagales","order_zh":"天门冬目","family_en":"Orchidaceae","family_zh":"兰科","iucn":null,"langs":26,"desc_zh":null,"desc_en":"Dactylorhiza majalis, or the broad-leaved marsh orchid, is a terrestrial Eurasian orchid. Subspecies include the western marsh orchid (Dactylorhiza majalis subsp. occidentalis) and southern marsh orchid (Dactylorhiza majalis subsp. praetermissa).","img":"images/139.jpg","thumb":"images/t/139.jpg","file":"00 0589 Breitblättrige Knabenkraut (Dactylorhiza majalis).jpg","ar":0.664,"py":"zhaozelanhua zzlh","cr_by":"W. Bulach","cr_lic":"CC BY-SA 4.0","cr_licurl":"https://creativecommons.org/licenses/by-sa/4.0","habit":null,"origin":null},{"id":140,"zh":"Gymnadenia nigra","en":"Gymnadenia nigra","sci":"Gymnadenia nigra","order_en":"Asparagales","order_zh":"天门冬目","family_en":"Orchidaceae","family_zh":"兰科","iucn":null,"langs":26,"desc_zh":null,"desc_en":"Gymnadenia nigra, also known as the black vanilla orchid, is a species of orchid and the provincial flower of Jämtland, a historical province of Sweden. It is a perennial species found in the major mountain ranges of Europe, including the Pyrenees and the Alps…","img":"images/140.jpg","thumb":"images/t/140.jpg","file":"Nigritella nigra brunkulla.JPG","ar":0.675,"py":"","cr_by":"Photo2222","cr_lic":"CC BY-SA 3.0","cr_licurl":"http://creativecommons.org/licenses/by-sa/3.0/","habit":"草本","origin":["欧洲"]},{"id":141,"zh":"Himantoglossum hircinum","en":"Himantoglossum hircinum","sci":"Himantoglossum hircinum","order_en":"Asparagales","order_zh":"天门冬目","family_en":"Orchidaceae","family_zh":"兰科","iucn":null,"langs":26,"desc_zh":null,"desc_en":"Himantoglossum hircinum, the lizard orchid, is a species of orchid in the genus Himantoglossum found in Europe and North Africa.","img":"images/141.jpg","thumb":"images/t/141.jpg","file":"Himantoglossum hircinum.jpg","ar":0.661,"py":"","cr_by":"Hans Hillewaert","cr_lic":"CC BY-SA 4.0","cr_licurl":"https://creativecommons.org/licenses/by-sa/4.0","habit":null,"origin":["欧洲","非洲"]},{"id":142,"zh":"Anacamptis coriophora","en":"Anacamptis coriophora","sci":"Anacamptis coriophora","order_en":"Asparagales","order_zh":"天门冬目","family_en":"Orchidaceae","family_zh":"兰科","iucn":null,"langs":26,"desc_zh":null,"desc_en":"Anacamptis coriophora, the bug orchid, is a species of orchid, found in Europe, the Mediterranean, and the Near East to Iran.","img":"images/142.jpg","thumb":"images/t/142.jpg","file":"Anacamptis coriophora (Orchis coriophora), Tsaghkadzor, in culture, 2012.06.22 (29067292560).jpg","ar":1.501,"py":"","cr_by":"Vahe Martirosyan from Glendale, CA, USA","cr_lic":"CC BY 2.0","cr_licurl":"https://creativecommons.org/licenses/by/2.0","habit":null,"origin":["亚洲","欧洲"]},{"id":143,"zh":"Hammarbya paludosa","en":"Hammarbya paludosa","sci":"Hammarbya paludosa","order_en":"Asparagales","order_zh":"天门冬目","family_en":"Orchidaceae","family_zh":"兰科","iucn":"LC","langs":25,"desc_zh":null,"desc_en":"Hammarbya paludosa (or Malaxis paludosa) is a small orchid commonly known as bog orchid, bog adder's-mouth or bog adder's-mouth orchid. It grows in bogs in temperate and subarctic regions of the Northern Hemisphere.","img":"images/143.jpg","thumb":"images/t/143.jpg","file":"Hammarbya paludosa Niedersachsen 01.jpg","ar":0.703,"py":"","cr_by":"Orchi","cr_lic":"CC BY-SA 3.0","cr_licurl":"http://creativecommons.org/licenses/by-sa/3.0/","habit":null,"origin":null},{"id":144,"zh":"角蜂眉兰","en":"Ophrys lutea","sci":"Ophrys lutea","order_en":"Asparagales","order_zh":"天门冬目","family_en":"Orchidaceae","family_zh":"兰科","iucn":null,"langs":24,"desc_zh":null,"desc_en":"Ophrys lutea, the yellow bee-orchid, is a species of orchid native to southern Europe, North Africa, and the Middle East, the range extending from Portugal and Morocco to Syria.","img":"images/144.jpg","thumb":"images/t/144.jpg","file":"Ophrys lutea 1 maig.JPG","ar":0.617,"py":"jiaofengmeilan jfml","cr_by":"Victor M. Vicente Selvas","cr_lic":"CC BY-SA 3.0","cr_licurl":"https://creativecommons.org/licenses/by-sa/3.0","habit":null,"origin":["亚洲","欧洲","非洲"]},{"id":145,"zh":"Epipactis microphylla","en":"Epipactis microphylla","sci":"Epipactis microphylla","order_en":"Asparagales","order_zh":"天门冬目","family_en":"Orchidaceae","family_zh":"兰科","iucn":null,"langs":24,"desc_zh":null,"desc_en":"Epipactis microphylla, the small-leaved helleborine, is a species of orchid. It is native to much of Europe and to Southwest Asia as far east as Iran though noticeably absent from the British Isles and from Scandinavia.","img":"images/145.jpg","thumb":"images/t/145.jpg","file":"Epipactis microphylla Saarland 02.jpg","ar":0.75,"py":"","cr_by":"Orchi","cr_lic":"CC BY-SA 3.0","cr_licurl":"http://creativecommons.org/licenses/by-sa/3.0/","habit":null,"origin":["亚洲","欧洲","非洲"]},{"id":146,"zh":"番红花","en":"Crocus sativus","sci":"Crocus sativus","order_en":"Asparagales","order_zh":"天门冬目","family_en":"Iridaceae","family_zh":"鸢尾科","iucn":null,"langs":62,"desc_zh":"番红花（学名：Crocus sativus），也叫藏红花、西红花、彼岸花，古称郁金、郁金香、撒馥兰、撒䭱兰，鸢尾科番红花属的一种多年生草本植物。其干燥的雌蕊柱头为料理和医药中常用的番红花香料。 番红花广泛分布于地中海地区、北非、南欧、伊朗高原、阿拉伯半岛、青藏高原、蒙古高原和北美洲，植物在全球多地皆可繁盛生长，但因为其能利用的部份只有雌蕊的柱头部分，所以产量很低，商业化种植及采收需要耗费大量人力物力。","desc_en":"Crocus sativus, commonly known as saffron crocus or autumn crocus, is a species of flowering plant in the iris family Iridaceae. A cormous autumn-flowering cultivated perennial, unknown in the wild, it is best known for the culinary use of its floral stigmas a…","img":"images/146.jpg","thumb":"images/t/146.jpg","file":"Saffran crocus sativus moist.jpg","ar":0.75,"py":"fanhonghua fhh","cr_by":"HeiWu","cr_lic":"CC BY-SA 3.0","cr_licurl":"http://creativecommons.org/licenses/by-sa/3.0/","habit":"草本","origin":null},{"id":147,"zh":"黄菖蒲","en":"Iris pseudacorus","sci":"Iris pseudacorus","order_en":"Asparagales","order_zh":"天门冬目","family_en":"Iridaceae","family_zh":"鸢尾科","iucn":"LC","langs":62,"desc_zh":"黄菖蒲（学名：Iris pseudacorus）是鸢尾科鸢尾属的植物。分布在欧洲以及中国等地，目前已由人工引种栽培。","desc_en":"Iris pseudacorus, the yellow flag, yellow iris, or water flag, is a species of flowering plant in the family Iridaceae. It is native to Europe, western Asia and northwest Africa.","img":"images/147.jpg","thumb":"images/t/147.jpg","file":"Iris pseudacorus 001.jpg","ar":1.333,"py":"huangchangpu hcp","cr_by":"Jean-Jacques MILAN","cr_lic":"CC BY-SA 3.0","cr_licurl":"http://creativecommons.org/licenses/by-sa/3.0/","habit":null,"origin":["亚洲","欧洲","非洲"]},{"id":148,"zh":"德国鸢尾","en":"Iris x germanica","sci":"Iris × germanica","order_en":"Asparagales","order_zh":"天门冬目","family_en":"Iridaceae","family_zh":"鸢尾科","iucn":null,"langs":46,"desc_zh":"德国鸢尾（学名：Iris germanica）是鸢尾科鸢尾属的植物。分布于欧洲以及中国大陆的青岛、江苏、湖北等地，目前已由人工引种栽培。","desc_en":"Iris × germanica is the accepted name for a species of flowering plants in the family Iridaceae commonly known as the bearded iris or the German bearded iris. It is of hybrid origin. Varieties include I. × g. var. florentina.","img":"images/148.jpg","thumb":"images/t/148.jpg","file":"00 1238 Deutsche Schwertlilie (Iris × germanica).jpg","ar":0.667,"py":"deguoyuanwei dgyw","cr_by":"W. Bulach","cr_lic":"CC BY-SA 4.0","cr_licurl":"https://creativecommons.org/licenses/by-sa/4.0","habit":null,"origin":null},{"id":149,"zh":"春番红花","en":"Crocus vernus","sci":"Crocus vernus","order_en":"Asparagales","order_zh":"天门冬目","family_en":"Iridaceae","family_zh":"鸢尾科","iucn":null,"langs":39,"desc_zh":"春番红花（学名：Crocus vernus）是鸢尾科番红花属多年生草本植物，原产阿尔卑斯山以及西巴尔干。","desc_en":"Crocus vernus (spring crocus, giant crocus) is a species of flowering plant in the family Iridaceae, native to the Alps, the Pyrenees, and the Balkans. Its cultivars and those of Crocus flavus (Dutch crocus) are used as ornamental plants.","img":"images/149.jpg","thumb":"images/t/149.jpg","file":"20140213Crocus tommasinianus2.jpg","ar":1.333,"py":"chunfanhonghua cfhh","cr_by":"AnRo0002","cr_lic":"CC0","cr_licurl":"http://creativecommons.org/publicdomain/zero/1.0/deed.en","habit":null,"origin":["欧洲"]},{"id":150,"zh":"西伯利亚鸢尾","en":"Iris sibirica","sci":"Iris sibirica","order_en":"Asparagales","order_zh":"天门冬目","family_en":"Iridaceae","family_zh":"鸢尾科","iucn":null,"langs":38,"desc_zh":"西伯利亚鸢尾（学名：Iris sibirica）是鸢尾科鸢尾属的植物。其种加词“sibirica”意为“西伯利亚的”。分布于欧洲以及中国大陆的江苏、湖北、江西等地，目前已由人工引种栽培。","desc_en":"Iris sibirica, commonly known as Siberian iris or Siberian flag, is a species of flowering plant in the family Iridaceae. It is a rhizomatous herbaceous perennial, from Europe (including France, Italy, Switzerland, Austria, Czech Republic, Slovakia, Germany, H…","img":"images/150.jpg","thumb":"images/t/150.jpg","file":".00 3385 Sibirische Schwertlilie (Iris sibirica).jpg","ar":0.749,"py":"xiboliyayuanwei xblyyw","cr_by":"W. Bulach","cr_lic":"CC BY-SA 4.0","cr_licurl":"https://creativecommons.org/licenses/by-sa/4.0","habit":"禾草","origin":["亚洲","欧洲"]},{"id":151,"zh":"射干","en":"Iris domestica","sci":"Iris domestica","order_en":"Asparagales","order_zh":"天门冬目","family_en":"Iridaceae","family_zh":"鸢尾科","iucn":null,"langs":29,"desc_zh":"射干（拼音：yè gān，注音：ㄧㄝˋ ㄍㄢ，学名：Iris domestica）为鸢尾科鸢尾属多年生草本植物。《本草经集注·草木下品》云：“此即是乌翣根，庭台多种之，黄色，亦治毒肿。方多作‘夜干’字，今‘射’亦作‘夜’音……又别有射干，相似而花白茎长，似射人之执竿者。”这里的“射人”为古代官名。《本草图经·草部下品之上卷第八》云：“今观射干之形，其茎梗疏长，正如长竿状，得名由此耳。","desc_en":"Iris domestica, commonly known as leopard lily, blackberry lily, and leopard flower, is an ornamental plant in the family Iridaceae. In 2005, based on molecular DNA sequence evidence, Belamcanda chinensis, the sole species in the genus Belamcanda, was transfer…","img":"images/151.jpg","thumb":"images/t/151.jpg","file":"Belamcanda chinensis 2007.jpg","ar":1.501,"py":"shegan sg","cr_by":"Tom Murphy VII","cr_lic":"CC BY 2.5","cr_licurl":"https://creativecommons.org/licenses/by/2.5","habit":null,"origin":null},{"id":152,"zh":"香根鸢尾","en":"Iris pallida","sci":"Iris pallida","order_en":"Asparagales","order_zh":"天门冬目","family_en":"Iridaceae","family_zh":"鸢尾科","iucn":null,"langs":28,"desc_zh":"香根鸢尾（学名：Iris pallida）是鸢尾科鸢尾属的植物。其种加词“pallida ”意为“淡色的”。分布于欧洲以及中国等地，目前已由人工引种栽培。 香根鸢尾的根称为鸢尾根，是西方草药学中的一种重要的草药，现在已成为香水的一种定香剂以及基本香型，也是很多金酒品牌的配料。 香根鸢尾是法国的国花。","desc_en":"Iris pallida, the Dalmatian iris or sweet iris, is a hardy flowering perennial plant of the genus Iris, family Iridaceae. It is native to the Dalmatian coast (Croatia) but widely naturalised elsewhere.","img":"images/152.jpg","thumb":"images/t/152.jpg","file":"Dettaglio - Iridaceae Iris pallida Link. Erbario Frizzi Perugia n. 2407.jpg","ar":0.589,"py":"xianggenyuanwei xgyw","cr_by":"Giuseppe Frizzi","cr_lic":"Public domain","cr_licurl":null,"habit":"草本","origin":null},{"id":153,"zh":"变色鸢尾","en":"Iris versicolor","sci":"Iris versicolor","order_en":"Asparagales","order_zh":"天门冬目","family_en":"Iridaceae","family_zh":"鸢尾科","iucn":"LC","langs":27,"desc_zh":"变色鸢尾（学名：Iris versicolor）是鸢尾科鸢尾属的植物。分布在北美洲以及中国等地，目前已由人工引种栽培。 其种加词“versicolor”意为“变色的”。","desc_en":"Iris versicolor or Iris versicolour is also commonly known as the blue flag, harlequin blueflag, larger blue flag, northern blue flag, and poison flag, plus other variations of these names, and in Great Britain and Ireland as purple iris.","img":"images/153.jpg","thumb":"images/t/153.jpg","file":".00 7973 Verschiedenfarbige Schwertlilie (Iris versicolor).jpg","ar":1.501,"py":"bianseyuanwei bsyw","cr_by":"W. Bulach","cr_lic":"CC BY-SA 4.0","cr_licurl":"https://creativecommons.org/licenses/by-sa/4.0","habit":"禾草","origin":["北美洲"]},{"id":154,"zh":"秋水仙番红花","en":"Crocus tommasinianus","sci":"Crocus tommasinianus","order_en":"Asparagales","order_zh":"天门冬目","family_en":"Iridaceae","family_zh":"鸢尾科","iucn":null,"langs":26,"desc_zh":null,"desc_en":"Crocus tommasinianus, the woodland crocus, early crocus, or Tommasini's crocus, is a species of flowering plant in the family Iridaceae. It is named after the botanist Muzio G. Spirito de Tommasini (1794–1879).","img":"images/154.jpg","thumb":"images/t/154.jpg","file":"Crocus tommasinianum1UME.jpg","ar":0.75,"py":"qiushuixianfanhonghua qsxfhh","cr_by":"Ulf Eliasson","cr_lic":"CC BY 2.5","cr_licurl":"https://creativecommons.org/licenses/by/2.5","habit":null,"origin":null},{"id":155,"zh":"怪味鸢尾","en":"Iris foetidissima","sci":"Iris foetidissima","order_en":"Asparagales","order_zh":"天门冬目","family_en":"Iridaceae","family_zh":"鸢尾科","iucn":null,"langs":26,"desc_zh":null,"desc_en":"Iris foetidissima, the stinking iris, gladdon, Gladwin iris, roast-beef plant, or stinking gladwin, is a species of flowering plant in the family Iridaceae, found in open woodland, hedgebanks and on sea-cliffs.","img":"images/155.jpg","thumb":"images/t/155.jpg","file":"Iris foetidissima PaR.JPG","ar":1.333,"py":"guaiweiyuanwei gwyw","cr_by":"Jymm","cr_lic":"Public domain","cr_licurl":null,"habit":null,"origin":["欧洲"]},{"id":156,"zh":"洋葱","en":"onion","sci":"Allium cepa","order_en":"Asparagales","order_zh":"天门冬目","family_en":"Amaryllidaceae","family_zh":"石蒜科","iucn":null,"langs":199,"desc_zh":"洋葱（学名：Allium cepa），又称圆葱、葱头、洋蒜，新疆地区又称皮芽子，是一种常见的石蒜科葱属植物。 洋葱在全世界广泛栽培，主要用途为食用，既可生食也可烹熟后食用，还可腌渍或制成调味品，多搭配咸味菜肴。生洋葱气味较为辛辣刺鼻，可能会刺激眼睛。 与洋葱同属的常见近缘物种包括大蒜、韭菜、葱、藠头等。红葱头属于洋葱的一个栽培型。","desc_en":"The onion (Allium cepa L.Tooltip Carl Linnaeus, from Latin cepa), also known as the bulb onion or common onion, is a vegetable that is the most widely cultivated species of the genus Allium.","img":"images/156.jpg","thumb":"images/t/156.jpg","file":"Allium cepa, Amol.jpg","ar":1.333,"py":"yangcong yc","cr_by":"Mehdi","cr_lic":"CC BY-SA 3.0","cr_licurl":"https://creativecommons.org/licenses/by-sa/3.0","habit":"乔木","origin":null},{"id":157,"zh":"蒜","en":"Allium sativum","sci":"Allium sativum","order_en":"Asparagales","order_zh":"天门冬目","family_en":"Amaryllidaceae","family_zh":"石蒜科","iucn":null,"langs":186,"desc_zh":"蒜（学名：Allium sativum）是石蒜科葱属的一种植物，亦名大蒜，因原产于中亚及西亚（即中国古代所称的西域），得古名「胡蒜」。蒜有两个自然亚种，人工培育的品种多达上百个。其地下鳞茎味道辛辣，有刺激性气味，称为蒜头，可作调味，亦可入药，为佛教中的五辛之一。蒜叶称为青蒜或蒜苗，花苔称为蒜薹，均可作菜蔬食用。 蒜在世界多地被人类食用、药用的历史长达数千年，栽培广泛，尤其在古埃及、地中海地区及亚洲多地有着深远的文化影响。","desc_en":"Garlic (Allium sativum) is a species of bulbous flowering plants in the genus Allium. Its close relatives include the onion, shallot, leek, chives, Welsh onion, and Chinese onion.","img":"images/157.jpg","thumb":"images/t/157.jpg","file":"Garlic bulbs and cloves.jpg","ar":1.501,"py":"suan s","cr_by":"Ivar Leidus","cr_lic":"CC BY-SA 4.0","cr_licurl":"https://creativecommons.org/licenses/by-sa/4.0","habit":null,"origin":["亚洲"]},{"id":158,"zh":"虾夷葱","en":"Allium schoenoprasum","sci":"Allium schoenoprasum","order_en":"Asparagales","order_zh":"天门冬目","family_en":"Amaryllidaceae","family_zh":"石蒜科","iucn":"LC","langs":89,"desc_zh":"虾夷葱（学名：Allium schoenoprasum），又称细香葱、虾夷葱，是葱属植物的一员。其细长管状叶常同葱一样用为调味料，为常用辛香料，也可用作草药。虾夷葱和洋葱或大蒜相比气味较淡。其英文名称亦称为「chives」，而且一定会加s的复数形，原因是因为它们总是长成一丛而非单独生长。","desc_en":"Chives, scientific name Allium schoenoprasum, is a species of flowering plant in the family Amaryllidaceae. A perennial plant, A. schoenoprasum is widespread in nature across much of Eurasia and North America.","img":"images/158.jpg","thumb":"images/t/158.jpg","file":"Allium schoenoprasum 001.JPG","ar":1.333,"py":"xiayicong xyc","cr_by":"H. Zell","cr_lic":"CC BY-SA 3.0","cr_licurl":"https://creativecommons.org/licenses/by-sa/3.0","habit":"草本","origin":null},{"id":159,"zh":"熊葱","en":"Allium ursinum","sci":"Allium ursinum","order_en":"Asparagales","order_zh":"天门冬目","family_en":"Amaryllidaceae","family_zh":"石蒜科","iucn":null,"langs":86,"desc_zh":"熊葱（学名：Allium ursinum），又名野韭菜、熊果大蒜、熊蒜（bear's garlic）、野蒜菜及林地蒜，是石蒜科葱属的多年生草本植物，学名种加词意为“熊”，因欧洲民间故事中认为熊从冬眠中苏醒后会食用本种植物而得名。食用时味道如同韭菜，但气味相对并不强烈。多生长于林地树荫。春季刚发出的第一至第五叶味道鲜嫩，适于食用，开花后口感下降。","desc_en":"Allium ursinum, known as wild garlic, ramsons, cowleekes, cows's leek, cowleek, buckrams, broad-leaved garlic, wood garlic, bear leek, Eurasian wild garlic, onion grass, or bear's garlic, is a bulbous perennial flowering plant in the amaryllis family, Amarylli…","img":"images/159.jpg","thumb":"images/t/159.jpg","file":"Illustration Allium ursinum1.jpg","ar":0.689,"py":"xiongcong xc","cr_by":null,"cr_lic":"Public domain","cr_licurl":null,"habit":"禾草","origin":["亚洲"]},{"id":160,"zh":"火葱","en":"Allium ascalonicum","sci":"Allium ascalonicum","order_en":"Asparagales","order_zh":"天门冬目","family_en":"Amaryllidaceae","family_zh":"石蒜科","iucn":null,"langs":73,"desc_zh":"火葱（学名：Allium cepa var. aggregatum），又名分葱、红葱头、四季葱、大头葱、珠葱、油葱、朱葱、绵葱、干葱。为石蒜科葱属的多年生草本鳞茎植物。鳞茎表面有紫红色薄膜，肉浅紫白色。原产于西亚，后传播到南亚、东南亚，在中国南方、北非及南欧皆有分布，多生于村边，目前已由人工引种广泛栽培，在亚洲各地广泛作为调味料用蔬菜。火葱原认为是自有的一个物种（Allium ascalonicum），但现已并入洋葱处置。","desc_en":"The shallot or is a cultivar group of the onion. Until 2010, the (French red) shallot was classified as a separate species, Allium ascalonicum. The taxon was synonymized with Allium cepa (the common onion) in 2010, as the difference was too small to justify a…","img":"images/160.jpg","thumb":"images/t/160.jpg","file":"Shallots - sliced and whole.jpg","ar":1.546,"py":"huocong hc","cr_by":"No machine-readable author provided. Charles P. assumed (based on copyright claims).","cr_lic":"Public domain","cr_licurl":null,"habit":null,"origin":["亚洲"]},{"id":161,"zh":"葱","en":"Welsh onion","sci":"Allium fistulosum","order_en":"Asparagales","order_zh":"天门冬目","family_en":"Amaryllidaceae","family_zh":"石蒜科","iucn":null,"langs":63,"desc_zh":"葱（学名：Allium fistulosum），别名青葱、大葱、叶葱、胡葱、冬葱、汉葱、木葱、葱仔、菜伯、水葱、和事草，为多年生草本植物。叶子圆筒形，中间空，脆弱易折，呈青色。在东亚国家以及各处亚裔地区中，葱常作为一种很普遍的香料调味品或蔬菜食用，在东方烹调中占有重要的角色。葱在佛教、道教被归类为为五辛之一，对修行有负面影响，因此佛教徒和道教徒禁止进食含有葱的食品。","desc_en":"Allium fistulosum, the Welsh onion, also commonly called bunching onion, long green onion, Japanese bunching onion, stone leek, rock onion and spring onion, is a species of perennial plant, often considered to be a kind of scallion.","img":"images/161.jpg","thumb":"images/t/161.jpg","file":"Allium fistulosum Ypey26.jpg","ar":0.552,"py":"cong c","cr_by":null,"cr_lic":"Public domain","cr_licurl":null,"habit":"乔木","origin":["亚洲"]},{"id":162,"zh":"雪钟花","en":"Galanthus nivalis","sci":"Galanthus nivalis","order_en":"Asparagales","order_zh":"天门冬目","family_en":"Amaryllidaceae","family_zh":"石蒜科","iucn":"NT","langs":59,"desc_zh":"雪滴花（学名：Galanthus nivalis），是雪花莲属是二十个物种中最著名且分布最广的。雪滴花是春季最早开花的鳞茎，可以在自然的区域形成美丽的白色地毯。较容易与雪片莲属和秋雪片莲属混淆。","desc_en":"Galanthus nivalis, the snowdrop or common snowdrop, is the best-known and most widespread of the 20 species in its genus, Galanthus. Snowdrops are among the first bulbs to bloom in spring and can form impressive carpets of white in areas where they are native…","img":"images/162.jpg","thumb":"images/t/162.jpg","file":"Snowdrops in Lothersdale Churchyard.jpg","ar":1.499,"py":"xuezhonghua xzh","cr_by":"Tim Green","cr_lic":"CC BY 2.0","cr_licurl":"https://creativecommons.org/licenses/by/2.0","habit":null,"origin":null},{"id":163,"zh":"喇叭水仙","en":"Narcissus pseudonarcissus","sci":"Narcissus pseudonarcissus","order_en":"Asparagales","order_zh":"天门冬目","family_en":"Amaryllidaceae","family_zh":"石蒜科","iucn":null,"langs":47,"desc_zh":"黄水仙（学名：Narcissus pseudonarcissus），又名洋水仙、喇叭水仙，是石蒜科水仙属的植物。分布在欧洲等地，目前已由人工引种栽培。多年生草本，鳞茎最大者长0.45米，宽0.1米，花瓣淡黄色，中心副冠是深黄色的喇叭形，边缘不规则褶皱，叶绿色，略带灰色，基生，宽线形，先端钝，顶生1花，花期3－4月。","desc_en":"Narcissus pseudonarcissus, commonly named the wild daffodil or Lent lily (Welsh: Cennin Pedr), is a perennial flowering plant. This species has pale yellow tepals, with a darker central trumpet.","img":"images/163.jpg","thumb":"images/t/163.jpg","file":"- Narcissus pseudonarcissus 03 -.jpg","ar":1.501,"py":"labashuixian lbsx","cr_by":"User:Nino Barbieri","cr_lic":"CC BY-SA 2.5","cr_licurl":"https://creativecommons.org/licenses/by-sa/2.5","habit":"草本","origin":null},{"id":164,"zh":"红口水仙","en":"Narcissus poeticus","sci":"Narcissus poeticus","order_en":"Asparagales","order_zh":"天门冬目","family_en":"Amaryllidaceae","family_zh":"石蒜科","iucn":"LC","langs":43,"desc_zh":"红口水仙（学名：Narcissus poeticus）是水仙属的模式种，原产于中南欧，后来作为观赏植物引入北美等其他地区。其花有香气，高20—40厘米（7.9—15.7英寸）。从中提取的精油可用来制作香水","desc_en":"Narcissus poeticus, the poet's daffodil, poet's narcissus, nargis, pheasant's eye, findern flower or pinkster lily, was one of the first daffodils to be cultivated, and is frequently identified as the narcissus of ancient times (although Narcissus tazetta and…","img":"images/164.jpg","thumb":"images/t/164.jpg","file":"Grandalla (Narcissus poeticus) al Montseny (Catalunya).jpg","ar":0.96,"py":"hongkoushuixian hksx","cr_by":"Arnaucc","cr_lic":"CC BY-SA 3.0","cr_licurl":"https://creativecommons.org/licenses/by-sa/3.0","habit":null,"origin":null},{"id":165,"zh":"象大蒜","en":"Allium ampeloprasum","sci":"Allium ampeloprasum","order_en":"Asparagales","order_zh":"天门冬目","family_en":"Amaryllidaceae","family_zh":"石蒜科","iucn":"LC","langs":42,"desc_zh":null,"desc_en":"Allium ampeloprasum is a member of the onion genus Allium. The wild plant is commonly known as wild leek or broadleaf wild leek. Its native range includes southern Europe, southwestern Asia and North Africa, but it has been cultivated and naturalized in many o…","img":"images/165.jpg","thumb":"images/t/165.jpg","file":"Allium ampeloprasum MHNT.BOT.2006.46.12.jpg","ar":1.302,"py":"xiangdasuan xds","cr_by":"Roger Culos","cr_lic":"CC BY-SA 3.0","cr_licurl":"https://creativecommons.org/licenses/by-sa/3.0","habit":null,"origin":["亚洲","欧洲","非洲"]},{"id":166,"zh":"韭菜","en":"Allium tuberosum","sci":"Allium tuberosum","order_en":"Asparagales","order_zh":"天门冬目","family_en":"Amaryllidaceae","family_zh":"石蒜科","iucn":null,"langs":41,"desc_zh":"韭（jiǔ）菜，又称韮菜（学名：Allium tuberosum），韭菜所在的葱属经过调整，已由原先的百合科搬到石蒜科，是石蒜科葱属的多年生草本植物，丛生，叶细长而扁，开小白花。韭菜又称起阳子，叶和花嫩时可以食用。韭菜采收容易，可用于园艺，在世界广泛种植，并在一些国家被列为入侵植物。","desc_en":"Allium tuberosum (garlic chives, Oriental garlic, Asian chives, Chinese chives, Chinese leek) is a species of plant native to the Chinese province of Shanxi, and cultivated and naturalized elsewhere in Asia and around the world.","img":"images/166.jpg","thumb":"images/t/166.jpg","file":"Allium tuberosum odoratum juliol.JPG","ar":1.195,"py":"jiucai jc","cr_by":"Victor M. Vicente Selvas","cr_lic":"Public domain","cr_licurl":null,"habit":null,"origin":["亚洲"]},{"id":167,"zh":"芦笋","en":"Asparagus officinalis","sci":"Asparagus officinalis","order_en":"Asparagales","order_zh":"天门冬目","family_en":"Asparagaceae","family_zh":"天门冬科","iucn":"LC","langs":112,"desc_zh":"芦笋（学名：Asparagus officinalis）又名石刁柏，为天门冬科天门冬属 多年生开花草本植物。像它的表兄弟韭、葱、蒜，它一度被归入百合科。 芦笋原产于欧洲大部分地区，以及北非和西亚，是被广泛种植的蔬菜作物。绿芦笋和白芦笋只是有无照到阳光的区别。","desc_en":"Asparagus (Asparagus officinalis) or garden asparagus is a perennial flowering plant species in the genus Asparagus native to Eurasia. Widely cultivated as a vegetable crop, its young shoots are used as a spring vegetable.","img":"images/167.jpg","thumb":"images/t/167.jpg","file":"Asparagus plants - geograph.org.uk - 552470.jpg","ar":0.75,"py":"lusun ls","cr_by":"Evelyn Simak","cr_lic":"CC BY-SA 2.0","cr_licurl":"https://creativecommons.org/licenses/by-sa/2.0","habit":"草本","origin":["亚洲"]},{"id":168,"zh":"铃兰","en":"Convallaria majalis","sci":"Convallaria majalis","order_en":"Asparagales","order_zh":"天门冬目","family_en":"Asparagaceae","family_zh":"天门冬科","iucn":null,"langs":98,"desc_zh":"铃兰（学名：Convallaria majalis，英语：Lily of the Valley，法语：Muguet de mai），也称山谷百合、风铃草、君影草，是铃兰属中的唯一种，味甜，高毒性。原产北半球温带，欧、亚及北美洲和中国的东北、华北地区海拔850-2,500处均有野生分布。经典法语歌曲《le temps du muguet》即是指铃兰花。","desc_en":"Lily-of-the-valley (Convallaria majalis), also written as lily of the valley, is a woodland flowering plant with sweetly scented, pendent, bell-shaped white flowers borne in sprays in spring. It is native to Europe, Western Asia and Northern Asia.","img":"images/168.jpg","thumb":"images/t/168.jpg","file":"Convallaria majalis inflorescence - Keila.jpg","ar":0.667,"py":"linglan ll","cr_by":"Ivar Leidus","cr_lic":"CC BY-SA 4.0","cr_licurl":"https://creativecommons.org/licenses/by-sa/4.0","habit":null,"origin":["亚洲","欧洲","北美洲"]},{"id":169,"zh":"剑麻","en":"sisal","sci":"Agave sisalana","order_en":"Asparagales","order_zh":"天门冬目","family_en":"Asparagaceae","family_zh":"天门冬科","iucn":null,"langs":66,"desc_zh":"剑麻（学名：Agave sisalana）又名菠萝麻、琼麻、衿麻，是天门冬科龙舌兰亚科龙舌兰属的一种纤维作物，原产墨西哥南部。1901年由美国领事达文生自夏威夷间接引进至台湾。剑麻常与同亚科的凤尾兰（学名：Yucca gloriosa）混淆。","desc_en":"Sisal (, Spanish: [siˈsal]; Agave sisalana) is a species of flowering plant native to southern Mexico, but widely cultivated and naturalized in many other countries. It yields a stiff leaf fiber used in making rope and various other products.","img":"images/169.jpg","thumb":"images/t/169.jpg","file":"Plantsisal.jpg","ar":0.8,"py":"jianma jm","cr_by":null,"cr_lic":"CC BY-SA 3.0","cr_licurl":"http://creativecommons.org/licenses/by-sa/3.0/","habit":null,"origin":["北美洲"]},{"id":170,"zh":"龙舌兰","en":"Agave americana","sci":"Agave americana","order_en":"Asparagales","order_zh":"天门冬目","family_en":"Asparagaceae","family_zh":"天门冬科","iucn":"LC","langs":54,"desc_zh":"龙舌兰（学名：Agave americana）是一种天门冬科龙舌兰亚科龙舌兰属植物，其鳞根的汁液可以提炼成龙舌兰糖浆并酿制成普逵酒的，但另一种龙舌兰酒特基拉酒（Tequila）所采用的的是龙舌兰属中另外一个种蓝色龙舌兰作为原料，而并非由本种制作而成。","desc_en":"Agave americana, commonly known as the century plant, maguey, or American aloe, is a flowering plant species belonging to the family Asparagaceae. It is native to Mexico and the United States, specifically Texas.","img":"images/170.jpg","thumb":"images/t/170.jpg","file":"14 November 2016, Century plant or Maguey (Agave Americana), Mosqueira.JPG","ar":0.75,"py":"longshelan lsl","cr_by":"Kolforn ( Kolforn ) I'd appreciate if you could mail me (Kolforn@gmail.com) if you want to use this picture out of the W","cr_lic":"CC BY-SA 4.0","cr_licurl":"https://creativecommons.org/licenses/by-sa/4.0","habit":null,"origin":["北美洲"]},{"id":171,"zh":"晚香玉","en":"Agave amica","sci":"Agave amica","order_en":"Asparagales","order_zh":"天门冬目","family_en":"Asparagaceae","family_zh":"天门冬科","iucn":null,"langs":53,"desc_zh":"晚香玉（学名：Polianthes tuberosa），别名月下香，是天门冬科（龙舌兰亚科）晚香玉属的一种多年生球根开花植物。 多年生草本，根状茎块状；线形叶子丛生，先端尖；花茎较长，上部呈总状花序，夏秋开白色花，有浓香味，晚上香味更浓。 晚香玉花在晚上开花，在印度东部地区，被人们称作“Ratkirani”，意思就是“夜晚的女王”。","desc_en":"Polianthes tuberosa, the tuberose, is a perennial plant in the family Asparagaceae, subfamily Agavoideae, extracts of which are used as a note in perfumery. Now widely grown as an ornamental plant, the species is native to Mexico.","img":"images/171.jpg","thumb":"images/t/171.jpg","file":"Polianthes tuberosa, Burdwan, West Bengal, India 25 10 2012.jpg","ar":0.722,"py":"wanxiangyu wxy","cr_by":"JDP90 (Joydeep)","cr_lic":"CC BY-SA 3.0","cr_licurl":"https://creativecommons.org/licenses/by-sa/3.0","habit":"草本","origin":["北美洲"]},{"id":172,"zh":"海葱","en":"Drimia maritima","sci":"Drimia maritima","order_en":"Asparagales","order_zh":"天门冬目","family_en":"Asparagaceae","family_zh":"天门冬科","iucn":"LC","langs":43,"desc_zh":"海葱(Urginea maritima)是天门冬科绵枣儿亚科的多年生鳞茎植物。","desc_en":"Drimia maritima (syn. Urginea maritima) is a species of flowering plant in the family Asparagaceae, subfamily Scilloideae (formerly the family Hyacinthaceae).","img":"images/172.jpg","thumb":"images/t/172.jpg","file":"Drimia maritima - Köhler–s Medizinal-Pflanzen-277.jpg","ar":0.747,"py":"haicong hc","cr_by":"Franz Eugen Köhler, Köhler's Medizinal-Pflanzen","cr_lic":"Public domain","cr_licurl":null,"habit":null,"origin":["亚洲","欧洲","非洲"]},{"id":173,"zh":"风信子","en":"Hyacinthus orientalis","sci":"Hyacinthus orientalis","order_en":"Asparagales","order_zh":"天门冬目","family_en":"Asparagaceae","family_zh":"天门冬科","iucn":null,"langs":38,"desc_zh":"风信子（学名：Hyacinthus orientalis）是天门冬科风信子属的植物。其种加词“orientalis”意为“东方的”。原产于亚洲西南部、土耳其南部和中部、叙利亚西北部、黎巴嫩和以色列北部，在16世纪引种到欧洲。","desc_en":"Hyacinthus orientalis, the common hyacinth, garden hyacinth or Dutch hyacinth, is a species of flowering plant in the family Asparagaceae, subfamily Scilloideae. It is native to western Asia, from southern Turkey, through Syria and Lebanon to northern Israel.","img":"images/173.jpg","thumb":"images/t/173.jpg","file":"Hyacinth bloem.jpg","ar":0.744,"py":"fengxinzi fxz","cr_by":"Rasbak","cr_lic":"CC BY-SA 3.0","cr_licurl":"http://creativecommons.org/licenses/by-sa/3.0/","habit":null,"origin":["亚洲"]},{"id":174,"zh":"蓝铃花","en":"Hyacinthoides non-scripta","sci":"Hyacinthoides non-scripta","order_en":"Asparagales","order_zh":"天门冬目","family_en":"Asparagaceae","family_zh":"天门冬科","iucn":null,"langs":38,"desc_zh":"蓝铃花（Hyacinthoides non-scripta）是一种鳞茎状的多年生植物，它主要分布在西班牙西北部至英伦三岛的大西洋地区。蓝铃花最早由卡尔·林奈在其1753年的著作《植物种志》中描述。","desc_en":"Hyacinthoides non-scripta (formerly Endymion non-scriptus or Scilla non-scripta) is a bulbous perennial plant found in Atlantic areas from the north-western part of the Iberian Peninsula to the British Isles, and also frequently used as a garden plant.","img":"images/174.jpg","thumb":"images/t/174.jpg","file":"Jacinthes des bois (Hyacinthoides non-scripta).jpg","ar":0.667,"py":"lanlinghua llh","cr_by":"JackyM59","cr_lic":"CC BY-SA 4.0","cr_licurl":"https://creativecommons.org/licenses/by-sa/4.0","habit":"草本","origin":["欧洲"]},{"id":175,"zh":"伞花虎眼万年青","en":"Ornithogalum umbellatum","sci":"Ornithogalum umbellatum","order_en":"Asparagales","order_zh":"天门冬目","family_en":"Asparagaceae","family_zh":"天门冬科","iucn":null,"langs":37,"desc_zh":null,"desc_en":"Ornithogalum umbellatum, the garden star-of-Bethlehem, grass lily, nap-at-noon, or eleven-o'clock lady, is a perennial bulbous flowering plant in the asparagus family (Asparagaceae). O.","img":"images/175.jpg","thumb":"images/t/175.jpg","file":"Ornithogalum umbellatum close-up2.jpg","ar":1.333,"py":"sanhuahuyanwannianqing shhywnq","cr_by":"Meneerke bloem","cr_lic":"CC BY-SA 3.0","cr_licurl":"https://creativecommons.org/licenses/by-sa/3.0","habit":"禾草","origin":null},{"id":176,"zh":"短叶丝兰","en":"Yucca brevifolia","sci":"Yucca brevifolia","order_en":"Asparagales","order_zh":"天门冬目","family_en":"Asparagaceae","family_zh":"天门冬科","iucn":"LC","langs":36,"desc_zh":"短叶丝兰（学名：Yucca brevifolia），又名约书亚树，为天门冬科丝兰属下的一个物种，属单子叶树木，分布于美国西南部干燥地区，包括加州、亚利桑那州、犹他州、内华达州至西北墨西哥（下加利福尼亚、南下加利福尼亚州、锡那罗亚与索诺拉沙漠），主要生长于莫哈韦沙漠约书亚树国家公园海拔介于400、1,800米（1,300、5,900英尺）之间的空旷草原（女王山谷与失马山谷）。","desc_en":"Yucca brevifolia (also known as the Joshua tree, yucca palm, tree yucca, and palm tree yucca) is a plant species belonging to the genus Yucca. It is tree-like in appearance, which is reflected in its common names.","img":"images/176.jpg","thumb":"images/t/176.jpg","file":"Joshua Tree NP - Joshua Tree 2.jpg","ar":0.646,"py":"duanyesilan dysl","cr_by":"Jarek Tuszyński","cr_lic":"CC BY-SA 3.0","cr_licurl":"https://creativecommons.org/licenses/by-sa/3.0","habit":"乔木","origin":["北美洲"]},{"id":177,"zh":"吊兰","en":"Chlorophytum comosum","sci":"Chlorophytum comosum","order_en":"Asparagales","order_zh":"天门冬目","family_en":"Asparagaceae","family_zh":"天门冬科","iucn":null,"langs":35,"desc_zh":"吊兰（学名：Chlorophytum comosum）又名钓兰、挂兰、兰草、折鹤兰，欧美国家称蜘蛛草（spider plant），日本称折鹤兰，是相当常见的垂挂式观叶植物，原产于南非。","desc_en":"Chlorophytum comosum, usually called spider plant or common spider plant due to its spider-like look, also known as spider ivy, airplane plant, ribbon plant (a name it shares with Dracaena sanderiana), and hen and chicks, is a species of evergreen perennial fl…","img":"images/177.jpg","thumb":"images/t/177.jpg","file":"Malamadre (Chlorophytum comosum).jpg","ar":1.333,"py":"diaolan dl","cr_by":"Juan Carlos Fonseca Mata","cr_lic":"CC BY-SA 4.0","cr_licurl":"https://creativecommons.org/licenses/by-sa/4.0","habit":"草本","origin":["非洲","大洋洲"]},{"id":178,"zh":"蓝色龙舌兰","en":"Agave tequilana","sci":"Agave tequilana","order_en":"Asparagales","order_zh":"天门冬目","family_en":"Asparagaceae","family_zh":"天门冬科","iucn":null,"langs":34,"desc_zh":"蓝色龙舌兰（英语：Tequila agave，学名：Agave tequilana），又称特基拉龙舌兰，是龙舌兰属的一个物种，是龙舌兰属中能作为龙舌兰酒中等级最高的「特基拉酒」（Tequila）的原料。蓝色龙舌兰是墨西哥哈利斯科州重要的农作物，生长于超过1500公尺的高山上的沙质土壤，长度可达两公尺，约五年后可长达五公尺。","desc_en":"Agave tequilana, commonly called blue agave (agave azul) or tequila agave, is an agave plant that is an important economic product of Jalisco state of Mexico, due to its role as the base ingredient of tequila.","img":"images/178.jpg","thumb":"images/t/178.jpg","file":"Agave tequilana 1.jpg","ar":1.333,"py":"lanselongshelan lslsl","cr_by":"Stan Shebs","cr_lic":"CC BY-SA 3.0","cr_licurl":"https://creativecommons.org/licenses/by-sa/3.0","habit":null,"origin":["北美洲"]},{"id":179,"zh":"朱蕉","en":"Cordyline fruticosa","sci":"Cordyline fruticosa","order_en":"Asparagales","order_zh":"天门冬目","family_en":"Asparagaceae","family_zh":"天门冬科","iucn":"LC","langs":34,"desc_zh":"朱蕉（学名：Cordyline fruticosa）为天门冬科朱蕉属下的一个种，又名红叶铁树。多年生常绿灌木，广布于中国、印度与热带亚洲。 高约 1-2 公尺，叶片聚生于茎的顶端，交互生长，叶的大小依品种而有所不同，叶面颜色、斑纹也因品种不同而有极大差异，朱蕉的园艺变种相当多，约二十种，是台湾相当常见的庭园观叶植物。朱蕉也是药用植物，其花、叶、根均可入药，中国广西民间曾用来治咯血、尿血、菌痢等症。","desc_en":"Cordyline fruticosa is an evergreen flowering plant in the family Asparagaceae. It is known by a wide variety of common names, including ti plant, palm lily, and cabbage palm.","img":"images/179.jpg","thumb":"images/t/179.jpg","file":"Ti plant (Cordyline fruticosa).jpg","ar":0.666,"py":"zhujiao zj","cr_by":"Cliff","cr_lic":"CC BY 2.0","cr_licurl":"https://creativecommons.org/licenses/by/2.0","habit":null,"origin":["亚洲"]},{"id":180,"zh":"库拉索芦荟","en":"Aloe vera","sci":"Aloe vera","order_en":"Asparagales","order_zh":"天门冬目","family_en":"Asphodelaceae","family_zh":"阿福花科","iucn":null,"langs":100,"desc_zh":"芦荟（学名：Aloe vera），又名真芦荟、翠叶芦荟、库拉索芦荟或美国芦荟，是芦荟属下的一种多肉植物。芦荟属广泛分布于全世界的热带及亚热带，包含高海拔、海岸、沙漠、草原等地区。能于花圃或盆栽内种植。尽管芦荟的妆用及药用价值存在争议，但仍出现于许多消费产品。 芦荟为无茎或短茎多肉植物，株高约60-100公分，但根据品种的不同还是有蛮大的差距，像是高芦荟、非洲芦荟等等会高达20米，有的则较短小只有10厘米，像是珍珠芦荟。","desc_en":"Aloe vera () is a succulent plant species of the genus Aloe. It is widely distributed, and is considered an invasive species in many world regions. An evergreen perennial, it originates from the Arabian Peninsula, but also grows wild in tropical, semi-tropical…","img":"images/180.jpg","thumb":"images/t/180.jpg","file":"Starr 011104-0040 Aloe vera.jpg","ar":0.75,"py":"kulasuoluhui klslh","cr_by":"Forest & Kim Starr","cr_lic":"CC BY 3.0","cr_licurl":"https://creativecommons.org/licenses/by/3.0","habit":"多肉","origin":["亚洲"]},{"id":181,"zh":"树丛芦荟","en":"Aloe arborescens","sci":"Aloe arborescens","order_en":"Asparagales","order_zh":"天门冬目","family_en":"Asphodelaceae","family_zh":"阿福花科","iucn":"LC","langs":42,"desc_zh":"树丛芦荟（学名：Aloe arborescens）是阿福花科芦荟属的一种常绿灌木，原产非洲南部的博茨瓦纳、南非、马拉维、莫桑比克、斯威士兰、津巴布韦。也叫大芦荟，日语称木立芦荟（木立アロエ；“木立”在日语中是树丛的意思）。种加词的意思是像树一样。","desc_en":"Aloe arborescens, commonly known as krantz aloe or the candelabra aloe, is a species of flowering succulent perennial plant that belongs to the genus Aloe, which it shares with the well known and studied Aloe vera.","img":"images/181.jpg","thumb":"images/t/181.jpg","file":"Aloe arborescens - Candelabra aloe 01.jpg","ar":1.501,"py":"shucongluhui sclh","cr_by":"Zeynel Cebeci","cr_lic":"CC BY-SA 4.0","cr_licurl":"https://creativecommons.org/licenses/by-sa/4.0","habit":"多肉","origin":null},{"id":182,"zh":"萱草","en":"Hemerocallis fulva","sci":"Hemerocallis fulva","order_en":"Asparagales","order_zh":"天门冬目","family_en":"Asphodelaceae","family_zh":"阿福花科","iucn":null,"langs":34,"desc_zh":"萱草（学名：Hemerocallis fulva）是阿福花科萱草属植物，旧的克朗奎斯特分类法中属于百合科（Liliaceae）。另有黄花萱草、忘忧草、橙萱、紫萱、宜男草、疗愁、鹿箭、黄花菜、金针菜等名。原产于中国、西伯利亚、日本和东南亚，台湾于1661年由华南引入。为中国传统的母亲花，常以萱堂代称母亲，与椿庭相对，古称谖草。","desc_en":"Hemerocallis fulva, the orange day-lily, tawny daylily, corn lily, tiger daylily, fulvous daylily, ditch lily or Fourth of July lily (also railroad daylily, roadside daylily, outhouse lily, track lily, and wash-house lily), is a species of daylily native to As…","img":"images/182.jpg","thumb":"images/t/182.jpg","file":"00 6322 Hemerocallis fulva - Gelbroten Taglilie.jpg","ar":1.501,"py":"xuancao xc","cr_by":"W. Bulach","cr_lic":"CC BY-SA 4.0","cr_licurl":"https://creativecommons.org/licenses/by-sa/4.0","habit":null,"origin":["亚洲"]},{"id":183,"zh":"二歧芦荟","en":"Aloe dichotoma","sci":"Aloe dichotoma","order_en":"Asparagales","order_zh":"天门冬目","family_en":"Asphodelaceae","family_zh":"阿福花科","iucn":null,"langs":31,"desc_zh":"二歧树芦荟（学名：Aloidendron dichotomum）前称二歧芦荟（Aloe dichotoma），是南部非洲特有的一种芦荟，尤其是在南非北开普省及纳米比亚。在尼湖德维（Nieuwoudtville）至洛来斯芳坦（Loeriesfontein）的路上就有一片二歧树芦荟的森林。当地原住的布希曼人会将二歧树芦荟的树干挖空，制成箭筒，故又名箭筒芦荟或箭袋树。","desc_en":"Aloidendron dichotomum, formerly Aloe dichotoma, the quiver tree or kokerboom, is a tall, branching species of succulent plant, indigenous to Southern Africa, specifically in the Northern Cape province of South Africa, and parts of Southern Namibia.","img":"images/183.jpg","thumb":"images/t/183.jpg","file":"Aloe dichotoma -Keetmanshoop, Namibia-21Aug2009-2.jpg","ar":0.75,"py":"erqiluhui eqlh","cr_by":"Le Grand Portage , derivative work: Fletcher6 ( talk )","cr_lic":"CC BY 2.0","cr_licurl":"https://creativecommons.org/licenses/by/2.0","habit":"多肉","origin":["非洲"]},{"id":184,"zh":"新西兰麻","en":"Phormium tenax","sci":"Phormium tenax","order_en":"Asparagales","order_zh":"天门冬目","family_en":"Asphodelaceae","family_zh":"阿福花科","iucn":null,"langs":30,"desc_zh":null,"desc_en":"Phormium tenax (called flax in New Zealand English; harakeke in Māori; New Zealand flax outside New Zealand; and New Zealand hemp in historical nautical contexts) is an evergreen perennial plant native to New Zealand and Norfolk Island that is an important fib…","img":"images/184.jpg","thumb":"images/t/184.jpg","file":"Phormium tenax Piha02.jpg","ar":0.674,"py":"xinxilanma xxlm","cr_by":"Kahuroa","cr_lic":"Public domain","cr_licurl":null,"habit":"草本","origin":["大洋洲"]},{"id":185,"zh":"好望角芦荟","en":"Aloe ferox","sci":"Aloe ferox","order_en":"Asparagales","order_zh":"天门冬目","family_en":"Asphodelaceae","family_zh":"阿福花科","iucn":null,"langs":27,"desc_zh":null,"desc_en":"Aloe ferox, commonly known as bitter aloe, is a species of flowering plant in the family Asphodelaceae. This woody aloe is indigenous to southern Africa. It is one of several Aloe species used to make bitter aloes, a purgative medication, and also yields a non…","img":"images/185.jpg","thumb":"images/t/185.jpg","file":"Aloe Ferox between Cofimvaba and Ngcobo.jpg","ar":0.75,"py":"haowangjiaoluhui hwjlh","cr_by":"Gregorydavid","cr_lic":"CC BY 2.5","cr_licurl":"https://creativecommons.org/licenses/by/2.5","habit":null,"origin":["非洲"]},{"id":186,"zh":"白阿福花","en":"Asphodelus albus","sci":"Asphodelus albus","order_en":"Asparagales","order_zh":"天门冬目","family_en":"Asphodelaceae","family_zh":"阿福花科","iucn":null,"langs":26,"desc_zh":null,"desc_en":"Asphodelus albus, common name white asphodel, is a herbaceous perennial plant belonging to the genus Asphodelus.","img":"images/186.jpg","thumb":"images/t/186.jpg","file":"Asphodelus albus.004 - A Coruña.jpg","ar":0.75,"py":"baiafuhua bafh","cr_by":"Fernando Losada Rodríguez","cr_lic":"CC BY-SA 4.0","cr_licurl":"https://creativecommons.org/licenses/by-sa/4.0","habit":"草本","origin":null},{"id":187,"zh":"天蓝百合","en":"Pasithea caerulea","sci":"Pasithea caerulea","order_en":"Asparagales","order_zh":"天门冬目","family_en":"Xanthorrhoeaceae","family_zh":"黄脂木科","iucn":null,"langs":9,"desc_zh":null,"desc_en":"Pasithea caerulea is a species of herb in the family Asphodelaceae. It is native to Peru and Chile in South America and is the only species in the monotypic genus Pasithea. P.","img":"images/187.jpg","thumb":"images/t/187.jpg","file":"Bluette (3436174277).jpg","ar":1,"py":"tianlanbaihe tlbh","cr_by":"Jason Hollinger","cr_lic":"CC BY 2.0","cr_licurl":"https://creativecommons.org/licenses/by/2.0","habit":"草本","origin":["南美洲"]},{"id":188,"zh":"椰子","en":"Cocos nucifera","sci":"Cocos nucifera","order_en":"Arecales","order_zh":"棕榈目","family_en":"Arecaceae","family_zh":"棕榈科","iucn":null,"langs":155,"desc_zh":"椰（学名：Cocos nucifera），又名椰瓢或可可椰子，是棕榈科椰属的唯一物种。椰子是椰子树的果实，常见于热带地区。椰子树分布广泛的原因之一，是其果实可以在海中随风浪漂流上千公里后在离母树非常远的地方落地生根。一般商业售卖的椰子在收割时仍是绿色的未成熟果实，略呈三角形状，大小接近足球。在泰国南部人们会利用训练过的猕猴来采摘椰子。 一般在原产地以外出售的“椰子”实际上是椰子棕色的核，也叫作「椰仁」，是椰子的种子。","desc_en":"The coconut (Cocos nucifera) is a member of the palm family (Arecaceae) and the only living species of the genus Cocos. The term \"coconut\" (or the archaic \"cocoanut\") can denote the whole coconut palm tree or the large hard fruit.","img":"images/188.jpg","thumb":"images/t/188.jpg","file":"1859-Martinique.web.jpg","ar":0.657,"py":"yezi yz","cr_by":"Patrick Verdier, Free On Line Photos","cr_lic":"Copyrighted free use","cr_licurl":null,"habit":"棕榈","origin":["亚洲"]},{"id":189,"zh":"椰枣","en":"Phoenix dactylifera","sci":"Phoenix dactylifera","order_en":"Arecales","order_zh":"棕榈目","family_en":"Arecaceae","family_zh":"棕榈科","iucn":null,"langs":127,"desc_zh":"椰枣（学名：Phoenix dactylifera），又称枣椰树、海枣、棕栆、波斯枣、伊拉克蜜枣、无漏子、番枣、海棕、仙枣，为棕榈科刺葵属的植物。枣椰树具有耐旱、耐碱、耐热而又喜欢潮湿的特点。 果实产量高，是西亚一些国家的重要出口农作物。枣椰树在阿拉伯神话和伊斯兰教中具有重要地位，沙乌地阿拉伯国徽的上方就是枣椰树。另基督教中之棕树节及犹太教中之住棚节亦与枣椰树有关，可视为中东宗教传统的一大特色。","desc_en":"Phoenix dactylifera, commonly known as the date palm, is a flowering-plant species in the palm family Arecaceae, native to the region from the Gulf States to India. It is cultivated for its edible sweet fruit called dates.","img":"images/189.jpg","thumb":"images/t/189.jpg","file":"Phoenix dactylifera - EJ Burns - 606494286.jpeg","ar":0.75,"py":"yezao yz","cr_by":"EJ Burns","cr_lic":"CC BY 4.0","cr_licurl":"https://creativecommons.org/licenses/by/4.0","habit":"棕榈","origin":["亚洲"]},{"id":190,"zh":"槟榔","en":"Areca catechu","sci":"Areca catechu","order_en":"Arecales","order_zh":"棕榈目","family_en":"Arecaceae","family_zh":"棕榈科","iucn":null,"langs":80,"desc_zh":"槟榔（bīng·láng）（学名：Areca catechu）一词可指其植株或嫩果，别名碌树、宾门、螺果、仁频、仁榔、洗瘴丹、仙瘴丹、榔子、台湾口香糖等；闽南语“菁仔”是指未加工的槟榔嫩果。槟榔与椰子同属棕榈科常绿乔木，主干可长至二十米高。“槟榔”一词源于马来语“pinang”。槟榔原产于马来西亚联邦，分布区域涵盖亚洲的斯里兰卡、泰国、印度、非洲东部及大洋洲等热带地区。国际癌症研究机构认定槟榔是第一类致癌物。","desc_en":"Areca catechu is a species of palm native to the Philippines cultivated for areca nuts. It was carried widely through the tropics by the Austronesian migrations and trade since at least 1500 BCE due to its use in betel nut chewing.","img":"images/190.jpg","thumb":"images/t/190.jpg","file":"Beetle palm with nut bunch.jpg","ar":0.958,"py":"binlang bl","cr_by":"Pratheepps","cr_lic":"CC BY-SA 2.5","cr_licurl":"https://creativecommons.org/licenses/by-sa/2.5","habit":"棕榈","origin":["亚洲"]},{"id":191,"zh":"油棕","en":"Elaeis guineensis","sci":"Elaeis guineensis","order_en":"Arecales","order_zh":"棕榈目","family_en":"Arecaceae","family_zh":"棕榈科","iucn":"LC","langs":57,"desc_zh":"油棕（学名：Elaeis guineensis）又名非洲油棕、油棕榈、油椰子，是棕榈科油棕属的一种植物，其种加词“guineensis”意为“几内亚的”。原产于非洲热带雨林，从西非、中非至东非，分布范围西自塞内加尔，东抵肯尼亚，南起安哥拉，北至乍得，被引入至马来西亚和印度尼西亚、中美洲及南美洲等地区；属于产油经济作物，主要用于生产棕榈油（果肉榨取）及棕仁油（核仁榨取）。","desc_en":"Elaeis guineensis is a species of palm commonly called oil palm but also sometimes African oil palm or macaw-fat. The first Western person to describe it and bring back seeds was the French naturalist Michel Adanson.","img":"images/191.jpg","thumb":"images/t/191.jpg","file":"De la graine de palme.jpg","ar":1.333,"py":"youzong yz","cr_by":"BeraDigle","cr_lic":"CC BY-SA 4.0","cr_licurl":"https://creativecommons.org/licenses/by-sa/4.0","habit":"棕榈","origin":["非洲"]},{"id":192,"zh":"巴西苺","en":"Euterpe oleracea","sci":"Euterpe oleracea","order_en":"Arecales","order_zh":"棕榈目","family_en":"Arecaceae","family_zh":"棕榈科","iucn":null,"langs":55,"desc_zh":"阿萨伊棕榈（英语：acai palm）或千叶菜棕（学名：Euterpe oleracea）是一种原产于巴西亚马逊地区的棕榈树（棕榈科菜椰属），因其果实（阿萨伊果）、棕榈心（作为蔬菜）、叶子和树干木材而被人种植。该物种原产于亚马逊东部，尤其是巴西，主要分布在沼泽和洪泛平原，树干高大细长，可达25米（82英尺）高，羽状叶可长达3米（9.8英尺）。 阿萨伊果（acai berry，acai）又称巴西莓，外表类似蓝莓，可以食用。","desc_en":"The açaí palm ( ə-SY-ee, Brazilian Portuguese: [asaˈi] ; from Nheengatu asai), Euterpe oleracea, is a species of palm tree (Arecaceae) cultivated for its fruit (açaí berries, or simply açaí), hearts of palm (a vegetable), leaves, and trunk wood.","img":"images/192.jpg","thumb":"images/t/192.jpg","file":"Euterpe oleracea salu.jpg","ar":1.333,"py":"baximei bxm","cr_by":"Vihelik","cr_lic":"Public domain","cr_licurl":null,"habit":"棕榈","origin":["南美洲"]},{"id":193,"zh":"糖棕","en":"Borassus flabellifer","sci":"Borassus flabellifer","order_en":"Arecales","order_zh":"棕榈目","family_en":"Arecaceae","family_zh":"棕榈科","iucn":null,"langs":55,"desc_zh":"糖棕又名扇椰子（学名：Borassus flabellifer）为棕榈科糖棕属下的一个种。","desc_en":"Borassus flabellifer, commonly known as doub palm, palmyra palm, tala, tal palm, toddy palm, lontar palm, wine palm, or ice apple, is a fan palm native to South Asia (especially in Bangladesh, East India, and South India) and Southeast Asia.","img":"images/193.jpg","thumb":"images/t/193.jpg","file":"Borassus flabellifer.jpg","ar":0.667,"py":"tangzong tz","cr_by":"Franz Xaver","cr_lic":"CC BY-SA 3.0","cr_licurl":"http://creativecommons.org/licenses/by-sa/3.0/","habit":"棕榈","origin":["亚洲"]},{"id":194,"zh":"加拿利海枣","en":"Lá palama aceitosa","sci":"Phoenix canariensis","order_en":"Arecales","order_zh":"棕榈目","family_en":"Arecaceae","family_zh":"棕榈科","iucn":"LC","langs":52,"desc_zh":"加拿利海枣（学名：Phoenix canariensis）又名长叶刺葵、加拿利枣椰，是一种多年生的棕榈科刺葵属常绿乔木。原产于非洲西海岸的加那利群岛。","desc_en":"Phoenix canariensis, the Canary Island date palm, is a species of flowering plant in the palm family Arecaceae, native to the Canary Islands off the coast of Northwestern Africa. It is a relative of Phoenix dactylifera, the true date palm.","img":"images/194.jpg","thumb":"images/t/194.jpg","file":"Phoenix canariensis kz01.jpg","ar":0.726,"py":"jianalihaizao jnlhz","cr_by":"Krzysztof Ziarnek, Kenraiz","cr_lic":"CC BY-SA 4.0","cr_licurl":"https://creativecommons.org/licenses/by-sa/4.0","habit":"棕榈","origin":["非洲"]},{"id":195,"zh":"蛇皮果","en":"Salacca zalacca","sci":"Salacca zalacca","order_en":"Arecales","order_zh":"棕榈目","family_en":"Arecaceae","family_zh":"棕榈科","iucn":null,"langs":48,"desc_zh":"蛇皮果（学名：Salacca zalacca）是东南亚地区的水果，属于棕榈科蛇皮果属，原产于印尼的爪哇岛及苏门答腊岛，也有在其他地方种植作食用，包括有：巴厘岛、龙目岛、帝汶岛、马来西亚、马鲁古省及苏拉威西。 树叶柄短，可长达6米长，2米宽，中茎15厘米宽，小叶片无数。以红棕色凸凹不平的果皮花纹得名。果实和无花果大小差不多，但果序丛生，味道酸甜。","desc_en":"Salak (Salacca zalacca) is a species of palm tree (family Arecaceae) native to Java and Sumatra in Indonesia. It is cultivated in other regions of Indonesia as a food crop or snack, and popularly grown in Bali, Lombok, Timor, Maluku, Sulawesi and Papua.","img":"images/195.jpg","thumb":"images/t/195.jpg","file":"Salak Salacca zalacca.jpg","ar":0.666,"py":"shepiguo spg","cr_by":"Cliff","cr_lic":"CC BY 2.0","cr_licurl":"https://creativecommons.org/licenses/by/2.0","habit":"棕榈","origin":["亚洲"]},{"id":196,"zh":"丛榈","en":"Chamaerops humilis","sci":"Chamaerops humilis","order_en":"Arecales","order_zh":"棕榈目","family_en":"Arecaceae","family_zh":"棕榈科","iucn":"LC","langs":47,"desc_zh":"丛榈（学名：Chamaerops humilis）为棕榈科矮棕属下的一个种。种加名 humilis 意为“矮的”。","desc_en":"Chamaerops is a genus of flowering plants in the family Arecaceae. It contains only one species, Chamaerops humilis, variously called European fan palm or the Mediterranean dwarf palm.","img":"images/196.jpg","thumb":"images/t/196.jpg","file":"Chamaerops humilis (Zingaro)015.jpg","ar":1.333,"py":"congl cl","cr_by":"tato grasso","cr_lic":"CC BY-SA 2.5","cr_licurl":"https://creativecommons.org/licenses/by-sa/2.5","habit":"棕榈","origin":["欧洲"]},{"id":197,"zh":"海椰子","en":"Lodoicea maldivica","sci":"Lodoicea maldivica","order_en":"Arecales","order_zh":"棕榈目","family_en":"Arecaceae","family_zh":"棕榈科","iucn":"EN","langs":47,"desc_zh":"海椰子（学名：Lodoicea maldivica），又名海底椰、白玉丹、白律丹、绿巨人，是塞舌尔普拉兰岛及屈里厄斯岛的一种特有棕榈。以拥有植物界最大种子著称。过去在不明此一奇特种子原出处时，由于是出现在印度洋以及马尔地夫、印度与斯里兰卡海滩上，所以有「马尔地夫椰子」或「海椰子」之称。「海底椰」一名则更具传奇性，当时人们想像此漂流于海上的核果应是来自于海底植物，成熟脱落后漂浮至海面。 海椰子树高可达30公尺。","desc_en":"Lodoicea, commonly known as the sea coconut, coco de mer, or double coconut, is a monotypic genus in the palm family. The sole species, Lodoicea maldivica, is endemic to the islands of Praslin and Curieuse in the Seychelles, and was historically found on the n…","img":"images/197.jpg","thumb":"images/t/197.jpg","file":"Female coco de mer growth.jpg","ar":0.75,"py":"haiyezi hyz","cr_by":"WL~commonswiki","cr_lic":"CC BY-SA 3.0","cr_licurl":"http://creativecommons.org/licenses/by-sa/3.0/","habit":"棕榈","origin":null},{"id":198,"zh":"硕莪树","en":"Metroxylon sagu","sci":"Metroxylon sagu","order_en":"Arecales","order_zh":"棕榈目","family_en":"Arecaceae","family_zh":"棕榈科","iucn":"LC","langs":41,"desc_zh":"硕莪树（学名：Metroxylon sagu）又名西谷椰子、西密棕、西米椰子，属棕榈科西谷椰属，是一种原生于东南亚马来群岛的植物，以生产西米（硕莪淀粉）而知名。","desc_en":"Metroxylon sagu, the true sago palm, is a species of palm in the genus Metroxylon, native to tropical southeastern Asia. The tree is a major source of sago starch.","img":"images/198.jpg","thumb":"images/t/198.jpg","file":"Sago (Metroxylon sagu) in New Guinea.jpg","ar":0.75,"py":"shuoeshu ses","cr_by":"Toksave","cr_lic":"CC BY-SA 3.0","cr_licurl":"http://creativecommons.org/licenses/by-sa/3.0/","habit":"棕榈","origin":["亚洲"]},{"id":199,"zh":"桄榔","en":"Arenga pinnata","sci":"Arenga pinnata","order_en":"Arecales","order_zh":"棕榈目","family_en":"Arecaceae","family_zh":"棕榈科","iucn":null,"langs":40,"desc_zh":"桄榔（学名：Arenga pinnata）又称砂糖椰子，为棕榈科桄榔属下的一个植物种。由羽状叶片组成辐射状树冠，树干上留有老叶纤维状的黑色叶鞘。桄榔叶长约8.5公尺，其上小叶约1.5公尺长，叶尖形状不规则。生长在雨林，分布于马来西亚、印尼。","desc_en":"Arenga pinnata (syn. Arenga saccharifera) is an economically important feather palm native to tropical Asia, from eastern India east to Malaysia, Indonesia, and the Philippines in the east.","img":"images/199.jpg","thumb":"images/t/199.jpg","file":"Aren pinna 070612 042 stgd.jpg","ar":0.686,"py":"guanglang gl","cr_by":"W.A. Djatmiko ( Wie146 )","cr_lic":"CC BY-SA 3.0","cr_licurl":"https://creativecommons.org/licenses/by-sa/3.0","habit":"棕榈","origin":["亚洲"]},{"id":200,"zh":"水椰","en":"Nypa fruticans","sci":"Nypa fruticans","order_en":"Arecales","order_zh":"棕榈目","family_en":"Arecaceae","family_zh":"棕榈科","iucn":"LC","langs":40,"desc_zh":"水椰（学名：Nypa fruticans）又名亚答树（马来语：atap，意为“屋顶”），棕榈科植物，自成一个单种属，生长在热带沼泽潮间带，也是棕榈科唯一的水生物种。分布于东亚沿海、南亚、东南亚乃至澳洲北部及所罗门群岛。 本种的果实称为亚答籽或水椰子，嫩果可食用。叶子可以编织及盖屋。 一般观点认为水椰属于真红树植物，也有人将其归为半红树植物。它是红树林演替最后阶段的物种，经常形成纯林。","desc_en":"Nypa fruticans, commonly known as the nipa palm (or simply nipa, from Malay: nipah) or mangrove palm, is a species of palm native to the coastlines and estuarine habitats of the Indian and Pacific Oceans.","img":"images/200.jpg","thumb":"images/t/200.jpg","file":"Nipa palms.jpg","ar":1.333,"py":"shuiye sy","cr_by":"Qaalvin","cr_lic":"CC BY-SA 3.0","cr_licurl":"https://creativecommons.org/licenses/by-sa/3.0","habit":"棕榈","origin":["亚洲"]},{"id":201,"zh":"棕榈","en":"Trachycarpus fortunei","sci":"Trachycarpus fortunei","order_en":"Arecales","order_zh":"棕榈目","family_en":"Arecaceae","family_zh":"棕榈科","iucn":null,"langs":39,"desc_zh":"棕榈（学名：Trachycarpus fortunei）又名唐棕、栟棕、栟榈、中国扇棕、棕树、唐棕榈、山棕，是棕榈科棕榈属植物。 种名「fortunei」以英国植物学家福钧（Robert Fortune）的名字命名。","desc_en":"Trachycarpus fortunei, also known as the Chusan palm, Chinese windmill palm, hemp palm, or simply windmill palm, is a species of hardy evergreen palm tree in the family Arecaceae, native to parts of China, Japan, Myanmar and India.","img":"images/201.jpg","thumb":"images/t/201.jpg","file":".00 4850 Chinesische Hanfpalme (Trachycarpus fortunei).jpg","ar":1.501,"py":"zongl zl","cr_by":"W. Bulach","cr_lic":"CC BY-SA 4.0","cr_licurl":"https://creativecommons.org/licenses/by-sa/4.0","habit":"棕榈","origin":["亚洲"]},{"id":202,"zh":"华盛顿棕榈","en":"Washingtonia filifera","sci":"Washingtonia filifera","order_en":"Arecales","order_zh":"棕榈目","family_en":"Arecaceae","family_zh":"棕榈科","iucn":"LC","langs":39,"desc_zh":"丝葵（学名：Washingtonia filifera）又名老人葵、华盛顿椰子等，是棕榈科丝葵属的一种植物。","desc_en":"Washingtonia filifera, commonly known as the California fan palm, cotton palm or desert fan palm, is a flowering plant in the family Arecaceae, native to the far southwestern United States and northwestern Mexico.","img":"images/202.jpg","thumb":"images/t/202.jpg","file":"California fan palm 02.jpg","ar":0.702,"py":"huashengdunzongl hsdzl","cr_by":"Bernard Gagnon","cr_lic":"CC BY-SA 3.0","cr_licurl":"https://creativecommons.org/licenses/by-sa/3.0","habit":"棕榈","origin":["北美洲"]},{"id":203,"zh":"玉米","en":"maize","sci":"Zea mays","order_en":"Poales","order_zh":"禾本目","family_en":"Poaceae","family_zh":"禾本科","iucn":"LC","langs":244,"desc_zh":"玉米（学名：Zea mays）是禾本科玉米属的一年生草本植物，起源于北美洲及由美洲原住民最早种植，后来被引种到世界各地及进行改良，成为全世界总产量最高的重要粮食作物；玉米亦可作饲料使用，还有在生物科技产业作为乙醇燃料的原材料，亦在各个化工领域被大量利用，能做成塑胶等等不同的物品。","desc_en":"Maize (; Zea mays), also known as corn, is a tall stout grass that produces cereal grain. The leafy stalk of the plant gives rise to male inflorescences or tassels which produce pollen, and female inflorescences called ears.","img":"images/203.jpg","thumb":"images/t/203.jpg","file":"Klip kukuruza uzgojen u Međimurju (Croatia).JPG","ar":0.75,"py":"yumi ym","cr_by":"Silverije","cr_lic":"CC BY-SA 3.0","cr_licurl":"https://creativecommons.org/licenses/by-sa/3.0","habit":"禾草","origin":null},{"id":204,"zh":"大麦","en":"Hordeum vulgare","sci":"Hordeum vulgare","order_en":"Poales","order_zh":"禾本目","family_en":"Poaceae","family_zh":"禾本科","iucn":null,"langs":174,"desc_zh":"大麦（学名：Hordeum vulgare，英语：barley）是一种禾本科植物，主要的粮食和饲料作物，也可以作为啤酒或某些蒸馏酒的发酵原料。汉语俗称三月黄。大麦是世界上第四大耕作谷物，仅次于玉米、稻和小麦，2014年，大麦收获面积达49万平方公里，年产量约1.44亿吨；到2016年，大麦世界年产量约1.47亿吨。","desc_en":"Barley (Hordeum vulgare), a member of the grass family, is a major cereal grain grown in temperate climates globally. One of the first cultivated grains, it was domesticated in the Fertile Crescent around 9000 BC, giving it nonshattering spikelets and making i…","img":"images/204.jpg","thumb":"images/t/204.jpg","file":"Champ d'Orge carrée (Hordeum vulgare).jpg","ar":1.501,"py":"damai dm","cr_by":"JackyM59","cr_lic":"CC BY-SA 4.0","cr_licurl":"https://creativecommons.org/licenses/by-sa/4.0","habit":"禾草","origin":null},{"id":205,"zh":"燕麦","en":"Avena sativa","sci":"Avena sativa","order_en":"Poales","order_zh":"禾本目","family_en":"Poaceae","family_zh":"禾本科","iucn":null,"langs":152,"desc_zh":"燕麦（学名：Avena sativa）一称皮燕麦。为禾本科早熟禾亚科燕麦属植物，是人类的主食之一，常制成燕麦片、大燕麦片贩售，大燕麦片也常作为家畜的饲料。燕麦是高营养成份的食物，定期食用时可以降低血液中的胆固醇。 燕麦中所含的燕麦球蛋白（Avenin，是类似小麦中麦胶蛋白的成份）会让少部份人有乳糜泻症状。而燕麦在制造过程也常会混合到少量含有麸质的谷类，例如小麦及大麦。","desc_en":"The oat (Avena sativa), sometimes called the common oat, is a species of cereal grass (Avena) grown for fodder and for its seed, which is known by the same name (usually in the plural).","img":"images/205.jpg","thumb":"images/t/205.jpg","file":"Illustration Avena sativa0.jpg","ar":0.609,"py":"yanmai ym","cr_by":null,"cr_lic":"Public domain","cr_licurl":null,"habit":"禾草","origin":null},{"id":206,"zh":"裸麦","en":"Secale cereale","sci":"Secale cereale","order_en":"Poales","order_zh":"禾本目","family_en":"Poaceae","family_zh":"禾本科","iucn":null,"langs":147,"desc_zh":"黑麦（学名：Secale cereale）又名裸麦，是一种在温带地区分布很广的谷物。相对于小麦来说裸麦更适应冷和干燥的气候。适合高寒或干旱地区生长。2013年联合国粮食及农业组织估计全世界裸麦产量为1670万吨。裸麦和小麦的杂交产品叫做小黑麦，它结合了两种作物的特性。在中欧和东欧，裸麦主要用来烤面包。","desc_en":"Rye (Secale cereale) is a grass grown extensively as a grain, a cover crop and a forage crop. It is grown principally in an area from Eastern and Northern Europe into Russia.","img":"images/206.jpg","thumb":"images/t/206.jpg","file":"Ear of rye.jpg","ar":1.333,"py":"luomai lm","cr_by":"LSDSL","cr_lic":"CC BY-SA 3.0","cr_licurl":"http://creativecommons.org/licenses/by-sa/3.0/","habit":"禾草","origin":["欧洲"]},{"id":207,"zh":"高粱","en":"Sorghum bicolor","sci":"Sorghum bicolor","order_en":"Poales","order_zh":"禾本目","family_en":"Poaceae","family_zh":"禾本科","iucn":null,"langs":90,"desc_zh":"高粱（学名：Sorghum bicolor）又名二色高粱、蜀黍，禾本科，一年生高大草本植物，喜温、抗旱、耐涝，种子有红、白、褐各种颜色，有黏性变种。二色高粱是驯化后的高粱物种，野生的物种和二色高粱组成了高粱属。原产于非洲，目前主要种植在热带及亚热带地区，用世界不同地区的高粱品种间的基因遗传距离大致推算，高粱从印度传入中国的时间约在950年前的辽朝、宋朝及西夏时期。 种名 bicolor 意为“二色的”。","desc_en":"Sorghum bicolor, commonly called sorghum () and also known as broomcorn, great millet, Indian millet, Guinea corn, jowar, or milo, is a species in the grass genus Sorghum. It is typically an annual, but some cultivars are perennial.","img":"images/207.jpg","thumb":"images/t/207.jpg","file":"Sorghum bicolor03.jpg","ar":0.75,"py":"gaoliang gl","cr_by":"No machine-readable author provided. Pethan assumed (based on copyright claims).","cr_lic":"CC BY-SA 3.0","cr_licurl":"http://creativecommons.org/licenses/by-sa/3.0/","habit":"禾草","origin":["亚洲","非洲"]},{"id":208,"zh":"水稻","en":"oryza molida","sci":"Oryza sativa","order_en":"Poales","order_zh":"禾本目","family_en":"Poaceae","family_zh":"禾本科","iucn":null,"langs":88,"desc_zh":"稻（学名：Oryza sativa），其果实为可作为粮食食用部位，称米，是禾本科稻属的一至二年生草本植物，也是稻属中作为粮食的最主要最悠久的一种，又称为亚洲型栽培稻、亚洲稻，简单来说也可以说是“稻”或“稻作”，一般所谓水稻、旱稻也是本种。 依分类学而言，亚洲型栽培稻大致可区分为籼稻（indica）、粳稻（japonica，温带粳稻）与爪哇稻（javanica，热带粳稻）三个亚种。全世界有半数以上人口以水稻为主食。","desc_en":"Oryza sativa, having the common name Asian cultivated rice, is the much more common of the two rice species cultivated as a cereal, the other species being O. glaberrima, African rice.","img":"images/208.jpg","thumb":"images/t/208.jpg","file":"Reis-Rispe.jpg","ar":0.75,"py":"shuidao sd","cr_by":"Leo Michels","cr_lic":"Public domain","cr_licurl":null,"habit":"禾草","origin":["亚洲"]},{"id":209,"zh":"芦苇","en":"Phragmites australis","sci":"Phragmites australis","order_en":"Poales","order_zh":"禾本目","family_en":"Poaceae","family_zh":"禾本科","iucn":"LC","langs":83,"desc_zh":"芦苇（学名：Phragmites australis）属于禾本科芦竹亚科（Arundinoideae）的芦苇属，是生长于沼泽、河沿、海滩等湿地的一种多年生植物，遍布于全世界温带、亚热带及热带地区。","desc_en":"Phragmites australis, known as the common reed, is a species of flowering plant in the grass family Poaceae. It is a wetland grass that can grow up to 20 feet (6 metres) tall and has a cosmopolitan distribution worldwide.","img":"images/209.jpg","thumb":"images/t/209.jpg","file":"Phragmites australis Schilfrohr.jpg","ar":0.763,"py":"luwei lw","cr_by":"Darkone ( talk · contribs )","cr_lic":"CC BY-SA 2.0","cr_licurl":"https://creativecommons.org/licenses/by-sa/2.0","habit":"禾草","origin":null},{"id":210,"zh":"狗牙根","en":"Cynodon dytahilo","sci":"Cynodon dactylon","order_en":"Poales","order_zh":"禾本目","family_en":"Poaceae","family_zh":"禾本科","iucn":null,"langs":80,"desc_zh":"狗牙根（学名：Cynodon dactylon），亦称绊根草（植物名实图考）、铁线草、爬根草、咸沙草、百慕达草，多年生草本植物。","desc_en":"Cynodon dactylon, commonly known as Bermuda grass or as couch grass in Australia and New Zealand, is a grass found worldwide in warm and tropical climates. It is native to Europe, Africa, Australia, and much of Asia and has been introduced to the Americas.","img":"images/210.jpg","thumb":"images/t/210.jpg","file":"Cynodon dactylon RF.jpg","ar":1.333,"py":"gouyagen gyg","cr_by":"Robert Flogaus-Faust","cr_lic":"CC BY 4.0","cr_licurl":"https://creativecommons.org/licenses/by/4.0","habit":"禾草","origin":["亚洲","欧洲","非洲","大洋洲"]},{"id":211,"zh":"小米","en":"Setaria italica","sci":"Setaria italica","order_en":"Poales","order_zh":"禾本目","family_en":"Poaceae","family_zh":"禾本科","iucn":null,"langs":79,"desc_zh":"粟（学名：Setaria italica ；英语：foxtail millet），亦称稷、粱、粟米，北方又称谷子，俗称小米、黄小米、小黄米，属禾本科狗尾草属的一种农作物。也有将穗大毛长粒粗的称为粱，而穗小毛短粒细的称为粟；或是大粟为「粱」，小粟为「粟」。是五谷中籽实最小的。 早在新石器时代就已经开始种植，在青海遗址中也有出土。","desc_en":"Foxtail millet, scientific name Setaria italica (synonym Panicum italicum L.), is an annual grass grown for human food. It is the second-most widely planted species of millet and the most grown millet species in Asia.","img":"images/211.jpg","thumb":"images/t/211.jpg","file":"Foxtailmillet.jpg","ar":1.475,"py":"xiaomi xm","cr_by":"No machine-readable author provided. Marknesbitt assumed (based on copyright claims).","cr_lic":"Public domain","cr_licurl":null,"habit":"禾草","origin":["亚洲"]},{"id":212,"zh":"偃麦草","en":"Elymus repens","sci":"Elymus repens","order_en":"Poales","order_zh":"禾本目","family_en":"Poaceae","family_zh":"禾本科","iucn":null,"langs":75,"desc_zh":"偃麦草（学名：Elymus repens）是一种禾本科植物，原产欧亚大陆和西北非，包括中国甘肃、河北、黑龙江、内蒙古、青海、山东、四川、新疆、西藏、云南等省区。","desc_en":"Elymus repens, commonly known as couch grass , is a very common perennial species of grass native to most of Europe, Asia, the Arctic, and northwest Africa.","img":"images/212.jpg","thumb":"images/t/212.jpg","file":"Kweek Elytrigia repens.jpg","ar":0.757,"py":"yanmaicao ymc","cr_by":"Rasbak","cr_lic":"CC BY-SA 3.0","cr_licurl":"http://creativecommons.org/licenses/by-sa/3.0/","habit":"禾草","origin":["亚洲","欧洲","非洲"]},{"id":213,"zh":"秀贵甘蔗","en":"Saccharum officinarum","sci":"Saccharum officinarum","order_en":"Poales","order_zh":"禾本目","family_en":"Poaceae","family_zh":"禾本科","iucn":null,"langs":69,"desc_zh":"甘蔗（学名：Saccharum officinarum）又名红甘蔗，为禾本科甘蔗属下的一个种。皮墨红色，茎肉富纤维质多汁液，清甜嫩脆、食而不腻，可削皮后直接食用或搾汁饮用。","desc_en":"Saccharum officinarum is a large, strong-growing species of grass in the sugarcane genus. Its stout stalks are rich in sucrose, a disaccharide sugar which accumulates in the stalk internodes.","img":"images/213.jpg","thumb":"images/t/213.jpg","file":"Saccharum officinarum, Mozambique.jpg","ar":0.781,"py":"xiuguiganzhe xggz","cr_by":"Ton Rulkens","cr_lic":"CC BY-SA 2.0","cr_licurl":"https://creativecommons.org/licenses/by-sa/2.0","habit":"禾草","origin":["大洋洲"]},{"id":214,"zh":"斯佩耳特小麦","en":"Triticum spelta","sci":"Triticum spelta","order_en":"Poales","order_zh":"禾本目","family_en":"Poaceae","family_zh":"禾本科","iucn":null,"langs":67,"desc_zh":"斯佩耳特小麦（学名：Triticum spelta）是一种小麦。它在青铜时代到中世纪时的部分欧洲地区都是重要的农产品。如今在中欧仍有种植，作为一种健康食品重新在市场中出现。","desc_en":"Spelt (Triticum spelta), also known as dinkel wheat is a species of wheat. It is a relict crop, eaten in Central Europe and northern Spain. It is high in protein. In Australia it is marketed as a health food.","img":"images/214.jpg","thumb":"images/t/214.jpg","file":"202304 7 Tr.spelta color.svg","ar":0.365,"py":"sipeiertexiaomai spetxm","cr_by":"DataBase Center for Life Science (DBCLS)","cr_lic":"CC BY 4.0","cr_licurl":"https://creativecommons.org/licenses/by/4.0","habit":"禾草","origin":["欧洲"]},{"id":215,"zh":"普通小麦","en":"Triticum aestivum","sci":"Triticum aestivum","order_en":"Poales","order_zh":"禾本目","family_en":"Poaceae","family_zh":"禾本科","iucn":null,"langs":66,"desc_zh":"普通小麦（学名：Triticum aestivum）为禾本科小麦属下的一个种。全世界生产的小麦中约有95%是普通小麦。普通小麦也是全球范围内产量最高的经济作物之一。 普通小麦起源于约8000年前，在外高加索与今伊朗的里海沿岸，二粒小麦偶然与山羊草属的节节麦（Aegilops tauschii）杂交而形成。","desc_en":"Common wheat (Triticum aestivum), also known as bread wheat, is a cultivated wheat species. It originated around 8,000 years ago, from the hybridization of an already existing domesticated variety of wheat and the wild goatgrass in the South Caucasus or southw…","img":"images/215.jpg","thumb":"images/t/215.jpg","file":"Tarweaar.jpg","ar":0.455,"py":"putongxiaomai ptxm","cr_by":"Rasbak","cr_lic":"CC BY-SA 3.0","cr_licurl":"http://creativecommons.org/licenses/by-sa/3.0/","habit":"禾草","origin":["亚洲"]},{"id":216,"zh":"黍","en":"Panicum miliaceum","sci":"Panicum miliaceum","order_en":"Poales","order_zh":"禾本目","family_en":"Poaceae","family_zh":"禾本科","iucn":null,"langs":65,"desc_zh":"黍（shǔ）（学名：Panicum miliaceum）又名糜子、黍稷、糜黍、稷，古称穄，脱壳后称黄米、稷米、粢米，是禾本科黍属的一年生草本植物，生长期短、耐寒、耐旱、耐贫瘠，全球均有分布。主要种植于印度、中国、尼泊尔、非洲、俄罗斯、乌克兰、白俄罗斯和中东等地区。其种子形小可食用，也常用作鸟食和酿酒。","desc_en":"Panicum miliaceum is a grain crop with many common names, including proso millet, broomcorn millet, common millet, hog millet, Kashfi millet, red millet, and white millet.","img":"images/216.jpg","thumb":"images/t/216.jpg","file":"Panicum miliaceum0.jpg","ar":1.333,"py":"shu s","cr_by":"Kurt Stüber [1]","cr_lic":"CC BY-SA 3.0","cr_licurl":"http://creativecommons.org/licenses/by-sa/3.0/","habit":"禾草","origin":["亚洲"]},{"id":217,"zh":"香根草","en":"Chrysopogon zizanioides","sci":"Chrysopogon zizanioides","order_en":"Poales","order_zh":"禾本目","family_en":"Poaceae","family_zh":"禾本科","iucn":null,"langs":60,"desc_zh":"香根草（学名：Chrysopogon zizanioides），又名培地茅、岩兰草、优尸罗草、忧尸罗草、乌施罗草、嗢尸罗草（梵语：उषीर，罗马化：uṣīra）、茅根香（佛经意译），是禾本科多年生草本植物，原产于印度次大陆与中南半岛，经人工栽种，目前广泛分布于亚洲、非洲、美洲与澳洲热带与亚热带地区。 香根草耐暑、耐涝，可度过寒冬，分蘖丛生，生长快速，茎梗直立有节，抽穗成熟一般高达1.5米（4.","desc_en":"Chrysopogon zizanioides, commonly known as vetiver and khus, is a perennial bunchgrass of the family Poaceae. Vetiver is most closely related to sorghum while sharing many morphological characteristics with other fragrant grasses, such as lemongrass (Cymbopogo…","img":"images/217.jpg","thumb":"images/t/217.jpg","file":"Vetiveria zizanioides0.jpg","ar":1.327,"py":"xianggencao xgc","cr_by":null,"cr_lic":"Public domain","cr_licurl":null,"habit":"禾草","origin":null},{"id":218,"zh":"白茅","en":"Imperata cylindrica","sci":"Imperata cylindrica","order_en":"Poales","order_zh":"禾本目","family_en":"Poaceae","family_zh":"禾本科","iucn":null,"langs":59,"desc_zh":"白茅（学名：Imperata cylindrica），又名藗，为禾本科白茅属下的一个种。在中药中食用其根部，称作白茅根，又称作茅根、茅草根、丝茅、茹根，可清热。通常分布于日晒良好的河滩或草原地区。产于中国辽宁、河北、山西、山东、陕西、新疆等北方地区；非洲北部、土耳其、伊拉克、伊朗、中亚、高加索及地中海区域。模式标本采自法国南部。","desc_en":"Imperata cylindrica (commonly known as cogongrass or kunai grass ) is a species of perennial rhizomatous grass native to tropical and subtropical Asia, Micronesia, Melanesia, Australia, Africa, and Southern Europe.","img":"images/218.jpg","thumb":"images/t/218.jpg","file":"JapaneseBloodGrass2.JPG","ar":0.724,"py":"baimao bm","cr_by":"GearedBull at English Wikipedia","cr_lic":"CC BY 3.0","cr_licurl":"https://creativecommons.org/licenses/by/3.0","habit":"禾草","origin":["亚洲","欧洲","非洲","大洋洲"]},{"id":219,"zh":"柠檬草","en":"Cymbopogon citratus","sci":"Cymbopogon citratus","order_en":"Poales","order_zh":"禾本目","family_en":"Poaceae","family_zh":"禾本科","iucn":null,"langs":55,"desc_zh":"柠檬草（学名：Cymbopogon citratus）又名柠檬香茅，生长在开阔的热带干燥土壤，分布于印度南部及斯里兰卡。全株芳香，丛生的球茎上产生大量叶片及分之的圆锥花序。","desc_en":"Cymbopogon citratus, commonly known as West Indian lemon grass or simply lemon grass, is a tropical plant native to South Asia and Maritime Southeast Asia and introduced to many tropical regions. Cymbopogon citratus is often sold in stem form.","img":"images/219.jpg","thumb":"images/t/219.jpg","file":"YosriNov04Pokok Serai.JPG","ar":0.75,"py":"ningmengcao nmc","cr_by":null,"cr_lic":"CC BY 2.0","cr_licurl":"https://creativecommons.org/licenses/by/2.0","habit":"禾草","origin":["亚洲"]},{"id":220,"zh":"野燕麦","en":"Avena fatua","sci":"Avena fatua","order_en":"Poales","order_zh":"禾本目","family_en":"Poaceae","family_zh":"禾本科","iucn":"LC","langs":54,"desc_zh":"野燕麦（学名：Avena fatua）为禾本科燕麦属下的一种植物，为一种常见的杂草。","desc_en":"Avena fatua is a species of grass in the oat genus. It is known as the common wild oat. Like fellow wild oat species A. sterilis, it bears 42 chromosomes, and its seeds shatter at maturity for yearly seeding.","img":"images/220.jpg","thumb":"images/t/220.jpg","file":"OTRS2009032010019662 HEOS4488.jpg","ar":0.667,"py":"yeyanmai yym","cr_by":"Helge Oskarsen","cr_lic":"CC BY-SA 3.0","cr_licurl":"https://creativecommons.org/licenses/by-sa/3.0","habit":"禾草","origin":["亚洲","欧洲"]},{"id":221,"zh":"硬粒小麦","en":"Triticum durum","sci":"Triticum durum","order_en":"Poales","order_zh":"禾本目","family_en":"Poaceae","family_zh":"禾本科","iucn":null,"langs":53,"desc_zh":"硬粒小麦又名杜兰小麦（学名：Triticum durum or Triticum turgidum var. durum）为禾本科小麦属，曾经被归为圆锥小麦的亚种。 基因组学研究表明：50万年前，二倍体的小麦属乌拉尔图小麦（Triticum urartu）与山羊草属的拟山羊草（Aegilops speltoides）杂交，形成了圆锥小麦（T. turgidum）与提莫非维小麦（T.timopheevii），这两种均为四倍体。","desc_en":"Durum (), also called pasta wheat or macaroni wheat (Triticum durum or Triticum turgidum subsp. durum), is a tetraploid species of wheat. It is the second-most cultivated species of wheat after common wheat, although it represents only 5 to 8% of global wheat…","img":"images/221.jpg","thumb":"images/t/221.jpg","file":"Triticum-durum-ear.JPG","ar":1.352,"py":"yinglixiaomai ylxm","cr_by":"Sten Porse","cr_lic":"CC BY-SA 3.0","cr_licurl":"http://creativecommons.org/licenses/by-sa/3.0/","habit":"禾草","origin":["欧洲"]},{"id":222,"zh":"鸭茅","en":"Dactylis glomerata","sci":"Dactylis glomerata","order_en":"Poales","order_zh":"禾本目","family_en":"Poaceae","family_zh":"禾本科","iucn":null,"langs":53,"desc_zh":"鸭茅（学名：Dactylis glomerata）也叫做鸡脚草、果园草，是一种禾本科草本植物。在中国，这种草主要分布于西南部和西北部，是一种喂牛喂马的牧草，一般都是在春天或者秋天的时候播的种。","desc_en":"Dactylis glomerata is a species of flowering plant in the grass family Poaceae, known as cock's-foot, also colloquially as orchard grass, or cat grass (due to its popularity for use with domestic cats).","img":"images/222.jpg","thumb":"images/t/222.jpg","file":"00 2785 Gewöhnliche Knäuelgras (Dactylis glomerata).jpg","ar":0.667,"py":"yamao ym","cr_by":"W. Bulach","cr_lic":"CC BY-SA 4.0","cr_licurl":"https://creativecommons.org/licenses/by-sa/4.0","habit":"禾草","origin":["亚洲","欧洲","非洲"]},{"id":223,"zh":"御谷","en":"Cenchrus americanus","sci":"Cenchrus americanus","order_en":"Poales","order_zh":"禾本目","family_en":"Poaceae","family_zh":"禾本科","iucn":null,"langs":53,"desc_zh":"御谷（学名：Pennisetum glaucum），又名蜡烛稗、珍珠粟，为禾本科狼尾草属的植物。","desc_en":"Pearl millet (Cenchrus americanus, commonly known as the synonym Pennisetum glaucum) is the most widely grown type of millet. It has been grown in Africa and the Indian subcontinent since prehistoric times.","img":"images/223.jpg","thumb":"images/t/223.jpg","file":"Grain millet, early grain fill, Tifton, 7-3-02.jpg","ar":1.333,"py":"yugu yg","cr_by":null,"cr_lic":"Public domain","cr_licurl":null,"habit":"禾草","origin":["亚洲","非洲"]},{"id":224,"zh":"芦荻","en":"Arundo donax","sci":"Arundo donax","order_en":"Poales","order_zh":"禾本目","family_en":"Poaceae","family_zh":"禾本科","iucn":"LC","langs":51,"desc_zh":"芦荻又名芦竹（学名：Arundo donax），是多年生挺水高大宿根草本，形如芦苇。地下茎短缩、粗壮，多分枝，叶片广披针形，圆锥花序顶生，穗状呈扫帚状，9-12月为花果期。为主要水边观景植物。 分布于热带、亚热带，中国华东、华南和西南等地。被国际自然保护联盟物种存续委员会的入侵物种专家小组（ISSG）列入世界百大外来入侵种。","desc_en":"Arundo donax is a tall perennial cane. It is one of several so-called reed species. It has several common names including giant cane, elephant grass, carrizo, arundo, Spanish cane, Colorado river reed, wild cane, and giant reed.","img":"images/224.jpg","thumb":"images/t/224.jpg","file":"Illustration Arundo donax0.jpg","ar":0.566,"py":"ludi ld","cr_by":null,"cr_lic":"Public domain","cr_licurl":null,"habit":"禾草","origin":["亚洲"]},{"id":225,"zh":"多年生黑麦草","en":"Lolium perenne","sci":"Lolium perenne","order_en":"Poales","order_zh":"禾本目","family_en":"Poaceae","family_zh":"禾本科","iucn":null,"langs":49,"desc_zh":"黑麦草（学名：Lolium perenne），又名多年生黑麦草，是一种禾本科植物。在世界各地被广泛种植。原产于西南欧、北非及亚洲西南。可用作饲料，或者用来铺草坪，全英草地网球和门球俱乐部的草坪就是黑麦草铺成的。","desc_en":"Lolium perenne, common name perennial ryegrass, English ryegrass, winter ryegrass, or ray grass, is a grass from the family Poaceae. It is native to Europe, Asia and northern Africa, but is widely cultivated and naturalised around the world.","img":"images/225.jpg","thumb":"images/t/225.jpg","file":"Lolium perenne Engels raaigras doorschietend.jpg","ar":0.75,"py":"duonianshengheimaicao dnshmc","cr_by":"Rasbak","cr_lic":"CC BY-SA 3.0","cr_licurl":"http://creativecommons.org/licenses/by-sa/3.0/","habit":"禾草","origin":["亚洲","欧洲","非洲"]},{"id":226,"zh":"毒麦","en":"Lolium temulentum","sci":"Lolium temulentum","order_en":"Poales","order_zh":"禾本目","family_en":"Poaceae","family_zh":"禾本科","iucn":null,"langs":48,"desc_zh":"毒麦（学名：Lolium temulentum）禾本科黑麦草属的植物。常用作麦类作物遗传学和基因组学研究的模式植物。","desc_en":"Lolium temulentum, typically known as darnel, poison darnel, darnel ryegrass or cockle, is an annual plant of the genus Lolium within the family Poaceae. The plant stem can grow up to one meter tall, with inflorescence in the ears and purple grain.","img":"images/226.jpg","thumb":"images/t/226.jpg","file":"Illustration Leymus arenarius and Lolium temulentum0.jpg","ar":0.605,"py":"dumai dm","cr_by":null,"cr_lic":"Public domain","cr_licurl":null,"habit":"禾草","origin":null},{"id":227,"zh":"梯牧草","en":"Phleum pratense","sci":"Phleum pratense","order_en":"Poales","order_zh":"禾本目","family_en":"Poaceae","family_zh":"禾本科","iucn":null,"langs":46,"desc_zh":"梯牧草（学名：Phleum pratense）又叫提摩草、提摩西草（英语：Timothy-grass）、猫尾草（英语：common cat's tail），是一种多年生禾本科植物，原产于除地中海地区外的欧洲大部分地方。梯牧草生长高度约50至150厘米，叶可长达45厘米、宽达1厘米，花连带密集的小穗有7至15厘米长、8至10毫米宽。","desc_en":"Timothy (Phleum pratense) is a species of perennial grass native to most of Europe and northern and western Asia. It is also known as timothy-grass, meadow cat's-tail or common cat's-tail.","img":"images/227.jpg","thumb":"images/t/227.jpg","file":"Timothy grass.jpg","ar":0.435,"py":"timucao tmc","cr_by":"Blokenearexeter","cr_lic":"CC0","cr_licurl":"http://creativecommons.org/publicdomain/zero/1.0/deed.en","habit":"禾草","origin":["亚洲","欧洲"]},{"id":228,"zh":"草地早熟禾","en":"Poa pratensis","sci":"Poa pratensis","order_en":"Poales","order_zh":"禾本目","family_en":"Poaceae","family_zh":"禾本科","iucn":"LC","langs":45,"desc_zh":"草地早熟禾（学名：Poa pratensis）也称狭颖早熟禾、多花早熟禾、绿早熟禾、扁杆早熟禾，是一种禾本科植物。这种植物原产于欧亚大陆、中亚细亚区，广泛分布于北温带冷凉湿润地区。在中国分布于东北、河北、山东、山西、内蒙古、甘肃、新疆、青海、西藏、四川、江西等省区。 在原产地可做为牧草，因排水良好、可肥沃土壤，也可做为公园的草坪。在美国，美式足球与棒球的多座球场草皮使用草地早熟禾。","desc_en":"Poa pratensis, commonly known as Kentucky bluegrass (or blue grass), smooth meadow-grass, or common meadow-grass, is a perennial species of grass native to practically all of Europe, North Asia and the mountains of Algeria, Morocco, and Tunisia.","img":"images/228.jpg","thumb":"images/t/228.jpg","file":"Poa pratensis (Veldbeemdgras plant).jpg","ar":0.865,"py":"caodizaoshuhe cdzsh","cr_by":"Rasbak 08:35, 1 May 2007 (UTC)","cr_lic":"CC BY-SA 3.0","cr_licurl":"http://creativecommons.org/licenses/by-sa/3.0/","habit":"禾草","origin":["亚洲","欧洲"]},{"id":229,"zh":"稗","en":"Echinochloa crus-galli","sci":"Echinochloa crus-galli","order_en":"Poales","order_zh":"禾本目","family_en":"Poaceae","family_zh":"禾本科","iucn":"LC","langs":45,"desc_zh":"稗（学名：Echinochloa crusgalli），亦称稗子、稗草，为禾本科稗属植物，形似水稻的杂草。 口语广义上的“稗”，涵盖了三个属：稗属、雀稗属、类雀稗属。","desc_en":"Echinochloa crus-galli is a species of wild grass originating from tropical Asia that was formerly classified as a panicum grass. It is commonly known as cockspur (or cockspur grass), barnyard millet, water grass, common barnyard grass, or simply barnyard gras…","img":"images/229.jpg","thumb":"images/t/229.jpg","file":"Echinochloa crus-galli01.jpg","ar":0.667,"py":"bai b","cr_by":"Robert H. Mohlenbrock. USDA SCS. 1989. Midwest wetland flora: Field office illustrated guide to plant species. Midwest N","cr_lic":"Public domain","cr_licurl":null,"habit":"禾草","origin":["亚洲"]},{"id":230,"zh":"苔麸","en":"Eragrostis tef","sci":"Eragrostis tef","order_en":"Poales","order_zh":"禾本目","family_en":"Poaceae","family_zh":"禾本科","iucn":null,"langs":45,"desc_zh":"苔麸（阿姆哈拉语：ጤፍ；提格利尼亚语：ጣፍ；奥罗莫语：xaafii；英语：teff），也称衣索比亚画眉草，是一种原产于非洲之角衣索比亚高原的一年生画眉草，早在公元前1000年，甚至可能在前4000年时，人们就开始种植苔麸以获取其可食用的种子，苔麸至今仍是埃塞俄比亚最重要的主食作物之一，与其他谷类相比，苔麸产量低且易倒伏，苔麸芽蝇是其主要害虫。","desc_en":"Teff (Amharic: ጤፍ), Eragrostis tef, also known as Williams lovegrass and annual bunch grass, is an annual species of lovegrass native to Eritrea and Ethiopia, where it originated in the highlands of both countries.","img":"images/230.jpg","thumb":"images/t/230.jpg","file":"Teff pluim Eragrostis tef.jpg","ar":1.333,"py":"taifu tf","cr_by":"No machine-readable author provided. Rasbak assumed (based on copyright claims).","cr_lic":"CC BY-SA 3.0","cr_licurl":"http://creativecommons.org/licenses/by-sa/3.0/","habit":"禾草","origin":["非洲"]},{"id":231,"zh":"牛筋草","en":"Eleusine indica","sci":"Eleusine indica","order_en":"Poales","order_zh":"禾本目","family_en":"Poaceae","family_zh":"禾本科","iucn":"LC","langs":45,"desc_zh":"牛筋草（学名：Eleusine indica），禾本科䅟属。俗名：蟋蟀草、牛顿草、牛信棕、草霸王（台罗：tsháu-pà-ông）。开花期为全年。繁殖器官是种子。 种名indica意为印度的。","desc_en":"Eleusine indica, the Indian goosegrass, yard-grass, goosegrass, wiregrass, or crowfootgrass, is a species of grass in the family Poaceae. It is a small annual grass distributed throughout the warmer areas of the world to about 50 degrees latitude.","img":"images/231.jpg","thumb":"images/t/231.jpg","file":"Eleusine indica, closeup.jpg","ar":1.127,"py":"niujincao njc","cr_by":"Tauʻolunga","cr_lic":"CC BY-SA 3.0","cr_licurl":"http://creativecommons.org/licenses/by-sa/3.0/","habit":"禾草","origin":null},{"id":232,"zh":"假高粱","en":"Sorghum halepense","sci":"Sorghum halepense","order_en":"Poales","order_zh":"禾本目","family_en":"Poaceae","family_zh":"禾本科","iucn":null,"langs":44,"desc_zh":"石茅（学名：Sorghum halepense）又名约翰逊草(英语：Johnson grass)、假高梁，为禾本科高粱属下的一个种。","desc_en":"Johnson grass or Johnsongrass, Sorghum halepense, is a plant in the grass family, Poaceae, native to Asia and northern Africa. The plant has been introduced to all continents except Antarctica, and most larger islands and archipelagos.","img":"images/232.jpg","thumb":"images/t/232.jpg","file":"Sorghum halepense-Sorgho d'Alep-20150622.jpg","ar":1.501,"py":"jiagaoliang jgl","cr_by":"Daniel VILLAFRUELA .","cr_lic":"CC BY-SA 4.0","cr_licurl":"https://creativecommons.org/licenses/by-sa/4.0","habit":"禾草","origin":["亚洲","非洲","北美洲","南美洲"]},{"id":233,"zh":"䅟子","en":"Eleusine coracana","sci":"Eleusine coracana","order_en":"Poales","order_zh":"禾本目","family_en":"Poaceae","family_zh":"禾本科","iucn":null,"langs":44,"desc_zh":"䅟子（学名：Eleusine coracana）为禾本科䅟属下的一个种。为一年生草本植物，耐旱、耐涝、耐盐碱、耐瘠薄、耐储藏，在中国主要栽培于长江以南和安徽、河南、陕西、西藏等地。茎叶可作编织和造纸原料，或作家畜饲料，子实供食用或供酿酒。别名:龙爪粟，鸭爪粟，鸡爪粟，云南稗，雁爪稗。","desc_en":"Finger millet (Eleusine coracana) is an annual herbaceous plant. It is a tetraploid and self-pollinating species probably evolved from its wild relative Eleusine africana. Finger millet is native to the Ethiopian and Ugandan highlands.","img":"images/233.jpg","thumb":"images/t/233.jpg","file":"Finger Millet Seed.jpg","ar":1.333,"py":"canzi cz","cr_by":"Gaurav Dhwaj Khadka","cr_lic":"CC BY 4.0","cr_licurl":"https://creativecommons.org/licenses/by/4.0","habit":"禾草","origin":["非洲"]},{"id":234,"zh":"一粒小麦","en":"Triticum monococcum","sci":"Triticum monococcum","order_en":"Poales","order_zh":"禾本目","family_en":"Poaceae","family_zh":"禾本科","iucn":"LC","langs":44,"desc_zh":"单粒小麦（学名：Triticum monococcum）是小麦属中最原始的二倍体栽培种，野生的单粒小麦发现于新月沃土地区石器时代的遗址中，约公元前7000年左右在今土耳其东南部地区开始人工培育。单粒小麦的穗较小，麦粒排列紧密，扁平整齐。穗轴脆，易折断。晚熟，产量和品质都极差。可以做小麦种植资源。","desc_en":"Einkorn (from German Einkorn, literally \"single grain\") can refer to either a wild species of wheat (Triticum) or a domesticated form of wheat. The wild form is T. boeoticum (syn. T. m. subsp. boeoticum), and the domesticated form is T. monococcum (syn. T. m.","img":"images/234.jpg","thumb":"images/t/234.jpg","file":"Triticum monococcum0.jpg","ar":0.75,"py":"yilixiaomai ylxm","cr_by":null,"cr_lic":"CC BY-SA 3.0","cr_licurl":"http://creativecommons.org/licenses/by-sa/3.0/","habit":"禾草","origin":null},{"id":235,"zh":"甜根子草","en":"Saccharum spontaneum","sci":"Saccharum spontaneum","order_en":"Poales","order_zh":"禾本目","family_en":"Poaceae","family_zh":"禾本科","iucn":"LC","langs":43,"desc_zh":"甜根子草（学名：Saccharum spontaneum。又名割手密、小巴茅）为禾本科甘蔗属下的一个种。原产于印度，它和甘蔗一样，会把糖分储存在茎里，茎的基部尝起来略带甜味，所以称作甜根子草。多年生草本植物，可长至3米高。","desc_en":"Saccharum spontaneum (wild sugarcane, kans grass) is a grass native throughout much of tropical and subtropical Asia, northern Australia, and eastern and northern Africa.","img":"images/235.jpg","thumb":"images/t/235.jpg","file":"K5601-19.jpg","ar":0.661,"py":"tiangenzicao tgzc","cr_by":"Scott Bauer","cr_lic":"Public domain","cr_licurl":null,"habit":"禾草","origin":["亚洲","非洲","大洋洲"]},{"id":236,"zh":"薏苡","en":"Coix lacryma-jobi","sci":"Coix lacryma-jobi","order_en":"Poales","order_zh":"禾本目","family_en":"Poaceae","family_zh":"禾本科","iucn":null,"langs":43,"desc_zh":"薏苡（学名：Coix lacryma-jobi），别名𧆐、𦼮、草黍子、六谷子、菩提珠、草珠子、薏米、薏仁米、薏仁、沟子米。属禾本科薏苡属。","desc_en":"Job's tears (Coix lacryma-jobi), also known as adlay or adlay millet, is a tall grain-bearing perennial tropical plant of the family Poaceae (grass family).","img":"images/236.jpg","thumb":"images/t/236.jpg","file":"Coix lacryma-jobi1.jpg","ar":0.75,"py":"yiyi yy","cr_by":null,"cr_lic":"CC BY-SA 3.0","cr_licurl":"http://creativecommons.org/licenses/by-sa/3.0/","habit":"禾草","origin":["亚洲"]},{"id":237,"zh":"欧洲海滨草","en":"Ammophila arenaria","sci":"Ammophila arenaria","order_en":"Poales","order_zh":"禾本目","family_en":"Poaceae","family_zh":"禾本科","iucn":null,"langs":43,"desc_zh":null,"desc_en":"Ammophila arenaria (syn Calamagrostis arenaria) is a species of grass in the family Poaceae. It is known by the common names marram grass and European beachgrass. It is one of two species of the genus Ammophila.","img":"images/237.jpg","thumb":"images/t/237.jpg","file":"Hvid klit.jpg","ar":1.338,"py":"ouzhouhaibincao ozhbc","cr_by":"Malene Thyssen (User Malene )","cr_lic":"CC BY-SA 3.0","cr_licurl":"http://creativecommons.org/licenses/by-sa/3.0/","habit":"禾草","origin":["欧洲","非洲"]},{"id":238,"zh":"黄花茅","en":"Anthoxanthum odoratum","sci":"Anthoxanthum odoratum","order_en":"Poales","order_zh":"禾本目","family_en":"Poaceae","family_zh":"禾本科","iucn":null,"langs":42,"desc_zh":"黄花茅（学名：Anthoxanthum odoratum）为禾本科黄花茅属下的一个种。珠高约60公分，春天开花，黄色小花组成圆锥花序。扁平叶片末端尖细，绿色部份含香豆精，具香甜气味。茎硬而光滑不分枝，组成丛簇，根系紧密可防止水土流失。分布亚洲和欧洲，生长在草地及山坡牧场。","desc_en":"Anthoxanthum odoratum is a short-lived perennial grass, commonly known as sweet vernal grass, that is native to acidic grassland in Eurasia and northern Africa.","img":"images/238.jpg","thumb":"images/t/238.jpg","file":"AnthoxanthumOdoratum.jpg","ar":0.621,"py":"huanghuamao hhm","cr_by":null,"cr_lic":"CC BY-SA 3.0","cr_licurl":"http://creativecommons.org/licenses/by-sa/3.0/","habit":"禾草","origin":["亚洲","非洲"]},{"id":239,"zh":"鹬草","en":"Phalaris arundinacea","sci":"Phalaris arundinacea","order_en":"Poales","order_zh":"禾本目","family_en":"Poaceae","family_zh":"禾本科","iucn":"LC","langs":40,"desc_zh":"鹬草（学名：Phalaris arundinacea），又称𬟁草，为禾本科鹬草属下的一种多年生草本植物，广泛分布于欧亚、北非和北美地区，在很多地方是一种入侵植物，生长在水边。 其高度可达两米，圆锥花序高30厘米，叶子通常纯绿，偶有杂色，具粗壮的根状茎，种子传播速度极快，因此难以根除。","desc_en":"Phalaris arundinacea, or reed canary grass, is a tall, perennial grass that commonly forms extensive single-species stands along the margins of lakes and streams and in wet open areas, with a wide distribution in Europe, Asia, northern Africa and North America…","img":"images/239.jpg","thumb":"images/t/239.jpg","file":"Phalaris arundinacea 1.jpg","ar":0.613,"py":"yucao yc","cr_by":"Franz Xaver","cr_lic":"CC BY-SA 3.0","cr_licurl":"https://creativecommons.org/licenses/by-sa/3.0","habit":"禾草","origin":["亚洲","欧洲","非洲","北美洲"]},{"id":240,"zh":"早熟禾","en":"Poa annua","sci":"Poa annua","order_en":"Poales","order_zh":"禾本目","family_en":"Poaceae","family_zh":"禾本科","iucn":"LC","langs":39,"desc_zh":"早熟禾（学名：Poa annua）为禾本科早熟禾属下的一个种。","desc_en":"Poa annua, or annual meadow grass (known in America more commonly as annual bluegrass or simply poa), is a widespread low-growing turfgrass in temperate climates. Notwithstanding the reference to annual plant in its name, perennial biotypes do exist.","img":"images/240.jpg","thumb":"images/t/240.jpg","file":"Poa annua.jpeg","ar":1.333,"py":"zaoshuhe zsh","cr_by":"Kristian Peters -- Fabelfroh 10:06, 7 May 2007 (UTC)","cr_lic":"CC BY-SA 3.0","cr_licurl":"http://creativecommons.org/licenses/by-sa/3.0/","habit":"禾草","origin":null},{"id":241,"zh":"纸莎草","en":"Cyperus papyrus","sci":"Cyperus papyrus","order_en":"Poales","order_zh":"禾本目","family_en":"Cyperaceae","family_zh":"莎草科","iucn":"LC","langs":68,"desc_zh":"纸莎（suō）草（学名：Cyperus papyrus，英语：papyrus），又称纸草、埃及莎草、埃及纸草、蒲草（bulrush）、埃及蒲草、印度丛草（Indian matting plant）等。属于莎草科莎草属。是北非洲原产的一种多年生草本植物。","desc_en":"Cyperus papyrus, better known by the common names papyrus sedge, papyrus, paper reed, Indian matting plant, or Nile grass, is a species of aquatic flowering plant belonging to the sedge family Cyperaceae.","img":"images/241.jpg","thumb":"images/t/241.jpg","file":"Papyrus (Cyperus papyrus) (7079191471).jpg","ar":1.333,"py":"zhisuocao zsc","cr_by":"Bernard DUPONT from FRANCE","cr_lic":"CC BY-SA 2.0","cr_licurl":"https://creativecommons.org/licenses/by-sa/2.0","habit":"禾草","origin":["欧洲","非洲"]},{"id":242,"zh":"香附子","en":"Cyperus rotundus","sci":"Cyperus rotundus","order_en":"Poales","order_zh":"禾本目","family_en":"Cyperaceae","family_zh":"莎草科","iucn":"LC","langs":66,"desc_zh":"香附子（学名：Cyperus rotundus），别名莎草、大香附、香头草、土香草、土香（台湾和闽南一带）、水香棱、地藾草，为莎草科的多年生草本植物，茎直立，三棱形，高40厘米；叶近基生出，细长，呈线形，略比茎短，约20厘米。叶脉平行，中脉明显，春夏开花抽穗，穗状花序做繖房状排列，花序扁状长筒型，红褐色。莎草多生于山坡草地或水边湿地上，在中国广大地区都有分布。","desc_en":"Cyperus rotundus (coco-grass, Java grass, nut grass, purple nut sedge or purple nutsedge, red nut sedge, Khmer kravanh chruk) is a species of sedge (Cyperaceae) native to Africa, southern and central Europe (north to France and Austria), and southern Asia.","img":"images/242.jpg","thumb":"images/t/242.jpg","file":"Nutgrass Cyperus rotundus02.jpg","ar":0.638,"py":"xiangfuzi xfz","cr_by":"No machine-readable author provided. Rickjpelleg assumed (based on copyright claims).","cr_lic":"CC BY 2.5","cr_licurl":"https://creativecommons.org/licenses/by/2.5","habit":"禾草","origin":["亚洲","欧洲","非洲"]},{"id":243,"zh":"荸荠","en":"Eleocharis dulcis","sci":"Eleocharis dulcis","order_en":"Poales","order_zh":"禾本目","family_en":"Cyperaceae","family_zh":"莎草科","iucn":"LC","langs":53,"desc_zh":"荸（bí）荠（qí）（学名：Eleocharis dulcis；英文：Chinese water chestnut），又名马荠、马蹄、地栗、凫茈（cí）、茈骨、乌芋、菩荠、地梨、芍（sháo）、马薯、铺李子，是莎草科荸荠属一种。","desc_en":"Eleocharis dulcis, the Chinese water chestnut or water chestnut, is a grass-like sedge native to Asia, tropical Africa, and Oceania. It is grown in many countries for its edible corms, but if eaten uncooked, the surface of the plants may transmit fasciolopsias…","img":"images/243.jpg","thumb":"images/t/243.jpg","file":"Eleocharis dulcis Blanco1.15.jpg","ar":0.668,"py":"biqi bq","cr_by":"Francisco Manuel Blanco (O.S.A.)","cr_lic":"Public domain","cr_licurl":null,"habit":"禾草","origin":["亚洲","非洲"]},{"id":244,"zh":"油莎草","en":"Cyperus esculentus","sci":"Cyperus esculentus","order_en":"Poales","order_zh":"禾本目","family_en":"Cyperaceae","family_zh":"莎草科","iucn":"LC","langs":46,"desc_zh":"油莎草（学名：Cyperus esculentus），又名油莎豆、铁荸荠、黄土香，英文俗名为Chufa Sedge、Yellow Nutsedge、Tigernut Sedge或Earthalmond。其块茎在英文中称作tigernut，在西班牙文中称作chufa。油莎草是莎草科莎草属植物。","desc_en":"Cyperus esculentus (also called chufa, tiger nut, atadwe, yellow nutsedge, earth almond, and in Chishona, pfende) is a species of plant in the sedge family widespread across much of the world.","img":"images/244.jpg","thumb":"images/t/244.jpg","file":"Cyperus esculentus L. (AM AK301430-1), white background.jpg","ar":0.723,"py":"yousuocao ysc","cr_by":"Wilcox, Mike","cr_lic":"CC BY 4.0","cr_licurl":"https://creativecommons.org/licenses/by/4.0","habit":"禾草","origin":["亚洲","欧洲","非洲"]},{"id":245,"zh":"东方羊胡子草","en":"Eriophorum angustifolium","sci":"Eriophorum angustifolium","order_en":"Poales","order_zh":"禾本目","family_en":"Cyperaceae","family_zh":"莎草科","iucn":"LC","langs":39,"desc_zh":"东方羊胡子草（学名：Eriophorum angustifolium）为莎草科羊胡子草属下的一个种。 为多年生草本植物，可高达60厘米。其种子成熟后分裂出状如棉絮的白色细丝，可以随风飞散，以利于传播种子。","desc_en":"Eriophorum angustifolium, commonly known as common cottongrass or common cottonsedge, is a species of flowering plant in the sedge family, Cyperaceae. Native to North America, North Asia, and Europe, it grows on peat or acidic soils, in open wetland, heath or…","img":"images/245.jpg","thumb":"images/t/245.jpg","file":"00 3892 Schmalblättrige Wollgras (Eriophorum angustifolium).jpg","ar":0.667,"py":"dongfangyanghuzicao dfyhzc","cr_by":"W. Bulach","cr_lic":"CC BY-SA 4.0","cr_licurl":"https://creativecommons.org/licenses/by-sa/4.0","habit":"禾草","origin":["亚洲","欧洲","北美洲"]},{"id":246,"zh":"海滨三棱草","en":"Bolboschoenus maritimus","sci":"Bolboschoenus maritimus","order_en":"Poales","order_zh":"禾本目","family_en":"Cyperaceae","family_zh":"莎草科","iucn":"LC","langs":37,"desc_zh":"海滨三棱草（学名：Bolboschoenus maritimus），是莎草科三棱草属多年生草本植物，广布于温带、亚热带地区；在中国分布于新疆；台湾可能有分布。","desc_en":"Bolboschoenus maritimus is a species of flowering plant from family Cyperaceae. Common names for this species include sea clubrush, cosmopolitan bulrush, alkali bulrush, saltmarsh bulrush, and bayonet grass.","img":"images/246.jpg","thumb":"images/t/246.jpg","file":"Bolboschoenus maritimus syn Cyperus maritimus.jpg","ar":0.402,"py":"haibinsanlengcao hbslc","cr_by":"Johann Georg Sturm (Painter: Jacob Sturm )","cr_lic":"Public domain","cr_licurl":null,"habit":"禾草","origin":null},{"id":247,"zh":"Carex arenaria","en":"Carex arenaria","sci":"Carex arenaria","order_en":"Poales","order_zh":"禾本目","family_en":"Cyperaceae","family_zh":"莎草科","iucn":null,"langs":37,"desc_zh":null,"desc_en":"Carex arenaria, or sand sedge, is a species of perennial sedge of the genus Carex which is commonly found growing in dunes and other sandy habitats, as the species epithet suggests (Latin arenarius, \"sandy\"). It grows by long stolons under the soil surface.","img":"images/247.jpg","thumb":"images/t/247.jpg","file":"CarexArenaria.jpg","ar":0.687,"py":"","cr_by":"Christian Fischer","cr_lic":"CC BY-SA 3.0","cr_licurl":"https://creativecommons.org/licenses/by-sa/3.0","habit":"禾草","origin":null},{"id":248,"zh":"华一本芒","en":"Cladium mariscus","sci":"Cladium mariscus","order_en":"Poales","order_zh":"禾本目","family_en":"Cyperaceae","family_zh":"莎草科","iucn":"LC","langs":36,"desc_zh":"华一本芒（学名：Cladium mariscus）又名华克拉莎，为莎草科一本芒属的植物。分布在朝鲜、日本以及中国大陆的云南、广西、广东等地，生长于海拔2,200米的地区，目前尚未由人工引种栽培。","desc_en":"Cladium mariscus is a species of flowering plant in the sedge family known by the common names swamp sawgrass, great fen-sedge, saw-sedge or sawtooth sedge. Previously it was known as elk sedge.","img":"images/248.jpg","thumb":"images/t/248.jpg","file":"Cladium mariscus.jpeg","ar":1.333,"py":"huayibenmang hybm","cr_by":"Kristian Peters -- Fabelfroh 15:47, 20 October 2006 (UTC)","cr_lic":"CC BY-SA 3.0","cr_licurl":"http://creativecommons.org/licenses/by-sa/3.0/","habit":"禾草","origin":["亚洲","欧洲"]},{"id":249,"zh":"沼生水葱","en":"Schoenoplectus lacustris","sci":"Schoenoplectus lacustris","order_en":"Poales","order_zh":"禾本目","family_en":"Cyperaceae","family_zh":"莎草科","iucn":"LC","langs":35,"desc_zh":null,"desc_en":"Schoenoplectus lacustris, the common club-rush, is a species of club-rush (genus Schoenoplectus) that grows in fresh water across Europe, much of Asia, and with a disjunct population in southern Africa.","img":"images/249.jpg","thumb":"images/t/249.jpg","file":"Schoenoplectus acutus var occidentalis.jpg","ar":0.667,"py":"zhaoshengshuicong zssc","cr_by":null,"cr_lic":"Public domain","cr_licurl":null,"habit":"禾草","origin":["亚洲","欧洲","非洲"]},{"id":250,"zh":"湿生苔草","en":"Carex limosa","sci":"Carex limosa","order_en":"Poales","order_zh":"禾本目","family_en":"Cyperaceae","family_zh":"莎草科","iucn":"LC","langs":35,"desc_zh":"湿生苔草（学名：Carex limosa）为莎草科苔草属的植物。分布于俄罗斯西伯利亚和远东地区、日本、蒙古、朝鲜、欧洲、北美以及中国大陆的辽宁、黑龙江等地，生长于海拔700米的地区，多生于沼泽地以及水边草地，目前尚未由人工引种栽培。","desc_en":"Carex limosa is a species of sedge known as bog-sedge, mud sedge, and shore sedge.","img":"images/250.jpg","thumb":"images/t/250.jpg","file":"Carex limosa inflorescence kz.jpg","ar":0.764,"py":"shishengtaicao sstc","cr_by":"Krzysztof Ziarnek","cr_lic":"CC BY-SA 3.0","cr_licurl":"http://creativecommons.org/licenses/by-sa/3.0/","habit":"禾草","origin":null},{"id":251,"zh":"菠萝","en":"Ananas comosus","sci":"Ananas comosus","order_en":"Poales","order_zh":"禾本目","family_en":"Bromeliaceae","family_zh":"凤梨科","iucn":null,"langs":154,"desc_zh":"菠萝（学名：Ananas comosus，星马称黄梨，台湾称凤梨）是一种原产于南美洲的热带水果，为禾本目凤梨科凤梨属植物，因多汁酸甜受到喜爱，有解暑之效，是凤梨科中最具经济价值的种类。其食用部位并非果实，而是肥大的肉质花序轴。南美洲种植凤梨已有许多世纪，在17世纪传入欧洲，于1820年代开始在温室与热带地区开始商业种植。","desc_en":"The pineapple (Ananas comosus) is a tropical plant with an edible fruit; it is the most economically significant plant in the family Bromeliaceae. The pineapple is native to South America, where it has been cultivated for many centuries.","img":"images/251.jpg","thumb":"images/t/251.jpg","file":"Nanas variegata cheche.jpg","ar":1.333,"py":"boluo bl","cr_by":"VpuipV ,pemegang hak cipta","cr_lic":"CC BY-SA 4.0","cr_licurl":"https://creativecommons.org/licenses/by-sa/4.0","habit":"灌木","origin":["南美洲"]},{"id":252,"zh":"松萝菠萝","en":"Tillandsia usneoides","sci":"Tillandsia usneoides","order_en":"Poales","order_zh":"禾本目","family_en":"Bromeliaceae","family_zh":"凤梨科","iucn":"LC","langs":37,"desc_zh":"松萝凤梨（学名：Tillandsia usneoides）为菠萝科空气凤梨属下的一个种，英文俗称“西班牙藓”（Spanish moss），在法属波利尼西亚俗称“老人须”（grandpa's beard）。","desc_en":"Spanish moss (Tillandsia usneoides) is an epiphytic flowering plant that often grows upon large trees in tropical and subtropical climates. It is native to much of Mexico, Bermuda, the Bahamas, Central America, South America (as far south as northern Patagonia…","img":"images/252.jpg","thumb":"images/t/252.jpg","file":"Flickr - ggallice - Spanish moss flower.jpg","ar":0.685,"py":"songluoboluo slbl","cr_by":"Geoff Gallice from Gainesville, FL, USA","cr_lic":"CC BY 2.0","cr_licurl":"https://creativecommons.org/licenses/by/2.0","habit":"乔木","origin":["欧洲","北美洲","南美洲"]},{"id":253,"zh":"莴氏普亚凤梨","en":"Puya Raymondi violadora","sci":"Puya raimondii","order_en":"Poales","order_zh":"禾本目","family_en":"Bromeliaceae","family_zh":"凤梨科","iucn":"EN","langs":28,"desc_zh":"莴氏普亚凤梨（学名Puya raimondii），又名安地斯皇后，是玻利维亚及秘鲁特有的一种凤梨科植物，生长在海拔3200-4800米处。它们是由法国科学家阿尔西德·道比尼（Alcide d'Orbigny）于1830年在玻利维亚科恰班巴省海拔3960米处发现。取此名是为纪念在秘鲁进行多年研究的义大利植物学家安东尼奥·莱蒙廸（Antonio Raimondi）。道比尼后来在秘鲁查文德万塔尔也发现此种植物。 莴氏普亚凤梨的花序巨大。","desc_en":"Puya raimondii, also known as the Queen of the Andes (English), titanka and ilakuash (Quechua) or puya de Raimondi (Spanish), is the largest species of bromeliad, its inflorescences reaching up to 15 m (50 ft) in height.","img":"images/253.jpg","thumb":"images/t/253.jpg","file":"Puya raimondii hábito.jpg","ar":0.75,"py":"woshipuyafengli wspyfl","cr_by":"Pepe Roque","cr_lic":"CC BY-SA 3.0","cr_licurl":"https://creativecommons.org/licenses/by-sa/3.0","habit":null,"origin":["南美洲"]},{"id":254,"zh":"蜻蜓菠萝","en":"Aechmea fasciata","sci":"Aechmea fasciata","order_en":"Poales","order_zh":"禾本目","family_en":"Bromeliaceae","family_zh":"凤梨科","iucn":null,"langs":25,"desc_zh":"蜻蜓菠萝（学名：Aechmea fasciata），又叫蜻蜓凤梨、斑粉菠萝、美叶光萼荷，为凤梨科萼凤梨属附生草本植物，或菠萝科蜻蜓菠萝属下的一个种。原产于巴西，附生在雨林树干上。喜半阴、温暖和潮湿环境。生长适温为15—25℃，越冬温度约为10℃。对环境适应力强，既耐阴也耐旱。栽培3、4年后开花。","desc_en":"Aechmea fasciata is a species of flowering plant in the Bromeliaceae family. It is commonly called the silver vase or urn plant and is native to Brazil. This plant is probably the best known species in this genus, and it is often grown as a houseplant in tempe…","img":"images/254.jpg","thumb":"images/t/254.jpg","file":"Aechmea fasciata2.jpg","ar":1.333,"py":"qingtingboluo qtbl","cr_by":"Paul & Aline Burland","cr_lic":"CC BY-SA 2.0","cr_licurl":"https://creativecommons.org/licenses/by-sa/2.0","habit":null,"origin":["南美洲"]},{"id":255,"zh":"食蚁凤梨","en":"Brocchinia reducta","sci":"Brocchinia reducta","order_en":"Poales","order_zh":"禾本目","family_en":"Bromeliaceae","family_zh":"凤梨科","iucn":null,"langs":19,"desc_zh":null,"desc_en":"Brocchinia reducta is a carnivorous plant in the bromeliad family. It is native to southern Venezuela, Brazil, Colombia, and Guyana, and is found in areas with nutrient-poor, high moisture soil. B.","img":"images/255.jpg","thumb":"images/t/255.jpg","file":"Brocchinia reducta (Roraima tepui).jpg","ar":1.504,"py":"shiyifengli syfl","cr_by":"Christian Hummert","cr_lic":"CC BY-SA 2.0 de","cr_licurl":"https://creativecommons.org/licenses/by-sa/2.0/de/deed.en","habit":null,"origin":["南美洲"]},{"id":256,"zh":"贝尔特罗嘉宝凤梨","en":"Catopsis berteroniana","sci":"Catopsis berteroniana","order_en":"Poales","order_zh":"禾本目","family_en":"Bromeliaceae","family_zh":"凤梨科","iucn":null,"langs":16,"desc_zh":"贝尔特罗嘉宝凤梨（学名：Catopsis berteroniana；标音：kətɒpsɪs bɚtəɹəʊniːɑːnə）为著生的凤梨科植物，被认为可能是食肉植物，类似瘦缩布洛凤梨，通常也称作著生食虫凤梨，尽管有迹象显示这仍是有疑问的。原产佛罗里达南部到巴西南部一带。一般生长在树上无遮荫的细枝，而且似乎能比其它可媲美本种大小的积水凤梨捕捉到更多的虫子在它积水槽。本属另有许多其它种类， 然而都没有被认定是食肉植物。","desc_en":"Catopsis berteroniana , commonly known as the powdery strap airplant or the lantern of the forest, is an epiphytic bromeliad thought to be a possible carnivorous plant, similar to Brocchinia reducta, although the evidence is equivocal.","img":"images/256.jpg","thumb":"images/t/256.jpg","file":"CatopsisBerteroniana AtSierraDeLema4836.jpg","ar":0.648,"py":"beierteluojiabaofengli betljbfl","cr_by":"BotBln","cr_lic":"CC BY-SA 3.0","cr_licurl":"http://creativecommons.org/licenses/by-sa/3.0/","habit":"乔木","origin":["北美洲","南美洲"]},{"id":257,"zh":"高山普亚凤梨","en":"Puya alpestris","sci":"Puya alpestris","order_en":"Poales","order_zh":"禾本目","family_en":"Bromeliaceae","family_zh":"凤梨科","iucn":null,"langs":16,"desc_zh":null,"desc_en":"Puya alpestris is a species of bromeliad endemic to the Chilean Andes. It is native to dry hills, rock outcrops in central and southern Chile at elevations of 0 to 2200 meters. It is one of the most southerly occurring species within the family.","img":"images/257.jpg","thumb":"images/t/257.jpg","file":"Puyaalpestris1.JPG","ar":1.333,"py":"gaoshanpuyafengli gspyfl","cr_by":"Stickpen","cr_lic":"Public domain","cr_licurl":null,"habit":null,"origin":["南美洲"]},{"id":258,"zh":"智利普亚凤梨","en":"Puya chilensis","sci":"Puya chilensis","order_en":"Poales","order_zh":"禾本目","family_en":"Bromeliaceae","family_zh":"凤梨科","iucn":null,"langs":16,"desc_zh":"智利普亚凤梨（羊惧树）（学名：Puya chilensis）为原生于智利山区的干燥地带的多年生常绿陆生凤梨科植物。叶互生，呈灰绿色长带状，叶缘带有刺齿，纤维可用来编制渔网。黄色或绿色的花呈总状花序，外型类似中世纪的晨曦之星，高度可达2米（6英尺7英寸）。能透过侧生芽进行无性生殖，但是植株生长缓慢，需要生长超过 20 年才会开花。叶片上的棘齿可能可以用来保护植株的中心部分不会受到草食动物的啃食。","desc_en":"Puya chilensis is a species of terrestrial bromeliad. It is endemic to central Chile.","img":"images/258.jpg","thumb":"images/t/258.jpg","file":"Puya chilensis - nebrooks - 606660188.jpeg","ar":0.563,"py":"zhilipuyafengli zlpyfl","cr_by":"nebrooks","cr_lic":"CC BY 4.0","cr_licurl":"https://creativecommons.org/licenses/by/4.0","habit":null,"origin":["南美洲"]},{"id":259,"zh":"垂花水塔花","en":"Billbergia nutans","sci":"Billbergia nutans","order_en":"Poales","order_zh":"禾本目","family_en":"Bromeliaceae","family_zh":"凤梨科","iucn":null,"langs":16,"desc_zh":"垂花水塔花（学名：Billbergia nutans）为凤梨科水塔花属的植物。分布于巴西，生长于海拔200米至600米的地区，目前已由人工引种栽培。","desc_en":"Billbergia nutans, or Queen's-tears, is an epiphytic bromeliad native to Brazil, Paraguay, Uruguay, and Argentina. This plant is often used as an ornamental plant.","img":"images/259.jpg","thumb":"images/t/259.jpg","file":"Billbergia nutans1SHSU.jpg","ar":1.333,"py":"chuihuashuitahua chsth","cr_by":"Shu Suehiro","cr_lic":"CC BY 3.0","cr_licurl":"https://creativecommons.org/licenses/by/3.0","habit":null,"origin":["南美洲"]},{"id":260,"zh":"灯心草","en":"Juncus effusus","sci":"Juncus effusus","order_en":"Poales","order_zh":"禾本目","family_en":"Juncaceae","family_zh":"灯心草科","iucn":"LC","langs":40,"desc_zh":"灯心草（学名：Juncus effusus），又名圆蔺（lìn）、灯芯草、水灯花、水灯心、蔺草、灯草、龙须草、野席草、马棕根、野马棕，是灯心草属多年生草本植物，分布于全球温暖地区，生长于海拔200－3,400米的地区。其种加词“Effusus”意为“散乱的”。","desc_en":"Juncus effusus is a perennial herbaceous flowering plant species in the rush family Juncaceae, with the common names common rush or soft rush.","img":"images/260.jpg","thumb":"images/t/260.jpg","file":"Juncus effuses.jpg","ar":1.333,"py":"dengxincao dxc","cr_by":"The original uploader was Meggar at English Wikipedia .","cr_lic":"CC BY-SA 3.0","cr_licurl":"http://creativecommons.org/licenses/by-sa/3.0/","habit":"禾草","origin":null},{"id":261,"zh":"地杨梅","en":"Luzula campestris","sci":"Luzula campestris","order_en":"Poales","order_zh":"禾本目","family_en":"Juncaceae","family_zh":"灯心草科","iucn":null,"langs":32,"desc_zh":"地杨梅（学名：Luzula campestris）为灯心草科地杨梅属下的一个种。","desc_en":"Luzula campestris, commonly known as field wood-rush or Good Friday grass is a flowering plant in the rush family Juncaceae. It is also one of the plants known as chimney sweeps or sweep's broom because of the brush-like appearance of their flowers.","img":"images/261.jpg","thumb":"images/t/261.jpg","file":"Luzula campestris IP0605002.jpg","ar":0.699,"py":"diyangmei dym","cr_by":"Leo Michels User:Der Michels","cr_lic":"Public domain","cr_licurl":null,"habit":"禾草","origin":["亚洲","欧洲"]},{"id":262,"zh":"宽叶香蒲","en":"Typha latifolia","sci":"Typha latifolia","order_en":"Poales","order_zh":"禾本目","family_en":"Typhaceae","family_zh":"香蒲科","iucn":"LC","langs":60,"desc_zh":"宽叶香蒲（学名：Typha latifolia），别名香蒲、蒲黄，为香蒲科香蒲属的植物，广泛分布于南北美、欧洲、亚洲和非洲，环境适应能力很强。高可达三米。 香蒲可当做水生蔬菜。可作蔬菜的部分有假茎基部（蒲菜）、地下幼嫩的匍匐茎和芽（象牙菜），炒食或烩菜，也可做汤。印第安人也有食用它的习惯。","desc_en":"Typha latifolia is a perennial herbaceous wetland plant in the genus Typha. It is known in English as bulrush (sometimes as common bulrush to distinguish from other species of Typha), and in North America as broadleaf cattail.","img":"images/262.jpg","thumb":"images/t/262.jpg","file":"Lisdodde.jpg","ar":0.75,"py":"kuanyexiangpu kyxp","cr_by":"Andrawaag","cr_lic":"CC BY-SA 4.0","cr_licurl":"https://creativecommons.org/licenses/by-sa/4.0","habit":"禾草","origin":["北美洲"]},{"id":263,"zh":"Syngonanthus nitens","en":"Syngonanthus nitens","sci":"Syngonanthus nitens","order_en":"Poales","order_zh":"禾本目","family_en":"Eriocaulaceae","family_zh":"谷精草科","iucn":null,"langs":12,"desc_zh":null,"desc_en":"Syngonanthus nitens is a grass-like species of Eriocaulaceae which exists in the region of Jalapão, state of Tocantins, Brazil - the region is part of the Brazilian cerrado.","img":"images/263.jpg","thumb":"images/t/263.jpg","file":"Capim Dourado.JPG","ar":1.506,"py":"","cr_by":"Daniel.zilenovski","cr_lic":"CC BY-SA 3.0","cr_licurl":"https://creativecommons.org/licenses/by-sa/3.0","habit":"禾草","origin":["南美洲"]},{"id":264,"zh":"鸭跖草","en":"Commelina communis","sci":"Commelina communis","order_en":"Commelinales","order_zh":"鸭跖草目","family_en":"Commelinaceae","family_zh":"鸭跖草科","iucn":null,"langs":30,"desc_zh":"鸭跖草（学名：Commelina communis），古名鼻斫草，又名鸡舌草、淡竹叶、竹叶菜、碧蝉花，为鸭跖草科鸭跖草属一年生草本植物。原生于中国大陆的四川、云南、甘肃以东的区域、台湾、朝鲜、俄罗斯远东地区、日本、越南，也引入到了欧洲中部和东南部以及北美东部的部分地区，成为一种有害的杂草，模式标本采自北美。常见于路边阴凉处，花由两个较大的蓝色花瓣和一个较小的白色花瓣组成。","desc_en":"Commelina communis the Asiatic dayflower, is an herbaceous annual plant in the dayflower family. It gets its name because the blooms last for only one day. It is native throughout much of East Asia and northern parts of Southeast Asia.","img":"images/264.jpg","thumb":"images/t/264.jpg","file":"C.communis after rain.jpg","ar":1.202,"py":"yazhicao yzc","cr_by":"EHM02667","cr_lic":"CC BY-SA 3.0","cr_licurl":"https://creativecommons.org/licenses/by-sa/3.0","habit":"草本","origin":["亚洲"]},{"id":265,"zh":"吊竹梅","en":"Tradescantia zebrina","sci":"Tradescantia zebrina","order_en":"Commelinales","order_zh":"鸭跖草目","family_en":"Commelinaceae","family_zh":"鸭跖草科","iucn":null,"langs":30,"desc_zh":"吊竹梅（学名：Tradescantia zebrina），又名吊竹草、水龟草，鸭跖草科紫万年青属下多年生常绿蔓生草本植物。原生于墨西哥与中美地带，如今在亚洲、非洲、澳洲、南美洲等地都已普及。台湾于1909年引进，全岛各地普遍栽培，并驯化成野生；喜生于溪边，路旁阴湿地。吊竹梅因适宜吊盆栽植，因而得名。","desc_en":"Tradescantia zebrina, formerly known as Zebrina pendula, is a species of creeping plant in the Tradescantia genus. Common names include silver inch plant and wandering Jew. The latter name is controversial, and some now use the alternative wandering dude.","img":"images/265.jpg","thumb":"images/t/265.jpg","file":"Zebrina pendula 20060521 2 closer.jpg","ar":1.286,"py":"diaozhumei dzm","cr_by":"Ruestz (upload 13:54, 11 January 2008)","cr_lic":"CC BY-SA 3.0","cr_licurl":"http://creativecommons.org/licenses/by-sa/3.0/","habit":null,"origin":null},{"id":266,"zh":"紫背万年青","en":"Tradescantia spathacea","sci":"Tradescantia spathacea","order_en":"Commelinales","order_zh":"鸭跖草目","family_en":"Commelinaceae","family_zh":"鸭跖草科","iucn":null,"langs":28,"desc_zh":"紫背万年青（学名：Tradescantia spathacea），又称青红兰、蚌兰、荷包兰、蚌花、小蚌花，为药食两用植物。多年生草本植物，高20～50厘米。茎多分枝，带肉质，紫红色，下部匍匐状，节上常生须根，上部近于直立。叶互生，披针形。原产于墨西哥。","desc_en":"Tradescantia spathacea, also called the oyster plant, boatlily or 'Moses-in-the-cradle', is an herb in the Commelinaceae family which was first described in 1788. It is native to Central America.","img":"images/266.jpg","thumb":"images/t/266.jpg","file":"Tradescantia spathacea-Yucatan.jpg","ar":1.093,"py":"zibeiwannianqing zbwnq","cr_by":"Jim Conrad","cr_lic":"Public domain","cr_licurl":null,"habit":"草本","origin":["北美洲"]},{"id":267,"zh":"淡色紫露草","en":"Tradescantia pallida","sci":"Tradescantia pallida","order_en":"Commelinales","order_zh":"鸭跖草目","family_en":"Commelinaceae","family_zh":"鸭跖草科","iucn":null,"langs":28,"desc_zh":"淡色紫露草（学名：Tradescantia pallida）是鸭跖草科紫露草属多年生草本植物，其种加词pallida 意为“淡色的”。原产墨西哥。其紫叶品种称为紫竹梅、紫锦草（Tradescantia pallida 'Purpurea'），是一种常见的观赏植物。","desc_en":"Tradescantia pallida is a species of spiderwort native to the Gulf Coast region of eastern Mexico. It is a perennial herbaceous species with a trailing habit. The cultivar T.","img":"images/267.jpg","thumb":"images/t/267.jpg","file":"Tradescantia pallida-IMG 20180707 120135.jpg","ar":1.333,"py":"dansezilucao dszlc","cr_by":"Sun Jiao (Interaccoonale)","cr_lic":"CC BY 4.0","cr_licurl":"https://creativecommons.org/licenses/by/4.0","habit":"草本","origin":["北美洲"]},{"id":268,"zh":"圆叶鸭跖草","en":"Commelina benghalensis","sci":"Commelina benghalensis","order_en":"Commelinales","order_zh":"鸭跖草目","family_en":"Commelinaceae","family_zh":"鸭跖草科","iucn":"LC","langs":25,"desc_zh":"圆叶鸭跖草（学名：Commelina benghalensis），又名饭包草、竹叶菜，为鸭跖草科鸭跖草属下的一个种。分布在亚洲热带和亚热带、台湾岛、非洲热带和亚热带以及中国大陆的海南、福建、广西、江西、山东、陕西、云南、河南、湖南、安徽、湖北、河北、江苏、四川、广东、浙江等地，生长于海拔350米至2,300米的地区，多生长在湿地，目前尚未由人工引种栽培。 其种加词“benghalensis”意为“孟加拉国的”。","desc_en":"Commelina benghalensis, commonly known as the Benghal dayflower, tropical spiderwort, or wandering Jew, kanshira in Bengali, is a perennial herb native to tropical Asia and Africa.","img":"images/268.jpg","thumb":"images/t/268.jpg","file":"ARS - Commelina benghalensis.jpg","ar":1.504,"py":"yuanyeyazhicao yyyzc","cr_by":"Herb Pilcher, USDA ARS","cr_lic":"Public domain","cr_licurl":null,"habit":"草本","origin":["亚洲","非洲"]},{"id":269,"zh":"水葫芦","en":"Eichhornia crassipes","sci":"Eichhornia crassipes","order_en":"Commelinales","order_zh":"鸭跖草目","family_en":"Pontederiaceae","family_zh":"雨久花科","iucn":null,"langs":53,"desc_zh":"凤眼蓝（学名：Pontederia crassipes），或称凤眼莲、军舰莲、水葫芦，是一种原产于南美洲亚马逊河流域属于雨久花科梭鱼草属的一种漂浮性水生植物。凤眼蓝曾一度被很多国家引进，广泛分布与世界各地，亦被列入世界百大外来入侵种之一。","desc_en":"Pontederia crassipes (formerly Eichhornia crassipes), commonly known as common water hyacinth, is an aquatic plant native to South America, naturalized throughout the world, and often invasive outside its native range.","img":"images/269.jpg","thumb":"images/t/269.jpg","file":"Pontederia crassipes in native habitat, Transpantaneira, Poconé, Mato Grosso, Brazil.jpg","ar":1.658,"py":"shuihulu shl","cr_by":"Bernard DUPONT","cr_lic":"CC BY-SA 2.0","cr_licurl":"https://creativecommons.org/licenses/by-sa/2.0","habit":null,"origin":["南美洲"]},{"id":270,"zh":"姜","en":"ginger","sci":"Zingiber officinale","order_en":"Zingiberales","order_zh":"姜目","family_en":"Zingiberaceae","family_zh":"姜科","iucn":"DD","langs":165,"desc_zh":"姜（学名：Zingiber officinale），为姜科姜属的植物，原产于海洋东南亚，最早由南岛民族培植。姜开有黄绿色的花和辣味的根茎。根茎鲜品或干品可以作为调味品。姜经过泡制作为中药药材之一，也可以冲泡为草本茶。姜耕种起源于亚洲并拥有悠久历史，目前在印度、东南亚、西非和加勒比地区生产也见增长。","desc_en":"Ginger (Zingiber officinale) is a flowering plant whose rhizome, ginger root or ginger, is widely used as a spice and a folk medicine. It is an herbaceous perennial that grows annual pseudostems (false stems made of the rolled bases of leaves) about one meter…","img":"images/270.jpg","thumb":"images/t/270.jpg","file":"Koeh-146-no text.jpg","ar":0.768,"py":"jiang j","cr_by":"Franz Eugen Köhler, Köhler's Medizinal-Pflanzen","cr_lic":"Public domain","cr_licurl":null,"habit":"草本","origin":["亚洲"]},{"id":271,"zh":"姜黄","en":"Curcuma longa","sci":"Curcuma longa","order_en":"Zingiberales","order_zh":"姜目","family_en":"Zingiberaceae","family_zh":"姜科","iucn":"DD","langs":127,"desc_zh":"姜黄（学名：Curcuma longa），又称宝鼎香，为姜科姜黄属植物，在一些亚洲国家称作turmeric或kunyit。其根茎所磨成的深黄色粉末为咖哩的主要成份之一，也用在南洋料理，尝起来味苦而辛，带点土味。主成分姜黄素（curcumin）具有一些医疗保健的效果，因此姜黄也出现在中医药材中。","desc_en":"Turmeric (), or Curcuma longa (), is a flowering plant in the ginger family Zingiberaceae. It is a perennial, rhizomatous, herbaceous plant native to the Indian subcontinent and Southeast Asia that requires temperatures between 20 and 30 °C (68 and 86 °F) and…","img":"images/271.jpg","thumb":"images/t/271.jpg","file":"Curcuma longa roots.jpg","ar":2.429,"py":"jianghuang jh","cr_by":"Simon A. Eugster","cr_lic":"CC BY-SA 3.0","cr_licurl":"https://creativecommons.org/licenses/by-sa/3.0","habit":"草本","origin":["亚洲"]},{"id":272,"zh":"小豆蔻","en":"Elettaria cardamomum","sci":"Elettaria cardamomum","order_en":"Zingiberales","order_zh":"姜目","family_en":"Zingiberaceae","family_zh":"姜科","iucn":null,"langs":68,"desc_zh":"小豆蔻（学名：Elettaria cardamomum；英语：true cardamom），又名印度小豆蔻、细豆蔻、绿豆蔻、苏泣迷罗、素泣谜罗香（梵语：सूक्ष्मैला，罗马化：sūkṣmailā），香港坊间香料舖称之为青砂仁，是一种姜科多年生的草本植物。喜欢生长在山坡边阴凉潮湿的地方。小豆蔻是一种烹调香料、种子可以做中药。 多年生草本。根茎粗壮，棕红色。叶两列，叶片狭长披针状，叶鞘具棕黄色柔毛。穗状花序由茎基部抽出。","desc_en":"Elettaria cardamomum, commonly known as green cardamom or true cardamom, is a herbaceous, perennial plant in the ginger family, native to southern India. It is the most common of the species whose seeds are used as a spice called cardamom that has a strong aro…","img":"images/272.jpg","thumb":"images/t/272.jpg","file":"ElettariaCardamomum.jpg","ar":1.333,"py":"xiaodoukou xdk","cr_by":"Chhe ( talk )","cr_lic":"Public domain","cr_licurl":null,"habit":"草本","origin":["亚洲"]},{"id":273,"zh":"白莪术","en":"Curcuma zedoaria","sci":"Curcuma zedoaria","order_en":"Zingiberales","order_zh":"姜目","family_en":"Zingiberaceae","family_zh":"姜科","iucn":"DD","langs":44,"desc_zh":"白莪术（zhú）（学名：Curcuma zedoaria）为姜科姜黄属多年生草本植物，原产南亚，东亚不产。中国栽培的莪术（学名：Curcuma phaeocaulis）过去常误作本种。","desc_en":"Curcuma zedoaria (zedoary , white turmeric, or temu putih) is a perennial herb and member of the genus Curcuma, family Zingiberaceae. The plant is native to South Asia and Southeast Asia but is now naturalized in other places including the US state of Florida.","img":"images/273.jpg","thumb":"images/t/273.jpg","file":"Curcuma zedoaria - Köhler–s Medizinal-Pflanzen-048.jpg","ar":0.731,"py":"baieshu bes","cr_by":"Franz Eugen Köhler, Köhler's Medizinal-Pflanzen","cr_lic":"Public domain","cr_licurl":null,"habit":"草本","origin":["亚洲","北美洲"]},{"id":274,"zh":"大高良姜","en":"Alpinia galanga","sci":"Alpinia galanga","order_en":"Zingiberales","order_zh":"姜目","family_en":"Zingiberaceae","family_zh":"姜科","iucn":null,"langs":44,"desc_zh":"大高良姜（学名：Alpinia galanga），别称高良姜、大良姜、南姜、 山姜、廉姜、良姜、良姜子、红豆蔻、红豆扣、红扣、红蔻、番郁金、诺卡及郭哈等 ，在粤菜烹饪的专业术语中称潮汕姜 ，为姜科山姜属植物。","desc_en":"Alpinia galanga, a plant in the ginger family, bears a rhizome used largely as an herb in Unani medicine and as a spice in Southeast Asian cookery. It is one of four plants known as \"galangal\".","img":"images/274.jpg","thumb":"images/t/274.jpg","file":"Alpinia officinarum - Köhler–s Medizinal-Pflanzen-156.jpg","ar":0.747,"py":"dagaoliangjiang dglj","cr_by":"Franz Eugen Köhler, Köhler's Medizinal-Pflanzen","cr_lic":"Public domain","cr_licurl":null,"habit":"草本","origin":["亚洲"]},{"id":275,"zh":"山柰","en":"Kaempferia galanga","sci":"Kaempferia galanga","order_en":"Zingiberales","order_zh":"姜目","family_en":"Zingiberaceae","family_zh":"姜科","iucn":"DD","langs":39,"desc_zh":"山柰（学名：Kaempferia galanga）亦称三柰、沙姜、番郁金、三藾、山辣、土麝香、埔姜花，是一种姜科山柰属的植物。","desc_en":"Kaempferia galanga, commonly known as kencur, aromatic ginger, sand ginger, cutcherry, is a monocotyledonous plant in the ginger family, and one of four plants called galangal.","img":"images/275.jpg","thumb":"images/t/275.jpg","file":"Galangal.web.jpg","ar":0.623,"py":"shannai sn","cr_by":null,"cr_lic":"Public domain","cr_licurl":null,"habit":null,"origin":["亚洲"]},{"id":276,"zh":"香豆蔻","en":"black cardamom","sci":"Amomum subulatum","order_en":"Zingiberales","order_zh":"姜目","family_en":"Zingiberaceae","family_zh":"姜科","iucn":"DD","langs":39,"desc_zh":"香豆蔻（学名：Amomum subulatum）为姜科豆蔻属下的一个种。","desc_en":"Amomum subulatum, also known as black cardamom, hill cardamom, Bengal cardamom, greater cardamom, Indian cardamom, Nepal cardamom, winged cardamom, big cardamon, or brown cardamom, is a perennial herbaceous plant in the family Zingiberaceae.","img":"images/276.jpg","thumb":"images/t/276.jpg","file":"BlackCardamom.jpg","ar":1.488,"py":"xiangdoukou xdk","cr_by":"Brian Arthur","cr_lic":"CC BY-SA 3.0","cr_licurl":"https://creativecommons.org/licenses/by-sa/3.0","habit":"草本","origin":["亚洲"]},{"id":277,"zh":"马尼拉麻蕉","en":"Musa textilis","sci":"Musa textilis","order_en":"Zingiberales","order_zh":"姜目","family_en":"Musaceae","family_zh":"芭蕉科","iucn":"NT","langs":54,"desc_zh":"马尼拉麻蕉（学名：Musa textilis），又称马尼拉麻，属芭蕉科（Musaceae），原产菲律宾，广泛生长在婆罗洲和苏门答腊岛。至今，菲律宾仍是世界是最大的蕉麻生产国。本植物虽然称为马尼拉蕉麻，但属于芭蕉科植物，与真麻无亲缘关系。 多年生草本，形似芭蕉，茎直立柔软，由粗厚的叶鞘包迭而成柱状；叶很大，钜圆形，螺旋排列；穗状花序，单性花。浆果似香蕉。从根茎可生长出多至25个不含有纤维的肉质枝茎，丛生成环形。","desc_en":"Abacá ( ah-bə-KAH; Filipino: abaka [ɐbɐˈka]), also known as Manila hemp, is a species of banana, Musa textilis, endemic to the Philippines. The plant grows to 13–22 feet (4.0–6.","img":"images/277.jpg","thumb":"images/t/277.jpg","file":"Abaca Tree.jpg","ar":1.501,"py":"manilamajiao mnlmj","cr_by":"MarvinBikolano","cr_lic":"CC BY-SA 4.0","cr_licurl":"https://creativecommons.org/licenses/by-sa/4.0","habit":null,"origin":["亚洲"]},{"id":278,"zh":"小果野蕉","en":"Musa acuminata","sci":"Musa acuminata","order_en":"Zingiberales","order_zh":"姜目","family_en":"Musaceae","family_zh":"芭蕉科","iucn":"LC","langs":36,"desc_zh":"小果野蕉（学名：Musa acuminata）又名尖蕉、香蕉，为芭蕉科芭蕉属的植物。分布在越南、泰国、缅甸、马来西亚、菲律宾、印度以及中国大陆的云南、广西等地，生长于海拔1,000米至1,200米的地区，多生长于沼泽、半沼泽、阴湿的沟谷或坡地上。 本种也是杂交种香蕉（M. x paradisiaca）的亲本之一，香蕉另一亲本则为野蕉（M. balbisiana）。","desc_en":"Musa acuminata is a species of banana native to Southern Asia, its range comprising the Indian subcontinent and Southeast Asia. Many of the modern edible dessert bananas are derived from this species, although some are hybrids with Musa balbisiana.","img":"images/278.jpg","thumb":"images/t/278.jpg","file":"Bananapao.JPG","ar":1.36,"py":"xiaoguoyejiao xgyj","cr_by":"Jorgemach7","cr_lic":"CC BY-SA 3.0","cr_licurl":"https://creativecommons.org/licenses/by-sa/3.0","habit":null,"origin":["亚洲"]},{"id":279,"zh":"美人蕉","en":"Canna indica","sci":"Canna indica","order_en":"Zingiberales","order_zh":"姜目","family_en":"Cannaceae","family_zh":"美人蕉科","iucn":null,"langs":46,"desc_zh":"美人蕉（学名：Canna indica）是美人蕉科美人蕉属的植物。原产于西印度群岛，墨西哥和美国东南部（佛罗里达州，得克萨斯州，路易斯安那州和南卡罗来纳州）。地下根茎富含淀粉，可食。几千年来一直是美洲原住民种植的一种小型粮食作物。它也在撒哈拉以南非洲的大部分地区及东南亚和大洋洲归化。分布于印度以及中国大陆的南部和西南部等地，生长于海拔800米的地区，目前已由人工引种栽培，作为传统旱藕的替代品，制作粉丝。种名indica意为印度的。","desc_en":"Canna indica, commonly known as Indian shot, African arrowroot, edible canna, purple arrowroot, Sierra Leone arrowroot, is a plant species in the family Cannaceae. It is native to the Americas and naturalized elsewhere.","img":"images/279.jpg","thumb":"images/t/279.jpg","file":"00 3890 Indisches Blumenrohr (Canna indica).jpg","ar":0.667,"py":"meirenjiao mrj","cr_by":"W. Bulach","cr_lic":"CC BY-SA 4.0","cr_licurl":"https://creativecommons.org/licenses/by-sa/4.0","habit":null,"origin":null},{"id":280,"zh":"旅人蕉","en":"Ravenala madagascariensis","sci":"Ravenala madagascariensis","order_en":"Zingiberales","order_zh":"姜目","family_en":"Strelitziaceae","family_zh":"鹤望兰科","iucn":"LC","langs":51,"desc_zh":"旅人蕉 （学名：Ravenala madagascariensis ），别称旅人木、散尾葵、扁芭槿、扇芭蕉、水木等，属姜目鹤望兰科，为旅人蕉属下的单属种 植物，原产于马达加斯加。由于叶鞘呈杯状能贮存大量水液，其树液亦可饮用，供旱漠旅人提供紧急的水源，故而得名旅人蕉。 其种加词“madagascariensis”意为“马达加斯加的”。马达加斯加国徽有旅人蕉的叶片图案。","desc_en":"Ravenala madagascariensis, commonly known as the traveller's tree, fan palm, traveller's palm or East-West palm, is a species of monocotyledonous flowering plant found in Madagascar. It is not a true palm but a member of the family Strelitziaceae.","img":"images/280.jpg","thumb":"images/t/280.jpg","file":"Ravenala madagascariensis, Atsinanana, Madagascar 1.jpg","ar":0.667,"py":"lrenjiao lrj","cr_by":"kristofz","cr_lic":"CC BY 4.0","cr_licurl":"https://creativecommons.org/licenses/by/4.0","habit":"乔木","origin":["非洲"]},{"id":281,"zh":"斑叶竹芋","en":"Maranta arundinacea","sci":"Maranta arundinacea","order_en":"Zingiberales","order_zh":"姜目","family_en":"Marantaceae","family_zh":"竹芋科","iucn":null,"langs":43,"desc_zh":"葛郁金（学名：Maranta arundinacea），又称竹芋、竹薯、粉薯、太白薯、太白笋、美人蕉、藕仔薯或金笋，为一多年生植物，常见于热带雨林。葛郁金所制成的淀粉常在餐饮烹饪上用于勾芡等用途，其使用最早可追溯至西元前8200年的南美洲北部。","desc_en":"Maranta arundinacea, also known as arrowroot, maranta, West Indian arrowroot, obedience plant or Bermuda arrowroot is a large, perennial herb found in rainforest habitats of the Americas, but cultivated in tropical regions worldwide.","img":"images/281.jpg","thumb":"images/t/281.jpg","file":"Forraçao2.jpg","ar":1.333,"py":"banyezhuyu byzy","cr_by":null,"cr_lic":"CC BY-SA 3.0","cr_licurl":"http://creativecommons.org/licenses/by-sa/3.0/","habit":"草本","origin":null},{"id":282,"zh":"翅果竹芋","en":"Thaumatococcus daniellii","sci":"Thaumatococcus daniellii","order_en":"Zingiberales","order_zh":"姜目","family_en":"Marantaceae","family_zh":"竹芋科","iucn":null,"langs":22,"desc_zh":null,"desc_en":"Thaumatococcus daniellii, also known as miracle fruit, is a plant species from tropical Africa of the Marantaceae (arrowroot and prayer plant) family. It is a large, rhizomatous, flowering herb native to the rainforests of western Africa in Sierra Leone, south…","img":"images/282.jpg","thumb":"images/t/282.jpg","file":"Moimoi.JPG","ar":1.333,"py":"chiguozhuyu cgzy","cr_by":"Zz411 at English Wikipedia","cr_lic":"CC BY-SA 3.0","cr_licurl":"http://creativecommons.org/licenses/by-sa/3.0/","habit":"草本","origin":["非洲"]},{"id":283,"zh":"金鱼藻","en":"Ceratophyllum demersum","sci":"Ceratophyllum demersum","order_en":"Ceratophyllales","order_zh":"金鱼藻目","family_en":"Ceratophyllaceae","family_zh":"金鱼藻科","iucn":"LC","langs":35,"desc_zh":"金鱼藻（学名：Ceratophyllum demersum），又称作松藻、鱼草、细草、软草，有时根据英文名coontail直译为浣熊尾巴草，为金鱼藻科金鱼藻属底下的一物种。其生活型态可为沉水型，亦可为浮水型。除南极洲外，世界各大陆都有其原生分布。对纽西兰而言，金鱼藻是一种有害的外来水藻。同时，其为一种广受欢迎的水生植物。","desc_en":"Ceratophyllum demersum, commonly known as hornwort (a common name shared with the unrelated Anthocerotophyta), rigid hornwort, coontail, or coon's tail, is a species of flowering plant in the genus Ceratophyllum.","img":"images/283.jpg","thumb":"images/t/283.jpg","file":"Ceratophyllum demersum 2010-8-14 RioMontoro SierraMadrona.jpg","ar":1.333,"py":"jinyuzao jyz","cr_by":"Javier martin","cr_lic":"Public domain","cr_licurl":null,"habit":null,"origin":null},{"id":284,"zh":"家黑种草","en":"Nigella sativa","sci":"Nigella sativa","order_en":"Ranunculales","order_zh":"毛茛目","family_en":"Ranunculaceae","family_zh":"毛茛科","iucn":null,"langs":83,"desc_zh":"家黑种草（学名：Nigella sativa；属名是拉丁语“黑色”niger的指小词，种加词意思是“栽培的”），古称草豉（《本草拾遗》）、少尼子（《回回药方》；阿拉伯语：شونيز，罗马化：shūnīz/shawnīz）、香黑子（《回回药方》），也叫黑葛缕、黑孜然、茴香花、瘤果黑种草，是毛茛科黑种草属一年生草本植物，原产西亚，在欧洲、北非、南亚、中亚亦常见栽培。其种子可炼成黑籽油。","desc_en":"Nigella sativa (common names, black caraway, black cumin, nigella, charnushka, or kalonji) is an annual flowering plant in the family Ranunculaceae, native to western Asia (the Levant, Cyprus, Turkey, Iran and Iraq), and eastern Europe (Bulgaria and Romania).","img":"images/284.jpg","thumb":"images/t/284.jpg","file":"Nigella sativa - Köhler–s Medizinal-Pflanzen-227.jpg","ar":0.825,"py":"jiaheizhongcao jhzc","cr_by":"Franz Eugen Köhler, Köhler's Medizinal-Pflanzen","cr_lic":"Public domain","cr_licurl":null,"habit":"草本","origin":["亚洲","欧洲"]},{"id":285,"zh":"驴蹄草","en":"Caltha palustris","sci":"Caltha palustris","order_en":"Ranunculales","order_zh":"毛茛目","family_en":"Ranunculaceae","family_zh":"毛茛科","iucn":"LC","langs":61,"desc_zh":"驴蹄草（学名：Trollius paluster）是一种属于毛茛科驴蹄草属的多年生草本植物，又名驴蹄菜、沼泽金盏花（Marsh Marigold）、立金花。原产于北半球的温带地区，包括欧洲的冰岛与俄罗斯北极地区，亚洲温带与北极地区及北美洲。","desc_en":"Caltha palustris, known as marsh-marigold and kingcup, is a small to medium sized perennial herbaceous plant of the buttercup family, native to marshes, fens, ditches and wet woodland in temperate regions of the Northern Hemisphere.","img":"images/285.jpg","thumb":"images/t/285.jpg","file":".00 1402 Sumpfdotterblume - (Caltha palustris).jpg","ar":1.506,"py":"lticao ltc","cr_by":"W. Bulach","cr_lic":"CC BY-SA 4.0","cr_licurl":"https://creativecommons.org/licenses/by-sa/4.0","habit":"草本","origin":null},{"id":286,"zh":"高毛茛","en":"Ranunculus acris","sci":"Ranunculus acris","order_en":"Ranunculales","order_zh":"毛茛目","family_en":"Ranunculaceae","family_zh":"毛茛科","iucn":null,"langs":61,"desc_zh":"草甸毛茛（学名：Ranunculus acris），又称为高毛茛、普通毛茛，是毛茛科毛茛属的一种植物，原产于欧洲与欧亚大陆温带地区。","desc_en":"Ranunculus acris is a species of flowering plant in the family Ranunculaceae, and is one of the more common buttercups across Europe and temperate Eurasia. Common names include meadow buttercup, tall buttercup, common buttercup and giant buttercup.","img":"images/286.jpg","thumb":"images/t/286.jpg","file":"Ranunculus acris niittyleinikki.jpg","ar":0.551,"py":"gaomaogen gmg","cr_by":"Alinja","cr_lic":"CC BY-SA 4.0","cr_licurl":"https://creativecommons.org/licenses/by-sa/4.0","habit":null,"origin":["亚洲","欧洲"]},{"id":287,"zh":"匍枝毛茛","en":"Ranunculus repens","sci":"Ranunculus repens","order_en":"Ranunculales","order_zh":"毛茛目","family_en":"Ranunculaceae","family_zh":"毛茛科","iucn":null,"langs":57,"desc_zh":"匍枝毛茛（学名：Ranunculus repens）为毛茛科毛茛属下的一个种。","desc_en":"Ranunculus repens, the creeping buttercup, is a flowering plant in the buttercup family Ranunculaceae, native to Europe, Asia and northwestern Africa. It is also called creeping crowfoot and (along with restharrow) sitfast.","img":"images/287.jpg","thumb":"images/t/287.jpg","file":"Creeping butercup close 800.jpg","ar":1.187,"py":"puzhimaogen pzmg","cr_by":null,"cr_lic":"CC BY-SA 3.0","cr_licurl":"http://creativecommons.org/licenses/by-sa/3.0/","habit":null,"origin":["亚洲","欧洲","非洲"]},{"id":288,"zh":"欧洲乌头","en":"Aconitum napellus","sci":"Aconitum napellus","order_en":"Ranunculales","order_zh":"毛茛目","family_en":"Ranunculaceae","family_zh":"毛茛科","iucn":"LC","langs":56,"desc_zh":"欧洲乌头（学名：Aconitum napellus）为毛莨科乌头属的多年生植物。分布于欧洲，生长在遮阴潮湿的土壤。为耐寒多年生草本，叶互生叶片深裂，为多叶茎，总状花序高长且密集，由淡紫色的盔形小花组成，于初夏开放。全株有毒，其块根的根节是植物中最强的神经毒素之一。","desc_en":"Aconitum napellus, monkshood, aconite, Venus' chariot or wolfsbane, is a species of highly toxic flowering plants in the genus Aconitum of the family Ranunculaceae, native and endemic to western and central Europe.","img":"images/288.jpg","thumb":"images/t/288.jpg","file":"Aconitum napellus 230705.jpg","ar":0.554,"py":"ouzhouwutou ozwt","cr_by":"Bernd Haynold","cr_lic":"CC BY-SA 2.5","cr_licurl":"https://creativecommons.org/licenses/by-sa/2.5","habit":"草本","origin":["亚洲","欧洲","北美洲"]},{"id":289,"zh":"栎林银莲花","en":"Anemone nemorosa","sci":"Anemone nemorosa","order_en":"Ranunculales","order_zh":"毛茛目","family_en":"Ranunculaceae","family_zh":"毛茛科","iucn":null,"langs":54,"desc_zh":"丛林银莲花（学名：Anemonoides nemorosa）是毛茛科西南银莲花属的一种植物，原产于欧洲。","desc_en":"Anemonoides nemorosa (syn. Anemone nemorosa), the wood anemone, also historically known as windflower because of William Turner's interpretation of its Latin name anemone in his 1551 New Herball, is an early spring flowering plant in the buttercup family Ranun…","img":"images/289.jpg","thumb":"images/t/289.jpg","file":".00 2814 Blüte des Buschwindröschen (Anemone nemorosa).jpg","ar":0.75,"py":"lilinyinlianhua llylh","cr_by":"W. Bulach","cr_lic":"CC BY-SA 4.0","cr_licurl":"https://creativecommons.org/licenses/by-sa/4.0","habit":"草本","origin":["欧洲"]},{"id":290,"zh":"葡萄叶铁线莲","en":"Clematis vitalba","sci":"Clematis vitalba","order_en":"Ranunculales","order_zh":"毛茛目","family_en":"Ranunculaceae","family_zh":"毛茛科","iucn":null,"langs":53,"desc_zh":"白藤铁线莲（学名：Clematis vitalba），常误译为葡萄叶铁线莲，是一种富有韧性的多年生的木质藤本植物，拥有木质茎，能攀爬至 20 至 30 公尺的高处。它在原生地通常见于白垩和石灰岩区，但经引进后，能在多种环境中茁壮，包括林地、森林边缘、开阔地区，甚至能在柳树丛生的河岸、废弃地和沿海及低地一带扎根。白藤铁线莲的快速蔓延会阻塞并破坏原始森林，导致原生植物消失。这种生态危害多发生在大量外来植物入侵或牲畜破坏栖地后。","desc_en":"Clematis vitalba (also known as old man's beard and traveller's joy) is a shrub in the genus Clematis of the family Ranunculaceae. It is native to Europe and western Asia.","img":"images/290.jpg","thumb":"images/t/290.jpg","file":"Clematis-vitalba-Waldrebe(Samenstand).jpg","ar":1.233,"py":"putaoyetiexianlian ptytxl","cr_by":"Michael Gasperl ( Migas )","cr_lic":"CC BY-SA 3.0","cr_licurl":"http://creativecommons.org/licenses/by-sa/3.0/","habit":"灌木","origin":["亚洲","欧洲"]},{"id":291,"zh":"日本獐耳细辛","en":"Hepatica nobilis","sci":"Hepatica nobilis","order_en":"Ranunculales","order_zh":"毛茛目","family_en":"Ranunculaceae","family_zh":"毛茛科","iucn":null,"langs":52,"desc_zh":"三角草（学名：Hepatica nobilis），为毛茛科獐耳细辛属下的一个植物。","desc_en":"Anemone hepatica (syn. Hepatica nobilis), the common hepatica, liverwort, liverleaf, kidneywort, or pennywort, is a species of flowering plant in the buttercup family Ranunculaceae, native to woodland in temperate regions of the Northern Hemisphere.","img":"images/291.jpg","thumb":"images/t/291.jpg","file":"Hepatica nobilis plant.JPG","ar":1.333,"py":"ribenzhangerxixin rbzexx","cr_by":null,"cr_lic":"CC BY-SA 3.0","cr_licurl":"http://creativecommons.org/licenses/by-sa/3.0/","habit":"草本","origin":null},{"id":292,"zh":"榕叶毛茛","en":"Ficaria verna","sci":"Ficaria verna","order_en":"Ranunculales","order_zh":"毛茛目","family_en":"Ranunculaceae","family_zh":"毛茛科","iucn":null,"langs":50,"desc_zh":"榕叶毛茛（学名：Ficaria verna，原名Ranunculus ficaria），又称为小白屈菜，是毛茛科榕毛茛属的一种多年生植物，原产于欧洲与西亚。叶片深绿色有光泽，呈心形，花朵则为亮黄色。在引入北美后，榕叶毛茛被认为是一种会威胁当地生物多样性的入侵物种。 英国浪漫主义诗人威廉·华兹华斯尤为喜爱榕叶毛茛，他曾为其写过《致小白屈菜》（To the Small Celandine）等三首诗（以下为《致小白屈菜》摘录）：","desc_en":"Ficaria verna (formerly Ranunculus ficaria L.), commonly known as lesser celandine or pilewort, is a low-growing, hairless perennial flowering plant in the buttercup family Ranunculaceae.","img":"images/292.jpg","thumb":"images/t/292.jpg","file":"20150324Ficaria verna4.jpg","ar":1.333,"py":"rongyemaogen rymg","cr_by":"AnRo0002","cr_lic":"CC0","cr_licurl":"http://creativecommons.org/publicdomain/zero/1.0/deed.en","habit":"草本","origin":["亚洲","欧洲","北美洲"]},{"id":293,"zh":"春侧金盏花","en":"Adonis vernalis","sci":"Adonis vernalis","order_en":"Ranunculales","order_zh":"毛茛目","family_en":"Ranunculaceae","family_zh":"毛茛科","iucn":null,"langs":47,"desc_zh":"春侧金盏花（学名：Adonis vernalis），又名春福寿草，是一种多年生的开花植物，生长在欧亚大陆的干旱草原及沙地。它们主要在潘诺尼亚平原及西西伯利亚平原，由西班牙至中欧及南欧，北至瑞典都有个别的群落。它们与其他欧洲的侧金盏花属不同，是在春天开花的，花朵直径长8厘米及有多达20枝鲜黄色的花瓣。 春侧金盏花存在极少量的毒性原理。但它吸收不良，因此中毒不太可能。含有刺激心脏的化合物，包括：阿多尼丁及乌头酸。它们也作为观赏植物。","desc_en":"Adonis vernalis, known variously as pheasant's eye, spring pheasant's eye, yellow pheasant's eye and false hellebore, is a perennial flowering plant in the buttercup family Ranunculaceae. It is found in dry meadows and steppes in Eurasia.","img":"images/293.jpg","thumb":"images/t/293.jpg","file":"Adonis vernalis gonsenheim.jpg","ar":1.275,"py":"chuncejinzhanhua ccjzh","cr_by":"Martin Bahmann","cr_lic":"CC BY-SA 3.0","cr_licurl":"http://creativecommons.org/licenses/by-sa/3.0/","habit":"草本","origin":["亚洲"]},{"id":294,"zh":"欧洲金莲花","en":"Trollius europaeus","sci":"Trollius europaeus","order_en":"Ranunculales","order_zh":"毛茛目","family_en":"Ranunculaceae","family_zh":"毛茛科","iucn":null,"langs":47,"desc_zh":null,"desc_en":"Trollius europaeus, the globeflower, is a perennial flowering plant of the family Ranunculaceae. The plant is native to Europe and Western Asia and is a protected species in Russia and Bulgaria.","img":"images/294.jpg","thumb":"images/t/294.jpg","file":"Trollius europaeus flower - Keila.jpg","ar":1.25,"py":"ouzhoujinlianhua ozjlh","cr_by":"Ivar Leidus","cr_lic":"CC BY-SA 4.0","cr_licurl":"https://creativecommons.org/licenses/by-sa/4.0","habit":"草本","origin":["亚洲","欧洲"]},{"id":295,"zh":"石龙芮","en":"Ranunculus sceleratus","sci":"Ranunculus sceleratus","order_en":"Ranunculales","order_zh":"毛茛目","family_en":"Ranunculaceae","family_zh":"毛茛科","iucn":"LC","langs":45,"desc_zh":"石龙芮（学名：Ranunculus sceleratus）为毛茛科毛茛属下的一个种。石龙芮别名「黄花菜」，与萱草科萱草属下的黄花菜同名，二者极易混淆。不同的是，后者因其美味常被人食用，而前者则有剧毒，倘若不慎误食，有可能出现口腔灼热肿胀、咀嚼困难、呼吸困难等症状，严重时会危及生命。","desc_en":"Ranunculus sceleratus known by the common names celery-leaved buttercup, celery-leaf buttercup, and cursed buttercup is a species of flowering plant in the buttercup family Ranunculaceae.","img":"images/295.jpg","thumb":"images/t/295.jpg","file":"Ranunculus sceleratus - mürktulikas Keilas.jpg","ar":1.333,"py":"shilongrui slr","cr_by":"Ivar Leidus","cr_lic":"CC BY-SA 3.0","cr_licurl":"https://creativecommons.org/licenses/by-sa/3.0","habit":null,"origin":["亚洲","北美洲"]},{"id":296,"zh":"耧斗菜","en":"columbine","sci":"Aquilegia vulgaris","order_en":"Ranunculales","order_zh":"毛茛目","family_en":"Ranunculaceae","family_zh":"毛茛科","iucn":null,"langs":45,"desc_zh":null,"desc_en":"Aquilegia vulgaris is a species of perennial flowering plant of the genus Aquilegia (columbine) in the family Ranunculaceae. Commonly called the common columbine, European crowfoot, and granny's bonnet, it presently possesses the most expansive range and great…","img":"images/296.jpg","thumb":"images/t/296.jpg","file":"Aquilegia vulgaris - Harilik kurekell.jpg","ar":0.667,"py":"loudoucai ldc","cr_by":"Ivar Leidus","cr_lic":"CC BY-SA 3.0 ee","cr_licurl":"https://creativecommons.org/licenses/by-sa/3.0/ee/deed.en","habit":"草本","origin":["欧洲"]},{"id":297,"zh":"黑根铁筷子","en":"Helleborus niger","sci":"Helleborus niger","order_en":"Ranunculales","order_zh":"毛茛目","family_en":"Ranunculaceae","family_zh":"毛茛科","iucn":null,"langs":43,"desc_zh":"黑根铁筷子（学名：Helleborus niger）为毛茛科铁筷子属下的一个物种，因冬季开花而俗称圣诞玫瑰。种加词意思是“黑色的”，指的是它的根部颜色。欧洲古代称之为黑嚏根草，与白嚏根草（藜芦属植物）相对。","desc_en":"Helleborus niger, commonly called Christmas rose or black hellebore, is an evergreen perennial flowering plant in the buttercup family, Ranunculaceae. It is one of about 20 species from the genus Helleborus.","img":"images/297.jpg","thumb":"images/t/297.jpg","file":"Bloem van een kerstroos (Helleborus niger) 16-12-2021. (d.j.b) 02.jpg","ar":1,"py":"heigentiekuaizi hgtkz","cr_by":"Dominicus Johannes Bergsma","cr_lic":"CC BY-SA 4.0","cr_licurl":"https://creativecommons.org/licenses/by-sa/4.0","habit":"草本","origin":null},{"id":298,"zh":"绿豆升麻","en":"Actaea spicata","sci":"Actaea spicata","order_en":"Ranunculales","order_zh":"毛茛目","family_en":"Ranunculaceae","family_zh":"毛茛科","iucn":null,"langs":40,"desc_zh":null,"desc_en":"Actaea spicata, the baneberry or herb Christopher, is a species of flowering plant in the genus Actaea, native from Europe to western Siberia and northern Iran.","img":"images/298.jpg","thumb":"images/t/298.jpg","file":"დათვყურძენა Actaea spicata Baneberry.JPG","ar":1.506,"py":"ldoushengma ldsm","cr_by":"Lazaregagnidze","cr_lic":"CC BY-SA 3.0","cr_licurl":"https://creativecommons.org/licenses/by-sa/3.0","habit":"草本","origin":["亚洲","欧洲"]},{"id":299,"zh":"罂粟","en":"Papaver somniferum","sci":"Papaver somniferum","order_en":"Ranunculales","order_zh":"毛茛目","family_en":"Papaveraceae","family_zh":"罂粟科","iucn":null,"langs":95,"desc_zh":"罂粟（学名：Papaver somniferum），也叫罂子粟、御米、米囊、莺粟、鸦片罂粟、大烟，是罂粟科罂粟属一年生草本植物，是制取鸦片的主要原料，同时其提取物也是多种镇痛剂的来源，例如吗啡、蒂巴因、可待因、罂粟碱、那可汀。学名“somniferum”的意思是“催眠”，反映出它有麻醉性。罂粟的种子罂粟籽是重要的食物，其中含有对健康有益的油脂，可用于面包、饼干中烘焙，或制成酱料，使用于沙律中，也可制成罂粟籽油。","desc_en":"Papaver somniferum, commonly known as the opium poppy or breadseed poppy, is a species of flowering plant in the family Papaveraceae. It is the species of plant from which both opium and poppy seeds are derived and is also a valuable ornamental plant grown in…","img":"images/299.jpg","thumb":"images/t/299.jpg","file":"Papaver somniferum flowers.jpg","ar":1.172,"py":"yingsu ys","cr_by":"tanja niggendijker from apeldoorn, the netherlands","cr_lic":"CC BY 2.0","cr_licurl":"https://creativecommons.org/licenses/by/2.0","habit":null,"origin":["欧洲"]},{"id":300,"zh":"虞美人","en":"Papaver rhoeas","sci":"Papaver rhoeas","order_en":"Ranunculales","order_zh":"毛茛目","family_en":"Papaveraceae","family_zh":"罂粟科","iucn":null,"langs":89,"desc_zh":"虞美人（学名：Papaver rhoeas），又名丽春花、赛牡丹、满园春、仙女蒿、御仙花、雏芥子、雏罂粟、小种罂粟花、蝴蝶满园春，罂粟科罂粟属草本植物，花期夏季，花色有红、白、紫、蓝等颜色，浓艳华美。原产于亚欧温带大陆，在古代中国即有大量栽培，现已引种至新西兰、澳大利亚和北美。","desc_en":"Papaver rhoeas, with common names including common poppy, corn poppy, corn rose, field poppy, Flanders poppy, red poppy, and Odai, is an annual herbaceous species of flowering plant in the poppy family Papaveraceae.","img":"images/300.jpg","thumb":"images/t/300.jpg","file":"Papaver rhoeas LC0050.jpg","ar":0.659,"py":"yumeiren ymr","cr_by":"Jörg Hempel","cr_lic":"CC BY-SA 2.5","cr_licurl":"https://creativecommons.org/licenses/by-sa/2.5","habit":"草本","origin":["亚洲","非洲"]},{"id":301,"zh":"白屈菜","en":"Chelidonium majus","sci":"Chelidonium majus","order_en":"Ranunculales","order_zh":"毛茛目","family_en":"Papaveraceae","family_zh":"罂粟科","iucn":null,"langs":62,"desc_zh":"白屈菜（学名：Chelidonium majus）为罂粟科白屈菜属下的一个种。在中国大部分省区均有分布，沂源、博山山区有分布，以鲁山较为集中，生于山谷湿润地带。生于海拔500—2200米的山坡、山谷林缘草地或路旁、石缝。朝鲜半岛、日本、俄罗斯及欧洲也有分布。","desc_en":"Chelidonium majus, the greater celandine, is a perennial herbaceous flowering plant in the poppy family Papaveraceae. One of two species in the genus Chelidonium, it is native to Europe and western Asia and introduced widely in North America.","img":"images/301.jpg","thumb":"images/t/301.jpg","file":"Chelidonium majus bgiu.jpg","ar":1.333,"py":"baiqucai bqc","cr_by":null,"cr_lic":"CC BY-SA 3.0","cr_licurl":"http://creativecommons.org/licenses/by-sa/3.0/","habit":"草本","origin":["亚洲","欧洲","北美洲"]},{"id":302,"zh":"球果紫菫","en":"Fumaria officinalis","sci":"Fumaria officinalis","order_en":"Ranunculales","order_zh":"毛茛目","family_en":"Papaveraceae","family_zh":"罂粟科","iucn":null,"langs":52,"desc_zh":"球果紫菫（学名：Fumaria officinalis）为紫菫科烟堇属 下的一个种。","desc_en":"Fumaria officinalis, the common fumitory, drug fumitory or earth smoke, is a herbaceous annual flowering plant in the poppy family Papaveraceae. It is the most common species of the genus Fumaria in Western and Central Europe.","img":"images/302.jpg","thumb":"images/t/302.jpg","file":"(MHNT) Fumaria officinalis - Habit.jpg","ar":0.731,"py":"qiuguozijin qgzj","cr_by":"Didier Descouens","cr_lic":"CC BY-SA 4.0","cr_licurl":"https://creativecommons.org/licenses/by-sa/4.0","habit":"草本","origin":["欧洲"]},{"id":303,"zh":"蓟罂粟","en":"Argemone mexicana","sci":"Argemone mexicana","order_en":"Ranunculales","order_zh":"毛茛目","family_en":"Papaveraceae","family_zh":"罂粟科","iucn":null,"langs":47,"desc_zh":"蓟罂粟（学名：Argemone mexicana）为罂粟科蓟罂粟属下的一个种。其种加词“mexicana”意为“墨西哥的”。","desc_en":"Argemone mexicana, also known by the common names Mexican poppy, Mexican prickly poppy, flowering thistle, cardo, and cardosanto, is a species of poppy found in Mexico and now widely naturalized in many parts of the world.","img":"images/303.jpg","thumb":"images/t/303.jpg","file":"Argemone mexicana flower 2.jpg","ar":1.499,"py":"jiyingsu jys","cr_by":"B.navez","cr_lic":"CC BY-SA 3.0","cr_licurl":"https://creativecommons.org/licenses/by-sa/3.0","habit":null,"origin":["北美洲"]},{"id":304,"zh":"花菱草","en":"Eschscholzia californica","sci":"Eschscholzia californica","order_en":"Ranunculales","order_zh":"毛茛目","family_en":"Papaveraceae","family_zh":"罂粟科","iucn":null,"langs":38,"desc_zh":"花菱草（学名：Eschscholzia californica，通俗名：加州罂粟、金英花），是罂粟科花菱草属的一种草本植物。其种加词“californica”意为“加利福尼亚的”。原产于美国西部及墨西哥，分布在美国的加州，向外延伸至俄勒冈州、华盛顿州、内华达州、亚利桑那州及新墨西哥州等地，在墨西哥则分布在索诺拉州及下加利福尼亚州西北部。生长在海拔零至二千公尺的草地及开阔地区。 花菱草是美国加州的州花，加州指定每年的四月六日为花菱草日。","desc_en":"Eschscholzia californica, the California poppy, golden poppy, Mexican poppy, California sunlight or cup of gold, is a species of flowering plant in the family Papaveraceae, native to the United States and Mexico.","img":"images/304.jpg","thumb":"images/t/304.jpg","file":"California poppy.jpg","ar":1.333,"py":"hualingcao hlc","cr_by":"Artslave","cr_lic":"CC BY 2.0","cr_licurl":"https://creativecommons.org/licenses/by/2.0","habit":null,"origin":["北美洲"]},{"id":305,"zh":"荷包牡丹","en":"Lamprocapnos spectabilis","sci":"Lamprocapnos spectabilis","order_en":"Ranunculales","order_zh":"毛茛目","family_en":"Papaveraceae","family_zh":"罂粟科","iucn":null,"langs":38,"desc_zh":"荷包牡丹（学名：Lamprocapnos spectabilis），又名兔儿牡丹、鱼儿牡丹、铃儿草、铃心草、璎珞牡丹、荷包花、蒲包花、土当归、活血草、华鬘草（日本），是罂粟科荷包牡丹属的多年生草本植物，原产于中国北部，花多为桃红色与白色的复色花。广泛分布在亚洲东部，自西伯利亚南部到日本的地区。19世纪时荷包牡丹才被引进欧洲，而在北美一般只能靠人工栽培。 其种加词“spectabilis”意为“显著的”，“引人注目的”。","desc_en":"Lamprocapnos spectabilis, commonly known as bleeding heart or Asian bleeding heart, is a species of flowering plant belonging to the fumitory subfamily (Fumarioideae) of the Papaveraceae (poppy family).","img":"images/305.jpg","thumb":"images/t/305.jpg","file":"Lamprocapnos spectabilis (1).jpg","ar":1.501,"py":"hebaomudan hbmd","cr_by":"Roozitaa","cr_lic":"CC BY-SA 3.0","cr_licurl":"https://creativecommons.org/licenses/by-sa/3.0","habit":null,"origin":["亚洲","欧洲"]},{"id":306,"zh":"刺小檗","en":"Berberis vulgaris","sci":"Berberis vulgaris","order_en":"Ranunculales","order_zh":"毛茛目","family_en":"Berberidaceae","family_zh":"小檗科","iucn":null,"langs":64,"desc_zh":"刺檗（学名：Berberis vulgaris）是小檗科小檗属的植物。原产于欧洲中部和南部、北非和西亚等地区，落叶灌木，高达4米。叶长圆状匙形或倒卵形，长2-5厘米，宽1-2厘米。 果实可以食用，富含维生素C，但味道很酸，而且因刺多不易收获，所以在多数地区都未作为食物供人食用。通常是做成食品添加剂、果酱或果干。在伊朗有较大归模的种植，当地也常使用刺檗果干入菜，波斯语将这种果干称作Zereshk (زرشک)。伊朗也是刺檗果干的最大产地。","desc_en":"Berberis vulgaris, also known as common barberry, European barberry or simply barberry, is a shrub in the genus Berberis native to the Old World. It produces edible but sharply acidic berries, which people in many countries eat as a tart and refreshing fruit.","img":"images/306.jpg","thumb":"images/t/306.jpg","file":"Berberis vulgaris berries. - Flickr - gailhampshire.jpg","ar":1.778,"py":"cixiaobo cxb","cr_by":"gailhampshire from Cradley, Malvern, U.K","cr_lic":"CC BY 2.0","cr_licurl":"https://creativecommons.org/licenses/by/2.0","habit":"灌木","origin":null},{"id":307,"zh":"俄勒冈十大功劳","en":"Mahonia aquifolium","sci":"Mahonia aquifolium","order_en":"Ranunculales","order_zh":"毛茛目","family_en":"Berberidaceae","family_zh":"小檗科","iucn":null,"langs":36,"desc_zh":"北美十大功劳（学名：Mahonia aquifolium）是一种常绿小灌木，为十大功劳属的模式种。","desc_en":"Berberis aquifolium, the Oregon grape, holly-leaved barberry, or Mahonia, is a North American species of flowering plant in the family Berberidaceae. It is an evergreen shrub growing up to 3 metres (10 ft) tall and 1.5 m (5 ft) wide.","img":"images/307.jpg","thumb":"images/t/307.jpg","file":"Mahonia aquifolium.jpg","ar":1.473,"py":"elegangshidagonglao elgsdgl","cr_by":"The original uploader was Meggar at English Wikipedia .","cr_lic":"CC BY-SA 3.0","cr_licurl":"http://creativecommons.org/licenses/by-sa/3.0/","habit":"灌木","origin":["北美洲"]},{"id":308,"zh":"日本小檗","en":"Berberis thunbergii","sci":"Berberis thunbergii","order_en":"Ranunculales","order_zh":"毛茛目","family_en":"Berberidaceae","family_zh":"小檗科","iucn":null,"langs":32,"desc_zh":"日本小檗（学名：Berberis thunbergii），为小檗科小檗属的植物。分布于日本以及中国大陆的大部分省区等地，目前广泛采用为园林植物，是小檗属中载培最广泛的种之一。 花期4-6月，果期7-10月。","desc_en":"Berberis thunbergii, the Japanese barberry, Thunberg's barberry, or red barberry, is a species of flowering plant in the barberry family Berberidaceae, native to Japan and eastern Asia, though widely naturalized in China and North America, where it has become…","img":"images/308.jpg","thumb":"images/t/308.jpg","file":"Berberis thunbergii (tree).jpg","ar":1.388,"py":"ribenxiaobo rbxb","cr_by":"Alpsdake","cr_lic":"CC BY-SA 4.0","cr_licurl":"https://creativecommons.org/licenses/by-sa/4.0","habit":"灌木","origin":["亚洲","北美洲"]},{"id":309,"zh":"麦哲伦小檗","en":"Berberis microphylla","sci":"Berberis microphylla","order_en":"Ranunculales","order_zh":"毛茛目","family_en":"Berberidaceae","family_zh":"小檗科","iucn":null,"langs":27,"desc_zh":null,"desc_en":"Berberis microphylla, common name box-leaved barberry and Magellan barberry, in Spanish calafate and michay and other names, is an evergreen shrub, with simple, shiny box-like leaves.","img":"images/309.jpg","thumb":"images/t/309.jpg","file":"Berberis microphylla - Flickr - Dick Culbert.jpg","ar":1.494,"py":"maizhelunxiaobo mzlxb","cr_by":"Dick Culbert from Gibsons, B.C., Canada","cr_lic":"CC BY 2.0","cr_licurl":"https://creativecommons.org/licenses/by/2.0","habit":"灌木","origin":["亚洲","南美洲"]},{"id":310,"zh":"达尔文小蘗","en":"Berberis darwinii","sci":"Berberis darwinii","order_en":"Ranunculales","order_zh":"毛茛目","family_en":"Berberidaceae","family_zh":"小檗科","iucn":null,"langs":26,"desc_zh":null,"desc_en":"Berberis darwinii, Darwin's barberry, is a species of flowering plant in the family Berberidaceae. It is native to southern Chile and Argentina and naturalized elsewhere. Regional vernacular names include michay, calafate, and quelung. Growing to 3–4 m (9.","img":"images/310.jpg","thumb":"images/t/310.jpg","file":"Berberis darwinii - Flickr - Dick Culbert.jpg","ar":1.202,"py":"daerwenxiaobo dewxb","cr_by":"Dick Culbert from Gibsons, B.C., Canada","cr_lic":"CC BY 2.0","cr_licurl":"https://creativecommons.org/licenses/by/2.0","habit":"灌木","origin":["南美洲"]},{"id":311,"zh":"Tinospora cordifolia","en":"Tinospora cordifolia","sci":"Tinospora cordifolia","order_en":"Ranunculales","order_zh":"毛茛目","family_en":"Menispermaceae","family_zh":"防己科","iucn":null,"langs":34,"desc_zh":null,"desc_en":"Tinospora cordifolia, guruchi, guduchi, amrita, or the heart-leaved moonseed, is a herbaceous vine of the family Menispermaceae native to South and Southeast Asia. It has been used in Ayurveda in an attempt to treat various disorders.","img":"images/311.jpg","thumb":"images/t/311.jpg","file":"Tinospora cordifolia fruits.jpg","ar":0.749,"py":"","cr_by":"Sanu N","cr_lic":"CC BY-SA 4.0","cr_licurl":"https://creativecommons.org/licenses/by-sa/4.0","habit":"藤本","origin":["亚洲"]},{"id":312,"zh":"印防己实","en":"Anamirta cocculus","sci":"Anamirta cocculus","order_en":"Ranunculales","order_zh":"毛茛目","family_en":"Menispermaceae","family_zh":"防己科","iucn":null,"langs":22,"desc_zh":null,"desc_en":"Anamirta cocculus (Marathi: काकमारी) is a Southeast Asian and Indian climbing plant. It is the source of picrotoxin, a poisonous compound with stimulant properties. The plant is large-stemmed (up to 10 cm in diameter); the bark is \"corky gray\" with white wood.","img":"images/312.jpg","thumb":"images/t/312.jpg","file":"Anamirta cocculus - Köhler–s Medizinal-Pflanzen-157.jpg","ar":0.769,"py":"yinfangjishi yfjs","cr_by":"Franz Eugen Köhler, Köhler's Medizinal-Pflanzen","cr_lic":"Public domain","cr_licurl":null,"habit":"藤本","origin":["亚洲"]},{"id":313,"zh":"银桦","en":"Grevillea robusta","sci":"Grevillea robusta","order_en":"Proteales","order_zh":"山龙眼目","family_en":"Proteaceae","family_zh":"山龙眼科","iucn":"LC","langs":38,"desc_zh":"银桦（学名：Grevillea robusta），为山龙眼科银桦属下的一个植物种。原产地为澳洲，现于台湾是常见的树种。","desc_en":"Grevillea robusta, commonly known as the southern silky oak, silk oak or silky oak, silver oak or Australian silver oak, is a species of flowering plant in the family Proteaceae.","img":"images/313.jpg","thumb":"images/t/313.jpg","file":"Grevillearobusta40181608300 6dbb4fe9b0 o.jpg","ar":1.333,"py":"yinhua yh","cr_by":"MargaretRDonald","cr_lic":"CC BY-SA 4.0","cr_licurl":"https://creativecommons.org/licenses/by-sa/4.0","habit":"乔木","origin":["大洋洲"]},{"id":314,"zh":"蓟花山龙眼","en":"Protea cynaroides","sci":"Protea cynaroides","order_en":"Proteales","order_zh":"山龙眼目","family_en":"Proteaceae","family_zh":"山龙眼科","iucn":"LC","langs":29,"desc_zh":"国王海神花（学名：Protea cynaroides），又称帝王花（king protea），是海神花属的一种植物，广泛分布于南非凡波斯一带，并为该国国花。本种花的花蜜可吸引橘胸太阳鸟、南方双领花蜜鸟、孔雀石色花蜜鸟与卡佛食蜜鸟等鸟类取食，这些鸟类啄食花蜜时会沾黏花粉于脸部与喙上，进而协助花朵传粉。此外本种花的花蜜亦可吸引多种昆虫，但牠们协助传粉的重要性仍不清楚。","desc_en":"Protea cynaroides, also called the king protea (from Afrikaans: koningsprotea, Xhosa: isiQwane sobukumkani), is a flowering plant. It is a distinctive member of Protea, having the largest flower head in the genus.","img":"images/314.jpg","thumb":"images/t/314.jpg","file":"Protéa royale à Stellenbosch (Afrique du Sud).jpg","ar":1.076,"py":"jihuashanlongyan jhsly","cr_by":"© Pierre André","cr_lic":"CC BY-SA 4.0","cr_licurl":"https://creativecommons.org/licenses/by-sa/4.0","habit":"灌木","origin":["非洲"]},{"id":315,"zh":"Banksia serrata","en":"Banksia serrata","sci":"Banksia serrata","order_en":"Proteales","order_zh":"山龙眼目","family_en":"Proteaceae","family_zh":"山龙眼科","iucn":"LC","langs":22,"desc_zh":null,"desc_en":"Banksia serrata, commonly known as the saw banksia, the old man banksia, the saw-tooth banksia or the red honeysuckle and as wiriyagan by the Cadigal people, is a species of woody shrub or tree of the genus Banksia, in the family Proteaceae.","img":"images/315.jpg","thumb":"images/t/315.jpg","file":"Banksia serrata Henry Hd email.jpg","ar":0.667,"py":"","cr_by":"Cas Liber","cr_lic":"Public domain","cr_licurl":null,"habit":"乔木","origin":["大洋洲"]},{"id":316,"zh":"智利榛","en":"Gevuina avellana","sci":"Gevuina avellana","order_en":"Proteales","order_zh":"山龙眼目","family_en":"Proteaceae","family_zh":"山龙眼科","iucn":"LC","langs":20,"desc_zh":null,"desc_en":"Gevuina avellana, commonly known as the Chilean hazelnut (avellano chileno in Spanish) or Gevuina hazelnut, is an evergreen tree growing up to 20 meters (65 feet) tall. It is the only species currently classified in the genus Gevuina.","img":"images/316.jpg","thumb":"images/t/316.jpg","file":"Gevuina avellana 2.jpg","ar":1.375,"py":"zhilizhen zlz","cr_by":"Franz Xaver","cr_lic":"CC BY-SA 3.0","cr_licurl":"http://creativecommons.org/licenses/by-sa/3.0/","habit":"乔木","origin":["南美洲"]},{"id":317,"zh":"澳洲坚果","en":"Macadamia integrifolia","sci":"Macadamia integrifolia","order_en":"Proteales","order_zh":"山龙眼目","family_en":"Proteaceae","family_zh":"山龙眼科","iucn":"VU","langs":20,"desc_zh":"澳洲坚果（学名：Macadamia integrifolia）为山龙眼科澳洲坚果属下的一个种。","desc_en":"Macadamia integrifolia is a small to medium-sized tree native to Australian rainforests. Common names include macadamia, smooth-shelled macadamia, bush nut, Queensland nut, Bauple nut and nut oak.","img":"images/317.jpg","thumb":"images/t/317.jpg","file":"Starr 070112-3410 Macadamia integrifolia.jpg","ar":1.333,"py":"aozhoujianguo azjg","cr_by":"Forest & Kim Starr","cr_lic":"CC BY 3.0","cr_licurl":"https://creativecommons.org/licenses/by/3.0","habit":"乔木","origin":["大洋洲"]},{"id":318,"zh":"Protea afra","en":"Protea afra","sci":"Protea afra","order_en":"Proteales","order_zh":"山龙眼目","family_en":"Proteaceae","family_zh":"山龙眼科","iucn":"LC","langs":20,"desc_zh":null,"desc_en":"Protea afra (sometimes called the common protea), native to Africa, inhabiting from South Africa to Kenya, is a small tree or shrub which occurs in subtropical open or wooded grassland, usually on rocky ridges. Its leaves are leathery and hairless.","img":"images/318.jpg","thumb":"images/t/318.jpg","file":"Protea caffra IMG 2758.JPG","ar":0.667,"py":"","cr_by":"Marco Schmidt [1]","cr_lic":"CC BY-SA 2.5","cr_licurl":"https://creativecommons.org/licenses/by-sa/2.5","habit":"乔木","origin":["非洲"]},{"id":319,"zh":"海岸班克木","en":"Banksia integrifolia","sci":"Banksia integrifolia","order_en":"Proteales","order_zh":"山龙眼目","family_en":"Proteaceae","family_zh":"山龙眼科","iucn":"LC","langs":19,"desc_zh":"变叶佛塔树（学名：Banksia integrifolia，英语：coast banksia），又名佛塔树、全缘叶斑克木，是一种生长在澳洲东海岸的树木。其种加词“integrifolia”意为“全缘叶的”。变叶佛塔树是分布最广泛的佛塔树属物种之一，其分布范围由昆士兰州中部至维多利亚州，在沙丘和山岭上都可以存活。各个地区的变叶佛塔树生长情况有较大差异，最常见的是最高可达25米（82英尺）的树状变叶佛塔树。","desc_en":"Banksia integrifolia, commonly known as the coast banksia, is a species of tree that grows along the east coast of Australia. One of the most widely distributed Banksia species, it occurs between Victoria and Central Queensland in a broad range of habitats, fr…","img":"images/319.jpg","thumb":"images/t/319.jpg","file":"B integrifolia integrifolia1.jpg","ar":0.613,"py":"haianbankemu habkm","cr_by":"No machine-readable author provided. Casliber assumed (based on copyright claims).","cr_lic":"Public domain","cr_licurl":null,"habit":"乔木","origin":null},{"id":320,"zh":"莲","en":"Nelumbo nucifera","sci":"Nelumbo nucifera","order_en":"Proteales","order_zh":"山龙眼目","family_en":"Nelumbonaceae","family_zh":"莲科","iucn":null,"langs":103,"desc_zh":"莲（学名：Nelumbo nucifera；英语：lotus）是莲科莲属多年生草本出水植物，又称荷、荷花、莲花，古称芙蓉、菡萏、芙蕖，梵名迦摩罗（梵语：कमल，罗马化：kamala）、钵头摩/钵特摩/波头摩/波昙/波昙摩/钵昙摩（尤指红莲，梵语：पद्म，罗马化：padma）、分陀利/分陀利迦/芬陀利/芬陀利迦/奔荼利/奔荼利迦（尤指白莲，梵语：पुण्डरीक，罗马化：puṇḍarīka）。花一般盛开于夏季，莲花也因而成为夏日之风物。","desc_en":"Nelumbo nucifera, also known as Padma (Sanskrit: पद्म, romanized: Padma, lit. 'Lotus') or Kamala (Sanskrit: कमल, lit. 'Lotus'), sacred lotus, pink lotus, Indian lotus, or simply lotus, is one of two extant species of aquatic plant in the family Nelumbonaceae.","img":"images/320.jpg","thumb":"images/t/320.jpg","file":"Sacred lotus Nelumbo nucifera.jpg","ar":1.091,"py":"lian l","cr_by":"T.Voekler","cr_lic":"CC BY-SA 3.0","cr_licurl":"https://creativecommons.org/licenses/by-sa/3.0","habit":null,"origin":["亚洲"]},{"id":321,"zh":"法桐","en":"Plantanus orientalis","sci":"Platanus orientalis","order_en":"Proteales","order_zh":"山龙眼目","family_en":"Platanaceae","family_zh":"悬铃木科","iucn":"DD","langs":55,"desc_zh":"法桐（学名：Platanus orientalis）又称三球悬铃木，是悬铃木科植物。由于二球悬铃木（英桐）最早由法国人在法租界霞飞路一带引入，因此中文中法国梧桐多指英桐而非法桐。法桐与梧桐没有亲属关系。 其种加词“orientalis”意为“东方的”。","desc_en":"Platanus orientalis, the Oriental plane, is a large, deciduous tree in the family Platanaceae, growing to 30 m (98 ft) or more, and known for its longevity and spreading crown. In autumn, its deep green leaves may change to blood red, amber, and yellow.","img":"images/321.jpg","thumb":"images/t/321.jpg","file":"Fruits of Platanus orientalis.jpg","ar":0.75,"py":"fatong ft","cr_by":"Samuli Lintula","cr_lic":"Public domain","cr_licurl":null,"habit":"乔木","origin":null},{"id":322,"zh":"锦熟黄杨","en":"Buxus sempervirens","sci":"Buxus sempervirens","order_en":"Buxales","order_zh":"黄杨目","family_en":"Buxaceae","family_zh":"黄杨科","iucn":"LC","langs":62,"desc_zh":"锦熟黄杨（学名：Buxus sempervirens）是黄杨科黄杨属的一种植物，原产于西欧、南欧、西北非及西亚，北起英国南部、南至摩洛哥北部、东达土耳其。原产于西高加索的科尔基斯黄杨（Buxus colchica）与原产于伊朗北部与东高加索的希尔卡尼亚黄杨（Buxus hyrcana）与锦熟黄杨亲缘关系非常近，常被认为是锦熟黄杨的异名。","desc_en":"Buxus sempervirens, the common box, European box, or boxwood, is a species of flowering plant in the genus Buxus, native to western and southern Europe, northwest Africa, and southwest Asia, from southern England south to northern Morocco, and east through the…","img":"images/322.jpg","thumb":"images/t/322.jpg","file":"Buxus sempervirens.jpg","ar":0.633,"py":"jinshuhuangyang jshy","cr_by":"No machine-readable author provided. MPF assumed (based on copyright claims).","cr_lic":"CC BY 2.5","cr_licurl":"https://creativecommons.org/licenses/by/2.5","habit":null,"origin":["亚洲","欧洲","非洲"]},{"id":323,"zh":"顶花板凳果","en":"Pachysandra terminalis","sci":"Pachysandra terminalis","order_en":"Buxales","order_zh":"黄杨目","family_en":"Buxaceae","family_zh":"黄杨科","iucn":null,"langs":19,"desc_zh":"顶花板凳果（学名：Pachysandra terminalis）是黄杨科板凳果属的植物。分布于日本以及中国大陆的四川、湖北、浙江、陕西、甘肃等地，生长于海拔1,000米至2,600米的地区，常生于山区林下阴湿地，已由人工引种栽培，用于药材或园艺。","desc_en":"Pachysandra terminalis, the Japanese pachysandra, carpet box or Japanese spurge, is a species of flowering plant in the boxwood family Buxaceae, native to Japan, Korea and China and introduced to eastern North America.","img":"images/323.jpg","thumb":"images/t/323.jpg","file":"Pachysandra terminalis0.jpg","ar":1.333,"py":"dinghuabandengguo dhbdg","cr_by":"Kurt Stüber [1]","cr_lic":"CC BY-SA 3.0","cr_licurl":"http://creativecommons.org/licenses/by-sa/3.0/","habit":"草本","origin":["亚洲","北美洲"]},{"id":324,"zh":"昆栏树","en":"Trochodendron aralioides","sci":"Trochodendron aralioides","order_en":"Trochodendrales","order_zh":"昆栏树目","family_en":"Trochodendraceae","family_zh":"昆栏树科","iucn":null,"langs":14,"desc_zh":"昆栏树（学名：Trochodendron aralioides）为昆栏树科昆栏树属下的唯一一种。 昆栏树分布于日本、南韩及台湾，生长在日本的针阔叶混合林及常绿阔叶林，以及台湾中央山脉及北部山区的常绿阔叶林中。","desc_en":"Trochodendron aralioides, sometimes colloquially called wheel tree, is a flowering plant and the sole living species in the genus Trochodendron, which also includes several extinct species.","img":"images/324.jpg","thumb":"images/t/324.jpg","file":"Trochodendron aralioides 2.jpg","ar":1.506,"py":"kunlanshu kls","cr_by":"Eric in SF","cr_lic":"CC BY-SA 3.0","cr_licurl":"https://creativecommons.org/licenses/by-sa/3.0","habit":"乔木","origin":["亚洲"]},{"id":325,"zh":"长萼大叶草","en":"Gunnera manicata","sci":"Gunnera manicata","order_en":"Gunnerales","order_zh":"洋二仙草目","family_en":"Gunneraceae","family_zh":"洋二仙草科","iucn":null,"langs":23,"desc_zh":"大叶蚁塔（Gunnera manicata），又名长萼大叶草，俗称巨人大黄（源自英语：Brazilian giant-rhubarb/giant rhubarb），是洋二仙草属的一种植物，原产于巴西马尔山脉附近地区。它是一种有著巨大叶子的常绿草本植物，高可达2.5米（8.2英尺）至4米（13英尺），叶子直径可达4英尺（120厘米），植株整体覆盖面积达9平方米（97平方英尺）。叶子底部和茎上有刺，开红绿色小花，结的果子也很小。","desc_en":"Gunnera manicata, known as Brazilian giant-rhubarb, giant rhubarb, or dinosaur food is a species of flowering plant in the family Gunneraceae from the coastal Serra do Mar Mountains of Santa Catarina, Parana and Rio Grande do Sul States, Brazil.","img":"images/325.jpg","thumb":"images/t/325.jpg","file":"Gunnera manicata3.JPG","ar":1.333,"py":"changedayecao cedyc","cr_by":"Required attribution is: Photo by Tom Oates. The original uploader was Nabokov at English Wikipedia . (a.k.a. Tom Oates)","cr_lic":"CC BY-SA 3.0","cr_licurl":"https://creativecommons.org/licenses/by-sa/3.0","habit":null,"origin":["南美洲"]},{"id":326,"zh":"落地生根","en":"Kalanchoe pinnata","sci":"Kalanchoe pinnata","order_en":"Saxifragales","order_zh":"虎耳草目","family_en":"Crassulaceae","family_zh":"景天科","iucn":null,"langs":55,"desc_zh":"落地生根（学名：Kalanchoe pinnata）又称叶生根、土三七、天灯笼、古仔灯、大还魂、倒地莲、倒吊莲、打不死、番鬼牡丹，原产地为热带非洲，是景天科伽蓝菜属的多肉植物。由于若将其叶放在泥土上，叶边的一点即能发芽生长，不必依赖种子繁殖，故名落地生根。若将它屈折或打断，其叶著地即能生长，故亦有「打不死」之名。具有止血、消炎、止痛、消肿解毒之功效。但脾胃虚寒者慎服。此外也可做切花、盆栽、花坛和庭园露地栽培。花语：坚忍，有毅力。","desc_en":"Kalanchoe pinnata, commonly known as cathedral bells, air plant, life plant, miracle leaf, and love bush, is a succulent plant native to Madagascar. It is a popular houseplant and has become naturalized in tropical and subtropical areas.","img":"images/326.jpg","thumb":"images/t/326.jpg","file":"Kalanchoe pinnata kz1.JPG","ar":0.667,"py":"luodishenggen ldsg","cr_by":"Krzysztof Ziarnek, Kenraiz","cr_lic":"CC BY-SA 4.0","cr_licurl":"https://creativecommons.org/licenses/by-sa/4.0","habit":"多肉","origin":["非洲"]},{"id":327,"zh":"蔷薇红景天","en":"Rhodiola rosea","sci":"Rhodiola rosea","order_en":"Saxifragales","order_zh":"虎耳草目","family_en":"Crassulaceae","family_zh":"景天科","iucn":null,"langs":51,"desc_zh":"红景天（学名：Rhodiola rosea）是景天科红景天属的植物。分布于日本、朝鲜、俄罗斯、蒙古以及吉林、河北、山西、新疆等地，生长于海拔1,800米至2,700米的地区，多生长于山坡林下或草坡上，目前尚未由人工引种栽培。","desc_en":"Rhodiola rosea (commonly golden root, rose root, roseroot, Aaron's rod, Arctic root, king's crown, lignum rhodium, orpin rose) is a perennial flowering plant in the family Crassulaceae.","img":"images/327.jpg","thumb":"images/t/327.jpg","file":"Rhodiola rosea (Montage s3).jpg","ar":1,"py":"qiangweihongjingtian qwhjt","cr_by":"Alpsdake","cr_lic":"CC BY-SA 4.0","cr_licurl":"https://creativecommons.org/licenses/by-sa/4.0","habit":"草本","origin":["亚洲","欧洲","北美洲"]},{"id":328,"zh":"苔景天","en":"Sedum acre","sci":"Sedum acre","order_en":"Saxifragales","order_zh":"虎耳草目","family_en":"Crassulaceae","family_zh":"景天科","iucn":null,"langs":50,"desc_zh":"苔景天（学名：Sedum acre）是景天科景天属下的一个种，也叫苦味景天、欧洲万年草。种加词acre的意思是刺激的苦辛味。有中文资料将其误译为锐叶景天，但实际上苔景天的叶尖钝圆，而非锐尖。","desc_en":"Sedum acre, commonly known as the goldmoss stonecrop, mossy stonecrop, goldmoss sedum, biting stonecrop, and wallpepper, is a perennial flowering plant in the family Crassulaceae.","img":"images/328.jpg","thumb":"images/t/328.jpg","file":"Sedum acre single - Niitvälja.jpg","ar":0.714,"py":"taijingtian tjt","cr_by":"Ivar Leidus","cr_lic":"CC BY-SA 4.0","cr_licurl":"https://creativecommons.org/licenses/by-sa/4.0","habit":"草本","origin":["亚洲","欧洲","非洲","北美洲","南美洲","大洋洲"]},{"id":329,"zh":"长生草","en":"Sempervivum tectorum","sci":"Sempervivum tectorum","order_en":"Saxifragales","order_zh":"虎耳草目","family_en":"Crassulaceae","family_zh":"景天科","iucn":null,"langs":46,"desc_zh":null,"desc_en":"Sempervivum tectorum, the common houseleek, is a species of flowering plant in the family Crassulaceae, native to the mountains of southern Europe, cultivated in the whole of Europe for its appearance and a Roman-era tradition claiming that it protects buildin…","img":"images/329.jpg","thumb":"images/t/329.jpg","file":"Matafoc flor 8 agost06 050.jpg","ar":1.333,"py":"changshengcao csc","cr_by":"Victor M. Vicente Selvas","cr_lic":"Public domain","cr_licurl":null,"habit":null,"origin":["欧洲"]},{"id":330,"zh":"翡翠木","en":"Crassula ovata","sci":"Crassula ovata","order_en":"Saxifragales","order_zh":"虎耳草目","family_en":"Crassulaceae","family_zh":"景天科","iucn":null,"langs":41,"desc_zh":"翡翠木（学名：Crassula ovata）又称发财树、玉树、燕子掌，原生于南非。为景天科青锁龙属多肉质亚灌木植物。","desc_en":"Crassula ovata, commonly known as jade plant, lucky plant, money plant or money tree, is a succulent plant with small pink or white flowers that is native to the KwaZulu-Natal and Eastern Cape provinces of South Africa, and Mozambique; it is common as a housep…","img":"images/330.jpg","thumb":"images/t/330.jpg","file":"2016-10-03 Crassula ovata, Camdeboo NP, Eastern Cape (31803933474).jpg","ar":1.487,"py":"feicuimu fcm","cr_by":"Bernard DUPONT from FRANCE","cr_lic":"CC BY-SA 2.0","cr_licurl":"https://creativecommons.org/licenses/by-sa/2.0","habit":"多肉","origin":["非洲"]},{"id":331,"zh":"长寿花","en":"Kalanchoe blossfeldiana","sci":"Kalanchoe blossfeldiana","order_en":"Saxifragales","order_zh":"虎耳草目","family_en":"Crassulaceae","family_zh":"景天科","iucn":null,"langs":37,"desc_zh":"长寿花（学名：Kalanchoe blossfeldiana）又称家乐花、燕子海棠、圣诞伽蓝菜、寿星花、布洛斯费尔德高凉菜，属景天科伽蓝菜属，原产于非洲的马达加斯加。长寿花是常见的观赏花卉。","desc_en":"Kalanchoe blossfeldiana is a commonly cultivated evergreen house plant of the genus Kalanchoe native to Madagascar. It is known by the English common names flaming Katy, Christmas kalanchoe, florist kalanchoe and Madagascar widow's-thrill.","img":"images/331.jpg","thumb":"images/t/331.jpg","file":"Kalanchoe.blossfeldiana.jpg","ar":1.023,"py":"changshouhua csh","cr_by":"Cdpanic at English Wikipedia","cr_lic":"CC BY-SA 3.0","cr_licurl":"http://creativecommons.org/licenses/by-sa/3.0/","habit":null,"origin":["非洲"]},{"id":332,"zh":"白景天","en":"Sedum album","sci":"Sedum album","order_en":"Saxifragales","order_zh":"虎耳草目","family_en":"Crassulaceae","family_zh":"景天科","iucn":null,"langs":37,"desc_zh":null,"desc_en":"Sedum album, the white stonecrop, is a flowering plant of the genus Sedum in the family Crassulaceae. It is found in the northern temperate regions of the world, often growing in crevices or free-draining rocky soil.","img":"images/332.jpg","thumb":"images/t/332.jpg","file":"Sedum album.jpg","ar":0.941,"py":"baijingtian bjt","cr_by":"Franz Xaver","cr_lic":"CC BY-SA 3.0","cr_licurl":"http://creativecommons.org/licenses/by-sa/3.0/","habit":null,"origin":null},{"id":333,"zh":"紫八宝","en":"Hylotelephium telephium","sci":"Hylotelephium telephium","order_en":"Saxifragales","order_zh":"虎耳草目","family_en":"Crassulaceae","family_zh":"景天科","iucn":null,"langs":35,"desc_zh":"紫八宝（学名：Hylotelephium purpureum）又称紫景天，为景天科八宝属的植物。分布于远东地区、日本、欧洲、北美洲以及中国大陆的新疆、黑龙江、吉林、辽宁等地，生长于海拔420米至1,550米的地区，多生长于山坡草原上或林下阴湿山沟边，目前尚未由人工引种栽培。","desc_en":"Hylotelephium telephium (synonym Sedum telephium), known as orpine, livelong, frog's-stomach, harping Johnny, life-everlasting, live-forever, midsummer-men, Orphan John, witch's moneybags, and garden stonecrop is a succulent perennial plant of the family Crass…","img":"images/333.jpg","thumb":"images/t/333.jpg","file":"(MHNT) Hylotelephium telephium - Habitus.jpg","ar":1.501,"py":"zibabao zbb","cr_by":"Didier Descouens","cr_lic":"CC BY-SA 4.0","cr_licurl":"https://creativecommons.org/licenses/by-sa/4.0","habit":"多肉","origin":["亚洲"]},{"id":334,"zh":"三角叶落地生根","en":"Kalanchoe daigremontiana","sci":"Kalanchoe daigremontiana","order_en":"Saxifragales","order_zh":"虎耳草目","family_en":"Crassulaceae","family_zh":"景天科","iucn":"EN","langs":31,"desc_zh":"三角叶落地生根（学名：Kalanchoe daigremontiana）也叫大叶虎纹落地生根、大叶虎纹不死鸟、锐叶掌上珠，日语名缀弁庆，是伽蓝菜属落地生根亚属的一种多肉植物，原产马达加斯加。其叶对生，十字形排列，呈长三角形至长卵形，正面纯绿色，背面有斑纹，叶基耳状或盾状，叶缘有齿，齿间能长出用于无性繁殖的不定芽。","desc_en":"Kalanchoe daigremontiana, formerly known as Bryophyllum daigremontianum and commonly called mother of thousands, alligator plant or Mexican hat plant, is a succulent plant native to Madagascar.","img":"images/334.jpg","thumb":"images/t/334.jpg","file":"Zyworodka - Kalanchoe daigremontiana.JPG","ar":1.68,"py":"sanjiaoyeluodishenggen sjyldsg","cr_by":"Alina Zienowicz Ala z","cr_lic":"Public domain","cr_licurl":null,"habit":"多肉","origin":["非洲"]},{"id":335,"zh":"东爪草","en":"Crassula aquatica","sci":"Crassula aquatica","order_en":"Saxifragales","order_zh":"虎耳草目","family_en":"Crassulaceae","family_zh":"景天科","iucn":null,"langs":30,"desc_zh":"东爪草（学名：Tillaea aquatica）为景天科东爪草属下的一个种。","desc_en":"Crassula aquatica is a succulent plant known by the common names water pygmyweed, common pygmyweed and just pigmyweed. It is an annual plant of salt marshes, vernal pools, wetlands, and other fresh to brackish water bodies.","img":"images/335.jpg","thumb":"images/t/335.jpg","file":"Crassula aquatica.jpg","ar":1.333,"py":"dongzhuacao dzc","cr_by":"Hörður Kristinsson from Eyjafjarðarsveit, Island","cr_lic":"CC BY 2.0","cr_licurl":"https://creativecommons.org/licenses/by/2.0","habit":"多肉","origin":null},{"id":336,"zh":"脐景天","en":"Umbilicus rupestris","sci":"Umbilicus rupestris","order_en":"Saxifragales","order_zh":"虎耳草目","family_en":"Crassulaceae","family_zh":"景天科","iucn":null,"langs":30,"desc_zh":null,"desc_en":"Wall pennywort (Umbilicus rupestris), also called navelwort,, hipwort or penny-pies, is a fleshy, perennial, edible flowering plant in the stonecrop family Crassulaceae in the genus Umbilicus so named for its umbilicate (navel-like) leaves.","img":"images/336.jpg","thumb":"images/t/336.jpg","file":"Navelwort 700.jpg","ar":0.75,"py":"qijingtian qjt","cr_by":"Photo by sannse","cr_lic":"CC BY-SA 3.0","cr_licurl":"http://creativecommons.org/licenses/by-sa/3.0/","habit":"草本","origin":null},{"id":337,"zh":"厚叶岩白菜","en":"Bergenia crassifolia","sci":"Bergenia crassifolia","order_en":"Saxifragales","order_zh":"虎耳草目","family_en":"Saxifragaceae","family_zh":"虎耳草科","iucn":null,"langs":36,"desc_zh":"厚叶岩白菜（Bergenia crassifolia），又名西伯利亚茶、蒙古茶、巴丹茶、白菜皮、冬白菜等，是岩白菜属的一个种。青海白菜高约 30 cm，叶子呈匙羮形。 厚叶岩白菜含有多种多酚类化合物，例如：熊果苷和单宁。","desc_en":"Bergenia crassifolia is a species of flowering plant of the genus Bergenia in the family Saxifragaceae. Common names for the species include heart-leaved bergenia, heartleaf bergenia, leather bergenia, winter-blooming bergenia, elephant-ears, elephant's ears,…","img":"images/337.jpg","thumb":"images/t/337.jpg","file":"Bergenia crassifolia a1.jpg","ar":1.325,"py":"houyeyanbaicai hyybc","cr_by":"Jerzy Opioła","cr_lic":"CC BY-SA 4.0","cr_licurl":"https://creativecommons.org/licenses/by-sa/4.0","habit":null,"origin":["亚洲","欧洲"]},{"id":338,"zh":"小鳞茎虎耳草","en":"Saxifraga granulata","sci":"Saxifraga granulata","order_en":"Saxifragales","order_zh":"虎耳草目","family_en":"Saxifragaceae","family_zh":"虎耳草科","iucn":null,"langs":34,"desc_zh":null,"desc_en":"Saxifraga granulata, commonly called meadow saxifrage, is a species of flowering plant in the family Saxifragaceae. It is native to most of Europe and Morocco.","img":"images/338.jpg","thumb":"images/t/338.jpg","file":"Saxifraga granulata 140505.jpg","ar":0.75,"py":"xiaolinjinghuercao xljhec","cr_by":"Bernd Haynold","cr_lic":"CC BY-SA 3.0","cr_licurl":"http://creativecommons.org/licenses/by-sa/3.0/","habit":null,"origin":["欧洲"]},{"id":339,"zh":"挪威虎耳草","en":"Saxifraga oppositifolia","sci":"Saxifraga oppositifolia","order_en":"Saxifragales","order_zh":"虎耳草目","family_en":"Saxifragaceae","family_zh":"虎耳草科","iucn":null,"langs":32,"desc_zh":"挪威虎耳草（学名：Saxifraga oppositifolia）为虎耳草科虎耳草属下的一个种。","desc_en":"Saxifraga oppositifolia, the purple saxifrage or purple mountain saxifrage, is a species of plant that is very common in the high Arctic and also some high mountainous areas further south, including northern Britain, the Alps and the Rocky Mountains.","img":"images/339.jpg","thumb":"images/t/339.jpg","file":"Purpsaxifrage2.jpg","ar":0.75,"py":"nuoweihuercao nwhec","cr_by":null,"cr_lic":"CC BY-SA 3.0","cr_licurl":"http://creativecommons.org/licenses/by-sa/3.0/","habit":null,"origin":["欧洲","北美洲"]},{"id":340,"zh":"Saxifraga aizoides","en":"Saxifraga aizoides","sci":"Saxifraga aizoides","order_en":"Saxifragales","order_zh":"虎耳草目","family_en":"Saxifragaceae","family_zh":"虎耳草科","iucn":null,"langs":31,"desc_zh":null,"desc_en":"Saxifraga aizoides, yellow mountain saxifrage or yellow saxifrage, is a flowering alpine plant of the genus Saxifraga.","img":"images/340.jpg","thumb":"images/t/340.jpg","file":"Saxifraga aizoides (flowers).jpg","ar":1.333,"py":"","cr_by":"Hans Hillewaert","cr_lic":"CC BY-SA 3.0","cr_licurl":"https://creativecommons.org/licenses/by-sa/3.0","habit":null,"origin":null},{"id":341,"zh":"Saxifraga tridactylites","en":"Saxifraga tridactylites","sci":"Saxifraga tridactylites","order_en":"Saxifragales","order_zh":"虎耳草目","family_en":"Saxifragaceae","family_zh":"虎耳草科","iucn":null,"langs":30,"desc_zh":null,"desc_en":"Saxifraga tridactylites, the rue-leaved saxifrage or \"nailwort\", is a species of plant in the family Saxifragaceae. Rue-leaved saxifrage is a winter-annual herb with distinctive, trilobed, fleshy leaves and red stems.","img":"images/341.jpg","thumb":"images/t/341.jpg","file":"Saxifraga tridactylites3.jpg","ar":0.797,"py":"","cr_by":"No machine-readable author provided. Aroche assumed (based on copyright claims).","cr_lic":"CC BY-SA 2.5","cr_licurl":"https://creativecommons.org/licenses/by-sa/2.5","habit":"草本","origin":null},{"id":342,"zh":"鹅莓","en":"Ribes uva-crispa","sci":"Ribes uva-crispa","order_en":"Saxifragales","order_zh":"虎耳草目","family_en":"Grossulariaceae","family_zh":"醋栗科","iucn":null,"langs":100,"desc_zh":"鹅莓（学名：Ribes uva-crispa），又称醋栗或欧洲醋栗，是茶藨子科醋栗属草本植物的一种。","desc_en":"Ribes uva-crispa, commonly known as the gooseberry or European gooseberry, is a species of flowering shrub native to Europe, northwestern Africa, and southwestern Asia. It belongs to the family Grossulariaceae, which includes currants and gooseberries.","img":"images/342.jpg","thumb":"images/t/342.jpg","file":"Stachelbeeren.jpg","ar":0.75,"py":"emei em","cr_by":null,"cr_lic":"CC BY-SA 3.0","cr_licurl":"http://creativecommons.org/licenses/by-sa/3.0/","habit":"灌木","origin":["亚洲","欧洲","非洲"]},{"id":343,"zh":"黑加仑","en":"Ribes nigrum","sci":"Ribes nigrum","order_en":"Saxifragales","order_zh":"虎耳草目","family_en":"Grossulariaceae","family_zh":"醋栗科","iucn":null,"langs":90,"desc_zh":"黑加仑（学名：Ribes nigrum），又名黑醋栗、黑加伦子、黑豆果、黑茶藨子、黑穗醋栗，为虎耳草目茶藨子科小型灌木，其成熟果实为黑色小浆果，可以食用，也可以加工成果汁、果酱等食品，果实外观近似葡萄，但实为不同目的植物。","desc_en":"The blackcurrant (Ribes nigrum), black currant or cassis is a deciduous shrub in the family Grossulariaceae grown for its edible berries. It is native to temperate parts of central and northern Europe and northern Asia, where it prefers damp fertile soils.","img":"images/343.jpg","thumb":"images/t/343.jpg","file":"Schwarzejohannisbeere.jpg","ar":1.357,"py":"heijialun hjl","cr_by":null,"cr_lic":"Public domain","cr_licurl":null,"habit":"灌木","origin":["亚洲","欧洲"]},{"id":344,"zh":"荷兰芍药","en":"Paeonia officinalis","sci":"Paeonia officinalis","order_en":"Saxifragales","order_zh":"虎耳草目","family_en":"Paeoniaceae","family_zh":"芍药科","iucn":"LC","langs":38,"desc_zh":null,"desc_en":"Paeonia officinalis, the common peony, or garden peony, is a species of flowering plant in the family Paeoniaceae, native to mainly mountainous areas of Southern Europe and introduced in Central and Western Europe and North America.","img":"images/344.jpg","thumb":"images/t/344.jpg","file":"PAEONIA OFFICINALIS - MONTSEC - IB-200 (Peònia de muntanya).jpg","ar":1.333,"py":"helanshaoyao hlsy","cr_by":"Isidre blanc","cr_lic":"CC BY-SA 4.0","cr_licurl":"https://creativecommons.org/licenses/by-sa/4.0","habit":null,"origin":["欧洲","北美洲"]},{"id":345,"zh":"牡丹","en":"Paeonia × suffruticosa","sci":"Paeonia suffruticosa","order_en":"Saxifragales","order_zh":"虎耳草目","family_en":"Paeoniaceae","family_zh":"芍药科","iucn":null,"langs":31,"desc_zh":"牡丹（学名：Paeonia × suffruticosa）为芍药科芍药属的一种落叶小灌木，拥有非常巨大且多层的花朵，是起源于中国的一个杂交栽培种，高1～1.5米；二回三出复叶，小叶常3－5裂。初夏开白色、红色或紫色花，花单生大型，雌蕊生于肉质花盘上，密被细毛。常见于和中国文化有关之工艺品中，例如唐朝和清朝的女子头饰、工笔画、汉服纹样等。","desc_en":"Paeonia × suffruticosa is a group of tree peony cultivars that are the result of hybridization with peony species exclusively belonging to the subsection Vaginatae. The common name used in China is mǔdān (Chinese: 牡丹) or Moutan peony.","img":"images/345.jpg","thumb":"images/t/345.jpg","file":"Strauchpfingstrose - Botanischer Garten in Wien.JPG","ar":0.75,"py":"mudan md","cr_by":"C.Stadler/Bwag","cr_lic":"CC BY-SA 4.0","cr_licurl":"https://creativecommons.org/licenses/by-sa/4.0","habit":"乔木","origin":null},{"id":346,"zh":"波斯铁木","en":"Parrotia persica","sci":"Parrotia persica","order_en":"Saxifragales","order_zh":"虎耳草目","family_en":"Hamamelidaceae","family_zh":"金缕梅科","iucn":null,"langs":32,"desc_zh":null,"desc_en":"Parrotia persica, the Persian ironwood, is a deciduous tree in the family Hamamelidaceae, closely related to the witch-hazel genus Hamamelis. It is native to the Caspian region of northern Iran (where it is called انجیلی anjili) and southeastern Azerbaijan (wh…","img":"images/346.jpg","thumb":"images/t/346.jpg","file":"برگ درخت انجیلی در اردیبهشت ماه.jpg","ar":0.81,"py":"bositiemu bstm","cr_by":"Waheed butt","cr_lic":"CC BY-SA 4.0","cr_licurl":"https://creativecommons.org/licenses/by-sa/4.0","habit":"乔木","origin":["亚洲"]},{"id":347,"zh":"北美金缕梅","en":"Hamamelis virginiana","sci":"Hamamelis virginiana","order_en":"Saxifragales","order_zh":"虎耳草目","family_en":"Hamamelidaceae","family_zh":"金缕梅科","iucn":"LC","langs":31,"desc_zh":"北美金缕梅（学名：Hamamelis virginiana），又名维吉尼亚金缕梅，是金缕梅属的一种落叶灌木。原产于北美洲东部，由加拿大的新斯科舍省向西至美国的明尼苏达州，向南至佛罗里达州中部与德克萨斯州东部。","desc_en":"Hamamelis virginiana, known as witch-hazel, common witch-hazel, American witch-hazel and beadwood, is a species of flowering shrub native to eastern North America, from Nova Scotia west to Minnesota, and south to central Florida to eastern Texas.","img":"images/347.jpg","thumb":"images/t/347.jpg","file":"Hamamelis virginiana - Köhler–s Medizinal-Pflanzen-070.jpg","ar":0.734,"py":"beimeijinlmei bmjlm","cr_by":"Franz Eugen Köhler, Köhler's Medizinal-Pflanzen","cr_lic":"Public domain","cr_licurl":null,"habit":"灌木","origin":["北美洲"]},{"id":348,"zh":"酿酒葡萄","en":"Vitis vinifera","sci":"Vitis vinifera","order_en":"Vitales","order_zh":"葡萄目","family_en":"Vitaceae","family_zh":"葡萄科","iucn":"LC","langs":86,"desc_zh":"葡萄（学名：Vitis vinifera），是一种主要用来酿造酒的葡萄，葡萄科葡萄属的开花植物。目前有 5,000 到 10,000 个品种，但只有少数品种对生产具有商业意义。 野生葡萄一般归类为野生亚种（V. v. subsp. sylvestris），而培植种则是指名亚种（V. v. subsp. vinifera）。驯化的葡萄树是有雌雄同体的花，而野生亚种的是雌雄异花的（雄花和雌花在不同的植物上），需要授粉来结果。","desc_en":"Vitis vinifera, the common grape vine, is a species of flowering plant, native to the Mediterranean region, Central Europe, and southwestern Asia, from Morocco and Portugal north to southern Germany and east to northern Iran.","img":"images/348.jpg","thumb":"images/t/348.jpg","file":"Vitis vinifera - Köhler–s Medizinal-Pflanzen-145.jpg","ar":0.816,"py":"niangjiuputao njpt","cr_by":"Franz Eugen Köhler, Köhler's Medizinal-Pflanzen","cr_lic":"Public domain","cr_licurl":null,"habit":"藤本","origin":["亚洲","欧洲"]},{"id":349,"zh":"五叶地锦","en":"Parthenocissus quinquefolia","sci":"Parthenocissus quinquefolia","order_en":"Vitales","order_zh":"葡萄目","family_en":"Vitaceae","family_zh":"葡萄科","iucn":"LC","langs":46,"desc_zh":"五叶地锦（学名：Parthenocissus quinquefolia）为葡萄科地锦属的植物。分布于北美以及中国大陆的华北、东北等地，目前已由人工引种栽培。","desc_en":"Parthenocissus quinquefolia, commonly known as Virginia creeper, woodbine, five-leaved ivy, or five-finger, is a species of flowering vine in the grape family Vitaceae.","img":"images/349.jpg","thumb":"images/t/349.jpg","file":"Klimop detail 2.JPG","ar":0.75,"py":"wuyedijin wydj","cr_by":"Tasja","cr_lic":"Public domain","cr_licurl":null,"habit":"藤本","origin":["北美洲"]},{"id":350,"zh":"美洲葡萄","en":"Vitis labrusca","sci":"Vitis labrusca","order_en":"Vitales","order_zh":"葡萄目","family_en":"Vitaceae","family_zh":"葡萄科","iucn":null,"langs":35,"desc_zh":"美洲葡萄（学名：Vitis labrusca）为葡萄科葡萄属下的一个种。","desc_en":"Vitis labrusca, the fox grape, is a species of grapevines belonging to the Vitis genus in the flowering plant family Vitaceae. The vines are native to eastern North America and are the source of many grape cultivars, including Catawba, Concord, Delaware, Isabe…","img":"images/350.jpg","thumb":"images/t/350.jpg","file":"ConcordGrapes.jpg","ar":0.935,"py":"meizhouputao mzpt","cr_by":"Unknown Unknown ; cropped, cleaned up, and levels adjustment by Howcheng","cr_lic":"Public domain","cr_licurl":null,"habit":"藤本","origin":["北美洲"]},{"id":351,"zh":"爬墙虎","en":"Parthenocissus tricuspidata","sci":"Parthenocissus tricuspidata","order_en":"Vitales","order_zh":"葡萄目","family_en":"Vitaceae","family_zh":"葡萄科","iucn":null,"langs":32,"desc_zh":"爬墙虎（学名：Parthenocissus tricuspidata）又名爬山虎、地锦、土鼓藤、红葡萄藤，属葡萄科地锦属。原产朝鲜半岛、日本及中国华北和东北地区。","desc_en":"Parthenocissus tricuspidata is a species of flowering plant in the grape family (Vitaceae) native to eastern Asia (Korea, Japan, and northern and eastern China), where it thrives in floodplain bushes, riverside woodland and moist mountain mixed forests.","img":"images/351.jpg","thumb":"images/t/351.jpg","file":"姫路モノレール跡-06.jpg","ar":0.667,"py":"paqianghu pqh","cr_by":"Gohachiyasu1214","cr_lic":"CC BY-SA 4.0","cr_licurl":"https://creativecommons.org/licenses/by-sa/4.0","habit":"藤本","origin":["亚洲"]},{"id":352,"zh":"山葡萄","en":"Vitis amurensis","sci":"Vitis amurensis","order_en":"Vitales","order_zh":"葡萄目","family_en":"Vitaceae","family_zh":"葡萄科","iucn":null,"langs":31,"desc_zh":"山葡萄（学名：Vitis amurensis）为葡萄科葡萄属的植物。","desc_en":"Vitis amurensis, the Amur grape, is a species of grape native to the Asian continent. Its name comes from the Amur Valley in Russia and China. It is very resistant to frost, but is not tolerant to drought.","img":"images/352.jpg","thumb":"images/t/352.jpg","file":"Vitis amurensis.jpg","ar":1.504,"py":"shanputao spt","cr_by":"Doronenko","cr_lic":"CC BY 2.5","cr_licurl":"https://creativecommons.org/licenses/by/2.5","habit":null,"origin":["亚洲"]},{"id":353,"zh":"大豆","en":"soybean","sci":"Glycine max","order_en":"Fabales","order_zh":"豆目","family_en":"Fabaceae","family_zh":"豆科","iucn":null,"langs":149,"desc_zh":"大豆（学名：Glycine max，英语：soybean）古称菽（shū），是豆科大豆属植物，其种子含有丰富的蛋白质，此名词一般都指其种子而言。一年生草本植物，高30-90厘米。 大豆是东亚的原生种植物，果实呈椭圆形、球形。因品系不同，而种皮颜色有黄色、淡绿色、黑色、棕色，所以又别名为黄豆（黄大豆）、青豆（是指青大豆，不是指豌豆）、黑豆（黑大豆）；此外，另有茶大豆。。其中，以黄豆最常见。","desc_en":"The soybean, soy bean, or soya bean (Glycine max) is a species of legume native to East Asia, widely grown for its edible bean. Soy is a staple crop, the world's most grown legume, and an important animal feed.","img":"images/353.jpg","thumb":"images/t/353.jpg","file":"Soybean.USDA.jpg","ar":0.673,"py":"dadou dd","cr_by":null,"cr_lic":"Public domain","cr_licurl":null,"habit":null,"origin":["亚洲"]},{"id":354,"zh":"豌豆","en":"Pisum sativum","sci":"Pisum sativum","order_en":"Fabales","order_zh":"豆目","family_en":"Fabaceae","family_zh":"豆科","iucn":null,"langs":145,"desc_zh":"豌豆（学名：Pisum sativum）为豆科豌豆属一年生或二年生攀缘草本植物，是重要的粮食和蔬菜，别称胡豆、麦豆、寒豆、小寒豆、淮豆、麻豆、青小豆、青斑豆、留豆、金豆、回回豆、麦豌豆、雪豆、毕豆、麻累、国豆、马豆等。","desc_en":"Pea is a pulse or fodder crop, but the word often refers to the seed or sometimes the pod of this flowering plant species. Peas are eaten as a vegetable. Carl Linnaeus gave the species the scientific name Pisum sativum in 1753 (meaning cultivated pea).","img":"images/354.jpg","thumb":"images/t/354.jpg","file":"NCI peas in pod.jpg","ar":1.975,"py":"wandou wd","cr_by":"Renee Comet (photographer) AV Number: AV-9400-4164","cr_lic":"Public domain","cr_licurl":null,"habit":"草本","origin":null},{"id":355,"zh":"花生","en":"peanut","sci":"Arachis hypogaea","order_en":"Fabales","order_zh":"豆目","family_en":"Fabaceae","family_zh":"豆科","iucn":null,"langs":131,"desc_zh":"花生（学名：Arachis hypogaea）是豆科落花生属的一种植物。其果仁广泛用作食品。花生原产于南美洲，为热带及亚热带作物。","desc_en":"The peanut (Arachis hypogaea), also known as the groundnut, goober (US, via Kikongo), goober pea, pindar (US, via Kikongo) or monkey nut (UK), is a legume crop grown mainly for its edible seeds, contained in underground pods.","img":"images/355.jpg","thumb":"images/t/355.jpg","file":"Groundnuts in container.jpg","ar":0.75,"py":"huasheng hs","cr_by":"Ibn Dagara","cr_lic":"CC BY-SA 4.0","cr_licurl":"https://creativecommons.org/licenses/by-sa/4.0","habit":null,"origin":["南美洲"]},{"id":356,"zh":"酸豆","en":"Tamarindus indica","sci":"Tamarindus indica","order_en":"Fabales","order_zh":"豆目","family_en":"Fabaceae","family_zh":"豆科","iucn":"LC","langs":118,"desc_zh":"酸豆（学名：Tamarindus indica），别名罗望子、酸角、酸果、酸子、亚参、九层皮、泰国甜角、酸梅树、亚森果，是豆科酸豆属唯一的种，是热带乔木，原产于东部非洲，包括马达加斯加落叶林，但已被引种到亚洲热带地区、拉丁美洲和加勒比地区。英文Tamarindus由Tarmar和indus组成，Tarmar的意思为熟枣的，indus是指印度。罗望子是中国海南省三亚市的市树。","desc_en":"Tamarind (Tamarindus indica) is a leguminous tree bearing edible fruit that is indigenous to tropical Africa and naturalized in Asia. The genus Tamarindus is monotypic, meaning that it contains only this species. It belongs to the family Fabaceae.","img":"images/356.jpg","thumb":"images/t/356.jpg","file":"Tamarindus indica pods.JPG","ar":0.75,"py":"suandou sd","cr_by":"B.navez","cr_lic":"CC BY 2.5","cr_licurl":"https://creativecommons.org/licenses/by/2.5","habit":"乔木","origin":["亚洲","非洲"]},{"id":357,"zh":"鹰嘴豆","en":"Cicer arietinum","sci":"Cicer arietinum","order_en":"Fabales","order_zh":"豆目","family_en":"Fabaceae","family_zh":"豆科","iucn":null,"langs":117,"desc_zh":"鹰嘴豆（学名：Cicer arietinum）又名马豆、桃尔豆、鸡心豆、鸡豆、雪莲子等，原产自东南土耳其，逐渐驯化扩展至黎凡特地区，目前是地中海、中东、印度菜系的主要成分；而于 2019 年，印度占全球鹰嘴豆产量的 70%。在欧洲食用鹰嘴豆也十分普遍，此食材时常出现在小说里面，也是维吾尔医常用药材。因其形状奇特，尖如鹰嘴，故得鹰嘴豆之名。 鹰嘴豆的淀粉具有板栗香味。白色的品种在口感和外型上都与莲子相似。","desc_en":"The chickpea or chick pea (Cicer arietinum) is an annual legume of the family Fabaceae, subfamily Faboideae, cultivated for its edible seeds. Its different types are variously known as gram, Bengal gram, chana (চানা), garbanzo, garbanzo bean, or Egyptian pea.","img":"images/357.jpg","thumb":"images/t/357.jpg","file":"Cicer arietinum HabitusFruits BotGardBln0906a.jpg","ar":0.857,"py":"yingzuidou yzd","cr_by":null,"cr_lic":"CC BY-SA 3.0","cr_licurl":"http://creativecommons.org/licenses/by-sa/3.0/","habit":"草本","origin":null},{"id":358,"zh":"菜豆","en":"Phaseolus vulgaris","sci":"Phaseolus vulgaris","order_en":"Fabales","order_zh":"豆目","family_en":"Fabaceae","family_zh":"豆科","iucn":"LC","langs":117,"desc_zh":"菜豆（英语：common bean，学名：Phaseolus vulgaris）也叫云藊豆、芸豆（亦作芸豆）、架豆、刀豆、肾豆等，是一种一年生草本植物，因其干种子或绿色未成熟豆荚可食用，而在世界各地种植。菜豆的豆角称为四季豆或芸豆角。菜豆原产于美洲大陆，属豆科菜豆属植物，为北美洲三谷之一，后传入亚欧大陆并成为世界性的餐桌上常见蔬菜。","desc_en":"Phaseolus vulgaris, the common bean, is a herbaceous annual plant. Its botanical classification, along with other Phaseolus species, is as a member of the legume family, Fabaceae. It forms a green-leaved vine which produces beans inside of pods.","img":"images/358.jpg","thumb":"images/t/358.jpg","file":"Snijboon peulen Phaseolus vulgaris.jpg","ar":0.75,"py":"caidou cd","cr_by":"Rasbak","cr_lic":"CC BY-SA 3.0","cr_licurl":"http://creativecommons.org/licenses/by-sa/3.0/","habit":"藤本","origin":null},{"id":359,"zh":"小扁豆","en":"Lens culinaris","sci":"Lens culinaris","order_en":"Fabales","order_zh":"豆目","family_en":"Fabaceae","family_zh":"豆科","iucn":null,"langs":107,"desc_zh":"小扁豆（学名：Lens culinaris，英语：lentil）又称兵豆，是豆科蝶形花亚科小扁豆属（兵豆属）一年生或越年生草本植物，果实为荚果，种子呈扁平状，可作食用，故名。每株约40厘米（16英寸）高。 小扁豆有许多其他中文名，如：滨豆、小金扁豆、「鸡豆」、鸡豌豆、「鸡眼豆」。","desc_en":"The lentil (Vicia lens or Lens culinaris) is an annual legume grown for its lens-shaped edible seeds or pulses, also called lentils. It is about 40 cm (16 in) tall, and the seeds grow in pods, usually with two seeds in each.","img":"images/359.jpg","thumb":"images/t/359.jpg","file":"Lens culinaris Sturm8.jpg","ar":0.689,"py":"xiaobiandou xbd","cr_by":"Johann Georg Sturm (Painter: Jacob Sturm )","cr_lic":"Public domain","cr_licurl":null,"habit":"草本","origin":null},{"id":360,"zh":"光果甘草","en":"liquorice","sci":"Glycyrrhiza glabra","order_en":"Fabales","order_zh":"豆目","family_en":"Fabaceae","family_zh":"豆科","iucn":"LC","langs":106,"desc_zh":"光果甘草（学名：Glycyrrhiza glabra，英语：Liquorice），又名洋甘草，多年生豆科甘草属植物，原产于西亚和南欧，散见于全欧与地中海周边。尽管风味类似，但与茴芹，八角或茴香无植物学上的联系。被用作糖果和烟草的调味剂，尤见于部份欧洲和西亚国家。","desc_en":"Liquorice (Commonwealth English) or licorice (American English; see spelling differences; IPA: LIK-ər-ish, -⁠iss) is the common name of Glycyrrhiza glabra, a flowering plant of the bean family Fabaceae, from the root of which a sweet, aromatic flavouring is ex…","img":"images/360.jpg","thumb":"images/t/360.jpg","file":"Illustration Glycyrrhiza glabra0.jpg","ar":0.621,"py":"guangguogancao gggc","cr_by":null,"cr_lic":"Public domain","cr_licurl":null,"habit":"草本","origin":["亚洲","欧洲","非洲"]},{"id":361,"zh":"蚕豆","en":"Broad Bean","sci":"Vicia faba","order_en":"Fabales","order_zh":"豆目","family_en":"Fabaceae","family_zh":"豆科","iucn":null,"langs":105,"desc_zh":"蚕豆（学名：Vicia faba）是一年生或越年生豆科草本植物，又名胡豆、佛豆、川豆、倭豆、罗汉豆、豌豆（湖北湖南部分地区称谓），原产亚洲西南部和非洲北部。相传西汉张骞出使西域时期传入中国，8世纪左右从中国传入日本。据说为菩提僊那渡日后交给行基种植于兵库县的武库村。","desc_en":"Vicia faba, commonly known as the broad bean, fava bean, or faba bean, is a species of vetch, a flowering plant in the pea and bean family Fabaceae. It is widely cultivated as a crop for human consumption, and also as a cover crop.","img":"images/361.jpg","thumb":"images/t/361.jpg","file":"Illustration Vicia faba1.jpg","ar":0.627,"py":"candou cd","cr_by":null,"cr_lic":"Public domain","cr_licurl":null,"habit":null,"origin":null},{"id":362,"zh":"胡芦巴","en":"Trigonella foenum-graecum","sci":"Trigonella foenum-graecum","order_en":"Fabales","order_zh":"豆目","family_en":"Fabaceae","family_zh":"豆科","iucn":null,"langs":93,"desc_zh":"胡芦巴（学名：Trigonella foenum-graecum），又称云香草、香草、苦草、苦豆、苦朵菜、香苜蓿或香豆子等，为一年生豆科蝶形花亚科胡芦巴属的一种植物，其种子是调味料和中药；不仅是一种蔬菜，也是一种药材。 原产地中海地区，中国在四川、河南、甘肃、安徽等省也有栽培。 胡芦巴为一年生草本植物，株高35至85厘米，全株有香气。茎直立多丛生。三出羽状复叶互生，小叶长卵形或卵状披针形。","desc_en":"Fenugreek (; Trigonella foenum-graecum) is an annual plant in the family Fabaceae, with leaves consisting of three small obovate to oblong leaflets. It is cultivated worldwide as a semiarid crop.","img":"images/362.jpg","thumb":"images/t/362.jpg","file":"Junger Bockshornklee.jpg","ar":0.853,"py":"huluba hlb","cr_by":"Yak","cr_lic":"CC BY-SA 3.0","cr_licurl":"https://creativecommons.org/licenses/by-sa/3.0","habit":"草本","origin":["亚洲"]},{"id":363,"zh":"紫花苜蓿","en":"Medicago sativa","sci":"Medicago sativa","order_en":"Fabales","order_zh":"豆目","family_en":"Fabaceae","family_zh":"豆科","iucn":"LC","langs":93,"desc_zh":"紫花苜蓿（学名：Medicago sativa， 阿拉伯语：البرسيم الحجازي），又叫做紫苜蓿、牧蓿、苜蓿、路蒸，属豆科植物。","desc_en":"Medicago sativa, commonly known as alfalfa () in North America and lucerne () in the United Kingdom, South Africa, Australia, and New Zealand, is a perennial flowering plant in the legume family, Fabaceae.","img":"images/363.jpg","thumb":"images/t/363.jpg","file":"75 Medicago sativa L.jpg","ar":0.676,"py":"zihuamuxu zhmx","cr_by":"Amédée Masclef","cr_lic":"Public domain","cr_licurl":null,"habit":"草本","origin":null},{"id":364,"zh":"含羞草","en":"Mimosa pudica","sci":"Mimosa pudica","order_en":"Fabales","order_zh":"豆目","family_en":"Fabaceae","family_zh":"豆科","iucn":"LC","langs":88,"desc_zh":"含羞草（学名：Mimosa pudica），由于其独特的生理习性有着众多的别名昵称，如喝呼草、知羞草、怕丑草等。含羞草原产于美洲热带的巴西，是豆科含羞草属的一种多年生草本植物。由于这种植物生长力顽强，所以在不少国家，含羞草都被当成是一种野草 。花语：敏锐，细腻的感触，纤细的感情。花色有粉红和紫红。花期为6月至9月。","desc_en":"Mimosa pudica (also called sensitive plant, sleepy grass, sleepy plant, action plant, humble plant, touch-me-not, touch-and-die, shame plant or shy plant) is a creeping annual or perennial flowering plant of the pea/legume family Fabaceae.","img":"images/364.jpg","thumb":"images/t/364.jpg","file":"Mimosa-pudica-SF25124.jpg","ar":1.333,"py":"hanxiucao hxc","cr_by":"Steve Fitzgerald","cr_lic":"CC BY-SA 4.0","cr_licurl":"https://creativecommons.org/licenses/by-sa/4.0","habit":"禾草","origin":["亚洲","非洲","北美洲","大洋洲"]},{"id":365,"zh":"绿豆","en":"Vigna radiata","sci":"Vigna radiata","order_en":"Fabales","order_zh":"豆目","family_en":"Fabaceae","family_zh":"豆科","iucn":"LC","langs":86,"desc_zh":"绿豆（学名：Vigna radiata (L.) R. Wilczek）是一种豆科、蝶形花亚科豇豆属植物。别名“青小豆”、“植豆”、“交豆”、“文豆”、“八重生”、“菉豆”。","desc_en":"The mung bean or green gram (Vigna radiata) is a plant species in the legume family. It is mainly cultivated in East, Southeast, and in South Asia and used as an ingredient in both savoury and sweet dishes.","img":"images/365.jpg","thumb":"images/t/365.jpg","file":"Mung beans (Vigna radiata).jpg","ar":1.501,"py":"ldou ld","cr_by":"Ivar Leidus","cr_lic":"CC BY-SA 4.0","cr_licurl":"https://creativecommons.org/licenses/by-sa/4.0","habit":null,"origin":["亚洲"]},{"id":366,"zh":"长角豆","en":"Ceratonia siliqua","sci":"Ceratonia siliqua","order_en":"Fabales","order_zh":"豆目","family_en":"Fabaceae","family_zh":"豆科","iucn":"LC","langs":81,"desc_zh":"长角豆（学名：Ceratonia siliqua）是豆科长角豆属的植物，原产于地中海东部。目前已由人工引种栽培。由于这种子的重量一致（重量多在200毫克左右），所以早期钻石的重量用这种植物的种子称量。直至1907年国际商定为宝石计量单位「克拉」开始沿用至今。","desc_en":"The carob ( KARR-əb; Ceratonia siliqua) is a flowering evergreen tree or shrub in the Caesalpinioideae subfamily of the legume family, Fabaceae. The carob tree is native to the Mediterranean region and the Middle East.","img":"images/366.jpg","thumb":"images/t/366.jpg","file":"Algarrobo múltiple.jpg","ar":1.333,"py":"changjiaodou cjd","cr_by":"Eduardo Milla","cr_lic":"CC BY-SA 4.0","cr_licurl":"https://creativecommons.org/licenses/by-sa/4.0","habit":"乔木","origin":["亚洲","欧洲"]},{"id":367,"zh":"木豆","en":"Cajanus cajan","sci":"Cajanus cajan","order_en":"Fabales","order_zh":"豆目","family_en":"Fabaceae","family_zh":"豆科","iucn":null,"langs":76,"desc_zh":"木豆（学名：Cajanus cajan），又名蒲姜豆、木豆、米豆、树荳、柳豆、白树豆、花螺树豆、观音豆、番仔豆、山豆根，为豆科木豆属下的一个种，台湾一般称为树豆，阿美语称 fata'an，泰雅语称 singut，大武垅语称 taluvawvaw,布农语称“qalidang”，可采集食用，又也可作榨油用。最多生长于印度东部和埃及，在台湾也很常见为人所栽培，为许多台湾原住民族的重要粮食之一，阿美族人将这种树豆视为吉祥物。","desc_en":"The pigeon pea (Cajanus cajan) is a perennial legume from the family Fabaceae native to the Eastern Hemisphere. The pigeon pea is widely cultivated in tropical and semitropical regions around the world, being commonly consumed in the Indian Subcontinent, South…","img":"images/367.jpg","thumb":"images/t/367.jpg","file":"Guandu.jpg","ar":0.541,"py":"mudou md","cr_by":"Lígia Prado","cr_lic":"Public domain","cr_licurl":null,"habit":"草本","origin":null},{"id":368,"zh":"刺槐","en":"Robinia pseudoacacia","sci":"Robinia pseudoacacia","order_en":"Fabales","order_zh":"豆目","family_en":"Fabaceae","family_zh":"豆科","iucn":"LC","langs":73,"desc_zh":"刺槐又名洋槐，是原生于北美洲的一个树种，但现在被广泛引种到亚洲、欧洲等地。汉语名称取自其与同属蝶形花亚科的槐属的相似度（刺槐族仅在美洲存在分布）；拉丁学名中的种名“pseudoacacia”是假金合欢或假相思树之意，尽管两属同属苏木亚科与洋槐关系甚远。","desc_en":"Robinia pseudoacacia, commonly known as black locust, is a medium-sized hardwood deciduous tree, belonging to the tribe Robinieae of the legume family. Another common name is false acacia, a literal translation of the specific name (pseudo [Greek ψευδο-] meani…","img":"images/368.jpg","thumb":"images/t/368.jpg","file":"Korina 2011-05-20 Robinia pseudoacacia 3.jpg","ar":0.75,"py":"cihuai ch","cr_by":"Annabell Hormann / korina.info","cr_lic":"CC BY-SA 4.0","cr_licurl":"https://creativecommons.org/licenses/by-sa/4.0","habit":"乔木","origin":["亚洲","欧洲","非洲","北美洲"]},{"id":369,"zh":"红菽草","en":"Trifolium pratense","sci":"Trifolium pratense","order_en":"Fabales","order_zh":"豆目","family_en":"Fabaceae","family_zh":"豆科","iucn":"LC","langs":66,"desc_zh":"红菽草（学名：Trifolium pratense），又名红车轴草、红花苜宿、红三叶草、红花三叶草，为豆科三叶草属下的一种多年生草本植物，高20—80 cm（8—31英寸），耐旱，可以作为牧草。它原产于地中海附近地区，每年5月到10月开粉红色花。在引入北美之后成为入侵物种。","desc_en":"Trifolium pratense (from Latin prātum, meaning meadow), red clover, is a herbaceous species of flowering plant in the bean family, Fabaceae. It is native to the Old World, but planted and naturalised in many other regions.","img":"images/369.jpg","thumb":"images/t/369.jpg","file":"Trifolium pratense - Keila2.jpg","ar":0.75,"py":"hongshucao hsc","cr_by":"Ivar Leidus","cr_lic":"CC BY-SA 4.0","cr_licurl":"https://creativecommons.org/licenses/by-sa/4.0","habit":"草本","origin":null},{"id":370,"zh":"鸡母珠","en":"Abrus precatorius","sci":"Abrus precatorius","order_en":"Fabales","order_zh":"豆目","family_en":"Fabaceae","family_zh":"豆科","iucn":null,"langs":65,"desc_zh":"鸡母珠（学名：Abrus precatorius），又名相思子、美人豆、亦被称作红豆，是豆科相思子属的一种有毒植物，泛热带分布。","desc_en":"Abrus precatorius, commonly known as jequirity bean or rosary pea, is a herbaceous flowering plant in the bean family Fabaceae. It is a slender, perennial climber with long, pinnate-leafleted leaves that twines around trees, shrubs, and hedges.","img":"images/370.jpg","thumb":"images/t/370.jpg","file":"Abrus precatorius (L.) Fabaceae (21617028808).jpg","ar":1.378,"py":"jimuzhu jmz","cr_by":"Len Worthington","cr_lic":"CC BY-SA 2.0","cr_licurl":"https://creativecommons.org/licenses/by-sa/2.0","habit":"藤本","origin":["亚洲","大洋洲"]},{"id":371,"zh":"白车轴草","en":"Trifolium repens","sci":"Trifolium repens","order_en":"Fabales","order_zh":"豆目","family_en":"Fabaceae","family_zh":"豆科","iucn":null,"langs":63,"desc_zh":"白三叶草（学名：Trifolium repens），又名白花三叶草、白三叶、菽草、白车轴草或白花苜蓿，是一种产自欧洲、北非及西亚的三叶草。它们广泛的引进世界各地，尤其是北美洲的草地甚为普遍，中国南北各地均有分布。","desc_en":"Trifolium repens, the white clover, is a herbaceous perennial plant in the bean family, Fabaceae (also known as Leguminosae). The species is native to Eurasia and is one of the most widely cultivated types of clover.","img":"images/371.jpg","thumb":"images/t/371.jpg","file":"Illustration Trifolium repens1.jpg","ar":0.623,"py":"baichezhoucao bczc","cr_by":null,"cr_lic":"Public domain","cr_licurl":null,"habit":"草本","origin":["亚洲"]},{"id":372,"zh":"凤凰木","en":"Delonix regia","sci":"Delonix regia","order_en":"Fabales","order_zh":"豆目","family_en":"Fabaceae","family_zh":"豆科","iucn":"LC","langs":60,"desc_zh":"凤凰木（学名：Delonix regia，英语：Poinciana）又名影树、凤凰树、凤凰花、金凤、火凤凰、洋楹、红花楹（广州）、火树、红火楹、火焰木、森之炎、攀霞拿等，为豆科凤凰木属的植物。在香港，凤凰木的花期约为五月至七月，而在台湾则在初夏左右开花。有趣的是，这种树开花的时间，通常也会在学校的毕业季节前后。 凤凰木的特征就是华丽的花朵，以及外观如蕨类植物般的绿叶。它主要生长在世界上许多热带或亚热带地区，作为装饰用树和遮蔽太阳的树木。","desc_en":"Delonix regia is a species of flowering plant in the bean family Fabaceae, subfamily Caesalpinioideae native to Madagascar. It is noted for its fern-like leaves and flamboyant display of orange-red flowers over summer.","img":"images/372.jpg","thumb":"images/t/372.jpg","file":"Royal Poinciana.jpg","ar":1.333,"py":"fenghuangmu fhm","cr_by":"Averette","cr_lic":"CC BY-SA 3.0","cr_licurl":"https://creativecommons.org/licenses/by-sa/3.0","habit":"乔木","origin":["非洲"]},{"id":373,"zh":"阿勒勃","en":"Cassia fistula","sci":"Cassia fistula","order_en":"Fabales","order_zh":"豆目","family_en":"Fabaceae","family_zh":"豆科","iucn":"LC","langs":59,"desc_zh":"阿勒勃（学名：Cassia fistula），讹作阿勃勒（台湾通称），又称波斯皂荚、婆罗门皂荚、腊肠树（中国大陆通称）、猪肠豆（香港通称）、南蛮皂荚（日本通称）、长果子树、牛角树、雨兰松、黄金雨、金急雨（英语：golden shower），是一种豆科苏木亚科的植物。原产于南亚南部，从巴基斯坦南部往东直到印度及缅甸，往南直到斯里兰卡。阿勒勃常被误称为金链花，但金链花其实是毒豆，一种原产欧洲的有毒植物。","desc_en":"Cassia fistula, also known as golden shower, purging cassia, Indian laburnum, kani konna, or pudding-pipe tree, is a flowering plant in the family Fabaceae. The species is native to the Indian subcontinent and adjacent regions of Southeast Asia.","img":"images/373.jpg","thumb":"images/t/373.jpg","file":"Cassia fistula (1).JPG","ar":1.501,"py":"alebo alb","cr_by":"Delonix","cr_lic":"CC BY-SA 3.0","cr_licurl":"https://creativecommons.org/licenses/by-sa/3.0","habit":"乔木","origin":["亚洲"]},{"id":374,"zh":"蝶豆","en":"Clitoria ternatea","sci":"Clitoria ternatea","order_en":"Fabales","order_zh":"豆目","family_en":"Fabaceae","family_zh":"豆科","iucn":null,"langs":59,"desc_zh":"蝶豆（学名：Clitoria ternatea），是豆科蝶豆属的植物。由于蝶豆的花外观类似人类女性外生殖器，因此它的拉丁语属名被命名为「Clitoria」（蝶豆属），词源为「阴蒂」（Clitoris）。 根及种子有毒，可造成恶心、呕吐、腹泻。","desc_en":"Clitoria ternatea, commonly known as Shankhupushpam (conch-shaped flower), Asian pigeonwings, bluebellvine, blue pea, butterfly pea, cordofan pea, or Darwin pea, is a plant species belonging to the family Fabaceae and native to the Indonesian island of Ternate…","img":"images/374.jpg","thumb":"images/t/374.jpg","file":"Clitoria ternatea - Asian pigeonwings in Bhopal, India September 2025.jpg","ar":0.562,"py":"diedou dd","cr_by":"Suyash.dwivedi","cr_lic":"CC BY-SA 4.0","cr_licurl":"https://creativecommons.org/licenses/by-sa/4.0","habit":null,"origin":["亚洲"]},{"id":375,"zh":"豇豆","en":"Vigna unguiculata","sci":"Vigna unguiculata","order_en":"Fabales","order_zh":"豆目","family_en":"Fabaceae","family_zh":"豆科","iucn":null,"langs":59,"desc_zh":"豇（jiāng）豆（学名：Vigna unguiculata）是一种豆科豇豆属的植物。豆荚稍肉质且柔软，外观呈长条状圆柱形，长度大约30—50公分，直径约0.6—1.0公分；内有种子多颗，种子长椭圆形或圆柱形或稍肾形，长 0.6—1.2 公分，黄白色、暗红色或其他颜色。 豇豆是最重要的食品豆科作物之一，涵盖亚洲、非洲、欧洲南部、中美洲和南美洲等半干旱热带地区。","desc_en":"The cowpea (Vigna unguiculata) is an annual herbaceous legume from the genus Vigna. It can be erect, semierect (trailing), or climbing. A high level of morphological diversity is found within the species with large variations in the size, shape, and structure…","img":"images/375.jpg","thumb":"images/t/375.jpg","file":"BlackeyeBean.jpg","ar":1.331,"py":"jiangdou jd","cr_by":null,"cr_lic":"Public domain","cr_licurl":null,"habit":"藤本","origin":["非洲"]},{"id":376,"zh":"黄花草木樨","en":"Melilotus officinalis","sci":"Melilotus officinalis","order_en":"Fabales","order_zh":"豆目","family_en":"Fabaceae","family_zh":"豆科","iucn":null,"langs":57,"desc_zh":"黄香草木樨（学名：Melilotus officinalis）是豆科草木樨属植物，原产欧亚大陆中西部，在温带地区广泛栽培、归化。《中国植物志》把草木樨（学名：Melilotus suaveolens）和黄香草木樨并为一种，但分子生物学研究并不支持这一处理。","desc_en":"Melilotus officinalis, known as sweet yellow clover, yellow melilot, ribbed melilot and common melilot, is a species of legume native to Eurasia and introduced in North America, Africa, and Australia.","img":"images/376.jpg","thumb":"images/t/376.jpg","file":"20140613Melilotus officinalis.jpg","ar":1.333,"py":"huanghuacaomuxi hhcmx","cr_by":"AnRo0002","cr_lic":"CC0","cr_licurl":"http://creativecommons.org/publicdomain/zero/1.0/deed.en","habit":null,"origin":["亚洲","非洲","北美洲","大洋洲"]},{"id":377,"zh":"救荒野豌豆","en":"Vicia sativa","sci":"Vicia sativa","order_en":"Fabales","order_zh":"豆目","family_en":"Fabaceae","family_zh":"豆科","iucn":"LC","langs":55,"desc_zh":"救荒野豌豆（学名：Vicia sativa）是豆科野豌豆属的植物。广泛分布于南极洲之外的各个大陆，生长于海拔50米至3,000米的地区，多生长于田边草丛、荒山以及林中，目前已由人工引种栽培。","desc_en":"Vicia sativa, known as the common vetch, garden vetch, tare or simply vetch, is a nitrogen-fixing leguminous plant in the family Fabaceae. It is now naturalised throughout the world occurring on every continent, except Antarctica and the Arctic.","img":"images/377.jpg","thumb":"images/t/377.jpg","file":"(MHNT) Vicia sativa.jpg","ar":0.641,"py":"jiuhuangyewandou jhywd","cr_by":"Didier Descouens","cr_lic":"CC BY-SA 4.0","cr_licurl":"https://creativecommons.org/licenses/by-sa/4.0","habit":null,"origin":null},{"id":378,"zh":"南欧紫荆","en":"Cercis siliquastrum","sci":"Cercis siliquastrum","order_en":"Fabales","order_zh":"豆目","family_en":"Fabaceae","family_zh":"豆科","iucn":"LC","langs":55,"desc_zh":"南欧紫荆（学名：Cercis siliquastrum），属于苏木亚科紫荆属的一种落叶乔木，其高度不超过10米，原产于南欧和西亚，性喜钙质较干燥土壤。叶子较圆，尾部呈V形，绿色带微蓝，先开花后生叶，花为紫红色，非常美观，果实为豆荚。常被作为公园、院落观赏植物而栽种。 南欧紫荆又被称为“犹大树”，根据传说，出卖耶稣的犹大是在这种树上吊死的，这使树木因此感到羞耻，以至于白色的花全都变成了紫红色。","desc_en":"Cercis siliquastrum, commonly known as European Cercis, the Judas tree or Judas-tree, is a small deciduous species of redbud in the flowering plant family Fabaceae which is noted for its prolific display of deep pink flowers in spring.","img":"images/378.jpg","thumb":"images/t/378.jpg","file":"Cercis siliquastrum - Judas tree - Erguvan 01.jpg","ar":0.698,"py":"nanouzijing nozj","cr_by":"Zeynel Cebeci","cr_lic":"CC BY-SA 4.0","cr_licurl":"https://creativecommons.org/licenses/by-sa/4.0","habit":"乔木","origin":["亚洲","欧洲"]},{"id":379,"zh":"广布野豌豆","en":"Vicia cracca","sci":"Vicia cracca","order_en":"Fabales","order_zh":"豆目","family_en":"Fabaceae","family_zh":"豆科","iucn":null,"langs":54,"desc_zh":"多花野豌豆（学名：Vicia cracca）为豆科蚕豆属下的一个种。","desc_en":"Vicia cracca (tufted vetch, cow vetch, bird vetch, blue vetch, boreal vetch), is a species of flowering plant in the pea and bean family Fabaceae. It is native to Europe and Asia.","img":"images/379.jpg","thumb":"images/t/379.jpg","file":"Tufted vetch close 800.jpg","ar":0.628,"py":"guangbuyewandou gbywd","cr_by":"The original uploader was Sannse at English Wikipedia .","cr_lic":"CC BY-SA 3.0","cr_licurl":"http://creativecommons.org/licenses/by-sa/3.0/","habit":null,"origin":["亚洲","欧洲"]},{"id":380,"zh":"木蓝","en":"Indigofera tinctoria","sci":"Indigofera tinctoria","order_en":"Fabales","order_zh":"豆目","family_en":"Fabaceae","family_zh":"豆科","iucn":null,"langs":54,"desc_zh":"木蓝（学名：Indigofera tinctoria），亦作槐蓝、靛、蓝靛、马棘，豆科植物。","desc_en":"Indigofera tinctoria, also called true indigo, is a species of plant from the bean family that was one of the original sources of indigo dye.","img":"images/380.jpg","thumb":"images/t/380.jpg","file":"Indigofera tinctoria1.jpg","ar":1.333,"py":"mulan ml","cr_by":"Kurt Stüber [1]","cr_lic":"CC BY-SA 3.0","cr_licurl":"http://creativecommons.org/licenses/by-sa/3.0/","habit":null,"origin":null},{"id":381,"zh":"银合欢","en":"Leucaena leucocephala","sci":"Leucaena leucocephala","order_en":"Fabales","order_zh":"豆目","family_en":"Fabaceae","family_zh":"豆科","iucn":null,"langs":53,"desc_zh":"银合欢（学名：Leucaena leucocephala）别名白相思子、细叶番婆树、臭菁仔。为含羞草亚科银合欢属植物，原产墨西哥南部和中美洲北部，现扩散到世界各地热带和亚热带地区，名列世界百大外来入侵种。 银合欢由于树根会分泌出含羞草素抑制其他种植物生长，排他性极强又无天敌因而形成单一性的纯林地带，因此减低生物多样性。","desc_en":"Leucaena leucocephala is a small fast-growing mimosoid tree native to southern Mexico and northern Central America (Belize and Guatemala). It is now naturalized throughout the tropics including parts of Asia.","img":"images/381.jpg","thumb":"images/t/381.jpg","file":"Arya.lamtoro.tembara.tiga putra.pilang.2019.00.jpg","ar":1,"py":"yinhehuan yhh","cr_by":"Aris riyanto","cr_lic":"CC BY 3.0","cr_licurl":"https://creativecommons.org/licenses/by/3.0","habit":"乔木","origin":["北美洲"]},{"id":382,"zh":"金雀儿","en":"Cytisus scoparius","sci":"Cytisus scoparius","order_en":"Fabales","order_zh":"豆目","family_en":"Fabaceae","family_zh":"豆科","iucn":null,"langs":52,"desc_zh":"金雀花（学名：Cytisus scoparius；英语：common broom），又名金雀儿，为豆科金雀儿属下的一种多年生落叶灌木，原产于欧洲中部和西部。它是金雀花王朝的象征。作为一种的园艺植物，金雀花被引入了世界各地，但因为它适应性太强而在北美洲等地成为了入侵物种。","desc_en":"Cytisus scoparius (syn. Sarothamnus scoparius), the common broom or Scotch broom, is a deciduous leguminous shrub native to western and central Europe. In Great Britain and Ireland, the standard name is broom; this name is also used for other members of the Ge…","img":"images/382.jpg","thumb":"images/t/382.jpg","file":"Cytisus scoparius 001.jpg","ar":1.333,"py":"jinqueer jqe","cr_by":"Willow","cr_lic":"CC BY 2.5","cr_licurl":"https://creativecommons.org/licenses/by/2.5","habit":"灌木","origin":["欧洲"]},{"id":383,"zh":"大花田菁","en":"Sesbania grandiflora","sci":"Sesbania grandiflora","order_en":"Fabales","order_zh":"豆目","family_en":"Fabaceae","family_zh":"豆科","iucn":null,"langs":52,"desc_zh":"大花田菁（学名：Sesbania grandiflora）为豆科田菁属下的一个种。种名grandiflora意为“大花的”。","desc_en":"Sesbania grandiflora, common names vegetable hummingbird, katurai, agati, agastya, agasya, kathurumurunga and West Indian pea, is a leguminous tree of family Fabaceae native to Malesia, including Malaysia, New Guinea, and the Philippines.","img":"images/383.jpg","thumb":"images/t/383.jpg","file":"Starr 050518-1632 Sesbania grandiflora.jpg","ar":0.75,"py":"dahuatianjing dhtj","cr_by":"Forest & Kim Starr","cr_lic":"CC BY 3.0","cr_licurl":"https://creativecommons.org/licenses/by/3.0","habit":"乔木","origin":["亚洲","大洋洲"]},{"id":384,"zh":"鹰爪豆","en":"Spartium junceum","sci":"Spartium junceum","order_en":"Fabales","order_zh":"豆目","family_en":"Fabaceae","family_zh":"豆科","iucn":null,"langs":51,"desc_zh":"鹰爪豆属（学名：Spartium）是蝶形花科下的一个属，为灌木植物。该属仅有鹰爪豆（Spartium junceum）一种，原产于地中海地区。属名Spartium源于希腊语spartos，即“金雀豆”。","desc_en":"Spartium junceum, known as Spanish broom, rush broom, or weaver's broom, it is a species of flowering plant in the family Fabaceae and the sole species in the genus Spartium. It is closely related to the other brooms (in the genera Cytisus and Genista).","img":"images/384.jpg","thumb":"images/t/384.jpg","file":"Spartium junceum (habitus).jpg","ar":0.75,"py":"yingzhaodou yzd","cr_by":"Hans Hillewaert","cr_lic":"CC BY-SA 3.0","cr_licurl":"https://creativecommons.org/licenses/by-sa/3.0","habit":"禾草","origin":null},{"id":385,"zh":"香豌豆","en":"sweet pea","sci":"Lathyrus odoratus","order_en":"Fabales","order_zh":"豆目","family_en":"Fabaceae","family_zh":"豆科","iucn":"CR","langs":51,"desc_zh":"香豌豆（学名：Lathyrus odoratus）为豆科山黧豆属下的一个种。","desc_en":"The sweet pea, Lathyrus odoratus, is a flowering plant in the genus Lathyrus in the family Fabaceae (legumes), native to Sicily, southern Italy and the Aegean Islands.","img":"images/385.jpg","thumb":"images/t/385.jpg","file":"Lathyrus odoratus Cupanii1b.UME.jpg","ar":0.75,"py":"xiangwandou xwd","cr_by":"Epibase","cr_lic":"CC BY 2.5","cr_licurl":"https://creativecommons.org/licenses/by/2.5","habit":"藤本","origin":["欧洲"]},{"id":386,"zh":"博士茶","en":"Aspalathus linearis","sci":"Aspalathus linearis","order_en":"Fabales","order_zh":"豆目","family_en":"Fabaceae","family_zh":"豆科","iucn":null,"langs":51,"desc_zh":"博士茶（阿非利卡语：Rooibos，发音：[ˈroːi̯bɔs]，意为“红色灌木”；英语化发音：[ˈɹɔɪ.bɒs]；学名：Aspalathus linearis），又名路易波士茶、南非国宝茶，是一种生长在南非开普顿北部弗因博斯的豆科灌木植物，有「南非的红宝石」的美誉。它不含咖啡因，南非医学研究委员会发表的研究认为它有抑制基因突变、预防癌症的功效，因此被当作一种健康补充剂来出售。","desc_en":"Rooibos ( ROY-boss; Afrikaans: [ˈroːibɔs] , lit. 'red bush'), or Aspalathus linearis, is a broom-like member of the plant family Fabaceae that grows in South Africa's Fynbos biome.","img":"images/386.jpg","thumb":"images/t/386.jpg","file":"Rooibos (Aspalathus linearis)PICT2813.JPG","ar":1.333,"py":"boshicha bsc","cr_by":"Winfried Bruenken ( Amrum )","cr_lic":"CC BY-SA 2.5","cr_licurl":"https://creativecommons.org/licenses/by-sa/2.5","habit":"灌木","origin":["非洲"]},{"id":387,"zh":"黑小豆","en":"Vigna mungo","sci":"Vigna mungo","order_en":"Fabales","order_zh":"豆目","family_en":"Fabaceae","family_zh":"豆科","iucn":null,"langs":51,"desc_zh":"黑吉豆（ Vigna mungo ）是一种原产于南亚的豇豆属豆类。这种作物在印度南部以及孟加拉国和尼泊尔北部广泛种植。黑吉豆也是印度饮食的一部分，通常与咖喱和米饭一起食用。黑吉豆还通过印度移民引入加勒比地区、斐济、毛里求斯、缅甸和非洲等其他热带地区。","desc_en":"The black gram (Vigna mungo) is a bean grown in South Asia. Like its relative the mung bean, it has been reclassified from the genus Phaseolus to Vigna. The product sold as black gram is usually the whole bean, whereas the split bean (the interior being white)…","img":"images/387.jpg","thumb":"images/t/387.jpg","file":"Black gram.jpg","ar":1.407,"py":"heixiaodou hxd","cr_by":"Sanjay Acharya","cr_lic":"CC BY-SA 3.0","cr_licurl":"http://creativecommons.org/licenses/by-sa/3.0/","habit":null,"origin":["亚洲"]},{"id":388,"zh":"刺毛黧豆","en":"Mucuna pruriens","sci":"Mucuna pruriens","order_en":"Fabales","order_zh":"豆目","family_en":"Fabaceae","family_zh":"豆科","iucn":null,"langs":50,"desc_zh":"刺毛黧豆（学名：Mucuna pruriens）为豆科黎豆属下的一个种。直接接触表面的微细毛对人体的皮肤有很强的刺激性。","desc_en":"Mucuna pruriens is a tropical legume native to Africa and tropical Asia and widely naturalized and cultivated. Its English common names include monkey tamarind, velvet bean, Bengal velvet bean, Florida velvet bean, Mauritius velvet bean, Yokohama velvet bean,…","img":"images/388.jpg","thumb":"images/t/388.jpg","file":"Bengal Bean (6425610525).jpg","ar":1.333,"py":"cimaolidou cmld","cr_by":"Dinesh Valke from Thane, India","cr_lic":"CC BY-SA 2.0","cr_licurl":"https://creativecommons.org/licenses/by-sa/2.0","habit":null,"origin":["亚洲","非洲"]},{"id":389,"zh":"白花草木樨","en":"Melilotus albus","sci":"Melilotus albus","order_en":"Fabales","order_zh":"豆目","family_en":"Fabaceae","family_zh":"豆科","iucn":null,"langs":49,"desc_zh":"白花草木樨（学名：Melilotus albus）是一种豆科草木犀属植物。其种加词“albus”意为“白色的”。这种植物在中国河北、内蒙古、陕西、甘肃等省区都有野生种分布。在西北、东北、华北等地有悠久的栽培历史。产中国东北、华北、西北及西南各地。生于田边、路旁荒地及湿润的砂地。欧洲地中海沿岸、中东、西南亚、中亚及西伯利亚均有分布。","desc_en":"Melilotus albus, known as honey clover, white melilot (UK), Bokhara clover (Australia), white sweetclover (US), and sweet clover, is a nitrogen-fixing legume in the family Fabaceae.","img":"images/389.jpg","thumb":"images/t/389.jpg","file":"Melilotus alba bgiu.jpg","ar":0.718,"py":"baihuacaomuxi bhcmx","cr_by":"No machine-readable author provided. Bogdan assumed (based on copyright claims).","cr_lic":"CC BY-SA 3.0","cr_licurl":"http://creativecommons.org/licenses/by-sa/3.0/","habit":null,"origin":["北美洲"]},{"id":390,"zh":"百脉根","en":"Lotus corniculatus","sci":"Lotus corniculatus","order_en":"Fabales","order_zh":"豆目","family_en":"Fabaceae","family_zh":"豆科","iucn":null,"langs":49,"desc_zh":"百脉根（学名：Lotus corniculatus）是一种豆科植物。这种植物在中国南北等地均有栽培。在云南、贵州、四川、湖北、湖南、陕西、甘肃等地区均发现有野生种。","desc_en":"Lotus corniculatus is a flowering plant in the pea family Fabaceae. Common names include common bird's-foot trefoil, eggs and bacon, birdsfoot deervetch, and just bird's-foot trefoil (a name also often applied to other Lotus spp.).","img":"images/390.jpg","thumb":"images/t/390.jpg","file":"(MHNT) Lotus corniculatus - Plant habit.jpg","ar":1.81,"py":"baimaigen bmg","cr_by":"Didier Descouens","cr_lic":"CC BY-SA 4.0","cr_licurl":"https://creativecommons.org/licenses/by-sa/4.0","habit":null,"origin":null},{"id":391,"zh":"Polygala vulgaris","en":"Polygala vulgaris","sci":"Polygala vulgaris","order_en":"Fabales","order_zh":"豆目","family_en":"Polygalaceae","family_zh":"远志科","iucn":null,"langs":36,"desc_zh":null,"desc_en":"Polygala vulgaris, known as the common milkwort, is a herbaceous perennial plant of the genus Polygala in the family Polygalaceae. It grows in Northwen Europe, Western Russia, and Turkey, and has been introduced to parts of the U.S.","img":"images/391.jpg","thumb":"images/t/391.jpg","file":"Polygala vulgaris 290504.jpg","ar":0.845,"py":"","cr_by":null,"cr_lic":"CC BY-SA 3.0","cr_licurl":"http://creativecommons.org/licenses/by-sa/3.0/","habit":"草本","origin":["欧洲"]},{"id":392,"zh":"Polygala amarella","en":"Polygala amarella","sci":"Polygala amarella","order_en":"Fabales","order_zh":"豆目","family_en":"Polygalaceae","family_zh":"远志科","iucn":null,"langs":27,"desc_zh":null,"desc_en":"Polygala amarella (or P. amara), commonly known as dwarf milkwort or Kentish milkwort, is a plant of the family Polygalaceae. A European native, it grows on chalky grass land and limestone mountain pastures.","img":"images/392.jpg","thumb":"images/t/392.jpg","file":"Polygala amarella1a.jpg","ar":0.692,"py":"","cr_by":"Algirdas","cr_lic":"CC BY-SA 3.0","cr_licurl":"http://creativecommons.org/licenses/by-sa/3.0/","habit":"禾草","origin":["欧洲"]},{"id":393,"zh":"桃","en":"Prunus persica","sci":"Prunus persica","order_en":"Rosales","order_zh":"蔷薇目","family_en":"Rosaceae","family_zh":"蔷薇科","iucn":null,"langs":159,"desc_zh":"桃（学名：Prunus persica）是源自中国，蔷薇科李属的一种植物，花可以观赏，果实多汁，作为水果，可以生食或制桃脯、罐头等，核仁也可以食用。 桃品种众多，口感分脆桃和软桃，果肉有白色和黄色的，通常颜色略带粉红，一般在日本最受欢迎的品种多为白色果肉，香甜多汁；欧洲、澳洲和北美洲的人则在历史上较为喜欢黄色果肉而味道偏酸的品种。在原产国中国则百花齐放，由于南北方差异巨大，桃子种类丰富，脆桃、蜜桃、油桃等都深受人们喜爱。","desc_en":"The peach (Prunus persica) is a deciduous tree that bears edible juicy fruits with various characteristics. Most are simply called peaches, while the glossy-skinned, non-fuzzy varieties are called nectarines.","img":"images/393.jpg","thumb":"images/t/393.jpg","file":"Peaches at Applecrest Farm Orchards - 20108462909.jpg","ar":1.501,"py":"tao t","cr_by":"Allagash Brewing","cr_lic":"CC BY 2.0","cr_licurl":"https://creativecommons.org/licenses/by/2.0","habit":"乔木","origin":null},{"id":394,"zh":"草莓","en":"strawberry","sci":"Fragaria × ananassa","order_en":"Rosales","order_zh":"蔷薇目","family_en":"Rosaceae","family_zh":"蔷薇科","iucn":null,"langs":135,"desc_zh":"草莓（学名：Fragaria × ananassa；英语：strawberry），中国大陆和台湾称草莓，在香港常叫为士多啤梨，为草莓属中最常见的杂交栽培种，有时为与其它草莓属物种相区分也称花园草莓。草莓是多年生草本植物，植株寿命一般为3年左右。 人们所食用的“果实”部份实为假果，植物学定义上真正的果实是布满草莓表面的众多小点状物，果实类型为瘦果。不同于大多数水果由子房发育而成，草莓的食用部份是由花托在授粉后发育变大而成。","desc_en":"The garden strawberry (or simply strawberry; Fragaria × ananassa) is a widely grown hybrid plant cultivated worldwide for its fruit. The genus Fragaria, the strawberries, is in the rose family, Rosaceae.","img":"images/394.jpg","thumb":"images/t/394.jpg","file":"Strawberries.JPG","ar":1.333,"py":"caomei cm","cr_by":null,"cr_lic":"CC BY-SA 2.0","cr_licurl":"https://creativecommons.org/licenses/by-sa/2.0","habit":null,"origin":null},{"id":395,"zh":"扁桃","en":"Prunus amygdalus","sci":"Prunus amygdalus","order_en":"Rosales","order_zh":"蔷薇目","family_en":"Rosaceae","family_zh":"蔷薇科","iucn":null,"langs":134,"desc_zh":"扁桃（学名：Prunus amygdalus，英语：almond）是蔷薇科李属的一个种，原产于波斯，唐朝的《酉阳杂俎》和《岭表录异》对“偏桃木”有所记载。其果核内的种子是常见的零嘴，香港、台湾、星马等中国大陆以外的中文地区所一般称的「杏仁」其实是扁桃仁。扁桃分为甜味扁桃(英文:Sweet Almond)和苦味扁桃(英文:Bitter Almond)两种，其中甜扁桃可以食用，也就是一般食用的扁桃，苦扁桃则毒性过高无法食用。","desc_en":"The almond (Prunus amygdalus, syn. Prunus dulcis (Mill.) D.A.Webb, nom. illeg. non Prunus dulcis Rouchy) is a species of tree from the genus Prunus. Along with the peach, it is classified in the subgenus Amygdalus, distinguished from the other subgenera by cor…","img":"images/395.jpg","thumb":"images/t/395.jpg","file":"Almonds - in shell, shell cracked open, shelled, blanched.jpg","ar":1.501,"py":"biantao bt","cr_by":"Ivar Leidus","cr_lic":"CC BY-SA 4.0","cr_licurl":"https://creativecommons.org/licenses/by-sa/4.0","habit":"乔木","origin":["亚洲","欧洲"]},{"id":396,"zh":"杏","en":"Prunus armeniaca","sci":"Prunus armeniaca","order_en":"Rosales","order_zh":"蔷薇目","family_en":"Rosaceae","family_zh":"蔷薇科","iucn":"DD","langs":129,"desc_zh":"普通杏（学名：Prunus armeniaca）或杏，是李属李亚属植物，为最常见的栽培杏种；其果实又称杏子、杏实、杏桃，其果肉、果仁均可食用。","desc_en":"Prunus armeniaca is the most commonly cultivated apricot species. The native range is somewhat uncertain due to its extensive prehistoric cultivation. Genetic studies indicate Central Asia is the center of origin.","img":"images/396.jpg","thumb":"images/t/396.jpg","file":"Apricots.jpg","ar":1.325,"py":"xing x","cr_by":"Fir0002","cr_lic":"CC BY-SA 3.0","cr_licurl":"http://creativecommons.org/licenses/by-sa/3.0/","habit":null,"origin":["亚洲"]},{"id":397,"zh":"榅桲","en":"Cydonia oblonga","sci":"Cydonia oblonga","order_en":"Rosales","order_zh":"蔷薇目","family_en":"Rosaceae","family_zh":"蔷薇科","iucn":"LC","langs":115,"desc_zh":"榅桲（拉丁学名：Cydonia oblonga），又名木梨，是榅桲属中唯一物种。 落叶小乔木或灌木，一般为5～8米高；卵形或长椭圆形叶子，背面密生白色软毛，单叶互生，叶长60～110公厘；晚春或初夏开花，花白色或粉红色，有5瓣，直径约50公厘，花梗和花萼也有毛；果实秋季成熟，梨形或苹果形，未成熟时青色，有白毛，成熟后金黄色，直径有70～110公厘，味甘酸。 原生于中亚和高加索山区；现被引种到世界各地，成为重要的水果品种。","desc_en":"The quince (; Cydonia oblonga) is the sole member of the genus Cydonia in the Malinae subtribe (which contains apples, pears, and other fruits) of the Rosaceae family.","img":"images/397.jpg","thumb":"images/t/397.jpg","file":"Cydonia.jpg","ar":1.333,"py":"wenbo wb","cr_by":null,"cr_lic":"CC BY-SA 3.0","cr_licurl":"http://creativecommons.org/licenses/by-sa/3.0/","habit":"乔木","origin":null},{"id":398,"zh":"甜樱桃","en":"Prunus avium","sci":"Prunus avium","order_en":"Rosales","order_zh":"蔷薇目","family_en":"Rosaceae","family_zh":"蔷薇科","iucn":"LC","langs":103,"desc_zh":"欧洲甜樱桃（学名：Prunus avium）又名甜樱桃、大樱桃、甜车厘子、车厘子，为蔷薇科李属的植物，是最主要的鲜食樱桃物种。原生于欧洲、非洲西北部和亚洲西部，分布从不列颠群岛南至摩洛哥和突尼西亚，东至瑞典南部、波兰、乌克兰、高加索、伊朗和阿富汗。","desc_en":"Prunus avium, commonly called wild cherry, sweet cherry or gean, is a species of cherry, a flowering plant in the rose family, Rosaceae. It is native to western Eurasia and naturalized elsewhere. It is an ancestor of P. cerasus (sour cherry).","img":"images/398.jpg","thumb":"images/t/398.jpg","file":"Prunus avium fruit.jpg","ar":0.995,"py":"tianyingtao tyt","cr_by":"MPF","cr_lic":"CC BY 2.5","cr_licurl":"https://creativecommons.org/licenses/by/2.5","habit":"乔木","origin":["亚洲"]},{"id":399,"zh":"绒毛悬钩子","en":"Rubus idaeus","sci":"Rubus idaeus","order_en":"Rosales","order_zh":"蔷薇目","family_en":"Rosaceae","family_zh":"蔷薇科","iucn":null,"langs":97,"desc_zh":"覆盆子（学名：Rubus idaeus）是蔷薇科悬钩子属的木本植物，其果实味道酸甜，植株的枝干上长有倒钩刺。","desc_en":"Rubus idaeus (raspberry, also called red raspberry or occasionally European red raspberry to distinguish it from other raspberry species) is a red-fruited species of Rubus native to Eurasia and commonly cultivated in other temperate regions.","img":"images/399.jpg","thumb":"images/t/399.jpg","file":"Raspberry - whole (Rubus idaeus).jpg","ar":1.502,"py":"rongmaoxuangouzi rmxgz","cr_by":"Ivar Leidus","cr_lic":"CC BY-SA 4.0","cr_licurl":"https://creativecommons.org/licenses/by-sa/4.0","habit":null,"origin":["亚洲"]},{"id":400,"zh":"欧洲李","en":"Prunus domestica","sci":"Prunus domestica","order_en":"Rosales","order_zh":"蔷薇目","family_en":"Rosaceae","family_zh":"蔷薇科","iucn":"DD","langs":95,"desc_zh":"欧洲李（学名：Prunus domestica）是蔷薇科李属的一个栽培种。欧洲李与樱桃李亲缘关系较近，可能从樱桃李驯化而来，也可能源于樱桃李和黑刺李的杂交。","desc_en":"Prunus domestica is a species of flowering plant in the family Rosaceae. A deciduous tree, it includes many varieties of the fruit trees known as plums in English, though not all plums belong to this species.","img":"images/400.jpg","thumb":"images/t/400.jpg","file":"Fruits Prunus domestica.jpg","ar":1.333,"py":"ouzhouli ozl","cr_by":"YAMAMAYA","cr_lic":"CC BY-SA 3.0","cr_licurl":"https://creativecommons.org/licenses/by-sa/3.0","habit":"乔木","origin":null},{"id":401,"zh":"黑刺李","en":"Prunus spinosa","sci":"Prunus spinosa","order_en":"Rosales","order_zh":"蔷薇目","family_en":"Rosaceae","family_zh":"蔷薇科","iucn":"LC","langs":91,"desc_zh":"黑刺李（学名：Prunus spinosa），别名刺李，为蔷薇科李属的植物。分布于西亚、欧洲、北非以及中国陕西等地，生长于海拔800米至1,200米的地区，常生于林中旷地、森林草原地带、林缘以及河谷旁。","desc_en":"Prunus spinosa, called blackthorn or sloe, is a species of flowering plant in the rose family, Rosaceae. It is native to Europe and West Asia, and has been naturalised in parts of North America.","img":"images/401.jpg","thumb":"images/t/401.jpg","file":"Closeup of blackthorn aka sloe aka prunus spinosa sweden 20050924.jpg","ar":1.333,"py":"heicili hcl","cr_by":null,"cr_lic":"CC BY-SA 3.0","cr_licurl":"http://creativecommons.org/licenses/by-sa/3.0/","habit":null,"origin":["亚洲","欧洲","北美洲"]},{"id":402,"zh":"欧洲酸樱桃","en":"Prunus cerasus","sci":"Prunus cerasus","order_en":"Rosales","order_zh":"蔷薇目","family_en":"Rosaceae","family_zh":"蔷薇科","iucn":null,"langs":89,"desc_zh":"欧洲酸樱桃（学名：Prunus cerasus）又名酸樱桃、酸车厘子，是蔷薇科李属的植物。分布在欧洲、西亚以及中国大陆的新疆等地。可用来酿酒。","desc_en":"Prunus cerasus (sour cherry, tart cherry, or dwarf cherry) is an Old World species of Prunus in the subgenus Cerasus (cherries). It has two main groups of cultivars: the dark-red Morello cherry and the lighter-red Amarelle cherry. The sour pulp is edible.","img":"images/402.jpg","thumb":"images/t/402.jpg","file":"Prunus cerasus - Köhler–s Medizinal-Pflanzen-113.jpg","ar":0.779,"py":"ouzhousuanyingtao ozsyt","cr_by":"Franz Eugen Köhler, Köhler's Medizinal-Pflanzen","cr_lic":"Public domain","cr_licurl":null,"habit":null,"origin":null},{"id":403,"zh":"犬蔷薇","en":"Rosa canina","sci":"Rosa canina","order_en":"Rosales","order_zh":"蔷薇目","family_en":"Rosaceae","family_zh":"蔷薇科","iucn":null,"langs":86,"desc_zh":"犬蔷薇（学名：Rosa canina；英语：dog rose）是蔷薇科蔷薇属落叶灌木，也叫狗蔷薇、狗牙蔷薇，原产于欧洲、非洲西北部以及亚洲西部，是罗马尼亚的国花，也是英格兰汉普郡的郡花。","desc_en":"Rosa canina, the dog rose, is a variable climbing, wild rose species native to Europe, northwest Africa, and western Asia.","img":"images/403.jpg","thumb":"images/t/403.jpg","file":"Divlja ruza cvijet 270508.jpg","ar":0.75,"py":"quanqiangwei qqw","cr_by":"Roberta F.","cr_lic":"CC BY-SA 3.0","cr_licurl":"https://creativecommons.org/licenses/by-sa/3.0","habit":"藤本","origin":["亚洲","欧洲","非洲"]},{"id":404,"zh":"枇杷","en":"Eriobotrya japonica","sci":"Eriobotrya japonica","order_en":"Rosales","order_zh":"蔷薇目","family_en":"Rosaceae","family_zh":"蔷薇科","iucn":null,"langs":86,"desc_zh":"枇杷（学名：Eriobotrya japonica），古名卢橘，又名金丸、芦枝、小芒果、琵琶果，是蔷薇科中的枇杷属的一种植物。枇杷原产中国东南部，因果子形状似乐器琵琶而名。","desc_en":"The loquat (Eriobotrya japonica, Chinese: 枇杷; Pinyin: pípá) is a large evergreen shrub or tree grown commercially for its orange coloured fruits. It is also cultivated as an ornamental plant.","img":"images/404.jpg","thumb":"images/t/404.jpg","file":"Portugal - Algarve - Barao de Sao Joao - Ann scrumping loquats (25187478424).jpg","ar":0.75,"py":"pipa pp","cr_by":"muffinn from Worcester, UK","cr_lic":"CC BY 2.0","cr_licurl":"https://creativecommons.org/licenses/by/2.0","habit":"乔木","origin":["亚洲"]},{"id":405,"zh":"欧洲花楸","en":"Sorbus aucuparia","sci":"Sorbus aucuparia","order_en":"Rosales","order_zh":"蔷薇目","family_en":"Rosaceae","family_zh":"蔷薇科","iucn":"LC","langs":79,"desc_zh":"北欧花楸（学名：Sorbus aucuparia），也叫欧洲花楸，是蔷薇科花楸属的一种植物。广泛分布于欧亚大陆及非洲北部部分地区。其果实可以食用，叶子可以入药。山梨糖醇和山梨酸最早是从其中提取出来的。","desc_en":"Sorbus aucuparia, commonly called rowan (, also UK: ) and mountain-ash, is a species of deciduous tree or shrub in the rose family. The tree has a slender trunk with smooth bark, a loose and roundish crown, and its leaves are pinnate in pairs of leaflets on a…","img":"images/405.jpg","thumb":"images/t/405.jpg","file":"Rowan berries.JPG","ar":1.501,"py":"ouzhouhuaqiu ozhq","cr_by":"Thomas Bjørkan","cr_lic":"CC BY-SA 3.0","cr_licurl":"https://creativecommons.org/licenses/by-sa/3.0","habit":"乔木","origin":["亚洲","欧洲","非洲"]},{"id":406,"zh":"稠李","en":"Prunus padus","sci":"Prunus padus","order_en":"Rosales","order_zh":"蔷薇目","family_en":"Rosaceae","family_zh":"蔷薇科","iucn":"LC","langs":79,"desc_zh":"稠李（学名：Prunus padus），又名臭耳子（甘肃）、臭李子（东北），是蔷薇科李属的植物，原生于欧洲至东亚一带。","desc_en":"Prunus padus, known as bird cherry, hackberry (unrelated to the genus Celtis), hagberry, or Mayday tree, is a flowering plant in the rose family. It is a deciduous small tree or large shrub up to 16 metres (52 ft) tall, the type species of the subgenus Padus,…","img":"images/406.jpg","thumb":"images/t/406.jpg","file":"Bird cherry tree 1.jpg","ar":1.333,"py":"chouli cl","cr_by":"Игоревич","cr_lic":"Public domain","cr_licurl":null,"habit":"乔木","origin":["亚洲","欧洲","北美洲"]},{"id":407,"zh":"西洋梨","en":"Pyrus communis","sci":"Pyrus communis","order_en":"Rosales","order_zh":"蔷薇目","family_en":"Rosaceae","family_zh":"蔷薇科","iucn":"LC","langs":78,"desc_zh":"西洋梨（学名：Pyrus communis），又称秋洋梨、洋梨、阳梨、巴梨、大头梨、香蕉梨、茄梨、葫芦梨，香港俗称啤梨，梨属植物。果实经过后熟，柔软多汁，具有香气，风味甚佳。","desc_en":"Pyrus communis, the common pear, is a species of pear native to central and eastern Europe, and western Asia. It is one of the most important fruits of temperate regions, being the species from which most orchard pear cultivars grown in Europe, North America,…","img":"images/407.jpg","thumb":"images/t/407.jpg","file":"Pears.jpg","ar":0.656,"py":"xiyangli xyl","cr_by":"Keith Weller","cr_lic":"Public domain","cr_licurl":null,"habit":null,"origin":["亚洲","欧洲"]},{"id":408,"zh":"野草莓","en":"Fragaria vesca","sci":"Fragaria vesca","order_en":"Rosales","order_zh":"蔷薇目","family_en":"Rosaceae","family_zh":"蔷薇科","iucn":null,"langs":75,"desc_zh":"野草莓（学名：Fragaria vesca），又名森林草莓，是一种广泛分布于北半球的多年生草本植物。常在退化森林或曾受干扰的地区内茁壮生长。在夏威夷、留尼旺及纽西兰等地被视为入侵物种，形成相当高密度的匍匐林区。","desc_en":"Fragaria vesca, commonly called the woodland strawberry, Alpine strawberry, wild strawberry, Carpathian strawberry or European strawberry, is a perennial herbaceous plant in the rose family that grows naturally throughout much of the Northern Hemisphere, and t…","img":"images/408.jpg","thumb":"images/t/408.jpg","file":"Fragaria vesca LC0389.jpg","ar":0.75,"py":"yecaomei ycm","cr_by":"Jörg Hempel","cr_lic":"CC BY-SA 3.0 de","cr_licurl":"https://creativecommons.org/licenses/by-sa/3.0/de/deed.en","habit":"草本","origin":["欧洲"]},{"id":409,"zh":"欧楂","en":"Mespilus germanica","sci":"Mespilus germanica","order_en":"Rosales","order_zh":"蔷薇目","family_en":"Rosaceae","family_zh":"蔷薇科","iucn":"LC","langs":74,"desc_zh":"欧楂（学名：Mespilus germanica）是原产于亚洲西南部和在欧洲东南部的落叶植物，1930年代引种到中国青岛，常被栽培作为果树。 它被广泛种植于欧洲和美国境内。 树高15至20英尺（4.5至6米），可通过播种或者嫁接繁殖。叶似鱼叉，略长带绒，开有1.5英寸（4厘米）白色或粉色的花。果实形似苹果，称亦欧楂果，直径约 1.5至2英寸（4至5厘米），味道略酸，成熟于深秋。冷霜可使果子变软，称此过程为软化（bletting）。","desc_en":"Mespilus germanica, known as the medlar or common medlar, is a large shrub or small tree in the rose family Rosaceae. When the genus Mespilus is included in the genus Crataegus, the correct name for this species is Crataegus germanica (L.) Kuntze.","img":"images/409.jpg","thumb":"images/t/409.jpg","file":"Medlar blossom.JPG","ar":1.328,"py":"ouzha oz","cr_by":"Mel Etitis","cr_lic":"CC BY-SA 2.5","cr_licurl":"https://creativecommons.org/licenses/by-sa/2.5","habit":"乔木","origin":null},{"id":410,"zh":"苹果树","en":"Malus domestica","sci":"Malus domestica","order_en":"Rosales","order_zh":"蔷薇目","family_en":"Rosaceae","family_zh":"蔷薇科","iucn":null,"langs":74,"desc_zh":"苹果（学名：Malus domestica）是蔷薇科桃亚科苹果族苹果属植物，为落叶乔木，在世界上广泛种植。果实又称林檎或柰（古汉语称呼），一般呈红色，但需视品种而定，含丰富矿物质和维生素，是人们最常食用的水果之一。人们根据需求的不同口感、用途（比如烹饪、生吃、酿苹果酒等）培育不同的品种，已知有超过7,500个苹果品种，拥有一系列人们需要的不同特性。 苹果起源于中亚，直到今天当地还可以找到苹果的野生祖先：新疆野苹果。","desc_en":"An apple is the round, edible fruit of an apple tree (Malus spp.). Fruit trees of the orchard or domestic apple (Malus domestica), the most widely grown in the genus, are cultivated worldwide.","img":"images/410.jpg","thumb":"images/t/410.jpg","file":"Tree with red apples in Barkedal 4.jpg","ar":1,"py":"pingguoshu pgs","cr_by":"W.carter","cr_lic":"CC0","cr_licurl":"http://creativecommons.org/publicdomain/zero/1.0/deed.en","habit":"乔木","origin":["亚洲"]},{"id":411,"zh":"樱桃李","en":"Prunus cerasifera","sci":"Prunus cerasifera","order_en":"Rosales","order_zh":"蔷薇目","family_en":"Rosaceae","family_zh":"蔷薇科","iucn":"DD","langs":70,"desc_zh":"樱桃李（学名：Prunus cerasifera）为蔷薇科李属的植物。分布在巴尔干半岛、小亚细亚、天山、中亚、伊朗以及新疆等地，生长于海拔800米至2,000米的地区，见于山坡林中、多石砾的坡地及峡谷水边。Pissardii、Nigra、Woodii等品种叶片呈红紫色，俗称紫叶李、红叶李，是常见的观赏树木。紫叶李品种Atropurpurea与沙樱桃的杂交品种紫叶矮樱叶子也呈紫色 。","desc_en":"Prunus cerasifera is a species of plum known by the common names cherry plum and myrobalan plum. Native to Eurasia and naturalized elsewhere, P. cerasifera is believed to be one of the parents of the cultivated plum.","img":"images/411.jpg","thumb":"images/t/411.jpg","file":"20140317Prunus cerasifera Hockenheimer Rheinbogen5.jpg","ar":1.333,"py":"yingtaoli ytl","cr_by":"AnRo0002","cr_lic":"CC0","cr_licurl":"http://creativecommons.org/publicdomain/zero/1.0/deed.en","habit":null,"origin":["亚洲"]},{"id":412,"zh":"兴安悬钩子","en":"Rubus chamaemorus","sci":"Rubus chamaemorus","order_en":"Rosales","order_zh":"蔷薇目","family_en":"Rosaceae","family_zh":"蔷薇科","iucn":"LC","langs":65,"desc_zh":"云莓（学名：Rubus chamaemorus）又名兴安悬钩子，是一种在广泛在北半球亚寒带地方生长的悬钩子属多年生灌木，分布于加拿大、斯堪的纳维亚地区、波罗的海沿岸、芬兰、爱尔兰、苏格兰、俄罗斯、中国东北、日本、朝鲜半岛以及近北极地区。 云莓多生长在林下或苔藓层中，目前尚未由人工引种栽培。花以白色为主，果实琥珀色，可直接生食或制成果酱。","desc_en":"Rubus chamaemorus (also known as cloudberry) is a species of flowering plant in the rose family, Rosaceae. It has numerous common names varying by region, such as Nordic berry, Arctic berry, baked apple, knotberry, aqpik, and lowbush salmonberry.","img":"images/412.jpg","thumb":"images/t/412.jpg","file":"Hjortron.jpg","ar":1.333,"py":"xinganxuangouzi xaxgz","cr_by":"Philipum","cr_lic":"Public domain","cr_licurl":null,"habit":"草本","origin":null},{"id":413,"zh":"单核山楂","en":"Crataegus monogyna","sci":"Crataegus monogyna","order_en":"Rosales","order_zh":"蔷薇目","family_en":"Rosaceae","family_zh":"蔷薇科","iucn":"LC","langs":62,"desc_zh":null,"desc_en":"Crataegus monogyna, known as common hawthorn, whitethorn, one-seed hawthorn, or single-seeded hawthorn, is a species of flowering plant in the rose family, Rosaceae. It grows to about 10 metres (33 feet) tall, producing hermaphrodite flowers in late spring.","img":"images/413.jpg","thumb":"images/t/413.jpg","file":"Crataegus monogyna - Common hawthorn.jpg","ar":1.411,"py":"danheshanzha dhsz","cr_by":null,"cr_lic":"CC BY-SA 3.0","cr_licurl":"http://creativecommons.org/licenses/by-sa/3.0/","habit":null,"origin":["欧洲"]},{"id":414,"zh":"洋委陵菜","en":"Potentilla erecta","sci":"Potentilla erecta","order_en":"Rosales","order_zh":"蔷薇目","family_en":"Rosaceae","family_zh":"蔷薇科","iucn":null,"langs":61,"desc_zh":"洋委陵菜（学名：Potentilla erecta）是蔷薇科委陵菜属的一种多年生草本植物。该种原产于欧洲与西亚。","desc_en":"Potentilla erecta (syn. Tormentilla erecta, Potentilla laeta, Potentilla tormentilla, known as the (common) tormentil, septfoil, or erect cinquefoil ) is a herbaceous perennial plant belonging to the rose family (Rosaceae).","img":"images/414.jpg","thumb":"images/t/414.jpg","file":"Potentilla erecta01.jpg","ar":1.333,"py":"yangweilingcai ywlc","cr_by":"User:Tigerente","cr_lic":"CC BY 2.5","cr_licurl":"https://creativecommons.org/licenses/by/2.5","habit":"草本","origin":null},{"id":415,"zh":"旋果蚊草子","en":"Filipendula ulmaria","sci":"Filipendula ulmaria","order_en":"Rosales","order_zh":"蔷薇目","family_en":"Rosaceae","family_zh":"蔷薇科","iucn":"LC","langs":60,"desc_zh":"旋果蚊子草（学名：Filipendula ulmaria）为蔷薇科蚊子草属的植物。分布在俄罗斯、土耳其、欧亚北极地区、寒温带、蒙古以及中国大陆的新疆等地，生长于海拔1,200米至2,400米的地区，多生于山谷阴处、林缘、沼泽或水边。","desc_en":"Filipendula ulmaria, commonly known as meadowsweet or mead wort, is a perennial herbaceous plant in the family Rosaceae that grows in damp meadows. It is native throughout most of Europe and Western Asia (Near East and Middle East).","img":"images/415.jpg","thumb":"images/t/415.jpg","file":".00 7237 Echte Mädesüß (Filipendula ulmaria).jpg","ar":0.667,"py":"xuanguowencaozi xgwcz","cr_by":"W. Bulach","cr_lic":"CC BY-SA 4.0","cr_licurl":"https://creativecommons.org/licenses/by-sa/4.0","habit":"草本","origin":null},{"id":416,"zh":"无花果","en":"Ficus carica","sci":"Ficus carica","order_en":"Rosales","order_zh":"蔷薇目","family_en":"Moraceae","family_zh":"桑科","iucn":"LC","langs":152,"desc_zh":"无花果（学名：Ficus carica）是桑科榕属的一种落叶小乔木，果实呈球根状，无花果尾部有一个小孔，花则生长于果内，在近小孔处长有雄花，远离小孔的顶部长有雌花，另外生有不育花（瘿花），花粉由榕小蜂传播。无花果非常好繁殖，最简单的方法就是扦插，无花果就是一种水果。 无花果原产于中东和西亚地区，栽培历史已超过五千多年。因外观见果不见花而得名，另有映日果、优昙钵、阿驵、底珍树、蜜果和阿驵（《酉阳杂俎》、译自波斯语：anjir）等别名。","desc_en":"The fig is the edible fruit of Ficus carica (the common fig), a species of tree or shrub in the flowering plant family Moraceae, native to the Mediterranean region, and to western and southern Asia.","img":"images/416.jpg","thumb":"images/t/416.jpg","file":"Illustration Ficus carica0.jpg","ar":0.634,"py":"wuhuaguo whg","cr_by":null,"cr_lic":"Public domain","cr_licurl":null,"habit":"乔木","origin":["亚洲","欧洲"]},{"id":417,"zh":"菠萝蜜","en":"Artocarpus heterophyllus","sci":"Artocarpus heterophyllus","order_en":"Rosales","order_zh":"蔷薇目","family_en":"Moraceae","family_zh":"桑科","iucn":null,"langs":115,"desc_zh":"波罗蜜（学名：Artocarpus heterophyllus），是桑科波罗蜜属常绿乔木，另外还有一种名称相似的植物小波罗蜜。","desc_en":"The jackfruit, jakfruit or nangka (Artocarpus heterophyllus) is a species of tree in the fig, mulberry, and breadfruit family (Moraceae). The jackfruit is the largest tree fruit, reaching as much as 55 kg (120 pounds) in weight, 90 cm (35 inches) in length, an…","img":"images/417.jpg","thumb":"images/t/417.jpg","file":"Artocarpus heterophyllus 3.jpg","ar":1.45,"py":"boluomi blm","cr_by":"Franz Xaver","cr_lic":"CC BY-SA 3.0","cr_licurl":"https://creativecommons.org/licenses/by-sa/3.0","habit":"乔木","origin":null},{"id":418,"zh":"面包树","en":"breadfruit","sci":"Artocarpus altilis","order_en":"Rosales","order_zh":"蔷薇目","family_en":"Moraceae","family_zh":"桑科","iucn":null,"langs":98,"desc_zh":"太平洋面包树（学名：Artocarpus altilis），旧称面包树，又称面包果、罗蜜树、马槟榔、面磅树，夏威夷当地人称为 Ulu，属桑科桂木属。桂木属又名「波罗蜜属」，太平洋面包树的果实很像「菠萝蜜」水果，但是体积较「菠萝蜜」小，大约是一个手掌大小。 太平洋面包树原产于新几内亚以及马来群岛，如今因人类传播而分布波利尼西亚，印度南部，加勒比地区等热带地区。","desc_en":"Breadfruit (Artocarpus altilis) is a species of flowering tree in the mulberry and jackfruit family (Moraceae). Its name is derived from the texture of the moderately ripe fruit when cooked, similar to freshly baked bread and having a potato-like flavor.","img":"images/418.jpg","thumb":"images/t/418.jpg","file":"Artocarpus altilis (fruit).jpg","ar":0.75,"py":"mianbaoshu mbs","cr_by":"Hans Hillewaert","cr_lic":"CC BY-SA 3.0","cr_licurl":"https://creativecommons.org/licenses/by-sa/3.0","habit":"乔木","origin":null},{"id":419,"zh":"菩提树","en":"Ficus religiosa","sci":"Ficus religiosa","order_en":"Rosales","order_zh":"蔷薇目","family_en":"Moraceae","family_zh":"桑科","iucn":"LC","langs":71,"desc_zh":"菩提树（学名：Ficus religiosa），又称毕钵罗树、菩提榕，是一种桑科榕属（又称无花果属）植物。原产于印度也是印度的国树，在中国西南部、以及中南半岛也有。菩提树的别名有：神圣之树、思维树、天竺菩提树、印度菩提树、佛树、觉树、道树、道场树。是佛教三大圣树之一，另外两个是：无忧树、娑罗双树。","desc_en":"Ficus religiosa or sacred fig is a species of fig native to the Indian subcontinent and Indochina that belongs to Moraceae, the fig or mulberry family. It is also known as the bodhi tree, bo tree, peepul tree, peepal tree, pipala tree or ashvattha tree (in Ban…","img":"images/419.jpg","thumb":"images/t/419.jpg","file":"Bodhi Baum (Ficus religiosa).jpg","ar":1.775,"py":"putishu pts","cr_by":"Burkhard Mücke","cr_lic":"CC BY-SA 4.0","cr_licurl":"https://creativecommons.org/licenses/by-sa/4.0","habit":"乔木","origin":["亚洲"]},{"id":420,"zh":"白桑","en":"Morus alba","sci":"Morus alba","order_en":"Rosales","order_zh":"蔷薇目","family_en":"Moraceae","family_zh":"桑科","iucn":null,"langs":68,"desc_zh":"白桑（Morus alba）是桑属的一种小型到中型的落叶乔木，高度约10–20 米。白桑原生于中国北部，并广于世界各地种植。由于白桑是养蚕业的重要饲料，很早就在中国培育，果实称为桑椹，初生白色，成熟后成为紫黑色。花为雌雄异株，雄花为柔荑花序，雌花为穗状花序。根皮（桑白皮）、桑椹、桑叶都可以作为中药使用。此外桑椹可以酿酒，树皮可以造纸，造出的纸称为“桑皮纸”。 其种加词“alba”意为“白色的”。","desc_en":"Morus alba, known as white mulberry, common mulberry and silkworm mulberry, is a fast-growing, small to medium-sized mulberry tree which grows to 10–20 m (33–66 ft) tall. It is native to China and is widely cultivated and naturalized elsewhere.","img":"images/420.jpg","thumb":"images/t/420.jpg","file":"Morus-alba.jpg","ar":1.333,"py":"baisang bs","cr_by":"GerardM","cr_lic":"CC BY-SA 2.1 es","cr_licurl":"https://creativecommons.org/licenses/by-sa/2.1/es/deed.en","habit":"乔木","origin":["亚洲"]},{"id":421,"zh":"黑桑","en":"Morus nigra","sci":"Morus nigra","order_en":"Rosales","order_zh":"蔷薇目","family_en":"Moraceae","family_zh":"桑科","iucn":null,"langs":67,"desc_zh":"黑桑（学名：Morus nigra）为桑科桑属的植物。起源于亚美尼亚高原，分布在亚洲以及中国大陆的新疆等地，目前已由人工引种栽培。 其种加词“nigra”意为“黑色的，暗色的”。","desc_en":"Morus nigra, or the black mulberry, is a species of flowering plant in the family Moraceae that is native to southwestern Asia, where it has been cultivated for so long that its precise natural range is unknown.","img":"images/421.jpg","thumb":"images/t/421.jpg","file":"Illustration Morus nigra0.jpg","ar":0.67,"py":"heisang hs","cr_by":null,"cr_lic":"Public domain","cr_licurl":null,"habit":null,"origin":["亚洲"]},{"id":422,"zh":"孟加拉榕","en":"Ficus benghalensis","sci":"Ficus benghalensis","order_en":"Rosales","order_zh":"蔷薇目","family_en":"Moraceae","family_zh":"桑科","iucn":null,"langs":60,"desc_zh":"孟加拉榕（学名：Ficus benghalensis）为桑科榕属的植物，原产于印度。树高十至十五米，树叶呈长椭圆形，叶端为尖状。枝叶繁茂，向四方蔓生。 其种加词“benghalensis”意为“孟加拉国的”。","desc_en":"Ficus benghalensis, Ficus indica, or Ficus audrey commonly known as banyan, banyan fig, audrey fig and Indian banyan, is a tree native to the Indian subcontinent. Specimens in India are among the largest trees in the world by canopy coverage.","img":"images/422.jpg","thumb":"images/t/422.jpg","file":"Banyantree.jpg","ar":1.417,"py":"mengjialarong mjlr","cr_by":"Ahoerstemeier","cr_lic":"CC BY-SA 3.0","cr_licurl":"http://creativecommons.org/licenses/by-sa/3.0/","habit":"乔木","origin":["亚洲"]},{"id":423,"zh":"异株荨麻","en":"Urtica dioica","sci":"Urtica dioica","order_en":"Rosales","order_zh":"蔷薇目","family_en":"Urticaceae","family_zh":"荨麻科","iucn":"LC","langs":88,"desc_zh":"异株荨麻（学名：Urtica dioica）是荨麻科荨麻属的植物。分布在喜马拉雅西部、北非、亚洲、欧洲、北美以及中国大陆的西藏、新疆、青海等地，生长于海拔3,300米至3,900米的地区，常生长在山坡阴湿处。茎叶表面遍布毒刺，碰触时会注入许多化学物质，造成刺痛。","desc_en":"Urtica dioica, often known as common nettle, burn nettle, stinging nettle, nettle leaf, or just a nettle or stinger, is a herbaceous perennial flowering plant in the family Urticaceae.","img":"images/423.jpg","thumb":"images/t/423.jpg","file":"Brennnessel 1.JPG","ar":1.228,"py":"yizhuqianma yzqm","cr_by":null,"cr_lic":"CC BY-SA 3.0","cr_licurl":"http://creativecommons.org/licenses/by-sa/3.0/","habit":"草本","origin":["亚洲","欧洲","非洲"]},{"id":424,"zh":"苎麻","en":"Boehmeria nivea","sci":"Boehmeria nivea","order_en":"Rosales","order_zh":"蔷薇目","family_en":"Urticaceae","family_zh":"荨麻科","iucn":null,"langs":55,"desc_zh":"苎麻（学名：Boehmeria nivea）为荨麻科苎麻属的一种。原生于东亚，包括中国及中印半岛等地区。作为农作物而被引入到世界各地。","desc_en":"Boehmeria nivea, commonly known as ramie, Chinese grass or Chinese silk plant, is a monoecious shrub or subshrub in the family Urticaceae commonly found in China.","img":"images/424.jpg","thumb":"images/t/424.jpg","file":"Boehmeria nivea 1.jpg","ar":1.333,"py":"zhuma zm","cr_by":"Sphl","cr_lic":"CC BY-SA 3.0","cr_licurl":"http://creativecommons.org/licenses/by-sa/3.0/","habit":"禾草","origin":["亚洲"]},{"id":425,"zh":"欧荨麻","en":"Urtica urens","sci":"Urtica urens","order_en":"Rosales","order_zh":"蔷薇目","family_en":"Urticaceae","family_zh":"荨麻科","iucn":null,"langs":50,"desc_zh":"欧荨麻（学名：Urtica urens）为荨麻科荨麻属的植物。分布在西伯利亚、亚洲、非洲、欧洲、高加索以及中国大陆的西藏、青海、辽宁、新疆等地，生长于海拔2,800米至2,900米的地区，多生长于林缘路边及住宅旁，目前尚未由人工引种栽培。","desc_en":"Urtica urens, commonly known as annual nettle, dwarf nettle, small nettle, dog nettle, burning nettle, or bush nettle is a herbaceous annual flowering plant species in the nettle family Urticaceae.","img":"images/425.jpg","thumb":"images/t/425.jpg","file":"Urtica urens 002.JPG","ar":0.75,"py":"ouqianma oqm","cr_by":"H. Zell","cr_lic":"CC BY-SA 3.0","cr_licurl":"https://creativecommons.org/licenses/by-sa/3.0","habit":"灌木","origin":["亚洲","非洲","北美洲","大洋洲"]},{"id":426,"zh":"eastern pellitory-of-the-wall","en":"eastern pellitory-of-the-wall","sci":"Parietaria officinalis","order_en":"Rosales","order_zh":"蔷薇目","family_en":"Urticaceae","family_zh":"荨麻科","iucn":null,"langs":38,"desc_zh":null,"desc_en":"Parietaria officinalis, the eastern pellitory-of-the-wall, also known as upright pellitory and lichwort, is a plant of the nettle family. Its leaves, however, are non-stinging. The plant grows on rubbish and on walls, hence the name.","img":"images/426.jpg","thumb":"images/t/426.jpg","file":"Parietaria officinalis 3.jpg","ar":0.667,"py":"","cr_by":"Franz Xaver","cr_lic":"CC BY-SA 3.0","cr_licurl":"https://creativecommons.org/licenses/by-sa/3.0","habit":null,"origin":null},{"id":427,"zh":"枣树","en":"Ziziphus jujuba","sci":"Ziziphus jujuba","order_en":"Rosales","order_zh":"蔷薇目","family_en":"Rhamnaceae","family_zh":"鼠李科","iucn":"LC","langs":86,"desc_zh":"枣（学名：Ziziphus jujuba），俗称红枣、黑枣、大枣，生长在温带地区的小乔木，原产于中国大陆中部与南部、朝鲜半岛、黎巴嫩、伊朗、巴基斯坦、印度、孟加拉，在中国大陆的南北各地都有分布。因其经济价值，被移植到日本、欧洲南部、北美洲。花朵小多蜜，是一种蜜源植物。果实为枣，长圆形，未成熟时呈黄绿色，类似缩小版翠绿色印度枣，成熟后呈褐红色。可鲜食也可制成果干或蜜饯果脯等。营养丰富，富含铁元素和维生素。","desc_en":"Jujube (UK ; US or ), sometimes jujuba, scientific name Ziziphus jujuba, and also called red date, Chinese date, and Chinese jujube, is a species in the genus Ziziphus in the buckthorn family Rhamnaceae.","img":"images/427.jpg","thumb":"images/t/427.jpg","file":"Jujube n.jpg","ar":1.639,"py":"zaoshu zs","cr_by":"Rémi Tournebize","cr_lic":"CC BY-SA 3.0","cr_licurl":"https://creativecommons.org/licenses/by-sa/3.0","habit":"灌木","origin":["亚洲"]},{"id":428,"zh":"欧鼠李","en":"Frangula alnus","sci":"Frangula alnus","order_en":"Rosales","order_zh":"蔷薇目","family_en":"Rhamnaceae","family_zh":"鼠李科","iucn":"LC","langs":56,"desc_zh":"欧鼠李（学名：Frangula alnus），为鼠李科裸芽鼠李属下的一个植物种。","desc_en":"Frangula alnus, commonly known as alder buckthorn, glossy buckthorn, or breaking buckthorn, is a tall deciduous shrub in the family Rhamnaceae. Unlike other \"buckthorns\", alder buckthorn does not have thorns.","img":"images/428.jpg","thumb":"images/t/428.jpg","file":"Frangula alnus sl7.jpg","ar":1.333,"py":"oushuli osl","cr_by":"Stefan.lefnaer","cr_lic":"CC BY-SA 4.0","cr_licurl":"https://creativecommons.org/licenses/by-sa/4.0","habit":"灌木","origin":["亚洲","欧洲","非洲"]},{"id":429,"zh":"药鼠李","en":"Rhamnus cathartica","sci":"Rhamnus cathartica","order_en":"Rosales","order_zh":"蔷薇目","family_en":"Rhamnaceae","family_zh":"鼠李科","iucn":"LC","langs":56,"desc_zh":"药鼠李（学名：Rhamnus cathartica）为鼠李科鼠李属下的一个种。","desc_en":"Rhamnus cathartica, the European buckthorn, common buckthorn, purging buckthorn, or just buckthorn, is a species of small tree in the flowering plant family Rhamnaceae.","img":"images/429.jpg","thumb":"images/t/429.jpg","file":"Rhamnus cathartica 1.jpg","ar":1.501,"py":"yaoshuli ysl","cr_by":"Franz Xaver","cr_lic":"CC BY-SA 3.0","cr_licurl":"https://creativecommons.org/licenses/by-sa/3.0","habit":"乔木","origin":["亚洲","欧洲","非洲"]},{"id":430,"zh":"滇刺枣","en":"Ziziphus mauritiana","sci":"Ziziphus mauritiana","order_en":"Rosales","order_zh":"蔷薇目","family_en":"Rhamnaceae","family_zh":"鼠李科","iucn":"LC","langs":47,"desc_zh":"印度枣（学名：Ziziphus mauritiana）是鼠李科枣属植物，原产中国云南、四川、广西、广东以及南亚、东南亚、非洲。","desc_en":"Ziziphus mauritiana, also known as Indian jujube, Indian plum, Chinee apple, ber (Hindi: बेर) and dunks, is a tropical, spiny, evergreen shrub or small tree in the buckthorn family Rhamnaceae. It is often confused with the closely related Chinese jujube (Z.","img":"images/430.jpg","thumb":"images/t/430.jpg","file":"Ziziphus mauritiana fruit 2.jpg","ar":1.028,"py":"diancizao dcz","cr_by":"Ethel Aardvark","cr_lic":"CC BY 3.0","cr_licurl":"https://creativecommons.org/licenses/by/3.0","habit":"乔木","origin":["亚洲"]},{"id":431,"zh":"滨枣","en":"Paliurus spina-christi","sci":"Paliurus spina-christi","order_en":"Rosales","order_zh":"蔷薇目","family_en":"Rhamnaceae","family_zh":"鼠李科","iucn":null,"langs":36,"desc_zh":"滨枣（学名：Paliurus spina-christi）是鼠李科中的一个植物种。滨枣的学名可能来自于人们以为耶稣带的荆棘之冠是用滨枣作的。","desc_en":"Paliurus spina-christi, commonly known as Jerusalem thorn, garland thorn, Christ's thorn, or crown of thorns, is a species of Paliurus native to the northern Mediterranean region, Southwest Asia and Central Asia, from Spain and southern France east to Afghanis…","img":"images/431.jpg","thumb":"images/t/431.jpg","file":"Paliurus spina-christi 4.jpg","ar":1.138,"py":"binzao bz","cr_by":"Franz Xaver","cr_lic":"CC BY-SA 3.0","cr_licurl":"https://creativecommons.org/licenses/by-sa/3.0","habit":null,"origin":["亚洲","欧洲"]},{"id":432,"zh":"欧洲野榆","en":"Ulmus minor","sci":"Ulmus minor","order_en":"Rosales","order_zh":"蔷薇目","family_en":"Ulmaceae","family_zh":"榆科","iucn":"DD","langs":57,"desc_zh":"欧洲野榆（学名：Ulmus minor；英语：European field elm）是欧洲的三种榆属植物之一。和欧洲白榆、欧洲山榆一样，欧洲野榆也易感荷兰榆树病，但欧洲野榆的抗性稍高。 欧洲野榆形态变化很大，叶形倒披针形、倒卵形、椭圆形或近圆形，叶片上表面光滑或粗糙，叶片下表面无毛或有毛，嫩枝无毛至密被柔毛。","desc_en":"Ulmus minor Mill., the field elm, is by far the most polymorphic of the European species, although its taxonomy remains a matter of contention. Its natural range is predominantly south European, extending to Asia Minor and Iran; its northern outposts are the B…","img":"images/432.jpg","thumb":"images/t/432.jpg","file":"Illustration Ulmus carpinifolia0.jpg","ar":0.645,"py":"ouzhouyeyu ozyy","cr_by":null,"cr_lic":"Public domain","cr_licurl":null,"habit":"乔木","origin":["欧洲"]},{"id":433,"zh":"欧洲山榆","en":"Ulmus glabra","sci":"Ulmus glabra","order_en":"Rosales","order_zh":"蔷薇目","family_en":"Ulmaceae","family_zh":"榆科","iucn":"DD","langs":57,"desc_zh":"欧洲山榆（学名：Ulmus glabra，英语：European mountain elm或wych elm），又名光榆、无毛榆、欧洲光皮榆、阔叶榆（英语：broadleaf elm）、苏格兰榆（英语：Scottish elm, Scotch elm, Scots elm），是榆属下的一种大型落叶乔木，高度可达40米，分布于爱尔兰到乌拉尔山脉的广大欧洲山区，向北分布范围可达北纬67度，是欧洲三种榆树中分布最广的一种（另外两种为欧洲野榆和…","desc_en":"Ulmus glabra, the wych elm or Scots elm, has the widest range of the European elm species, from Ireland eastwards to the Ural Mountains, and from the Arctic Circle south to the mountains of the Peloponnese and Sicily, where the species reaches its southern lim…","img":"images/433.jpg","thumb":"images/t/433.jpg","file":"RN Ulmus glabra (alnarp sweden).jpg","ar":0.75,"py":"ouzhoushanyu ozsy","cr_by":"Ronnie Nijboer","cr_lic":"CC0","cr_licurl":"http://creativecommons.org/publicdomain/zero/1.0/deed.en","habit":"乔木","origin":["亚洲"]},{"id":434,"zh":"大麻","en":"Cannabis sativa","sci":"Cannabis sativa","order_en":"Rosales","order_zh":"蔷薇目","family_en":"Cannabaceae","family_zh":"大麻科","iucn":null,"langs":89,"desc_zh":"大麻（学名：Cannabis sativa）是大麻科大麻属植物的物种之一，可能是大麻属的唯一物种，中国古称麻、枲、苴、汉麻、火麻或黄麻，又称为大麻草、寻常大麻、苜蓿大麻。大麻使用者惯称Sativa（与indica（印度大麻）相对比）。 本种外表高大瘦长、叶子长而狭窄，因为含有大麻素成份，可作为医疗与娱乐性药物使用，但在许多国家则被视为毒品禁止。","desc_en":"Cannabis sativa is an annual herbaceous flowering plant. The species was first classified by Carl Linnaeus in 1753. The specific epithet sativa means 'cultivated'.","img":"images/434.jpg","thumb":"images/t/434.jpg","file":"Cannabis sativa 2.jpg","ar":0.751,"py":"dama dm","cr_by":"Thayne Tuason","cr_lic":"CC BY-SA 4.0","cr_licurl":"https://creativecommons.org/licenses/by-sa/4.0","habit":"草本","origin":["亚洲"]},{"id":435,"zh":"蛇麻","en":"Humulus lupulus","sci":"Humulus lupulus","order_en":"Rosales","order_zh":"蔷薇目","family_en":"Cannabaceae","family_zh":"大麻科","iucn":null,"langs":86,"desc_zh":"蛇麻（学名：Humulus lupulus），又音译作忽布（英语hops），是大麻科葎草属的植物物种，因其花序用于酿造啤酒，因此又称作啤酒花。","desc_en":"Humulus lupulus, the common hop or hops, is a species of flowering plant in the hemp family, Cannabaceae. It is a perennial, herbaceous climbing plant which sends up new shoots in early spring and dies back to a cold-hardy rhizome in autumn.","img":"images/435.jpg","thumb":"images/t/435.jpg","file":"Hop mannelijke plant Humulus lupulus male plant.jpg","ar":0.75,"py":"shema sm","cr_by":"No machine-readable author provided. Rasbak assumed (based on copyright claims).","cr_lic":"CC BY-SA 3.0","cr_licurl":"http://creativecommons.org/licenses/by-sa/3.0/","habit":"藤本","origin":["亚洲","欧洲","北美洲"]},{"id":436,"zh":"沙棘","en":"Hippophae rhamnoides","sci":"Hippophae rhamnoides","order_en":"Rosales","order_zh":"蔷薇目","family_en":"Elaeagnaceae","family_zh":"胡颓子科","iucn":"LC","langs":64,"desc_zh":"沙棘（学名：Hippophae rhamnoides），或作海沙棘，是沙棘属的一种带有棘刺的落叶多年生小乔木或灌木。其种加词“rhamnoides”源于希腊语，意为“像鼠李的”。原产于亚洲和欧洲的温带、寒温带地区。沙棘可防风固沙，其果实可以食用或用来制作饮料，此外沙棘果在美容和药用上也有价值。","desc_en":"Sea-buckthorn (Hippophae rhamnoides), also known as sea buckthorn, sandthorn, sallowthorn or seaberry, is a species of flowering plant in the family Elaeagnaceae, native to cold-temperate regions of Eurasia. It is a spiny deciduous shrub.","img":"images/436.jpg","thumb":"images/t/436.jpg","file":"Hippophae (Novogrudinina).jpg","ar":0.75,"py":"shaji sj","cr_by":"Виталий Уайлд","cr_lic":"CC BY-SA 4.0","cr_licurl":"https://creativecommons.org/licenses/by-sa/4.0","habit":"灌木","origin":["亚洲"]},{"id":437,"zh":"沙枣","en":"Elaeagnus angustifolia","sci":"Elaeagnus angustifolia","order_en":"Rosales","order_zh":"蔷薇目","family_en":"Elaeagnaceae","family_zh":"胡颓子科","iucn":"LC","langs":49,"desc_zh":"沙枣（学名：Elaeagnus angustifolia）也称银柳、香柳、桂香柳。常生长在沙漠地区。果实像枣，可食用，故名沙枣。用于水土保持、防沙护林。","desc_en":"Elaeagnus angustifolia, commonly called Russian olive, silver berry, oleaster, or wild olive, is a species of Elaeagnus, native to Asia and limited areas of eastern Europe. It is widely established in North America as an introduced species.","img":"images/437.jpg","thumb":"images/t/437.jpg","file":"Elaeagnus angustifolia 20050608 852.jpg","ar":0.75,"py":"shazao sz","cr_by":"Georg Slickers","cr_lic":"CC BY-SA 3.0","cr_licurl":"http://creativecommons.org/licenses/by-sa/3.0/","habit":null,"origin":["亚洲","欧洲"]},{"id":438,"zh":"夏栎","en":"Quercus robur","sci":"Quercus robur","order_en":"Fagales","order_zh":"壳斗目","family_en":"Fagaceae","family_zh":"壳斗科","iucn":"LC","langs":84,"desc_zh":"夏栎（学名：Quercus robur），也常称作欧洲有柄橡木、长柄栎、夏橡、欧洲白栎、英国栎、英国橡。原生于欧洲、安那托利亚至高加索地区，北非部分地区和中国青岛亦有分布。","desc_en":"Quercus robur, pedunculate oak, European oak, or English oak, is a species of flowering plant in the beech and oak family, Fagaceae. It is a large tree, native to Europe and western Asia, and is widely cultivated in other temperate regions.","img":"images/438.jpg","thumb":"images/t/438.jpg","file":"Paprastasis azuolas.JPG","ar":1.332,"py":"xiali xl","cr_by":"Algirdas at Lithuanian Wikipedia","cr_lic":"Public domain","cr_licurl":null,"habit":"乔木","origin":["亚洲","欧洲"]},{"id":439,"zh":"欧洲山毛榉","en":"Fagus sylvatica","sci":"Fagus sylvatica","order_en":"Fagales","order_zh":"壳斗目","family_en":"Fagaceae","family_zh":"壳斗科","iucn":"LC","langs":78,"desc_zh":"欧洲山毛榉（学名：Fagus sylvatica），又名欧洲水青冈，是壳斗科山毛榉属的一种落叶植物。","desc_en":"Fagus sylvatica, the European beech or common beech, and a mutation known has copper beech (Fagus sylvatica purpurea), is a large deciduous tree in the beech family with smooth silvery-grey bark, large leaf area, and a short trunk with low branches.","img":"images/439.jpg","thumb":"images/t/439.jpg","file":"Grib skov.jpg","ar":1.065,"py":"ouzhoushanmaoju ozsmj","cr_by":"Malene Thyssen","cr_lic":"CC BY-SA 3.0","cr_licurl":"http://creativecommons.org/licenses/by-sa/3.0/","habit":"乔木","origin":["欧洲"]},{"id":440,"zh":"欧洲栗","en":"Castanea sativa","sci":"Castanea sativa","order_en":"Fagales","order_zh":"壳斗目","family_en":"Fagaceae","family_zh":"壳斗科","iucn":"LC","langs":77,"desc_zh":"欧洲栗（学名：Castanea sativa），又称西洋栗、甜栗、甘栗，属于被子植物中的山毛榉科。原产于欧洲东南部与小亚细亚，现已广泛种植于欧洲各地。欧洲栗的果树耐寒且长寿，它的果实「栗子」则常被用作食材。 欧洲栗中最粗的一棵即“百骑大栗树”，位于意大利西西里岛埃特纳火山，也是最粗的树木及植物之一。它是欧洲的乡土树种，非洲北部和亚洲西部也有分布。","desc_en":"The sweet chestnut (Castanea sativa), also known as the Spanish chestnut or European chestnut, is a species of tree in the family Fagaceae, native to Southern Europe and Anatolia, and widely cultivated in Western and Central Europe.","img":"images/440.jpg","thumb":"images/t/440.jpg","file":"Romagne 86 Châtaignes 2008.jpg","ar":1.504,"py":"ouzhouli ozl","cr_by":"JLPC","cr_lic":"CC BY-SA 3.0","cr_licurl":"https://creativecommons.org/licenses/by-sa/3.0","habit":"乔木","origin":["亚洲","欧洲"]},{"id":441,"zh":"西班牙栓皮栎","en":"Quercus suber","sci":"Quercus suber","order_en":"Fagales","order_zh":"壳斗目","family_en":"Fagaceae","family_zh":"壳斗科","iucn":"LC","langs":75,"desc_zh":"西班牙栓皮栎（学名：Quercus suber）为壳斗科栎属下的一个种。是一种中型常绿橡树，原产于西北亚和西南欧。常被用来制作软木塞，因此又被称为软木橡树或木塞橡树。 软木橡树最高可生长到20公尺，但在一般自然环境却少有如此高大。叶长约4~7厘米边缘微裂或有锯齿状，叶面暗绿色叶背则呈现泛白色，叶于支末端呈自然垂落状。种子约2~3公分长，与一般橡树子不同在于壳斗呈现流苏杯状。","desc_en":"Quercus suber, commonly called the cork oak, is a medium-sized, evergreen oak tree in the section Quercus sect. Cerris. It is the primary source of cork for wine bottle stoppers and other uses, such as cork flooring and as the cores of cricket balls.","img":"images/441.jpg","thumb":"images/t/441.jpg","file":"Quercus suber JPG1.jpg","ar":1.502,"py":"xibanyashuanpili xbyspl","cr_by":"Jean-Pol GRANDMONT","cr_lic":"CC BY 3.0","cr_licurl":"https://creativecommons.org/licenses/by/3.0","habit":"乔木","origin":["欧洲","非洲"]},{"id":442,"zh":"无梗花栎","en":"Quercus petraea","sci":"Quercus petraea","order_en":"Fagales","order_zh":"壳斗目","family_en":"Fagaceae","family_zh":"壳斗科","iucn":"LC","langs":69,"desc_zh":"无梗花栎（学名：Quercus petraea），又称岩生栎，分布于欧洲及安纳托利亚。 无梗花栎是爱尔兰的国树，也是威尔士非官方的代表标志，因此在威尔士亦称威尔士橡树（Welsh Oak），同时也被认为是康沃尔郡的郡树，因此亦称康沃尔橡树（Cornish Oak）。","desc_en":"Quercus petraea, commonly known as the sessile oak, Welsh oak, Cornish oak, Irish oak or durmast oak, is a species of deciduous oak tree native to most of Europe and into Anatolia and Iran.","img":"images/442.jpg","thumb":"images/t/442.jpg","file":"Quercus petraea 02.jpg","ar":1.333,"py":"wugenghuali wghl","cr_by":null,"cr_lic":"CC BY-SA 2.5","cr_licurl":"https://creativecommons.org/licenses/by-sa/2.5","habit":"乔木","origin":["亚洲","欧洲"]},{"id":443,"zh":"冬青栎","en":"Quercus ilex","sci":"Quercus ilex","order_en":"Fagales","order_zh":"壳斗目","family_en":"Fagaceae","family_zh":"壳斗科","iucn":"LC","langs":65,"desc_zh":"冬青栎（学名：Quercus ilex）是一种来自于地中海地区的常绿大型栎属树木。它和栓皮栎一样属于栎属中的白栎，它们可以在一个夏季里就成熟。16世纪它被引入英国，今天这些最老的英国冬青栎还活着。在意大利西西里岛上有一棵冬青栎据传有700年的树龄了。在马耳他有一片树林里的树木据说有500至1000年的树龄。冬青栎是马耳他的国树。在迦太基占据马耳他岛之前它是岛上的主流树木。","desc_en":"The holm oak (Quercus ilex), also called the holly oak, is a large evergreen oak native to the Mediterranean region. It is a member of the section Ilex of the genus, with acorns that mature in a single summer.","img":"images/443.jpg","thumb":"images/t/443.jpg","file":"Frouzet fg02.jpg","ar":1.333,"py":"dongqingli dql","cr_by":"Fritz Geller-Grimm","cr_lic":"CC BY-SA 3.0","cr_licurl":"https://creativecommons.org/licenses/by-sa/3.0","habit":null,"origin":["欧洲"]},{"id":444,"zh":"北美红橡","en":"Quercus rubra","sci":"Quercus rubra","order_en":"Fagales","order_zh":"壳斗目","family_en":"Fagaceae","family_zh":"壳斗科","iucn":"LC","langs":51,"desc_zh":"北美红橡（学名：Quercus rubra）为北美洲原生植物，为与南方红橡（Quercus falcata）区别亦称北方红橡。分布区域北至五大湖区，南至乔治亚州、密西西比州、阿拉巴马州和路易斯安那州，东至新斯科细亚省，西至奥克拉荷马州、堪萨斯州、内布拉斯加州和明尼苏达州的美国东部和中部以及加拿大东南部和中南部地区。北美红橡现今已被引入西欧的小部份地区，作为花园和公园中的观赏树种种植。它也是新泽西州的州树和爱德华王子岛省的省树。","desc_en":"Quercus rubra, the northern red oak or common red oak, is an oak tree in the red oak group (Quercus section Lobatae). It is a native of North America, in the eastern and central United States and southeast and south-central Canada.","img":"images/444.jpg","thumb":"images/t/444.jpg","file":"Twin Sisters Trail (14) (14092717698).jpg","ar":0.667,"py":"beimeihongxiang bmhx","cr_by":"Nicholas A. Tonelli from Northeast Pennsylvania, USA","cr_lic":"CC BY 2.0","cr_licurl":"https://creativecommons.org/licenses/by/2.0","habit":"乔木","origin":["北美洲"]},{"id":445,"zh":"土耳其栎","en":"Quercus cerris","sci":"Quercus cerris","order_en":"Fagales","order_zh":"壳斗目","family_en":"Fagaceae","family_zh":"壳斗科","iucn":"LC","langs":51,"desc_zh":"土耳其栎（学名：Quercus cerris）是一种原产于东南欧和小亚细亚的橡树，是栎属下Cerris的模式种。","desc_en":"Quercus cerris, the Turkey oak or Austrian oak, is an oak native to south-eastern Europe and Asia Minor. It is the type species of Quercus sect. Cerris, a section of the genus characterised by shoot buds surrounded by soft bristles, bristle-tipped leaf lobes,…","img":"images/445.jpg","thumb":"images/t/445.jpg","file":"Dettaglio Cupuliferae Quercus cerris Lin. - Erbario Frizzi Perugia n. 824.jpg","ar":0.478,"py":"tuerqili teql","cr_by":"Giuseppe Frizzi","cr_lic":"Public domain","cr_licurl":null,"habit":null,"origin":["亚洲","欧洲"]},{"id":446,"zh":"柔毛栎","en":"Quercus pubescens","sci":"Quercus pubescens","order_en":"Fagales","order_zh":"壳斗目","family_en":"Fagaceae","family_zh":"壳斗科","iucn":"LC","langs":48,"desc_zh":"柔毛栎（Quercus pubescens）是一种原生于南欧、亚洲西南等地的一种栎属植物，在比利牛斯山脉至克里米亚、高加索等地均有分布，法国及中欧也可见到。","desc_en":"Quercus pubescens (synonyms virgiliana), commonly known as the downy oak, pubescent oak or Italian oak, is a species of white oak (genus Quercus sect. Quercus) native to southern Europe and southwest Asia.","img":"images/446.jpg","thumb":"images/t/446.jpg","file":"Quercus pubescens Tuscany.jpg","ar":0.75,"py":"roumaoli rml","cr_by":"Etrusko25","cr_lic":"CC BY-SA 3.0","cr_licurl":"https://creativecommons.org/licenses/by-sa/3.0","habit":null,"origin":["亚洲","欧洲"]},{"id":447,"zh":"凯梅斯橡木","en":"Quercus coccifera","sci":"Quercus coccifera","order_en":"Fagales","order_zh":"壳斗目","family_en":"Fagaceae","family_zh":"壳斗科","iucn":"LC","langs":46,"desc_zh":null,"desc_en":"Quercus coccifera, commonly known as kermes oak, holly oak, or Palestine oak, is an evergreen oak shrub or tree in section Ilex of the genus. It has many synonyms, including Quercus calliprinos.","img":"images/447.jpg","thumb":"images/t/447.jpg","file":"Quercus coccifera Bellotas 2010-10-03 DehesaBoyaldePuertollano.jpg","ar":1.333,"py":"kaimeisixiangmu kmsxm","cr_by":"Javier martin","cr_lic":"Public domain","cr_licurl":null,"habit":"乔木","origin":["欧洲","非洲"]},{"id":448,"zh":"欧榛","en":"Corylus avellana","sci":"Corylus avellana","order_en":"Fagales","order_zh":"壳斗目","family_en":"Betulaceae","family_zh":"桦木科","iucn":"LC","langs":91,"desc_zh":"欧榛（学名：Corylus avellana）也称欧洲榛，落叶灌木，春天长出下垂的柔荑花序，秋天结出成串坚果。是一种原生在欧洲与亚洲西部的榛属植物。南至不列颠群岛、希腊、伊比利半岛、土耳其与赛普勒斯，北至斯堪地纳维亚中部、东至乌拉山中部、高加索与伊朗的西北方都有分布。","desc_en":"Corylus avellana, the common hazel, is a species of flowering plant in the birch family Betulaceae. The shrubs usually grow 3–8 metres (10–26 feet) tall. The nut is round, in contrast to the longer filbert nut.","img":"images/448.jpg","thumb":"images/t/448.jpg","file":"Corylus avellana shrub.jpg","ar":1.333,"py":"ouzhen oz","cr_by":"MPF","cr_lic":"CC BY-SA 3.0","cr_licurl":"https://creativecommons.org/licenses/by-sa/3.0","habit":"灌木","origin":["亚洲","欧洲"]},{"id":449,"zh":"欧洲桤木","en":"Alnus glutinosa","sci":"Alnus glutinosa","order_en":"Fagales","order_zh":"壳斗目","family_en":"Betulaceae","family_zh":"桦木科","iucn":"LC","langs":76,"desc_zh":"普通赤杨（学名：Alnus glutinosa）是桦木科赤杨属的落叶乔木，主要分布于欧洲、亚洲西南部和非洲北部。普通赤杨喜潮湿，在存在Frankia alni细菌的情况下可在贫瘠的土壤中生长。它是中等大小、生命短暂的树木，大约能长到30米（98英尺）。","desc_en":"Alnus glutinosa, the common alder, black alder, European alder, European black alder, or just alder, is a species of tree in the family Betulaceae, native to most of Europe, southwest Asia and northern Africa.","img":"images/449.jpg","thumb":"images/t/449.jpg","file":"Alnus glutinosa 011.jpg","ar":1.333,"py":"ouzhouqimu ozqm","cr_by":"Willow","cr_lic":"CC BY 2.5","cr_licurl":"https://creativecommons.org/licenses/by/2.5","habit":"乔木","origin":["亚洲","欧洲","非洲"]},{"id":450,"zh":"垂枝桦","en":"Betula pendula","sci":"Betula pendula","order_en":"Fagales","order_zh":"壳斗目","family_en":"Betulaceae","family_zh":"桦木科","iucn":"LC","langs":71,"desc_zh":"垂枝桦（学名：Betula pendula），也称欧洲银桦、疣枝桦、疣皮桦、阿尔泰桦等，为桦木科桦木属的植物。分布于欧洲、西西伯利亚以及中国大陆的新疆等地，生长于海拔500米至2,000米的地区，多生在河滩、山谷、山脚湿润地带和向阳的石山坡，目前尚未由人工引种栽培。 垂枝桦为芬兰的国树。","desc_en":"Betula pendula, commonly known as silver birch, warty birch, European white birch, or East Asian white birch, is a species of tree in the family Betulaceae, native to Europe and parts of Asia, though in southern Europe, it is only found at higher altitudes.","img":"images/450.jpg","thumb":"images/t/450.jpg","file":"Betula pendula Finland.jpg","ar":1.333,"py":"chuizhihua czh","cr_by":"Percita at Flickr","cr_lic":"CC BY-SA 2.0","cr_licurl":"https://creativecommons.org/licenses/by-sa/2.0","habit":"乔木","origin":["亚洲","欧洲"]},{"id":451,"zh":"欧洲角树","en":"Carpinus betulus","sci":"Carpinus betulus","order_en":"Fagales","order_zh":"壳斗目","family_en":"Betulaceae","family_zh":"桦木科","iucn":"LC","langs":61,"desc_zh":"欧洲角树（学名：Carpinus betulus）是桦树桦木科的一种，原产于西亚和中欧、东欧和南欧，包括英格兰南部。它需要温暖的气候才能良好地生长，并且只生长在海拔高达一千米的地方。它生长在与橡树的混合林中，或在山毛榉的某些地区。","desc_en":"Carpinus betulus, the European or common hornbeam, is a species of tree in the birch family Betulaceae, native to Western Asia and central, eastern, and southern Europe, including southern England.","img":"images/451.jpg","thumb":"images/t/451.jpg","file":"Brohmer-Berge-Rothemühl-24-10-2009-30.jpg","ar":0.75,"py":"ouzhoujiaoshu ozjs","cr_by":"Botaurus","cr_lic":"Public domain","cr_licurl":null,"habit":"乔木","origin":["亚洲","欧洲"]},{"id":452,"zh":"毛桦","en":"Betula pubescens","sci":"Betula pubescens","order_en":"Fagales","order_zh":"壳斗目","family_en":"Betulaceae","family_zh":"桦木科","iucn":"LC","langs":60,"desc_zh":"毛桦（拉丁语：Betula pubescens），又称毛白桦、欧洲白桦，是桦树的一种，原产地是北欧、冰岛、北亚、格陵兰岛。毛桦是一种落叶乔木，高约10至20米。毛桦是白桦的亲属物种，外表极为相似。","desc_en":"Betula pubescens (syn. Betula alba), commonly known as downy birch and also as moor birch, white birch, European white birch or hairy birch, is a species of deciduous tree, native and abundant throughout northern Europe and northern Asia, growing further north…","img":"images/452.jpg","thumb":"images/t/452.jpg","file":"Abedulpubescente.jpg","ar":0.75,"py":"maohua mh","cr_by":"Elfo del bosque","cr_lic":"CC BY-SA 3.0","cr_licurl":"https://creativecommons.org/licenses/by-sa/3.0","habit":"乔木","origin":null},{"id":453,"zh":"普通胡桃","en":"Juglans regia","sci":"Juglans regia","order_en":"Fagales","order_zh":"壳斗目","family_en":"Juglandaceae","family_zh":"胡桃科","iucn":"LC","langs":92,"desc_zh":"普通胡桃（学名：Juglans regia）又名波斯胡桃、英国胡桃、胡桃、核桃，是胡桃科胡桃属的植物，亦是最常见的胡桃的一种。在南北半球的温带地区广泛栽培。由于长期的人为栽培，其自然分布范围不详，据推测原产于巴尔干半岛到中国之间的区域。","desc_en":"Juglans regia, known by various common names including the common walnut, English walnut, or Persian walnut amongst other names, is a species of walnut. It is native to Eurasia in at least southwest and central Asia and southeast Europe, but its exact natural…","img":"images/453.jpg","thumb":"images/t/453.jpg","file":"Juglans regia Echte Walnussfrucht 1.jpg","ar":0.75,"py":"putonghutao ptht","cr_by":"Böhringer Friedrich","cr_lic":"CC BY-SA 2.5","cr_licurl":"https://creativecommons.org/licenses/by-sa/2.5","habit":null,"origin":["亚洲","欧洲"]},{"id":454,"zh":"长山核桃","en":"Carya illinoinensis","sci":"Carya illinoinensis","order_en":"Fagales","order_zh":"壳斗目","family_en":"Juglandaceae","family_zh":"胡桃科","iucn":"LC","langs":54,"desc_zh":"长山核桃（学名：Carya illinoinensis）是胡桃科山核桃属的一种植物。又称碧根果、美国山核桃、薄壳山核桃、胡桃。种子可食用。","desc_en":"The pecan ( pih-KAN, also US: pih-KAHN, PEE-kan, UK: PEE-kən; Carya illinoinensis) is a species of hickory native to the Southern United States and northern Mexico in the region of the Mississippi River. Originally native to the south-central U.S.","img":"images/454.jpg","thumb":"images/t/454.jpg","file":"Carya illinoinensis (pecan tree) 1 (24790682337).jpg","ar":0.775,"py":"changshanhetao csht","cr_by":"James St. John","cr_lic":"CC BY 2.0","cr_licurl":"https://creativecommons.org/licenses/by/2.0","habit":"乔木","origin":["北美洲"]},{"id":455,"zh":"黑胡桃","en":"Juglans nigra","sci":"Juglans nigra","order_en":"Fagales","order_zh":"壳斗目","family_en":"Juglandaceae","family_zh":"胡桃科","iucn":"LC","langs":43,"desc_zh":null,"desc_en":"Juglans nigra, the eastern American black walnut, is a species of deciduous tree in the walnut family, Juglandaceae, native to central and eastern North America, growing mostly in riparian zones.","img":"images/455.jpg","thumb":"images/t/455.jpg","file":"Black Walnut Juglans nigra Nut 2400px.jpg","ar":1.2,"py":"heihutao hht","cr_by":"Photo by and (c)2007 Derek Ramsey ( Ram-Man ). Location credit to the Chanticleer Garden.","cr_lic":"CC BY-SA 3.0","cr_licurl":"http://creativecommons.org/licenses/by-sa/3.0/","habit":"乔木","origin":["北美洲"]},{"id":456,"zh":"壮核桃","en":"Juglans cinerea","sci":"Juglans cinerea","order_en":"Fagales","order_zh":"壳斗目","family_en":"Juglandaceae","family_zh":"胡桃科","iucn":"EN","langs":29,"desc_zh":null,"desc_en":"Juglans cinerea, commonly known as butternut or white walnut, is a species of walnut native to the eastern United States and southeast Canada.","img":"images/456.jpg","thumb":"images/t/456.jpg","file":"Juglans cinerea 01.jpg","ar":1.333,"py":"zhuanghetao zht","cr_by":"Kristjan","cr_lic":"Public domain","cr_licurl":null,"habit":null,"origin":["北美洲"]},{"id":457,"zh":"香杨梅","en":"Myrica gale","sci":"Myrica gale","order_en":"Fagales","order_zh":"壳斗目","family_en":"Myricaceae","family_zh":"杨梅科","iucn":"LC","langs":38,"desc_zh":null,"desc_en":"Myrica gale is a species of flowering plant in the family Myricaceae native to cool temperate regions of Eurasia and North America. Common names include bog-myrtle, sweet gale, Dutch myrtle, and sweetgale.","img":"images/457.jpg","thumb":"images/t/457.jpg","file":"Gagelstrauch(Myrica gale)female.JPG","ar":1.333,"py":"xiangyangmei xym","cr_by":"Hajotthu","cr_lic":"CC BY 3.0","cr_licurl":"https://creativecommons.org/licenses/by/3.0","habit":null,"origin":["亚洲","北美洲"]},{"id":458,"zh":"木麻黄","en":"Casuarina equisetifolia","sci":"Casuarina equisetifolia","order_en":"Fagales","order_zh":"壳斗目","family_en":"Casuarinaceae","family_zh":"木麻黄科","iucn":"LC","langs":44,"desc_zh":"木麻黄（学名：Casuarina equisetifolia L.）为木麻黄科木麻黄属的植物。","desc_en":"Casuarina equisetifolia, commonly known as coastal she-oak, horsetail she-oak, ironwood, beach sheoak, beach casuarina, whistling tree or Australian pine is a species of flowering plant in the family Casuarinaceae and is native to Australia, New Guinea, Southe…","img":"images/458.jpg","thumb":"images/t/458.jpg","file":"Casuarina equesitifolia tree.jpg","ar":1.332,"py":"mumahuang mmh","cr_by":"Ethel Aardvark","cr_lic":"CC BY 3.0","cr_licurl":"https://creativecommons.org/licenses/by/3.0","habit":"乔木","origin":["亚洲","大洋洲"]},{"id":459,"zh":"黄瓜","en":"Cucumis sativus","sci":"Cucumis sativus","order_en":"Cucurbitales","order_zh":"葫芦目","family_en":"Cucurbitaceae","family_zh":"葫芦科","iucn":null,"langs":180,"desc_zh":"黄瓜（学名：Cucumis sativus）也称胡瓜、青瓜、刺瓜、瓜仔哖，属葫芦科黄瓜属植物。原生于亚洲中部，于3000年前在印度驯化，现在分布于全球各地，并且广泛分布于中国各地，是中国夏季主要蔬菜，且为温室产品之一。","desc_en":"The cucumber (Cucumis sativus) is a widely-cultivated creeping vine plant in the family Cucurbitaceae that bears cylindrical to spherical fruits, used as culinary vegetables.","img":"images/459.jpg","thumb":"images/t/459.jpg","file":"Cucumis sativus 0001.JPG","ar":1.333,"py":"huanggua hg","cr_by":"H. Zell","cr_lic":"CC BY-SA 3.0","cr_licurl":"https://creativecommons.org/licenses/by-sa/3.0","habit":"藤本","origin":["亚洲"]},{"id":460,"zh":"西瓜","en":"watermelon","sci":"Citrullus lanatus","order_en":"Cucurbitales","order_zh":"葫芦目","family_en":"Cucurbitaceae","family_zh":"葫芦科","iucn":null,"langs":176,"desc_zh":"西瓜 （学名：Citrullus lanatus），古亦称寒瓜，是葫芦科西瓜属的一种植物或其果实，原产于非洲，现世界多地有栽培。其植株为一年生匍匐蔓藤，叶形状裂为掌状。 西瓜的果实在植物学形态分类上属于一种特化的浆果，称为瓠果。其外皮光滑，呈绿色或黄色，且有深绿色的花纹，果瓤多汁，为红色或黄色，有黑色籽。","desc_en":"The watermelon (Citrullus lanatus) is a species of flowering plant in the family Cucurbitaceae, that has a large, edible fruit. It is a scrambling and trailing vine-like plant, and is widely cultivated worldwide, with more than 1,000 varieties.","img":"images/460.jpg","thumb":"images/t/460.jpg","file":"Watermelon-garden.jpg","ar":1.496,"py":"xigua xg","cr_by":"Kumon","cr_lic":"CC BY 2.0","cr_licurl":"https://creativecommons.org/licenses/by/2.0","habit":"藤本","origin":["非洲"]},{"id":461,"zh":"甜瓜","en":"Cucumis melo","sci":"Cucumis melo","order_en":"Cucurbitales","order_zh":"葫芦目","family_en":"Cucurbitaceae","family_zh":"葫芦科","iucn":null,"langs":118,"desc_zh":"甜瓜（学名：Cucumis melo）为葫芦科黄瓜属一年生平卧或攀援草本植物，果实为瓠果。甜瓜的起源地不明，亚洲中西部和非洲都曾被认为是甜瓜的主要遗传多样性中心。","desc_en":"Cucumis melo, also known as melon or true melon, is a species of Cucumis that has been developed into many cultivated varieties. The fruit is a pepo. The flesh is either sweet or bland, with or without an aroma, and the rind can be smooth (such as honeydew), r…","img":"images/461.jpg","thumb":"images/t/461.jpg","file":"Canteloupe and cross section.jpg","ar":1.844,"py":"tiangua tg","cr_by":"fir0002 flagstaffotos [at] gmail.com Canon 20D + Sigma 150mm f/2.8","cr_lic":"GFDL 1.2","cr_licurl":"http://www.gnu.org/licenses/old-licenses/fdl-1.2.html","habit":null,"origin":["亚洲","非洲"]},{"id":462,"zh":"苦瓜","en":"Momordica charantia","sci":"Momordica charantia","order_en":"Cucurbitales","order_zh":"葫芦目","family_en":"Cucurbitaceae","family_zh":"葫芦科","iucn":null,"langs":96,"desc_zh":"苦瓜（学名：Momordica charantia）又名凉瓜、半生瓜、癞葡萄、锦荔枝等，是葫芦科的热带和亚热带藤本植物。苦瓜原产于非洲。野生或半驯化的变种在史前时期遍布亚洲，很可能在东南亚被完全驯化。","desc_en":"Momordica charantia (commonly called bitter melon, gouya, cerassee, goya, bitter apple, bitter gourd, bitter squash, balsam-pear, karela, karavila and many more names listed below) is a tropical and subtropical vine of the family Cucurbitaceae, widely grown in…","img":"images/462.jpg","thumb":"images/t/462.jpg","file":"Feuilles de Margôzy.jpg","ar":0.75,"py":"kugua kg","cr_by":"Morenga01","cr_lic":"CC BY-SA 4.0","cr_licurl":"https://creativecommons.org/licenses/by-sa/4.0","habit":"藤本","origin":["亚洲","非洲"]},{"id":463,"zh":"葫芦","en":"Lagenaria siceraria","sci":"Lagenaria siceraria","order_en":"Cucurbitales","order_zh":"葫芦目","family_en":"Cucurbitaceae","family_zh":"葫芦科","iucn":null,"langs":93,"desc_zh":"葫芦（学名：Lagenaria siceraria），别称壶芦、扁蒲、蒲瓜、瓠子、匏仔、瓢箪、瓠瓜、匏、蒲子、长瓜、蒲仔、夜开花、葫芦蒲、地蒲、葫芦瓜等，是属于葫芦目葫芦科葫芦属的一种植物，它是爬藤植物，其果实也被称为葫芦。","desc_en":"Calabash (; Lagenaria siceraria), also known as bottle gourd, white-flowered gourd, long melon, birdhouse gourd, New Guinea bean, New Guinea butter bean, Tasmania bean, zucca melon and opo squash, is a vine which is grown for its fruit.","img":"images/463.jpg","thumb":"images/t/463.jpg","file":"Courge encore verte.jpg","ar":1.333,"py":"hulu hl","cr_by":"撮影者はカールおじさんです。","cr_lic":"CC BY-SA 3.0","cr_licurl":"http://creativecommons.org/licenses/by-sa/3.0/","habit":"藤本","origin":["非洲"]},{"id":464,"zh":"佛手瓜","en":"Sicyos edulis","sci":"Sicyos edulis","order_en":"Cucurbitales","order_zh":"葫芦目","family_en":"Cucurbitaceae","family_zh":"葫芦科","iucn":null,"langs":73,"desc_zh":"佛手瓜（学名：Sicyos edulis）是一种葫芦科刺果瓜属植物，又称菜肴梨（英语：chayote, vegetable pear）、合手瓜、合掌瓜、佛手、隼人瓜、拳头瓜、梨瓜等。原产于墨西哥、中美洲和西印度群岛，1915年传入中国，在江南一带有种植，以云南、浙江、福建、广东最多。台湾于1935年自日本引进种植。其藤尖称为龙须菜。 本种曾被归类于佛手瓜属（Sechium），但现已知佛手瓜属是刺果瓜属的异名。","desc_en":"Chayote (; previously placed in the obsolete genus Sechium, now in the genus Sicyos, as Sicyos edulis), also known as christophine, mirliton, güisquil, and choko, is an edible plant belonging to the gourd family, Cucurbitaceae.","img":"images/464.jpg","thumb":"images/t/464.jpg","file":"Sechium edule dsc07767.jpg","ar":1.333,"py":"foshougua fsg","cr_by":null,"cr_lic":"CC BY-SA 3.0","cr_licurl":"http://creativecommons.org/licenses/by-sa/3.0/","habit":null,"origin":["北美洲"]},{"id":465,"zh":"美洲南瓜","en":"Cucurbita pepo","sci":"Cucurbita pepo","order_en":"Cucurbitales","order_zh":"葫芦目","family_en":"Cucurbitaceae","family_zh":"葫芦科","iucn":"LC","langs":67,"desc_zh":"美洲南瓜（学名：Cucurbita pepo）是葫芦目葫芦科南瓜属的一种植物。主要种植于北美洲，有许多栽培品种，英文通常称为Squash。在亚洲最常见的品种为南瓜和西葫芦。 美洲南瓜在北美有数千年的人工栽培历史，最早可以追溯到西元前8750年墨西哥的瓦哈卡河谷，美国则是西元前4000年在密苏里州开始有纪录。。","desc_en":"Cucurbita pepo is a cultivated plant of the genus Cucurbita. It yields varieties of winter squash and pumpkin, but the most widespread varieties belong to the subspecies Cucurbita pepo subsp. pepo, called summer squash.","img":"images/465.png","thumb":"images/t/465.png","file":"Cucurbita pepo collage 1.png","ar":1.209,"py":"meizhounangua mzng","cr_by":"Various","cr_lic":"CC BY-SA 1.0","cr_licurl":"https://creativecommons.org/licenses/by-sa/1.0","habit":"藤本","origin":["欧洲"]},{"id":466,"zh":"冬瓜","en":"Wax gourd","sci":"Benincasa hispida","order_en":"Cucurbitales","order_zh":"葫芦目","family_en":"Cucurbitaceae","family_zh":"葫芦科","iucn":null,"langs":66,"desc_zh":"冬瓜（学名：Benincasa pruriens），又称东瓜（非正式）、白瓜、黄楷崧、白东瓜皮、白冬瓜、白瓜皮、白瓜子、地芝，属葫芦目葫芦科，是冬瓜属的唯一物种。是一年生蔓性草本植物。冬瓜原生于南亚及东南亚，后扩展至中国南部等亚洲地区，现在东亚和南亚地区广泛有栽培。","desc_en":"Benincasa hispida, the wax gourd, also called ash gourd, white gourd, winter gourd, winter melon, tallow gourd, ash pumpkin, dongah or Chinese preserving melon, is a species of vine. The wax gourd is native to South and Southeast Asia.","img":"images/466.jpg","thumb":"images/t/466.jpg","file":"सफेद कद्दू, राख लौकी, भोपाल 01.jpg","ar":1.333,"py":"donggua dg","cr_by":"Suyash.dwivedi","cr_lic":"CC BY-SA 4.0","cr_licurl":"https://creativecommons.org/licenses/by-sa/4.0","habit":"藤本","origin":["亚洲"]},{"id":467,"zh":"药西瓜","en":"Citrullus colocynthis","sci":"Citrullus colocynthis","order_en":"Cucurbitales","order_zh":"葫芦目","family_en":"Cucurbitaceae","family_zh":"葫芦科","iucn":null,"langs":57,"desc_zh":"药西瓜（学名：Citrullus colocynthis）是葫芦科西瓜属的一种攀缘藤本植物，原产于地中海盆地与亚洲部分地区，尤其是土耳其与努比亚。 药西瓜主要生长在沙漠地带。其与西瓜为同属植物，但药西瓜的果实与普通西瓜相比小而硬，且味苦，故又名苦西瓜。药西瓜种子可以食用，在西非被称为“埃古斯”，是当地饮食中的主要食材之一。 在阿拉伯半岛等地，药西瓜还是一种传统药材，可用作泻药、利尿剂等。","desc_en":"Citrullus colocynthis, with many common names including colocynth, bitter apple, bitter cucumber, vine of Sodom, or wild gourd, is a poisonous desert viny plant native to the Mediterranean Basin and West Asia, especially the Levant, Turkey (especially in regio…","img":"images/467.jpg","thumb":"images/t/467.jpg","file":"Citrullus colocynthis - Köhler–s Medizinal-Pflanzen-040.jpg","ar":0.75,"py":"yaoxigua yxg","cr_by":"Franz Eugen Köhler, Köhler's Medizinal-Pflanzen","cr_lic":"Public domain","cr_licurl":null,"habit":"藤本","origin":["亚洲","欧洲"]},{"id":468,"zh":"竹节秋海棠","en":"Begonia maculata","sci":"Begonia maculata","order_en":"Cucurbitales","order_zh":"葫芦目","family_en":"Begoniaceae","family_zh":"秋海棠科","iucn":null,"langs":16,"desc_zh":null,"desc_en":"Begonia maculata (maculata meaning \"spotted\"), the polka dot begonia, is a species of begonia native to southeast Brazil. It grows naturally in the understory of the Atlantic rainforest, with occurrences confirmed in the Brazilian states of Espírito Santo and…","img":"images/468.jpg","thumb":"images/t/468.jpg","file":"Begonia maculata3073316230.jpg","ar":0.666,"py":"zhujieqiuhaitang zjqht","cr_by":"Cliff from I now live in Arlington, VA (Outside Washington DC), USA","cr_lic":"CC BY 2.0","cr_licurl":"https://creativecommons.org/licenses/by/2.0","habit":null,"origin":["南美洲"]},{"id":469,"zh":"蟆叶秋海棠","en":"Begonia rex","sci":"Begonia rex","order_en":"Cucurbitales","order_zh":"葫芦目","family_en":"Begoniaceae","family_zh":"秋海棠科","iucn":null,"langs":16,"desc_zh":"尖蕊秋海棠（学名：Begonia rex）或紫叶秋海棠，为秋海棠科秋海棠属的植物。分布于印度、喜马拉雅山区、越南以及中国大陆的广西、贵州、云南等地，生长于海拔990米至1,100米的地区，一般生长在山沟岩石上和山沟密林中，目前已由人工引种栽培。","desc_en":"Begonia rex, the king begonia, fancy-leaf begonia, or painted-leaf begonia is a species of flowering plant in the family Begoniaceae. It's a rhizomatous begonia first brought to England from Assam, and documented in 1857.","img":"images/469.jpg","thumb":"images/t/469.jpg","file":"Begonia rex.jpg","ar":0.571,"py":"mayeqiuhaitang myqht","cr_by":"W.J. Hooker","cr_lic":"Public domain","cr_licurl":null,"habit":null,"origin":["亚洲"]},{"id":470,"zh":"秋海棠","en":"Begonia grandis","sci":"Begonia grandis","order_en":"Cucurbitales","order_zh":"葫芦目","family_en":"Begoniaceae","family_zh":"秋海棠科","iucn":null,"langs":15,"desc_zh":"秋海棠（学名：Begonia grandis），又名八香、无名断肠草、无名相思草（本草拾遗）、相思草、断肠花、八月春，是秋海棠科秋海棠属的植物。","desc_en":"Begonia grandis, the hardy begonia, is a species of flowering plant in the family Begoniaceae. This herbaceous perennial has alternate, simple leaves on arching stems.","img":"images/470.jpg","thumb":"images/t/470.jpg","file":"Begonia grandis 001.JPG","ar":1.333,"py":"qiuhaitang qht","cr_by":"User:SB_Johnny","cr_lic":"CC BY-SA 3.0","cr_licurl":"http://creativecommons.org/licenses/by-sa/3.0/","habit":"草本","origin":["北美洲"]},{"id":471,"zh":"豹耳秋海棠","en":"Begonia bowerae","sci":"Begonia bowerae","order_en":"Cucurbitales","order_zh":"葫芦目","family_en":"Begoniaceae","family_zh":"秋海棠科","iucn":null,"langs":14,"desc_zh":null,"desc_en":"Begonia bowerae, the eyelash begonia, is a species of flowering plant in the family Begoniaceae, native to Oaxaca and Chiapas states of Mexico. A popular houseplant, a number of cultivars are available.","img":"images/471.jpg","thumb":"images/t/471.jpg","file":"Begonia bowerae.JPG","ar":1.333,"py":"baoerqiuhaitang beqht","cr_by":"No machine-readable author provided. Mininain assumed (based on copyright claims).","cr_lic":"CC BY-SA 3.0","cr_licurl":"http://creativecommons.org/licenses/by-sa/3.0/","habit":null,"origin":["北美洲"]},{"id":472,"zh":"大红秋海棠","en":"Begonia coccinea","sci":"Begonia coccinea","order_en":"Cucurbitales","order_zh":"葫芦目","family_en":"Begoniaceae","family_zh":"秋海棠科","iucn":null,"langs":13,"desc_zh":null,"desc_en":"Begonia coccinea, the scarlet begonia, is a species of plant in the family Begoniaceae. It is native to the Atlantic Forest of Brazil.","img":"images/472.jpg","thumb":"images/t/472.jpg","file":"Gardenology.org-IMG 2097 rbgs11jan.jpg","ar":0.75,"py":"dahongqiuhaitang dhqht","cr_by":"Raffi Kojian","cr_lic":"CC BY-SA 3.0","cr_licurl":"https://creativecommons.org/licenses/by-sa/3.0","habit":null,"origin":["南美洲"]},{"id":473,"zh":"巧茶","en":"Catha edulis","sci":"Catha edulis","order_en":"Celastrales","order_zh":"卫矛目","family_en":"Celastraceae","family_zh":"卫矛科","iucn":"LC","langs":63,"desc_zh":"巧茶（学名：Catha edulis）为卫矛科巧茶属的植物，又名阿比西尼亚茶（Abyssinian tea）、埃塞俄比亚茶（Ethiopian tea）、索马里茶（Somali tea）、阿拉伯茶（Arabian tea）、也门茶、布希曼茶（Bushman's tea）、迷拉（miraa）、东非罂粟，或音译作卡塔叶、卡特草、加德树（khat/qat）或恰特草（chat），分布在热带非洲、埃塞俄比亚、阿拉伯半岛以及中国大陆的海南、广西等地…","desc_en":"Khat or qat (Catha edulis), also known as Bushman's tea, especially in South Africa, is a species of flowering plant in the family Celastraceae, and the sole species in genus Catha.","img":"images/473.jpg","thumb":"images/t/473.jpg","file":"Catha edulis.jpg","ar":1.333,"py":"qiaocha qc","cr_by":"User:Katpatuka","cr_lic":"Public domain","cr_licurl":null,"habit":"乔木","origin":["亚洲","非洲"]},{"id":474,"zh":"欧洲卫矛","en":"Euonymus europaeus","sci":"Euonymus europaeus","order_en":"Celastrales","order_zh":"卫矛目","family_en":"Celastraceae","family_zh":"卫矛科","iucn":"LC","langs":47,"desc_zh":"欧洲卫矛（学名：Euonymus europaeus）是卫矛属的一种落叶灌木或小乔木，原产于欧洲，后作为观赏植物引入世界其他地区。 其种加词“europaeus ”意为“欧洲的”。","desc_en":"Euonymus europaeus, the spindle, European spindle, or common spindle, is a species of flowering plant in the family Celastraceae, native to much of Europe, where it inhabits the edges of forest, hedges and gentle slopes, tending to thrive on nutrient-rich, cha…","img":"images/474.jpg","thumb":"images/t/474.jpg","file":"20131018Euonymus europaeus4.jpg","ar":1.333,"py":"ouzhouweimao ozwm","cr_by":"AnRo0002","cr_lic":"CC0","cr_licurl":"http://creativecommons.org/publicdomain/zero/1.0/deed.en","habit":"乔木","origin":["欧洲"]},{"id":475,"zh":"梅花草","en":"Grass-of-Parnassus","sci":"Parnassia palustris","order_en":"Celastrales","order_zh":"卫矛目","family_en":"Celastraceae","family_zh":"卫矛科","iucn":"LC","langs":47,"desc_zh":"梅花草（学名：Parnassia palustris）为卫矛科梅花草属下的一个种。与梅树外观相似得名。","desc_en":"Parnassia palustris, the marsh grass of Parnassus, northern grass-of-Parnassus, or just grass-of-Parnassus, and bog star, is a flowering plant in the staff-vine family Celastraceae. It is the county flower of Cumberland in England, and appears on its flag.","img":"images/475.jpg","thumb":"images/t/475.jpg","file":"Dettaglio - Droseraceae Parnassia palustris Lin. Erbario Frizzi Perugia n. 1964.jpg","ar":0.75,"py":"meihuacao mhc","cr_by":"Giuseppe Frizzi","cr_lic":"Public domain","cr_licurl":null,"habit":"藤本","origin":["欧洲"]},{"id":476,"zh":"冬青卫矛","en":"Euonymus japonicus","sci":"Euonymus japonicus","order_en":"Celastrales","order_zh":"卫矛目","family_en":"Celastraceae","family_zh":"卫矛科","iucn":null,"langs":30,"desc_zh":"冬青卫矛（学名：Euonymus japonicus）亦称绿篱卫矛、日本卫矛、正木等，为卫矛属植物。供观赏，常植为绿篱。","desc_en":"Euonymus japonicus (evergreen spindle or Japanese spindle) is a species of flowering plant in the family Celastraceae, native to Japan and Korea.","img":"images/476.jpg","thumb":"images/t/476.jpg","file":"Euonymus japonicus.flowers.jpg","ar":1.329,"py":"dongqingweimao dqwm","cr_by":null,"cr_lic":"CC BY-SA 3.0","cr_licurl":"http://creativecommons.org/licenses/by-sa/3.0/","habit":null,"origin":["亚洲"]},{"id":477,"zh":"阳桃","en":"Averrhoa carambola","sci":"Averrhoa carambola","order_en":"Oxalidales","order_zh":"酢浆草目","family_en":"Oxalidaceae","family_zh":"酢浆草科","iucn":"DD","langs":86,"desc_zh":"杨桃（学名：Averrhoa carambola）又称阳桃、洋桃、五敛子，古名苌楚、铫芅、刘杙。是酢浆草科洋桃属的常绿灌木或小乔木。原产于热带印度、印尼和斯里兰卡一带热带亚洲。闽人称为杨桃，因经大洋而来，广东人包括香港，亦称为洋桃。其果实大小约直径6-8厘米，可作食用，以水果或当料理的食材来吃，如沙拉、西式咸菜、蜜饯等，味道像梨。","desc_en":"Averrhoa carambola is a species of tree in the family Oxalidaceae native to tropical Southeast Asia; it has a number of common names, including carambola, star fruit and five-corner.","img":"images/477.jpg","thumb":"images/t/477.jpg","file":"Averrhoa carambola flowers.jpg","ar":1.333,"py":"yangtao yt","cr_by":"Tauʻolunga","cr_lic":"CC BY-SA 3.0","cr_licurl":"http://creativecommons.org/licenses/by-sa/3.0/","habit":"乔木","origin":["亚洲"]},{"id":478,"zh":"三敛","en":"Averrhoa bilimbi","sci":"Averrhoa bilimbi","order_en":"Oxalidales","order_zh":"酢浆草目","family_en":"Oxalidaceae","family_zh":"酢浆草科","iucn":null,"langs":65,"desc_zh":"三敛（学名：Averrhoa bilimbi）为酢浆草科阳桃属的植物。分布于热带亚洲包括马来西亚、印度以及广东、广西、台湾等地，生长于海拔120米至1,200米的地区，目前已由人工引种栽培。","desc_en":"Averrhoa bilimbi (commonly known as bilimbi, orkkaappuli, cucumber tree, or tree sorrel) is a fruit-bearing tree of the genus Averrhoa, family Oxalidaceae. It is native to the Maluku Islands and Sulawesi in Indonesia, and has become naturalised and is common t…","img":"images/478.jpg","thumb":"images/t/478.jpg","file":"Averrhoa bilimbi dsc03692.jpg","ar":0.75,"py":"sanlian sl","cr_by":"David Monniaux","cr_lic":"CC BY-SA 3.0","cr_licurl":"http://creativecommons.org/licenses/by-sa/3.0/","habit":"乔木","origin":["亚洲"]},{"id":479,"zh":"木薯","en":"cassava","sci":"Manihot esculenta","order_en":"Malpighiales","order_zh":"金虎尾目","family_en":"Euphorbiaceae","family_zh":"大戟科","iucn":null,"langs":117,"desc_zh":"木薯（学名：Manihot esculenta），又称树薯，是一种大戟科木薯属植物，原产于南美洲。广泛种植于尼日利亚、泰国、巴西、印度尼西亚等100多个国家或地区, 是全球第六大粮食作物, 也是第三大能量来源。","desc_en":"Manihot esculenta, commonly called cassava, manioc, or yuca (among numerous regional names), is a woody shrub of the spurge family, Euphorbiaceae, native to South America, from Brazil, Paraguay and parts of the Andes.","img":"images/479.jpg","thumb":"images/t/479.jpg","file":"Manihot esculenta dsc07325.jpg","ar":1.333,"py":"mushu ms","cr_by":"David Monniaux","cr_lic":"CC BY-SA 3.0","cr_licurl":"http://creativecommons.org/licenses/by-sa/3.0/","habit":"灌木","origin":["南美洲"]},{"id":480,"zh":"蓖麻","en":"Ricinus communis","sci":"Ricinus communis","order_en":"Malpighiales","order_zh":"金虎尾目","family_en":"Euphorbiaceae","family_zh":"大戟科","iucn":null,"langs":102,"desc_zh":"蓖麻（学名：Ricinus communis；英语：castor oil plant）是一种大戟科植物，是蓖麻属（Ricinus）下的唯一物种。","desc_en":"Ricinus communis, the castor bean or castor oil plant, is a species of perennial flowering plant in the spurge family, Euphorbiaceae. It is the sole species in the monotypic genus, Ricinus, and subtribe, Ricininae.","img":"images/480.jpg","thumb":"images/t/480.jpg","file":"Casterplant 03.jpg","ar":0.75,"py":"bima bm","cr_by":"Dvellakat","cr_lic":"CC BY-SA 4.0","cr_licurl":"https://creativecommons.org/licenses/by-sa/4.0","habit":"草本","origin":["亚洲","欧洲","非洲"]},{"id":481,"zh":"一品红","en":"Euphorbia pulcherrima","sci":"Euphorbia pulcherrima","order_en":"Malpighiales","order_zh":"金虎尾目","family_en":"Euphorbiaceae","family_zh":"大戟科","iucn":"LC","langs":81,"desc_zh":"一品红（学名：Euphorbia pulcherrima），又名为圣诞红、圣诞花，大戟科大戟属植物，在圣诞节用来摆设的著名红色花卉。大红大绿的叶片相间，外观色彩充满圣诞节的应景气氛，因而称为圣诞红。 那些被人认为是花朵的红色部份其实是苞叶，而真正的花是在叶束中间的部份。被栽培的品系的叶通常会被制成橙色、浅绿色、奶油色及大理石花纹，要达到这效果，在十月至圣诞节时，它们不可以在晚上被灯光照射。即使是少量灯光照亦会阻止其开「花」。","desc_en":"The poinsettia (; Euphorbia pulcherrima) is a commercially important flowering plant species of the diverse spurge family Euphorbiaceae. Indigenous to Mexico and Central America, the poinsettia was first described by Europeans in 1834.","img":"images/481.jpg","thumb":"images/t/481.jpg","file":"Euphorbia pulcherrima (Barlovento) 04.jpg","ar":1.333,"py":"yipinhong yph","cr_by":"Frank Vincentz","cr_lic":"CC BY-SA 3.0","cr_licurl":"http://creativecommons.org/licenses/by-sa/3.0/","habit":"乔木","origin":["欧洲","北美洲"]},{"id":482,"zh":"橡胶树","en":"Hevea brasiliensis","sci":"Hevea brasiliensis","order_en":"Malpighiales","order_zh":"金虎尾目","family_en":"Euphorbiaceae","family_zh":"大戟科","iucn":"LC","langs":65,"desc_zh":"橡胶树（学名：Hevea brasiliensis），又称为巴西橡胶树、巴西护谟树、帕拉橡胶树或三叶橡胶树，是大戟科橡胶树属的一种乔木，其树汁是天然橡胶主要的原材料，其木材亦可制作家具。 原产于南美洲亚马逊森林，印第安人称橡胶树为“cahuchu”或“caoutchou”，意为“流泪之树”。在已知的产胶植物中，橡胶树产胶量最高, 品质最好，当前全球99%以上的天然橡胶均来源于该树。","desc_en":"Hevea brasiliensis, the Pará rubber tree, sharinga tree, seringueira, or, most commonly, rubber tree or rubber plant, is a flowering plant belonging to the spurge family, Euphorbiaceae.","img":"images/482.jpg","thumb":"images/t/482.jpg","file":"Hevea brasiliensis - Köhler–s Medizinal-Pflanzen-071.jpg","ar":0.722,"py":"xiangjiaoshu xjs","cr_by":"Franz Eugen Köhler, Köhler's Medizinal-Pflanzen","cr_lic":"Public domain","cr_licurl":null,"habit":"乔木","origin":["南美洲"]},{"id":483,"zh":"麻疯树","en":"Barbados nut","sci":"Jatropha curcas","order_en":"Malpighiales","order_zh":"金虎尾目","family_en":"Euphorbiaceae","family_zh":"大戟科","iucn":"LC","langs":50,"desc_zh":"桐油树（学名：Jatropha curcas），又名麻风树、痲疯树、南洋油桐、黄肿树、假白榄等，为大戟科落叶灌木。其发源地在加勒比海的岛上，但葡萄牙商人把它引进了非洲和亚洲各地，现已分布在全世界的热带和亚热带地区。 桐油树的种仁含油率很高，达到40%以上，经过加工适用于生产生物柴油。在印度，桐油树被选为出产生物柴油的主要原料之一。 桐油树可生长在南北纬30度之间，在许多非洲国家被大量种植（如马里）。","desc_en":"Jatropha curcas is a species of flowering plant in the spurge family, Euphorbiaceae, that is native to the American tropics: Mexico, the Caribbean and Central and South America.","img":"images/483.jpg","thumb":"images/t/483.jpg","file":"Jatropha curcas1 henning.jpg","ar":0.786,"py":"mafengshu mfs","cr_by":null,"cr_lic":"CC BY-SA 2.5","cr_licurl":"https://creativecommons.org/licenses/by-sa/2.5","habit":"乔木","origin":["北美洲","南美洲"]},{"id":484,"zh":"泽漆","en":"Euphorbia helioscopia","sci":"Euphorbia helioscopia","order_en":"Malpighiales","order_zh":"金虎尾目","family_en":"Euphorbiaceae","family_zh":"大戟科","iucn":null,"langs":48,"desc_zh":"泽漆（学名：Euphorbia helioscopia）为大戟科大戟属的植物。","desc_en":"Euphorbia helioscopia, the sun spurge or madwoman's milk, is a species of flowering plant in the spurge family Euphorbiaceae. It is a herbaceous annual plant, native to most of Europe, northern Africa, and eastward through most of Asia.","img":"images/484.jpg","thumb":"images/t/484.jpg","file":"Euphorbia helioscopia –IMG 6077 01.jpg","ar":1,"py":"zeqi zq","cr_by":"Kızıl","cr_lic":"CC BY-SA 4.0","cr_licurl":"https://creativecommons.org/licenses/by-sa/4.0","habit":"草本","origin":["亚洲","欧洲","非洲"]},{"id":485,"zh":"铁海棠","en":"Euphorbia milii","sci":"Euphorbia milii","order_en":"Malpighiales","order_zh":"金虎尾目","family_en":"Euphorbiaceae","family_zh":"大戟科","iucn":"LC","langs":47,"desc_zh":"虎刺梅（学名：Euphorbia milii），又名麒麟花、铁海棠、万年刺，属大戟科大戟属，原产于马达加斯加。","desc_en":"Euphorbia milii, the crown-of-thorns, Christ plant or Christ's thorn, is a species of flowering plant in the spurge family, Euphorbiaceae, native to Madagascar.","img":"images/485.jpg","thumb":"images/t/485.jpg","file":"Euphorbia Milii flowers.jpg","ar":1.501,"py":"tiehaitang tht","cr_by":"Ezra Katz","cr_lic":"CC BY-SA 3.0","cr_licurl":"https://creativecommons.org/licenses/by-sa/3.0","habit":null,"origin":["非洲"]},{"id":486,"zh":"飞扬草","en":"Euphorbia hirta","sci":"Euphorbia hirta","order_en":"Malpighiales","order_zh":"金虎尾目","family_en":"Euphorbiaceae","family_zh":"大戟科","iucn":null,"langs":44,"desc_zh":"飞扬草（学名：Euphorbia hirta L.）为大戟科大戟属的植物。一年生草本，植株高10-40公分，全株具有乳汁，被毛。茎斜生或直立，被毛，淡红色至紫色。单叶对生，叶卵形至椭圆形，歪基，叶缘锯齿，被毛。大戟花序聚繖状排列，总苞宽钟状，单性花，雄花多数，无花被片，雌花1枚，柱头3裂，子房3室。蒴果。","desc_en":"Euphorbia hirta (sometimes called asthma-plant) is a pantropical weed, originating from the tropical regions of the Americas. It is a hairy herb that grows in open grasslands, roadsides and pathways.","img":"images/486.jpg","thumb":"images/t/486.jpg","file":"Hierba de la golondrina (Euphorbia hirta) I.jpg","ar":1,"py":"feiyangcao fyc","cr_by":"Juan Carlos Fonseca Mata","cr_lic":"CC BY-SA 4.0","cr_licurl":"https://creativecommons.org/licenses/by-sa/4.0","habit":"草本","origin":null},{"id":487,"zh":"毒疮树","en":"Hippomane mancinella","sci":"Hippomane mancinella","order_en":"Malpighiales","order_zh":"金虎尾目","family_en":"Euphorbiaceae","family_zh":"大戟科","iucn":"LC","langs":43,"desc_zh":"毒番石榴（学名：Hippomane mancinella），又名马疯大戟木，是一种属于大戟科乌桕族的乔木植物，原生于美国佛罗里达州、巴哈马群岛、加勒比海、中美洲及南美洲北部等新热带界地区，有剧毒。其纹理细密的黄褐色木材常被用来做家具。","desc_en":"The manchineel tree (Hippomane mancinella), also known as the tree of death, is a species of flowering plant in the spurge family (Euphorbiaceae). Its native range stretches from tropical southern North America to northern South America.","img":"images/487.jpg","thumb":"images/t/487.jpg","file":"Hippomane mancinella (fruit).jpg","ar":1.335,"py":"duchuangshu dcs","cr_by":"Hans Hillewaert","cr_lic":"CC BY-SA 3.0","cr_licurl":"https://creativecommons.org/licenses/by-sa/3.0","habit":"乔木","origin":["北美洲","南美洲"]},{"id":488,"zh":"石栗","en":"Aleurites moluccanus","sci":"Aleurites moluccanus","order_en":"Malpighiales","order_zh":"金虎尾目","family_en":"Euphorbiaceae","family_zh":"大戟科","iucn":"LC","langs":43,"desc_zh":"石栗（学名：Aleurites moluccanus）又名油桃、烛果树、黑桐油树、铁桐、油果、检果、海胡桃、南洋石栗、烛栗，为大戟科石栗属常绿阔叶乔木。","desc_en":"Aleurites moluccanus, commonly known as candlenut, Indian walnut or, in Hawaii, kukui, is a tree in the spurge family Euphorbiaceae. It grows to about 30 m (98 ft) tall and produces drupe fruit.","img":"images/488.jpg","thumb":"images/t/488.jpg","file":"Starr 020803-0119 Aleurites moluccana.jpg","ar":1.333,"py":"shili sl","cr_by":"Forest & Kim Starr","cr_lic":"CC BY 3.0","cr_licurl":"https://creativecommons.org/licenses/by/3.0","habit":"乔木","origin":null},{"id":489,"zh":"绿玉树","en":"Euphorbia tirucalli","sci":"Euphorbia tirucalli","order_en":"Malpighiales","order_zh":"金虎尾目","family_en":"Euphorbiaceae","family_zh":"大戟科","iucn":"LC","langs":41,"desc_zh":"绿玉树（学名：Euphorbia tirucalli），别称光棍树、绿珊瑚、青珊瑚、铁树、铁罗、龙骨树、神仙棒、乳葱树、白蚁树等，是大戟科大戟属植物。原产于非洲的地中海沿岸地区，现分布于香港、台湾澎湖列岛、海南、美国、马来西亚、印度、英国及法国等地。花期6-9月，果期7-11月。由于原产地环境干燥，叶片较早脱落以减少水分蒸发，故常呈无叶状态，外形貌似绿色玉石故得此名。","desc_en":"Euphorbia tirucalli (commonly known as Indian tree spurge, naked lady, pencil tree, pencil cactus, fire stick, aveloz or milk bush) is a tree native to Africa that grows in semi-arid tropical climates.","img":"images/489.jpg","thumb":"images/t/489.jpg","file":"Euphorbia tirucalli 'Sticks on Fire' Closeup 3264px.jpg","ar":1.333,"py":"lyushu lys","cr_by":"Photo by and (c)2006 Derek Ramsey ( Ram-Man ). Location credit to the Chanticleer Garden.","cr_lic":"CC BY-SA 3.0","cr_licurl":"http://creativecommons.org/licenses/by-sa/3.0/","habit":"多肉","origin":["非洲"]},{"id":490,"zh":"欧洲柏大戟","en":"Euphorbia cyparissias","sci":"Euphorbia cyparissias","order_en":"Malpighiales","order_zh":"金虎尾目","family_en":"Euphorbiaceae","family_zh":"大戟科","iucn":null,"langs":40,"desc_zh":"欧洲柏大戟（学名：Euphorbia cyparissias）是大戟科大戟属的一个种，原产欧洲和土耳其，于1860年代作为观赏植物引入北美洲。","desc_en":"Euphorbia cyparissias, the cypress spurge, is a species of plant in the genus Euphorbia. It is native to Europe and was introduced to North America in the 1860s as an ornamental plant.","img":"images/490.jpg","thumb":"images/t/490.jpg","file":"Euphorbia cyparissias in Avoriaz (1).jpg","ar":1,"py":"ouzhoubaidaji ozbdj","cr_by":"Krzysztof Golik","cr_lic":"CC BY-SA 4.0","cr_licurl":"https://creativecommons.org/licenses/by-sa/4.0","habit":null,"origin":["欧洲","北美洲"]},{"id":491,"zh":"扁桃大戟","en":"Euphorbia amygdaloides","sci":"Euphorbia amygdaloides","order_en":"Malpighiales","order_zh":"金虎尾目","family_en":"Euphorbiaceae","family_zh":"大戟科","iucn":null,"langs":37,"desc_zh":null,"desc_en":"Euphorbia amygdaloides, the wood spurge, is a species of flowering plant in the family Euphorbiaceae, native to woodland locations in Europe, Turkey and the Caucasus.","img":"images/491.jpg","thumb":"images/t/491.jpg","file":"Euphorbia amygdaloides 4 RF.jpg","ar":1.329,"py":"biantaodaji btdj","cr_by":"Robert Flogaus-Faust","cr_lic":"CC BY 4.0","cr_licurl":"https://creativecommons.org/licenses/by/4.0","habit":"乔木","origin":["亚洲","欧洲"]},{"id":492,"zh":"欧洲山杨","en":"Populus tremula","sci":"Populus tremula","order_en":"Malpighiales","order_zh":"金虎尾目","family_en":"Salicaceae","family_zh":"杨柳科","iucn":"LC","langs":93,"desc_zh":"欧洲山杨（学名：Populus tremula）是杨柳科杨属的植物。分布于欧洲、高加索、西伯利亚及中国的新疆等地，生长于海拔700米至2,300米的地区，一般生长在河谷和针叶林林缘。花期4月，果期5月。","desc_en":"Populus tremula (commonly called aspen, common aspen, Eurasian aspen, European aspen, or quaking aspen) is a species of poplar native to cool temperate regions of the Old World.","img":"images/492.jpg","thumb":"images/t/492.jpg","file":"Ospeholt i Hurdal.JPG","ar":0.667,"py":"ouzhoushanyang ozsy","cr_by":"Øyvind Holmstad","cr_lic":"CC BY-SA 4.0","cr_licurl":"https://creativecommons.org/licenses/by-sa/4.0","habit":null,"origin":null},{"id":493,"zh":"白柳","en":"Salix alba","sci":"Salix alba","order_en":"Malpighiales","order_zh":"金虎尾目","family_en":"Salicaceae","family_zh":"杨柳科","iucn":"LC","langs":83,"desc_zh":"白柳（学名：Salix alba）为杨柳科柳属的植物。原产于欧洲和亚洲中西部，后来移种到世界其他地区，生长于海拔40米至3,100米的地区，多生长在沿河生长。 其种加词“alba”意为“白色的”。","desc_en":"Salix alba, the white willow, is a species of willow native to Europe and western and Central Asia. The name derives from the white tone to the undersides of the leaves.","img":"images/493.jpg","thumb":"images/t/493.jpg","file":"2015-05-08 Büdingen Naturdenkmal 440.221 Silber-Weide - 0919.jpg","ar":0.667,"py":"bailiu bl","cr_by":"Sven Teschke","cr_lic":"CC BY-SA 3.0 de","cr_licurl":"https://creativecommons.org/licenses/by-sa/3.0/de/deed.en","habit":null,"origin":["亚洲","欧洲"]},{"id":494,"zh":"黑杨","en":"Populus nigra","sci":"Populus nigra","order_en":"Malpighiales","order_zh":"金虎尾目","family_en":"Salicaceae","family_zh":"杨柳科","iucn":"DD","langs":70,"desc_zh":"黑杨（学名：Populus nigra）是杨柳科杨属的植物。分布在西亚、欧洲、中亚、高加索、巴尔干以及中国大陆的新疆等地，生长于海拔50米至3,685米的地区，目前尚未由人工引种栽培。 其种加词“nigra”意为“黑色的，暗色的”。","desc_en":"Populus nigra, the black poplar, is a species of cottonwood poplar, the type species of section Aigeiros of the genus Populus, native to Europe, southwest and central Asia, and northwest Africa.","img":"images/494.jpg","thumb":"images/t/494.jpg","file":"Populus nigra.Italica.01.jpg","ar":0.75,"py":"heiyang hy","cr_by":"No machine-readable author provided. JoJan assumed (based on copyright claims).","cr_lic":"CC BY-SA 3.0","cr_licurl":"http://creativecommons.org/licenses/by-sa/3.0/","habit":null,"origin":["亚洲","欧洲","非洲"]},{"id":495,"zh":"银白杨","en":"Populus alba","sci":"Populus alba","order_en":"Malpighiales","order_zh":"金虎尾目","family_en":"Salicaceae","family_zh":"杨柳科","iucn":"LC","langs":69,"desc_zh":"银白杨（学名：Populus alba）通称白杨，为杨柳科杨属的植物。喜光，根系发达，木材轻软，可供观赏。 其种加词“alba”意为“白色的”。","desc_en":"Populus alba, commonly called silver poplar, silverleaf poplar, white poplar, or abele is a species of poplar, most closely related to the aspens (Populus sect. Populus).","img":"images/495.jpg","thumb":"images/t/495.jpg","file":"Populus alba, Czajecice, 20060812 1358.jpg","ar":0.75,"py":"yinbaiyang yby","cr_by":"Jakub Hałun","cr_lic":"CC BY-SA 3.0","cr_licurl":"http://creativecommons.org/licenses/by-sa/3.0/","habit":null,"origin":["亚洲","欧洲","非洲"]},{"id":496,"zh":"黄花柳","en":"Salix caprea","sci":"Salix caprea","order_en":"Malpighiales","order_zh":"金虎尾目","family_en":"Salicaceae","family_zh":"杨柳科","iucn":"LC","langs":67,"desc_zh":"黄花柳（学名：Salix caprea）是杨柳科柳属的植物。分布于欧洲、俄罗斯以及中国大陆的新疆等地，生长于海拔500米至3,100米的地区，多生长在山坡和林中，目前尚未由人工引种栽培。 白银色种（Salix caprea pendula）民间又名「银柳」，亦是经常用于插花。","desc_en":"Salix caprea, known as goat willow, pussy willow or great sallow, is a common species of willow native to Europe and western and central Asia.","img":"images/496.jpg","thumb":"images/t/496.jpg","file":"Salix caprea8.jpg","ar":1.333,"py":"huanghualiu hhl","cr_by":"Kurt Stüber [1]","cr_lic":"CC BY-SA 3.0","cr_licurl":"http://creativecommons.org/licenses/by-sa/3.0/","habit":null,"origin":["亚洲","欧洲"]},{"id":497,"zh":"垂柳","en":"Salix babylonica","sci":"Salix babylonica","order_en":"Malpighiales","order_zh":"金虎尾目","family_en":"Salicaceae","family_zh":"杨柳科","iucn":"DD","langs":66,"desc_zh":"垂柳（学名：Salix babylonica）是杨柳科柳属的植物。别名“垂枝柳”、“倒挂柳”、“倒插杨柳”。原产于中国北方，后沿着丝绸之路传到欧洲和亚洲其他地区。","desc_en":"Salix babylonica (Babylon willow or weeping willow; Chinese: 垂柳; pinyin: chuí liǔ) is a species of willow native to dry areas of northern China, Korea, Mongolia, Japan, and Siberia but cultivated for millennia elsewhere in Asia, being traded along the Silk Roa…","img":"images/497.jpg","thumb":"images/t/497.jpg","file":"(MHNT) Salix babylonica - Les Martels, Giroussens Tarn.jpg","ar":1.501,"py":"chuiliu cl","cr_by":"Didier Descouens","cr_lic":"CC BY-SA 4.0","cr_licurl":"https://creativecommons.org/licenses/by-sa/4.0","habit":null,"origin":["亚洲","欧洲"]},{"id":498,"zh":"香堇菜","en":"Viola odorata","sci":"Viola odorata","order_en":"Malpighiales","order_zh":"金虎尾目","family_en":"Violaceae","family_zh":"堇菜科","iucn":null,"langs":66,"desc_zh":"香堇菜（学名：Viola odorata）是堇菜科堇菜属的植物，原产于欧洲、北非和西亚。","desc_en":"Viola odorata is a species of flowering plant in the family Violaceae. The small hardy herbaceous perennial is commonly known as wood violet, sweet violet, English violet, common violet, florist's violet, or garden violet. The plant is native to Eurasia.","img":"images/498.jpg","thumb":"images/t/498.jpg","file":"20130407Viola odorata1.jpg","ar":0.75,"py":"xiangjincai xjc","cr_by":"AnRo0002","cr_lic":"CC0","cr_licurl":"http://creativecommons.org/publicdomain/zero/1.0/deed.en","habit":"草本","origin":["亚洲"]},{"id":499,"zh":"三色堇","en":"Viola tricolor","sci":"Viola tricolor","order_en":"Malpighiales","order_zh":"金虎尾目","family_en":"Violaceae","family_zh":"堇菜科","iucn":null,"langs":66,"desc_zh":"三色菫（学名：Viola tricolor；英语：wild pansy）是堇菜科堇菜属的一年生或短期多年生草本植物，又名三色堇菜（中国植物图鉴）、蝴蝶花、三色紫罗兰、人脸花、阿拉叶－尼勒－其其格（蒙语），在欧洲是常见的野花，也常栽培于公园中，是一种常见的园艺植物。三色菫也被引进北美，并在当地广泛繁衍。 三色菫以露天栽种为宜，无论花坛、庭园、盆栽皆适合。","desc_en":"Viola tricolor is a common European wild flower, growing as an annual or short-lived perennial. The species is also known as wild pansy, Johnny Jump up (though this name is also applied to similar species such as the yellow pansy), heartsease, heart's ease, he…","img":"images/499.jpg","thumb":"images/t/499.jpg","file":"20180612Viola tricolor2.jpg","ar":0.75,"py":"sansejin ssj","cr_by":"AnRo0002","cr_lic":"CC0","cr_licurl":"http://creativecommons.org/publicdomain/zero/1.0/deed.en","habit":"草本","origin":["欧洲"]},{"id":500,"zh":"大花三色堇","en":"Viola × wittrockiana","sci":"Viola ×wittrockiana","order_en":"Malpighiales","order_zh":"金虎尾目","family_en":"Violaceae","family_zh":"堇菜科","iucn":null,"langs":46,"desc_zh":"大花三色堇（学名：Viola ×wittrockiana）是堇菜科堇菜属的一个园艺栽培种，由三色堇与阿尔泰堇菜、黄堇菜杂交而得。大花三色堇诞生于1800年代的北欧，1820年代之后快速得到普及，成为主要园艺花卉之一。大花三色堇较为耐寒，主要在冬春开花。大花三色堇也是思想自由的象征之一。 大花三色堇染色体数是2n = 44–52，通常为2n = 48。","desc_en":"The garden pansy (Viola × wittrockiana) is a type of polychromatic large-flowered hybrid plant cultivated as a garden flower. It is derived by hybridization from several species in the section Melanium (\"the pansies\") of the genus Viola, particularly V.","img":"images/500.jpg","thumb":"images/t/500.jpg","file":"Pansy Viola x wittrockiana Red Cultivar Flower 2000px.jpg","ar":0.818,"py":"dahuasansejin dhssj","cr_by":"Photo by and (c)2008 Derek Ramsey ( Ram-Man )","cr_lic":"GFDL 1.2","cr_licurl":"http://www.gnu.org/licenses/old-licenses/fdl-1.2.html","habit":null,"origin":["亚洲","欧洲"]},{"id":501,"zh":"野生堇菜","en":"Viola arvensis","sci":"Viola arvensis","order_en":"Malpighiales","order_zh":"金虎尾目","family_en":"Violaceae","family_zh":"堇菜科","iucn":null,"langs":43,"desc_zh":"野生堇菜（学名：Viola arvensis）为菫菜科堇菜属下的一个种。","desc_en":"Viola arvensis is a species of violet known by the common name field pansy. It is native to Europe, western Asia, and North Africa, and it is known on other continents as an introduced species and a weed of disturbed and cultivated areas.","img":"images/501.jpg","thumb":"images/t/501.jpg","file":"(MHNT) Viola arvensis - White flower.jpg","ar":1.201,"py":"yeshengjincai ysjc","cr_by":"Didier Descouens","cr_lic":"CC BY-SA 4.0","cr_licurl":"https://creativecommons.org/licenses/by-sa/4.0","habit":null,"origin":["亚洲","欧洲","非洲"]},{"id":502,"zh":"Viola riviniana","en":"Viola riviniana","sci":"Viola riviniana","order_en":"Malpighiales","order_zh":"金虎尾目","family_en":"Violaceae","family_zh":"堇菜科","iucn":null,"langs":41,"desc_zh":null,"desc_en":"Viola riviniana, the common dog-violet, is a species of flowering plant in the family Violaceae, native to Eurasia and Africa. It is also called wood violet and dog violet. It inhabits woodland edges, grassland and shady hedge banks.","img":"images/502.jpg","thumb":"images/t/502.jpg","file":"Viola riviniana and canina.jpg","ar":0.616,"py":"","cr_by":"Carl Axel Magnus Lindman","cr_lic":"Public domain","cr_licurl":null,"habit":"草本","origin":["亚洲","非洲"]},{"id":503,"zh":"百香果","en":"Passiflora edulis","sci":"Passiflora edulis","order_en":"Malpighiales","order_zh":"金虎尾目","family_en":"Passifloraceae","family_zh":"西番莲科","iucn":null,"langs":81,"desc_zh":"西番莲（学名：Passiflora edulis），又名百香果、热情果、鸡蛋果、时计果，产于美洲的热带及亚热带地区。原产于巴西，巴拉圭，1610年间传入欧洲。西番莲的果汁常被用作香料，加在其他果汁中。","desc_en":"Passiflora edulis, commonly known as passion fruit, is a vine species of passion flower native to southern Brazil, through Paraguay, and northern Argentina.","img":"images/503.jpg","thumb":"images/t/503.jpg","file":"Markisa madu manis seperti kamu.jpg","ar":1.333,"py":"baixiangguo bxg","cr_by":"Rarani","cr_lic":"CC BY-SA 4.0","cr_licurl":"https://creativecommons.org/licenses/by-sa/4.0","habit":"藤本","origin":["南美洲"]},{"id":504,"zh":"蓝花西番莲","en":"Blue Passionflower","sci":"Passiflora caerulea","order_en":"Malpighiales","order_zh":"金虎尾目","family_en":"Passifloraceae","family_zh":"西番莲科","iucn":null,"langs":44,"desc_zh":"蓝花西番莲（学名：Passiflora caerulea），别名巴西耐寒西番莲，原产于巴西，是多年生草本藤本植物，比其他种类的西番莲有更高的耐寒性。本种因花色艳而成为园艺植物，各茎节上均长有卷须以作攀爬，是十分受欢迎的观花园艺植物。","desc_en":"Passiflora caerulea, the blue passionflower, bluecrown passionflower or common passion flower, is a species of flowering plant in the family Passifloraceae. It is native to South America and has been introduced elsewhere.","img":"images/504.jpg","thumb":"images/t/504.jpg","file":"Blue passion flower (Passiflora caerulea).jpg","ar":1.333,"py":"lanhuaxifanlian lhxfl","cr_by":"K. Chaikovska (Kate Chkv)","cr_lic":"CC BY 4.0","cr_licurl":"https://creativecommons.org/licenses/by/4.0","habit":"藤本","origin":["南美洲"]},{"id":505,"zh":"毛西番莲","en":"Passiflora foetida","sci":"Passiflora foetida","order_en":"Malpighiales","order_zh":"金虎尾目","family_en":"Passifloraceae","family_zh":"西番莲科","iucn":null,"langs":37,"desc_zh":"毛西番莲（学名：Passiflora foetida）又称为野百香果、龙珠果、小时计果，为二年生蔓性草本植物，常见于广西、广东、云南和台湾。常逸生于海拔120-500米草坡、灌丛中，为泛热带杂草。全株密生长毛，因而得其有「毛」之名，常藉卷须攀附其他作物上，为危害农地作物的杂草。其具有食虫习性，苞片被证实可以捕猎小型昆虫并将其消化吸收用于果实发育，但鉴于其食虫目的更倾向于保护果实，故也有学者将其归为捕虫植物。","desc_en":"Passiflora foetida (common names: stinking passionflower, wild maracuja, bush passion fruit, wild water lemon, stoneflower, love-in-a-mist, or running pop) is a species of passion flower that is native to the southwestern United States (southern Texas and Ariz…","img":"images/505.jpg","thumb":"images/t/505.jpg","file":"Passiflora foetida fruits.JPG","ar":1.499,"py":"maoxifanlian mxfl","cr_by":"B.navez","cr_lic":"CC BY-SA 3.0","cr_licurl":"https://creativecommons.org/licenses/by-sa/3.0","habit":"藤本","origin":["北美洲","南美洲"]},{"id":506,"zh":"美国西番莲","en":"Passiflora incarnata","sci":"Passiflora incarnata","order_en":"Malpighiales","order_zh":"金虎尾目","family_en":"Passifloraceae","family_zh":"西番莲科","iucn":null,"langs":36,"desc_zh":null,"desc_en":"Passiflora incarnata, commonly known as maypop, purple passionflower, true passionflower, wild apricot, and wild passion vine, is a fast-growing perennial vine with climbing or trailing stems.","img":"images/506.jpg","thumb":"images/t/506.jpg","file":"Gc2 passiflora incarnata.jpg","ar":0.713,"py":"meiguoxifanlian mgxfl","cr_by":"Hans-Simon Holtzbecker","cr_lic":"Public domain","cr_licurl":null,"habit":"藤本","origin":null},{"id":507,"zh":"山竹","en":"Garcinia mangostana","sci":"Garcinia mangostana","order_en":"Malpighiales","order_zh":"金虎尾目","family_en":"Clusiaceae","family_zh":"藤黄科","iucn":null,"langs":84,"desc_zh":"山竹（学名：Garcinia mangostana），又名莽吉柿、芒翕、山竺、山竹子、倒捻子、凤果，热带常绿乔木，为藤黄科藤黄属下的一个种。原产于马来群岛中的巽他群岛和摩鹿加群岛，由于盛产于南洋热带地区，有“热带果后”之称。在马来西亚、新加坡和泰国，榴梿和山竹被视为“夫妻果”，故此相对于称为「果王」的榴梿而言，山竹就是「果后」。","desc_en":"Mangosteen (Garcinia mangostana), also called mangostan or purple mangosteen, is a tropical evergreen tree with edible fruit native to the Malay Peninsula and Borneo. It has been cultivated extensively in tropical Asia since ancient times.","img":"images/507.jpg","thumb":"images/t/507.jpg","file":"Berthe Hoola van Nooten48.jpg","ar":0.668,"py":"shanzhu sz","cr_by":"Berthe Hoola van Nooten (1817-1892), Pieter De Pannemaeker (lithographer)","cr_lic":"Public domain","cr_licurl":null,"habit":"乔木","origin":["亚洲"]},{"id":508,"zh":"藤黄果","en":"Garcinia indica","sci":"Garcinia indica","order_en":"Malpighiales","order_zh":"金虎尾目","family_en":"Clusiaceae","family_zh":"藤黄科","iucn":"VU","langs":32,"desc_zh":null,"desc_en":"Garcinia indica, a plant in the mangosteen family (Clusiaceae), commonly known as kokum, is a fruit-bearing tree that has culinary, pharmaceutical, and industrial uses.","img":"images/508.jpg","thumb":"images/t/508.jpg","file":"Garcinia indica - fruits, seeds, pulp and rinds.jpg","ar":1.336,"py":"tenghuangguo thg","cr_by":"Subray Hegde","cr_lic":"CC BY 1.0","cr_licurl":"https://creativecommons.org/licenses/by/1.0","habit":"乔木","origin":null},{"id":509,"zh":"藤黄果","en":"Garcinia gummi-gutta","sci":"Garcinia gummi-gutta","order_en":"Malpighiales","order_zh":"金虎尾目","family_en":"Clusiaceae","family_zh":"藤黄科","iucn":"LC","langs":28,"desc_zh":null,"desc_en":"Garcinia gummi-gutta is a tropical species of Garcinia native to India. Common names include Garcinia cambogia (a former scientific name), as well as brindle berry, and Malabar tamarind. It is a tree which grows up to 20 metres tall.","img":"images/509.jpg","thumb":"images/t/509.jpg","file":"കുടപ്പുളി.JPG","ar":1.12,"py":"tenghuangguo thg","cr_by":"Vssun at ml.wikipedia","cr_lic":"CC BY-SA 3.0","cr_licurl":"https://creativecommons.org/licenses/by-sa/3.0","habit":"乔木","origin":["亚洲"]},{"id":510,"zh":"大叶藤黄","en":"Garcinia xanthochymus","sci":"Garcinia xanthochymus","order_en":"Malpighiales","order_zh":"金虎尾目","family_en":"Clusiaceae","family_zh":"藤黄科","iucn":"LC","langs":23,"desc_zh":"大叶藤黄（学名：Garcinia xanthochymus），又名蛋树，为金丝桃科藤黄属的热带常绿乔木植物。","desc_en":"Garcinia xanthochymus, the false mangosteen, gamboge, yellow mangosteen, Himalayan Garcinia, or sour mangosteen is a species of mangosteen native to India, Nepal, Bangladesh, Indochina, and southern China at elevations of 0 – 1400 meters.","img":"images/510.jpg","thumb":"images/t/510.jpg","file":"Mysore Gambot.jpg","ar":1.505,"py":"dayetenghuang dyth","cr_by":"jayeshpatil912","cr_lic":"CC BY 2.0","cr_licurl":"https://creativecommons.org/licenses/by/2.0","habit":null,"origin":["亚洲"]},{"id":511,"zh":"贯叶连翘","en":"Hypericum perforatum","sci":"Hypericum perforatum","order_en":"Malpighiales","order_zh":"金虎尾目","family_en":"Hypericaceae","family_zh":"金丝桃科","iucn":null,"langs":78,"desc_zh":"贯叶连翘（学名：Hypericum perforatum）， 又名贯叶金丝桃、圣约翰草（St John's wort），金丝桃科金丝桃属植物，是欧美的常用草药。主要用于妇女调经，亦有宁神、平衡情绪的作用。临床上发现对抑郁症患者有疗效，对癌症无效，，也一般不推荐用于调经。","desc_en":"Hypericum perforatum, commonly known as St. John's wort (sometimes perforate St. John's wort or common St. John's wort), is a flowering plant in the family Hypericaceae.","img":"images/511.jpg","thumb":"images/t/511.jpg","file":"(MHNT) Hypericum perforatum flower and buttons.jpg","ar":0.734,"py":"guanyelianqiao gylq","cr_by":"Didier Descouens","cr_lic":"CC BY-SA 4.0","cr_licurl":"https://creativecommons.org/licenses/by-sa/4.0","habit":"草本","origin":["亚洲","欧洲","非洲"]},{"id":512,"zh":"Hypericum maculatum","en":"Hypericum maculatum","sci":"Hypericum maculatum","order_en":"Malpighiales","order_zh":"金虎尾目","family_en":"Hypericaceae","family_zh":"金丝桃科","iucn":null,"langs":27,"desc_zh":null,"desc_en":"Hypericum maculatum, commonly known as imperforate St John's-wort, or spotted St. Johnswort, is a species of perennial herbaceous flowering plant in the family Hypericaceae. It is native to Europe and Western Asia where it grows in moist meadows.","img":"images/512.jpg","thumb":"images/t/512.jpg","file":"Geflecktes Johanniskraut.jpg","ar":0.75,"py":"","cr_by":null,"cr_lic":"CC BY-SA 3.0","cr_licurl":"http://creativecommons.org/licenses/by-sa/3.0/","habit":"草本","origin":["亚洲","欧洲"]},{"id":513,"zh":"红茄苳","en":"Rhizophora mucronata","sci":"Rhizophora mucronata","order_en":"Malpighiales","order_zh":"金虎尾目","family_en":"Rhizophoraceae","family_zh":"红树科","iucn":"LC","langs":32,"desc_zh":"红茄苳（学名：Rhizophora mucronata），为红树科红树属下的一个种。","desc_en":"Rhizophora mucronata (loop-root mangrove, red mangrove or Asiatic mangrove) is a species of mangrove found on coasts and river banks in East Africa and the Indo-Pacific region.","img":"images/513.jpg","thumb":"images/t/513.jpg","file":"Rhizophora mucronata Propagules.jpg","ar":0.75,"py":"hongqiedong hqd","cr_by":"self","cr_lic":"CC BY-SA 3.0","cr_licurl":"https://creativecommons.org/licenses/by-sa/3.0","habit":null,"origin":["亚洲","非洲"]},{"id":514,"zh":"芹叶牻牛儿苗","en":"Erodium cicutarium","sci":"Erodium cicutarium","order_en":"Geraniales","order_zh":"牻牛儿苗目","family_en":"Geraniaceae","family_zh":"牻牛儿苗科","iucn":null,"langs":54,"desc_zh":"芹叶牻牛儿苗（学名：Erodium cicutarium）为牻牛儿苗科牻牛儿苗属下的一个种。","desc_en":"Erodium cicutarium, also known as common stork's-bill, redstem filaree, redstem stork's bill or pinweed, is a herbaceous annual – or in warm climates, biennial – member of the family Geraniaceae of flowering plants.","img":"images/514.jpg","thumb":"images/t/514.jpg","file":"Erodium cicutarium flowers - Keila.jpg","ar":1.501,"py":"qinyemangniuermiao qymnem","cr_by":"Ivar Leidus","cr_lic":"CC BY-SA 4.0","cr_licurl":"https://creativecommons.org/licenses/by-sa/4.0","habit":"草本","origin":["亚洲","非洲","北美洲"]},{"id":515,"zh":"汉荭鱼腥草","en":"Geranium robertianum","sci":"Geranium robertianum","order_en":"Geraniales","order_zh":"牻牛儿苗目","family_en":"Geraniaceae","family_zh":"牻牛儿苗科","iucn":null,"langs":53,"desc_zh":"汉荭鱼腥草（学名：Geranium robertianum）为牻牛儿苗科老鹳草属的植物。分布于朝鲜、日本、地中海、中亚、西伯利亚、欧洲、台湾以及中国大陆的西南、华东、华中等地，生长于海拔900米至3,200米的地区，常生于山地林下、沟坡、岩壁和路旁。","desc_en":"Geranium robertianum, commonly known as herb-robert or, in North America, as Robert's geranium, is a species of cranesbill that is widespread throughout the northern hemisphere and introduced to some countries in the southern.","img":"images/515.jpg","thumb":"images/t/515.jpg","file":"(MHNT) Geranium robertianum - blossom and bud.jpg","ar":0.918,"py":"hanhongyuxingcao hhyxc","cr_by":"Didier Descouens","cr_lic":"CC BY-SA 4.0","cr_licurl":"https://creativecommons.org/licenses/by-sa/4.0","habit":"草本","origin":["北美洲"]},{"id":516,"zh":"森林老鹳草","en":"Geranium sylvaticum","sci":"Geranium sylvaticum","order_en":"Geraniales","order_zh":"牻牛儿苗目","family_en":"Geraniaceae","family_zh":"牻牛儿苗科","iucn":null,"langs":46,"desc_zh":null,"desc_en":"Geranium sylvaticum, the wood cranesbill or woodland geranium, is a species of hardy flowering plant in the family Geraniaceae, native to Europe and northern Turkey.","img":"images/516.jpg","thumb":"images/t/516.jpg","file":"Geranium sylvaticum (1).JPG","ar":0.8,"py":"senlinlaoguancao sllgc","cr_by":"Philipp Weigell","cr_lic":"CC BY 3.0","cr_licurl":"https://creativecommons.org/licenses/by/3.0","habit":null,"origin":["欧洲"]},{"id":517,"zh":"血红老鹳草","en":"Geranium sanguineum","sci":"Geranium sanguineum","order_en":"Geraniales","order_zh":"牻牛儿苗目","family_en":"Geraniaceae","family_zh":"牻牛儿苗科","iucn":null,"langs":39,"desc_zh":null,"desc_en":"Geranium sanguineum, common name bloody crane's-bill or bloody geranium, is a species of hardy flowering herbaceous perennial plant in the cranesbill family Geraniaceae. It is the county flower of Northumberland.","img":"images/517.jpg","thumb":"images/t/517.jpg","file":"(MHNT) Geranium sanguineum - Flower and leaf - Les Martels, Giroussens Tarn.jpg","ar":1.49,"py":"xuehonglaoguancao xhlgc","cr_by":"Didier Descouens","cr_lic":"CC BY-SA 4.0","cr_licurl":"https://creativecommons.org/licenses/by-sa/4.0","habit":"草本","origin":null},{"id":518,"zh":"草原老鹳草","en":"Geranium pratense","sci":"Geranium pratense","order_en":"Geraniales","order_zh":"牻牛儿苗目","family_en":"Geraniaceae","family_zh":"牻牛儿苗科","iucn":null,"langs":37,"desc_zh":"草地老鹳草（学名：Geranium pratense）是牻牛儿苗科老鹳草属的植物。分布在欧洲、内蒙古、西伯利亚、中亚山地以及中国大陆的内蒙古、东北、山西、西藏、西北、四川等地，生长于海拔390米至4,000米的地区，一般生长在山地草甸或亚高山草甸。","desc_en":"Geranium pratense, the meadow crane's-bill or meadow geranium, is a species of flowering plant in the family Geraniaceae, native to Europe and Asia. Forming a clump up to 1 m (3.","img":"images/518.jpg","thumb":"images/t/518.jpg","file":"00 1916 Blüten und Früchte des Wiesen-Storchschnabel.jpg","ar":0.75,"py":"caoyuanlaoguancao cylgc","cr_by":"W. Bulach","cr_lic":"CC BY-SA 4.0","cr_licurl":"https://creativecommons.org/licenses/by-sa/4.0","habit":"草本","origin":["亚洲","欧洲"]},{"id":519,"zh":"丁香","en":"clove","sci":"Syzygium aromaticum","order_en":"Myrtales","order_zh":"桃金娘目","family_en":"Myrtaceae","family_zh":"桃金娘科","iucn":null,"langs":128,"desc_zh":"丁子香或丁香（学名：Syzygium aromaticum）是桃金娘科蒲桃属的一个种，也叫鸡舌香、鸡舌。Clove来自拉丁文「CLAVUS」，代表「钉子」的意思，因外型像小钉。原产于印度尼西亚的摩鹿加群岛（MOLUCCAS），摩鹿加又被称为香料岛(SPICE ISLAND)。当地传统习俗在婴儿诞生时，栽种一棵丁香树苗，母亲们由丁香树成长荣枯，最为其子女命运的前兆。","desc_en":"Cloves are the aromatic flower buds of a tree in the family Myrtaceae, Syzygium aromaticum (). They are native to the Maluku Islands, or Moluccas, in Indonesia, and are commonly used as a spice, flavoring, or fragrance in consumer products, such as toothpaste,…","img":"images/519.jpg","thumb":"images/t/519.jpg","file":"Cengkih.jpg","ar":0.75,"py":"dingxiang dx","cr_by":"Bayu Nugroho","cr_lic":"CC BY-SA 4.0","cr_licurl":"https://creativecommons.org/licenses/by-sa/4.0","habit":"乔木","origin":["亚洲"]},{"id":520,"zh":"番石榴","en":"Psidium guajava","sci":"Psidium guajava","order_en":"Myrtales","order_zh":"桃金娘目","family_en":"Myrtaceae","family_zh":"桃金娘科","iucn":"LC","langs":87,"desc_zh":"番石榴（学名：Psidium guajava），是桃金娘科番石榴属的常绿灌木或小乔木植物。因多籽类似石榴而得名，在台湾又俗称为芭乐，源自台湾话的林菝仔；客家语则称朳仔；中山、顺德一带、澳门粤语又称花稔等。番石榴原产于加勒比地区、中美洲和南美洲，因适应性良好而广泛栽培于热带及亚热带地区。可用播种、扦插、空中压条及嫁接等方法繁殖。各国因种植、加工和出口番石榴的果实而形成规模庞大的果树产业。2023年番石榴全球总产量达到79.","desc_en":"Psidium guajava, the common guava, yellow guava, lemon guava, or apple guava is an evergreen shrub or small tree native to South America. It is pollinated by insects. When cultivated, it is pollinated mainly by the common honey bee, Apis mellifera.","img":"images/520.jpg","thumb":"images/t/520.jpg","file":"Apple Guava.jpg","ar":1.333,"py":"fanshiliu fsl","cr_by":"Fuadsyazwan ( talk )","cr_lic":"Public domain","cr_licurl":null,"habit":"乔木","origin":["南美洲"]},{"id":521,"zh":"阎浮树","en":"Syzygium cumini","sci":"Syzygium cumini","order_en":"Myrtales","order_zh":"桃金娘目","family_en":"Myrtaceae","family_zh":"桃金娘科","iucn":"LC","langs":76,"desc_zh":"阎浮树（学名：Syzygium cumini；梵语：जम्बूफलम् (Jambu)），为桃金娘科蒲桃属，又名肯氏蒲桃、海南蒲桃（广州植物志、海南植物志）、堇宝莲、乌墨、鸟木、乌楣、印度蓝莓、印度黑莓等，分布于南亚及东南亚。","desc_en":"Syzygium cumini, also known as Java plum, Malabar plum, jambolan, black plum, jamun, jambul, is an evergreen tropical tree in the flowering plant family Myrtaceae, and favored for its fruit, timber, and ornamental value.","img":"images/521.jpg","thumb":"images/t/521.jpg","file":"Syzygium cumini plant.jpg","ar":0.562,"py":"yanfushu yfs","cr_by":"কামরুল ইসলাম শাহীন","cr_lic":"CC BY-SA 4.0","cr_licurl":"https://creativecommons.org/licenses/by-sa/4.0","habit":"乔木","origin":["亚洲"]},{"id":522,"zh":"多香果","en":"Pimenta dioica","sci":"Pimenta dioica","order_en":"Myrtales","order_zh":"桃金娘目","family_en":"Myrtaceae","family_zh":"桃金娘科","iucn":"LC","langs":56,"desc_zh":"多香果又名全香子、众香子、牙买加胡椒，是桃金娘科多香果属的一种植物，原产于美洲的热带地区。干燥未成熟的果实与叶子可以做为香料使用，由于果实具有丁香、胡椒、肉桂、肉荳蔻等多种香料的味道，所以被称为多香果。","desc_en":"Allspice, also known as Jamaica pepper, myrtle pepper, pimenta, or pimento, is the dried unripe berry of Pimenta dioica, a midcanopy tree native to the Greater Antilles, southern Mexico, and Central America, now cultivated in many warm parts of the world.","img":"images/522.jpg","thumb":"images/t/522.jpg","file":"Piment Flower.jpg","ar":1.333,"py":"duoxiangguo dxg","cr_by":"Christian Blue","cr_lic":"CC BY-SA 4.0","cr_licurl":"https://creativecommons.org/licenses/by-sa/4.0","habit":"乔木","origin":["北美洲"]},{"id":523,"zh":"香桃木","en":"common myrtle","sci":"Myrtus communis","order_en":"Myrtales","order_zh":"桃金娘目","family_en":"Myrtaceae","family_zh":"桃金娘科","iucn":"LC","langs":54,"desc_zh":"香桃木（学名：Myrtus communis），别名为香桃金娘、甜香桃木，原生于南欧至地中海沿岸一带，为桃金娘科香桃木属下的一个种。常绿灌木，分布于中南半岛、菲律宾、日本、印度、斯里兰卡、马来西亚、印度尼西亚、台湾以及中国的福建、广东、广西、云南、贵州、湖南，生长于海拨50－900米的地区，常见于丘陵坡地，是一种酸性土壤指示植物。","desc_en":"Myrtus communis, the common myrtle or true myrtle, is a species of flowering plant in the myrtle family Myrtaceae. It is an evergreen shrub native to southern Europe, North Africa, Western Asia, Macaronesia, and the Indian subcontinent, and also cultivated.","img":"images/523.jpg","thumb":"images/t/523.jpg","file":"Illustration Myrtus communis0.jpg","ar":0.597,"py":"xiangtaomu xtm","cr_by":null,"cr_lic":"Public domain","cr_licurl":null,"habit":"乔木","origin":["亚洲","欧洲","非洲"]},{"id":524,"zh":"拟爱神木","en":"Plinia cauliflora","sci":"Plinia cauliflora","order_en":"Myrtales","order_zh":"桃金娘目","family_en":"Myrtaceae","family_zh":"桃金娘科","iucn":"LC","langs":52,"desc_zh":"拟爱神木（英语：Jabuticaba，学名：Plinia cauliflora，旧学名：Myrciaria cauliflora）为热带、亚热带水果，原产地为南美洲巴西米纳斯吉拉斯。抗虫害和适应环境力强，其果实也叫木葡萄、树葡萄，成熟的外表为紫色，果肉呈白色略透明状，内有种籽一粒，不坚硬，容易咬碎。果肉味道清甜、果皮味酸。可以连籽一同食用。其含有较丰富的维生素C等营养物质及磷、镁等微量元素。","desc_en":"A jaboticaba () or jabuticaba (Portuguese: [ʒabutʃiˈkabɐ]) is a round, edible fruit produced by a jaboticaba tree (Plinia cauliflora), also known as Brazilian grapetree.","img":"images/524.jpg","thumb":"images/t/524.jpg","file":"Flor de jaboticaba (Myrciaria cauliflora) CASA de mamâ, Sao Paulo.jpg","ar":1.333,"py":"niaishenmu nasm","cr_by":"mauroguanandi","cr_lic":"CC BY 2.0","cr_licurl":"https://creativecommons.org/licenses/by/2.0","habit":"乔木","origin":["南美洲"]},{"id":525,"zh":"蓝桉","en":"Eucalyptus globulus","sci":"Eucalyptus globulus","order_en":"Myrtales","order_zh":"桃金娘目","family_en":"Myrtaceae","family_zh":"桃金娘科","iucn":"LC","langs":49,"desc_zh":"蓝桉（学名：Eucalyptus globulus，英语：Blue gum）为桃金娘科桉属下的一个种，又名蓝胶尤加利，是一种高大常绿乔木，为澳大利亚东南边的特有种，也是澳大利亚栽培最广泛的树种之一。一般可长到30—50米（98—164英尺）。历史记录中最高可达101米（331英尺）。自然分布范围包括塔斯马尼亚和维多利亚州南部。在金岛和弗林德斯岛上也有孤立的蓝桉。","desc_en":"Eucalyptus globulus, commonly known as southern blue gum or blue gum, is a species of flowering plant in the family Myrtaceae. It is a tall, evergreen tree endemic to southeastern Australia.","img":"images/525.jpg","thumb":"images/t/525.jpg","file":"Eucalyptus globulus globulus buds.jpg","ar":1.51,"py":"lanan la","cr_by":"Murray Fagg","cr_lic":"CC BY 3.0 au","cr_licurl":"https://creativecommons.org/licenses/by/3.0/au/deed.en","habit":"乔木","origin":["大洋洲"]},{"id":526,"zh":"南美棯","en":"Feijoa sellowiana","sci":"Feijoa sellowiana","order_en":"Myrtales","order_zh":"桃金娘目","family_en":"Myrtaceae","family_zh":"桃金娘科","iucn":"LC","langs":49,"desc_zh":"费约果（Feijoa）、凤梨番石榴、非油果、菠萝番石榴。原产地在中南美洲哥伦比亚、 乌拉圭和阿根廷北部，盛产于纽西兰，外皮深绿色，内部类似芭乐。含丰富维他命C。其常用名“斐济果”为早期缺乏正式中文译名期间，民间根据其发音类似“斐济”而产生的俗说讹传。费约果得名于葡萄牙植物学家若昂·达·席尔瓦·费约（João da Silva Feijó）。","desc_en":"Feijoa sellowiana, also known as Acca sellowiana (O.Berg) Burret, is a species of flowering plant in the myrtle family, Myrtaceae. It is the only species in the genus Feijoa.","img":"images/526.jpg","thumb":"images/t/526.jpg","file":"Acca sellowiana Fruit MHNT Fronton.jpg","ar":1.316,"py":"nanmeiren nmr","cr_by":"Didier Descouens","cr_lic":"CC BY-SA 4.0","cr_licurl":"https://creativecommons.org/licenses/by-sa/4.0","habit":"乔木","origin":["南美洲"]},{"id":527,"zh":"蒲桃","en":"Syzygium jambos","sci":"Syzygium jambos","order_en":"Myrtales","order_zh":"桃金娘目","family_en":"Myrtaceae","family_zh":"桃金娘科","iucn":"LC","langs":48,"desc_zh":"蒲桃（学名：Syzygium jambos），也叫做葡桃、香果、风鼓、水石榴、水葡萄、南无撵布、攘波，桃金娘科的常绿乔木。东南亚原产的果树。海南地区有野生蒲桃，华南地区有人工栽培的蒲桃。 蒲桃可以作为防风植物栽培，果实可以食用。泰文说法又称为「古代莲雾」。味道闻起来像莱姆，吃起来清香微甜，属于季节交替才会出现的水果。","desc_en":"Syzygium jambos is a species of rose apple originating in Southeast Asia and occurring widely elsewhere, having been introduced as an ornamental and fruit tree.","img":"images/527.jpg","thumb":"images/t/527.jpg","file":"Syzygium jambos.JPG","ar":0.75,"py":"putao pt","cr_by":"B.Navez","cr_lic":"CC BY-SA 3.0","cr_licurl":"http://creativecommons.org/licenses/by-sa/3.0/","habit":"乔木","origin":["亚洲"]},{"id":528,"zh":"马六甲蒲桃","en":"Syzygium malaccense","sci":"Syzygium malaccense","order_en":"Myrtales","order_zh":"桃金娘目","family_en":"Myrtaceae","family_zh":"桃金娘科","iucn":"LC","langs":46,"desc_zh":"马六甲蒲桃（学名：Syzygium malaccense），又名马来莲雾，为桃金娘科蒲桃属的植物。分布在越南、马来西亚、印度、老挝以及云南、台湾等地，生长于海拔150米至600米的地区。","desc_en":"Syzygium malaccense is a species of flowering tree native to tropical Asia and Australia. It was cultivated from prehistoric times by the Austronesian peoples and introduced deliberately to remote Oceania as canoe plants.","img":"images/528.jpg","thumb":"images/t/528.jpg","file":"Pommerac trinidad.jpg","ar":1.052,"py":"maliujiaputao mljpt","cr_by":"Justinisaacs","cr_lic":"CC BY-SA 3.0","cr_licurl":"https://creativecommons.org/licenses/by-sa/3.0","habit":"乔木","origin":["亚洲","大洋洲"]},{"id":529,"zh":"莲雾","en":"Syzygium samarangense","sci":"Syzygium samarangense","order_en":"Myrtales","order_zh":"桃金娘目","family_en":"Myrtaceae","family_zh":"桃金娘科","iucn":"LC","langs":41,"desc_zh":"莲雾（星马称作水蓊）（学名：Syzygium samarangense），又名天桃，别名辇（niǎn）雾、琏雾、爪哇蒲桃、日落果、洋蒲桃，是桃金娘科的常绿小乔木。因其果实长得像铃铛，亦称为bell-fruit。原产于马来群岛，在马来西亚、印尼、菲律宾、广东和台湾普遍栽培，是一种主要生长于热带的水果。 莲雾的颜色有暗红色、淡红色、绿色、白色。","desc_en":"Syzygium samarangense is a species of flowering plant in the family Myrtaceae, native to an area that includes the Greater Sunda Islands, Malay Peninsula, and the Andaman and Nicobar Islands, but introduced in prehistoric times to a wider area and now widely c…","img":"images/529.jpg","thumb":"images/t/529.jpg","file":"Lainwu (Wax apple) diamond P00063.JPG","ar":0.933,"py":"lianwu lw","cr_by":"Taiwan7007","cr_lic":"CC BY 3.0","cr_licurl":"https://creativecommons.org/licenses/by/3.0","habit":null,"origin":null},{"id":530,"zh":"苏里南苦樱桃","en":"Eugenia uniflora","sci":"Eugenia uniflora","order_en":"Myrtales","order_zh":"桃金娘目","family_en":"Myrtaceae","family_zh":"桃金娘科","iucn":"LC","langs":40,"desc_zh":"红果仔（学名：Eugenia uniflora），也称棱果蒲桃，是原产于热带南美洲东海岸、苏里南至巴西南部地区，以及巴拉圭和乌拉圭的部份地区的热带植物，常绿灌木或小乔木，桃金娘科，叶对生，长卵形，近无柄，长2.5-5厘米，先端渐尖，浓绿油亮。新生幼叶褐红色，具有观赏性。花白色，单生于花柄之顶；稍芳香；萼片4枚。果实扁圆形，熟时红色，最后转为深紫色。熟果口味特别，不具有苦味或刺激性。","desc_en":"Eugenia uniflora is a flowering plant in the family Myrtaceae, native to tropical South America's east coast, ranging from Suriname, French Guiana to southern Brazil, as well as Uruguay and parts of Paraguay and Argentina.","img":"images/530.jpg","thumb":"images/t/530.jpg","file":"Pitanga (do tupi 'ybapytanga) no pampa gaúcho 02.jpg","ar":0.75,"py":"sulinankuyingtao slnkyt","cr_by":"Bageense","cr_lic":"CC BY-SA 4.0","cr_licurl":"https://creativecommons.org/licenses/by-sa/4.0","habit":"乔木","origin":["南美洲"]},{"id":531,"zh":"赤桉","en":"Eucalyptus camaldulensis","sci":"Eucalyptus camaldulensis","order_en":"Myrtales","order_zh":"桃金娘目","family_en":"Myrtaceae","family_zh":"桃金娘科","iucn":"NT","langs":37,"desc_zh":"赤桉（学名：Eucalyptus camaldulensis）为桃金娘科桉属下的一个种。","desc_en":"Eucalyptus camaldulensis, commonly known as river red gum, is a flowering plant in the family Myrtaceae, and is endemic to Australia. It is a tree with smooth white or cream-coloured bark, lance-shaped or curved adult leaves, flower buds in groups of seven or…","img":"images/531.jpg","thumb":"images/t/531.jpg","file":"700 yr red river gum.jpg","ar":0.667,"py":"chian ca","cr_by":"fir0002 flagstaffotos [at] gmail.com Canon 20D + Tamron 28-75mm f/2.8","cr_lic":"GFDL 1.2","cr_licurl":"http://www.gnu.org/licenses/old-licenses/fdl-1.2.html","habit":"乔木","origin":["大洋洲"]},{"id":532,"zh":"野牡丹","en":"Melastoma malabathricum","sci":"Melastoma malabathricum","order_en":"Myrtales","order_zh":"桃金娘目","family_en":"Melastomataceae","family_zh":"野牡丹科","iucn":null,"langs":23,"desc_zh":"野牡丹（学名：Melastoma candidum，英文名称：Common Melastoma），为野牡丹科野牡丹属的植物，又名山石榴（台湾）、大金香炉、猪古稔（广东）、豹牙兰（云南）、豹牙郎木、倒罐草、九螺子花、高脚稔、罐罐草、地茄、金石榴、老虎杆、埔笔仔、痢疾罐、毛张口、小毛香、王不留行、王不留。原产于巴西，分布于台湾、印度以及中国大陆的广东、福建、广西、云南等地，生长于海拔120米的地区，多生长于山坡松林下和开朗的灌草丛中。","desc_en":"Melastoma malabathricum, known also as Malabar melastome, Indian rhododendron, Singapore rhododendron, planter's rhododendron and senduduk, is a flowering plant in the family Melastomataceae native to Seychelles, tropical and subtropical Asia to Australia and…","img":"images/532.jpg","thumb":"images/t/532.jpg","file":"Khloongkhleeng.jpg","ar":1.333,"py":"yemudan ymd","cr_by":"User:Loma","cr_lic":"CC BY-SA 3.0","cr_licurl":"https://creativecommons.org/licenses/by-sa/3.0","habit":null,"origin":["亚洲","大洋洲"]},{"id":533,"zh":"粉苞酸脚杆","en":"Medinilla magnifica","sci":"Medinilla magnifica","order_en":"Myrtales","order_zh":"桃金娘目","family_en":"Melastomataceae","family_zh":"野牡丹科","iucn":null,"langs":21,"desc_zh":null,"desc_en":"Medinilla magnifica, the showy medinilla or rose grape, is a species of epiphytic flowering plant, of the family Melastomataceae, native to the Philippines.","img":"images/533.jpg","thumb":"images/t/533.jpg","file":"Medinilla magnifica flor.jpg","ar":1.333,"py":"fenbaosuanjiaogan fbsjg","cr_by":"No machine-readable author provided. Alberto Salguero assumed (based on copyright claims).","cr_lic":"CC BY-SA 3.0","cr_licurl":"http://creativecommons.org/licenses/by-sa/3.0/","habit":null,"origin":["亚洲"]},{"id":534,"zh":"米氏野牡丹","en":"Miconia calvescens","sci":"Miconia calvescens","order_en":"Myrtales","order_zh":"桃金娘目","family_en":"Melastomataceae","family_zh":"野牡丹科","iucn":"LC","langs":17,"desc_zh":"米氏野牡丹（学名：Miconia calvescens）是大叶野牡丹属下的一个种，原产于墨西哥到南美洲。 并且入侵到了包括夏威夷在内的世界各地，同时也是世界百大外来入侵种之一。 米氏野牡丹一年数次开花，同时结果。大型圆锥花絮。花呈白色到粉色不等，其花香会吸引许多鸟类和动物前来觅食。紫色果实直接约半厘米，一颗米氏野牡丹的两朵花一个结果季可产出二十万颗种子。","desc_en":"Miconia calvescens, the velvet tree, miconia, or bush currant, is a species of flowering plant in the family Melastomataceae. It is native to Mexico and Central and South America and it has become one of the world's most invasive species.","img":"images/534.jpg","thumb":"images/t/534.jpg","file":"Starr Miconia calvescens0.jpg","ar":0.75,"py":"mishiyemudan msymd","cr_by":null,"cr_lic":"Copyrighted free use","cr_licurl":null,"habit":"乔木","origin":["北美洲","南美洲"]},{"id":535,"zh":"毛野牡丹藤","en":"Siete cueros","sci":"Clidemia hirta","order_en":"Myrtales","order_zh":"桃金娘目","family_en":"Melastomataceae","family_zh":"野牡丹科","iucn":null,"langs":16,"desc_zh":"毛野牡丹藤（学名：Clidemia hirta）为野牡丹科毛野牡丹属下的一个种。国际自然保护联盟物种存续委员会的入侵物种专家小组（ISSG）列为世界百大外来入侵种。","desc_en":"Miconia crenata, commonly called Koster's curse, is a species of plant in the family Melastomataceae. It is a perennial shrub native to Central and South America, including the Caribbean, and it has been introduced to tropical parts of the Indian Ocean, Asia,…","img":"images/535.jpg","thumb":"images/t/535.jpg","file":"Starr 030729-0107 Clidemia hirta.jpg","ar":1.333,"py":"maoyemudanteng mymdt","cr_by":"Forest & Kim Starr","cr_lic":"CC BY 3.0","cr_licurl":"https://creativecommons.org/licenses/by/3.0","habit":"灌木","origin":["亚洲","北美洲","南美洲","大洋洲"]},{"id":536,"zh":"Medinilla speciosa","en":"Medinilla speciosa","sci":"Medinilla speciosa","order_en":"Myrtales","order_zh":"桃金娘目","family_en":"Melastomataceae","family_zh":"野牡丹科","iucn":null,"langs":14,"desc_zh":null,"desc_en":"Medinilla speciosa is a perennial epiphytic plant in the genus Medinilla of the family Melastomataceae.","img":"images/536.jpg","thumb":"images/t/536.jpg","file":"Medinilla speciosa - par Mickael Schauli.jpg","ar":0.665,"py":"","cr_by":"Mickaël Schauli","cr_lic":"CC BY-SA 4.0","cr_licurl":"https://creativecommons.org/licenses/by-sa/4.0","habit":"草本","origin":null},{"id":537,"zh":"须喙绢木","en":"Miconia tomentosa","sci":"Miconia tomentosa","order_en":"Myrtales","order_zh":"桃金娘目","family_en":"Melastomataceae","family_zh":"野牡丹科","iucn":"LC","langs":13,"desc_zh":null,"desc_en":"Miconia tomentosa is a species of shrub or treelet in the family Melastomataceae. It is native to South America.","img":"images/537.jpg","thumb":"images/t/537.jpg","file":"Miconia tomentosa - Flickr - Tarciso Leão (3).jpg","ar":0.75,"py":"xuhuijuanmu xhjm","cr_by":"Tarciso Leão from Saint Paul, MN","cr_lic":"CC BY 2.0","cr_licurl":"https://creativecommons.org/licenses/by/2.0","habit":"灌木","origin":["南美洲"]},{"id":538,"zh":"柳兰","en":"Chamaenerion angustifolium","sci":"Chamaenerion angustifolium","order_en":"Myrtales","order_zh":"桃金娘目","family_en":"Onagraceae","family_zh":"柳叶菜科","iucn":null,"langs":61,"desc_zh":"柳兰（学名：Epilobium angustifolium ssp. angustifolium）为柳叶菜科柳叶菜属下的一个亚种。它原产于整个北半球温带地区，包括大部分北方针叶林。","desc_en":"Chamaenerion angustifolium is a perennial herbaceous flowering plant in the willowherb family, Onagraceae. It is known in North America as fireweed and in the British Isles as both fireweed and rosebay willowherb.","img":"images/538.jpg","thumb":"images/t/538.jpg","file":"Chamerion angustifolium - Fireweed 01.jpg","ar":0.668,"py":"liulan ll","cr_by":"Zeynel Cebeci","cr_lic":"CC BY-SA 4.0","cr_licurl":"https://creativecommons.org/licenses/by-sa/4.0","habit":"草本","origin":["欧洲","北美洲"]},{"id":539,"zh":"月见草","en":"Oenothera biennis","sci":"Oenothera biennis","order_en":"Myrtales","order_zh":"桃金娘目","family_en":"Onagraceae","family_zh":"柳叶菜科","iucn":null,"langs":43,"desc_zh":"月见草（学名：Oenothera biennis）为柳叶菜科月见草属下的一个种。原产于北美洲的东部和中部，分布范围从纽芬兰岛西部到艾伯塔省，东南到佛罗里达州，西南到德克萨斯州，并且在其他温带和亚热带地区广泛归化。","desc_en":"Oenothera biennis, the common evening-primrose, is a species of flowering plant in the family Onagraceae, native to eastern and central North America, from Newfoundland west to Alberta, southeast to Florida, and southwest to Texas, and widely naturalized elsew…","img":"images/539.jpg","thumb":"images/t/539.jpg","file":"Dettaglio - Onagrarieae Oenothera biennis Lam. Erbario Frizzi Perugia n. 1995.jpg","ar":0.471,"py":"yuejiancao yjc","cr_by":"Giuseppe Frizzi","cr_lic":"Public domain","cr_licurl":null,"habit":null,"origin":["北美洲"]},{"id":540,"zh":"柳叶菜","en":"Epilobium hirsutum","sci":"Epilobium hirsutum","order_en":"Myrtales","order_zh":"桃金娘目","family_en":"Onagraceae","family_zh":"柳叶菜科","iucn":"LC","langs":39,"desc_zh":"柳叶菜（学名：Epilobium hirsutum）也称鸡脚参、水朝阳花，为柳叶菜科柳叶菜属下的一个种。","desc_en":"Epilobium hirsutum is a flowering plant belonging to the willowherb genus Epilobium in the family Onagraceae. It is commonly known as the great willowherb, great hairy willowherb or hairy willowherb.","img":"images/540.jpg","thumb":"images/t/540.jpg","file":"Dettaglio - Onagrarieae Epilobium hirsutum Lin. Erbario Frizzi Perugia n. 1179.jpg","ar":0.549,"py":"liuyecai lyc","cr_by":"Giuseppe Frizzi","cr_lic":"Public domain","cr_licurl":null,"habit":null,"origin":null},{"id":541,"zh":"水珠草","en":"Circaea lutetiana","sci":"Circaea lutetiana","order_en":"Myrtales","order_zh":"桃金娘目","family_en":"Onagraceae","family_zh":"柳叶菜科","iucn":null,"langs":34,"desc_zh":null,"desc_en":"Circaea lutetiana, known as broad-leaved enchanter's nightshade, is a plant in the evening primrose family, Onagraceae. The genus name comes from the enchantress Circe of Greek mythology and the specific designation is derived from Lutetia, the Latin name for…","img":"images/541.jpg","thumb":"images/t/541.jpg","file":"Dettaglio - Onagrarieae Circaea lutetiana Lam. Erbario Frizzi Perugia G. 1985.jpg","ar":0.396,"py":"shuizhucao szc","cr_by":"Giuseppe Frizzi","cr_lic":"Public domain","cr_licurl":null,"habit":null,"origin":null},{"id":542,"zh":"石榴","en":"pomegranate","sci":"Punica granatum","order_en":"Myrtales","order_zh":"桃金娘目","family_en":"Lythraceae","family_zh":"千屈菜科","iucn":"LC","langs":135,"desc_zh":"石榴（学名：Punica granatum），或称安石榴，千屈菜科灌木。","desc_en":"The pomegranate (Punica granatum) is a fruit-bearing, deciduous shrub in the family Lythraceae, subfamily Punicoideae, that grows to between 1.5–5 metres (5–16 ft) tall.","img":"images/542.jpg","thumb":"images/t/542.jpg","file":"Punica granatum 004.JPG","ar":1.333,"py":"shiliu sl","cr_by":"H. Zell","cr_lic":"CC BY-SA 3.0","cr_licurl":"https://creativecommons.org/licenses/by-sa/3.0","habit":"灌木","origin":["亚洲","欧洲","非洲","北美洲","南美洲"]},{"id":543,"zh":"散沫花","en":"Lawsonia inermis","sci":"Lawsonia inermis","order_en":"Myrtales","order_zh":"桃金娘目","family_en":"Lythraceae","family_zh":"千屈菜科","iucn":"LC","langs":72,"desc_zh":"散沫花（学名：Lawsonia inermis），又名指甲花、海蒳，是千屈菜科散沫花属下唯一一个种。原产于非洲、南亚及澳大拉西亚的热带与亚热带地区，在澳大拉西亚主要分布于北部的半干旱地带。 植株为大灌木或小乔木，株高约二至六公尺。叶对生，无毛，近无柄，叶缘全缘，叶形为椭圆形至宽披针形，叶长1.5-5.0公分，叶宽0.5-2公分，叶先端为渐尖形。","desc_en":"Lawsonia inermis, also known as hina, the henna tree, the mignonette tree, and the Egyptian privet, is a flowering plant and one of the only two species of the genus Lawsonia, with the other being Lawsonia odorata. It is used as a traditional medicinal plant.","img":"images/543.jpg","thumb":"images/t/543.jpg","file":"Lawsonia inermis (3709419835).jpg","ar":1.333,"py":"sanmohua smh","cr_by":"Dinesh Valke from Thane, India","cr_lic":"CC BY-SA 2.0","cr_licurl":"https://creativecommons.org/licenses/by-sa/2.0","habit":"乔木","origin":null},{"id":544,"zh":"千屈菜","en":"Lythrum salicaria","sci":"Lythrum salicaria","order_en":"Myrtales","order_zh":"桃金娘目","family_en":"Lythraceae","family_zh":"千屈菜科","iucn":"LC","langs":50,"desc_zh":"千屈菜（学名：Lythrum salicaria），为千屈菜科千屈菜属下的一个植物种，又名「千禧花」。被列入「世界百大外来入侵种」之一。","desc_en":"Lythrum salicaria or purple-loosestrife is a flowering plant belonging to the family Lythraceae. It should not be confused with other plants sharing the name loosestrife that are members of the genus Lysimachia in the family Primulaceae.","img":"images/544.jpg","thumb":"images/t/544.jpg","file":"00 1804 Gewöhnlicher Blutweiderich - Lythrum.jpg","ar":0.667,"py":"qianqucai qqc","cr_by":"W. Bulach","cr_lic":"CC BY-SA 4.0","cr_licurl":"https://creativecommons.org/licenses/by-sa/4.0","habit":"草本","origin":["亚洲","欧洲","非洲","大洋洲"]},{"id":545,"zh":"菱角","en":"Trapa natans","sci":"Trapa natans","order_en":"Myrtales","order_zh":"桃金娘目","family_en":"Lythraceae","family_zh":"千屈菜科","iucn":"LC","langs":50,"desc_zh":"菱角是多种千屈菜科菱亚科菱属（学名：Trapa）的水生植物，果实可以食用。 属名Trapa来源于拉丁词calcitrapa，是一种古代四刺的武器，状如蒺藜，比喻菱果实具4角。","desc_en":"Trapa natans, the water caltrop, is a widespread species of flowering plant in the genus Trapa, family Lythraceae, grown as a food crop. Other vernacular names include buffalo nut, bat nut, devil pod, ling nut, mustache nut, singhara nut, water nut, and water…","img":"images/545.jpg","thumb":"images/t/545.jpg","file":"Expedition 10.jpg","ar":1.381,"py":"lingjiao lj","cr_by":"Bilous Olena","cr_lic":"CC BY 4.0","cr_licurl":"https://creativecommons.org/licenses/by/4.0","habit":"草本","origin":["亚洲","非洲"]},{"id":546,"zh":"榄仁树","en":"Terminalia catappa","sci":"Terminalia catappa","order_en":"Myrtales","order_zh":"桃金娘目","family_en":"Combretaceae","family_zh":"使君子科","iucn":"LC","langs":53,"desc_zh":"榄仁树（学名：Terminalia catappa ）别称大叶榄仁树、凉扇树、枇杷树、山枇杷树、法国枇杷、楠仁树、雨伞树、岛朴及古巴梯斯树等，为使君子科榄仁树属植物。","desc_en":"Terminalia catappa is a large tropical tree in the leadwood tree family, Combretaceae, native to Asia, Australia, the Pacific, Madagascar and Seychelles. Common names in English include country almond, Indian almond, Malabar almond, sea almond, tropical almond…","img":"images/546.jpg","thumb":"images/t/546.jpg","file":"01423jfCapalangan Sulipan Apalit Pampanga Peters Trees Shrinesfvf 20.JPG","ar":1.333,"py":"lanrenshu lrs","cr_by":"Judgefloro","cr_lic":"Public domain","cr_licurl":null,"habit":"乔木","origin":["亚洲","非洲","大洋洲"]},{"id":547,"zh":"使君子","en":"Combretum indicum","sci":"Combretum indicum","order_en":"Myrtales","order_zh":"桃金娘目","family_en":"Combretaceae","family_zh":"使君子科","iucn":null,"langs":43,"desc_zh":"使君子（学名：Combretum indicum）为使君子科使君子属植物。本种为古今中外著名的驱虫药，于治疗小儿病患上至少已有1600多年历史。 其种加词“indicum”意为“印度的”。","desc_en":"Combretum indicum, commonly known as the Rangoon creeper or Burma creeper, is a vine with red flower clusters which is native to tropical Asia and grows in thickets, primary and secondary forest, and along river banks in the Indian subcontinent, Malaysia and t…","img":"images/547.jpg","thumb":"images/t/547.jpg","file":"Combretum indicum 01.JPG","ar":1.508,"py":"shijunzi sjz","cr_by":"Prenn","cr_lic":"CC BY-SA 3.0","cr_licurl":"https://creativecommons.org/licenses/by-sa/3.0","habit":"藤本","origin":["亚洲"]},{"id":548,"zh":"羽叶省沽油","en":"Staphylea pinnata","sci":"Staphylea pinnata","order_en":"Crossosomatales","order_zh":"燥木目","family_en":"Staphyleaceae","family_zh":"省沽油科","iucn":"LC","langs":31,"desc_zh":null,"desc_en":"Staphylea pinnata, the European bladdernut, is a species of bladdernut native to Europe and naturalized in Britain.","img":"images/548.jpg","thumb":"images/t/548.jpg","file":"20130817Staphylea pinnata1.jpg","ar":0.75,"py":"yuyeshengguyou yysgy","cr_by":"AnRo0002","cr_lic":"CC0","cr_licurl":"http://creativecommons.org/publicdomain/zero/1.0/deed.en","habit":null,"origin":["欧洲"]},{"id":549,"zh":"柠檬","en":"Citrus × limon","sci":"Citrus × limon","order_en":"Sapindales","order_zh":"无患子目","family_en":"Rutaceae","family_zh":"芸香科","iucn":null,"langs":184,"desc_zh":"柠檬（学名：Citrus × limon）为芸香科柑橘属的一种，是原产于亚洲的常绿小乔木，其果实为黄色椭圆状。","desc_en":"The lemon (Citrus × limon) is a species of small evergreen tree in the Citrus genus of the flowering plant family Rutaceae. A true lemon is a hybrid of the citron and the bitter orange.","img":"images/549.jpg","thumb":"images/t/549.jpg","file":"Citrus x limon - Köhler–s Medizinal-Pflanzen-041.jpg","ar":0.805,"py":"ningmeng nm","cr_by":"Franz Eugen Köhler, Köhler's Medizinal-Pflanzen","cr_lic":"Public domain","cr_licurl":null,"habit":"乔木","origin":["亚洲"]},{"id":550,"zh":"橘","en":"Citrus reticulata","sci":"Citrus reticulata","order_en":"Sapindales","order_zh":"无患子目","family_en":"Rutaceae","family_zh":"芸香科","iucn":null,"langs":112,"desc_zh":"橘子（学名：Citrus reticulata），或写作桔子，芸香科柑橘属的一种水果，原产自中国南方、中南半岛、缅甸等地。在福州话称为橘，而闽南语称橘为柑仔，西南官话区的各方言中呼为“柑子”或“柑儿”，也有一些方言称之为“橘柑”。其种加词“reticuluma”意为“网纹的”。中华人民共和国国家标准称之为“柑橘”（citrus）。","desc_en":"A mandarin orange (Citrus reticulata), often simply called mandarin, is a small, rounded citrus tree fruit. Treated as a distinct species of orange, it is usually eaten plain or in fruit salads.","img":"images/550.jpg","thumb":"images/t/550.jpg","file":"Mandarin Oranges (Citrus Reticulata).jpg","ar":1.501,"py":"ju j","cr_by":"Joe Ravi","cr_lic":"CC BY-SA 3.0","cr_licurl":"https://creativecommons.org/licenses/by-sa/3.0","habit":"乔木","origin":null},{"id":551,"zh":"柚子","en":"pomelo","sci":"Citrus maxima","order_en":"Sapindales","order_zh":"无患子目","family_en":"Rutaceae","family_zh":"芸香科","iucn":"LC","langs":108,"desc_zh":"柚（学名：Citrus maxima）是芸香科柑橘属果树，其特征与柑橘相同。柚的果实称为柚子或文旦，又称香栾、朱栾、内紫、条、雷柚、碌柚、胡柑、臭橙、抛、苞、脬、枹、花柚子，广泛分布于中国河南、长江以南等地及东南亚，生长于海拔600－1400米的地区，多见于河谷、丘陵、山坡、民居附近，常用于栽培。该种栽培种数量众多，如玉环文旦、文旦柚、坪山柚、沙田柚、暹罗柚、蜜柚、胡柚、四季柚等。一般在中秋节前采收、作为中秋拜月、餽赠亲友的礼品。。","desc_en":"The pomelo ( POM-il-oh, PUM-; or pummelo, Citrus maxima), also known as a shaddock, is the largest citrus fruit. It is an ancestor of several cultivated citrus species, including the bitter orange and the grapefruit.","img":"images/551.jpg","thumb":"images/t/551.jpg","file":"Pomelo fruit.jpg","ar":1.333,"py":"youzi yz","cr_by":"Ivar Leidus","cr_lic":"CC BY-SA 4.0","cr_licurl":"https://creativecommons.org/licenses/by-sa/4.0","habit":null,"origin":["亚洲"]},{"id":552,"zh":"葡萄柚","en":"Citrus paradisi","sci":"Citrus paradisi","order_en":"Sapindales","order_zh":"无患子目","family_en":"Rutaceae","family_zh":"芸香科","iucn":null,"langs":101,"desc_zh":"葡萄柚（学名：Citrus × paradisi，港澳又称西柚），是芸香科柑橘属的一种亚热带植物。为常见的水果之一。起源于17世纪的巴巴多斯，为当地从亚洲引入种植橙（Citrus sinensis）及柚子（Citrus maxima）后而出现的杂交种，当地人发现时，一度戏称此果为“禁果”。","desc_en":"The grapefruit (Citrus × paradisi) is a subtropical citrus tree known for its relatively large, sour to semi-sweet, somewhat bitter fruit. The flesh of the fruit is segmented and varies in color from pale yellow to dark red.","img":"images/552.jpg","thumb":"images/t/552.jpg","file":"Citrus x paradisi (Macfad.) Pompelino Grapefruit 002.jpg","ar":1.506,"py":"putaoyou pty","cr_by":"Amada44","cr_lic":"CC BY 3.0","cr_licurl":"https://creativecommons.org/licenses/by/3.0","habit":"乔木","origin":null},{"id":553,"zh":"橙","en":"Citrus sinensis","sci":"Citrus ×sinensis","order_en":"Sapindales","order_zh":"无患子目","family_en":"Rutaceae","family_zh":"芸香科","iucn":null,"langs":97,"desc_zh":"柳橙（学名：Citrus sinensis）又名甜橙、黄果、金环，是芸香科柑橘属的物种。其种加词“sinensis”意为“中华的”。 甜橙是柑果，也是人类种植了很久的混合品种──本来是柚子（Citrus maxima）与橘子（Citrus reticulata）的杂交品种，起源于中国；考古证据显示，早在公元前2500年，中国已开始种植橙子。1493年哥伦布第二次造访新大陆时，橙子登上了美洲大陆。","desc_en":"Citrus × sinensis (sometimes written Citrus sinensis), the sweet orange, is a broadleaf evergreen hybrid between pomelo (Citrus maxima) and mandarin (Citrus reticulata).","img":"images/553.jpg","thumb":"images/t/553.jpg","file":"OrangeBloss wb.jpg","ar":1.136,"py":"cheng c","cr_by":"Ellen Levy Finch ( Elf )","cr_lic":"CC BY-SA 3.0","cr_licurl":"http://creativecommons.org/licenses/by-sa/3.0/","habit":null,"origin":null},{"id":554,"zh":"苦橙","en":"Citrus × aurantium","sci":"Citrus × aurantium","order_en":"Sapindales","order_zh":"无患子目","family_en":"Rutaceae","family_zh":"芸香科","iucn":null,"langs":84,"desc_zh":"酸橙（学名：Citrus × aurantium）又名苦橙、南庄橙、来母、金柚葡萄柚、胡柚、常山胡柚、塞维亚柑橘，是柚（Citrus maxima）与橘（Citrus reticulata）的杂交种，属芸香科柑橘属植物。 栽培品种玳玳花（Citrus × aurantium Amara）开白花，香气浓郁。","desc_en":"The bitter orange, sour orange, Seville orange, bigarade orange, or marmalade orange is the hybrid citrus tree species Citrus × aurantium, and its fruit. It is native to Southeast Asia and has been spread by humans to many parts of the world.","img":"images/554.jpg","thumb":"images/t/554.jpg","file":"Turunç - Citrus aurantium 02.JPG","ar":0.688,"py":"kucheng kc","cr_by":"Zeynel Cebeci","cr_lic":"CC BY-SA 4.0","cr_licurl":"https://creativecommons.org/licenses/by-sa/4.0","habit":"乔木","origin":["亚洲"]},{"id":555,"zh":"枸橼","en":"Citrus medica","sci":"Citrus medica","order_en":"Sapindales","order_zh":"无患子目","family_en":"Rutaceae","family_zh":"芸香科","iucn":"LC","langs":79,"desc_zh":"枸橼（学名：Citrus medica ，拼音：jǔ yuán，注音：ㄐㄩˇ ㄩㄢˊ），又称香橼、香水柠檬、枸橼子、香泡，是芸香科柑橘属的一种植物；和青柠的外观上相似。枸橼是犹太人庆祝住棚节必备的植物之一。 枸橼和苦橙杂交的后代就是现今各种的柠檬。","desc_en":"The citron (Citrus medica) is a large fragrant citrus fruit with a thick, coarse rind. It resembles a lemon, but is larger. It is one of the original citrus fruits from which all other citrus types developed through natural hybrid speciation or artificial hybr…","img":"images/555.jpg","thumb":"images/t/555.jpg","file":"Chinesische Zedrat Zitrone.jpg","ar":1.405,"py":"gouyuan gy","cr_by":"Johann Werfring","cr_lic":"CC BY-SA 3.0","cr_licurl":"https://creativecommons.org/licenses/by-sa/3.0","habit":null,"origin":["亚洲"]},{"id":556,"zh":"木橘","en":"Aegle marmelos","sci":"Aegle marmelos","order_en":"Sapindales","order_zh":"无患子目","family_en":"Rutaceae","family_zh":"芸香科","iucn":"NT","langs":68,"desc_zh":"木橘（学名：Aegle marmelos），又名木苹果、孟加拉苹果、孟加拉木苹果、日本苦橙，或音译作贝尔果、贝儿果，为芸香科木橘属下的唯一物种。 原生于印度次大陆及东南亚，本物种见于印度、孟加拉国。 木橘树在印度教和佛教都被认为是神圣的。","desc_en":"Aegle marmelos, commonly known as bael (a.k.a. bel, beli, or bhel), also Bengal quince, golden apple, Japanese bitter orange, stone apple or wood apple, is a species of tree native to the Indian subcontinent and Southeast Asia.","img":"images/556.jpg","thumb":"images/t/556.jpg","file":"Bael03 FSPark Asit.jpg","ar":1.333,"py":"muju mj","cr_by":"Asit K. Ghosh Thaumaturgist","cr_lic":"CC BY-SA 3.0","cr_licurl":"https://creativecommons.org/licenses/by-sa/3.0","habit":"乔木","origin":["亚洲"]},{"id":557,"zh":"墨西哥莱檬","en":"Citrus × aurantiifolia","sci":"Citrus ×aurantifolia","order_en":"Sapindales","order_zh":"无患子目","family_en":"Rutaceae","family_zh":"芸香科","iucn":null,"langs":65,"desc_zh":"墨西哥青柠檬又名墨西哥莱姆（Citrus × aurantiifolia），柑橘类的一种。原产于印度、缅甸等亚洲热带地区的小乔木。果实可作食用。 此外，佛岛青柠派（key lime pie）是由墨西哥青柠檬汁、蛋黄和大量炼乳为主要原料做成的西式馅饼。","desc_en":"The Key lime, also known as West Indian lime, Mexican lime, or Egyptian lime (Citrus × aurantiifolia) is a type of lime. While it is treated as a species in botanical classification, it originated as a natural hybrid between Citrus micrantha (a wild papeda) an…","img":"images/557.jpg","thumb":"images/t/557.jpg","file":"Owoce Lima.jpg","ar":1,"py":"moxigelaimeng mxglm","cr_by":"Agnieszka Kwiecień, Nova","cr_lic":"CC BY-SA 3.0","cr_licurl":"https://creativecommons.org/licenses/by-sa/3.0","habit":null,"origin":["北美洲"]},{"id":558,"zh":"香柠檬","en":"Citrus ×bergamia","sci":"Citrus ×bergamia","order_en":"Sapindales","order_zh":"无患子目","family_en":"Rutaceae","family_zh":"芸香科","iucn":null,"langs":64,"desc_zh":"香柠檬（学名：Citrus × bergamia），又名香柑、香柠檬橙，芸香科柑橘属水果，原产于意大利卡拉布里亚，果实较小、形状似梨。 香柠檬果肉酸涩，表皮芬芳，可提炼香柠檬油，多应用于格雷伯爵茶。 香柠檬的英文为bergamot或bergamot orange，在汉语中长期被误译为佛手柑，然而香柠檬与佛手柑其实是不同的物种。唇形科的草本植物蜂香薄荷在英文中也可称bergamot，因此有时也被称为「佛手柑草」。","desc_en":"Citrus bergamia, commonly known as the bergamot orange (pronounced ), is a fragrant citrus fruit the size of an orange, with a yellow or green colour similar to a lime, depending on ripeness.","img":"images/558.jpg","thumb":"images/t/558.jpg","file":"Bergamottepflanze.jpg","ar":0.75,"py":"xiangningmeng xnm","cr_by":null,"cr_lic":"CC BY-SA 3.0","cr_licurl":"http://creativecommons.org/licenses/by-sa/3.0/","habit":null,"origin":null},{"id":559,"zh":"荔枝","en":"Litchi chinensis","sci":"Litchi chinensis","order_en":"Sapindales","order_zh":"无患子目","family_en":"Sapindaceae","family_zh":"无患子科","iucn":null,"langs":105,"desc_zh":"荔枝（学名：Litchi chinensis）又名荔支、离枝、丹荔、丽枝、贵妃香、火山荔、勒荔、荔果，是中国南部原产的一种果树，广泛栽培于东南亚至新几内亚等亚热带地区，是无患子目无患子科荔枝属的唯一物种。其果树与果实状似同科不同属的龙眼。 荔枝是中国华南的重要水果农作物，每年产量逾百万吨，因其果实对保鲜的要求相当高，一般采用低温运输。 生荔枝和荔枝核含有毒物亚甲基环丙基乙酸，食用过量会导致低血糖和急性癫痫发作。","desc_en":"Lychees ( LIE-chee, US also LEE-chee) are the fruit of the tree Litchi chinensis, the sole member of the genus Litchi, part of the soapberry family, Sapindaceae.","img":"images/559.jpg","thumb":"images/t/559.jpg","file":"Lychee.jpg","ar":1.508,"py":"lizhi lz","cr_by":"Barry Fitzgerald, USDA","cr_lic":"Public domain","cr_licurl":null,"habit":"乔木","origin":["亚洲"]},{"id":560,"zh":"红毛丹","en":"Nephelium lappaceum","sci":"Nephelium lappaceum","order_en":"Sapindales","order_zh":"无患子目","family_en":"Sapindaceae","family_zh":"无患子科","iucn":"LC","langs":88,"desc_zh":"红毛丹（学名：Nephelium lappaceum，马来语：Rambutan），为东南亚原产之无患子科韶子属大型热带乔木，马来文称之“rambutan”，意为“毛茸茸之物”。成熟的红毛丹果通常是红色的，也有黄色果子的变种。有的红毛丹的核的大小近似于芝麻。","desc_en":"Rambutan (; Nephelium lappaceum) is a medium-sized tropical tree in the family Sapindaceae. The name also refers to the edible fruit produced by this tree. The rambutan is native to Southeast Asia.","img":"images/560.jpg","thumb":"images/t/560.jpg","file":"Rambutan white background alt.jpg","ar":1.628,"py":"hongmaodan hmd","cr_by":"Muhammad Mahdi Karim","cr_lic":"GFDL 1.2","cr_licurl":"http://www.gnu.org/licenses/old-licenses/fdl-1.2.html","habit":"乔木","origin":["亚洲"]},{"id":561,"zh":"欧亚槭","en":"Acer pseudoplatanus","sci":"Acer pseudoplatanus","order_en":"Sapindales","order_zh":"无患子目","family_en":"Sapindaceae","family_zh":"无患子科","iucn":"LC","langs":75,"desc_zh":"岩槭（学名：Acer pseudoplatanus），也称为岩槭、白槭、假挪威槭、欧亚槭，是枫属的一种被子植物、落叶植物，属于阔叶树，抗风能力好。它原产于中欧和西亚，从法国开始东至乌克兰、土耳其北和高加索地区，南至意大利和西班牙北部的山丘地带。","desc_en":"Acer pseudoplatanus, known as the sycamore in the British Isles and as the sycamore maple in the United States, is a species of maple native to Central Europe and Western Asia. It is a large deciduous, broad-leaved tree, tolerant of wind and coastal exposure.","img":"images/561.jpg","thumb":"images/t/561.jpg","file":"ID 1211 Bergahorn 0011.jpg","ar":0.667,"py":"ouyaqi oyq","cr_by":"Christian Pirkl","cr_lic":"CC BY-SA 3.0 at","cr_licurl":"https://creativecommons.org/licenses/by-sa/3.0/at/deed.en","habit":"乔木","origin":["亚洲","欧洲"]},{"id":562,"zh":"欧洲七叶树","en":"Aesculus hippocastanum","sci":"Aesculus hippocastanum","order_en":"Sapindales","order_zh":"无患子目","family_en":"Sapindaceae","family_zh":"无患子科","iucn":"VU","langs":73,"desc_zh":"欧洲七叶树（学名：Aesculus hippocastanum），果实又称马栗（Horse Chestnut），是无患子科七叶树属的植物。分布于希腊、马其顿、保加利亚和阿尔巴尼亚，作为行道树广泛栽植于世界各地。","desc_en":"Aesculus hippocastanum, the horse chestnut, is a species of flowering plant in the maple, soapberry and lychee family Sapindaceae. It is a large, deciduous, synoecious (hermaphroditic-flowered) tree.","img":"images/562.jpg","thumb":"images/t/562.jpg","file":"ND 678.N.59 Hofers Kastanien in Wettringen.jpg","ar":1.275,"py":"ouzhouqiyeshu ozqys","cr_by":"Stephan van Helden","cr_lic":"CC BY-SA 4.0","cr_licurl":"https://creativecommons.org/licenses/by-sa/4.0","habit":"乔木","origin":["欧洲"]},{"id":563,"zh":"龙眼","en":"Dimocarpus longan","sci":"Dimocarpus longan","order_en":"Sapindales","order_zh":"无患子目","family_en":"Sapindaceae","family_zh":"无患子科","iucn":"DD","langs":68,"desc_zh":"龙眼（学名：Dimocarpus longan），又称桂圆、福圆、荔枝奴、亚荔枝、燕卵、牛眼，为水果，寿命最长可达400多年。","desc_en":"Longan (; Dimocarpus longan), also called lungan or dragon's eye, is a tropical tree species that produces edible fruit. It is one of the better-known tropical members of the soapberry family Sapindaceae, to which the lychee and rambutan also belong.","img":"images/563.jpg","thumb":"images/t/563.jpg","file":"Dimocarpus longan fruits.jpg","ar":0.656,"py":"longyan ly","cr_by":null,"cr_lic":"Public domain","cr_licurl":null,"habit":"乔木","origin":["亚洲"]},{"id":564,"zh":"挪威枫","en":"Acer platanoides","sci":"Acer platanoides","order_en":"Sapindales","order_zh":"无患子目","family_en":"Sapindaceae","family_zh":"无患子科","iucn":"LC","langs":65,"desc_zh":"挪威枫，枫属落叶乔木，原产于欧洲中东部，树龄最多约为250年。","desc_en":"Acer platanoides, commonly known as the Norway maple, is a species of maple native to eastern and central Europe and western Asia, from Spain east to Russia, north to southern Scandinavia and southeast to northern Iran.","img":"images/564.jpg","thumb":"images/t/564.jpg","file":"2020 year. Herbarium. Acer platanoides. img-012.jpg","ar":1.108,"py":"nuoweifeng nwf","cr_by":"Dmitry Makeev","cr_lic":"CC BY-SA 4.0","cr_licurl":"https://creativecommons.org/licenses/by-sa/4.0","habit":"乔木","origin":["亚洲","欧洲"]},{"id":565,"zh":"栓皮槭","en":"Acer campestre","sci":"Acer campestre","order_en":"Sapindales","order_zh":"无患子目","family_en":"Sapindaceae","family_zh":"无患子科","iucn":"LC","langs":64,"desc_zh":"栓皮槭（英语：field maple，学名：Acer campestre）是一种被子植物，属于无患子属与荔枝属的无患子科。它是欧洲大部地区、英国岛、土耳其至高加索地区的西南亚遗迹北非阿特拉斯山脉地区的本土植物。它被广泛种植，在欧洲非本土地区、美国、西澳大利亚气候适宜的地区都有它的身影。","desc_en":"Acer campestre, known as the field maple, is a flowering plant species in the family Sapindaceae. It is native to much of continental Europe, Britain, southwest Asia from Turkey to the Caucasus, and north Africa in the Atlas Mountains.","img":"images/565.jpg","thumb":"images/t/565.jpg","file":"Acer campestre 006.jpg","ar":0.75,"py":"shuanpiqi spq","cr_by":"Willow","cr_lic":"CC BY-SA 2.5","cr_licurl":"https://creativecommons.org/licenses/by-sa/2.5","habit":null,"origin":["亚洲","欧洲","非洲"]},{"id":566,"zh":"瓜拿纳","en":"guarana plant","sci":"Paullinia cupana","order_en":"Sapindales","order_zh":"无患子目","family_en":"Sapindaceae","family_zh":"无患子科","iucn":null,"langs":61,"desc_zh":"瓜拿纳，又名巴西香可可，英文Guarana（双名法：Paullinia cupana）原产于巴西亚马逊盆地，是无患子科泡林藤属（保力藤属）的爬藤植物。分布在巴西、秘鲁、哥伦比亚、委内瑞拉等亚马逊盆地区域，主要种植在巴西亚马逊州的玛瑙斯自治市和巴西东北部的巴伊亚州。","desc_en":"Guaraná ( from the Portuguese guaraná [ɡʷaɾɐˈna]; Paullinia cupana, syns. P. crysan, P. sorbilis) is a climbing plant in the family Sapindaceae, native to the Amazon basin and especially common in Brazil.","img":"images/566.jpg","thumb":"images/t/566.jpg","file":"Guarana - Paullinia cupana.jpg","ar":0.751,"py":"guanana gnn","cr_by":null,"cr_lic":"CC BY-SA 3.0","cr_licurl":"http://creativecommons.org/licenses/by-sa/3.0/","habit":"藤本","origin":["南美洲"]},{"id":567,"zh":"梣叶槭","en":"Acer negundo","sci":"Acer negundo","order_en":"Sapindales","order_zh":"无患子目","family_en":"Sapindaceae","family_zh":"无患子科","iucn":"LC","langs":51,"desc_zh":"梣叶槭（学名：Acer negundo），为槭树科槭属下的一个植物种。","desc_en":"Acer negundo, also known as the box elder, boxelder maple, Manitoba maple or ash-leaved maple, is a species of maple native to North America from Canada to Honduras. It is a fast-growing, short-lived tree with opposite, ash-like compound leaves.","img":"images/567.jpg","thumb":"images/t/567.jpg","file":"Acer negundo Bozeman 1.jpg","ar":1.333,"py":"qinyeqi qyq","cr_by":"Matt Lavin from Bozeman, Montana, USA","cr_lic":"CC BY-SA 2.0","cr_licurl":"https://creativecommons.org/licenses/by-sa/2.0","habit":"乔木","origin":["北美洲"]},{"id":568,"zh":"腰果","en":"Cashew","sci":"Anacardium occidentale","order_en":"Sapindales","order_zh":"无患子目","family_en":"Anacardiaceae","family_zh":"漆树科","iucn":"LC","langs":115,"desc_zh":"腰果（学名：Anacardium occidentale）是一种肾形核果，原产于南美洲，属无患子目漆树科腰果属。又名树花生、槚如树、鸡腰果、介寿果、腰子豆等，带有附果。","desc_en":"Cashew is the common name of a tropical evergreen tree Anacardium occidentale, in the family Anacardiaceae. It is the source of the cashew nut and the cashew apple. The tree can grow as tall as 14 meters (46 feet). Cashews are native to tropical South America.","img":"images/568.jpg","thumb":"images/t/568.jpg","file":"Anacardium occidentale - Köhler–s Medizinal-Pflanzen-010.jpg","ar":0.722,"py":"yaoguo yg","cr_by":"Franz Eugen Köhler, Köhler's Medizinal-Pflanzen","cr_lic":"Public domain","cr_licurl":null,"habit":"乔木","origin":["南美洲"]},{"id":569,"zh":"芒果树","en":"Mangifera indica","sci":"Mangifera indica","order_en":"Sapindales","order_zh":"无患子目","family_en":"Anacardiaceae","family_zh":"漆树科","iucn":"DD","langs":89,"desc_zh":"芒果树（学名：Mangifera indica）也作檬果树、杧果树，是芒果属的一种植物，果实为芒果，原产南亚东北部和中南半岛，在梵语中叫作āmra，音译为“庵罗”，性喜高温、干燥的天气，营养生长期（根、茎、叶）最适合温度为24－30℃，气温降到18℃以下时生长缓慢，10℃以下停止生长，生殖生长期（花、果）需较高温度，以排水良好且含腐植质的砂质土壤最适宜，pH值5.5－7.5为佳。","desc_en":"Mangifera indica, commonly known as the mango after its fruit, is an evergreen species of flowering plant in the family Anacardiaceae. It is a large fruit tree, capable of growing to a height and width of 30 m (100 ft).","img":"images/569.jpg","thumb":"images/t/569.jpg","file":"The Botanical Magazine. Mango.jpg","ar":0.836,"py":"mangguoshu mgs","cr_by":"Walter Hood Fitch (1817-1892) del. et lith. Description by John Smith (1798 - 1888)","cr_lic":"Public domain","cr_licurl":null,"habit":"乔木","origin":["亚洲"]},{"id":570,"zh":"阿月浑子","en":"Pistacia vera","sci":"Pistacia vera","order_en":"Sapindales","order_zh":"无患子目","family_en":"Anacardiaceae","family_zh":"漆树科","iucn":"NT","langs":87,"desc_zh":"阿月浑子（学名：Pistacia vera，英语：pistachio），又称胡榛子，是漆树科黄连木属的植物，其果实常称开心果，是一种常见干果。开心果营养丰富，味道可口，是很受欢迎的零食。最早的汉语商品名是开口笑，形容其硬壳裂开如笑容之状，但迅速被更口语化的开心果取代。富含维生素A、维生素E。","desc_en":"The pistachio (, UK also ; Pistacia vera) is a small to medium-sized tree of the cashew family. The tree produces seeds that are widely consumed as food. Pistachios can be used as an ingredient in desserts, chocolate, candy, ice cream, and as a paste or butter…","img":"images/570.jpg","thumb":"images/t/570.jpg","file":"Pistacia vera Kerman.jpg","ar":1.361,"py":"ayuehunzi ayhz","cr_by":"Stan Shebs","cr_lic":"CC BY-SA 3.0","cr_licurl":"https://creativecommons.org/licenses/by-sa/3.0","habit":"乔木","origin":null},{"id":571,"zh":"乳香黄连木","en":"Pistacia lentiscus","sci":"Pistacia lentiscus","order_en":"Sapindales","order_zh":"无患子目","family_en":"Anacardiaceae","family_zh":"漆树科","iucn":"LC","langs":59,"desc_zh":"乳香黄连木（学名：Pistacia lentiscus）是漆树科黄连木属常绿灌木，也叫洋乳香树、黏胶乳香树，原产于地中海区域。其树脂洋乳香是一种名贵香料。","desc_en":"Pistacia lentiscus (also lentisk or mastic) is a dioecious evergreen shrub or small tree of the genus Pistacia native to the Mediterranean Basin. It grows up to 4 m (13 ft) tall and is cultivated for its aromatic resin, mainly on the Greek island of Chios, aro…","img":"images/571.jpg","thumb":"images/t/571.jpg","file":"Dettaglio - Anacardiaceae Pistacia lentiscus Lin. Erbario Frizzi Perugia n. 3752.jpg","ar":0.75,"py":"ruxianghuanglianmu rxhlm","cr_by":"Giuseppe Frizzi","cr_lic":"Public domain","cr_licurl":null,"habit":"乔木","origin":["欧洲"]},{"id":572,"zh":"象李","en":"Sclerocarya birrea","sci":"Sclerocarya birrea","order_en":"Sapindales","order_zh":"无患子目","family_en":"Anacardiaceae","family_zh":"漆树科","iucn":"LC","langs":49,"desc_zh":"马鲁拉（学名：Sclerocarya birrea），又名非洲漆树，是漆树科象李属的物种。本物种以常绿乔木仔或灌木的形式存在。","desc_en":"Sclerocarya birrea (Ancient Greek: σκληρός ⟨sklērós⟩, meaning \"hard\", and κάρυον ⟨káryon⟩, \"nut\", in reference to the stone inside the fleshy fruit), commonly known as the marula, is a medium-sized deciduous fruit-bearing tree, indigenous to the miombo woodlan…","img":"images/572.jpg","thumb":"images/t/572.jpg","file":"Marula02.jpg","ar":1.506,"py":"xiangli xl","cr_by":"Rotational","cr_lic":"Public domain","cr_licurl":null,"habit":"乔木","origin":["非洲"]},{"id":573,"zh":"番橄榄","en":"Spondias dulcis","sci":"Spondias dulcis","order_en":"Sapindales","order_zh":"无患子目","family_en":"Anacardiaceae","family_zh":"漆树科","iucn":null,"langs":48,"desc_zh":"太平洋桲（Spondias dulcis），又称莎梨橄榄、沙梨橄榄、南洋橄榄。是漆树科槟榔青属的物种，果实可食。","desc_en":"Spondias dulcis (syn. Spondias cytherea), known commonly as Polynesian plum or Tahiti apple, is a tropical fruit tree native to Melanesia, with edible fruit containing a fibrous pit.","img":"images/573.jpg","thumb":"images/t/573.jpg","file":"2014-10-11 Spondias dulcis Goldpflaume anagoria.JPG","ar":1.184,"py":"fanganlan fgl","cr_by":"Anagoria","cr_lic":"CC BY 3.0","cr_licurl":"https://creativecommons.org/licenses/by/3.0","habit":"乔木","origin":["大洋洲"]},{"id":574,"zh":"印度苦楝树","en":"Azadirachta indica","sci":"Azadirachta indica","order_en":"Sapindales","order_zh":"无患子目","family_en":"Meliaceae","family_zh":"楝科","iucn":"LC","langs":91,"desc_zh":"印度苦楝树（学名：Azadirachta indica），又称印度楝树、印度蒜楝、印度假苦楝、宁树（英语：Neem）、印度紫丁香（Indian lilac），楝科蒜楝属植物，分布于印度、缅甸、孟加拉、斯里兰卡、马来西亚与巴基斯坦等亚洲亚热带、热带气候地区。其种加词“indica”意为“印度的”。 它生长快速，可以达到15-20公尺高，少数甚至可以达到35-40公尺高。它是常青树，但在严重干旱时，叶子会大部份或全部掉落。","desc_en":"Azadirachta indica, commonly known as neem, margosa, nimtree or Indian lilac, is a tree in the mahogany family Meliaceae. It is one of the two species in the genus Azadirachta.","img":"images/574.jpg","thumb":"images/t/574.jpg","file":"Neem (Azadirachta indica) in Hyderabad W IMG 6976.jpg","ar":1.137,"py":"yindukulianshu ydkls","cr_by":"J.M.Garg","cr_lic":"CC BY 3.0","cr_licurl":"https://creativecommons.org/licenses/by/3.0","habit":"乔木","origin":["亚洲"]},{"id":575,"zh":"苦楝","en":"Melia azedarach","sci":"Melia azedarach","order_en":"Sapindales","order_zh":"无患子目","family_en":"Meliaceae","family_zh":"楝科","iucn":"LC","langs":61,"desc_zh":"苦楝（学名：Melia azedarach，英文名称：Beadtree、 Bead Tree、Cape Lilac、Chinaberry、China-berry、China Berry、Chinaberry-tree、China-berry Tree、Melia、Persian Lilac、Pride-of-India, Melia、white cedar,），别称苦苓、楝、楝树、楝子 、森树、翠树、楝枣树、紫花树、紫花木、花心树、双白…","desc_en":"Melia azedarach, commonly known as the chinaberry tree, pride of India, bead-tree, Cape lilac, syringa berrytree, Persian lilac, Indian lilac, or white cedar, is a species of deciduous tree in the mahogany family, Meliaceae, that is native to Indomalaya and Au…","img":"images/575.jpg","thumb":"images/t/575.jpg","file":"Chinaberry1216.JPG","ar":0.75,"py":"kulian kl","cr_by":null,"cr_lic":"CC BY-SA 3.0","cr_licurl":"http://creativecommons.org/licenses/by-sa/3.0/","habit":"乔木","origin":["亚洲"]},{"id":576,"zh":"兰撒","en":"Lansium domesticum","sci":"Lansium domesticum","order_en":"Sapindales","order_zh":"无患子目","family_en":"Meliaceae","family_zh":"楝科","iucn":null,"langs":51,"desc_zh":"兰撒（学名：Lansium domesticum；马来语：langsat）又译作冷刹、芦菇或杜古（马来语：duku）、龙贡或龙宫果，为楝科㭴木属的一种。","desc_en":"Lansium domesticum, commonly known as langsat () or lanzones, ,--) is a species of tree in the family Meliaceae with commercially cultivated edible fruits. The species is native to Southeast Asia, from peninsular Thailand and Malaysia to Indonesia and the Phil…","img":"images/576.jpg","thumb":"images/t/576.jpg","file":"Lanzones.jpg","ar":1.333,"py":"lansa ls","cr_by":"Mike Gonzalez ( TheCoffee )","cr_lic":"CC BY-SA 3.0","cr_licurl":"https://creativecommons.org/licenses/by-sa/3.0","habit":"乔木","origin":["亚洲"]},{"id":577,"zh":"山陀儿","en":"Santol","sci":"Sandoricum koetjape","order_en":"Sapindales","order_zh":"无患子目","family_en":"Meliaceae","family_zh":"楝科","iucn":"LC","langs":44,"desc_zh":"山陀儿（学名：Sandoricum koetjape）为楝科山陀儿属下的一个种。分布在中南半岛、印度、马来西亚。在云南、台湾等地有种植。","desc_en":"Sandoricum koetjape, the santol, sentul, setun or cotton fruit, is a tropical fruit native to maritime Southeast Asia.","img":"images/577.png","thumb":"images/t/577.png","file":"Sandoricum koetjape Blanco1.127.png","ar":0.673,"py":"shantuoer ste","cr_by":"Francisco Manuel Blanco (O.S.A.)","cr_lic":"Public domain","cr_licurl":null,"habit":null,"origin":["亚洲"]},{"id":578,"zh":"阿拉伯乳香树","en":"Boswellia sacra","sci":"Boswellia sacra","order_en":"Sapindales","order_zh":"无患子目","family_en":"Burseraceae","family_zh":"橄榄科","iucn":"NT","langs":33,"desc_zh":"乳香树（学名：Boswellia sacra，学名的意思是神圣乳香）为乳香属下的一种植物，其树脂凝固后便成乳香。 一些学者认为Boswellia sacra只代表阿拉伯乳香树，而索马里的种群属于索马里乳香树（学名：Boswellia carteri），但这种区分缺少植物学依据。","desc_en":"Boswellia sacra, also known as Boswellia carteri and others, and commonly called the frankincense tree or the olibanum tree, is a tree in the genus Boswellia, in the Burseraceae family, from which frankincense, a resinous dried sap, is harvested.","img":"images/578.jpg","thumb":"images/t/578.jpg","file":"Boswellia sacra.jpg","ar":1.333,"py":"alaboruxiangshu albrxs","cr_by":"Scott Zona from USA","cr_lic":"CC BY 2.0","cr_licurl":"https://creativecommons.org/licenses/by/2.0","habit":"乔木","origin":["亚洲","非洲"]},{"id":579,"zh":"没药树","en":"Commiphora myrrha","sci":"Commiphora myrrha","order_en":"Sapindales","order_zh":"无患子目","family_en":"Burseraceae","family_zh":"橄榄科","iucn":null,"langs":32,"desc_zh":"没药树（学名：Commiphora myrrha）又名哈地丁树、地丁树，橄榄科常绿乔木，原产于索马利亚和衣索比亚。","desc_en":"Commiphora myrrha, called myrrh, Somali myrrh, herabol myrrh, common myrrh, is a tree in the family Burseraceae. It is one of the primary trees used in the production of myrrh, a resin made from dried tree sap.","img":"images/579.jpg","thumb":"images/t/579.jpg","file":"Commiphora myrrha - Köhler–s Medizinal-Pflanzen-019.jpg","ar":0.743,"py":"moyaoshu mys","cr_by":"Franz Eugen Köhler, Köhler's Medizinal-Pflanzen","cr_lic":"Public domain","cr_licurl":null,"habit":"乔木","origin":["亚洲","非洲"]},{"id":580,"zh":"臭椿","en":"Ailanthus altissima","sci":"Ailanthus altissima","order_en":"Sapindales","order_zh":"无患子目","family_en":"Simaroubaceae","family_zh":"苦木科","iucn":null,"langs":62,"desc_zh":"臭椿（学名：Ailanthus altissima ）原名樗（拼音：chū，注音：ㄕㄨ），又名大眼桐、姑姑翅、臭桐，属于苦木科，是一种落叶树。它原产于东亚北部与中部。与臭椿属其他成员不同，它生长在气候温和的地带而不是热带地区。这种树木生长迅速，适应环境能力强，可以在25年内达到15米（50英尺）的高度。然而此物种寿命较短，极少生存超过50年。 在中国，臭椿历史悠久且分布广泛。尔雅、说文解字、急救篇等古老字书均有记载。","desc_en":"Ailanthus altissima ( ay-LAN-thəss al-TIH-sim-ə), commonly known as tree of heaven or ailanthus tree, is a deciduous tree in the quassia family. It is native to northeast, central China, and Taiwan.","img":"images/580.jpg","thumb":"images/t/580.jpg","file":"Götterbaum (Ailanthus altissima).jpg","ar":0.74,"py":"chouchun cc","cr_by":"Darkone ( talk · contribs )","cr_lic":"CC BY-SA 2.5","cr_licurl":"https://creativecommons.org/licenses/by-sa/2.5","habit":"乔木","origin":["亚洲"]},{"id":581,"zh":"可可树","en":"cacao","sci":"Theobroma cacao","order_en":"Malvales","order_zh":"锦葵目","family_en":"Malvaceae","family_zh":"锦葵科","iucn":null,"langs":116,"desc_zh":"可可（学名：Theobroma cacao）是热带常绿植物，原产于南美，现在广泛在非洲、东南亚和拉丁美洲种植。用种子、枝条或树苗栽培。可可树最高可达15米，叶片宽阔，花直接簇生于枝干上，白色，花萼为粉色，直径约1厘米。果实成熟期为4到6个月，每年成熟两次，主要收获期为10月到12月。果实为荚状，长15至30厘米，外为绿色，内有20至100粒种子。收获后需发酵数日，使其内部变为红棕色，并产生浓郁的香味，然后剔开果肉，取出可可豆。","desc_en":"Theobroma cacao (cacao tree or cocoa tree) is a small (6–12 m (20–39 ft) tall) evergreen tree in the Malvaceae family. Its seeds—cocoa beans when dried and fermented—are used to make chocolate liquor, cocoa powder, cocoa butter and chocolate.","img":"images/581.jpg","thumb":"images/t/581.jpg","file":"Theobroma cacao - Köhler–s Medizinal-Pflanzen-136.jpg","ar":0.687,"py":"kekeshu kks","cr_by":"Franz Eugen Köhler, Köhler's Medizinal-Pflanzen","cr_lic":"Public domain","cr_licurl":null,"habit":"乔木","origin":null},{"id":582,"zh":"秋葵","en":"Abelmoschus esculentus","sci":"Abelmoschus esculentus","order_en":"Malvales","order_zh":"锦葵目","family_en":"Malvaceae","family_zh":"锦葵科","iucn":null,"langs":114,"desc_zh":"秋葵（学名：Abelmoschus esculentus），一种锦葵科、秋葵属的一年或多年生草本植物，是人类通过选择性育种改良而成的栽培植物，又称黄秋葵、咖啡黄葵、糊麻、补肾草、羊角椒、毛茄，其果实常被称作羊角豆或潺茄。秋葵的确切起源尚不清楚，通常认为原产于非洲西部至埃塞俄比亚一带。现已广泛种植于全球的热带、亚热带和暖温带地区，性喜温暖，耐高温和干旱。","desc_en":"Okra (US: , UK: ), Abelmoschus esculentus, known in some English-speaking countries as lady's fingers, is a flowering plant in the mallow family native to East Africa.","img":"images/582.jpg","thumb":"images/t/582.jpg","file":"Abelmoschus esculentus (1).jpg","ar":0.75,"py":"qiukui qk","cr_by":"Kristine Paulus from New York, United States","cr_lic":"CC BY 2.0","cr_licurl":"https://creativecommons.org/licenses/by/2.0","habit":null,"origin":["非洲"]},{"id":583,"zh":"猴面包树","en":"Adansonia digitata","sci":"Adansonia digitata","order_en":"Malvales","order_zh":"锦葵目","family_en":"Malvaceae","family_zh":"锦葵科","iucn":null,"langs":82,"desc_zh":"猴面包树（学名：Adansonia digitata），又名猢狲树、非洲猴面包树、酸瓠树、猴树、旅人树、死老鼠树，是一种锦葵科猴面包树属的大型落叶乔木，原产于热带非洲以及阿拉伯半岛，现今中国大陆南部以及台湾皆有人工引种栽培。 猴面包树会开出巨大的白花。华丽的花朵下垂，带有很多雄蕊，富含腐肉的气味，研究人员认为狐蝠科是它们主要授粉者。果实充满果肉，干燥变硬后会碎成块状，看起来就像是干了的面包块。","desc_en":"Adansonia digitata, the African baobab, is the most widespread tree species of the genus Adansonia, the baobabs, and is native to the African continent and the southern Arabian Peninsula (Yemen, Oman).","img":"images/583.jpg","thumb":"images/t/583.jpg","file":"Baobab and elephant, Tanzania.jpg","ar":1.501,"py":"houmianbaoshu hmbs","cr_by":"Ferdinand Reus from Arnhem, Holland","cr_lic":"CC BY-SA 2.0","cr_licurl":"https://creativecommons.org/licenses/by-sa/2.0","habit":"乔木","origin":["亚洲","非洲"]},{"id":584,"zh":"朱槿","en":"Hibiscus × rosa-sinensis","sci":"Hibiscus × rosa-sinensis","order_en":"Malvales","order_zh":"锦葵目","family_en":"Malvaceae","family_zh":"锦葵科","iucn":null,"langs":74,"desc_zh":"朱槿（学名：Hibiscus rosa-sinensis）是一种属于锦葵科木槿属的常绿灌木或小乔木，又称赤槿、日及、佛桑、烈红花、红扶桑、红木槿、桑槿、火红花、照殿红、宋槿、二红花、花上花、土红花、假牡丹、灯篮仔花，因原产于中国南部，欧洲各语系依循其拉丁学名皆称朱槿为中国蔷薇（英文：Rose of China、China rose）。由于早期花色大多为红色，中国岭南一带将之称为大红花。 其种加词“sinensis”意为“中华的”。","desc_en":"Hibiscus × rosa-sinensis (known colloquially as Chinese hibiscus, China rose, Hawaiian hibiscus, rose mallow and shoeblack plant) is a cultigen of tropical hibiscus, a flowering plant in the Hibiscus genus and Hibisceae tribe of the family Malvaceae.","img":"images/584.jpg","thumb":"images/t/584.jpg","file":"Hibiscus Brilliant.jpg","ar":1.366,"py":"zhujin zj","cr_by":"Andy / Andrew Fogg from near Cambridge, UK","cr_lic":"CC BY 2.0","cr_licurl":"https://creativecommons.org/licenses/by/2.0","habit":null,"origin":["大洋洲"]},{"id":585,"zh":"吉贝","en":"Ceiba pentandra","sci":"Ceiba pentandra","order_en":"Malvales","order_zh":"锦葵目","family_en":"Malvaceae","family_zh":"锦葵科","iucn":"LC","langs":73,"desc_zh":"美洲木棉（学名：Ceiba pentandra），又名吉贝、吉贝木棉、爪哇木棉，为锦葵科木棉亚科美洲木棉属的植物。属名源于泰诺语俗名seiba，种加词意思是五枚雄蕊的。","desc_en":"Ceiba pentandra is a tropical tree of the order Malvales and the family Malvaceae (previously placed in the family Bombacaceae), native to Central America, the Caribbean, and the northern half of South America; some authors also consider it native in western a…","img":"images/585.jpg","thumb":"images/t/585.jpg","file":"Ceiba pentandra in Cuba.jpg","ar":0.561,"py":"jibei jb","cr_by":"Burkhard Mücke","cr_lic":"CC BY-SA 4.0","cr_licurl":"https://creativecommons.org/licenses/by-sa/4.0","habit":"乔木","origin":["亚洲","非洲","北美洲","南美洲"]},{"id":586,"zh":"药葵","en":"Althaea officinalis","sci":"Althaea officinalis","order_en":"Malvales","order_zh":"锦葵目","family_en":"Malvaceae","family_zh":"锦葵科","iucn":null,"langs":69,"desc_zh":"药蜀葵（学名：Althaea officinalis）为锦葵科蜀葵属下的一个种。是欧洲、西亚和北非原生的多年生植物，亦产于中国大陆新疆塔城县依灭勒河沿岸。","desc_en":"Althaea officinalis, the marsh mallow or marshmallow, is a species of flowering plant indigenous to Europe, Western Asia and North Africa, which is used in herbalism and as an ornamental plant.","img":"images/586.jpg","thumb":"images/t/586.jpg","file":"Althea officinalis flor.jpg","ar":1.333,"py":"yaokui yk","cr_by":null,"cr_lic":"CC BY-SA 3.0","cr_licurl":"http://creativecommons.org/licenses/by-sa/3.0/","habit":null,"origin":["亚洲","欧洲","非洲"]},{"id":587,"zh":"小叶椴","en":"Tilia cordata","sci":"Tilia cordata","order_en":"Malvales","order_zh":"锦葵目","family_en":"Malvaceae","family_zh":"锦葵科","iucn":"LC","langs":62,"desc_zh":"小叶椴（Tilia cordata）分布在中国北方等地，也是一种在欧洲非常普遍的树。 种名cordata意为心形的。 小叶椴树高可达20到35米，干粗可达直径1到1.5米，树叶圆状或三角-椭圆状，4到8厘米长和宽，一般无毛（阔叶椴相反一般叶上有毛），只有在叶脉中轴上有少许棕色的毛。初夏开花，花小，黄绿色，有很浓的气味，易招引蜂。 小叶椴和阔叶椴的杂交品种是西洋椴。","desc_en":"Tilia cordata, the small-leaved lime or small-leaved linden, is a species of tree in the family Malvaceae, native to much of Europe. Its other common names include little-leaf or littleleaf linden, or traditionally in South East England, pry or pry tree.","img":"images/587.jpg","thumb":"images/t/587.jpg","file":"Tilia cordata, Lipa2009.jpg","ar":0.666,"py":"xiaoyeduan xyd","cr_by":"ImreKiss","cr_lic":"CC BY 3.0","cr_licurl":"https://creativecommons.org/licenses/by/3.0","habit":"乔木","origin":["欧洲"]},{"id":588,"zh":"欧锦葵","en":"Malva sylvestris","sci":"Malva sylvestris","order_en":"Malvales","order_zh":"锦葵目","family_en":"Malvaceae","family_zh":"锦葵科","iucn":null,"langs":58,"desc_zh":"欧锦葵（学名：Malva sylvestris）是一种锦葵科锦葵属的多年生草本植物，原产于欧洲、北非和西亚等地区。其植株高度可达 60 至 100 公分，叶片呈现掌状，而花朵多为带有深色条纹的紫色或粉红色，开花时间通常在每年 4 月至 10 月。除了观赏用途外，欧锦葵的花朵与叶片也常作为天然草药，具有润肺止咳、清热解毒的功效 。","desc_en":"Malva sylvestris is a species of the mallow genus Malva, of which it the type species. Known as common mallow to English-speaking Europeans, it acquired the common names of cheeses, high mallow and tall mallow (mauve des bois by the French) as it migrated from…","img":"images/588.jpg","thumb":"images/t/588.jpg","file":"Dettaglio - Malvaceae Malva sylvestris Lin. Erbario Frizzi Perugia n. 299.jpg","ar":0.466,"py":"oujinkui ojk","cr_by":"Giuseppe Frizzi","cr_lic":"Public domain","cr_licurl":null,"habit":null,"origin":["亚洲","欧洲","非洲"]},{"id":589,"zh":"玫瑰茄","en":"Hibiscus sabdariffa","sci":"Hibiscus sabdariffa","order_en":"Malvales","order_zh":"锦葵目","family_en":"Malvaceae","family_zh":"锦葵科","iucn":null,"langs":57,"desc_zh":"玫瑰茄（学名：Hibiscus sabdariffa Linn.）又称洛神花、洛神葵、洛神果、洛济葵、红桃K、山茄、红葵，是锦葵科木槿属的物种。","desc_en":"Roselle (Sabdariffa gossypiifolia) is a species of flowering plant in the genus Sabdariffa that is native to Africa, most likely West Africa. In the 16th and early 17th centuries it was spread to Asia and the West Indies, where it has since become naturalized…","img":"images/589.jpg","thumb":"images/t/589.jpg","file":"Bissap au Togo.jpg","ar":1.333,"py":"meiguiqie mgq","cr_by":"Bamouzou","cr_lic":"CC BY-SA 4.0","cr_licurl":"https://creativecommons.org/licenses/by-sa/4.0","habit":null,"origin":["非洲"]},{"id":590,"zh":"木槿","en":"Hibiscus syriacus","sci":"Hibiscus syriacus","order_en":"Malvales","order_zh":"锦葵目","family_en":"Malvaceae","family_zh":"锦葵科","iucn":null,"langs":56,"desc_zh":"木槿（学名：Hibiscus syriacus）是锦葵科木槿属开花植物。原产于中国中南、东南地区，后引至亚洲大部份地区在内的他处，广为种植。因收集自叙利亚花园，得种加词syriacus。韩国又称无穷花（韩语：무궁화／无穷花，罗马化：mugunghwa），作为国花出现于国徽、国歌。","desc_en":"Hibiscus syriacus is a species of flowering plant in the mallow family, Malvaceae. It is native to areas of east Asia, but widely introduced elsewhere, including much of Europe and North America.","img":"images/590.jpg","thumb":"images/t/590.jpg","file":"Ruhland, Grenzstr. 3, Straucheibisch, Blüte, Frühling, 05.jpg","ar":1.21,"py":"mujin mj","cr_by":"Wilhelm Zimmerling PAR","cr_lic":"CC BY-SA 4.0","cr_licurl":"https://creativecommons.org/licenses/by-sa/4.0","habit":"灌木","origin":["亚洲","欧洲","北美洲"]},{"id":591,"zh":"蜀葵","en":"Alcea rosea","sci":"Alcea rosea","order_en":"Malvales","order_zh":"锦葵目","family_en":"Malvaceae","family_zh":"锦葵科","iucn":null,"langs":52,"desc_zh":"蜀葵（学名：Alcea rosea）是锦葵科蜀葵属植物，又名一丈红、熟季花、麻杆花、戎葵、吴葵、卫足葵、胡葵、戎葵。古又名菺（音同肩）。在晋语地区俗称为大花。原产中国西南地区，15世纪前传入欧洲，世界各地均有栽培，花及根和种子可入药。","desc_en":"Alcea rosea, the common hollyhock, is an ornamental dicot flowering plant in the family Malvaceae. It was imported into Europe from southwestern China during, or possibly before, the 15th century.","img":"images/591.jpg","thumb":"images/t/591.jpg","file":"חוטמית תרבותית.jpg","ar":0.714,"py":"shukui sk","cr_by":"Hanay","cr_lic":"CC BY-SA 4.0","cr_licurl":"https://creativecommons.org/licenses/by-sa/4.0","habit":null,"origin":["亚洲","欧洲"]},{"id":592,"zh":"阔叶椴","en":"Tilia platyphyllos","sci":"Tilia platyphyllos","order_en":"Malvales","order_zh":"锦葵目","family_en":"Malvaceae","family_zh":"锦葵科","iucn":"LC","langs":49,"desc_zh":"阔叶椴（Tilia platyphyllos）是锦葵科的一种植物。阔叶椴是一种落叶树，原产并广泛分布于欧洲。阔叶椴也是常见的行道树，木材还可以用于雕刻。阔叶椴也经常是防护林的树种。","desc_en":"Tilia platyphyllos, the large-leaved lime, broad-leaved lime, or large-leaved linden, is a species of flowering plant in the family Malvaceae (Tiliaceae). It is a deciduous tree, native to much of continental Europe including southwestern Great Britain, typica…","img":"images/592.jpg","thumb":"images/t/592.jpg","file":"Lípa u Horního Záblatí v roce 2011 (1).JPG","ar":0.667,"py":"kuoyeduan kyd","cr_by":"Chmee2","cr_lic":"CC BY-SA 3.0","cr_licurl":"https://creativecommons.org/licenses/by-sa/3.0","habit":"乔木","origin":["欧洲"]},{"id":593,"zh":"轻木","en":"Ochroma pyramidale","sci":"Ochroma pyramidale","order_en":"Malvales","order_zh":"锦葵目","family_en":"Malvaceae","family_zh":"锦葵科","iucn":"LC","langs":47,"desc_zh":"轻木（学名：Ochroma pyramidale）为轻木属下唯一一种，属锦葵目锦葵科木棉亚科植物，是一种巨大，且生长快速的树，可以生长到30公尺高。轻木是一种常绿植物或是落叶植物（干季时）。也叫巴尔萨木、巴尔沙木或巴沙木（英语：balsa tree）。","desc_en":"Ochroma pyramidale, commonly known as balsa, is a large, fast-growing tree native to the Americas. It is the sole member of the genus Ochroma, and is classified in the subfamily Bombacoideae of the mallow family Malvaceae.","img":"images/593.jpg","thumb":"images/t/593.jpg","file":"Balsa Tree Flower - Flickr - treegrow.jpg","ar":1.333,"py":"qingmu qm","cr_by":"Katja Schulz from Washington, D. C., USA","cr_lic":"CC BY 2.0","cr_licurl":"https://creativecommons.org/licenses/by/2.0","habit":"乔木","origin":null},{"id":594,"zh":"欧洲瑞香","en":"Daphne mezereum","sci":"Daphne mezereum","order_en":"Malvales","order_zh":"锦葵目","family_en":"Thymelaeaceae","family_zh":"瑞香科","iucn":null,"langs":60,"desc_zh":"二月瑞香（学名：Daphne mezereum）是瑞香科瑞香属的一种植物，原产于欧洲与西亚大部分地区，北至斯堪的纳维亚北部与俄罗斯。在欧洲南部，二月瑞香主要生长于中高海拔与亚高山带。而在欧洲北部，则可生长于海平面附近。石灰岩地区较常见。","desc_en":"Daphne mezereum, the mezereon, is a species of Daphne in the flowering plant family Thymelaeaceae, native to most of Europe and Western Asia, north to northern Scandinavia and Russia.","img":"images/594.jpg","thumb":"images/t/594.jpg","file":"Daphne mezereum flowers - Keila.jpg","ar":0.7,"py":"ouzhouruixiang ozrx","cr_by":"Ivar Leidus","cr_lic":"CC BY-SA 4.0","cr_licurl":"https://creativecommons.org/licenses/by-sa/4.0","habit":null,"origin":["亚洲","欧洲"]},{"id":595,"zh":"洋瑞香","en":"Daphne laureola","sci":"Daphne laureola","order_en":"Malvales","order_zh":"锦葵目","family_en":"Thymelaeaceae","family_zh":"瑞香科","iucn":null,"langs":34,"desc_zh":null,"desc_en":"Daphne laureola, commonly called spurge-laurel, is a woodland shrub in the flowering plant family Thymelaeaceae. Its native range covers much of western and southern Europe and extends to Algeria, Morocco and the Azores.","img":"images/595.jpg","thumb":"images/t/595.jpg","file":"Daphne laureola.jpg","ar":0.75,"py":"yangruixiang yrx","cr_by":"User:Tigerente","cr_lic":"CC BY-SA 3.0","cr_licurl":"http://creativecommons.org/licenses/by-sa/3.0/","habit":"灌木","origin":["欧洲"]},{"id":596,"zh":"娑罗树","en":"Shorea robusta","sci":"Shorea robusta","order_en":"Malvales","order_zh":"锦葵目","family_en":"Dipterocarpaceae","family_zh":"龙脑香科","iucn":"NT","langs":48,"desc_zh":"娑罗树（学名：Shorea robusta），又名沙罗双树、钵罗叉树、波罗叉树，摩诃娑罗树、沙罗树、鹤林、鹄树、无忧树，为龙脑香科娑罗属植物，产于印度及马来半岛等南亚雨林之中。属多年生乔木。树身高大，叶为长卵形而尖，表面光滑，花淡黄色，萼及花瓣外有灰色刚毛。因为气味芳香，木材坚固，可以用来制作家具或建材，又可供作药用或香料。佛教视之为圣树之一。","desc_en":"Shorea robusta, the sal tree (Devanagari: साल ; IAST: sāla), shala, sakhua, or sarai, is a species of tree in the family Dipterocarpaceae. The tree is native to India, Bangladesh, Nepal, Tibet and across the Himalayan regions.","img":"images/596.jpg","thumb":"images/t/596.jpg","file":"Shorea robusta.jpg","ar":0.726,"py":"suoluoshu sls","cr_by":null,"cr_lic":"Public domain","cr_licurl":null,"habit":"乔木","origin":["亚洲"]},{"id":597,"zh":"龙脑香","en":"Dryobalanops aromatica","sci":"Dryobalanops aromatica","order_en":"Malvales","order_zh":"锦葵目","family_en":"Dipterocarpaceae","family_zh":"龙脑香科","iucn":"VU","langs":22,"desc_zh":null,"desc_en":"Dryobalanops aromatica, commonly known as Borneo camphor, camphor tree, Malay camphor, or Sumatran camphor, is a species of plant in the family Dipterocarpaceae.","img":"images/597.jpg","thumb":"images/t/597.jpg","file":"Dryobalanops Aromatica canopy.jpg","ar":1.333,"py":"longnaoxiang lnx","cr_by":"Patrice78500","cr_lic":"Public domain","cr_licurl":null,"habit":"乔木","origin":["亚洲"]},{"id":598,"zh":"铺地半日花","en":"Helianthemum nummularium","sci":"Helianthemum nummularium","order_en":"Malvales","order_zh":"锦葵目","family_en":"Cistaceae","family_zh":"半日花科","iucn":null,"langs":34,"desc_zh":null,"desc_en":"Helianthemum nummularium (known as common rock-rose) is a species of rock-rose (Cistaceae), native to most of Europe.","img":"images/598.jpg","thumb":"images/t/598.jpg","file":"Helianthemum nummularium1.jpg","ar":0.75,"py":"pudibanrihua pdbrh","cr_by":null,"cr_lic":"CC BY-SA 2.5","cr_licurl":"https://creativecommons.org/licenses/by-sa/2.5","habit":null,"origin":["欧洲"]},{"id":599,"zh":"鼠尾草叶岩蔷薇","en":"Cistus salviifolius","sci":"Cistus salviifolius","order_en":"Malvales","order_zh":"锦葵目","family_en":"Cistaceae","family_zh":"半日花科","iucn":null,"langs":31,"desc_zh":null,"desc_en":"Cistus salviifolius, common names sage-leaved rock-rose, salvia cistus or Gallipoli rose, is a shrub of the family Cistaceae.","img":"images/599.jpg","thumb":"images/t/599.jpg","file":"00 3288 Cistus salviifolius - Salbeiblättrige Zistrose.jpg","ar":1.531,"py":"shuweicaoyeyanqiangwei swcyyqw","cr_by":"W. Bulach","cr_lic":"CC BY-SA 4.0","cr_licurl":"https://creativecommons.org/licenses/by-sa/4.0","habit":"灌木","origin":null},{"id":600,"zh":"萝卜","en":"Raphanus sativus","sci":"Raphanus sativus","order_en":"Brassicales","order_zh":"十字花目","family_en":"Brassicaceae","family_zh":"十字花科","iucn":null,"langs":134,"desc_zh":"萝卜（bo）（学名：Raphanus raphanistrum subsp. sativus），别名莱菔、芦菔、菈𦿚（音同“拉沓”），在中国福建下路地区、潮汕地区、四县与台湾俗称菜头（台罗：tshài-thâu），为十字花科萝卜属草本植物，是野萝卜的亚种。 萝卜的根部是最常见的蔬菜之一，但实际上整株植物均可食用。目前有专门食用叶子的品种，称为“叶萝卜”。种子称为莱菔子，是常用的中药。 萝卜分为白萝卜、青萝卜和樱桃萝卜三种。","desc_en":"The radish (Raphanus sativus or Raphanus raphanistrum subsp. sativus) is a flowering plant in the mustard family, Brassicaceae. Its large taproot is commonly used as a root vegetable, although the entire plant is edible and its leaves are sometimes used as a l…","img":"images/600.jpg","thumb":"images/t/600.jpg","file":"Radish 3371103037 4ab07db0bf o.jpg","ar":0.75,"py":"luobo lb","cr_by":"Self, en:User:Jengod","cr_lic":"CC BY-SA 3.0","cr_licurl":"https://creativecommons.org/licenses/by-sa/3.0","habit":null,"origin":["亚洲"]},{"id":601,"zh":"甘蓝","en":"Brassica oleracea","sci":"Brassica oleracea","order_en":"Brassicales","order_zh":"十字花目","family_en":"Brassicaceae","family_zh":"十字花科","iucn":"DD","langs":114,"desc_zh":"甘蓝（学名：Brassica oleracea）是十字花科植物，具多个变种，依食用部位概略分为：花用甘蓝（花椰菜、西兰花）、叶用甘蓝（高丽菜、叶用不结球甘蓝、芥蓝）、茎用甘蓝（苤蓝）等，是被人类广泛食用的蔬菜。","desc_en":"Brassica oleracea, also known as wild cabbage in its uncultivated form, is a plant of the family Brassicaceae. The species originated from feral populations of related plants in the Eastern Mediterranean, where it was most likely first cultivated.","img":"images/601.jpg","thumb":"images/t/601.jpg","file":"Brassica oleracea - Royal Botanical Garden, Madrid.JPG","ar":0.75,"py":"ganlan gl","cr_by":"Daderot","cr_lic":"Public domain","cr_licurl":null,"habit":null,"origin":["欧洲"]},{"id":602,"zh":"欧洲油菜","en":"Brassica napus","sci":"Brassica napus","order_en":"Brassicales","order_zh":"十字花目","family_en":"Brassicaceae","family_zh":"十字花科","iucn":null,"langs":93,"desc_zh":"西洋油菜（学名：Brassica napus）又名甘蓝型油菜、大油菜，是十字花科草本植物，主要用途是油料经济作物。油菜籽的种籽粒可制油脂，它分为冬油菜和春油菜两种。 油菜籽含芥酸、芥子碱、单宁等化学物质，含毒性。","desc_en":"Rapeseed (Brassica napus subsp. napus), also known as rape and oilseed rape and canola, is a yellow-flowered member of the Brassicaceae family. The plant is cultivated primarily for its oil-rich seed, which naturally contains mildly toxic erucic acid.","img":"images/602.jpg","thumb":"images/t/602.jpg","file":"(MHNT) Brassica napus - Habit.jpg","ar":0.983,"py":"ouzhouyoucai ozyc","cr_by":"Didier Descouens","cr_lic":"CC BY-SA 4.0","cr_licurl":"https://creativecommons.org/licenses/by-sa/4.0","habit":null,"origin":null},{"id":603,"zh":"辣根","en":"Armoracia rusticana","sci":"Armoracia rusticana","order_en":"Brassicales","order_zh":"十字花目","family_en":"Brassicaceae","family_zh":"十字花科","iucn":"LC","langs":81,"desc_zh":"辣根（学名：Armoracia rusticana），又称西洋山嵛菜、马萝卜、山萝卜、粉山葵、西洋山葵，原产东南欧，是十字花科辣根属多年生宿根耐寒植物。可以作为蔬菜使用，具有刺激鼻窦的香辣味道。辣根用于欧洲国家的烤牛肉等菜肴的佐料以外，因削皮后是白的，加入食用色素后可作为仿制山葵调料的材料。","desc_en":"Horseradish (Armoracia rusticana, syn. Cochlearia armoracia) is a perennial plant of the family Brassicaceae (which also includes mustard, wasabi, broccoli, cabbage, and radish).","img":"images/603.jpg","thumb":"images/t/603.jpg","file":"Armoracia rusticana.jpg","ar":0.75,"py":"lagen lg","cr_by":"Pethan","cr_lic":"CC BY-SA 3.0","cr_licurl":"http://creativecommons.org/licenses/by-sa/3.0/","habit":"草本","origin":["亚洲","欧洲"]},{"id":604,"zh":"水芹","en":"Lepidium sativum","sci":"Lepidium sativum","order_en":"Brassicales","order_zh":"十字花目","family_en":"Brassicaceae","family_zh":"十字花科","iucn":null,"langs":78,"desc_zh":"家独行菜（学名：Lepidium sativum）是十字花科独行菜属的植物，有时讹称水芹，与伞形科的真水芹相混淆。","desc_en":"Cress (Lepidium sativum), sometimes referred to as garden cress (or curly cress) to distinguish it from similar plants also referred to as cress (from Old English cresse), is a fast-growing, edible herb.","img":"images/604.jpg","thumb":"images/t/604.jpg","file":"Img 0717 garden cress.jpg","ar":1.506,"py":"shuiqin sq","cr_by":null,"cr_lic":"CC BY-SA 3.0","cr_licurl":"http://creativecommons.org/licenses/by-sa/3.0/","habit":"禾草","origin":null},{"id":605,"zh":"西洋菜","en":"Nasturtium officinale","sci":"Nasturtium officinale","order_en":"Brassicales","order_zh":"十字花目","family_en":"Brassicaceae","family_zh":"十字花科","iucn":"LC","langs":76,"desc_zh":"西洋菜（学名：Nasturtium officinale），别名豆瓣菜、水田芥、水芥菜、荷兰芥菜、水蔊菜等，是十字花科西洋菜属的一种植物。其为牛羊肝吸虫的第二中间宿主（病媒），因此作为食物食用的西洋菜需煮熟，以防感染。 西洋菜速生，原产于欧洲和亚洲，是已知最早被人类食用的叶菜之一。西洋菜和其近亲水芹、芥菜、萝卜、山葵等都有明显的辣味。 西洋菜的茎中空，使其可以漂浮在水面。白色丛生的花容易吸引食蚜蝇科的昆虫。","desc_en":"Watercress or yellowcress (Nasturtium officinale) is a species of aquatic flowering plant in the cabbage family, Brassicaceae. Watercress is a rapidly growing perennial plant native to Eurasia. It is one of the oldest known leaf vegetables consumed by humans.","img":"images/605.jpg","thumb":"images/t/605.jpg","file":"Cresson 02.jpg","ar":0.75,"py":"xiyangcai xyc","cr_by":"Chirocca77","cr_lic":"CC BY 4.0","cr_licurl":"https://creativecommons.org/licenses/by/4.0","habit":"草本","origin":["亚洲"]},{"id":606,"zh":"芸苔","en":"Brassica rapa","sci":"Brassica rapa","order_en":"Brassicales","order_zh":"十字花目","family_en":"Brassicaceae","family_zh":"十字花科","iucn":null,"langs":72,"desc_zh":"芸薹（学名：Brassica rapa），是芸薹属的一种植物，可作为叶菜（如小白菜、大白菜、菜心）、根用植物（如芜菁）和作为植物油（又称白菜型油菜注意，此并非更常见的甘蓝型油菜，详见油菜）食用。 在十八世纪时，卡尔·林奈视芜菁和油用的变种（即白菜型油菜）为不同的品种并分别命名为 B. rapa 和 B. campestris。然而二十世纪的分类学家发现这些植物是异体受精，因此认为是相同的物种。","desc_en":"Brassica rapa is an annual to biennial plant species native to Eurasia that is from the Brassicaceae family. The B. rapa subspecies oleifera is an oilseed commonly known as turnip rape, field mustard, bird's rape, and keblock.","img":"images/606.jpg","thumb":"images/t/606.jpg","file":"Malselvneper.JPG","ar":1.494,"py":"yuntai yt","cr_by":"Osopolar","cr_lic":"CC BY-SA 3.0","cr_licurl":"https://creativecommons.org/licenses/by-sa/3.0","habit":"草本","origin":["亚洲"]},{"id":607,"zh":"山葵","en":"Eutrema japonicum","sci":"Eutrema japonicum","order_en":"Brassicales","order_zh":"十字花目","family_en":"Brassicaceae","family_zh":"十字花科","iucn":null,"langs":66,"desc_zh":"山葵（学名：Eutrema japonicum；日语：山葵／わさび／ワサビ，罗马化：wasabi），音译为哇沙米 （台罗：ua-sá-bih）、哇沙比，又称为山萮菜，是一种属于十字花科山萮菜属的绿色植物，味道极其强烈。山葵的辛辣跟辣椒不同，辣椒的辣味刺激舌头，而山葵的辣味却刺激鼻窦。山葵常见于日本山谷河流旁边生长，其他品种包括W. koreana及W. tetsuigi；市面上普遍出售的两种山葵是W.","desc_en":"Wasabi (Japanese: ワサビ, わさび, or 山葵, pronounced [waꜜsabi]) or Japanese horseradish (Eutrema japonicum syn. Wasabia japonica) is a plant of the family Brassicaceae, which also includes horseradish and mustard in other genera.","img":"images/607.jpg","thumb":"images/t/607.jpg","file":"Fresh wasabi rhizomes.jpg","ar":1.333,"py":"shankui sk","cr_by":"Sabigirl at English Wikipedia","cr_lic":"Public domain","cr_licurl":null,"habit":null,"origin":["亚洲"]},{"id":608,"zh":"荠菜","en":"Capsella bursa-pastoris","sci":"Capsella bursa-pastoris","order_en":"Brassicales","order_zh":"十字花目","family_en":"Brassicaceae","family_zh":"十字花科","iucn":null,"langs":66,"desc_zh":"荠菜（学名：Capsella bursa-pastoris），又名护生草、地菜、地米菜、菱闸菜等，十字花科荠菜属植物。起源于东欧和小亚细亚，目前在世界各地都很常见。其种加词来自拉丁语，意思是“小盒子”、“牧人的钱包”，是形容它的角果形状像牧人的钱包。","desc_en":"Capsella bursa-pastoris, commonly known as shepherd's purse or lady's purse, is a small flowering plant in the mustard family. It has been described as a protocarnivore because its seeds contain mucilage, which traps nematodes.","img":"images/608.jpg","thumb":"images/t/608.jpg","file":"Capsella bursa-pastoris.JPG","ar":0.657,"py":"qicai qc","cr_by":"Eike Wulfmeyer","cr_lic":"CC BY-SA 2.5","cr_licurl":"https://creativecommons.org/licenses/by-sa/2.5","habit":null,"origin":["亚洲"]},{"id":609,"zh":"黑芥","en":"Brassica nigra","sci":"Brassica nigra","order_en":"Brassicales","order_zh":"十字花目","family_en":"Brassicaceae","family_zh":"十字花科","iucn":"LC","langs":61,"desc_zh":"黑芥（学名：Brassica nigra）是十字花科芸苔属的一种一年生植物，种子可作为香料。其原产于北非热带地区、欧洲温带地区与亚洲部分地区。","desc_en":"Rhamphospermum nigrum (syns. Mutarda nigra, Brassica nigra, and Sinapis nigra), black mustard, is an annual plant native to cooler regions of North Africa, temperate regions of Europe, and parts of Asia..","img":"images/609.jpg","thumb":"images/t/609.jpg","file":"Brassica nigra - Köhler–s Medizinal-Pflanzen-170.jpg","ar":0.818,"py":"heijie hj","cr_by":"Walther Otto Müller","cr_lic":"Public domain","cr_licurl":null,"habit":"草本","origin":["亚洲","欧洲","非洲"]},{"id":610,"zh":"芥菜","en":"Brassica juncea","sci":"Brassica juncea","order_en":"Brassicales","order_zh":"十字花目","family_en":"Brassicaceae","family_zh":"十字花科","iucn":null,"langs":61,"desc_zh":"芥菜（学名：Brassica juncea，英语：mustard greens）俗称辣菜、刈菜、大菜，是十字花科芸薹属一年生草本植物。研究发现芥菜最早起源于西亚，向东传播后，在中国北部驯化出根芥、在中亚的南部、南亚的北部驯化出籽用芥菜、在中国南部驯化出叶用芥菜和茎用芥菜。","desc_en":"Brassica juncea, commonly mustard greens, brown mustard, Chinese mustard, Indian mustard, Japanese mustard, Korean green mustard, leaf mustard, Oriental mustard and vegetable mustard, is a species of mustard plant.","img":"images/610.jpg","thumb":"images/t/610.jpg","file":"Brassica juncea var. juncea.JPG","ar":0.667,"py":"jiecai jc","cr_by":"Dalgial","cr_lic":"CC BY-SA 3.0","cr_licurl":"https://creativecommons.org/licenses/by-sa/3.0","habit":null,"origin":["亚洲"]},{"id":611,"zh":"白芥","en":"Sinapis alba","sci":"Sinapis alba","order_en":"Brassicales","order_zh":"十字花目","family_en":"Brassicaceae","family_zh":"十字花科","iucn":null,"langs":59,"desc_zh":"白芥（学名：Sinapis alba），为十字花科白芥属下的一个植物种。其种加词“alba”意为“白色的”。","desc_en":"White mustard (Sinapis alba), also called yellow mustard, is an annual plant of the cabbage family. It is sometimes also referred to as Brassica alba or B. hirta.","img":"images/611.jpg","thumb":"images/t/611.jpg","file":"Sinapis alba 1.JPG","ar":0.75,"py":"baijie bj","cr_by":"Ariel Palmon","cr_lic":"CC BY-SA 3.0","cr_licurl":"https://creativecommons.org/licenses/by-sa/3.0","habit":"草本","origin":["亚洲","欧洲"]},{"id":612,"zh":"拟南芥","en":"Arabidopsis thaliana","sci":"Arabidopsis thaliana","order_en":"Brassicales","order_zh":"十字花目","family_en":"Brassicaceae","family_zh":"十字花科","iucn":null,"langs":54,"desc_zh":"阿拉伯芥（学名：Arabidopsis thaliana），又名阿拉伯芥、鼠耳芥、阿拉伯草，是一种原生于欧亚大陆及非洲的被子植物。拟南芥被认为是一种杂草；它可在路边和被扰动土地上被找到。 拟南芥是一个生命周期相对较短的冬季一年生植物，它是植物生物学和遗传学领域的流行的模式生物。对于一个复杂的多细胞真核生物，拟南芥有一个相对较小的基因组，大约135百万碱基对（Mbp）。拟南芥是第一个基因组被完整测序的植物。","desc_en":"Arabidopsis thaliana, the thale cress, mouse-ear cress or arabidopsis, is a small plant from the mustard family (Brassicaceae), native to Eurasia and Africa. Commonly found along the shoulders of roads and in disturbed land, it is generally considered a weed.","img":"images/612.jpg","thumb":"images/t/612.jpg","file":"Arabidopsis thaliana.jpg","ar":0.721,"py":"ninanjie nnj","cr_by":"Original uploader was Brona at en.wikipedia . User:Roepers at nl.wikipedia","cr_lic":"CC BY-SA 3.0","cr_licurl":"http://creativecommons.org/licenses/by-sa/3.0/","habit":"草本","origin":["亚洲","非洲"]},{"id":613,"zh":"番木瓜","en":"Carica papaya","sci":"Carica papaya","order_en":"Brassicales","order_zh":"十字花目","family_en":"Caricaceae","family_zh":"番木瓜科","iucn":"DD","langs":163,"desc_zh":"番木瓜（学名：Carica papaya）又名木瓜、万寿果，热带和亚热带大型草本，叶大掌状，大多为雌雄异株，花黄色，果实长圆形，果肉厚味甜。木瓜的乳汁含木瓜蛋白酶，是制作松肉粉的主要成分。 中国古代即有“木瓜”，《诗经·卫风·木瓜》所称之“木瓜”是贴梗海棠的果实，而番木瓜约在17世纪引进中国大陆，约在清朝末年再引入台湾。","desc_en":"The papaya (, US: ) is the plant species Carica papaya, one of the 21 accepted species in the genus Carica of the family Caricaceae. It was first domesticated in Mesoamerica, within modern-day southern Mexico and Central America.","img":"images/613.jpg","thumb":"images/t/613.jpg","file":"Carica papaya - Köhler–s Medizinal-Pflanzen-029.jpg","ar":0.708,"py":"fanmugua fmg","cr_by":"Franz Eugen Köhler, Köhler's Medizinal-Pflanzen","cr_lic":"Public domain","cr_licurl":null,"habit":null,"origin":["北美洲"]},{"id":614,"zh":"旱金莲","en":"Tropaeolum majus","sci":"Tropaeolum majus","order_en":"Brassicales","order_zh":"十字花目","family_en":"Tropaeolaceae","family_zh":"旱金莲科","iucn":null,"langs":54,"desc_zh":"旱金莲（学名：Tropaeolum majus）又名金莲花，十字花目旱金莲科旱金莲属植物，与另一个同名的金莲花（Trollius chinensis，毛茛目毛茛科金莲花属）不同。 在台湾俗称的金莲花，实际上是旱金莲。","desc_en":"Tropaeolum majus, the garden nasturtium, nasturtium, Indian cress or monk's cress, is a species of flowering plant in the family Tropaeolaceae. An annual or a short-lived perennial with disc-shaped leaves and brilliant yellow, orange or red flowers, it is of c…","img":"images/614.jpg","thumb":"images/t/614.jpg","file":"Tropaeolum majus 2005 G1.jpg","ar":1.094,"py":"hanjinlian hjl","cr_by":"George Chernilevsky","cr_lic":"Public domain","cr_licurl":null,"habit":"草本","origin":["亚洲"]},{"id":615,"zh":"刺山柑","en":"Capparis spinosa","sci":"Capparis spinosa","order_en":"Brassicales","order_zh":"十字花目","family_en":"Capparaceae","family_zh":"山柑科","iucn":"LC","langs":79,"desc_zh":"刺山柑（学名：Capparis spinosa），又名马槟榔、棘风蝶木、西洋风蝶木、酸豆、水瓜柳、水瓜榴或是水瓜钮，是一种多年生的有刺半蔓性灌木，属于山柑科山柑属。刺山柑在台湾常被称为续随子，但真正的续随子是大戟属植物。刺山柑的叶厚身、对生、呈鹅卵形，有大大的白色到粉白色的花朵。原产于地中海的刺山柑，会在石墙或岩岸生长。当地人会把植物的果实腌制，可作调味用途。花蕾及果实可食用，但一般都会先腌制。","desc_en":"Capparis spinosa, the caper bush, also called Flinders rose, is a perennial plant that bears rounded, fleshy leaves and large white to pinkish-white flowers. The taxonomic status of the species is controversial and unsettled.","img":"images/615.jpg","thumb":"images/t/615.jpg","file":"Capparis zoharyi 4.jpg","ar":1.254,"py":"cishangan csg","cr_by":null,"cr_lic":"Public domain","cr_licurl":null,"habit":"灌木","origin":["欧洲"]},{"id":616,"zh":"檀香","en":"Santalum album","sci":"Santalum album","order_en":"Santalales","order_zh":"檀香目","family_en":"Santalaceae","family_zh":"檀香科","iucn":null,"langs":65,"desc_zh":"檀香树（学名：Santalum album；梵语：चन्दन，IAST：candana），又名真檀（《本草纲目》）、栴檀、旃檀、白旃檀（《楞严经》）、白檀、檀香，是檀香科檀香属的一种半寄生性植物。原产地为马来西亚半岛等东南亚地区，再经由海上贸易传播到印度，澳洲，再经由随佛教来到中国。品质纯正的檀香是一味中药材，分为檀香片和檀香粉，放在专用的檀香炉中燃烧，它独特的安抚作用可以使人清心、凝神、排除杂念，是修生养性的辅助工具。","desc_en":"Santalum album is a small tropical tree, and the traditional source of sandalwood oil. It is native to Indonesia (Java and the Lesser Sunda Islands), the Philippines, and Western Australia. It is commonly known as the white sandalwood or Indian sandalwood.","img":"images/616.jpg","thumb":"images/t/616.jpg","file":"Santalum album - Köhler–s Medizinal-Pflanzen-128.jpg","ar":0.734,"py":"tanxiang tx","cr_by":"Franz Eugen Köhler, Köhler's Medizinal-Pflanzen","cr_lic":"Public domain","cr_licurl":null,"habit":"乔木","origin":["亚洲","大洋洲"]},{"id":617,"zh":"槲寄生","en":"Viscum album","sci":"Viscum album","order_en":"Santalales","order_zh":"檀香目","family_en":"Santalaceae","family_zh":"檀香科","iucn":null,"langs":61,"desc_zh":"白果槲寄生（学名：Viscum album）又名欧洲槲寄生，是檀香科、槲寄生属的一种半寄生植物，从寄主树体获取水分与养分，原生于西亚、南亚和欧洲，在欧洲神话、传说与民俗中具有重要地位。现代西方仍将白果槲寄生作为圣诞节相关的装饰及象征物使用。 在北美，其文化角色通常由外形相近的本土种北美肉穗寄生所替代。","desc_en":"Viscum album is a species of mistletoe in the family Santalaceae, commonly called European mistletoe, common mistletoe, or simply mistletoe (Old English mistle). It is native to Europe, as well as western and southern Asia. V.","img":"images/617.jpg","thumb":"images/t/617.jpg","file":"Viscum album 2026 G1.jpg","ar":1,"py":"hujisheng hjs","cr_by":"George Chernilevsky","cr_lic":"CC BY 4.0","cr_licurl":"https://creativecommons.org/licenses/by/4.0","habit":"乔木","origin":["亚洲","欧洲"]},{"id":618,"zh":"澳洲圣诞树","en":"Nuytsia floribunda","sci":"Nuytsia floribunda","order_en":"Santalales","order_zh":"檀香目","family_en":"Loranthaceae","family_zh":"桑寄生科","iucn":"LC","langs":17,"desc_zh":"多花金焰檀（学名：Nuytsia floribunda）是分布在西澳洲的大型寄生植物，因花期在圣诞节前后而又名澳洲圣诞树，是金焰檀属现存唯一物种。","desc_en":"Nuytsia floribunda is a hemiparasitic tree found in Western Australia. The species is known locally as moodjar and, more recently, the Christmas tree or Western Australian Christmas tree.","img":"images/618.jpg","thumb":"images/t/618.jpg","file":"Christmas tree 02 gnangarra.jpg","ar":1.333,"py":"aozhoushengdanshu azsds","cr_by":"Gnangarra","cr_lic":"CC BY 2.5 au","cr_licurl":"https://creativecommons.org/licenses/by/2.5/au/deed.en","habit":"乔木","origin":["大洋洲"]},{"id":619,"zh":"小叶钝果寄生","en":"Taxillus kaempferi","sci":"Taxillus kaempferi","order_en":"Santalales","order_zh":"檀香目","family_en":"Loranthaceae","family_zh":"桑寄生科","iucn":null,"langs":13,"desc_zh":"小叶钝果寄生（学名：Taxillus kaempferi），为桑寄生科钝果寄生属下的一个植物种。","desc_en":"Taxillus kaempferi (Chinese: 小叶钝果寄生; pinyin: xiao ye dun guo ji sheng) is a parasitic plant species in the genus Taxillus found in China (Anhui, Fujian, W Hubei, S Jiangxi, Sichuan, S Zhejiang), Bhutan and Japan. Its host is Pinus thunbergii.","img":"images/619.jpg","thumb":"images/t/619.jpg","file":"Taxillus kaempferi matugumi01.jpg","ar":1.333,"py":"xiaoyedunguojisheng xydgjs","cr_by":"Keisotyo","cr_lic":"CC BY-SA 4.0","cr_licurl":"https://creativecommons.org/licenses/by-sa/4.0","habit":null,"origin":["亚洲"]},{"id":620,"zh":"梨果仙人掌","en":"Opuntia ficus-indica","sci":"Opuntia ficus-indica","order_en":"Caryophyllales","order_zh":"石竹目","family_en":"Cactaceae","family_zh":"仙人掌科","iucn":"DD","langs":64,"desc_zh":"梨果仙人掌又名食用仙人掌（学名：Opuntia ficus-indica）为仙人掌科仙人掌属的植物。分布于吉海及红海沿岸、澳洲大陆全境、毛里求斯、南非、东非、夏威夷以及台湾、云南、广东、四川、福建、贵州、浙江、广西等地，生长于海拔600米至2,900米的地区，多生在热河谷，目前尚未由人工引种栽培。","desc_en":"Opuntia ficus-indica, the Indian fig opuntia, fig opuntia, or prickly pear, is a species of cactus that has long been a domesticated crop plant grown in agricultural economies throughout arid and semiarid parts of the world. O.","img":"images/620.jpg","thumb":"images/t/620.jpg","file":"Dikenli İncir (Opuntia ficus-indica) Gaziantep Turkey.IMG 1104.jpg","ar":0.75,"py":"liguoxianrenzhang lgxrz","cr_by":"YG01","cr_lic":"CC BY 4.0","cr_licurl":"https://creativecommons.org/licenses/by/4.0","habit":"多肉","origin":["亚洲"]},{"id":621,"zh":"巨人柱","en":"Carnegiea gigantea","sci":"Carnegiea gigantea","order_en":"Caryophyllales","order_zh":"石竹目","family_en":"Cactaceae","family_zh":"仙人掌科","iucn":"LC","langs":55,"desc_zh":"巨人柱（学名：Carnegiea gigantea）是仙人掌科巨人柱属（Carnegiea）的唯一物种，也是世界最高的仙人掌品种之一，高度可超过12公尺。原产于墨西哥的索诺拉州、美国亚利桑那州的索诺拉沙漠以及加利福尼亚州的惠普尔山脉和帝国郡。巨人柱的花为亚利桑那州的州花。其学名是为了纪念美国企业家暨慈善家安德鲁·卡内基而起。1994年，巨人柱国家公园于亚利桑那州土桑设立，致力于保育巨人柱以及其栖地。","desc_en":"The saguaro ( sə-(G)WAR-oh, Spanish: [saˈɣwaɾo]; Carnegiea gigantea) is a tree-like cactus species in the monotypic genus Carnegiea that can grow to be over 12 meters (40 feet) tall.","img":"images/621.jpg","thumb":"images/t/621.jpg","file":"CarnegieaGigantea.jpg","ar":0.75,"py":"jurenzhu jrz","cr_by":"RoFra","cr_lic":"CC BY-SA 3.0 de","cr_licurl":"https://creativecommons.org/licenses/by-sa/3.0/de/deed.en","habit":"多肉","origin":["北美洲"]},{"id":622,"zh":"乌羽玉","en":"Lophophora williamsii","sci":"Lophophora williamsii","order_en":"Caryophyllales","order_zh":"石竹目","family_en":"Cactaceae","family_zh":"仙人掌科","iucn":"VU","langs":55,"desc_zh":"乌羽玉（学名：Lophophora williamsii），音译配有特（英语：Peyote），又称作威廉斯氏仙人球，俗称无刺的仙人掌，是一种细小及无刺的仙人掌。它们原产于美国德克萨斯州西南部至墨西哥，主要在奇瓦瓦沙漠、塔毛利帕斯州及圣路易斯波托西州生长。 乌羽玉及其同属的银冠玉均含有精神生物碱，如麦司卡林（三甲氧苯乙胺）等，会使人产生幻觉。故被用在宗教致幻剂及多种宗教超越上，包括冥想及迷幻药治疗法等。","desc_en":"Peyote, also known as Lophophora williamsii, is a small, spineless cactus which contains psychoactive alkaloids, particularly mescaline. Peyote is a Spanish word derived from the Nahuatl peyōtl, meaning \"caterpillar cocoon\", from a root peyōni, \"to glisten\".","img":"images/622.jpg","thumb":"images/t/622.jpg","file":"Peyote Cactus.jpg","ar":1.506,"py":"wuyuyu wyy","cr_by":null,"cr_lic":"Public domain","cr_licurl":null,"habit":"多肉","origin":["北美洲"]},{"id":623,"zh":"金琥","en":"Kroenleinia grusonii","sci":"Kroenleinia grusonii","order_en":"Caryophyllales","order_zh":"石竹目","family_en":"Cactaceae","family_zh":"仙人掌科","iucn":null,"langs":32,"desc_zh":"金鯱（学名：Echinocactus grusonii），又称象牙球、金鯱仙人球，是强刺球类仙人掌的代表，原产墨西哥中部圣路易波托西至伊达尔戈干燥炎热的沙漠地带。金鯱虽然在观赏植物市场中很普遍，但野生的金鯱却是濒危的稀有植物。 本种是仙人掌类中最具魅力的一类植物。它拥有浑圆碧绿的球体及钢硬的金黄色硬刺。球体的直径可达1米左右，球体顶部密生一圈金黄色的绒毛。金鯱顶部有21-27个棱脊高耸的直棱(一般仙人球只有棱12-14个)。","desc_en":"Kroenleinia grusonii, popularly known as the golden barrel cactus, golden ball, \"mother-in-law's cushion\" or \"mother-in-law's chair\", is a species of barrel cactus which is endemic to east-central Mexico.","img":"images/623.jpg","thumb":"images/t/623.jpg","file":"Echinocactus grusonii (aka).jpg","ar":1.08,"py":"jinhu jh","cr_by":"André Karwath aka Aka","cr_lic":"CC BY-SA 2.5","cr_licurl":"https://creativecommons.org/licenses/by-sa/2.5","habit":"多肉","origin":["北美洲"]},{"id":624,"zh":"昙花","en":"Epiphyllum oxypetalum","sci":"Epiphyllum oxypetalum","order_en":"Caryophyllales","order_zh":"石竹目","family_en":"Cactaceae","family_zh":"仙人掌科","iucn":"LC","langs":29,"desc_zh":"昙花（学名：Epiphyllum oxypetalum）也叫月下美人，是仙人掌科昙花属的一个种，原产墨西哥南部和中美洲。","desc_en":"Epiphyllum oxypetalum, the Dutchman's pipe cactus, princess of the night or queen of the night, is a species of cactus with a native range from Mexico to Nicaragua. It blooms nocturnally, and its flowers wilt before dawn.","img":"images/624.jpg","thumb":"images/t/624.jpg","file":"Nightblooming cereum.JPG","ar":1.501,"py":"tanhua th","cr_by":"Bobjgalindo","cr_lic":"CC BY-SA 4.0","cr_licurl":"https://creativecommons.org/licenses/by-sa/4.0","habit":"多肉","origin":["北美洲"]},{"id":625,"zh":"量天尺","en":"Selenicereus undatus","sci":"Selenicereus undatus","order_en":"Caryophyllales","order_zh":"石竹目","family_en":"Cactaceae","family_zh":"仙人掌科","iucn":null,"langs":28,"desc_zh":"量天尺（学名：Selenicereus undatus；异名：Hylocereus undatus），是仙人掌科蛇鞭柱属（旧属量天尺属）的植物。原产墨西哥南部及中美洲，现已在全球热带及亚热带地区广泛栽培，在澳大利亚、夏威夷、中国大陆（福建、广东、海南、广西）以及台湾等地归化，以气根攀缘于树干、岩石或墙壁上。","desc_en":"Selenicereus undatus, the white-fleshed pitahaya, is a species of the genus Selenicereus (formerly Hylocereus) in the family Cactaceae and is the most cultivated species in the genus.","img":"images/625.jpg","thumb":"images/t/625.jpg","file":"Selenicereus undatus 173646842.jpeg","ar":0.563,"py":"liangtianchi ltc","cr_by":"Tiago Lubiana","cr_lic":"CC0","cr_licurl":"http://creativecommons.org/publicdomain/zero/1.0/deed.en","habit":"多肉","origin":null},{"id":626,"zh":"星叶球","en":"Astrophytum asterias","sci":"Astrophytum asterias","order_en":"Caryophyllales","order_zh":"石竹目","family_en":"Cactaceae","family_zh":"仙人掌科","iucn":"VU","langs":26,"desc_zh":"星球（学名：Astrophytum asterias），又称星红仙人球、星叶球或兜，是一种无针的仙人掌，属于仙人掌科有星属。它们细小，直径长5-15厘米，高2-5厘米。在野外生长的，整个夏天都会开花。 星红仙人球的成熟期很长，并被列为易危。它们的衰落是因过度采集所致，城市化及除草剂的使用也有影响。幸运的是它们可以种子传播，虽然在野外已很稀少，但仍可靠种植来保存。它们现已有多个的栽培种，其中包括有很多斑点的「超兜」。","desc_en":"Astrophytum asterias is a species of cactus in the genus Astrophytum, and is native to small parts of Texas in the United States and Mexico. Common names include sand dollar cactus, sea urchin cactus, star cactus and star peyote.","img":"images/626.jpg","thumb":"images/t/626.jpg","file":"Astrophytum asterias11.jpg","ar":1.333,"py":"xingyeqiu xyq","cr_by":"GaleoC","cr_lic":"CC BY-SA 3.0","cr_licurl":"https://creativecommons.org/licenses/by-sa/3.0","habit":"多肉","origin":["北美洲"]},{"id":627,"zh":"蛇鞭柱","en":"Selenicereus grandiflorus","sci":"Selenicereus grandiflorus","order_en":"Caryophyllales","order_zh":"石竹目","family_en":"Cactaceae","family_zh":"仙人掌科","iucn":"LC","langs":26,"desc_zh":"蛇鞭柱（学名：Selenicereus grandiflorus）是仙人掌科蛇鞭柱属的模式种，也叫大花蛇鞭柱（其种加词grandiflorus意为“大花的”），原产墨西哥、中美洲和加勒比地区。蛇鞭柱和昙花一样只在夜晚开花。","desc_en":"Selenicereus grandiflorus is a cactus species originating from the Antilles, Mexico and Central America. The species is commonly referred to as queen of the night, night-blooming cereus (though these two terms are also used for other species), large-flowered c…","img":"images/627.jpg","thumb":"images/t/627.jpg","file":"Johann Jacob Haid Cereus.jpg","ar":0.689,"py":"shebianzhu sbz","cr_by":"Johann Jakob Haid","cr_lic":"Public domain","cr_licurl":null,"habit":"多肉","origin":["北美洲"]},{"id":628,"zh":"蟹爪兰","en":"Schlumbergera truncata","sci":"Schlumbergera truncata","order_en":"Caryophyllales","order_zh":"石竹目","family_en":"Cactaceae","family_zh":"仙人掌科","iucn":"VU","langs":25,"desc_zh":"蟹爪兰（学名：Schlumbergera truncata）又称螃蟹兰、感恩节仙人掌（英语：Thanksgiving cactus），是一种附生性小灌木，属双子叶植物石竹目仙人掌科仙人指属植物。其节径连接形状如螃蟹的副爪，故名蟹爪兰，但并非兰科物种。","desc_en":"Schlumbergera truncata, the false Christmas cactus, is a species of plant in the family Cactaceae. It is endemic to a small area of the coastal mountains of south-eastern Brazil where its natural habitats are subtropical or tropical moist forests.","img":"images/628.jpg","thumb":"images/t/628.jpg","file":"Schlumbergera Truncata.jpg","ar":1.333,"py":"xiezhualan xzl","cr_by":"JennTM","cr_lic":"CC BY-SA 4.0","cr_licurl":"https://creativecommons.org/licenses/by-sa/4.0","habit":"多肉","origin":["南美洲"]},{"id":629,"zh":"圣佩德罗仙人掌","en":"Echinopsis pachanoi","sci":"Echinopsis pachanoi","order_en":"Caryophyllales","order_zh":"石竹目","family_en":"Cactaceae","family_zh":"仙人掌科","iucn":"LC","langs":24,"desc_zh":null,"desc_en":"Echinopsis pachanoi, synonyms including Trichocereus pachanoi and Trichocereus macrogonus var. pachanoi, is a fast-growing columnar cactus found in the Andes at 2,000–3,000 m (6,600–9,800 ft) in altitude.","img":"images/629.jpg","thumb":"images/t/629.jpg","file":"Starr 070320-5799 Echinopsis pachanoi.jpg","ar":0.75,"py":"shengpeideluoxianrenzhang spdlxrz","cr_by":"Forest & Kim Starr","cr_lic":"CC BY 3.0","cr_licurl":"https://creativecommons.org/licenses/by/3.0","habit":"多肉","origin":["欧洲","非洲","南美洲"]},{"id":630,"zh":"多角仙人球","en":"Astrophytum capricorne","sci":"Astrophytum capricorne","order_en":"Caryophyllales","order_zh":"石竹目","family_en":"Cactaceae","family_zh":"仙人掌科","iucn":"LC","langs":23,"desc_zh":null,"desc_en":"Astrophytum capricorne, the goat's horn cactus, is a species of flowering plant in the cactus family Cactaceae, that is native to the Coahuila regions of Northern Mexico. Growing to 50 centimetres (20 in) tall by 10 centimetres (3.","img":"images/630.jpg","thumb":"images/t/630.jpg","file":"(MHNT) Astrophytum capricorne - Serres du Museum de Toulouse.jpg","ar":0.878,"py":"duojiaoxianrenqiu djxrq","cr_by":"Didier Descouens","cr_lic":"CC BY-SA 4.0","cr_licurl":"https://creativecommons.org/licenses/by-sa/4.0","habit":"多肉","origin":["北美洲"]},{"id":631,"zh":"麒麟果（水果）","en":"Selenicereus megalanthus","sci":"Selenicereus megalanthus","order_en":"Caryophyllales","order_zh":"石竹目","family_en":"Cactaceae","family_zh":"仙人掌科","iucn":null,"langs":23,"desc_zh":"黄麒麟量天尺（学名：Selenicereus megalanthus）是仙人掌科蛇鞭柱属的多年生附生植物，原产于南美洲西北部的热带地区。因其果实具有较高的经济价值，被广泛引种栽培，其常用的商品名为燕窝果或麒麟果。","desc_en":"Selenicereus megalanthus, synonym Hylocereus megalanthus, is a cactus species in the genus Selenicereus that is native to northern South America, where it is known, along with its fruit, by the name of pitahaya.","img":"images/631.jpg","thumb":"images/t/631.jpg","file":"Hylocereus megalanthus1EDWARD.jpg","ar":1.333,"py":"qilinguoshuiguo qlgsg","cr_by":"Edward","cr_lic":"Copyrighted free use","cr_licurl":null,"habit":"多肉","origin":["南美洲"]},{"id":632,"zh":"旺盛球","en":"Echinopsis oxygona","sci":"Echinopsis oxygona","order_en":"Caryophyllales","order_zh":"石竹目","family_en":"Cactaceae","family_zh":"仙人掌科","iucn":"LC","langs":23,"desc_zh":"仙人球（学名：Echinopsis oxygona），俗称草球，又名长盛球，原产于南美洲，一般生长在高热、干燥、少雨的沙漠地带。性喜干耐旱。仙人球的主要生长期是夏季，这也是它的盛花期。 仙人球是双子叶植物，属于仙人掌科。仙人球的定义有狭义和广义之分，狭义上特指本种，而广义上的仙人球则泛指所有球状或近似于球状的仙人掌类植物。仙人球寿命长体积大，有的品种寿命可高达五百年以上并长成直径两三米的巨球。同时仙人球也能被食用。","desc_en":"Echinopsis oxygona, also known as Eyries cactus, Easter lily cactus or sea-urchin cactus, is a species of flowering plant in the cactus family Cactaceae, native to south Brazil, Uruguay, Paraguay and northeastern Argentina.","img":"images/632.jpg","thumb":"images/t/632.jpg","file":"Echinopsis oxygona (7).jpg","ar":1.065,"py":"wangshengqiu wsq","cr_by":"Hazel","cr_lic":"CC BY-SA 2.0","cr_licurl":"https://creativecommons.org/licenses/by-sa/2.0","habit":"多肉","origin":["南美洲"]},{"id":633,"zh":"装饰仙人球","en":"Astrophytum ornatum","sci":"Astrophytum ornatum","order_en":"Caryophyllales","order_zh":"石竹目","family_en":"Cactaceae","family_zh":"仙人掌科","iucn":"VU","langs":22,"desc_zh":null,"desc_en":"Astrophytum ornatum, the bishop's cap or monk's hood cactus, is a flowering plant of the family Cactaceae, endemic to the Central Plateau of Mexico. It is the largest and tallest species of Astrophytum.","img":"images/633.jpg","thumb":"images/t/633.jpg","file":"(MHNT) Astrophytum ornatum - Jardin Botanique Henri GAUSSEN.jpg","ar":0.649,"py":"zhuangshixianrenqiu zsxrq","cr_by":"Didier Descouens","cr_lic":"CC BY-SA 4.0","cr_licurl":"https://creativecommons.org/licenses/by-sa/4.0","habit":"多肉","origin":["北美洲"]},{"id":634,"zh":"武伦柱","en":"Pachycereus pringlei","sci":"Pachycereus pringlei","order_en":"Caryophyllales","order_zh":"石竹目","family_en":"Cactaceae","family_zh":"仙人掌科","iucn":"LC","langs":22,"desc_zh":null,"desc_en":"Pachycereus pringlei (also known as Mexican giant cardon or elephant cactus) is a species of large cactus native to northwestern Mexico, in the states of Baja California, Baja California Sur, and Sonora.","img":"images/634.jpg","thumb":"images/t/634.jpg","file":"Pachycereus pringlei cardon sahueso.JPG","ar":0.673,"py":"wulunzhu wlz","cr_by":"Stephen Marlett","cr_lic":"Public domain","cr_licurl":null,"habit":"多肉","origin":["北美洲"]},{"id":635,"zh":"康乃馨","en":"Dianthus caryophyllus","sci":"Dianthus caryophyllus","order_en":"Caryophyllales","order_zh":"石竹目","family_en":"Caryophyllaceae","family_zh":"石竹科","iucn":null,"langs":78,"desc_zh":"香石竹（学名：Dianthus caryophyllus）又称剪绒花、洛阳花、康乃馨、狮头石竹、麝香石竹、大花石竹、荷兰石竹，为石竹科石竹属的植物，分布于欧洲温带以及中国大陆的福建、湖北等地，原产于地中海地区，是目前世界上应用最普遍的花卉之一。康乃馨包括许多变种与杂交种，在温室里几乎可以连续不断开花。1907年起，开始以粉红色康乃馨作为母亲节的象征，故今常被作为献给母亲的花。","desc_en":"Dianthus caryophyllus ( dy-AN-thəs KAIR-ee-ə-FIL-əs), commonly known as carnation or clove pink, is a species of Dianthus native to the Mediterranean region.","img":"images/635.jpg","thumb":"images/t/635.jpg","file":"Gartennelke 1.jpg","ar":0.772,"py":"kangnaixin knx","cr_by":"Darkone ( talk · contribs )","cr_lic":"CC BY-SA 1.0","cr_licurl":"https://creativecommons.org/licenses/by-sa/1.0","habit":null,"origin":["欧洲"]},{"id":636,"zh":"繁缕","en":"Stellaria media","sci":"Stellaria media","order_en":"Caryophyllales","order_zh":"石竹目","family_en":"Caryophyllaceae","family_zh":"石竹科","iucn":null,"langs":66,"desc_zh":"繁缕（学名：Stellaria media）属石竹科繁缕属植物，为原野杂草。其种加词“media”意为“中间的”。","desc_en":"Stellaria media, chickweed, is an annual flowering plant in the family Caryophyllaceae. It is native to Eurasia and naturalized throughout the world, where it is a weed of waste ground, farmland and gardens.","img":"images/636.jpg","thumb":"images/t/636.jpg","file":"Chickweed (aka).jpg","ar":0.856,"py":"fanl fl","cr_by":"André Karwath aka Aka","cr_lic":"CC BY-SA 2.5","cr_licurl":"https://creativecommons.org/licenses/by-sa/2.5","habit":"草本","origin":["亚洲"]},{"id":637,"zh":"麦仙翁","en":"Agrostemma githago","sci":"Agrostemma githago","order_en":"Caryophyllales","order_zh":"石竹目","family_en":"Caryophyllaceae","family_zh":"石竹科","iucn":null,"langs":60,"desc_zh":"麦仙翁（学名：Agrostemma githago）是石竹科麦仙翁属的植物。分布于亚洲、非洲、欧洲、北美以及中国大陆的内蒙古、吉林、新疆、黑龙江等地，生长于海拔100米至500米的地区，多生长在麦田中及路旁草地，目前已经做为观赏植物栽培。","desc_en":"Agrostemma githago, the common corn-cockle (also written \"corncockle\"), is a herbaceous annual flowering plant a member of Caryophyllaceae, also called the pink family or the carnation family of plants.","img":"images/637.jpg","thumb":"images/t/637.jpg","file":"Agrostemma githago 120605.jpg","ar":1.157,"py":"maixianweng mxw","cr_by":null,"cr_lic":"CC BY-SA 2.5","cr_licurl":"https://creativecommons.org/licenses/by-sa/2.5","habit":"草本","origin":null},{"id":638,"zh":"白玉草","en":"Silene vulgaris","sci":"Silene vulgaris","order_en":"Caryophyllales","order_zh":"石竹目","family_en":"Caryophyllaceae","family_zh":"石竹科","iucn":"LC","langs":60,"desc_zh":"白玉草（学名：Silene vulgaris）是石竹科蝇子草属的植物。分布于欧洲、蒙古、伊朗、土耳其、非洲、印度、尼泊尔以及中国大陆的黑龙江、西藏、内蒙古、新疆等地，生长于海拔150米至2,700米的地区，一般生于草甸、林下多砾石的草地、灌丛中及撂荒地，目前尚未由人工引种栽培。","desc_en":"Silene vulgaris, the bladder campion or maidenstears, is a plant species of the genus Silene within the family Caryophyllaceae. Native to the Old World, the plant has been naturalized elsewhere, including North America. The young shoots and leaves are edible.","img":"images/638.jpg","thumb":"images/t/638.jpg","file":"SileneVulgaris-bloem.jpg","ar":1.333,"py":"baiyucao byc","cr_by":null,"cr_lic":"CC BY-SA 3.0","cr_licurl":"http://creativecommons.org/licenses/by-sa/3.0/","habit":null,"origin":["北美洲"]},{"id":639,"zh":"肥皂草","en":"Saponaria officinalis","sci":"Saponaria officinalis","order_en":"Caryophyllales","order_zh":"石竹目","family_en":"Caryophyllaceae","family_zh":"石竹科","iucn":null,"langs":52,"desc_zh":"肥皂草（学名：Saponaria officinalis）为石竹科肥皂草属的一种草本植物，广泛分布于欧亚大陆。 肥皂草在地中海沿岸有野生，我国北方栽培较多，在部分地区已逸生。开花时，其根中的皂素含量可达20%。","desc_en":"Saponaria officinalis is a common perennial plant from the family Caryophyllaceae. This plant has many common names, including common soapwort, bouncing-bet, crow soap, and soapweed. There are about 20 species of soapworts altogether.","img":"images/639.jpg","thumb":"images/t/639.jpg","file":"Saponaria-officinalis-flower.jpg","ar":1.333,"py":"feizaocao fzc","cr_by":null,"cr_lic":"CC BY-SA 3.0","cr_licurl":"http://creativecommons.org/licenses/by-sa/3.0/","habit":"草本","origin":["亚洲"]},{"id":640,"zh":"须苞石竹","en":"Dianthus barbatus","sci":"Dianthus barbatus","order_en":"Caryophyllales","order_zh":"石竹目","family_en":"Caryophyllaceae","family_zh":"石竹科","iucn":null,"langs":46,"desc_zh":"须苞石竹（学名：Dianthus barbatus）也叫美国石竹（华北经济植物志要）、十样锦（江苏南部种子植物手册）、五彩石竹（北京植物志），为石竹科石竹属的植物，原产欧洲（原变种）、东北亚（头石竹）。","desc_en":"Dianthus barbatus, the sweet William, is a species of flowering plant in the family Caryophyllaceae, native to southern Europe and parts of Asia. It has become a popular ornamental garden plant.","img":"images/640.jpg","thumb":"images/t/640.jpg","file":"Dianthus barbatus PID1688-4.jpg","ar":0.75,"py":"xubaoshizhu xbsz","cr_by":"Benjamin Zwittnig","cr_lic":"CC BY 2.5 si","cr_licurl":"https://creativecommons.org/licenses/by/2.5/si/deed.en","habit":"草本","origin":["亚洲","欧洲"]},{"id":641,"zh":"异株蝇子草","en":"Red campion","sci":"Silene dioica","order_en":"Caryophyllales","order_zh":"石竹目","family_en":"Caryophyllaceae","family_zh":"石竹科","iucn":null,"langs":42,"desc_zh":null,"desc_en":"Silene dioica (syn. Melandrium rubrum), known as red campion and red catchfly, is a herbaceous flowering plant in the family Caryophyllaceae, native to Europe and introduced to the Americas.","img":"images/641.jpg","thumb":"images/t/641.jpg","file":"Bayrischer Wald 9929.JPG","ar":0.667,"py":"yizhuyingzicao yzyzc","cr_by":"J. Patrick Fischer","cr_lic":"CC BY-SA 3.0","cr_licurl":"https://creativecommons.org/licenses/by-sa/3.0","habit":"草本","origin":["欧洲"]},{"id":642,"zh":"叉枝蝇子草","en":"Silene latifolia","sci":"Silene latifolia","order_en":"Caryophyllales","order_zh":"石竹目","family_en":"Caryophyllaceae","family_zh":"石竹科","iucn":null,"langs":41,"desc_zh":"白花蝇子草（学名：Silene latifolia ssp. alba）是石竹科蝇子草属的植物。分布于亚洲、欧洲以及中国大陆的辽宁等地，生长于海拔200米至1,800米的地区，一般生于农田旁以及沟渠边，目前尚未由人工引种栽培。","desc_en":"Silene latifolia, commonly known as white campion, is a dioecious flowering plant in the family Caryophyllaceae, native to most of Europe, Western Asia and northern Africa.","img":"images/642.jpg","thumb":"images/t/642.jpg","file":"(MHNT) Silene latifolia - flower.jpg","ar":1.134,"py":"chazhiyingzicao czyzc","cr_by":"Didier Descouens","cr_lic":"CC BY-SA 4.0","cr_licurl":"https://creativecommons.org/licenses/by-sa/4.0","habit":"草本","origin":["亚洲","欧洲","非洲"]},{"id":643,"zh":"矮生剪秋罗","en":"Silene flos-cuculi","sci":"Silene flos-cuculi","order_en":"Caryophyllales","order_zh":"石竹目","family_en":"Caryophyllaceae","family_zh":"石竹科","iucn":null,"langs":41,"desc_zh":null,"desc_en":"Silene flos-cuculi (syn. Lychnis flos-cuculi), the ragged-robin, is a perennial herbaceous plant in the family Caryophyllaceae. It is native to Eurasia and Siberia and has been introduced to North America.","img":"images/643.jpg","thumb":"images/t/643.jpg","file":"2024-06-22 Kuckucks-Lichtnelke VON OBEN im FFH-Gebiet Belziger Bach.jpg","ar":0.75,"py":"aishengjianqiuluo asjql","cr_by":"Mimi und Ruebi","cr_lic":"CC BY 4.0","cr_licurl":"https://creativecommons.org/licenses/by/4.0","habit":"草本","origin":["亚洲","欧洲","北美洲"]},{"id":644,"zh":"菠菜","en":"Spinacia oleracea","sci":"Spinacia oleracea","order_en":"Caryophyllales","order_zh":"石竹目","family_en":"Amaranthaceae","family_zh":"苋科","iucn":null,"langs":134,"desc_zh":"菠菜（学名：Spinacia oleracea），又称菠薐、波斯草、赤根菜，是苋科菠菜属的一年生或二年生草本植物。是一种重要的绿叶蔬菜，在全球范围内广泛栽培和食用。菠菜的叶片柔嫩多汁，富含维生素、矿物质和抗氧化物，具有很高的营养价值和药用潜力。","desc_en":"Spinach (Spinacia oleracea) is a leafy green flowering plant native to Central and Western Asia. It is of the order Caryophyllales, family Amaranthaceae, subfamily Chenopodioideae.","img":"images/644.jpg","thumb":"images/t/644.jpg","file":"Spinacia oleracea Spinazie bloeiend.jpg","ar":0.767,"py":"bocai bc","cr_by":"Rasbak","cr_lic":"CC BY-SA 3.0","cr_licurl":"http://creativecommons.org/licenses/by-sa/3.0/","habit":"草本","origin":["亚洲"]},{"id":645,"zh":"甜菜","en":"Beta vulgaris","sci":"Beta vulgaris","order_en":"Caryophyllales","order_zh":"石竹目","family_en":"Amaranthaceae","family_zh":"苋科","iucn":null,"langs":98,"desc_zh":"甜菜（学名：Beta vulgaris；英语：beetroot）又名菾菜或红菜，为苋科甜菜属下的一个种。原产于欧洲西部和南部沿海，从瑞典直到西班牙，是热带甘蔗以外的一个主要糖来源。叶子也是一种蔬菜。","desc_en":"Beta vulgaris (beet) is a species of flowering plant in the subfamily Betoideae of the family Amaranthaceae. It is a perennial plant usually growing up to 120 centimetres (4 ft) tall. Three subspecies are typically recognised.","img":"images/645.jpg","thumb":"images/t/645.jpg","file":"Beta vulgaris - Köhler–s Medizinal-Pflanzen-167.jpg","ar":0.803,"py":"tiancai tc","cr_by":"Walther Otto Müller","cr_lic":"Public domain","cr_licurl":null,"habit":"草本","origin":null},{"id":646,"zh":"藜麦","en":"Chenopodium quinoa","sci":"Chenopodium quinoa","order_en":"Caryophyllales","order_zh":"石竹目","family_en":"Amaranthaceae","family_zh":"苋科","iucn":null,"langs":75,"desc_zh":"藜（lí）麦（学名：Chenopodium quinoa，又称昆诺阿藜、奎奴亚藜、奎藜，俗称印地安麦、灰米或小小米，是苋科藜属植物，与小麦无关且不属于谷物类，为南美洲高地特有的一年生植物。 作为人类主要粮食的谷物大多属于禾本科，而藜麦则属于苋科，所以被称作「准谷物」。在藜麦中完全成熟并散发出艳红光泽的可称为红藜麦，为一种代替谷物的健康食品。","desc_en":"Quinoa (Chenopodium quinoa; , from Quechua kinwa or kinuwa) is a flowering plant in the amaranth family. It is an herbaceous annual plant grown as a crop primarily for its edible seeds; the seeds are high in protein, dietary fiber, B vitamins and dietary miner…","img":"images/646.jpg","thumb":"images/t/646.jpg","file":"Quinua.JPG","ar":1.533,"py":"limai lm","cr_by":"Maurice Chédel","cr_lic":"Public domain","cr_licurl":null,"habit":"禾草","origin":["南美洲"]},{"id":647,"zh":"藜","en":"Chenopodium album","sci":"Chenopodium album","order_en":"Caryophyllales","order_zh":"石竹目","family_en":"Amaranthaceae","family_zh":"苋科","iucn":null,"langs":75,"desc_zh":"藜（学名：Chenopodium album）为苋科藜属的植物。分布于全球温带及热带各地，生长于海拔50米至4,200米的地区，见于路旁、荒地及田间。","desc_en":"Chenopodium album is a fast-growing annual plant in the flowering plant family Amaranthaceae. Though cultivated in some regions, the plant is elsewhere considered a weed.","img":"images/647.jpg","thumb":"images/t/647.jpg","file":"Melganzenvoet bloeiwijze Chenopodium album.jpg","ar":0.664,"py":"li l","cr_by":"Rasbak","cr_lic":"CC BY-SA 3.0","cr_licurl":"http://creativecommons.org/licenses/by-sa/3.0/","habit":"草本","origin":null},{"id":648,"zh":"青葙","en":"Celosia argentea","sci":"Celosia argentea","order_en":"Caryophyllales","order_zh":"石竹目","family_en":"Amaranthaceae","family_zh":"苋科","iucn":"LC","langs":52,"desc_zh":"青葙（学名：Celosia argentea）是苋科青葙属的一种植物。青葙为中药药材，名为青葙子的种子有清肝明目的作用。全株可做，饲料。幼嫩茎叶浸去苦味后，可作野菜食用。种子炒熟亦可加工制作各种糖食。此外，青葙花序宿存经久不凋，可供观赏。","desc_en":"Celosia argentea, commonly known as the plumed cockscomb or silver cock's comb, is a herbaceous plant of tropical origin in the family Amaranthaceae from tropical Africa. The plant is known for its very bright colors.","img":"images/648.jpg","thumb":"images/t/648.jpg","file":"Celosia argentea (Silver cockscomb) W IMG 0985.jpg","ar":0.823,"py":"qingxiang qx","cr_by":"J.M.Garg","cr_lic":"CC BY 3.0","cr_licurl":"https://creativecommons.org/licenses/by/3.0","habit":"草本","origin":["非洲"]},{"id":649,"zh":"土荆芥","en":"Dysphania ambrosioides","sci":"Dysphania ambrosioides","order_en":"Caryophyllales","order_zh":"石竹目","family_en":"Amaranthaceae","family_zh":"苋科","iucn":null,"langs":48,"desc_zh":"土荆芥（学名：Dysphania ambrosioides），又名臭杏、臭草、杀虫芥、鸭脚草。是苋科刺藜属的植物。","desc_en":"Dysphania ambrosioides, formerly Chenopodium ambrosioides, known as epazote, Jesuit's tea, Mexican tea or wormseed, is an annual or short-lived perennial herb native to the Americas.","img":"images/649.jpg","thumb":"images/t/649.jpg","file":"Dysphania ambrosioides Blanco1.69.jpg","ar":0.701,"py":"tujingjie tjj","cr_by":"Francisco Manuel Blanco (O.S.A.)","cr_lic":"Public domain","cr_licurl":null,"habit":"草本","origin":null},{"id":650,"zh":"千日红","en":"Gomphrena globosa","sci":"Gomphrena globosa","order_en":"Caryophyllales","order_zh":"石竹目","family_en":"Amaranthaceae","family_zh":"苋科","iucn":null,"langs":47,"desc_zh":"千日红（学名：Gomphrena globosa），又名圆仔花（台罗：înn-á-hue）、百日红（广州）、火球花（北京）、红绣球，原产于热带美洲各国内地，一般在春天播种繁殖。千日红的花语是“永恒、不变的爱”。分布于美洲热带以及中国大陆的南北各省等地，目前已由人工引种栽培。","desc_en":"Gomphrena globosa, commonly known as globe amaranth, is an edible plant from the family Amaranthaceae. The round-shaped flower inflorescences are a visually dominant feature and cultivars have been propagated to exhibit shades of magenta, purple, red, orange,…","img":"images/650.jpg","thumb":"images/t/650.jpg","file":"Starr 020304-9001 Gomphrena globosa.jpg","ar":0.599,"py":"qianrihong qrh","cr_by":"Forest & Kim Starr","cr_lic":"CC BY 3.0","cr_licurl":"https://creativecommons.org/licenses/by/3.0","habit":"草本","origin":["北美洲"]},{"id":651,"zh":"反枝苋","en":"Amaranthus retroflexus","sci":"Amaranthus retroflexus","order_en":"Caryophyllales","order_zh":"石竹目","family_en":"Amaranthaceae","family_zh":"苋科","iucn":null,"langs":46,"desc_zh":"反枝苋（学名：Amaranthus retroflexus）是苋科苋属的植物。生长于海拔600米至3,000米的地区，多生长于农地旁、人家附近的草地上、田园内及瓦房上。 其种加词“Retroflexus”意为“弯折”、“反折的”。","desc_en":"Amaranthus retroflexus is a species of flowering plant in the family Amaranthaceae with several common names, including red-root amaranth, redroot pigweed, red-rooted pigweed, common amaranth, pigweed amaranth, and common tumbleweed.","img":"images/651.jpg","thumb":"images/t/651.jpg","file":"Amaranthus retroflexus full1.jpg","ar":0.75,"py":"fanzhixian fzx","cr_by":"Lynk media","cr_lic":"CC BY-SA 3.0","cr_licurl":"https://creativecommons.org/licenses/by-sa/3.0","habit":null,"origin":null},{"id":652,"zh":"尾穗苋","en":"Amaranthus caudatus","sci":"Amaranthus caudatus","order_en":"Caryophyllales","order_zh":"石竹目","family_en":"Amaranthaceae","family_zh":"苋科","iucn":null,"langs":46,"desc_zh":"尾穗苋（学名：Amaranthus caudatus），又名老枪谷（出自《龙沙纪略》），是苋科苋属的一年生草本植物。分布于世界各地，生长于海拔580米至1,200米的地区。叶和种子可食。 在维多利亚时代的花语中，这种花（英语俗名为“Love-lies-bleeding”）的意思是无望的爱、绝望。","desc_en":"Amaranthus caudatus (also known as Amaranthus edulis and Amaranthus mantegazzianus) is a species of annual flowering plant. It goes by common names such as love-lies-bleeding, pendant amaranth, tassel flower, velvet flower, and foxtail amaranth.","img":"images/652.jpg","thumb":"images/t/652.jpg","file":"3836 - Amaranthus caudatus (Zieramaranth).JPG","ar":0.665,"py":"weisuixian wsx","cr_by":"Tubifex","cr_lic":"CC BY-SA 3.0","cr_licurl":"https://creativecommons.org/licenses/by-sa/3.0","habit":"草本","origin":["南美洲"]},{"id":653,"zh":"荞麦","en":"Fagopyrum esculentum","sci":"Fagopyrum esculentum","order_en":"Caryophyllales","order_zh":"石竹目","family_en":"Polygonaceae","family_zh":"蓼科","iucn":null,"langs":104,"desc_zh":"荞麦（学名：Fagopyrum esculentum，英语：buckwheat）亦作普通荞麦（common buckwheat）以跟其他同属物种区别，是蓼科荞麦属的植物，也有人将其分入蓼属，它是一种双子叶植物。 普通荞麦和同属的苦荞麦（F. tataricum Gaertn）、金荞麦（F. dibotrys H.Hara），在汉语与英语均称「麦」（wheat），且都可作粮食，但与其他粮食作物不同的是，它们不属于禾本科。","desc_en":"Buckwheat (Fagopyrum esculentum) or common buckwheat is a flowering plant in the knotweed family Polygonaceae cultivated for its grain-like seeds and as a cover crop.","img":"images/653.jpg","thumb":"images/t/653.jpg","file":"Illustration Fagopyrum esculentum0.jpg","ar":0.606,"py":"qiaomai qm","cr_by":null,"cr_lic":"Public domain","cr_licurl":null,"habit":"禾草","origin":["亚洲"]},{"id":654,"zh":"酸模","en":"Rumex acetosa","sci":"Rumex acetosa","order_en":"Caryophyllales","order_zh":"石竹目","family_en":"Polygonaceae","family_zh":"蓼科","iucn":null,"langs":83,"desc_zh":"酸模（学名：Rumex acetosa），又名蕦、薞芜，蓼科多年生草本植物，欧洲和西亚大多数的草原均可见到其踪迹。酸模含有丰富的维他命A、维他命C及草酸，草酸导致此植物尝起来有酸溜口味，常作料理调味用。酸模亦具药用价值，有利尿、发汗、行血等功效。","desc_en":"Sorrel (Rumex acetosa) is a perennial herbaceous plant in the family Polygonaceae. It is also called common sorrel, meadow sorrel, green sorrel, sour dock, spinach dock and narrow-leaved dock (\"dock\" often used for the genus).","img":"images/654.jpg","thumb":"images/t/654.jpg","file":"20150423Rumex acetosa4.jpg","ar":0.75,"py":"suanmo sm","cr_by":"AnRo0002","cr_lic":"CC0","cr_licurl":"http://creativecommons.org/publicdomain/zero/1.0/deed.en","habit":"草本","origin":["亚洲"]},{"id":655,"zh":"萹蓄","en":"Polygonum aviculare","sci":"Polygonum aviculare","order_en":"Caryophyllales","order_zh":"石竹目","family_en":"Polygonaceae","family_zh":"蓼科","iucn":null,"langs":64,"desc_zh":"萹蓄（学名：Polygonum aviculare），又名𦺇（音同“毒”），为蓼科萹蓄属下的一种一年生草本植物，高10—40 cm（3.9—15.7英寸），原产于北半球温带地区，后来也引入南半球。它可以入中药，《神农本草经》记载它“味苦，平”。","desc_en":"Polygonum aviculare or common knotgrass is a plant related to buckwheat and dock. It is also called prostrate knotweed, birdweed, pigweed and lowgrass. It is an annual found in fields and wasteland, with white flowers from June to October.","img":"images/655.jpg","thumb":"images/t/655.jpg","file":"Polygonum aviculare 4.JPG","ar":0.667,"py":"bianxu bx","cr_by":"Dalgial","cr_lic":"CC BY-SA 3.0","cr_licurl":"https://creativecommons.org/licenses/by-sa/3.0","habit":"草本","origin":["亚洲"]},{"id":656,"zh":"水蓼","en":"Persicaria hydropiper","sci":"Persicaria hydropiper","order_en":"Caryophyllales","order_zh":"石竹目","family_en":"Polygonaceae","family_zh":"蓼科","iucn":"LC","langs":56,"desc_zh":"水蓼（学名：Persicaria hydropiper；同义词：Polygonum hydropiper）是一种蓼科春蓼属植物，也称辣蓼。","desc_en":"Persicaria hydropiper (syn. Polygonum hydropiper), also known as water pepper, marshpepper knotweed, arse smart or tade, is a plant of the family Polygonaceae.","img":"images/656.jpg","thumb":"images/t/656.jpg","file":"Polygonum hydropiper1.jpg","ar":0.75,"py":"shuiliao sl","cr_by":"No machine-readable author provided. Aroche assumed (based on copyright claims).","cr_lic":"CC BY 2.5","cr_licurl":"https://creativecommons.org/licenses/by/2.5","habit":null,"origin":["亚洲","欧洲","北美洲","大洋洲"]},{"id":657,"zh":"春蓼","en":"Persicaria maculosa","sci":"Persicaria maculosa","order_en":"Caryophyllales","order_zh":"石竹目","family_en":"Polygonaceae","family_zh":"蓼科","iucn":"LC","langs":56,"desc_zh":"春蓼（学名：Persicaria maculosa 或 Polygonum persicaria），为蓼科春蓼属下的一个种。","desc_en":"Persicaria maculosa (syn. Polygonum persicaria) is an annual plant in the buckwheat family, Polygonaceae. Common names include lady's thumb, spotted lady's thumb, Jesusplant, and redshank.","img":"images/657.jpg","thumb":"images/t/657.jpg","file":"PolygonumPersicara-plant-sm.jpg","ar":1.333,"py":"chunliao cl","cr_by":"TeunSpaans at Dutch Wikipedia","cr_lic":"CC BY-SA 3.0","cr_licurl":"http://creativecommons.org/licenses/by-sa/3.0/","habit":"草本","origin":["亚洲","北美洲"]},{"id":658,"zh":"波叶大黄","en":"rhubarb","sci":"Rheum rhabarbarum","order_en":"Caryophyllales","order_zh":"石竹目","family_en":"Polygonaceae","family_zh":"蓼科","iucn":null,"langs":54,"desc_zh":"食用大黄指的是欧洲及中东地区用于食用的蓼科大黄属多年生草本植物。一般从粗短的根茎种植。大黄长有三角形的大叶，叶柄肥厚。花形细小，聚集成花序，颜色从绿白色到玫瑰红色。大黄的叶片富含草酸，不适宜食用。它的叶柄可作食用。 目前食用大黄的主要物种杂交大黄 Rheum × hybridum的来源不明确。波叶大黄（R. rhabarbarum = R. undulatum，在华北也有分布）和R.","desc_en":"Rhubarb is the fleshy, edible stalks (petioles) of species and hybrids (culinary rhubarb) of Rheum in the family Polygonaceae, which are cooked and used for food. The plant is a herbaceous perennial that grows from short, thick rhizomes.","img":"images/658.jpg","thumb":"images/t/658.jpg","file":"Rabarber stelen.jpg","ar":1.176,"py":"boyedahuang bydh","cr_by":null,"cr_lic":"CC BY-SA 3.0","cr_licurl":"http://creativecommons.org/licenses/by-sa/3.0/","habit":"草本","origin":null},{"id":659,"zh":"番杏","en":"Tetragonia tetragonoides","sci":"Tetragonia tetragonoides","order_en":"Caryophyllales","order_zh":"石竹目","family_en":"Aizoaceae","family_zh":"番杏科","iucn":null,"langs":33,"desc_zh":"番杏（学名：Tetragonia tetragonioides (Pall.) Kuntze）是番杏科番杏属的植物，又名法国菠菜、新西兰菠菜、洋菠菜、夏菠菜、滨莴苣、蔓菜、白番杏、白红菜。耐盐性强，在海水灌溉下仍然可以正常完成生活史。","desc_en":"Tetragonia tetragonioides, commonly called New Zealand spinach, warrigal greens or by its Māori name of Kōkihi, is a flowering plant in the fig-marigold family (Aizoaceae). It is often cultivated as a leafy vegetable.","img":"images/659.jpg","thumb":"images/t/659.jpg","file":"Tetragonia tetragonioides (Flower).jpg","ar":0.75,"py":"fanxing fx","cr_by":"Ixitixel","cr_lic":"CC BY-SA 3.0","cr_licurl":"http://creativecommons.org/licenses/by-sa/3.0/","habit":null,"origin":["亚洲","大洋洲"]},{"id":660,"zh":"莫邪菊","en":"Carpobrotus edulis","sci":"Carpobrotus edulis","order_en":"Caryophyllales","order_zh":"石竹目","family_en":"Aizoaceae","family_zh":"番杏科","iucn":null,"langs":30,"desc_zh":"食用日中花（学名：Carpobrotus edule）为番杏科莫邪菊属下的一个种。叶和果可食用。 本物种原产于南非，且为黑鼠的花朵，因此借着黑鼠食用后随同其粪便的传播，目前已透过人类扩散至世界多处，主要为地中海地区、澳大利亚及纽西兰等气候相近的地区，且被视为入侵物种。","desc_en":"Carpobrotus edulis is a creeping plant with succulent leaves in the fig-marigold family Aizoaceae, native to South Africa. Its common names include hottentot-fig, sour fig, ice plant, highway ice plant, or vygie.","img":"images/660.jpg","thumb":"images/t/660.jpg","file":"Carpobrutus edulis b.JPG","ar":1.333,"py":"moxieju mxj","cr_by":"Taken by Carsten Niehaus ( user:Lumbar ).","cr_lic":"CC BY-SA 3.0","cr_licurl":"http://creativecommons.org/licenses/by-sa/3.0/","habit":"多肉","origin":["非洲"]},{"id":661,"zh":"冰叶日中花","en":"Mesembryanthemum crystallinum","sci":"Mesembryanthemum crystallinum","order_en":"Caryophyllales","order_zh":"石竹目","family_en":"Aizoaceae","family_zh":"番杏科","iucn":null,"langs":27,"desc_zh":"冰叶日中花（学名：Mesembryanthemum crystallinum），又名冰花、冰草、水晶冰菜、冰菜或冰叶菜，为番杏科日中花属下的一个物种，是一种常为一年生的匍匐型多肉植物。原生于非洲大陆、西奈半岛及欧洲南部，而北美洲、南美洲及澳大利亚则有野外归化居群。 冰叶日中花的植株表面覆盖著大而闪亮的透明囊状细胞，形如冰晶，因而得名。","desc_en":"Mesembryanthemum crystallinum (the common, 'crystalline' or 'crystallinum' iceplant, or simply 'iceplant') is a species of annual/perennial, succulent flowering plant in the Mesembryanthemum genus of the Aizoaceae family.","img":"images/661.jpg","thumb":"images/t/661.jpg","file":"Unk desert flower 2.jpg","ar":1.333,"py":"bingyerizhonghua byrzh","cr_by":"Yummifruitbat","cr_lic":"CC BY-SA 4.0","cr_licurl":"https://creativecommons.org/licenses/by-sa/4.0","habit":"多肉","origin":["亚洲","欧洲","非洲"]},{"id":662,"zh":"海马齿","en":"Sesuvium portulacastrum","sci":"Sesuvium portulacastrum","order_en":"Caryophyllales","order_zh":"石竹目","family_en":"Aizoaceae","family_zh":"番杏科","iucn":"LC","langs":26,"desc_zh":"海马齿（学名：Sesuvium portulacastrum）为番杏科海马齿属的植物。分布于全球热带和亚热带海岸、台湾岛以及中国大陆的广东、东沙岛、福建、海南等地，一般生于近海岸的沙地上。","desc_en":"Sesuvium portulacastrum is a sprawling perennial herb in the family Aizoaceae that grows in coastal and mangrove areas throughout much of the world. It grows in sandy clay, coastal limestone and sandstone, tidal flats and salt marshes, throughout much of the w…","img":"images/662.jpg","thumb":"images/t/662.jpg","file":"Sesuvium p.jpg","ar":1.204,"py":"haimachi hmc","cr_by":"by Eric Guinther ( Marshman at en.wikipedia )","cr_lic":"CC BY-SA 3.0","cr_licurl":"http://creativecommons.org/licenses/by-sa/3.0/","habit":"草本","origin":["亚洲","非洲","北美洲","南美洲","大洋洲"]},{"id":663,"zh":"心叶日中花","en":"Mesembryanthemum cordifolium","sci":"Mesembryanthemum cordifolium","order_en":"Caryophyllales","order_zh":"石竹目","family_en":"Aizoaceae","family_zh":"番杏科","iucn":null,"langs":23,"desc_zh":"心叶日中花（学名：Mesembryanthemum cordifolium），又名心叶日中花、太阳玫瑰，为番杏科露草属下的一种多年生常绿草本。原产非洲南部。","desc_en":"Mesembryanthemum cordifolium, formerly known as Aptenia cordifolia, is a species of succulent plant in the family Aizoaceae. It is a creeping plant that forms a carpet of flat-growing perennial herbs in groups on the ground from a base.","img":"images/663.jpg","thumb":"images/t/663.jpg","file":"Растения в Седово 109.JPG","ar":1.333,"py":"xinyerizhonghua xyrzh","cr_by":"Andrey Butko","cr_lic":"CC BY-SA 3.0","cr_licurl":"https://creativecommons.org/licenses/by-sa/3.0","habit":"多肉","origin":null},{"id":664,"zh":"Mesembryanthemum nodiflorum","en":"Mesembryanthemum nodiflorum","sci":"Mesembryanthemum nodiflorum","order_en":"Caryophyllales","order_zh":"石竹目","family_en":"Aizoaceae","family_zh":"番杏科","iucn":null,"langs":20,"desc_zh":null,"desc_en":"Mesembryanthemum nodiflorum is a species of succulent plant in the genus Mesembryanthemum known by the common name slenderleaf iceplant. It is the type species for the genus.","img":"images/664.jpg","thumb":"images/t/664.jpg","file":"Mesambryanthemum nodiflorum.jpg","ar":0.75,"py":"","cr_by":"Tigerente","cr_lic":"CC BY-SA 3.0","cr_licurl":"https://creativecommons.org/licenses/by-sa/3.0","habit":"多肉","origin":["亚洲","欧洲","非洲"]},{"id":665,"zh":"紫茉莉","en":"Mirabilis jalapa","sci":"Mirabilis jalapa","order_en":"Caryophyllales","order_zh":"石竹目","family_en":"Nyctaginaceae","family_zh":"紫茉莉科","iucn":null,"langs":62,"desc_zh":"紫茉莉（学名：Mirabilis jalapa）别名地雷花、粉豆花、烟粉豆、粉果花、茉莲子、草茉莉、夜娇娇、夜晚花、夜来香、胭脂花、胭粉豆、洗澡花、煮饭花、做饭花、晚饭花、烧汤花、白粉花、潮来花、素香、五点红、喇叭花、老爷儿没、状元花等，属紫茉莉科植物。","desc_en":"Mirabilis jalapa, the marvel of Peru or four o'clock flower, is the most commonly grown ornamental species of Mirabilis plant, and is available in a range of colors.","img":"images/665.jpg","thumb":"images/t/665.jpg","file":"2006-10-18Mirabilis jalapa06.jpg","ar":1.343,"py":"zimoli zml","cr_by":"Wildfeuer","cr_lic":"CC BY 2.5","cr_licurl":"https://creativecommons.org/licenses/by/2.5","habit":null,"origin":["北美洲","南美洲"]},{"id":666,"zh":"光叶子花","en":"Bougainvillea glabra","sci":"Bougainvillea glabra","order_en":"Caryophyllales","order_zh":"石竹目","family_en":"Nyctaginaceae","family_zh":"紫茉莉科","iucn":"LC","langs":25,"desc_zh":"光叶子花（学名：Bougainvillea glabra）又名小叶九重葛、簕杜鹃、宝巾、三角梅、紫三角、紫亚兰、三角花等，为紫茉莉科叶子花属下的一个物种，是中国深圳、厦门和珠海的市花以及海南省的省花。","desc_en":"Bougainvillea glabra, the lesser bougainvillea or paperflower, is the most common species of bougainvillea used for bonsai. The epithet 'glabra' comes from Latin and means \"bald\".","img":"images/666.jpg","thumb":"images/t/666.jpg","file":"Flor de Santa Rita (Bougainvillea glabra) una especie de planta trepadora de la familia de las Nyctaginaceae (sobre Ruta Provincial 7, municipio de Ruiz de Montoya, Provincia de Misiones, República Argentina).jpg","ar":1.778,"py":"guangyezihua gyzh","cr_by":"Horacio Cambeiro","cr_lic":"CC BY 4.0","cr_licurl":"https://creativecommons.org/licenses/by/4.0","habit":null,"origin":null},{"id":667,"zh":"捕蝇草","en":"Dionaea muscipula","sci":"Dionaea muscipula","order_en":"Caryophyllales","order_zh":"石竹目","family_en":"Droseraceae","family_zh":"茅膏菜科","iucn":"VU","langs":71,"desc_zh":"捕蝇草（学名：Dionaea muscipula）是原产于北美洲的一种多年生草本植物。据说因为叶片边缘会有规则的刺毛，那种感觉就像维纳斯的睫毛一般，所以英文名称为Venus Flytrap，意思是「维纳斯的捕蝇陷阱」。中文及日文对捕蝇草还有「苍蝇的地狱」（ハエジゴク）这个别名。其主要特征就是能够迅速的关闭叶片捕食昆虫，这是种和其远亲猪笼草一样的食肉植物之一，在茅膏菜科捕蝇草属中仅此一种。捕蝇草于生态系中属生产者及消费者。","desc_en":"The Venus flytrap (Dionaea muscipula) is a carnivorous plant native to the temperate and subtropical wetlands of North Carolina and South Carolina, on the East Coast of the United States. Although various modern hybrids have been created in cultivation, D.","img":"images/667.jpg","thumb":"images/t/667.jpg","file":"Venus Flytrap Dionaea muscipula (26455092815).jpg","ar":0.78,"py":"buyingcao byc","cr_by":"Len Worthington","cr_lic":"CC BY-SA 2.0","cr_licurl":"https://creativecommons.org/licenses/by-sa/2.0","habit":null,"origin":["北美洲"]},{"id":668,"zh":"圆叶茅膏菜","en":"Drosera rotundifolia","sci":"Drosera rotundifolia","order_en":"Caryophyllales","order_zh":"石竹目","family_en":"Droseraceae","family_zh":"茅膏菜科","iucn":"LC","langs":56,"desc_zh":"圆叶茅膏菜（学名：Drosera rotundifolia），又及圆叶毛毡苔，是肉食性茅膏菜的一种，一般会在泥沼、沼泽及潮湿地方可以见到。圆叶茅膏菜是最广泛分布的茅膏菜之一，主要是环北带的植物，在整个欧洲北部、西伯利亚大部份地区、北美洲北部、韩国、日本、甚至新畿内亚都可以见到它们。","desc_en":"Drosera rotundifolia, the round-leaved sundew, roundleaf sundew, or common sundew, is a species of carnivorous flowering plant that grows in bogs, marshes and fens.","img":"images/668.jpg","thumb":"images/t/668.jpg","file":"Drosera rotondifolia.JPG","ar":1.333,"py":"yuanyemaogaocai yymgc","cr_by":"association AMV","cr_lic":"CC BY-SA 4.0","cr_licurl":"https://creativecommons.org/licenses/by-sa/4.0","habit":null,"origin":["亚洲","欧洲","北美洲","大洋洲"]},{"id":669,"zh":"马齿苋","en":"Portulaca oleracea","sci":"Portulaca oleracea","order_en":"Caryophyllales","order_zh":"石竹目","family_en":"Portulacaceae","family_zh":"马齿苋科","iucn":"LC","langs":92,"desc_zh":"马齿苋（学名：Portulaca oleracea），又名马生菜、马齿菜、马屎苋、五行草、酸苋、猪母乳、马勺菜、地马菜、马蛇子菜、长寿菜、老鼠耳、宝钏菜、蚂蚱菜，是马齿苋科马齿苋属植物。","desc_en":"Portulaca oleracea (common purslane, also known as little hogweed, or pursley) is a succulent plant in the family Portulacaceae. All parts of the plant are edible raw or cooked.","img":"images/669.jpg","thumb":"images/t/669.jpg","file":"Portulaca oleracea.JPG","ar":1.4,"py":"machixian mcx","cr_by":"ZooFari","cr_lic":"CC BY-SA 3.0","cr_licurl":"https://creativecommons.org/licenses/by-sa/3.0","habit":"多肉","origin":null},{"id":670,"zh":"海石竹","en":"Armeria maritima","sci":"Armeria maritima","order_en":"Caryophyllales","order_zh":"石竹目","family_en":"Plumbaginaceae","family_zh":"白花丹科","iucn":null,"langs":38,"desc_zh":"海石竹（学名：Armeria maritima）为蓝雪科海石竹属下的一个种。","desc_en":"Armeria maritima, the thrift, sea thrift or sea pink, is a species of flowering plant in the family Plumbaginaceae. It is a compact evergreen perennial which grows in low clumps and sends up long stems that support globes of bright pink flowers.","img":"images/670.jpg","thumb":"images/t/670.jpg","file":"Zawciag nadmorski Ameria maritima maritima.jpg","ar":0.75,"py":"haishizhu hsz","cr_by":null,"cr_lic":"CC BY-SA 3.0","cr_licurl":"http://creativecommons.org/licenses/by-sa/3.0/","habit":"草本","origin":null},{"id":671,"zh":"蓝花丹","en":"Plumbago auriculata","sci":"Plumbago auriculata","order_en":"Caryophyllales","order_zh":"石竹目","family_en":"Plumbaginaceae","family_zh":"白花丹科","iucn":null,"langs":33,"desc_zh":"蓝花丹（学名：Plumbago auriculata），又名蓝花矶松、花绣球、蓝茉莉，为蓝雪科半灌木。原产于非洲南部，在世界各地被广泛地作为观赏植物而栽种。种名auriculata意为耳形的，指代上部叶的叶柄基部常有小形半圆至长圆形的耳。园艺中，蓝花丹常与蓝雪花（Ceratostigma plumbaginoides）混淆。 蓝花丹为常绿柔弱半灌木，上端蔓状或极开散，高约1米或更长，除花序外无毛，被有细小的钙质颗粒。","desc_en":"Plumbago auriculata, the Cape leadwort, blue plumbago or Cape plumbago, is a species of flowering plant in the family Plumbaginaceae, native to South Africa and Mozambique.","img":"images/671.jpg","thumb":"images/t/671.jpg","file":"Plumbago.jpg","ar":1.333,"py":"lanhuadan lhd","cr_by":"No machine-readable author provided. Calvin Teo assumed (based on copyright claims).","cr_lic":"CC BY-SA 2.5","cr_licurl":"https://creativecommons.org/licenses/by-sa/2.5","habit":null,"origin":["非洲"]},{"id":672,"zh":"大果山茱萸","en":"Cornus mas","sci":"Cornus mas","order_en":"Cornales","order_zh":"山茱萸目","family_en":"Cornaceae","family_zh":"山茱萸科","iucn":"LC","langs":73,"desc_zh":"大果山茱萸（学名：Cornus mas，也做欧洲山茱萸）是一种于山茱萸科下的被子植物。于南欧（从法国到俄罗斯南部）、亚美尼亚、阿塞拜疆、乔治亚、伊朗、土耳其、黎巴嫩和叙利亚为原生物种。","desc_en":"Cornelian cherry (Cornus mas), also known as the European cornel, is a species of shrub or small tree in the dogwood family Cornaceae native to Western Europe, Southern Europe, and Southwestern Asia.","img":"images/672.jpg","thumb":"images/t/672.jpg","file":"CornusMas Fruits 01.jpg","ar":1.333,"py":"daguoshanzhuyu dgszy","cr_by":"B.navez","cr_lic":"CC BY-SA 3.0","cr_licurl":"http://creativecommons.org/licenses/by-sa/3.0/","habit":"乔木","origin":["亚洲","欧洲"]},{"id":673,"zh":"欧洲红瑞木","en":"Cornus sanguinea","sci":"Cornus sanguinea","order_en":"Cornales","order_zh":"山茱萸目","family_en":"Cornaceae","family_zh":"山茱萸科","iucn":null,"langs":54,"desc_zh":"欧洲红瑞木（学名：Swida sanguinea），为山茱萸科梾木属下的一个种。","desc_en":"Cornus sanguinea, the common dogwood or bloody dogwood, is a species of dogwood native to most of Europe and western Asia, from England and central Scotland east to the Caspian Sea. It is widely grown as an ornamental plant.","img":"images/673.jpg","thumb":"images/t/673.jpg","file":"Cornus-sanguinea.JPG","ar":1.333,"py":"ouzhouhongruimu ozhrm","cr_by":"Sten Porse","cr_lic":"CC BY-SA 3.0","cr_licurl":"http://creativecommons.org/licenses/by-sa/3.0/","habit":null,"origin":["亚洲","欧洲"]},{"id":674,"zh":"红瑞木","en":"Cornus alba","sci":"Cornus alba","order_en":"Cornales","order_zh":"山茱萸目","family_en":"Cornaceae","family_zh":"山茱萸科","iucn":null,"langs":38,"desc_zh":"红瑞木（学名：Cornus alba）是山茱萸属的一种落叶灌木，原产于西伯利亚、中国和韩国，后来作为观赏植物引入世界其他国家，还培育出了不同的品种 。它的花期在5至6月，开乳白色花，其茎在深秋和冬天变成红色，因而形成一道独特的景观。 其种加词“alba”意为“白色的”，意指所开的花开始为白色的。","desc_en":"Cornus alba, the red-barked, white or Siberian dogwood, is a species of flowering plant in the family Cornaceae, native to Siberia, northern China and Korea. It is a large deciduous surculose (suckering) shrub that can be grown as a small tree.","img":"images/674.jpg","thumb":"images/t/674.jpg","file":"Cornus alba a2.jpg","ar":1.345,"py":"hongruimu hrm","cr_by":"Opioła Jerzy (Poland)","cr_lic":"CC BY 2.5","cr_licurl":"https://creativecommons.org/licenses/by/2.5","habit":"乔木","origin":["亚洲","欧洲"]},{"id":675,"zh":"御膳橘","en":"Cornus suecica","sci":"Cornus suecica","order_en":"Cornales","order_zh":"山茱萸目","family_en":"Cornaceae","family_zh":"山茱萸科","iucn":null,"langs":30,"desc_zh":null,"desc_en":"Cornus suecica, the dwarf cornel or bunchberry, is a species of flowering plant in the dogwood family Cornaceae, native to cool temperate and subarctic regions of Europe, Asia, and North America.","img":"images/675.jpg","thumb":"images/t/675.jpg","file":"Cornus Suecica Bothnian Bay 2006 06 26.JPG","ar":1.25,"py":"yushanju ysj","cr_by":"— Estormiz 17:18, 17 August 2006 (UTC)","cr_lic":"Public domain","cr_licurl":null,"habit":null,"origin":["亚洲","欧洲","北美洲"]},{"id":676,"zh":"绣球花","en":"Hydrangea macrophylla","sci":"Hydrangea macrophylla","order_en":"Cornales","order_zh":"山茱萸目","family_en":"Hydrangeaceae","family_zh":"绣球科","iucn":null,"langs":48,"desc_zh":"绣球花（学名：Hydrangea macrophylla），又名绣球、八仙花、草绣球、紫阳花等，是绣球花科绣球属下的一个植物种。 绣球花原产于日本，是一种常见的园艺装饰花，花色一般包括红、蓝、紫色，会因所在环境的酸碱度引起花色变化，所以也可作为天然的酸碱指示剂，其在酸性的土壤偏向青色、中性至碱性的土壤则偏向红色。夏季开花，花期5-8月。也常用于制作干花。 原生种是「额紫杨花」（Hydrangea macrophylla f.","desc_en":"Hydrangea macrophylla is a species of flowering plant in the family Hydrangeaceae, native and endemic to Japan. It is a deciduous shrub growing to 3 m (10 ft) tall by 2.5 m (8 ft) or more broad with large heads of pink or blue flowers in summer and autumn.","img":"images/676.jpg","thumb":"images/t/676.jpg","file":"(Natural) Hydrangea macrophylla, Iwafune, Isumi, Chiba, Japan 2.jpg","ar":1.347,"py":"xiuqiuhua xqh","cr_by":"belvedere04","cr_lic":"CC BY 4.0","cr_licurl":"https://creativecommons.org/licenses/by/4.0","habit":"灌木","origin":["亚洲"]},{"id":677,"zh":"西洋山梅花","en":"Philadelphus coronarius","sci":"Philadelphus coronarius","order_en":"Cornales","order_zh":"山茱萸目","family_en":"Hydrangeaceae","family_zh":"绣球科","iucn":null,"langs":31,"desc_zh":null,"desc_en":"Philadelphus coronarius (sweet mock orange, English dogwood) is a species of flowering plant in the family Hydrangeaceae, native to the Caucasus and northeastern Turkey.","img":"images/677.jpg","thumb":"images/t/677.jpg","file":"Philadelphus coronarius.jpg","ar":1.333,"py":"xiyangshanmeihua xysmh","cr_by":"No machine-readable author provided. Rainer Bielefeld assumed (based on copyright claims).","cr_lic":"Public domain","cr_licurl":null,"habit":null,"origin":["亚洲"]},{"id":678,"zh":"圆锥绣球","en":"Hydrangea paniculata","sci":"Hydrangea paniculata","order_en":"Cornales","order_zh":"山茱萸目","family_en":"Hydrangeaceae","family_zh":"绣球科","iucn":"LC","langs":23,"desc_zh":"水亚木（学名：Hydrangea paniculata），又名糊八仙花、玉粉团、圆锥绣球。为绣球花科绣球属下的一种落叶灌木、小乔木，高度在1—5米（3.3—16.4英尺）之间。。","desc_en":"Hydrangea paniculata, or panicled hydrangea, is a species of flowering plant in the family Hydrangeaceae native to southern and eastern China, Korea, Japan and Russia (Sakhalin). It was first formally described by Philipp Franz von Siebold in 1829.","img":"images/678.jpg","thumb":"images/t/678.jpg","file":"Hydrangea paniculata IMG 6629.JPG","ar":1.501,"py":"yuanzhuixiuqiu yzxq","cr_by":"Hedwig Storch","cr_lic":"CC BY-SA 3.0","cr_licurl":"https://creativecommons.org/licenses/by-sa/3.0","habit":null,"origin":["亚洲"]},{"id":679,"zh":"树状八仙花","en":"Hydrangea arborescens","sci":"Hydrangea arborescens","order_en":"Cornales","order_zh":"山茱萸目","family_en":"Hydrangeaceae","family_zh":"绣球科","iucn":null,"langs":23,"desc_zh":null,"desc_en":"Hydrangea arborescens, commonly known as smooth hydrangea or sevenbark, is a species of flowering plant in the family Hydrangeaceae. It is a small- to medium-sized, multi-stemmed, deciduous shrub up to 2 m (7 ft) tall that is native to the eastern United State…","img":"images/679.jpg","thumb":"images/t/679.jpg","file":"Hydrangea arborescens 001.JPG","ar":0.75,"py":"shuzhuangbaxianhua szbxh","cr_by":"H. Zell","cr_lic":"CC BY-SA 3.0","cr_licurl":"https://creativecommons.org/licenses/by-sa/3.0","habit":"灌木","origin":["北美洲"]},{"id":680,"zh":"黑果越橘","en":"Vaccinium myrtillus","sci":"Vaccinium myrtillus","order_en":"Ericales","order_zh":"杜鹃花目","family_en":"Ericaceae","family_zh":"杜鹃花科","iucn":null,"langs":99,"desc_zh":"黑果越橘（学名：Vaccinium myrtillus，英语：bilberry, whortleberry），又称欧洲蓝莓（英语：European blueberry）或是山桑子，是杜鹃花科越橘属的植物。","desc_en":"Vaccinium myrtillus is a holarctic species of shrub with edible fruit of blue color, known by the common names bilberry, blaeberry, and whortleberry. It is more precisely called common bilberry or blue whortleberry to distinguish it from other Vaccinium relati…","img":"images/680.jpg","thumb":"images/t/680.jpg","file":"203 Vaccinum myrtillus L.jpg","ar":0.713,"py":"heiguoyueju hgyj","cr_by":"Amédée Masclef","cr_lic":"Public domain","cr_licurl":null,"habit":"灌木","origin":null},{"id":681,"zh":"越橘","en":"Vaccinium vitis-idaea","sci":"Vaccinium vitis-idaea","order_en":"Ericales","order_zh":"杜鹃花目","family_en":"Ericaceae","family_zh":"杜鹃花科","iucn":"LC","langs":97,"desc_zh":"越橘（学名：Vaccinium vitis-idaea），又名红豆（黑龙江）、牙疙瘩（大兴安岭），是杜鹃花科的常绿灌木植物，有“北国红豆”赞誉；性耐寒，味熟时略酸甜，未熟略苦，生长在海拔900－2000米针叶林与阔叶树交混区，红果实可当果酱、鲜食，叶可制成茶叶泡茶，叶含乌苏酸、鞣质成分。中医学认为它“利尿消炎”。喜酸性潮湿土壤。含有丰富的维他命A、维他命C、B族维他命等营养量，野生欧洲越橘大量分布在斯堪的纳维亚半岛（挪威和瑞典）。","desc_en":"Vaccinium vitis-idaea is a small evergreen shrub in the heath family, Ericaceae. It is known colloquially as the lingonberry, partridgeberry, foxberry, mountain cranberry, or cowberry.","img":"images/681.jpg","thumb":"images/t/681.jpg","file":"Vaccinium vitis-idaea 20060824 003.jpg","ar":1.333,"py":"yueju yj","cr_by":"Jonas Bergsten","cr_lic":"Public domain","cr_licurl":null,"habit":"灌木","origin":null},{"id":682,"zh":"帚石楠","en":"Calluna vulgaris","sci":"Calluna vulgaris","order_en":"Ericales","order_zh":"杜鹃花目","family_en":"Ericaceae","family_zh":"杜鹃花科","iucn":null,"langs":77,"desc_zh":"帚石楠（学名：Calluna vulgaris）是指杜鹃花科帚石楠属的植物，别名「苏格兰石楠」。在欧洲，帚石楠属与其同科近类欧石楠属经常遭到混淆，被互作训解的称号亦有不少（这种情况在汉语领域中更为明显）。虽然它们在生物分类上界线清晰，但在文化理解上却曾造成不少误会。两种花属的主要分别是帚石楠的花萼的裂片遮盖著花瓣，而欧石楠的花瓣则反过来盖著萼片。。","desc_en":"Calluna vulgaris, common heather, ling, or simply heather, is the sole species in the genus Calluna in the flowering plant family Ericaceae. It is a low-growing evergreen shrub growing to 20 to 50 centimetres (8 to 20 in) tall, or rarely to 1 metre (40 in) and…","img":"images/682.jpg","thumb":"images/t/682.jpg","file":"CallunaVulgaris.jpg","ar":1.172,"py":"zhoushinan zsn","cr_by":"Aqwis ( Aqwis )","cr_lic":"CC BY-SA 3.0","cr_licurl":"https://creativecommons.org/licenses/by-sa/3.0","habit":"灌木","origin":["亚洲","欧洲"]},{"id":683,"zh":"笃斯越橘","en":"bog bilberry","sci":"Vaccinium uliginosum","order_en":"Ericales","order_zh":"杜鹃花目","family_en":"Ericaceae","family_zh":"杜鹃花科","iucn":null,"langs":75,"desc_zh":"笃斯越橘（满语：ᡩᡠᡴᠰᡳ，穆麟德转写：duksi；拉丁学名：Vaccinium uliginosum），又名笃斯、黑豆树（大兴安岭）、𣛭柿（小兴安岭、伊春）、甸果、地果、龙果、蛤塘果（吉林）、讷日苏（蒙古语：ᠨᠡᠷᠰᠦ(᠊ᠨ)，汉语拼音字母：ners，中蒙通用转写：nersü(n)；达斡尔语：ner）、吉厄特（通古斯语：ǰukte, d/ǰusikte, ǰiksiŋē, t/čuikte）、吾格特（鄂伦春语）、皂李子等，种加词ul…","desc_en":"Vaccinium uliginosum (bog bilberry, bog blueberry, alpine blueberry or western blueberry) is an edible Eurasian and North American flowering plant in the heath family Ericaceae.","img":"images/683.jpg","thumb":"images/t/683.jpg","file":"Vaccinium uliginosum fruit.jpg","ar":1.333,"py":"dusiyueju dsyj","cr_by":"David Gaya","cr_lic":"CC BY-SA 2.5","cr_licurl":"https://creativecommons.org/licenses/by-sa/2.5","habit":null,"origin":["亚洲","北美洲"]},{"id":684,"zh":"熊果","en":"Arctostaphylos uva-ursi","sci":"Arctostaphylos uva-ursi","order_en":"Ericales","order_zh":"杜鹃花目","family_en":"Ericaceae","family_zh":"杜鹃花科","iucn":null,"langs":67,"desc_zh":"熊果又名熊葡萄、熊莓，是杜鹃花科熊果属的一种植物。","desc_en":"Arctostaphylos uva-ursi is a plant species of the genus Arctostaphylos widely distributed across circumboreal regions of the subarctic Northern Hemisphere. Kinnikinnick (from the Unami language for smoking \"mixture\") is a common name in Canada and the United S…","img":"images/684.jpg","thumb":"images/t/684.jpg","file":"Arctostaphylos uva-ursi 25924.JPG","ar":1.333,"py":"xiongguo xg","cr_by":"Walter Siegmund","cr_lic":"CC BY 2.5","cr_licurl":"https://creativecommons.org/licenses/by/2.5","habit":null,"origin":null},{"id":685,"zh":"草莓树","en":"Arbutus unedo","sci":"Arbutus unedo","order_en":"Ericales","order_zh":"杜鹃花目","family_en":"Ericaceae","family_zh":"杜鹃花科","iucn":"LC","langs":60,"desc_zh":"草莓树（学名：Arbutus unedo）是浆果鹃属下的一种常绿灌木或小树，原产于地中海地区，分布最西可达爱尔兰。在爱尔兰常被称为“爱尔兰草莓树”（Irish strawberry tree）或“基拉尼草莓树”（Killarney strawberry tree）。","desc_en":"Arbutus unedo, commonly known as strawberry tree, also called madrone, is an evergreen shrub or small tree in the family Ericaceae, native to the Mediterranean Basin and Western Europe.","img":"images/685.jpg","thumb":"images/t/685.jpg","file":"Arbouse.jpg","ar":0.812,"py":"caomeishu cms","cr_by":"Didier Descouens","cr_lic":"CC BY-SA 4.0","cr_licurl":"https://creativecommons.org/licenses/by-sa/4.0","habit":"乔木","origin":["欧洲"]},{"id":686,"zh":"白欧石楠","en":"Erica arborea","sci":"Erica arborea","order_en":"Ericales","order_zh":"杜鹃花目","family_en":"Ericaceae","family_zh":"杜鹃花科","iucn":"LC","langs":46,"desc_zh":"白欧石楠（Erica arborea）是一种常绿灌木，一般高约 1-4 公尺，有标本可达 7 公尺高。花色白，小花，长于酸性土壤。白欧石楠一般生长于环地中海地区的灌木地带，西至葡萄牙及加纳利和马德拉群岛、以至非洲紧连着的地带，例如：埃塞俄比亚高原、鲁文佐里山脉和喀麦隆山脉。 白欧石楠的木非常坚硬，而且抗热能力很强，所以常用于制作烟斗或刀柄。日常生活所讲的「石楠木」，一般都指白欧石楠，但有时亦指其他高身的欧石楠属树木，例如：葡萄牙石楠。","desc_en":"Erica arborea, the tree heath or tree heather, is a species of flowering plant (angiosperms) in the heather family Ericaceae, native to the Mediterranean Basin and Ethiopia, Kenya and Tanzania in East Africa. It is also cultivated as an ornamental.","img":"images/686.jpg","thumb":"images/t/686.jpg","file":"Axlenǧ s uleǧǧig.jpg","ar":1.501,"py":"baioushinan bosn","cr_by":"Zidat","cr_lic":"CC BY-SA 4.0","cr_licurl":"https://creativecommons.org/licenses/by-sa/4.0","habit":"乔木","origin":["欧洲","非洲"]},{"id":687,"zh":"岩高兰","en":"Empetrum nigrum","sci":"Empetrum nigrum","order_en":"Ericales","order_zh":"杜鹃花目","family_en":"Ericaceae","family_zh":"杜鹃花科","iucn":null,"langs":46,"desc_zh":"岩高兰（学名：Empetrum nigrum）为岩高兰科岩高兰属下的一个种。","desc_en":"Empetrum nigrum, the crowberry, black crowberry, mossberry, rockberry, or, in western Alaska, Labrador, etc., blackberry, is a flowering plant species in the heather family Ericaceae with a near circumboreal distribution in the Northern Hemisphere.","img":"images/687.jpg","thumb":"images/t/687.jpg","file":"Empetrum nigrum 12.jpg","ar":1.333,"py":"yangaolan ygl","cr_by":"B.gliwa","cr_lic":"CC BY-SA 2.5","cr_licurl":"https://creativecommons.org/licenses/by-sa/2.5","habit":null,"origin":null},{"id":688,"zh":"宽叶杜香","en":"Rhododendron tomentosum","sci":"Rhododendron tomentosum","order_en":"Ericales","order_zh":"杜鹃花目","family_en":"Ericaceae","family_zh":"杜鹃花科","iucn":null,"langs":45,"desc_zh":"杜香（学名：Rhododendron palustre）为杜鹃花科杜鹃花属杜香亚属下的一个种。","desc_en":"Rhododendron tomentosum (syn. Ledum palustre), commonly known as marsh Labrador tea, northern Labrador tea, marsh rosemary or wild rosemary, is a flowering plant in the subsection Ledum of the large genus Rhododendron in the family Ericaceae.","img":"images/688.jpg","thumb":"images/t/688.jpg","file":"Rhododendron-palustre.JPG","ar":1.333,"py":"kuanyeduxiang kydx","cr_by":null,"cr_lic":"CC BY-SA 3.0","cr_licurl":"http://creativecommons.org/licenses/by-sa/3.0/","habit":null,"origin":null},{"id":689,"zh":"红莓苔子","en":"Vaccinium oxycoccos","sci":"Vaccinium oxycoccos","order_en":"Ericales","order_zh":"杜鹃花目","family_en":"Ericaceae","family_zh":"杜鹃花科","iucn":"LC","langs":43,"desc_zh":"红莓苔子又名大果毛蒿豆（学名：Vaccinium oxycoccos）为杜鹃花科越桔属下的一个种。","desc_en":"Vaccinium oxycoccos is a species of cranberry in the heath family. It is known as small cranberry, marshberry, bog cranberry, swamp cranberry, or (particularly in Britain) just cranberry.","img":"images/689.jpg","thumb":"images/t/689.jpg","file":"VacciniumOxycoccos.jpg","ar":1.504,"py":"hongmeitaizi hmtz","cr_by":"Christian Fischer","cr_lic":"CC BY-SA 3.0","cr_licurl":"https://creativecommons.org/licenses/by-sa/3.0","habit":null,"origin":["欧洲"]},{"id":690,"zh":"黑海杜鹃","en":"Rhododendron ponticum","sci":"Rhododendron ponticum","order_en":"Ericales","order_zh":"杜鹃花目","family_en":"Ericaceae","family_zh":"杜鹃花科","iucn":null,"langs":37,"desc_zh":"黑海杜鹃（学名：Rhododendron ponticum）是杜鹃花科杜鹃花属常绿灌木。种加词意思是本都。","desc_en":"Rhododendron ponticum, called common rhododendron or pontic rhododendron, is a species of flowering plant in the heath family Ericaceae. It is native to the Iberian Peninsula in southwest Europe and the Caucasus region in northern West Asia.","img":"images/690.jpg","thumb":"images/t/690.jpg","file":"Pontische rododendron struik (Rhododendron ponticum).jpg","ar":1.333,"py":"heihaidujuan hhdj","cr_by":"Rasbak","cr_lic":"CC BY-SA 3.0","cr_licurl":"http://creativecommons.org/licenses/by-sa/3.0/","habit":null,"origin":["亚洲","欧洲"]},{"id":691,"zh":"大果蔓越梅","en":"Vaccinium macrocarpon","sci":"Vaccinium macrocarpon","order_en":"Ericales","order_zh":"杜鹃花目","family_en":"Ericaceae","family_zh":"杜鹃花科","iucn":"LC","langs":36,"desc_zh":"大果越橘（学名：Vaccinium macrocarpon）是蔓越橘的一种，原产于北美，属越橘属。大果越橘是多年生灌木，开白色或粉色花，果实为红色粉色，有酸味。","desc_en":"Vaccinium macrocarpon, also called large cranberry, American cranberry and bearberry, is a North American species of cranberry in the subgenus Oxycoccus. The name cranberry comes from the shape of the flower stamen, which looks like a crane's beak.","img":"images/691.jpg","thumb":"images/t/691.jpg","file":"Cranberry bog.jpg","ar":1.517,"py":"daguomanyuemei dgmym","cr_by":"Photo by Keith Weller","cr_lic":"Public domain","cr_licurl":null,"habit":null,"origin":["北美洲"]},{"id":692,"zh":"仙女越橘","en":"Andromeda polifolia","sci":"Andromeda polifolia","order_en":"Ericales","order_zh":"杜鹃花目","family_en":"Ericaceae","family_zh":"杜鹃花科","iucn":"LC","langs":36,"desc_zh":"仙女越橘（学名：Andromeda polifolia L.），是杜鹃花科仙女越橘属（学名：Andromeda L.）植物，也是该属唯一一种，分布于北半球北部。","desc_en":"Andromeda polifolia, common name bog-rosemary, is a species of flowering plant in the heath family Ericaceae, native to northern parts of the Northern Hemisphere.","img":"images/692.jpg","thumb":"images/t/692.jpg","file":"Dettaglio- Ericaceae Andormeda polifolia L. - Erbario Frizzi Perugia n. 4012.jpg","ar":0.352,"py":"xiannyueju xnyj","cr_by":"Giuseppe Frizzi","cr_lic":"Public domain","cr_licurl":null,"habit":null,"origin":null},{"id":693,"zh":"黄花九轮草","en":"Primula veris","sci":"Primula veris","order_en":"Ericales","order_zh":"杜鹃花目","family_en":"Primulaceae","family_zh":"报春花科","iucn":null,"langs":63,"desc_zh":"黄花九轮草（学名：Primula veris）是报春花科报春花属多年生草本植物。该物种的原生地在大部份的温带欧洲和西亚地区，虽然在苏格兰西北部的大部分北部地区并没有它的踪迹，但它再次出现在最北端的萨瑟兰和奥克尼群岛以及斯堪的纳维亚半岛。 该物种经常与欧报春杂交形成多花报春（Primula ×polyantha）。多花报春经常与高报春（Primula elatior）混淆。","desc_en":"Primula veris, the cowslip, common cowslip, or cowslip primrose (syn. Primula officinalis Hill), is a herbaceous perennial flowering plant in the primrose family Primulaceae.","img":"images/693.jpg","thumb":"images/t/693.jpg","file":"Common Cowslip.jpg","ar":0.751,"py":"huanghuajiuluncao hhjlc","cr_by":"Avetisyan Ani","cr_lic":"CC BY-SA 4.0","cr_licurl":"https://creativecommons.org/licenses/by-sa/4.0","habit":"草本","origin":["亚洲","欧洲"]},{"id":694,"zh":"欧洲报春","en":"Primula vulgaris","sci":"Primula vulgaris","order_en":"Ericales","order_zh":"杜鹃花目","family_en":"Primulaceae","family_zh":"报春花科","iucn":null,"langs":57,"desc_zh":"欧报春（学名：Primula vulgaris），又名欧洲报春花、西洋樱草，是报春花属下的一种多年生草本植物，广泛分布于西欧、南欧、北非、西亚，也是一种常见的园艺植物。其种加词的意思就是“普通的”。","desc_en":"Primula vulgaris is a species of flowering plant in the family Primulaceae, native to Eurasia. The common name of this plant is primrose, or occasionally common primrose or English primrose to distinguish it from other Primula species referred to as primroses.","img":"images/694.jpg","thumb":"images/t/694.jpg","file":"Chipping Sodbury MMB 02 primula vulgaris.jpg","ar":1.501,"py":"ouzhoubaochun ozbc","cr_by":"mattbuck ( category )","cr_lic":"CC BY-SA 3.0","cr_licurl":"https://creativecommons.org/licenses/by-sa/3.0","habit":null,"origin":["亚洲"]},{"id":695,"zh":"琉璃繁缕","en":"Lysimachia arvensis","sci":"Lysimachia arvensis","order_en":"Ericales","order_zh":"杜鹃花目","family_en":"Primulaceae","family_zh":"报春花科","iucn":null,"langs":57,"desc_zh":"琉璃繁缕（学名：Anagallis arvensis），为报春花科琉璃繁缕属下的一个植物物种。","desc_en":"Lysimachia arvensis, syn. Anagallis arvensis, commonly known as scarlet pimpernel, red pimpernel, red chickweed, poor man's barometer, poor man's weather-glass, shepherd's weather glass or shepherd's clock, is a species of low-growing annual plant with brightl…","img":"images/695.jpg","thumb":"images/t/695.jpg","file":"Scarlet Pimpernel (Lysimachia arvensis) - Pollença, Spain 2022-04-15.jpg","ar":1,"py":"liulifanl llfl","cr_by":"Ryan Hodnett","cr_lic":"CC BY-SA 4.0","cr_licurl":"https://creativecommons.org/licenses/by-sa/4.0","habit":"草本","origin":null},{"id":696,"zh":"毛黄连花","en":"Lysimachia vulgaris","sci":"Lysimachia vulgaris","order_en":"Ericales","order_zh":"杜鹃花目","family_en":"Primulaceae","family_zh":"报春花科","iucn":"LC","langs":37,"desc_zh":"毛黄连花（学名：Lysimachia vulgaris）为报春花科珍珠菜属的植物。分布在欧洲、高加索、中亚、西伯利亚以及中国大陆的新疆等地，生长于海拔500米至700米的地区，见于沟边芦苇地中，目前尚未由人工引种栽培。","desc_en":"Lysimachia vulgaris, the yellow loosestrife or garden loosestrife, is a species of herbaceous perennial flowering plant in the family Primulaceae. It was transferred to Myrsinoideae based on results of molecular phylogenetic research before being merged into t…","img":"images/696.jpg","thumb":"images/t/696.jpg","file":"Lysimachia vulgaris.jpeg","ar":0.87,"py":"maohuanglianhua mhlh","cr_by":"Kristian Peters -- Fabelfroh 15:11, 26 September 2005 (UTC)","cr_lic":"CC BY-SA 3.0","cr_licurl":"http://creativecommons.org/licenses/by-sa/3.0/","habit":"草本","origin":null},{"id":697,"zh":"仙客来","en":"Cyclamen persicum","sci":"Cyclamen persicum","order_en":"Ericales","order_zh":"杜鹃花目","family_en":"Primulaceae","family_zh":"报春花科","iucn":null,"langs":37,"desc_zh":"仙客来（学名：Cyclamen persicum），别名萝卜海棠、兔耳花、兔子花、一品冠、篝火花、翻瓣莲，是报春花科仙客来属多年生草本植物。仙客来是一种普遍种植的鲜花，适合种植于室内花盆，冬季则需温室种植。仙客来的某些栽培品种有浓郁的香气，而有些香气淡或无香气。 “仙客来”一词来自学名Cyclamen的音译，由于音译巧妙，使得花名有“仙客翩翩而至”的寓意。","desc_en":"Cyclamen persicum, the Persian cyclamen, is a species of flowering herbaceous perennial plant growing from a tuber, native to rocky hillsides, shrubland, and woodland up to 1,200 m (3,900 ft) above sea level, from south-central Turkey to the Levant.","img":"images/697.jpg","thumb":"images/t/697.jpg","file":"Yagur – Nesher, the Green Path – Mount Carmel 016.JPG","ar":0.75,"py":"xiankelai xkl","cr_by":"Hanay","cr_lic":"CC BY-SA 3.0","cr_licurl":"https://creativecommons.org/licenses/by-sa/3.0","habit":"草本","origin":["亚洲"]},{"id":698,"zh":"粉报春","en":"Primula farinosa","sci":"Primula farinosa","order_en":"Ericales","order_zh":"杜鹃花目","family_en":"Primulaceae","family_zh":"报春花科","iucn":null,"langs":36,"desc_zh":"粉报春（学名：Primula farinosa），为报春花科报春花属下的一个植物种。","desc_en":"Primula farinosa, the bird's-eye primrose, is a small perennial plant in the family Primulaceae, native to Northern Europe and further south at high altitudes in the mountains of southern Europe. It is also widespread in northern and central Asia.","img":"images/698.jpg","thumb":"images/t/698.jpg","file":"Primula farinosa flowers 100704.jpg","ar":1.07,"py":"fenbaochun fbc","cr_by":null,"cr_lic":"CC BY-SA 3.0","cr_licurl":"http://creativecommons.org/licenses/by-sa/3.0/","habit":"草本","origin":["欧洲"]},{"id":699,"zh":"茶树","en":"Camellia sinensis","sci":"Camellia sinensis","order_en":"Ericales","order_zh":"杜鹃花目","family_en":"Theaceae","family_zh":"山茶科","iucn":"DD","langs":93,"desc_zh":"茶树（学名：Camellia sinensis）是山茶科山茶属的一种，为多年生常绿木本植物，落叶灌木或乔木。在热带地区也有乔木型茶树高达15－30米，基部树围1.5米以上。栽培茶树往往通过修剪来抑制纵向生长，所以树高多在0.8－1.2米间。 其种加词“sinensis”意为“中华的”。","desc_en":"Camellia sinensis is a species of evergreen shrub or small tree in the flowering plant family Theaceae. Its leaves, leaf buds, and stems are used to produce tea.","img":"images/699.jpg","thumb":"images/t/699.jpg","file":"Csinensis.jpg","ar":1.333,"py":"chashu cs","cr_by":"AxelBoldt at en.wikipedia","cr_lic":"Public domain","cr_licurl":null,"habit":"乔木","origin":null},{"id":700,"zh":"山茶花","en":"Camellia japonica","sci":"Camellia japonica","order_en":"Ericales","order_zh":"杜鹃花目","family_en":"Theaceae","family_zh":"山茶科","iucn":"LC","langs":50,"desc_zh":"山茶（学名：Camellia japonica），又名山茶花､ 玉茗花、耐冬､ 椿花，山茶科山茶属植物，是一种常绿灌木或小乔木，古名海石榴｡ 山茶的花大多数为红色或淡红色，亦有白色，多为重瓣。茶花的品种极多，是东亚传统的观赏花卉，在“十大名花”中排名第七。茶花也在全世界多地广泛栽培，用于园艺装饰。种子也可榨油。","desc_en":"Camellia japonica, known as common camellia, or Japanese camellia, is a species of flowering plant from the genus Camellia in the tea family Theaceae. It is native to China and Japan, and grows naturally in forests at altitudes of around 300–1,100 metres (980–…","img":"images/700.jpg","thumb":"images/t/700.jpg","file":"Camellia japonica var. decumbens 3.JPG","ar":1.333,"py":"shanchahua sch","cr_by":"Qwert1234","cr_lic":"CC BY-SA 3.0","cr_licurl":"https://creativecommons.org/licenses/by-sa/3.0","habit":null,"origin":["亚洲"]},{"id":701,"zh":"富兰克林木","en":"Franklinia alatamaha","sci":"Franklinia alatamaha","order_en":"Ericales","order_zh":"杜鹃花目","family_en":"Theaceae","family_zh":"山茶科","iucn":"EW","langs":24,"desc_zh":"洋木荷属（学名：Franklinia）也称富兰克林木属，为山茶科的一个属。","desc_en":"Franklinia is a monotypic genus in the tea family, Theaceae. The sole species in this genus is a flowering tree, Franklinia alatamaha, commonly called Franklinias or the Franklin tree, and native to the Altamaha River valley in Georgia in the southeastern Unit…","img":"images/701.jpg","thumb":"images/t/701.jpg","file":"Franklinia alatamaha.jpg","ar":1.333,"py":"fulankelinmu flklm","cr_by":"Francine Riez","cr_lic":"CC BY-SA 3.0","cr_licurl":"https://creativecommons.org/licenses/by-sa/3.0","habit":"乔木","origin":["北美洲"]},{"id":702,"zh":"茶梅","en":"Camellia sasanqua","sci":"Camellia sasanqua","order_en":"Ericales","order_zh":"杜鹃花目","family_en":"Theaceae","family_zh":"山茶科","iucn":"LC","langs":21,"desc_zh":"茶梅（学名：Camellia sasanqua，日语：サザンカ）是山茶属油茶组的一种常绿灌木或小乔木，原产于日本南部（四国、九州）及琉球群岛。它在东亚拥有悠久的栽培历史，既作为观赏植物，又可用于种子榨油和叶片制茶。","desc_en":"Camellia sasanqua, with common name Sasanqua camellia or Christmas camellia (茶梅, サザンカ), is an evergreen shrub or small tree in the genus Camellia, section Oleifera of the family Theaceae. It is native to southern Japan (Shikoku, Kyushu) and the Ryukyu Islands.","img":"images/702.jpg","thumb":"images/t/702.jpg","file":"Camellia sasanqua1.jpg","ar":1.08,"py":"chamei cm","cr_by":"KENPEI","cr_lic":"CC BY-SA 3.0","cr_licurl":"http://creativecommons.org/licenses/by-sa/3.0/","habit":"乔木","origin":["亚洲"]},{"id":703,"zh":"油茶","en":"Camellia oleifera","sci":"Camellia oleifera","order_en":"Ericales","order_zh":"杜鹃花目","family_en":"Theaceae","family_zh":"山茶科","iucn":"LC","langs":17,"desc_zh":"油茶（学名：Camellia oleifera），俗称大果油茶（相对于小果油茶，即短柱山茶），是山茶科山茶属的植物。油茶种子包含脂肪，榨出的茶油色清味香，营养丰富。榨油后剩下的茶籽可作清洁剂。 在台湾，油茶又俗称苦茶，所以其种子榨出之油，又称苦茶油。","desc_en":"Camellia oleifera, which originated in China, is notable as an important source of edible oil (known as tea oil or camellia oil) obtained from its seeds. It is commonly known as the oil-seed camellia or tea oil camellia, though to a lesser extent other species…","img":"images/703.jpg","thumb":"images/t/703.jpg","file":"Camellia oleifera.jpg","ar":0.789,"py":"youcha yc","cr_by":"USDA Agricultural Research Service","cr_lic":"Public domain","cr_licurl":null,"habit":"乔木","origin":["亚洲"]},{"id":704,"zh":"人心果","en":"Manilkara zapota","sci":"Manilkara zapota","order_en":"Ericales","order_zh":"杜鹃花目","family_en":"Sapotaceae","family_zh":"山榄科","iucn":"LC","langs":77,"desc_zh":"人心果，别称仁心果、赤铁果、在台湾又称吴凤柿、人参果、台语查某李仔、查某囡仔、英文称Sapodilla、马来文称Basiku或Buah Ciku、印尼文称Sawo、越南称Hồng xiêm、寮国称Lamood或Rarmood。是一种山榄科铁线子属的常绿中乔木。人心果之称来自广东，因纵剖面似人心而得。 人心果树原产于美洲热带，结果时间很长，大概要用一年时间。","desc_en":"Manilkara zapota, commonly known as sapodilla (Spanish: [ˌsapoˈðiʝa]), sapote, chicozapote, chico, chicoo, chicle, naseberry, nispero, or soapapple, among other names, is an evergreen tree native to southern Mexico and Central America.","img":"images/704.jpg","thumb":"images/t/704.jpg","file":"Manilkara Zapota in HK.JPG","ar":1.37,"py":"renxinguo rxg","cr_by":"HK Arun","cr_lic":"CC BY-SA 3.0","cr_licurl":"https://creativecommons.org/licenses/by-sa/3.0","habit":"乔木","origin":["北美洲"]},{"id":705,"zh":"摩洛哥坚果","en":"Argania spinosa","sci":"Argania spinosa","order_en":"Ericales","order_zh":"杜鹃花目","family_en":"Sapotaceae","family_zh":"山榄科","iucn":null,"langs":55,"desc_zh":"摩洛哥坚果（学名：Sideroxylon spinosum），亦有音译阿甘，是一种生长自西地中海的北非地区的碳酸钙半沙漠山谷的山榄科特有种植物，可在摩洛哥西南部的苏斯及阿尔及利亚的廷杜夫合共8280平方公里的联合国教科文组织生物圈保护区内发现。 摩洛哥坚果之所以闻名遐迩是因为这种坚果榨出来的坚果油一种很受欢迎的产品，即可以食用也可以做为美容护肤用品而供人们使用。","desc_en":"Sideroxylon spinosum, known as argan (Tashelhit: ⴰⵔⴳⴰⵏ, romanized: argan), synonym Argania spinosa, is a species of flowering plant. It is a tree native to the calcareous semi-desert Sous valley and to the Chiadma and Haha regions of Morocco, as well as some p…","img":"images/705.jpg","thumb":"images/t/705.jpg","file":"Argania spinosa.jpg","ar":1.333,"py":"moluogejianguo mlgjg","cr_by":"No machine-readable author provided. MPF assumed (based on copyright claims).","cr_lic":"CC BY 2.5","cr_licurl":"https://creativecommons.org/licenses/by/2.5","habit":"乔木","origin":["非洲"]},{"id":706,"zh":"乳油木","en":"Vitellaria paradoxa","sci":"Vitellaria paradoxa","order_en":"Ericales","order_zh":"杜鹃花目","family_en":"Sapotaceae","family_zh":"山榄科","iucn":"VU","langs":47,"desc_zh":"乳油木（学名：Vitellaria paradoxa，旧名Butyrospermum parkii），又名牛油果、乳木果、雪亚果（Shea nut）或非洲果，是属于山榄科，乳木果属的一种树木。乳油木是非洲特有的植物，原产于马利、喀麦隆、刚果、象牙海岸、迦纳、几内亚、多哥、奈及利亚、塞内加尔、苏丹、布吉纳法索及乌干达等地。乳油木的种子很大，含有丰富的油脂，可以从中提取出乳木果油。","desc_en":"Vitellaria paradoxa (formerly Butyrospermum parkii), commonly known as shea tree, shi tree (, also ), or vitellaria, is a tree of the family Sapotaceae. It is the only species in the genus Vitellaria, and is indigenous to Africa.","img":"images/706.jpg","thumb":"images/t/706.jpg","file":"Vitellaria paradoxa MS4195.JPG","ar":1.333,"py":"ruyoumu rym","cr_by":"Marco Schmidt","cr_lic":"CC BY-SA 2.5","cr_licurl":"https://creativecommons.org/licenses/by-sa/2.5","habit":"乔木","origin":["非洲"]},{"id":707,"zh":"蛋黄果","en":"Pouteria campechiana","sci":"Pouteria campechiana","order_en":"Ericales","order_zh":"杜鹃花目","family_en":"Sapotaceae","family_zh":"山榄科","iucn":"LC","langs":46,"desc_zh":"蛋黄果（英文名：Canistel，学名：Pouteria campechiana）即具脉果榄。为山榄科桃榄属下的一个种。出自台湾宗教习惯，依果型又取名为仙桃。原产南美洲北部，也栽培于其他热带地区。台湾于1929年由菲律宾引入，试种于台湾总督府农业试验所嘉义支场 。","desc_en":"Pouteria campechiana (commonly known as the cupcake fruit, eggfruit, zapote amarillo, yellow sapote or canistel) is an evergreen tree native to, and cultivated in, southern Mexico, Belize, Guatemala, and El Salvador.","img":"images/707.jpg","thumb":"images/t/707.jpg","file":"Canistel.jpg","ar":0.993,"py":"danhuangguo dhg","cr_by":"Hans B. at Dutch Wikipedia","cr_lic":"Public domain","cr_licurl":null,"habit":"乔木","origin":["北美洲"]},{"id":708,"zh":"柿树","en":"Diospyros kaki","sci":"Diospyros kaki","order_en":"Ericales","order_zh":"杜鹃花目","family_en":"Ebenaceae","family_zh":"柿科","iucn":"LC","langs":78,"desc_zh":"柿（学名：Diospyros kaki），是柿树属的一种落叶乔木，是最常见的产柿子的植物，原产于中国长江流域，后来引入日本、美国等世界其他地区。","desc_en":"Diospyros kaki, the Oriental persimmon, Chinese persimmon, Japanese persimmon, kaki persimmon, or Fuyu persimmon, is the most widely cultivated species of the genus Diospyros. Although its first botanical description was not published until 1780, D.","img":"images/708.jpg","thumb":"images/t/708.jpg","file":"Kaki 20041002.jpg","ar":1.333,"py":"shishu ss","cr_by":"Sphl","cr_lic":"CC BY-SA 3.0","cr_licurl":"http://creativecommons.org/licenses/by-sa/3.0/","habit":null,"origin":["亚洲"]},{"id":709,"zh":"君迁子","en":"Diospyros lotus","sci":"Diospyros lotus","order_en":"Ericales","order_zh":"杜鹃花目","family_en":"Ebenaceae","family_zh":"柿科","iucn":"LC","langs":38,"desc_zh":"君迁子（学名：Diospyros lotus），又名黑枣、猴枣、豆柿，为柿科柿属下的一个种。它原产于欧亚大陆，从中国到南欧都有分布。君迁子在古希腊语中称“Dios pyros”，即“诸神之果”，这亦是柿属属名的来源。其果实味道像是樱桃和枣混在一起。","desc_en":"The date-plum (Diospyros lotus), also known by the common names Caucasian persimmon and lilac persimmon, is a widely cultivated species of the genus Diospyros, native to temperate Asia and southeast Europe.","img":"images/709.jpg","thumb":"images/t/709.jpg","file":"Caucasian persimmon - Diospyros lotus 07.jpg","ar":1.419,"py":"junqianzi jqz","cr_by":"Zeynel Cebeci","cr_lic":"CC BY-SA 4.0","cr_licurl":"https://creativecommons.org/licenses/by-sa/4.0","habit":null,"origin":["亚洲","欧洲"]},{"id":710,"zh":"凤仙花","en":"Impatiens balsamina","sci":"Impatiens balsamina","order_en":"Ericales","order_zh":"杜鹃花目","family_en":"Balsaminaceae","family_zh":"凤仙花科","iucn":null,"langs":50,"desc_zh":"凤仙花（学名：Impatiens balsamina），又名指甲花（台罗：tsíng-kah-hue）、指甲桃、急性子、凤仙透骨草，是凤仙花科凤仙花属的植物。","desc_en":"Impatiens balsamina, commonly known as balsam, garden balsam, rose balsam, touch-me-not or spotted snapweed, is a species of plant native to India and Myanmar. It is an annual plant growing to 20–75 cm tall, with a thick, but soft stem.","img":"images/710.jpg","thumb":"images/t/710.jpg","file":"Antsiranana 08.jpg","ar":0.75,"py":"fengxianhua fxh","cr_by":"Florantsika","cr_lic":"CC BY 4.0","cr_licurl":"https://creativecommons.org/licenses/by/4.0","habit":"草本","origin":["亚洲"]},{"id":711,"zh":"水金凤","en":"Impatiens noli-tangere","sci":"Impatiens noli-tangere","order_en":"Ericales","order_zh":"杜鹃花目","family_en":"Balsaminaceae","family_zh":"凤仙花科","iucn":"LC","langs":41,"desc_zh":"水金凤（学名：Impatiens noli-tangere），又名辉菜花，是凤仙花科凤仙花属的植物。分布于俄罗斯、朝鲜、日本以及中国大陆的陕西、河北、湖南、山东、辽宁、浙江、甘肃、湖北、内蒙古、安徽、黑龙江、吉林、山西、河南等地，生长于海拔900米至2,400米的地区，多生长于山坡林下。","desc_en":"Impatiens noli-tangere (touch-me-not balsam; Latin impatiēns 'impatient' or 'not allowing', and nōlī tangere 'do not touch': literally 'be unwilling to touch') is an annual herbaceous plant in the family Balsaminaceae found in damp places in Europe, Asia and N…","img":"images/711.jpg","thumb":"images/t/711.jpg","file":"NoliTangere Pflanze.jpg","ar":0.75,"py":"shuijinfeng sjf","cr_by":"Túrelio","cr_lic":"CC BY-SA 2.5","cr_licurl":"https://creativecommons.org/licenses/by-sa/2.5","habit":"草本","origin":["亚洲","欧洲","北美洲"]},{"id":712,"zh":"腺柄凤仙花","en":"Impatiens glandulifera","sci":"Impatiens glandulifera","order_en":"Ericales","order_zh":"杜鹃花目","family_en":"Balsaminaceae","family_zh":"凤仙花科","iucn":null,"langs":37,"desc_zh":null,"desc_en":"Impatiens glandulifera, Himalayan balsam, is a large annual plant native to the Himalayas. Via human introduction it is now present across much of the Northern Hemisphere and is considered an invasive species in many areas.","img":"images/712.jpg","thumb":"images/t/712.jpg","file":"Valley of flowers National Park 04.JPG","ar":1.333,"py":"xianbingfengxianhua xbfxh","cr_by":"Guptaele","cr_lic":"CC BY-SA 4.0","cr_licurl":"https://creativecommons.org/licenses/by-sa/4.0","habit":"草本","origin":["亚洲"]},{"id":713,"zh":"小花凤仙花","en":"Impatiens parviflora","sci":"Impatiens parviflora","order_en":"Ericales","order_zh":"杜鹃花目","family_en":"Balsaminaceae","family_zh":"凤仙花科","iucn":null,"langs":32,"desc_zh":"小花凤仙花（学名：Impatiens parviflora）是凤仙花科凤仙花属的植物。其种加词“parviflora”意为“小花的”。分布在蒙古、俄罗斯、欧洲以及中国大陆的西藏等地，生长于海拔1,200米至1,680米的地区，常生于沼泽地、河岸边以及山坡沟边潮湿处，目前尚未由人工引种栽培。","desc_en":"Impatiens parviflora (small balsam, or small-flowered touch-me-not) is a species of annual herbaceous plants in the family Balsaminaceae, native to some areas of Eurasia, naturalized elsewhere and found in damp shady places.","img":"images/713.jpg","thumb":"images/t/713.jpg","file":"Impatiens parviflora - plant (aka).jpg","ar":0.665,"py":"xiaohuafengxianhua xhfxh","cr_by":"André Karwath aka Aka","cr_lic":"CC BY-SA 2.5","cr_licurl":"https://creativecommons.org/licenses/by-sa/2.5","habit":"草本","origin":["亚洲"]},{"id":714,"zh":"花荵","en":"Polemonium caeruleum","sci":"Polemonium caeruleum","order_en":"Ericales","order_zh":"杜鹃花目","family_en":"Polemoniaceae","family_zh":"花荵科","iucn":null,"langs":33,"desc_zh":"花荵（学名：Polemonium caeruleum）为花荵科花荵属下的一个种。","desc_en":"Polemonium caeruleum, known as Jacob's-ladder or Greek valerian, is a hardy perennial flowering plant. The plant produces cup-shaped, blue or white flowers. It is native to temperate regions of Europe. It is the type species of the phlox family, Polemoniaceae.","img":"images/714.jpg","thumb":"images/t/714.jpg","file":"Polemonium caeruleum nf.jpg","ar":0.606,"py":"huaren hr","cr_by":"Carl Axel Magnus Lindman","cr_lic":"Public domain","cr_licurl":null,"habit":"草本","origin":["欧洲"]},{"id":715,"zh":"天蓝绣球","en":"Phlox paniculata","sci":"Phlox paniculata","order_en":"Ericales","order_zh":"杜鹃花目","family_en":"Polemoniaceae","family_zh":"花荵科","iucn":null,"langs":30,"desc_zh":"天蓝绣球（学名：Phlox paniculata）为花荵科天蓝绣球属下的一个种。","desc_en":"Phlox paniculata is a species of flowering plant in the phlox family (Polemoniaceae). It is native to parts of the eastern and central United States. It is extensively cultivated in temperate regions as an ornamental plant and has become established in the wil…","img":"images/715.jpg","thumb":"images/t/715.jpg","file":"(MHNT) Phlox paniculata famous light purple - Les Martels, Giroussens Tarn.jpg","ar":1.411,"py":"tianlanxiuqiu tlxq","cr_by":"Didier Descouens","cr_lic":"CC BY-SA 4.0","cr_licurl":"https://creativecommons.org/licenses/by-sa/4.0","habit":"草本","origin":["北美洲"]},{"id":716,"zh":"软枣猕猴桃","en":"Actinidia arguta","sci":"Actinidia arguta","order_en":"Ericales","order_zh":"杜鹃花目","family_en":"Actinidiaceae","family_zh":"猕猴桃科","iucn":null,"langs":34,"desc_zh":"软枣猕猴桃（学名：Actinidia arguta），台湾称之为迷你奇异果或袖珍奇异果，又名奇异莓（英文：Kiwiberry），中国大陆称之为软枣猕猴桃，俗称软枣子（中国东北部分地区写作方言中同音的元枣子），为猕猴桃科猕猴桃属的植物。分布在朝鲜、日本以及中国大陆的辽宁、浙江、山西、山东、安徽、河南、吉林、云南等、河北、黑龙江等地，生长于海拔200米至3,602米的地区，多生长在山坡灌木林中、沟边、山顶杂木林中、山坡杂木林中、山坡灌丛、山…","desc_en":"Actinidia arguta is a perennial vine native to Japan, Korea, Northern China, and the Russian Far East. The fruit is known as kiwiberry or hardy kiwi, which are small kiwifruits without the hair-like fiber covering the outside, unlike most other species of the…","img":"images/716.jpg","thumb":"images/t/716.jpg","file":"Actinidia arguta fruit - hardy kiwi - Kiwibeere 05.jpg","ar":1.307,"py":"ruanzaomihoutao rzmht","cr_by":"Rillke","cr_lic":"CC BY 3.0","cr_licurl":"https://creativecommons.org/licenses/by/3.0","habit":"藤本","origin":["亚洲"]},{"id":717,"zh":"眼镜蛇瓶子草","en":"Darlingtonia californica","sci":"Darlingtonia californica","order_en":"Ericales","order_zh":"杜鹃花目","family_en":"Sarraceniaceae","family_zh":"瓶子草科","iucn":"LC","langs":41,"desc_zh":"眼镜蛇瓶子草（学名：Darlingtonia californica），又称为加州瓶子草（California Pitcher plant）、眼镜蛇百合（Cobra Lily）、眼镜蛇植物（Cobra Plant），为瓶子草科眼镜蛇瓶子草属食虫植物。眼镜蛇瓶子草属为单种属，仅眼镜蛇瓶子草一种。其种加词“californica”意为“美国加利福尼亚的”。其原产于奥勒冈州及加利福尼亚州以北的沼泽及冷水浸润地。","desc_en":"Darlingtonia californica is a species of carnivorous plant in the new world pitcher plant family, Sarraceniaceae. The cobra lily is the sole species within its monotypic genus, Darlingtonia.","img":"images/717.jpg","thumb":"images/t/717.jpg","file":"Cobra lilies with flowers 1 - Darlingtonia SNS Oregon.jpg","ar":1.333,"py":"yanjingshepingzicao yjspzc","cr_by":"Ian Poellet","cr_lic":"CC BY-SA 4.0","cr_licurl":"https://creativecommons.org/licenses/by-sa/4.0","habit":null,"origin":["北美洲"]},{"id":718,"zh":"杜仲","en":"Eucommia ulmoides","sci":"Eucommia ulmoides","order_en":"Garryales","order_zh":"绞木目","family_en":"Eucommiaceae","family_zh":"杜仲科","iucn":"VU","langs":29,"desc_zh":"杜仲（学名：Eucommia ulmoides），别名木棉、思仙、思仲、思锦树、石思仙、扯丝皮、棉皮、玉丝皮，为杜仲科植物。杜仲的化学成分包括木脂素类、环烯醚萜类、黄酮类、苯丙素类、甾醇类、三萜类、多糖类、抗真菌蛋白和矿物元素等。","desc_en":"Eucommia ulmoides is a species of small tree native to China. It belongs to the monotypic family Eucommiaceae. It is considered vulnerable in the wild, but is widely cultivated in China for its bark and is highly valued in herbology such as traditional Chinese…","img":"images/718.jpg","thumb":"images/t/718.jpg","file":"Eucommia-ulmoides.JPG","ar":1.499,"py":"duzhong dz","cr_by":"Sten Porse","cr_lic":"CC BY-SA 3.0","cr_licurl":"https://creativecommons.org/licenses/by-sa/3.0","habit":"乔木","origin":["亚洲"]},{"id":719,"zh":"檄树","en":"Morinda citrifolia","sci":"Morinda citrifolia","order_en":"Gentianales","order_zh":"龙胆目","family_en":"Rubiaceae","family_zh":"茜草科","iucn":null,"langs":71,"desc_zh":"檄（xí）树（学名：Morinda citrifolia，又名海滨木巴戟、海巴戟，是茜草科巴戟天属的一种植物，与咖啡同科，灌木至小乔木，高1—5米（3英尺3英寸—16英尺5英寸），属于经济作物，分布于新加坡、马来西亚、印度尼西亚、台湾、海南、云南、西沙群岛、南沙群岛、永兴岛、澳大利亚、法属波利尼西亚、夏威夷等东南亚、太平洋岛屿。","desc_en":"Morinda citrifolia is a fruit-bearing tree in the coffee family, Rubiaceae. It is commonly known as noni or Indian mulberry, among many other names. Native to Southeast Asia and Australasia, the species was spread across the Pacific by Polynesian sailors.","img":"images/719.png","thumb":"images/t/719.png","file":"Morinda citrifolia Blanco1.52.png","ar":0.715,"py":"xishu xs","cr_by":"Francisco Manuel Blanco (O.S.A.)","cr_lic":"Public domain","cr_licurl":null,"habit":"乔木","origin":["亚洲","大洋洲"]},{"id":720,"zh":"小粒咖啡","en":"Coffea arabica","sci":"Coffea arabica","order_en":"Gentianales","order_zh":"龙胆目","family_en":"Rubiaceae","family_zh":"茜草科","iucn":"EN","langs":63,"desc_zh":"小果咖啡（学名：Coffea arabica）亦称阿拉伯咖啡、阿拉比卡咖啡，为茜草科（Rubiaceae）咖啡属的一个物种。小果咖啡原产于东非，属大灌木或小乔木，高度5到8米；叶薄革质，光滑深绿色，卵状披针形，长6—14厘米，宽3.5—5厘米，叶缘全缘成浅波浪状；花冠为白色，花期3～4月；核果椭圆形，成熟时变成红色，长约10～15毫米；常含两枚种子，称作咖啡豆。","desc_en":"Coffea arabica (), also known as the Arabica coffee, is a species of flowering plant in the coffee and madder family Rubiaceae. It is believed to be the first species of coffee to have been cultivated and is the dominant cultivar, representing about 60% of glo…","img":"images/720.jpg","thumb":"images/t/720.jpg","file":"Coffee Flowers.JPG","ar":1.333,"py":"xiaolikafei xlkf","cr_by":"Marcelo Corrêa","cr_lic":"CC BY-SA 3.0","cr_licurl":"http://creativecommons.org/licenses/by-sa/3.0/","habit":null,"origin":null},{"id":721,"zh":"香猪殃殃","en":"sweet woodruff","sci":"Galium odoratum","order_en":"Gentianales","order_zh":"龙胆目","family_en":"Rubiaceae","family_zh":"茜草科","iucn":null,"langs":60,"desc_zh":"香猪殃殃（学名：Galium odoratum）又名香车叶草，是茜草科猪殃殃属的植物，原产于欧洲、西亚及北非。植株具有香味，可以添加在食物及酒内以增加食品的风味。 多年生草本植物，植株长三十至五十公分，常平卧在地面上或攀附在其他植物上。叶为单叶，披针形，光滑无毛，长二至五公分，叶六至九片轮生。花小，花径四至七公厘，白色，每一朵花有四片花瓣，花瓣在基部合生，花序为聚繖花序。","desc_en":"Galium odoratum, the sweet woodruff or sweetscented bedstraw, is a flowering perennial plant in the family Rubiaceae, native to much of Europe. It is widely cultivated for its flowers and its sweet-smelling foliage.","img":"images/721.jpg","thumb":"images/t/721.jpg","file":"Waldmeister.jpg","ar":0.75,"py":"xiangzhuyangyang xzyy","cr_by":"Jopi","cr_lic":"Public domain","cr_licurl":null,"habit":"草本","origin":["欧洲"]},{"id":722,"zh":"蓬子菜","en":"Galium verum","sci":"Galium verum","order_en":"Gentianales","order_zh":"龙胆目","family_en":"Rubiaceae","family_zh":"茜草科","iucn":null,"langs":58,"desc_zh":"蓬子菜（学名：Galium verum）为茜草科拉拉藤属下的一个种。","desc_en":"Galium verum (lady's bedstraw or yellow bedstraw) is a herbaceous perennial flowering plant in the family Rubiaceae. It is widespread across most of Europe, North Africa, and temperate Asia from Israel, Lebanon and Turkey to Japan and Kamchatka.","img":"images/722.jpg","thumb":"images/t/722.jpg","file":"Galium verum 02.jpg","ar":0.75,"py":"pengzicai pzc","cr_by":"Bjoertvedt","cr_lic":"CC BY-SA 3.0","cr_licurl":"https://creativecommons.org/licenses/by-sa/3.0","habit":"草本","origin":["亚洲","欧洲","非洲"]},{"id":723,"zh":"原拉拉藤","en":"Galium aparine","sci":"Galium aparine","order_en":"Gentianales","order_zh":"龙胆目","family_en":"Rubiaceae","family_zh":"茜草科","iucn":null,"langs":51,"desc_zh":"原拉拉藤（学名：Galium aparine），或称为欧洲猪殃殃，为茜草科拉拉藤属下的一个种。","desc_en":"Galium aparine, with common names including cleavers, clivers, catchweed, robin-run-the-hedge, goosegrass, and sticky willy, is an annual, herbaceous plant of the family Rubiaceae.","img":"images/723.jpg","thumb":"images/t/723.jpg","file":"Flowers February 2008-4.jpg","ar":0.898,"py":"yuanlalateng yllt","cr_by":"Alvesgaspar","cr_lic":"CC BY-SA 3.0","cr_licurl":"https://creativecommons.org/licenses/by-sa/3.0","habit":"草本","origin":null},{"id":724,"zh":"栀子花","en":"Gardenia jasminoides","sci":"Gardenia jasminoides","order_en":"Gentianales","order_zh":"龙胆目","family_en":"Rubiaceae","family_zh":"茜草科","iucn":null,"langs":51,"desc_zh":"栀（zhī）子（zi）（学名：Gardenia jasminoides），又名木丹、鲜支、卮（zhī）子、越桃、白蟾花､ 林兰､ 水横枝、栀子花、支子花、枝子花、山栀花、黄鸡子、黄荑子、黄栀子、黄栀、黄栀花、山黄栀、玉荷花、白婵花、玉堂春，属茜草科栀子属常绿植物。 因栀子的花香清雅甜美，故为中国典型香花植物之一。常与梅、百合、菊、连香树、茉莉花、水仙合称为「七香」。中国两汉时期，种植栀子花，多为染物之用，为珍贵的经济作物之一。","desc_en":"Gardenia jasminoides, commonly known as gardenia and cape jasmine, is an evergreen flowering plant in the coffee family Rubiaceae. It is native to the subtropical and northern tropical parts of the Far East.","img":"images/724.jpg","thumb":"images/t/724.jpg","file":"Gardenia jasminoides in Mount Yagi 2008-06-13.jpg","ar":1.466,"py":"zhizihua zzh","cr_by":"Alpsdake","cr_lic":"CC BY-SA 3.0","cr_licurl":"https://creativecommons.org/licenses/by-sa/3.0","habit":null,"origin":null},{"id":725,"zh":"染色茜草","en":"Rubia tinctorum","sci":"Rubia tinctorum","order_en":"Gentianales","order_zh":"龙胆目","family_en":"Rubiaceae","family_zh":"茜草科","iucn":null,"langs":48,"desc_zh":"染色茜草（学名：Rubia tinctorum），为茜草科茜草属下的一种多年生草本植物，高可达1.5米，土耳其红和茜草玫瑰红是从该植物的根提取出来的，是西方古代较常见的染料，印度摩亨朱-达罗遗址中也发现了使用这种植物染色的棉布。","desc_en":"Rubia tinctorum, the rose madder or common madder or dyer's madder, is a herbaceous perennial plant species belonging to the bedstraw and coffee family Rubiaceae. The type genus of the whole Rubiaceae family of around 80 flowering plants is called Rubia.","img":"images/725.jpg","thumb":"images/t/725.jpg","file":"Rubia tinctorum flowers.jpg","ar":0.918,"py":"ranseqiancao rsqc","cr_by":"Carstor","cr_lic":"CC BY-SA 3.0","cr_licurl":"https://creativecommons.org/licenses/by-sa/3.0","habit":"草本","origin":null},{"id":726,"zh":"中果咖啡","en":"Coffea canephora","sci":"Coffea canephora","order_en":"Gentianales","order_zh":"龙胆目","family_en":"Rubiaceae","family_zh":"茜草科","iucn":"LC","langs":45,"desc_zh":"中果咖啡（学名：Coffea canephora）又名卡尼弗拉咖啡，异名罗布斯塔咖啡，是世界咖啡生产的第二大种，它在全球咖啡产量中占了大约43%，与小果咖啡达成平衡。 中果咖啡的浆果较小果咖啡大但比大果咖啡小，比小果咖啡抗病害能力强。中果咖啡适合在海拔700公尺以下的热带气候中生长，含咖啡因浓度高，约为2%-4%，但入口有苦、烧橡胶味，主要在印度尼西亚、印度、乌干达及越南等一些热带国家种植，大部分作为即溶咖啡之用。","desc_en":"Coffea canephora (especially C. canephora subvar. robusta, syn. Coffea robusta, or commonly robusta coffee) is a species of coffee plant that has its origins in central and western sub-Saharan Africa. It is a species of flowering plant in the family Rubiaceae.","img":"images/726.jpg","thumb":"images/t/726.jpg","file":"Coffea canephora berries.JPG","ar":1.333,"py":"zhongguokafei zgkf","cr_by":"Ksd5","cr_lic":"CC0","cr_licurl":"http://creativecommons.org/publicdomain/zero/1.0/deed.en","habit":null,"origin":["非洲"]},{"id":727,"zh":"大果咖啡","en":"Coffea liberica","sci":"Coffea liberica","order_en":"Gentianales","order_zh":"龙胆目","family_en":"Rubiaceae","family_zh":"茜草科","iucn":"LC","langs":39,"desc_zh":"大果咖啡（学名：Coffea liberica）又名赖比瑞亚咖啡、利比里卡咖啡，亦称利比里亚种（Liberica），是一种抗虫害、适合高温潮湿气候的物种，其浆果和种子都要比小果咖啡大到近两倍，香味浓郁，但味淡，一般北欧人比较喜欢这种咖啡。主要在非洲利比里亚、科特迪瓦、马达加斯加种植。 高产咖啡现在被认为是大果咖啡的异名","desc_en":"Coffea liberica, commonly known as Liberian coffee, is a species of flowering plant in the family Rubiaceae from which coffee is produced. It is native to western and central Africa (from Liberia to Uganda and Angola), and has become naturalised in areas inclu…","img":"images/727.jpg","thumb":"images/t/727.jpg","file":"Coffee tree chary.jpg","ar":0.734,"py":"daguokafei dgkf","cr_by":"DXLINH","cr_lic":"CC BY-SA 3.0","cr_licurl":"https://creativecommons.org/licenses/by-sa/3.0","habit":null,"origin":["亚洲","欧洲","非洲","南美洲"]},{"id":728,"zh":"卡痛","en":"Mitragyna speciosa","sci":"Mitragyna speciosa","order_en":"Gentianales","order_zh":"龙胆目","family_en":"Rubiaceae","family_zh":"茜草科","iucn":"LC","langs":39,"desc_zh":"卡痛树（学名：Mitragyna speciosa）是一种主长于东南亚的热带多年生常绿乔本。卡痛树的叶子，卡痛叶，有类似鸦片的镇定和刺激效果。有历史记载，卡痛叶被用作民间草药和偏方，有体力劳动者会用卡痛叶提神。 2019年，美国药监局警告消费者避免摄入卡痛叶，并申明未曾准许卡痛叶的医疗使用。","desc_en":"Mitragyna speciosa is a tropical evergreen tree of the Rubiaceae family native to Southeast Asia. It is indigenous to Cambodia, Thailand, Indonesia, Malaysia, Myanmar, and Papua New Guinea, where its dark green, glossy leaves, known as kratom, have been used i…","img":"images/728.jpg","thumb":"images/t/728.jpg","file":"Mitragyna speciosa111.JPG","ar":1.333,"py":"katong kt","cr_by":"Uomo vitruviano","cr_lic":"CC BY-SA 3.0","cr_licurl":"https://creativecommons.org/licenses/by-sa/3.0","habit":"乔木","origin":["亚洲","大洋洲"]},{"id":729,"zh":"吐根","en":"Carapichea ipecacuanha","sci":"Carapichea ipecacuanha","order_en":"Gentianales","order_zh":"龙胆目","family_en":"Rubiaceae","family_zh":"茜草科","iucn":null,"langs":36,"desc_zh":null,"desc_en":"Carapichea ipecacuanha is a species of flowering plant in the family Rubiaceae. It is native to Costa Rica, Nicaragua, Panama, Colombia, and Brazil. Its common name, ipecacuanha (Portuguese pronunciation: [ipekɐkuˈɐ̃ɲɐ]), is derived from the Tupi ypekakûãîa (l…","img":"images/729.jpg","thumb":"images/t/729.jpg","file":"Psychotria ipecacuanha - Köhler–s Medizinal-Pflanzen-251.jpg","ar":0.784,"py":"tugen tg","cr_by":"Franz Eugen Köhler, Köhler's Medizinal-Pflanzen","cr_lic":"Public domain","cr_licurl":null,"habit":null,"origin":["南美洲"]},{"id":730,"zh":"沼生拉拉藤","en":"Galium palustre","sci":"Galium palustre","order_en":"Gentianales","order_zh":"龙胆目","family_en":"Rubiaceae","family_zh":"茜草科","iucn":"LC","langs":33,"desc_zh":"沼生拉拉藤（学名：Galium palustre）为茜草科拉拉藤属下的一个种。","desc_en":"Galium palustre, the common marsh bedstraw or simply marsh-bedstraw, is a herbaceous annual plant of the family Rubiaceae. This plant is widely distributed, native to virtually every country in Europe, plus Morocco, the Azores, Turkey, Turkmenistan, Western Si…","img":"images/730.jpg","thumb":"images/t/730.jpg","file":"Galium palustre.jpeg","ar":1.333,"py":"zhaoshenglalateng zsllt","cr_by":"Kristian Peters -- Fabelfroh 08:10, 20 September 2006 (UTC)","cr_lic":"CC BY-SA 3.0","cr_licurl":"http://creativecommons.org/licenses/by-sa/3.0/","habit":"草本","origin":["亚洲","欧洲","北美洲"]},{"id":731,"zh":"团花","en":"Neolamarckia cadamba","sci":"Neolamarckia cadamba","order_en":"Gentianales","order_zh":"龙胆目","family_en":"Rubiaceae","family_zh":"茜草科","iucn":null,"langs":31,"desc_zh":"团花（学名：Neolamarckia cadamba），为茜草科团花属下的一个植物种。","desc_en":"Neolamarckia cadamba, with English common names burflower-tree, laran, and Leichhardt pine, and called kadamba or kadam or cadamba locally, is an evergreen, tropical tree native to South and Southeast Asia.","img":"images/731.jpg","thumb":"images/t/731.jpg","file":"Burflower 1.jpg","ar":0.75,"py":"tuanhua th","cr_by":"This work was made by Tushar Hossain and released under the license(s) stated below. Please feel free to use it for any ","cr_lic":"CC BY-SA 4.0","cr_licurl":"https://creativecommons.org/licenses/by-sa/4.0","habit":"乔木","origin":["亚洲"]},{"id":732,"zh":"钩藤","en":"Uncaria tomentosa","sci":"Uncaria tomentosa","order_en":"Gentianales","order_zh":"龙胆目","family_en":"Rubiaceae","family_zh":"茜草科","iucn":null,"langs":30,"desc_zh":"钩藤（学名：Uncaria tomentosa，英文Cat's Claw），是一种常绿藤本植物，因为枝条上的钩形似猫爪，所以在美洲地区称为Uña de gato（意为猫爪）。高可达10m-15m。 香港的科学家叶玉如教授首先在钩藤的钩藤碱有机会舒缓阿尔茨海默症。","desc_en":"Uncaria tomentosa is a woody vine found in the tropical jungles of South and Central America. It is known as cat's claw or uña de gato in Spanish because of its claw-shaped thorns.","img":"images/732.png","thumb":"images/t/732.png","file":"Uncaria tomentosa.png","ar":0.464,"py":"gouteng gt","cr_by":"Vangeliq.petrova","cr_lic":"CC BY-SA 4.0","cr_licurl":"https://creativecommons.org/licenses/by-sa/4.0","habit":"藤本","origin":["北美洲"]},{"id":733,"zh":"心叶木","en":"Adina cordifolia","sci":"Adina cordifolia","order_en":"Gentianales","order_zh":"龙胆目","family_en":"Rubiaceae","family_zh":"茜草科","iucn":null,"langs":30,"desc_zh":"心叶木（学名：Haldina cordifolia）为茜草科心叶木属下的一个种。","desc_en":"Adina cordifolia, synonym Haldina cordifolia, is a flowering plant in the family Rubiaceae. It is native to southern Asia, from India east to China and Vietnam and south to Peninsular Malaysia.","img":"images/733.jpg","thumb":"images/t/733.jpg","file":"Adina cordifolia 7zz.jpg","ar":0.667,"py":"xinyemu xym","cr_by":"Photo by David J. Stang","cr_lic":"CC BY-SA 4.0","cr_licurl":"https://creativecommons.org/licenses/by-sa/4.0","habit":"乔木","origin":["亚洲"]},{"id":734,"zh":"夹竹桃","en":"Nerium oleander","sci":"Nerium oleander","order_en":"Gentianales","order_zh":"龙胆目","family_en":"Apocynaceae","family_zh":"夹竹桃科","iucn":"LC","langs":99,"desc_zh":"夹竹桃（学名：Nerium oleander），又名洋夹竹桃或欧洲夹竹桃，是龙胆目夹竹桃科夹竹桃属的唯一一种，为常绿灌木或小乔木，原生于地中海盆地，因为茎部像竹，花朵像桃，因而为名，也是具观赏价值的中草药。北非古城沃吕比利斯就是以洋夹竹桃的旧拉丁文名而取名的。","desc_en":"Nerium oleander ( NEER-ee-əm), commonly known as oleander, rose laurel, be-still tree or rosebay, is a shrub or small tree cultivated worldwide in temperate and subtropical areas as an ornamental and landscaping plant.","img":"images/734.jpg","thumb":"images/t/734.jpg","file":"Nerium oleander flowers leaves.jpg","ar":1.369,"py":"jiazhutao jzt","cr_by":"Alvesgaspar","cr_lic":"CC BY 2.5","cr_licurl":"https://creativecommons.org/licenses/by/2.5","habit":"乔木","origin":null},{"id":735,"zh":"长春花","en":"Catharanthus roseus","sci":"Catharanthus roseus","order_en":"Gentianales","order_zh":"龙胆目","family_en":"Apocynaceae","family_zh":"夹竹桃科","iucn":null,"langs":65,"desc_zh":"长春花（学名：Catharanthus roseus），别名日日春、日日草、日日新、三万花（广西、广东）、四时春、时钟花、雁来红（广东）、五瓣梅、王瓣梅、五合梅（潮汕）、长春海棠，是夹竹桃科长春花属植物。","desc_en":"Catharanthus roseus, commonly known as bright eyes, Cape periwinkle, graveyard plant, Madagascar periwinkle, old maid, pink periwinkle, rose periwinkle, is a perennial species of flowering plant in the family Apocynaceae.","img":"images/735.jpg","thumb":"images/t/735.jpg","file":"2019-08-02 Catharanthus roseus, Ifaty, Madagascar 2.jpg","ar":1.333,"py":"changchunhua cch","cr_by":"imbeaul","cr_lic":"CC BY 4.0","cr_licurl":"https://creativecommons.org/licenses/by/4.0","habit":"草本","origin":["非洲"]},{"id":736,"zh":"小蔓长春花","en":"Vinca minor","sci":"Vinca minor","order_en":"Gentianales","order_zh":"龙胆目","family_en":"Apocynaceae","family_zh":"夹竹桃科","iucn":null,"langs":59,"desc_zh":"小蔓长春花（学名：Vinca minor）是夹竹桃科蔓长春花属的植物。分布在欧洲以及中国大陆的江苏等地，目前尚未由人工引种栽培。 其种加词“minor”意为“较小的”。","desc_en":"Vinca minor (common names lesser periwinkle or dwarf periwinkle) is a species of flowering plant in the dogbane family, native to central and southern Europe.","img":"images/736.jpg","thumb":"images/t/736.jpg","file":"20130421Vinca minor1.jpg","ar":1.333,"py":"xiaomanchangchunhua xmcch","cr_by":"AnRo0002","cr_lic":"CC0","cr_licurl":"http://creativecommons.org/publicdomain/zero/1.0/deed.en","habit":null,"origin":["欧洲"]},{"id":737,"zh":"黑板树","en":"Alstonia scholaris","sci":"Alstonia scholaris","order_en":"Gentianales","order_zh":"龙胆目","family_en":"Apocynaceae","family_zh":"夹竹桃科","iucn":"LC","langs":47,"desc_zh":"黑板树（学名：Alstonia scholaris）又称象皮树、灯架树、糖胶树、乳木、魔神树等，为夹竹桃科鸡骨常山属的模式种。常绿大乔木，其树体高大，为具有明显主干的乔木，株高15~25公尺，树冠伞盖状，树干挺直灰褐色、枝轮生、具白色乳液。叶序为单叶轮生，小叶4~10枚，叶面深绿、叶背浅白色。花是黄白色，花冠径8~12公分。荚果褐色，长30~60公分细长圆柱形，姿态优美，且不易落叶，对环境适应力强，属于快速生长的绿化植物。","desc_en":"Alstonia scholaris, commonly called blackboard tree, scholar tree, milkwood or devil's tree in English, is an evergreen tree in the oleander and frangipani family Apocynaceae. Its natural range is from Pakistan to China, and south to northern Australia.","img":"images/737.jpg","thumb":"images/t/737.jpg","file":"Alstonia scholaris at Sungai Berang valley, Kampung Gunung 20240225 164615.jpg","ar":0.75,"py":"heibanshu hbs","cr_by":"Wiki Farazi","cr_lic":"CC0","cr_licurl":"http://creativecommons.org/publicdomain/zero/1.0/deed.en","habit":"乔木","origin":["亚洲","大洋洲"]},{"id":738,"zh":"蛇根木","en":"Rauvolfia serpentina","sci":"Rauvolfia serpentina","order_en":"Gentianales","order_zh":"龙胆目","family_en":"Apocynaceae","family_zh":"夹竹桃科","iucn":null,"langs":47,"desc_zh":"蛇根木（学名：Rauvolfia serpentina）为夹竹桃科萝芙木属的植物。分布在大洋洲、泰国、印度尼西亚、缅甸、斯里兰卡、印度以及中国的云南、广西、广东等地，目前已由人工引种栽培。","desc_en":"Rauvolfia serpentina, the Indian snakeroot, devil pepper, serpentine wood, Sarpagandha (as known locally) or Chandrika, is a species of flower in the milkweed family Apocynaceae. It is native to the Indian subcontinent and East Asia (from India to Indonesia).","img":"images/738.png","thumb":"images/t/738.png","file":"Hortus Cliffortianus Rauvolfia.png","ar":0.603,"py":"shegenmu sgm","cr_by":"Carl von Linné (1707-1778)","cr_lic":"Public domain","cr_licurl":null,"habit":"草本","origin":["亚洲"]},{"id":739,"zh":"牛角瓜","en":"Calotropis gigantea","sci":"Calotropis gigantea","order_en":"Gentianales","order_zh":"龙胆目","family_en":"Apocynaceae","family_zh":"夹竹桃科","iucn":null,"langs":45,"desc_zh":"牛角瓜（学名：Calotropis gigantea，英文名称：Akund Calotrope、Bowstring Hemp、Crownplant、Madar、Mudar），别称断肠草（广东）、五狗卧花（广东崖县）、羊浸树（云南、广东）、羊浸渣叶、哮喘树、大麻风药、奶浆包、皇冠花、紫冠花、五狗卧花心、野攀枝花及牛角瓜叶等，为夹竹桃科牛角瓜属植物，本种的模式标本采自于印度。","desc_en":"Calotropis gigantea, the crown flower, is a species of Calotropis native to India, Cambodia, Vietnam, Bangladesh, Indonesia, Malaysia, Philippines,Thailand, Sri Lanka, China, Pakistan, and Nepal. It is a large shrub growing to 4 m (13 ft) tall.","img":"images/739.jpg","thumb":"images/t/739.jpg","file":"(Arya) Calotropis gigantea flower Pilangsari 2019.jpg","ar":1.333,"py":"niujiaogua njg","cr_by":"Aris riyanto","cr_lic":"CC BY-SA 4.0","cr_licurl":"https://creativecommons.org/licenses/by-sa/4.0","habit":"灌木","origin":["亚洲"]},{"id":740,"zh":"黄花夹竹桃","en":"Cascabela thevetia","sci":"Cascabela thevetia","order_en":"Gentianales","order_zh":"龙胆目","family_en":"Apocynaceae","family_zh":"夹竹桃科","iucn":"LC","langs":41,"desc_zh":"黄花夹竹桃（学名：Thevetia peruviana），亦称黄酒杯花，夹竹桃科黄花夹竹桃属，常见灌木或小乔木。其种加词“peruviana”意为“秘鲁的”。","desc_en":"Cascabela thevetia (syn. Thevetia peruviana) is a species of poisonous plant in the dogbane family Apocynaceae, native throughout Mexico and Central America and cultivated widely as an ornamental.","img":"images/740.jpg","thumb":"images/t/740.jpg","file":"Yellow Oleander (Thevetia peruviana) leaves & flowers in Kolkata W IMG 8008.jpg","ar":1.032,"py":"huanghuajiazhutao hhjzt","cr_by":"J.M.Garg","cr_lic":"CC BY-SA 3.0","cr_licurl":"https://creativecommons.org/licenses/by-sa/3.0","habit":null,"origin":["北美洲"]},{"id":741,"zh":"球兰","en":"Hoya carnosa","sci":"Hoya carnosa","order_en":"Gentianales","order_zh":"龙胆目","family_en":"Apocynaceae","family_zh":"夹竹桃科","iucn":null,"langs":40,"desc_zh":"球兰（学名：Hoya carnosa）是夹竹桃科萝藦亚科球兰属的植物。虽名称中有「兰」，但与一般常见的兰花不同科。","desc_en":"Hoya carnosa, the porcelain flower or wax plant, is a species of flowering plant in the family Apocynaceae, native to East Asia. It is a common house plant grown for its attractive waxy foliage, and sweetly scented flowers.","img":"images/741.jpg","thumb":"images/t/741.jpg","file":"NKN-2007-06-13 114250 Hoya Carnosa (Yvan Leduc author for Wikipedia).jpg","ar":1.504,"py":"qiulan ql","cr_by":"Yvan leduc","cr_lic":"CC BY-SA 3.0","cr_licurl":"https://creativecommons.org/licenses/by-sa/3.0","habit":null,"origin":["亚洲"]},{"id":742,"zh":"蔓长春花","en":"Vinca major","sci":"Vinca major","order_en":"Gentianales","order_zh":"龙胆目","family_en":"Apocynaceae","family_zh":"夹竹桃科","iucn":null,"langs":40,"desc_zh":"蔓长春花（学名：Vinca major）为夹竹桃科蔓长春花属的植物，又称攀缠长春花（江苏南部种子植物手册）。分布于台湾本岛、欧洲以及中国大陆的浙江、江苏等地，目前已由人工引种栽培。","desc_en":"Vinca major, with the common names bigleaf periwinkle, large periwinkle, greater periwinkle and blue periwinkle, is a species of flowering plant in the family Apocynaceae, native to the western Mediterranean.","img":"images/742.jpg","thumb":"images/t/742.jpg","file":"Vinca major - Flower and bud.jpg","ar":0.614,"py":"manchangchunhua mcch","cr_by":"Didier Descouens","cr_lic":"CC BY-SA 4.0","cr_licurl":"https://creativecommons.org/licenses/by-sa/4.0","habit":"草本","origin":["欧洲"]},{"id":743,"zh":"刺黄果","en":"Carissa carandas","sci":"Carissa carandas","order_en":"Gentianales","order_zh":"龙胆目","family_en":"Apocynaceae","family_zh":"夹竹桃科","iucn":null,"langs":40,"desc_zh":"刺黄果（学名：Carissa carandas）是夹竹桃科假虎刺属的植物。原产于印度．斯里兰卡等热带地区 又名小卡利撒、彩虹樱桃、红彩果等等 。","desc_en":"Carissa carandas is a species of flowering shrub in the family Apocynaceae. It produces berry-sized fruits that are commonly used as a condiment in Indian pickles and spices. The fruit is black and tastes sweet or sour depending on the plant.","img":"images/743.jpg","thumb":"images/t/743.jpg","file":"Carissa carandas flowers.JPG","ar":1.333,"py":"cihuangguo chg","cr_by":"Sakurai Midori","cr_lic":"CC BY-SA 3.0","cr_licurl":"https://creativecommons.org/licenses/by-sa/3.0","habit":"灌木","origin":["亚洲"]},{"id":744,"zh":"红色百金花","en":"Centaurium erythraea","sci":"Centaurium erythraea","order_en":"Gentianales","order_zh":"龙胆目","family_en":"Gentianaceae","family_zh":"龙胆科","iucn":"LC","langs":56,"desc_zh":"日本鬼灯檠（学名：Centaurium erythraea），或称红百金花、苦护胆与矢车菊，是一种植物，常被用来当作药草，晒干之后可以制成药草茶，而日本鬼灯檠制作的药草茶，有著治疗肝及肾方面毛病的妙用，并具有调理血压的效果。除此之外，将磨碎的日本鬼灯檠涂在伤口上，也可以止痛，是一种效用十分广泛的药用植物。","desc_en":"Centaurium erythraea is a species of flowering plant in the gentian family known by the names common centaury and European centaury. It is also commonly known as feverfoullie, gentian or centaury.","img":"images/744.jpg","thumb":"images/t/744.jpg","file":"Centaurium erythraea (flowers).jpg","ar":1.333,"py":"hongsebaijinhua hsbjh","cr_by":"Hans Hillewaert","cr_lic":"CC BY-SA 3.0","cr_licurl":"https://creativecommons.org/licenses/by-sa/3.0","habit":null,"origin":["欧洲"]},{"id":745,"zh":"黄龙胆","en":"Gentiana lutea","sci":"Gentiana lutea","order_en":"Gentianales","order_zh":"龙胆目","family_en":"Gentianaceae","family_zh":"龙胆科","iucn":null,"langs":52,"desc_zh":"黄龙胆（学名：Gentiana lutea）是原产于中欧和南欧山区的一种龙胆科植物。","desc_en":"Gentiana lutea, the great yellow gentian, is a species of gentian native to the mountains of central and southern Europe, including the Alps, the Carpathians (where scarce), the Pyrenees, the Apennines, and the mountains of the Balkan Peninsula.","img":"images/745.jpg","thumb":"images/t/745.jpg","file":"Gentiana lutea 230705.jpg","ar":0.752,"py":"huanglongdan hld","cr_by":"Bernd Haynold","cr_lic":"CC BY-SA 2.5","cr_licurl":"https://creativecommons.org/licenses/by-sa/2.5","habit":null,"origin":["欧洲"]},{"id":746,"zh":"春花龙胆","en":"Gentiana verna","sci":"Gentiana verna","order_en":"Gentianales","order_zh":"龙胆目","family_en":"Gentianaceae","family_zh":"龙胆科","iucn":null,"langs":36,"desc_zh":"春花龙胆（Gentiana verna）是龙胆属的一种低矮草本植物，春末夏初开蓝色花，偶尔开粉红或白色花，花朵五瓣，直径1-2厘米。广泛分布于亚洲大陆北部和欧洲大陆、英国和爱尔兰，海拔可达2,600米（8,500英尺）。","desc_en":"Gentiana verna, the spring gentian, is a species of flowering plant in the family Gentianaceae, and one of its smallest members, normally only growing to a height of a few centimetres.","img":"images/746.jpg","thumb":"images/t/746.jpg","file":"Gentiana verna (1).JPG","ar":0.8,"py":"chunhualongdan chld","cr_by":"Philipp Weigell","cr_lic":"CC BY 3.0","cr_licurl":"https://creativecommons.org/licenses/by/3.0","habit":null,"origin":null},{"id":747,"zh":"蓝色龙胆","en":"Gentiana pneumonanthe","sci":"Gentiana pneumonanthe","order_en":"Gentianales","order_zh":"龙胆目","family_en":"Gentianaceae","family_zh":"龙胆科","iucn":null,"langs":36,"desc_zh":null,"desc_en":"Gentiana pneumonanthe, the marsh gentian, is a species of the genus Gentiana. It was the first wildflower announced as flower of the year in Germany in 1980. The species can be found in marshes and moorlands.","img":"images/747.jpg","thumb":"images/t/747.jpg","file":"Gentiana pneumonanthe 130805a.jpg","ar":0.67,"py":"lanselongdan lsld","cr_by":"Bernd Haynold","cr_lic":"CC BY-SA 2.5","cr_licurl":"https://creativecommons.org/licenses/by-sa/2.5","habit":null,"origin":null},{"id":748,"zh":"无茎龙胆","en":"Gentiana acaulis","sci":"Gentiana acaulis","order_en":"Gentianales","order_zh":"龙胆目","family_en":"Gentianaceae","family_zh":"龙胆科","iucn":"LC","langs":36,"desc_zh":null,"desc_en":"Gentiana acaulis, the stemless gentian, or trumpet gentian, is a species of flowering plant in the family Gentianaceae, native to central and southern Europe, from Spain east to the Balkans, growing especially in mountainous regions, such as the Alps and Pyren…","img":"images/748.jpg","thumb":"images/t/748.jpg","file":"GentianaAcaulisRannoch.jpg","ar":0.657,"py":"wujinglongdan wjld","cr_by":null,"cr_lic":"CC BY-SA 3.0","cr_licurl":"http://creativecommons.org/licenses/by-sa/3.0/","habit":null,"origin":["欧洲"]},{"id":749,"zh":"马钱子","en":"Strychnos nux-vomica","sci":"Strychnos nux-vomica","order_en":"Gentianales","order_zh":"龙胆目","family_en":"Loganiaceae","family_zh":"马钱科","iucn":null,"langs":52,"desc_zh":"马钱子（学名：Strychnos nux-vomica）也称番木鳖、苦实把豆儿、火失刻把都、苦实、马前、牛眼、大方八、马钱树，是马钱科马钱属的一种落叶乔木。产于南亚和东南亚等地，喜热带湿润性气候，怕霜冻。模式标本采自斯里兰卡科伦坡。种子有毒，主要含有马钱子碱（strychnine，又名番木鳖碱）等多种生物碱。西医学上用种子提取物作中枢神经兴奋剂。中医学上以种子泡制后入药，有通络散结、消肿止痛之效。","desc_en":"Strychnos nux-vomica, the strychnine tree, also known as nux vomica, poison fruit, semen strychnos, and quaker buttons, is a deciduous tree native to India and to southeast Asia. It is a medium-sized tree in the family Loganiaceae that grows in open habitats.","img":"images/749.jpg","thumb":"images/t/749.jpg","file":"Strychnos nux-vomica - Köhler–s Medizinal-Pflanzen-266.jpg","ar":0.741,"py":"maqianzi mqz","cr_by":"Franz Eugen Köhler","cr_lic":"Public domain","cr_licurl":null,"habit":"乔木","origin":["亚洲"]},{"id":750,"zh":"琉璃苣","en":"borage","sci":"Borago officinalis","order_en":"Boraginales","order_zh":"紫草目","family_en":"Boraginaceae","family_zh":"紫草科","iucn":null,"langs":80,"desc_zh":"琉璃苣（学名：Borago officinalis）是一种一年生草本植物，原产于叙利亚，目前已经被广泛引种到欧洲、西亚、北非和南美洲等地。 琉璃苣株高一般为60-100厘米，叶互生粗糙，有柄，5-10厘米长，叶和茎上都有毛刺；花的花瓣5裂，通常为蓝色，但也有粉色或白色的变种，为疏散的聚伞花序，同株异花授粉，夏季开花，但在气候温暖适宜的地区可全年开花；果实为小坚果。 琉璃苣的花语：「勇气」。","desc_en":"Borage ( or ; Borago officinalis), also known as starflower, is an annual herb in the flowering plant family Boraginaceae native to the Mediterranean region.","img":"images/750.jpg","thumb":"images/t/750.jpg","file":"00 2100 Borretsch (Borago officinalis).jpg","ar":0.78,"py":"liuliju llj","cr_by":"W. Bulach","cr_lic":"CC BY-SA 4.0","cr_licurl":"https://creativecommons.org/licenses/by-sa/4.0","habit":"草本","origin":["欧洲"]},{"id":751,"zh":"聚合草","en":"Symphytum officinale","sci":"Symphytum officinale","order_en":"Boraginales","order_zh":"紫草目","family_en":"Boraginaceae","family_zh":"紫草科","iucn":null,"langs":59,"desc_zh":"聚合草（学名：Symphytum officinale）为紫草科聚合草属的植物。分布在俄罗斯以及中国大陆的 福建省、 四川省、 中国、 湖北省、江苏省等地，目前已由人工引种栽培。 花语为“寂静”。为多年生草本，高60~90公分，有香气。有补血、止泻之效。主治高血压、出血、止痢等，并有防癌、抗癌作用。","desc_en":"Symphytum officinale is a perennial flowering plant in the family Boraginaceae. Along with thirty four other species of Symphytum, it is known as comfrey (from the Latin confervere to 'heal' or literally to 'boil together', referring to uses in ancient traditi…","img":"images/751.jpg","thumb":"images/t/751.jpg","file":"Symphytum officinale 01.jpg","ar":0.75,"py":"juhecao jhc","cr_by":"Agnieszka Kwiecień ( Nova )","cr_lic":"CC BY 2.5","cr_licurl":"https://creativecommons.org/licenses/by/2.5","habit":"草本","origin":["欧洲","北美洲"]},{"id":752,"zh":"蓝蓟","en":"Echium vulgare","sci":"Echium vulgare","order_en":"Boraginales","order_zh":"紫草目","family_en":"Boraginaceae","family_zh":"紫草科","iucn":null,"langs":55,"desc_zh":"蓝蓟（学名：Echium vulgare）为紫草科蓝蓟属下的一个种。","desc_en":"Echium vulgare, known as viper's bugloss and blueweed, is a species of flowering plant in the borage family Boraginaceae. It is native to most of Europe and western and central Asia and it occurs as an introduced species in north-eastern North America, south-w…","img":"images/752.jpg","thumb":"images/t/752.jpg","file":"Dettaglio - Borraginaceae Echium vulgare Lin. Erbario Frizzi Perugia n. 731.jpg","ar":0.75,"py":"lanji lj","cr_by":"Giuseppe Frizzi","cr_lic":"Public domain","cr_licurl":null,"habit":null,"origin":["亚洲","欧洲","北美洲","南美洲","大洋洲"]},{"id":753,"zh":"沼泽勿忘草","en":"Myosotis scorpioides","sci":"Myosotis scorpioides","order_en":"Boraginales","order_zh":"紫草目","family_en":"Boraginaceae","family_zh":"紫草科","iucn":null,"langs":46,"desc_zh":"沼泽勿忘草（学名：Myosotis scorpioides）是紫草科勿忘草属多年生草本植物，原产欧洲、西亚、中亚、北亚，在美洲部分地区归化，常生于浅水或湿草地。","desc_en":"Myosotis scorpioides (syn. Myosotis palustris), the true forget-me-not or water forget-me-not, is a forget-me-not plant species in the borage family, Boraginaceae.","img":"images/753.jpg","thumb":"images/t/753.jpg","file":"Myosotis scorpioides - Niitvälja bog.jpg","ar":0.8,"py":"zhaozewuwangcao zzwwc","cr_by":"Ivar Leidus","cr_lic":"CC BY-SA 4.0","cr_licurl":"https://creativecommons.org/licenses/by-sa/4.0","habit":null,"origin":null},{"id":754,"zh":"蓝花肺草","en":"Pulmonaria officinalis","sci":"Pulmonaria officinalis","order_en":"Boraginales","order_zh":"紫草目","family_en":"Boraginaceae","family_zh":"紫草科","iucn":"LC","langs":46,"desc_zh":null,"desc_en":"Pulmonaria officinalis, common names lungwort, common lungwort, Mary's tears or Our Lady's milk drops, is a herbaceous rhizomatous evergreen perennial plant of the genus Pulmonaria, belonging to the family Boraginaceae.","img":"images/754.jpg","thumb":"images/t/754.jpg","file":"Pulmonaria officinalis 800.jpg","ar":0.844,"py":"lanhuafeicao lhfc","cr_by":null,"cr_lic":"CC BY-SA 3.0","cr_licurl":"http://creativecommons.org/licenses/by-sa/3.0/","habit":"草本","origin":null},{"id":755,"zh":"森林勿忘草","en":"Myosotis sylvatica","sci":"Myosotis sylvatica","order_en":"Boraginales","order_zh":"紫草目","family_en":"Boraginaceae","family_zh":"紫草科","iucn":null,"langs":44,"desc_zh":"森林勿忘草（学名：Myosotis sylvatica），又名森林勿忘我（英语：wood forget-me-not）、林地勿忘我（英语：woodland forget-me-not）、花园勿忘我（英语：garden forget-me-not），是紫草科勿忘草属二年生或多年生草本植物。","desc_en":"Myosotis sylvatica, the wood forget-me-not or woodland forget-me-not, is a species of flowering plant in the family Boraginaceae, native to Europe. This spring-flowering plant and its cultivars, typically with blue flowers, are the familiar forget-me-nots of g…","img":"images/755.jpg","thumb":"images/t/755.jpg","file":"Myosotis sylvatica (aka).jpg","ar":1.342,"py":"senlinwuwangcao slwwc","cr_by":"André Karwath aka Aka","cr_lic":"CC BY-SA 2.5","cr_licurl":"https://creativecommons.org/licenses/by-sa/2.5","habit":null,"origin":["欧洲"]},{"id":756,"zh":"药用牛舌草","en":"common bugloss","sci":"Anchusa officinalis","order_en":"Boraginales","order_zh":"紫草目","family_en":"Boraginaceae","family_zh":"紫草科","iucn":null,"langs":41,"desc_zh":"药用牛舌草（学名：Anchusa officinalis）是紫草科牛舌草属的植物。分布于欧洲等地，属中国原产的植物（非从国外引种）。","desc_en":"Anchusa officinalis, also knowns as common bugloss or common alkanet, is a species of flowering plant in the borage family. It is native to Europe and small parts of western Asia, but has been escaped from cultivation to grow in additional locations in Europe…","img":"images/756.jpg","thumb":"images/t/756.jpg","file":"Anchusa officinalis1.jpg","ar":0.75,"py":"yaoyongniushecao yynsc","cr_by":null,"cr_lic":"CC BY-SA 3.0","cr_licurl":"http://creativecommons.org/licenses/by-sa/3.0/","habit":null,"origin":["亚洲","欧洲"]},{"id":757,"zh":"番茄","en":"tomato","sci":"Solanum lycopersicum","order_en":"Solanales","order_zh":"茄目","family_en":"Solanaceae","family_zh":"茄科","iucn":null,"langs":208,"desc_zh":"番茄（学名：Solanum lycopersicum）是茄科茄属的一种植物。番茄原产于中美洲和南美洲，现作为食用蔬果已被全球广泛种植，同时具医疗效用，是茄科开花植物的模型生物之一。","desc_en":"The tomato (US: , UK: ; Solanum lycopersicum) is a plant whose fruit is an edible berry that is eaten as a vegetable. The tomato is a member of the nightshade family that includes tobacco, potato, and chili peppers.","img":"images/757.jpg","thumb":"images/t/757.jpg","file":"Bright red tomato and cross section02.jpg","ar":1.499,"py":"fanqie fq","cr_by":"fir0002 flagstaffotos [at] gmail.com Canon 20D + Sigma 150mm f/2.8","cr_lic":"GFDL 1.2","cr_licurl":"http://www.gnu.org/licenses/old-licenses/fdl-1.2.html","habit":"草本","origin":["北美洲","南美洲"]},{"id":758,"zh":"马铃薯","en":"potato","sci":"Solanum tuberosum","order_en":"Solanales","order_zh":"茄目","family_en":"Solanaceae","family_zh":"茄科","iucn":null,"langs":197,"desc_zh":"马铃薯（学名：Solanum tuberosum），属茄科茄属多年生草本植物，块茎可供食用，是全球第四大重要的粮食作物，仅次于稻米、玉米和小麦。原产于南美洲秘鲁与玻利维亚境内的安地斯山脉。马铃薯的人工栽培最早可追溯到大约公元前8000年到公元前5000年的秘鲁南部地区。大航海时代马铃薯与其他物种被装船带回欧亚大陆的菜单当中，现在是欧美地区许多国家的主食。","desc_en":"The potato () is a starchy tuberous vegetable native to the Americas that is consumed as a staple food in many parts of the world. Potatoes are underground stem tubers of the plant Solanum tuberosum, a perennial in the nightshade family Solanaceae.","img":"images/758.jpg","thumb":"images/t/758.jpg","file":"234 Solanum tuberosum L.jpg","ar":0.666,"py":"malingshu mls","cr_by":"Amédée Masclef","cr_lic":"Public domain","cr_licurl":null,"habit":"草本","origin":null},{"id":759,"zh":"茄","en":"Solanum melongena","sci":"Solanum melongena","order_en":"Solanales","order_zh":"茄目","family_en":"Solanaceae","family_zh":"茄科","iucn":null,"langs":170,"desc_zh":"茄（学名：Solanum melongena），官话、晋语、湘语多称茄子，粤语多称矮瓜，客语有叫吊菜，吴语、徽语有叫落苏，闽南语有叫红菜，闽东语称作紫菜或茄囝，潮州话叫力苏，新竹人特别称之昭惟。茄子是茄科茄属的一年生草本植物，部分热带品系为多年生，其结出的果实可食用，颜色多为紫色或紫黑色，也有淡绿色或白色品种，形状上也有长条形、圆形、椭圆、梨形等各种。根据品种的不同，食用方法多样。","desc_en":"Eggplant (in North American, Australian, and Philippine English), aubergine (in British, Irish, and New Zealand English), brinjal (in Indian, Bangladeshi, Pakistani, Singapore, Malaysian, South African, and Sri Lankan English), or baigan (in Caribbean English)…","img":"images/759.jpg","thumb":"images/t/759.jpg","file":"Solanum melongena 24 08 2012 (1).JPG","ar":0.916,"py":"qie q","cr_by":"Joydeep","cr_lic":"CC BY-SA 3.0","cr_licurl":"https://creativecommons.org/licenses/by-sa/3.0","habit":null,"origin":["亚洲","非洲","北美洲","大洋洲"]},{"id":760,"zh":"辣椒","en":"Capsicum annuum","sci":"Capsicum annuum","order_en":"Solanales","order_zh":"茄目","family_en":"Solanaceae","family_zh":"茄科","iucn":"LC","langs":91,"desc_zh":"一年生辣椒（学名：Capsicum annuum），即普通辣椒，是一种原产于美洲中部的辣椒属植物物种。该物种是辣椒属五个栽培种之中，被最为广泛种植的辣椒物种。1900万年前，番茄和辣椒有共同的祖先，后驯化栽培成为全球性最大宗也最广泛的经济种。","desc_en":"Capsicum annuum is a flowering plant in the family Solanaceae (nightshades), native to the northern regions of South America and to southwestern North America.","img":"images/760.jpg","thumb":"images/t/760.jpg","file":"Capsicum annuum - Köhler–s Medizinal-Pflanzen-027.jpg","ar":0.808,"py":"lajiao lj","cr_by":"Franz Eugen Köhler, Köhler's Medizinal-Pflanzen","cr_lic":"Public domain","cr_licurl":null,"habit":null,"origin":["北美洲","南美洲"]},{"id":761,"zh":"龙葵","en":"Solanum nigrum","sci":"Solanum nigrum","order_en":"Solanales","order_zh":"茄目","family_en":"Solanaceae","family_zh":"茄科","iucn":null,"langs":91,"desc_zh":"龙葵（学名：Solanum nigrum），又称黑珠仔菜、乌甜仔菜、乌籽菜、天茄子、天星星(东北)、烟李、烟李子（临沂）、牛酸浆、乌甜菜、大头根（阿美族语：Tatokem）、Wasiq（泰雅语）、Samechi（排湾语），是茄科茄属植物，因果实成熟时乌黑如龙的眼珠而得名。 外型与光果龙葵非常相似。","desc_en":"Solanum nigrum, the European black nightshade or simply black nightshade or blackberry nightshade, is a species of flowering plant in the family Solanaceae, native to Eurasia and introduced in the Americas, Australasia, and South Africa.","img":"images/761.jpg","thumb":"images/t/761.jpg","file":"Dettaglio - Solanaceae Solanum nigrum Lin. Erbario Frizzi Perugia n. 734.jpg","ar":0.556,"py":"longkui lk","cr_by":"Giuseppe Frizzi","cr_lic":"Public domain","cr_licurl":null,"habit":null,"origin":["亚洲","非洲"]},{"id":762,"zh":"曼陀罗","en":"Datura stramonium","sci":"Datura stramonium","order_en":"Solanales","order_zh":"茄目","family_en":"Solanaceae","family_zh":"茄科","iucn":null,"langs":88,"desc_zh":"曼陀罗（学名：Datura stramonium；英语：thorn apple）即紫花曼陀罗是茄科类曼陀罗属植物，俗名醉心花、狗核桃、醉仙桃、疯茄儿、南洋金花、山茄子、凤茄花、朝鲜牵牛花。几个世纪以来，曼陀罗被用作中医草药，以缓解哮喘症状和作为手术或接骨止痛剂，也是强力迷幻剂和谵妄剂。","desc_en":"Datura stramonium, known by the common names thornapple, jimsonweed (jimson weed), or devil's trumpet, is a poisonous flowering plant in the Daturae tribe of the nightshade family Solanaceae.","img":"images/762.jpg","thumb":"images/t/762.jpg","file":"Datura stramonium - Köhler–s Medizinal-Pflanzen-051.jpg","ar":0.793,"py":"mantuoluo mtl","cr_by":"Franz Eugen Köhler, Köhler's Medizinal-Pflanzen","cr_lic":"Public domain","cr_licurl":null,"habit":null,"origin":["北美洲"]},{"id":763,"zh":"颠茄","en":"Atropa bella-donna","sci":"Atropa bella-donna","order_en":"Solanales","order_zh":"茄目","family_en":"Solanaceae","family_zh":"茄科","iucn":null,"langs":84,"desc_zh":"颠茄（学名：Atropa belladonna；英语：belladonna，deadly nightshade）是一种茄科草本植物。 原产于西欧的多年生草本植物，后来移植到北非、西亚、北美等地，中国也有引进栽培。原产地为山地背阴潮湿地带，在富含石灰质的土壤中群生。 初春发芽，全长40-50厘米，最高可达5米。","desc_en":"Atropa bella-donna, commonly known as deadly nightshade or belladonna, is a toxic perennial herbaceous plant in the nightshade family Solanaceae, which also includes tomatoes, potatoes and eggplant.","img":"images/763.jpg","thumb":"images/t/763.jpg","file":"Atropa belladonna 003.JPG","ar":0.75,"py":"dianqie dq","cr_by":"H. Zell","cr_lic":"CC BY-SA 3.0","cr_licurl":"https://creativecommons.org/licenses/by-sa/3.0","habit":"草本","origin":["亚洲","欧洲"]},{"id":764,"zh":"天仙子","en":"Hyoscyamus niger","sci":"Hyoscyamus niger","order_en":"Solanales","order_zh":"茄目","family_en":"Solanaceae","family_zh":"茄科","iucn":null,"langs":80,"desc_zh":"天仙子（学名：Hyoscyamus niger）又名莨菪，旧称菲沃斯，为茄科植物。其种加词“niger”意为“黑色的”。","desc_en":"Henbane (Hyoscyamus niger, also black henbane and stinking nightshade) is a poisonous plant belonging to tribe Hyoscyameae of the nightshade family Solanaceae. Henbane is native to temperate Europe and Siberia, and naturalised in Great Britain and Ireland.","img":"images/764.jpg","thumb":"images/t/764.jpg","file":"Henbane1.JPG","ar":1.385,"py":"tianxianzi txz","cr_by":"Chilepine ( talk · contribs )","cr_lic":"Public domain","cr_licurl":null,"habit":null,"origin":["亚洲","欧洲"]},{"id":765,"zh":"烟草","en":"Nicotiana tabacum","sci":"Nicotiana tabacum","order_en":"Solanales","order_zh":"茄目","family_en":"Solanaceae","family_zh":"茄科","iucn":null,"langs":68,"desc_zh":"烟草（学名：Nicotiana tabacum）又称普通烟草，为茄科烟草属下的一个种，是人类生产香烟的主要种植型烟草作物或栽培烟草（cultivated tobacco）。","desc_en":"Nicotiana tabacum, or cultivated tobacco, is an annually grown herbaceous plant of the genus Nicotiana. N. tabacum is the most commonly grown species in the genus Nicotiana, as the plant's leaves are commercially harvested to be processed into tobacco for huma…","img":"images/765.jpg","thumb":"images/t/765.jpg","file":"Tabak P9290021.JPG","ar":0.748,"py":"yancao yc","cr_by":"Jom / Joachim Müllerchen","cr_lic":"CC BY 2.5","cr_licurl":"https://creativecommons.org/licenses/by/2.5","habit":"草本","origin":["南美洲"]},{"id":766,"zh":"灯笼果","en":"Physalis peruviana","sci":"Physalis peruviana","order_en":"Solanales","order_zh":"茄目","family_en":"Solanaceae","family_zh":"茄科","iucn":null,"langs":59,"desc_zh":"灯笼果（学名：Physalis peruviana），又称姑娘果、菇娘儿、锦灯笼、秘鲁苦蘵，是茄科灯笼果属的一种多年生草本植物，其种加词“peruviana”意为“秘鲁的”。植株高0.5-2.0米。果子是一个套着灯笼型荚子的小圆果，比拇指大一点，里面有很多小籽。成熟的果实是亮黄色，味道酸甜，可生食，也可以用来烤果饼、做果酱。 灯笼果原产秘鲁和智利，但是并不是什么重要的产品。当地人随便吃一点，偶尔也在菜市场看到。","desc_en":"Physalis peruviana is a species of plant in the nightshade family (Solanaceae) native to Chile and Peru. Within that region, it is called aguaymanto, uvilla or uchuva, in addition to numerous indigenous and regional names.","img":"images/766.jpg","thumb":"images/t/766.jpg","file":"Cape gooseberry bunch in hand.jpg","ar":0.75,"py":"denglongguo dlg","cr_by":"In Transit","cr_lic":"CC BY 4.0","cr_licurl":"https://creativecommons.org/licenses/by/4.0","habit":null,"origin":["南美洲"]},{"id":767,"zh":"欧白英","en":"Solanum dulcamara","sci":"Solanum dulcamara","order_en":"Solanales","order_zh":"茄目","family_en":"Solanaceae","family_zh":"茄科","iucn":null,"langs":58,"desc_zh":"欧白英（学名：Solanum dulcamara），为茄科茄属下的一个种。","desc_en":"Solanum dulcamara is a species of vine in the genus Solanum (which also includes the potato and the tomato) of the family Solanaceae. Common names include bittersweet, bittersweet nightshade, bitter nightshade, blue bindweed, Amara Dulcis, climbing nightshade,…","img":"images/767.jpg","thumb":"images/t/767.jpg","file":"Dettaglio - Solanaceae Solanum dulcamara Lin. Erbario Frizzi Perugia n. 551.jpg","ar":0.619,"py":"oubaiying oby","cr_by":"Giuseppe Frizzi","cr_lic":"Public domain","cr_licurl":null,"habit":"藤本","origin":["亚洲","欧洲","北美洲"]},{"id":768,"zh":"假叶树","en":"Ruscus aculeatus","sci":"Ruscus aculeatus","order_en":"Solanales","order_zh":"茄目","family_en":"Solanaceae","family_zh":"茄科","iucn":null,"langs":56,"desc_zh":"假叶树（学名：Ruscus aculeatus），又名百劳金雀花、瓜子松。原产于地中海沿岸。","desc_en":"Ruscus aculeatus, known as butcher's-broom, is a low evergreen dioecious Eurasian shrub, with flat shoots known as cladodes that give the appearance of stiff, spine-tipped leaves.","img":"images/768.jpg","thumb":"images/t/768.jpg","file":"Illustration Ruscus aculeatus0.jpg","ar":0.625,"py":"jiayeshu jys","cr_by":null,"cr_lic":"Public domain","cr_licurl":null,"habit":"灌木","origin":["亚洲","非洲"]},{"id":769,"zh":"黄花烟草","en":"Nicotiana rustica","sci":"Nicotiana rustica","order_en":"Solanales","order_zh":"茄目","family_en":"Solanaceae","family_zh":"茄科","iucn":null,"langs":53,"desc_zh":"黄花烟草（学名：Nicotiana rustica）为茄科烟草属下的一个种。 越南农民称为「老挝烟」（越南语：Thuốc lào/药老）。具有单胺氧化酶蓬生物碱和非常高的烟碱含量（约9倍烟草，这是含有约1-3％的烟碱正常烟叶，这里作为黄花烟草具有约9％）。 20世纪30年代从苏联传入了新疆，在绥定县、伊宁县等地种植，生产莫合烟。“莫合烟”是俄语“玛合勒嘎”的音译。","desc_en":"Nicotiana rustica, commonly known as Aztec tobacco or strong tobacco, known to the Powhatan people as Apooke, is a rainforest plant in the family Solanaceae native to South America.","img":"images/769.jpg","thumb":"images/t/769.jpg","file":"Dettaglio - Solanaceae Nicotiana rustica Lin. Erbario Frizzi Perugia n. 83.jpg","ar":0.547,"py":"huanghuayancao hhyc","cr_by":"Giuseppe Frizzi","cr_lic":"Public domain","cr_licurl":null,"habit":null,"origin":["南美洲"]},{"id":770,"zh":"番薯","en":"sweet potato","sci":"Ipomoea batatas","order_en":"Solanales","order_zh":"茄目","family_en":"Convolvulaceae","family_zh":"旋花科","iucn":"DD","langs":152,"desc_zh":"番薯（学名：Ipomoea batatas），亦称地瓜、甘薯、甜薯、番芋、苕（sháo）等，为旋花科番薯属的一种常见一年生或多年生植物。 番薯原产于南美洲的热带地区，哥伦布大交换后传播到欧洲，又通过殖民等路径传入世界各地。 番薯的地下块根硕大、味甜、富含淀粉，在历史上常扮演救济饥荒、提供粮食安全的角色，是世界主要主食作物之一。“番薯”一词也单指其块根，根据皮、肉颜色可称红薯（红苕、朱薯）、紫薯、白薯等。番薯的嫩茎叶也可作蔬菜食用。","desc_en":"The sweet potato or sweetpotato (Ipomoea batatas) is a dicotyledonous plant in the morning glory family, Convolvulaceae. Its sizeable, starchy, sweet-tasting tuberous roots are used as a root vegetable, which is a staple food in parts of the world.","img":"images/770.jpg","thumb":"images/t/770.jpg","file":"Ipomoea batatas 006.JPG","ar":1.332,"py":"fanshu fs","cr_by":"Llez","cr_lic":"CC BY-SA 3.0","cr_licurl":"https://creativecommons.org/licenses/by-sa/3.0","habit":null,"origin":["南美洲"]},{"id":771,"zh":"蕹菜","en":"water spinach","sci":"Ipomoea aquatica","order_en":"Solanales","order_zh":"茄目","family_en":"Convolvulaceae","family_zh":"旋花科","iucn":"LC","langs":76,"desc_zh":"蕹（wèng）菜（学名：Ipomoea aquatica），又称空心菜、空芯菜、通菜、壅（yōng）菜、瓮菜、应菜、藤菜及葛菜，为一年生草本植物，茎蔓性，中空，节上能生不定根。蕹菜原产于东南亚。","desc_en":"Ipomoea aquatica, commonly known as water spinach or kangkung, is a semi-aquatic, tropical plant grown as a vegetable for its tender shoots. I. aquatica is generally believed to have been first domesticated in Southeast Asia.","img":"images/771.jpg","thumb":"images/t/771.jpg","file":"N Ipoa D1600.JPG","ar":1.333,"py":"wengcai wc","cr_by":"Eric Guinther","cr_lic":"CC BY-SA 3.0","cr_licurl":"http://creativecommons.org/licenses/by-sa/3.0/","habit":null,"origin":["亚洲"]},{"id":772,"zh":"田旋花","en":"Convolvulus arvensis","sci":"Convolvulus arvensis","order_en":"Solanales","order_zh":"茄目","family_en":"Convolvulaceae","family_zh":"旋花科","iucn":null,"langs":71,"desc_zh":"田旋花（学名：Convolvulus arvensis）是旋花科旋花属的一个物种，分布在欧洲和亚洲。","desc_en":"Convolvulus arvensis, or field bindweed, is a species of bindweed in the Convolvulaceae native to Europe and Asia. It is a rhizomatous and climbing or creeping herbaceous perennial plant with stems growing to 0.5–2 metres (1.6–6.6 ft) in length.","img":"images/772.jpg","thumb":"images/t/772.jpg","file":"00 2050 Ackerwinde (Convolvulus arvensis).jpg","ar":0.75,"py":"tianxuanhua txh","cr_by":"W. Bulach","cr_lic":"CC BY-SA 4.0","cr_licurl":"https://creativecommons.org/licenses/by-sa/4.0","habit":"藤本","origin":["亚洲","欧洲"]},{"id":773,"zh":"旋花","en":"Calystegia sepium","sci":"Calystegia sepium","order_en":"Solanales","order_zh":"茄目","family_en":"Convolvulaceae","family_zh":"旋花科","iucn":"LC","langs":54,"desc_zh":"旋花（学名：Calystegia sepium）为旋花科打碗花属的植物。","desc_en":"Calystegia sepium (Rutland beauty, bugle vine, heavenly trumpets, bellbind, granny-pop-out-of-bed and many others) is a species of flowering plant in the family Convolvulaceae.","img":"images/773.jpg","thumb":"images/t/773.jpg","file":"Calystegia sepium - tara-seatapp.jpg","ar":0.667,"py":"xuanhua xh","cr_by":"Ivar Leidus","cr_lic":"CC BY-SA 3.0","cr_licurl":"https://creativecommons.org/licenses/by-sa/3.0","habit":"藤本","origin":null},{"id":774,"zh":"圆叶牵牛","en":"Ipomoea purpurea","sci":"Ipomoea purpurea","order_en":"Solanales","order_zh":"茄目","family_en":"Convolvulaceae","family_zh":"旋花科","iucn":null,"langs":41,"desc_zh":"圆叶牵牛（学名：Ipomoea purpurea）是旋花科番薯属的植物。其种加词“purpurea”意为“紫色的”，指的是花为紫色的。分布在世界各地，包括热带美洲以及中国大陆的大部分地区，生长于海拔2,800米的地区，多生长在田边、路边、宅旁和山谷林内，目前已由人工引种栽培。","desc_en":"Ipomoea purpurea, the common morning-glory, tall morning-glory, or purple morning glory, is a species in the genus Ipomoea. It is native to Mexico and Central America, and is naturalized throughout warm temperate and subtropical regions of the world.","img":"images/774.jpg","thumb":"images/t/774.jpg","file":"BlueMorningGlory.jpg","ar":0.816,"py":"yuanyeqianniu yyqn","cr_by":"Original uploader was PiccoloNamek at en.wikipedia","cr_lic":"CC BY-SA 3.0","cr_licurl":"http://creativecommons.org/licenses/by-sa/3.0/","habit":null,"origin":["北美洲"]},{"id":775,"zh":"肾叶打碗花","en":"Calystegia soldanella","sci":"Calystegia soldanella","order_en":"Solanales","order_zh":"茄目","family_en":"Convolvulaceae","family_zh":"旋花科","iucn":null,"langs":38,"desc_zh":"肾叶打碗花（学名：Calystegia soldanella），又名肾叶天剑、扶子苗（山东）、滨旋花（江苏、浙江）、砂附、海地瓜，是旋花科打碗花属的植物。分布于亚洲温带、欧洲、大洋洲海滨、台湾岛以及中国大陆的辽宁、江苏、山东、浙江、河北等地，生长于海拔100米的地区，常生长在海滨沙地和海岸岩石缝中，目前尚未由人工引种栽培。 染色体数2n=22。","desc_en":"Calystegia soldanella (syn. Convolvulus soldanella) is a species of bindweed known by various common names such as sea bells, sea bindweed, seashore false bindweed, shore bindweed, shore convolvulus and beach morning glory.","img":"images/775.jpg","thumb":"images/t/775.jpg","file":"Calystegia soldanella 060524wb.jpg","ar":1.501,"py":"shenyedawanhua sydwh","cr_by":"User:Strobilomyces","cr_lic":"CC BY-SA 3.0","cr_licurl":"http://creativecommons.org/licenses/by-sa/3.0/","habit":null,"origin":null},{"id":776,"zh":"罗勒","en":"basil","sci":"Ocimum basilicum","order_en":"Lamiales","order_zh":"唇形目","family_en":"Lamiaceae","family_zh":"唇形科","iucn":null,"langs":121,"desc_zh":"罗勒（学名：Ocimum basilicum，俗名金不换、九层塔（台湾）、七层塔（客家语）鱼生菜（香港及潮汕）、香花子（皖北），兰香（华北）、西王母菜）是一种可食用香草的统称。其大多数为一年生植物，少部分为多年生植物，其下包括许多栽培品种，其中于远东较为常见之品种为Thai basil(直译为泰国罗勒，Ocimum basilicum var.","desc_en":"Basil (Ocimum basilicum), also called great basil, is a culinary herb of the family Lamiaceae (mints). It is a tender plant and is used in cuisines worldwide.","img":"images/776.jpg","thumb":"images/t/776.jpg","file":"Basil-Basilico-Ocimum basilicum-albahaca.jpg","ar":1.333,"py":"luole ll","cr_by":"Castielli","cr_lic":"CC BY-SA 3.0","cr_licurl":"https://creativecommons.org/licenses/by-sa/3.0","habit":"草本","origin":["亚洲","非洲"]},{"id":777,"zh":"迷迭香","en":"Salvia rosmarinus","sci":"Salvia rosmarinus","order_en":"Lamiales","order_zh":"唇形目","family_en":"Lamiaceae","family_zh":"唇形科","iucn":null,"langs":114,"desc_zh":"迷迭香（学名：Salvia rosmarinus）是唇形科、鼠尾草属的一种多年生常绿灌木，原产于地中海盆地，其叶、茎、花富含芳香油，常用作烹饪或精油中的香料。","desc_en":"Salvia rosmarinus, synonym Rosmarinus officinalis, commonly known as rosemary, is a shrub with fragrant, evergreen, needle-like leaves and purple or sometimes white, pink, or blue flowers. It is a member of the mint family, Lamiaceae.","img":"images/777.jpg","thumb":"images/t/777.jpg","file":"P1090247(4x3)-Rosmarinus officinalis (41960388224).jpg","ar":1.333,"py":"midiexiang mdx","cr_by":"Miguel Angel Masegosa Martínez","cr_lic":"CC BY 2.0","cr_licurl":"https://creativecommons.org/licenses/by/2.0","habit":"灌木","origin":["欧洲"]},{"id":778,"zh":"牛至","en":"Origanum vulgare","sci":"Origanum vulgare","order_en":"Lamiales","order_zh":"唇形目","family_en":"Lamiaceae","family_zh":"唇形科","iucn":null,"langs":103,"desc_zh":"牛至（学名：Origanum vulgare），又名滇香薷，欧洲语言中称为“俄勒冈”、“披萨草”或“野马郁兰”（意大利语：origano；英语：oregano、pizza herb、wild marjoram），是唇形科牛至属中的一种植物。 牛至和马郁兰同属牛至属，为近亲。后者在中东也叫“甘牛至”（sweet marjoram）。","desc_en":"Oregano (US: , UK: ; Origanum vulgare) is a species of flowering plant in the mint family, Lamiaceae. It was native to the Mediterranean region, but widely naturalised elsewhere in the temperate Northern Hemisphere.","img":"images/778.jpg","thumb":"images/t/778.jpg","file":"Origanum vulgare inflorescence - Keila.jpg","ar":1.501,"py":"niuzhi nz","cr_by":"Ivar Leidus","cr_lic":"CC BY-SA 4.0","cr_licurl":"https://creativecommons.org/licenses/by-sa/4.0","habit":"草本","origin":["欧洲"]},{"id":779,"zh":"墨角兰","en":"marjoram","sci":"Origanum majorana","order_en":"Lamiales","order_zh":"唇形目","family_en":"Lamiaceae","family_zh":"唇形科","iucn":null,"langs":91,"desc_zh":"墨角兰（学名：Origanum majorana），隶属于唇形科牛至属，是一种有点对寒冷敏感的多年生香草，带有甜松和柑橘的香味。墨角兰又名马郁草、马约兰草、甜墨角兰（Sweet Marjoram）、多节墨角兰（Knotted Marjoram）及马乔兰(Marjoram)。叶对生，卵圆形，具顶生伞房花序，开白色或紫色花朵。","desc_en":"Marjoram (, Origanum majorana, syn. Majorana hortensis Moench) is a cold-sensitive perennial herb or undershrub with sweet pine and citrus flavours. In some Middle Eastern countries, marjoram is synonymous with oregano, and there the names sweet marjoram and k…","img":"images/779.jpg","thumb":"images/t/779.jpg","file":"Origanum majorana.jpg","ar":1.333,"py":"mojiaolan mjl","cr_by":null,"cr_lic":"CC BY-SA 3.0","cr_licurl":"http://creativecommons.org/licenses/by-sa/3.0/","habit":"草本","origin":null},{"id":780,"zh":"香蜂花","en":"Melissa officinalis","sci":"Melissa officinalis","order_en":"Lamiales","order_zh":"唇形目","family_en":"Lamiaceae","family_zh":"唇形科","iucn":null,"langs":79,"desc_zh":"香蜂花（学名：Melissa officinalis），又名柠檬香草（英语：lemon balm）、柠檬香蜂草，是唇形科蜜蜂花属的一个种，多年生草本，株高约40～45cm，原产中东温带地区，随后遍及亚洲及地中海国家。目前广泛植于于欧洲、中亚和北美地区。学名中的Melissa在希腊文中为「蜜蜂」之意。古希腊、罗马人认为香蜂花为月亮与狩猎女神阿耳忒弥斯（黛安娜）之化身，将其视为重要植物，栽培于寺庙周围，吸引蜂群制造蜂蜜，作为糖份来源。","desc_en":"Lemon balm (Melissa officinalis) is a perennial herbaceous plant in the mint family. It has lemon-scented leaves, white or pale pink flowers, and contains essential oils and compounds, such as geranial and neral. It grows to a maximum height of 1 m (3+1⁄2 ft).","img":"images/780.jpg","thumb":"images/t/780.jpg","file":"Melissa officinalis Bee Balm,Lemon Balm ბარამბო.JPG","ar":0.664,"py":"xiangfenghua xfh","cr_by":"Lazaregagnidze","cr_lic":"CC BY-SA 4.0","cr_licurl":"https://creativecommons.org/licenses/by-sa/4.0","habit":"草本","origin":["亚洲","欧洲"]},{"id":781,"zh":"柚木","en":"Tectona grandis","sci":"Tectona grandis","order_en":"Lamiales","order_zh":"唇形目","family_en":"Lamiaceae","family_zh":"唇形科","iucn":"EN","langs":77,"desc_zh":"柚木（学名Tectona grandis）又名胭脂树，是阔叶乔木，属于唇形科（或是马鞭草科）柚木属的植物。一般生长在南亚或东南亚，以缅甸(Burma Teak)出产的最为著名，原产地为缅甸 (Kyun)、印尼(jati)、泰国(Teak)、婆罗洲、爪哇、印度等，因富含油脂及高稳定度而受到广泛利用，在家具用材中，有群木之王的美誉 。","desc_en":"Teak (Tectona grandis) is a tropical hardwood tree species in the family Lamiaceae. It is a large, deciduous tree that occurs in mixed hardwood forests. Tectona grandis has small, fragrant white flowers arranged in dense clusters (panicles) at the end of the b…","img":"images/781.jpg","thumb":"images/t/781.jpg","file":"Starr 010304-0485 Tectona grandis.jpg","ar":1.333,"py":"youmu ym","cr_by":"Forest & Kim Starr","cr_lic":"CC BY 3.0","cr_licurl":"https://creativecommons.org/licenses/by/3.0","habit":"乔木","origin":["亚洲","非洲","北美洲"]},{"id":782,"zh":"鼠尾草","en":"Salvia officinalis","sci":"Salvia officinalis","order_en":"Lamiales","order_zh":"唇形目","family_en":"Lamiaceae","family_zh":"唇形科","iucn":"LC","langs":77,"desc_zh":"药用鼠尾草（学名：Salvia officinalis），《中国植物志》作「撒尔维亚」，是唇形科鼠尾草属的一种芳香性植物。常绿性小型亚灌木，有木质茎，叶子灰绿色，花蓝色至蓝紫色。原产于欧洲南部与地中海沿岸地区。药用鼠尾草有时也俗称「鼠尾草」，但容易与原产中国和日本的同属植物鼠尾草相混。无论其香草形状，都不像鼠尾。","desc_en":"Salvia officinalis, common sage or sage, is a perennial, evergreen subshrub, with woody stems, grayish leaves, and blue to purplish flowers. It is a member of the mint family (Lamiaceae) and native to the Mediterranean region, though it has been naturalized in…","img":"images/782.jpg","thumb":"images/t/782.jpg","file":"Salvia officinalis L. 3355742911.jpg","ar":0.75,"py":"shuweicao swc","cr_by":"iNaturalist.org (Alina Majcen) (Alina%20Majcen)","cr_lic":"CC0","cr_licurl":"http://creativecommons.org/publicdomain/zero/1.0/deed.en","habit":"灌木","origin":["欧洲"]},{"id":783,"zh":"胡椒薄荷","en":"Mentha × piperita","sci":"Mentha ×piperita","order_en":"Lamiales","order_zh":"唇形目","family_en":"Lamiaceae","family_zh":"唇形科","iucn":null,"langs":76,"desc_zh":"[[Category:物种微格式条目|Mentha × piperita]] 辣薄荷（学名：Mentha × piperita，又名胡椒薄荷，英语：Peppermint）唇形科年生草本植物，是一种被广泛种植的混种薄荷，原产于欧洲，可用于食物的调味料。这个薄荷品种是由绿薄荷（Mentha spicata，英语：Spearmint）与水薄荷（Mentha aquatica，英语：Watermint）混种而成的.","desc_en":"Peppermint (Mentha × piperita) is a hybrid species of mint, a cross between watermint and spearmint. Indigenous to Europe and the Middle East, the plant is now widely spread and cultivated in many regions of the world.","img":"images/783.jpg","thumb":"images/t/783.jpg","file":"Pfefferminze natur peppermint.jpg","ar":1.333,"py":"hujiaobohe hjbh","cr_by":null,"cr_lic":"CC BY 3.0","cr_licurl":"https://creativecommons.org/licenses/by/3.0","habit":null,"origin":["亚洲","欧洲"]},{"id":784,"zh":"野薄荷","en":"corn mint","sci":"Mentha arvensis","order_en":"Lamiales","order_zh":"唇形目","family_en":"Lamiaceae","family_zh":"唇形科","iucn":"LC","langs":69,"desc_zh":"田野薄荷（学名：Mentha arvensis；英语：field mint），也称谷薄荷、玉米薄荷（英语：corn mint），是薄荷属下的一种。其范围遍及环北方带，在有湿润土壤的欧洲、西亚、北亚都有分布，东至西喜马拉雅山脉和西伯利亚的东部，以及北美。 它是一种多年生草本植物，高10-60厘米（特殊情况能长到100厘米）。对生叶序，叶片较小，2-6.5厘米长，1-2厘米宽，长毛，边缘为齿状。","desc_en":"Mentha arvensis, the corn mint, field mint, or wild mint, is a species of flowering plant in the mint family Lamiaceae. It has a circumboreal distribution, being native to the temperate regions of Europe and western and central Asia, east to the Himalaya and e…","img":"images/784.jpg","thumb":"images/t/784.jpg","file":"Mentha arvensis 2005.08.28 09.49.00.jpg","ar":0.75,"py":"yebohe ybh","cr_by":"Michael Becker","cr_lic":"CC BY-SA 3.0","cr_licurl":"http://creativecommons.org/licenses/by-sa/3.0/","habit":null,"origin":["亚洲","欧洲","北美洲"]},{"id":785,"zh":"圣罗勒","en":"Holy Basil","sci":"Ocimum tenuiflorum","order_en":"Lamiales","order_zh":"唇形目","family_en":"Lamiaceae","family_zh":"唇形科","iucn":null,"langs":63,"desc_zh":"圣罗勒（学名：Ocimum tenuiflorum），又名神罗勒、打抛叶、打抛或嘎抛（泰语：กะเพรา，kaphrao），为唇形科罗勒属下的一种多年生草本植物，原生于印度次大陆，其相关栽植种遍及东南亚和热带地区。","desc_en":"Ocimum tenuiflorum, commonly known as tulasi, tulsi, or holy basil, is an aromatic perennial plant in the family Lamiaceae. It is widely cultivated throughout the Southeast Asian tropics.","img":"images/785.jpg","thumb":"images/t/785.jpg","file":"Tulasih.jpg","ar":0.563,"py":"shengluole sll","cr_by":"I Gd Nj Prt","cr_lic":"CC BY-SA 4.0","cr_licurl":"https://creativecommons.org/licenses/by-sa/4.0","habit":"草本","origin":["亚洲","大洋洲"]},{"id":786,"zh":"铺地百里香","en":"Thymus serpyllum","sci":"Thymus serpyllum","order_en":"Lamiales","order_zh":"唇形目","family_en":"Lamiaceae","family_zh":"唇形科","iucn":null,"langs":61,"desc_zh":"铺地百里香（学名：Thymus serpyllum；英语：creeping thyme），也称铺地香、匍匐百里香、野百里香（英语：wild thyme），是百里香属下的一个种，主要生长在欧洲和北非。它的植株很小，通常为2厘米高的小灌木，带有10厘米长的匍匐茎。叶子为椭圆形常绿叶，长为3-8毫米。花带有浓郁香味，为淡紫色、粉紫色、洋紫色或淡白色，4-6毫米长，簇生。其香味因植株不同而有浓淡之分，从浓重的草药味到淡淡柠檬味都有。","desc_en":"Thymus serpyllum, known by the common names of Breckland thyme, Breckland wild thyme, wild thyme, creeping thyme, or elfin thyme, is a species of flowering plant in the mint family, Lamiaceae.","img":"images/786.jpg","thumb":"images/t/786.jpg","file":"Thymus serpyllum1.jpg","ar":1.333,"py":"pudibailixiang pdblx","cr_by":null,"cr_lic":"CC BY-SA 3.0","cr_licurl":"http://creativecommons.org/licenses/by-sa/3.0/","habit":"灌木","origin":["欧洲","非洲"]},{"id":787,"zh":"短柄野芝麻","en":"Lamium album","sci":"Lamium album","order_en":"Lamiales","order_zh":"唇形目","family_en":"Lamiaceae","family_zh":"唇形科","iucn":null,"langs":61,"desc_zh":"短柄野芝麻又名野芝麻（学名：Lamium album）为唇形科野芝麻属下的一个种。","desc_en":"Lamium album, commonly called white dead-nettle, is a flowering plant in the family Lamiaceae. It is native throughout Europe and Asia, growing in a variety of habitats from open grassland to woodland, generally on moist, fertile soils.","img":"images/787.jpg","thumb":"images/t/787.jpg","file":"Lamium album Sturm39.jpg","ar":0.698,"py":"duanbingyezhima dbyzm","cr_by":"Johann Georg Sturm (Painter: Jacob Sturm )","cr_lic":"Public domain","cr_licurl":null,"habit":null,"origin":["亚洲","欧洲"]},{"id":788,"zh":"留兰香","en":"Mentha spicata","sci":"Mentha spicata","order_en":"Lamiales","order_zh":"唇形目","family_en":"Lamiaceae","family_zh":"唇形科","iucn":"LC","langs":60,"desc_zh":"留兰香（学名：Mentha spicata），又名绿薄荷、香薄荷、荷兰薄荷、青薄荷、香花菜、鱼香菜。是一种唇形科直立多年生草本植物，有香味，茎、叶经蒸馏可提取留兰香油。","desc_en":"Spearmint (Mentha spicata), also known as garden mint, common mint, lamb mint and mackerel mint, is native to Europe and southern temperate Asia, extending from Ireland in the west to southern China in the east.","img":"images/788.jpg","thumb":"images/t/788.jpg","file":"Minze.jpg","ar":1.333,"py":"liulanxiang llx","cr_by":"Simon Eugster -- Simon 13:07, 2 July 2006 (UTC)","cr_lic":"CC BY-SA 3.0","cr_licurl":"http://creativecommons.org/licenses/by-sa/3.0/","habit":null,"origin":["亚洲","欧洲"]},{"id":789,"zh":"荆芥","en":"Nepeta cataria","sci":"Nepeta cataria","order_en":"Lamiales","order_zh":"唇形目","family_en":"Lamiaceae","family_zh":"唇形科","iucn":null,"langs":60,"desc_zh":"猫薄荷（学名：Nepeta cataria，英语：catnip/catmint）是一种具有特殊气味的唇形科植物，多年生草本，植株可达1.5米，被白色短柔毛，可作芳香油及蜜源植物栽培，全草亦可供药用，以及猫科动物的兴奋剂。其原产地包括欧亚大陆的大部分地区。","desc_en":"Nepeta cataria, commonly known as catnip or catmint, is a species of the genus Nepeta in the mint family. It is native to southern and eastern Europe, northern parts of the Middle East, and Central Asia.","img":"images/789.jpg","thumb":"images/t/789.jpg","file":"Catnip flowers.jpg","ar":1.333,"py":"jingjie jj","cr_by":"D. Gordon E. Robertson","cr_lic":"CC BY-SA 3.0","cr_licurl":"https://creativecommons.org/licenses/by-sa/3.0","habit":"草本","origin":["亚洲","欧洲"]},{"id":790,"zh":"唇萼薄荷","en":"Mentha pulegium","sci":"Mentha pulegium","order_en":"Lamiales","order_zh":"唇形目","family_en":"Lamiaceae","family_zh":"唇形科","iucn":"LC","langs":59,"desc_zh":"唇萼薄荷（学名：Mentha pulegium），又称普列薄荷（Pennyroyal）、除蚤薄荷、胡薄荷，为薄荷属下的一个种。碾碎的唇萼薄荷会有类似绿薄荷的浓香气味。它也是一种传统的烹饪调料、草药和堕胎药。","desc_en":"Mentha pulegium, commonly (European) pennyroyal, or pennyrile, also called mosquito plant and pudding grass, is a species of flowering plant in the mint family, Lamiaceae, native to Europe, North Africa, and the Middle East.","img":"images/790.jpg","thumb":"images/t/790.jpg","file":"Gardenology.org-IMG 2751 rbgs11jan.jpg","ar":1.333,"py":"chunebohe cebh","cr_by":"Raffi Kojian","cr_lic":"CC BY-SA 3.0","cr_licurl":"https://creativecommons.org/licenses/by-sa/3.0","habit":"禾草","origin":["亚洲","欧洲","非洲"]},{"id":791,"zh":"狭叶薰衣草","en":"Lavandula angustifolia","sci":"Lavandula angustifolia","order_en":"Lamiales","order_zh":"唇形目","family_en":"Lamiaceae","family_zh":"唇形科","iucn":"LC","langs":59,"desc_zh":"狭叶薰衣草（学名：Lavandula angustifolia），又名薰衣草、真正薰衣草、英国薰衣草，是唇形科，薰衣草属的一种灌木。原产于地中海地区的西部，目前世界上主要种植地有法国、欧洲的西班牙北部的山脉与庇里牛斯山脉，保加利亚高山地区和亚洲的中国大陆甘肃的清水县。在澳门亦有随葡萄牙传入，并以之制作药油。狭叶薰衣草对气候，海拔都要求较高，所以种植面积不及杂交品种的薰衣草种植面积。","desc_en":"Lavandula angustifolia, formerly L. officinalis, is a flowering plant in the family Lamiaceae, native to the Mediterranean basin. Its common names include lavender, true lavender and English lavender (though it is not native to England); also garden lavender,…","img":"images/791.jpg","thumb":"images/t/791.jpg","file":"Lavandula angustifolia - Köhler–s Medizinal-Pflanzen-087.jpg","ar":0.734,"py":"xiayexunyicao xyxyc","cr_by":"Franz Eugen Köhler, Köhler's Medizinal-Pflanzen","cr_lic":"Public domain","cr_licurl":null,"habit":null,"origin":["欧洲"]},{"id":792,"zh":"普通百里香","en":"Thymus vulgaris","sci":"Thymus vulgaris","order_en":"Lamiales","order_zh":"唇形目","family_en":"Lamiaceae","family_zh":"唇形科","iucn":"LC","langs":57,"desc_zh":"普通百里香（学名：Thymus vulgaris、英语：common thyme），也叫花园百里香（英语：garden thyme）、南欧百里香，是唇形科百里香属常绿亚灌木，原产意大利、法国和西班牙，摩洛哥亦有分布。虽然也叫英国百里香（英语：English thyme），但是普通百里香并不是英国的原生植物。普通百里香是西餐中常用的调味香草。","desc_en":"Thymus vulgaris (common thyme, German thyme, garden thyme or just thyme) is a species of flowering plant in the mint family, Lamiaceae.","img":"images/792.jpg","thumb":"images/t/792.jpg","file":"Thymian (Thymus vulgaris), Nationalpark Hohe Tauern.jpg","ar":1.501,"py":"putongbailixiang ptblx","cr_by":"Naturpuur","cr_lic":"CC BY 4.0","cr_licurl":"https://creativecommons.org/licenses/by/4.0","habit":null,"origin":null},{"id":793,"zh":"奇佳子","en":"Salvia hispanica","sci":"Salvia hispanica","order_en":"Lamiales","order_zh":"唇形目","family_en":"Lamiaceae","family_zh":"唇形科","iucn":null,"langs":57,"desc_zh":"芡欧鼠尾草是唇形科鼠尾草属的一种一年生草本植物，原产于墨西哥中南部和瓜地马拉。芡欧鼠尾草可生长至约1.75m，开白色或紫色花朵。芡欧鼠尾草的种子又称奇亚籽，其外形类似芝麻，富含ω-3脂肪酸，可以食用。由于芡欧鼠尾草的种子不饱和脂肪酸含量很高，因此经常作为减肥美容食品食用。","desc_en":"Salvia hispanica, one of several related species commonly known as chia (), is a species of flowering plant in the mint family, Lamiaceae. It is native to central and southern Mexico and Guatemala.","img":"images/793.jpg","thumb":"images/t/793.jpg","file":"Salvia hispanica kz2.jpg","ar":0.72,"py":"qijiazi qjz","cr_by":"Krzysztof Ziarnek, Kenraiz","cr_lic":"CC BY-SA 4.0","cr_licurl":"https://creativecommons.org/licenses/by-sa/4.0","habit":null,"origin":["北美洲"]},{"id":794,"zh":"水薄荷","en":"Mentha aquatica","sci":"Mentha aquatica","order_en":"Lamiales","order_zh":"唇形目","family_en":"Lamiaceae","family_zh":"唇形科","iucn":"LC","langs":53,"desc_zh":"心叶水薄荷（学名：Clinopodium brownei (Sw.) Kuntze），是是唇形科薄荷属的多年生开花植物。它生长在潮湿的地方薄荷属下的一种多年生草本开花植物，其原产于欧洲（除了最北部），也生长于非洲的西北部、亚洲的西南部。","desc_en":"Mentha aquatica (water mint; syn. Mentha hirsuta Huds.) is a perennial flowering plant in the mint family, Lamiaceae. It grows in moist places and is native to much of Europe, northwest Africa and southwest Asia.","img":"images/794.jpg","thumb":"images/t/794.jpg","file":"Mentha aquatica 02.jpg","ar":0.641,"py":"shuibohe sbh","cr_by":"Burschik at English Wikipedia","cr_lic":"CC BY-SA 3.0","cr_licurl":"http://creativecommons.org/licenses/by-sa/3.0/","habit":"草本","origin":["亚洲","欧洲","非洲"]},{"id":795,"zh":"宽叶车前","en":"Plantago major","sci":"Plantago major","order_en":"Lamiales","order_zh":"唇形目","family_en":"Plantaginaceae","family_zh":"车前科","iucn":"LC","langs":77,"desc_zh":"大车前草（学名：Plantago major）又名宽叶车前，是车前科车前属的一种植物。这种植物原产于亚洲北部和欧洲，但现已遍布全球。它在殖民时期被无意中带到美洲。这种植物能够在紧致的土壤生长，包括从前筑路时被夯实的泥土路，所以在英语又名\"roadweed\"，意思就是「路上的野草」。 宽叶车前是一种风媒植物，叶子捣碎后可以用来止血，可食用及入药，但在美国被视为一种野草。","desc_en":"Plantago major, the broadleaf plantain, white man's footprint, waybread, or greater plantain, is a species of flowering plant in the plantain family Plantaginaceae. The plant is native to Eurasia and naturalized to America.","img":"images/795.jpg","thumb":"images/t/795.jpg","file":"Grote weegbree bloeiwijze Plantago major subsp. major.jpg","ar":0.714,"py":"kuanyecheqian kycq","cr_by":"Rasbak","cr_lic":"CC BY-SA 3.0","cr_licurl":"http://creativecommons.org/licenses/by-sa/3.0/","habit":null,"origin":["亚洲"]},{"id":796,"zh":"长叶车前","en":"Plantago lanceolata","sci":"Plantago lanceolata","order_en":"Lamiales","order_zh":"唇形目","family_en":"Plantaginaceae","family_zh":"车前科","iucn":null,"langs":69,"desc_zh":"长叶车前（学名：Plantago lanceolata） 又名窄叶车前、欧车前、披针叶车前，为车前属的品种之一，是一种多年生草本植物，株高约5至50厘米，根深可达60厘米左右。在英语世界里普遍被称为 ribwort plantain、English plantain、buckhorn plantain 或narrowleaf plantain。","desc_en":"Plantago lanceolata is a species of flowering plant in the plantain family Plantaginaceae. It is known by the common names ribwort plantain, narrowleaf plantain, English plantain, ribleaf, lamb's tongue, and buckhorn.","img":"images/796.jpg","thumb":"images/t/796.jpg","file":"Ribwort 600.jpg","ar":0.828,"py":"changyecheqian cycq","cr_by":"sannse","cr_lic":"CC BY-SA 3.0","cr_licurl":"http://creativecommons.org/licenses/by-sa/3.0/","habit":null,"origin":null},{"id":797,"zh":"毛地黄","en":"Digitalis purpurea","sci":"Digitalis purpurea","order_en":"Lamiales","order_zh":"唇形目","family_en":"Plantaginaceae","family_zh":"车前科","iucn":null,"langs":63,"desc_zh":"毛地黄（学名：Digitalis purpurea；foxglove、common foxglove、purple foxglove、lady's glove）为唇形目车前科毛地黄属下的一个种，其种加词“purpurea”意为“紫色的”。广泛分布于温带欧洲。也见于北美和其他温带部分地区。 本物种为著名的药用有毒植物，全株皆有毒。与同作药用的有毒植物如马醉木等是少数可作为观赏用之有毒却有药用的有毒植物。","desc_en":"Digitalis purpurea, the foxglove or common foxglove, is a toxic species of flowering plant in the plantain family Plantaginaceae, native to and widespread throughout most of temperate Europe.","img":"images/797.jpg","thumb":"images/t/797.jpg","file":"Brdy-stonek zvonku.jpg","ar":0.75,"py":"maodihuang mdh","cr_by":"Honza Groh","cr_lic":"CC BY 3.0","cr_licurl":"https://creativecommons.org/licenses/by/3.0","habit":"草本","origin":["欧洲"]},{"id":798,"zh":"新疆柳穿鱼","en":"Linaria vulgaris","sci":"Linaria vulgaris","order_en":"Lamiales","order_zh":"唇形目","family_en":"Plantaginaceae","family_zh":"车前科","iucn":null,"langs":48,"desc_zh":"新疆柳穿鱼（学名：Linaria vulgaris sp. acutiloba）为玄参科柳穿鱼属下的一个亚种。","desc_en":"Linaria vulgaris, the common toadflax, is a species of flowering plant in the family Plantaginaceae, native to Europe, and northern, central and eastern Asia. It has also been introduced to North America and is now common there.","img":"images/798.jpg","thumb":"images/t/798.jpg","file":"Linaria vulgaris - harilik käokannus Valingu.jpg","ar":0.667,"py":"xinjiangliuchuanyu xjlcy","cr_by":"Ivar Leidus","cr_lic":"CC BY-SA 3.0","cr_licurl":"https://creativecommons.org/licenses/by-sa/3.0","habit":null,"origin":["亚洲","欧洲"]},{"id":799,"zh":"药用水苦荬","en":"Veronica officinalis","sci":"Veronica officinalis","order_en":"Lamiales","order_zh":"唇形目","family_en":"Plantaginaceae","family_zh":"车前科","iucn":null,"langs":47,"desc_zh":null,"desc_en":"Veronica officinalis, the heath speedwell, common gypsyweed, common speedwell, or Paul's betony, is a species of flowering plant in the plantain family Plantaginaceae. It is native to Europe and western Asia.","img":"images/799.jpg","thumb":"images/t/799.jpg","file":"Veronica officinalis0.jpg","ar":0.75,"py":"yaoyongshuikumai yyskm","cr_by":"Kurt Stüber [1]","cr_lic":"CC BY-SA 3.0","cr_licurl":"http://creativecommons.org/licenses/by-sa/3.0/","habit":null,"origin":["亚洲","欧洲"]},{"id":800,"zh":"金鱼草","en":"Antirrhinum majus","sci":"Antirrhinum majus","order_en":"Lamiales","order_zh":"唇形目","family_en":"Plantaginaceae","family_zh":"车前科","iucn":null,"langs":45,"desc_zh":"金鱼草（学名：Antirrhinum majus）又名龙口花、龙头花、洋彩雀､ 龙雀花，为车前科金鱼草属多年生草本植物，原属玄参科，是一种模式生物。原产于地中海地区，分布区域从摩洛哥和葡萄牙向北至法国南部，东至土耳其和叙利亚。金鱼草因花状似金鱼而得名，其拉丁学名“Antirrhinum”意指“状如鼻子”，而“majus”则意为“五月开花”。","desc_en":"Antirrhinum majus, the common snapdragon (often – especially in horticulture – simply \"snapdragon\"), is a species of flowering plant belonging to the genus Antirrhinum.","img":"images/800.jpg","thumb":"images/t/800.jpg","file":"Antirrhinum majus from Thasos.JPG","ar":0.667,"py":"jinyucao jyc","cr_by":"User:Haplochromis","cr_lic":"CC BY 2.5","cr_licurl":"https://creativecommons.org/licenses/by/2.5","habit":"草本","origin":null},{"id":801,"zh":"毛蕊花","en":"Verbascum thapsus","sci":"Verbascum thapsus","order_en":"Lamiales","order_zh":"唇形目","family_en":"Scrophulariaceae","family_zh":"玄参科","iucn":null,"langs":55,"desc_zh":"毛蕊花（学名：Verbascum thapsus），为玄参科毛蕊花属下的一个植物种。 这种植物原生于非洲与亚洲北部,后期引进到了美洲和澳大利亚。","desc_en":"Verbascum thapsus, the great mullein, greater mullein or common mullein, is a species of mullein native to Europe, northern Africa, and Asia, and introduced in the Americas, Australia and New Zealand.","img":"images/801.gif","thumb":"images/t/801.gif","file":"00 2262 Kleinblütige Königskerze (Verbascum thapsus).gif","ar":0.752,"py":"maoruihua mrh","cr_by":"W. Bulach","cr_lic":"CC BY-SA 4.0","cr_licurl":"https://creativecommons.org/licenses/by-sa/4.0","habit":"草本","origin":["亚洲","欧洲","非洲","大洋洲"]},{"id":802,"zh":"大叶醉鱼草","en":"Buddleja davidii","sci":"Buddleja davidii","order_en":"Lamiales","order_zh":"唇形目","family_en":"Scrophulariaceae","family_zh":"玄参科","iucn":null,"langs":43,"desc_zh":"大叶醉鱼草（学名：Buddleja davidii），又名绛花醉鱼草（中国树木分类学）、穆坪醉鱼草（中国树木分类学）、兴山醉鱼草（中国树木分类学）、白背叶醉鱼草（云南植物研究）、白壶子（甘肃武都），是玄参科醉鱼草属的植物。","desc_en":"Buddleja davidii (spelling variant Buddleia davidii), also called butterfly-bush, orange eye, or summer lilac, is a species of flowering plant in the family Scrophulariaceae, native to most of China except for the far northeast.","img":"images/802.jpg","thumb":"images/t/802.jpg","file":"BuddlejaDavidiiStrauch.jpg","ar":1.333,"py":"dayezuiyucao dyzyc","cr_by":"-- IKAl 15:22, 23 July 2007 (UTC)","cr_lic":"CC BY-SA 2.5","cr_licurl":"https://creativecommons.org/licenses/by-sa/2.5","habit":"灌木","origin":["亚洲"]},{"id":803,"zh":"林地玄参","en":"Scrophularia nodosa","sci":"Scrophularia nodosa","order_en":"Lamiales","order_zh":"唇形目","family_en":"Scrophulariaceae","family_zh":"玄参科","iucn":null,"langs":39,"desc_zh":null,"desc_en":"Scrophularia nodosa (also called figwort, woodland figwort, and common figwort) is a perennial herbaceous plant found in temperate regions of the Northern Hemisphere except western North America. It grows in moist and cultivated waste ground.","img":"images/803.jpg","thumb":"images/t/803.jpg","file":"Scrophularia nodosa8.jpg","ar":1.333,"py":"lindixuancan ldxc","cr_by":"Kurt Stüber [1]","cr_lic":"CC BY-SA 3.0","cr_licurl":"http://creativecommons.org/licenses/by-sa/3.0/","habit":"草本","origin":["北美洲"]},{"id":804,"zh":"毒鱼草","en":"denseflower mullein","sci":"Verbascum densiflorum","order_en":"Lamiales","order_zh":"唇形目","family_en":"Scrophulariaceae","family_zh":"玄参科","iucn":null,"langs":32,"desc_zh":null,"desc_en":"Verbascum densiflorum, also known as denseflower mullein and dense-flowered mullein, is a species of plant in the figwort family Scrophulariaceae.","img":"images/804.jpg","thumb":"images/t/804.jpg","file":"00 2359 Großblütige Königskerze - Verbascum densiflorum.jpg","ar":0.6,"py":"duyucao dyc","cr_by":"W. Bulach","cr_lic":"CC BY-SA 4.0","cr_licurl":"https://creativecommons.org/licenses/by-sa/4.0","habit":null,"origin":null},{"id":805,"zh":"紫毛蕊花","en":"Purple mullein","sci":"Verbascum phoeniceum","order_en":"Lamiales","order_zh":"唇形目","family_en":"Scrophulariaceae","family_zh":"玄参科","iucn":null,"langs":27,"desc_zh":"紫毛蕊花（学名：Verbascum phoeniceum），为玄参科毛蕊花属下的一个植物种。","desc_en":"Verbascum phoeniceum, known as purple mullein, is a species of mullein that is part of the family Scrophulariaceae native to Central Europe, Central Asia and Western China. It is also naturalized in certain regions of the US and Canada.","img":"images/805.jpg","thumb":"images/t/805.jpg","file":"Verbascum phoeniceum2.jpg","ar":0.75,"py":"zimaoruihua zmrh","cr_by":"Jeffdelonge at French Wikipedia","cr_lic":"CC BY-SA 3.0","cr_licurl":"http://creativecommons.org/licenses/by-sa/3.0/","habit":"草本","origin":["亚洲","欧洲"]},{"id":806,"zh":"小鼻花","en":"Rhinanthus minor","sci":"Rhinanthus minor","order_en":"Lamiales","order_zh":"唇形目","family_en":"Orobanchaceae","family_zh":"列当科","iucn":null,"langs":37,"desc_zh":null,"desc_en":"Rhinanthus minor, known as yellow rattle, is a herbaceous wildflower in the genus Rhinanthus in the broomrape family. It has circumpolar distribution in Europe, Russia, western Asia, and northern North America.","img":"images/806.jpg","thumb":"images/t/806.jpg","file":"Yellow-rattle 700.jpg","ar":0.75,"py":"xiaobihua xbh","cr_by":null,"cr_lic":"CC BY-SA 3.0","cr_licurl":"http://creativecommons.org/licenses/by-sa/3.0/","habit":"禾草","origin":["亚洲","欧洲","北美洲"]},{"id":807,"zh":"Euphrasia rostkoviana","en":"Euphrasia rostkoviana","sci":"Euphrasia rostkoviana","order_en":"Lamiales","order_zh":"唇形目","family_en":"Orobanchaceae","family_zh":"列当科","iucn":null,"langs":35,"desc_zh":null,"desc_en":"Euphrasia officinalis, also known as eyebright or eyewort, is a species of plant in the family Orobanchaceae. Euphrasia officinalis herb has been used in the traditional Austrian medicine internally as tea, or externally as compresses, for treatment of disorde…","img":"images/807.jpg","thumb":"images/t/807.jpg","file":"Augentrost.jpg","ar":1.011,"py":"","cr_by":null,"cr_lic":"CC BY-SA 3.0","cr_licurl":"http://creativecommons.org/licenses/by-sa/3.0/","habit":"草本","origin":null},{"id":808,"zh":"Lathraea squamaria","en":"Lathraea squamaria","sci":"Lathraea squamaria","order_en":"Lamiales","order_zh":"唇形目","family_en":"Orobanchaceae","family_zh":"列当科","iucn":null,"langs":35,"desc_zh":null,"desc_en":"Lathraea squamaria, the common toothwort, is a species of flowering plant in the family Orobanchaceae. It is widely distributed in Europe and also occurs in Turkey.","img":"images/808.jpg","thumb":"images/t/808.jpg","file":"Lathraea squamaria LC0126.jpg","ar":0.677,"py":"","cr_by":"Jörg Hempel","cr_lic":"CC BY-SA 2.0 de","cr_licurl":"https://creativecommons.org/licenses/by-sa/2.0/de/deed.en","habit":"乔木","origin":["欧洲"]},{"id":809,"zh":"Melampyrum pratense","en":"Melampyrum pratense","sci":"Melampyrum pratense","order_en":"Lamiales","order_zh":"唇形目","family_en":"Orobanchaceae","family_zh":"列当科","iucn":null,"langs":29,"desc_zh":null,"desc_en":"Melampyrum pratense, the common cow-wheat, is a plant species in the family Orobanchaceae. The seed of the plant has an elaiosome, which is attractive to wood ants (Formica spp.).","img":"images/809.jpg","thumb":"images/t/809.jpg","file":"Melampyrum pratense.jpeg","ar":1.333,"py":"","cr_by":"Kristian Peters -- Fabelfroh 09:39, 3 October 2006 (UTC)","cr_lic":"CC BY-SA 3.0","cr_licurl":"http://creativecommons.org/licenses/by-sa/3.0/","habit":"草本","origin":null},{"id":810,"zh":"野捕虫堇","en":"Pinguicula vulgaris","sci":"Pinguicula vulgaris","order_en":"Lamiales","order_zh":"唇形目","family_en":"Lentibulariaceae","family_zh":"狸藻科","iucn":"LC","langs":46,"desc_zh":"野捕虫堇（学名：Pinguicula vulgaris），也称作紫花捕虫堇，是狸藻科多年生的食肉植物，其种加词“vulgaris”源自拉丁语“vulgar ”，意为“一般的、粗野的”。本种植株高3-16公分，顶部带有紫色，偶尔白色，花朵约15毫米或是更大，且呈漏斗状。本种捕虫堇生长在潮湿环绕的环境，诸如泥塘和沼泽，在低海拔或是亚高山带的海拔。本种具有广泛地环北带分布区域，原生于几乎所有的欧洲国家、俄国、中国、加拿大以及美国。","desc_en":"Pinguicula vulgaris, the common butterwort, is a perennial carnivorous plant in the butterwort genus of the family Lentibulariaceae.","img":"images/810.jpg","thumb":"images/t/810.jpg","file":"Pinguicula vulgaris 140505.jpg","ar":0.959,"py":"yebuchongjin ybcj","cr_by":null,"cr_lic":"CC BY-SA 3.0","cr_licurl":"http://creativecommons.org/licenses/by-sa/3.0/","habit":"草本","origin":null},{"id":811,"zh":"普通狸藻","en":"Utricularia vulgaris","sci":"Utricularia vulgaris","order_en":"Lamiales","order_zh":"唇形目","family_en":"Lentibulariaceae","family_zh":"狸藻科","iucn":"LC","langs":32,"desc_zh":"普通狸藻（学名：Utricularia vulgaris）为狸藻属水生食虫植物。其种加词“vulgaris”来源于拉丁文“vulgaris”，意为“普通的”。其分布于欧洲与亚洲，是狸藻属中分布最为广泛的物种。","desc_en":"Utricularia vulgaris (greater bladderwort or common bladderwort) is an aquatic species of bladderwort found in Asia and Europe. The plant is free-floating and does not put down roots.","img":"images/811.jpg","thumb":"images/t/811.jpg","file":"Uk pond bladderwort.jpg","ar":0.81,"py":"putonglizao ptlz","cr_by":"No machine-readable author provided. Veledan~commonswiki assumed (based on copyright claims).","cr_lic":"Public domain","cr_licurl":null,"habit":null,"origin":["亚洲","欧洲"]},{"id":812,"zh":"吊灯树","en":"Kigelia africana","sci":"Kigelia africana","order_en":"Lamiales","order_zh":"唇形目","family_en":"Bignoniaceae","family_zh":"紫葳科","iucn":"LC","langs":50,"desc_zh":"吊灯树（学名：Kigelia africana）为紫葳科吊灯树属的植物。分布在马达加斯加、非洲以及云南、福建、广东、海南、台湾等地，目前已由人工引种栽培。 其种加词“africana”意为“非洲的”。 吊灯树的果实虽然不可食用，但在非洲是被用作医治皮肤病的药物。","desc_en":"Kigelia is a genus of flowering plants in the trumpet vine family Bignoniaceae. The genus consists of only one species, Kigelia africana, syn. Kigelia pinnata, which occurs throughout tropical Africa and is cultivated elsewhere in the tropics.","img":"images/812.jpg","thumb":"images/t/812.jpg","file":"Kigelia-Africana-Serengeti.JPG","ar":1.407,"py":"diaodengshu dds","cr_by":"Bjørn Christian Tørrissen","cr_lic":"CC BY-SA 3.0","cr_licurl":"https://creativecommons.org/licenses/by-sa/3.0","habit":"藤本","origin":["非洲"]},{"id":813,"zh":"蓝花楹","en":"Jacaranda mimosifolia","sci":"Jacaranda mimosifolia","order_en":"Lamiales","order_zh":"唇形目","family_en":"Bignoniaceae","family_zh":"紫葳科","iucn":"VU","langs":43,"desc_zh":"蓝花楹（学名：Jacaranda mimosifolia）是紫葳科蓝花楹属的植物。分布在阿根廷、玻利维亚、巴西 、澳大利亚。目前已人工引种栽培到广西、海南、广东、云南、福建等地。","desc_en":"Jacaranda mimosifolia is a sub-tropical tree native to south-central South America that has been widely planted elsewhere because of its attractive and long-lasting violet-colored flowers. It is also known as the jacaranda, blue jacaranda, Nupur or black poui.","img":"images/813.jpg","thumb":"images/t/813.jpg","file":"Jacaranda1212.jpg","ar":1.333,"py":"lanhuaying lhy","cr_by":"Kahuroa","cr_lic":"Public domain","cr_licurl":null,"habit":"乔木","origin":["南美洲"]},{"id":814,"zh":"美国梓树","en":"Catalpa bignonioides","sci":"Catalpa bignonioides","order_en":"Lamiales","order_zh":"唇形目","family_en":"Bignoniaceae","family_zh":"紫葳科","iucn":"DD","langs":42,"desc_zh":null,"desc_en":"Catalpa bignonioides is a short-lived species of Catalpa that is native to the southeastern United States in Alabama, Florida, Georgia, Louisiana, and Mississippi.","img":"images/814.jpg","thumb":"images/t/814.jpg","file":"Catalpa bignonioides 05.jpg","ar":1.302,"py":"meiguozishu mgzs","cr_by":"Zeynel Cebeci","cr_lic":"CC BY-SA 4.0","cr_licurl":"https://creativecommons.org/licenses/by-sa/4.0","habit":"乔木","origin":["北美洲"]},{"id":815,"zh":"黄钟花","en":"Tecoma stans","sci":"Tecoma stans","order_en":"Lamiales","order_zh":"唇形目","family_en":"Bignoniaceae","family_zh":"紫葳科","iucn":"LC","langs":37,"desc_zh":null,"desc_en":"Tecoma stans is a species of flowering perennial shrub in the trumpet vine family, Bignoniaceae, that is native to the Americas. Common names include yellow trumpetbush, yellow bells, yellow elder, ginger Thomas.","img":"images/815.jpg","thumb":"images/t/815.jpg","file":"Tecoma stans (Bignoniaceae) 02.jpg","ar":1.333,"py":"huangzhonghua hzh","cr_by":"Filo gèn'","cr_lic":"CC BY-SA 4.0","cr_licurl":"https://creativecommons.org/licenses/by-sa/4.0","habit":"藤本","origin":null},{"id":816,"zh":"马樱丹","en":"Lantana camara","sci":"Lantana camara","order_en":"Lamiales","order_zh":"唇形目","family_en":"Verbenaceae","family_zh":"马鞭草科","iucn":null,"langs":63,"desc_zh":"马缨丹（学名：Lantana camara），别称五色梅、七色梅、五龙兰、如意草、五彩花、臭草、臭金凤、五雷丹、五色绣球、变色草等，客家人称之为绵鼻公花。原本主要分布于南美洲、西印度群岛，马缨丹属（Lantana）常绿灌木。一般花期大约是在4月中、下旬到隔年的2月中旬左右，不过也因气候与温度的影响，几乎整年都能看到开花，可说是常盛的植物。","desc_en":"Lantana camara (common lantana) is a species of flowering plant in the verbena family (Verbenaceae), native to the tropics of the Americas. It is a very adaptable species, which can inhabit a wide variety of ecosystems; once it has been introduced into a habit…","img":"images/816.jpg","thumb":"images/t/816.jpg","file":"LantanaFlowerLeaves.jpg","ar":1.333,"py":"mayingdan myd","cr_by":"Alvesgaspar","cr_lic":"CC BY-SA 3.0","cr_licurl":"http://creativecommons.org/licenses/by-sa/3.0/","habit":"禾草","origin":null},{"id":817,"zh":"马鞭草","en":"Verbena officinalis","sci":"Verbena officinalis","order_en":"Lamiales","order_zh":"唇形目","family_en":"Verbenaceae","family_zh":"马鞭草科","iucn":null,"langs":55,"desc_zh":"马鞭草（学名：Verbena officinalis）为马鞭草科(Verbenaceae)，马鞭草属(Verbena)植物。 英文名称：European Verbena","desc_en":"Verbena officinalis, the common vervain or common verbena, is a perennial herb native to Europe. It grows up to 70 cm (28 in) high, with an upright habitus. The lobed leaves are toothed, and the delicate spikes hold clusters of two-lipped mauve flowers.","img":"images/817.jpg","thumb":"images/t/817.jpg","file":"Eisenkraut, Passau.JPG","ar":0.75,"py":"mabiancao mbc","cr_by":"Konrad Lackerbeck","cr_lic":"CC BY-SA 2.5","cr_licurl":"https://creativecommons.org/licenses/by-sa/2.5","habit":"草本","origin":["欧洲"]},{"id":818,"zh":"柠檬龙至木","en":"Aloysia citrodora","sci":"Aloysia citrodora","order_en":"Lamiales","order_zh":"唇形目","family_en":"Verbenaceae","family_zh":"马鞭草科","iucn":null,"langs":43,"desc_zh":null,"desc_en":"Aloysia citrodora, lemon verbena, is a species of flowering plant in the verbena family Verbenaceae, native to South America. Other common names include lemon beebrush.","img":"images/818.jpg","thumb":"images/t/818.jpg","file":"Aloysia citriodora 002.jpg","ar":0.75,"py":"ningmenglongzhimu nmlzm","cr_by":"H. Zell","cr_lic":"CC BY-SA 3.0","cr_licurl":"https://creativecommons.org/licenses/by-sa/3.0","habit":"禾草","origin":["南美洲"]},{"id":819,"zh":"柳叶马鞭草","en":"Verbena bonariensis","sci":"Verbena bonariensis","order_en":"Lamiales","order_zh":"唇形目","family_en":"Verbenaceae","family_zh":"马鞭草科","iucn":null,"langs":28,"desc_zh":"柳叶马鞭草（学名：Verbena bonariensis）为马鞭草科马鞭草属下的一个种。","desc_en":"This is about the Verbena bonariensis described by Linnaeus. See also below for a common misapplication of this taxon. Verbena bonariensis, commonly known as the purpletop vervain, clustertop vervain, Argentinian vervain, tall verbena or pretty verbena, is a m…","img":"images/819.jpg","thumb":"images/t/819.jpg","file":"Verbena bonariensis.jpg","ar":1.333,"py":"liuyemabiancao lymbc","cr_by":"frank wouters","cr_lic":"CC BY 2.0","cr_licurl":"https://creativecommons.org/licenses/by/2.0","habit":"禾草","origin":["南美洲"]},{"id":820,"zh":"油橄榄","en":"Olea europaea","sci":"Olea europaea","order_en":"Lamiales","order_zh":"唇形目","family_en":"Oleaceae","family_zh":"木樨科","iucn":null,"langs":145,"desc_zh":"油橄榄（学名：Olea europaea，其种加词europaea的意思为欧洲），又称木犀榄，古称齐墩、阿列布，是一种木樨科木樨榄属常绿乔木，果实主要用于榨制橄榄油。《圣经》故事中曾用它的树枝作为大地复苏的标志，后来西方国家把它用作和平象征。本种原产于东地中海盆地的沿海地区（临近的东南欧、西亚和北非沿海地区），以及里海南岸的伊朗北部地区。它的果实，也叫做橄榄，它是地中海地区一种主要的农作物，用来生产橄榄油。","desc_en":"The olive (botanical name Olea europaea, \"European olive\") is a species of subtropical evergreen tree in the family Oleaceae. Originating in Asia Minor, it is abundant throughout the Mediterranean Basin, with wild subspecies in Africa and western Asia; modern…","img":"images/820.jpg","thumb":"images/t/820.jpg","file":"El Perelló - Old olive tree.jpg","ar":1.333,"py":"youganlan ygl","cr_by":"Hans Hillewaert","cr_lic":"CC BY-SA 3.0","cr_licurl":"https://creativecommons.org/licenses/by-sa/3.0","habit":"乔木","origin":["亚洲","欧洲","非洲"]},{"id":821,"zh":"欧洲白蜡树","en":"Fraxinus excelsior","sci":"Fraxinus excelsior","order_en":"Lamiales","order_zh":"唇形目","family_en":"Oleaceae","family_zh":"木樨科","iucn":"NT","langs":74,"desc_zh":"欧洲白蜡树又名欧洲梣（学名：Fraxinus excelsior）是一种梣属落叶乔木，主要分布在欧洲大陆，除斯堪的纳维亚北部和伊比利亚半岛以外均可生长，在亚洲土耳其北部到高加索山一带也分布。 欧洲白蜡树通高30米，冬季有黑色芽苞。每小枝生有羽状小叶9至13枚，长20至30厘米，叶片呈深绿色，秋季变黄。极为耐寒。","desc_en":"Fraxinus excelsior, known as the ash, or European ash or common ash to distinguish it from other types of ash, is a flowering plant species in the olive family Oleaceae.","img":"images/821.jpg","thumb":"images/t/821.jpg","file":"Fraxinus excelsior 001.jpg","ar":1.333,"py":"ouzhoubailashu ozbls","cr_by":"Willow","cr_lic":"CC BY 2.5","cr_licurl":"https://creativecommons.org/licenses/by/2.5","habit":null,"origin":["亚洲","欧洲"]},{"id":822,"zh":"茉莉花","en":"Jasminum sambac","sci":"Jasminum sambac","order_en":"Lamiales","order_zh":"唇形目","family_en":"Oleaceae","family_zh":"木樨科","iucn":null,"langs":56,"desc_zh":"茉莉花（学名：Jasminum sambac，梵语：मल्लिका，罗马化：Mallikā），又称茉莉，为木犀科素馨属的植物，是一种高约1至3公尺的灌木。茉莉花原产于印度，现时世界各地也很广泛地栽培。","desc_en":"Jasminum sambac (Arabian jasmine or Sambac jasmine or Mogra) is a species of jasmine native to Bhutan and India. It is cultivated in many places, especially West Asia, South Asia and Southeast Asia.","img":"images/822.jpg","thumb":"images/t/822.jpg","file":"JasminumSambac.jpg","ar":1.333,"py":"molihua mlh","cr_by":"Taken by Fanghong","cr_lic":"CC BY-SA 3.0","cr_licurl":"http://creativecommons.org/licenses/by-sa/3.0/","habit":"藤本","origin":["亚洲"]},{"id":823,"zh":"欧丁香","en":"Syringa vulgaris","sci":"Syringa vulgaris","order_en":"Lamiales","order_zh":"唇形目","family_en":"Oleaceae","family_zh":"木樨科","iucn":"LC","langs":56,"desc_zh":"欧丁香（学名：Syringa vulgaris），又称丁香、洋丁香，是木犀科丁香属的一个种，原产东南欧。温带地区广泛栽培，包括中国东北、西北、华北、江苏等地。","desc_en":"Syringa vulgaris, the lilac or common lilac, is a species of flowering plant in the olive family, Oleaceae. Native to the Balkan Peninsula, it is widely cultivated for its scented flowers in Europe (particularly the north and west) and North America.","img":"images/823.png","thumb":"images/t/823.png","file":"Lilac Larousse Extracted.png","ar":1.101,"py":"oudingxiang odx","cr_by":"Arbres d'ornement-1 - ornamental trees in colour- Public domain book illustration (visual explanation, informative drawi","cr_lic":"CC0","cr_licurl":"http://creativecommons.org/publicdomain/zero/1.0/deed.en","habit":null,"origin":["欧洲","北美洲"]},{"id":824,"zh":"花梣","en":"Fraxinus ornus","sci":"Fraxinus ornus","order_en":"Lamiales","order_zh":"唇形目","family_en":"Oleaceae","family_zh":"木樨科","iucn":"LC","langs":54,"desc_zh":"花梣（学名：Fraxinus ornus），又名花白蜡，是原产于南欧与西南亚的梣属植物，其分布范围西起西班牙与意大利，北至奥地利与捷克，向东经巴尔干半岛、土耳其、叙利亚西部延伸至黎巴嫩与亚美尼亚。","desc_en":"Fraxinus ornus, the manna ash or South European flowering ash, is a species of Fraxinus native to Southern Europe and Southwestern Asia, from Spain and Italy north to Austria and the Czech Republic, and east through the Balkans, Turkey, and western Syria to Le…","img":"images/824.jpg","thumb":"images/t/824.jpg","file":"(MHNT) Fraxinus ornus - Flowers - Fronton (Haute-Garonne).jpg","ar":1.084,"py":"huaqin hq","cr_by":"Didier Descouens","cr_lic":"CC BY-SA 4.0","cr_licurl":"https://creativecommons.org/licenses/by-sa/4.0","habit":null,"origin":["亚洲","欧洲"]},{"id":825,"zh":"素方花","en":"Jasminum officinale","sci":"Jasminum officinale","order_en":"Lamiales","order_zh":"唇形目","family_en":"Oleaceae","family_zh":"木樨科","iucn":null,"langs":47,"desc_zh":"素方（学名：Jasminum officinale），又名秀英花、蔓茉莉，为木樨科素馨属的一种植物。原产于印度、喜马拉雅山脉、喀什米尔。花期约6－10月，花可提炼香花浸膏做香料原料，并可为茶叶赋香。可通过扦插与压条法繁殖。","desc_en":"Jasminum officinale, known as the common jasmine or simply jasmine, is a species of flowering plant in the olive family Oleaceae. It is native to the Caucasus and parts of Asia, also widely naturalized.","img":"images/825.jpg","thumb":"images/t/825.jpg","file":"Jasminum officinale-IMG 3470.jpg","ar":1,"py":"sufanghua sfh","cr_by":"C T Johansson","cr_lic":"CC BY-SA 3.0","cr_licurl":"https://creativecommons.org/licenses/by-sa/3.0","habit":null,"origin":["亚洲"]},{"id":826,"zh":"穿心莲","en":"Andrographis paniculata","sci":"Andrographis paniculata","order_en":"Lamiales","order_zh":"唇形目","family_en":"Acanthaceae","family_zh":"爵床科","iucn":null,"langs":49,"desc_zh":"穿心莲（学名：Andrographis paniculata）为爵床科一年生草本植物。","desc_en":"Andrographis paniculata, commonly known as creat or green chiretta, is an annual herbaceous plant in the family Acanthaceae, native to India and Sri Lanka. It is widely cultivated in Southern and Southeastern Asia, where it has been believed to be a treatment…","img":"images/826.jpg","thumb":"images/t/826.jpg","file":"Andrographis-paniculata.jpg","ar":1.333,"py":"chuanxinlian cxl","cr_by":"Uwe Thobae","cr_lic":"CC BY-SA 3.0","cr_licurl":"http://creativecommons.org/licenses/by-sa/3.0/","habit":"草本","origin":["亚洲"]},{"id":827,"zh":"蛤蟆花","en":"Acanthus mollis","sci":"Acanthus mollis","order_en":"Lamiales","order_zh":"唇形目","family_en":"Acanthaceae","family_zh":"爵床科","iucn":null,"langs":38,"desc_zh":null,"desc_en":"Acanthus mollis, commonly known as bear's breeches, sea dock, bear's foot plant, sea holly, gator plant or oyster plant, is a species of plant in the family Acanthaceae and is native to the Mediterranean region.","img":"images/827.jpg","thumb":"images/t/827.jpg","file":"Acanthaceae - Acanthus mollis (2).JPG","ar":0.665,"py":"hamahua hmh","cr_by":"Hectonichus","cr_lic":"CC BY-SA 3.0","cr_licurl":"https://creativecommons.org/licenses/by-sa/3.0","habit":"草本","origin":["欧洲"]},{"id":828,"zh":"鸭嘴花","en":"Justicia adhatoda","sci":"Justicia adhatoda","order_en":"Lamiales","order_zh":"唇形目","family_en":"Acanthaceae","family_zh":"爵床科","iucn":"LC","langs":38,"desc_zh":null,"desc_en":"Justicia adhatoda commonly known in English as Malabar nut, adulsa, adhatoda, vasa, vasaka, is native to Asia. Adathoda means 'untouched by goats' in Tamil.","img":"images/828.jpg","thumb":"images/t/828.jpg","file":"Justicia adhatoda - Alipore - Kolkata 2013-02-10 4607.JPG","ar":0.665,"py":"yazuihua yzh","cr_by":"Biswarup Ganguly","cr_lic":"CC BY 3.0","cr_licurl":"https://creativecommons.org/licenses/by/3.0","habit":null,"origin":["亚洲"]},{"id":829,"zh":"翼叶山牵牛","en":"Thunbergia alata","sci":"Thunbergia alata","order_en":"Lamiales","order_zh":"唇形目","family_en":"Acanthaceae","family_zh":"爵床科","iucn":null,"langs":30,"desc_zh":"翼叶山牵牛（学名：Thunbergia alata）是爵床科山牵牛属的植物。分布于热带非洲以及中国大陆的广东、福建等地，目前已由人工引种栽培。","desc_en":"Thunbergia alata, commonly called black-eyed Susan vine, is a herbaceous perennial climbing plant species in the family Acanthaceae. It is native to Eastern Africa, and has been naturalized in other parts of the world.","img":"images/829.jpg","thumb":"images/t/829.jpg","file":"ACANTHACEAE Thunbergia alata Bojer ex Sims, INMA (MBML040839).pdf","ar":0.707,"py":"yiyeshanqianniu yysqn","cr_by":"Instituto Nacional da Mata Atlântica - INMA","cr_lic":"CC BY-SA 4.0","cr_licurl":"https://creativecommons.org/licenses/by-sa/4.0","habit":"藤本","origin":["非洲"]},{"id":830,"zh":"金苞花","en":"Pachystachys lutea","sci":"Pachystachys lutea","order_en":"Lamiales","order_zh":"唇形目","family_en":"Acanthaceae","family_zh":"爵床科","iucn":null,"langs":28,"desc_zh":"金苞花（学名：Pachystachys lutea），别名黄虾花、小虾花、虾子花、金苞虾衣花，原产地为墨西哥、秘鲁及南美洲奎亚那，有二种品种，一种苞片为紫褐色，另一种苞片则为黄色。苞片为黄色者较为常见，花型分为上下两唇，外型酷似橘子片。 金苞花花期较长，从夏至冬，花串寿命长达数周。野生小虾花可长高至2至3呎，而一般家庭所栽种者高多不超过1呎。","desc_en":"Pachystachys lutea, known as the golden shrimp plant or lollipop plant, is a tropical, soft-stemmed evergreen shrub between 0.5 and 2.5 meters tall, native to Peru.","img":"images/830.jpg","thumb":"images/t/830.jpg","file":"PachystachysLuteaOrlando.JPG","ar":1.333,"py":"jinbaohua jbh","cr_by":"UpstateNYer","cr_lic":"CC BY-SA 3.0","cr_licurl":"https://creativecommons.org/licenses/by-sa/3.0","habit":"灌木","origin":["南美洲"]},{"id":831,"zh":"大岩桐","en":"Sinningia speciosa","sci":"Sinningia speciosa","order_en":"Lamiales","order_zh":"唇形目","family_en":"Gesneriaceae","family_zh":"苦苣苔科","iucn":null,"langs":22,"desc_zh":"大岩桐（学名：Sinningia speciosa），大岩桐为园艺贸易的俗称，是苦苣苔科岩桐属的多年生球根花卉家族成员其种加词“speciosa”意为“外表美丽的”。 长大而鲜艳的花朵，所以常用作园艺植物。生长于南美洲巴西的热带草原。大岩桐通常在春、夏季开花，它的抗寒区为10-12。","desc_en":"Sinningia speciosa, sometimes known in the horticultural trade as gloxinia, is a tuberous member of the flowering plant native to Brazil within the family Gesneriaceae. Originally included in the genus Gloxinia in 1817, it was reclassified to Sinningia.","img":"images/831.jpg","thumb":"images/t/831.jpg","file":"Sinningia speciosa-IMG 0659.JPG","ar":1,"py":"dayantong dyt","cr_by":"Christer T Johansson","cr_lic":"CC BY 3.0","cr_licurl":"https://creativecommons.org/licenses/by/3.0","habit":null,"origin":["南美洲"]},{"id":832,"zh":"喜荫花","en":"Episcia cupreata","sci":"Episcia cupreata","order_en":"Lamiales","order_zh":"唇形目","family_en":"Gesneriaceae","family_zh":"苦苣苔科","iucn":null,"langs":16,"desc_zh":"喜荫花（学名：Episcia cupreata）为苦苣苔科喜荫花属下的一个种。","desc_en":"Episcia cupreata is a species of perennial plant in the family Gesneriaceae that is found in Brazil, Colombia, and Venezuela. Its common name is flame violet, although this name may also refer to other species of the genus Episcia.","img":"images/832.jpg","thumb":"images/t/832.jpg","file":"Arya.episcia cupreata viridiflora.bulak.2019.jpg","ar":0.75,"py":"xiyinhua xyh","cr_by":"Aris riyanto","cr_lic":"CC BY-SA 4.0","cr_licurl":"https://creativecommons.org/licenses/by-sa/4.0","habit":"草本","origin":["南美洲"]},{"id":833,"zh":"高山欧洲苣苔","en":"Ramonda myconi","sci":"Ramonda myconi","order_en":"Lamiales","order_zh":"唇形目","family_en":"Gesneriaceae","family_zh":"苦苣苔科","iucn":"LC","langs":16,"desc_zh":null,"desc_en":"Ramonda myconi, the Pyrenean-violet or rosette mullein, syn. R. pyrenaica, is a species of flowering plant in the family Gesneriaceae, which is a relictual endemite of shady, rocky places in the Pyrenees and north eastern Spain.","img":"images/833.jpg","thumb":"images/t/833.jpg","file":"RAMONDA MYCONI - LA CORRIU - IB-467 (Orella d'ós).JPG","ar":0.75,"py":"gaoshanouzhoujutai gsozjt","cr_by":"Isidre blanc","cr_lic":"CC BY-SA 4.0","cr_licurl":"https://creativecommons.org/licenses/by-sa/4.0","habit":"草本","origin":null},{"id":834,"zh":"非洲堇属","en":"Saintpaulia ionantha","sci":"Saintpaulia ionantha","order_en":"Lamiales","order_zh":"唇形目","family_en":"Gesneriaceae","family_zh":"苦苣苔科","iucn":"NT","langs":15,"desc_zh":null,"desc_en":"Streptocarpus ionanthus (synonym Saintpaulia ionantha) is a species of Streptocarpus in the section Saintpaulia, commonly known as an African violet. It is native to eastern and southwestern Tanzania.","img":"images/834.jpg","thumb":"images/t/834.jpg","file":"2007-04-20Saintpaulia ionantha04.jpg","ar":1.342,"py":"feizhoujinshu fzjs","cr_by":"Wildfeuer","cr_lic":"CC BY-SA 3.0","cr_licurl":"https://creativecommons.org/licenses/by-sa/3.0","habit":null,"origin":["非洲"]},{"id":835,"zh":"Ramonda nathaliae","en":"Ramonda nathaliae","sci":"Ramonda nathaliae","order_en":"Lamiales","order_zh":"唇形目","family_en":"Gesneriaceae","family_zh":"苦苣苔科","iucn":null,"langs":14,"desc_zh":null,"desc_en":"Ramonda nathaliae or Natalie's ramonda (Serbian: Наталијина рамонда, romanized: Natalijina ramonda; Macedonian: Наталиева рамонда, romanized: Natalieva ramonda) is a species of flowering plant in the family Gesneriaceae.","img":"images/835.jpg","thumb":"images/t/835.jpg","file":"Ramonda nathaliae.jpg","ar":1.333,"py":"","cr_by":"Francine Riez","cr_lic":"CC BY-SA 3.0","cr_licurl":"https://creativecommons.org/licenses/by-sa/3.0","habit":null,"origin":null},{"id":836,"zh":"欧洲冬青","en":"Ilex aquifolium","sci":"Ilex aquifolium","order_en":"Aquifoliales","order_zh":"冬青目","family_en":"Aquifoliaceae","family_zh":"冬青科","iucn":"LC","langs":63,"desc_zh":"欧洲冬青（学名Ilex aquifolium）是一种原产于西欧及南欧、西北非洲及西南亚洲的冬青。 欧洲冬青是常绿树，高达10-25米，树干直径40-80厘米阔，树皮呈灰色及光滑。叶子长5-12厘米及阔2-6厘米，形状各有不同。幼树及低枝上的叶子每边有3-5条尖刺，交替指向上下；在较高的树枝上的叶子有很少或没有尖刺。 花朵是雌雄异株的，呈白色及有4瓣，由蜜蜂传播花粉。果实呈红色，直径阔6-10毫米，有4个果核，一般在秋末成熟。","desc_en":"Ilex aquifolium, the holly, common holly, English holly, European holly, or occasionally Christmas holly, is a species of flowering plant in the family Aquifoliaceae, native to western and southern Europe, northwest Africa, and southwest Asia.","img":"images/836.jpg","thumb":"images/t/836.jpg","file":"Illustration Ilex aquifolium0.jpg","ar":0.596,"py":"ouzhoudongqing ozdq","cr_by":null,"cr_lic":"Public domain","cr_licurl":null,"habit":"乔木","origin":["亚洲","欧洲","非洲"]},{"id":837,"zh":"巴拉圭冬青","en":"yerba mate","sci":"Ilex paraguariensis","order_en":"Aquifoliales","order_zh":"冬青目","family_en":"Aquifoliaceae","family_zh":"冬青科","iucn":"NT","langs":58,"desc_zh":"巴拉圭冬青（学名：Ilex paraguariensis），为冬青科冬青属植物。原产于南美洲的亚热带地区，包括阿根廷北部、巴拉圭、乌拉圭、巴西南部及玻利维亚。将巴拉圭冬青干燥的叶片浸泡在热水中，所泡出来的茶汤称为玛黛茶（港台译作：玛黛茶；也称巴拉圭茶（Paraguay tea）、巴西茶（Brazilian tea）），含有咖啡因、鞣酸，是一种兴奋饮料，其咖啡因含量比等量的绿茶稍高，收敛性较茶弱。","desc_en":"Yerba mate or yerba maté ( YUR-bə MAH-tay), Ilex paraguariensis, is a plant species of the holly genus native to South America. The leaves of the plant can be steeped in hot water to make a beverage known as mate. Brewed cold, it is used to make tereré.","img":"images/837.jpg","thumb":"images/t/837.jpg","file":"Ilex paraguariensis - Köhler–s Medizinal-Pflanzen-074.jpg","ar":0.691,"py":"balaguidongqing blgdq","cr_by":"Franz Eugen Köhler, Köhler's Medizinal-Pflanzen","cr_lic":"Public domain","cr_licurl":null,"habit":null,"origin":["南美洲"]},{"id":838,"zh":"齿叶冬青","en":"Ilex crenata","sci":"Ilex crenata","order_en":"Aquifoliales","order_zh":"冬青目","family_en":"Aquifoliaceae","family_zh":"冬青科","iucn":null,"langs":21,"desc_zh":"齿叶冬青（学名：Ilex crenata，又名日本冬青）是冬青科冬青属的植物。分布于日本、欧美、台湾以及中国大陆东部等地，生长于海拔700米至2 100米的地区，常生长在山谷杂木林中、灌丛中、山顶灌丛中或石边。","desc_en":"Ilex crenata, also known as Japanese holly or box-leaved holly, is a species of flowering plant in the family Aquifoliaceae, native to East and Southeast Asia.","img":"images/838.jpg","thumb":"images/t/838.jpg","file":"Ilex Crenata5.jpg","ar":0.791,"py":"chiyedongqing cydq","cr_by":"KENPEI","cr_lic":"CC BY-SA 3.0","cr_licurl":"http://creativecommons.org/licenses/by-sa/3.0/","habit":null,"origin":["亚洲"]},{"id":839,"zh":"Ilex guayusa","en":"Ilex guayusa","sci":"Ilex guayusa","order_en":"Aquifoliales","order_zh":"冬青目","family_en":"Aquifoliaceae","family_zh":"冬青科","iucn":"LC","langs":19,"desc_zh":null,"desc_en":"Ilex guayusa ( or ) is a species of tree in the holly family, Aquifoliaceae. It is native to the Amazon rainforest. One of four known caffeinated holly trees, the leaves of the guayusa tree are harvested fresh and brewed like a tea for their stimulative effect…","img":"images/839.jpg","thumb":"images/t/839.jpg","file":"View of Ilex guayusa from above.jpg","ar":1.333,"py":"","cr_by":"Anna Premo","cr_lic":"FAL","cr_licurl":"http://artlibre.org/licence/lal/en","habit":"乔木","origin":["南美洲"]},{"id":840,"zh":"向日葵","en":"common sunflower","sci":"Helianthus annuus","order_en":"Asterales","order_zh":"菊目","family_en":"Asteraceae","family_zh":"菊科","iucn":"LC","langs":138,"desc_zh":"向日葵（学名：Helianthus annuus），别名向阳花、朝阳花、日头花、葵花、文菊，是一种大型菊科向日葵属植物。因用其果实榨取的食用油和果实具备较高经济价值，而被认为是一种经济作物。 向日葵也常被野生鸟类作为食物和牲畜饲料（作为膳食或青贮）。向日葵还常作为一种花园观赏植物被用于园艺种植。该植物最早是在美洲被人类驯化；16世纪，葵花籽从美洲被带到了欧洲，并在欧洲成为一种被广泛使用的烹饪原料。","desc_en":"The common sunflower (Helianthus annuus) is a large annual forb in the daisy family Asteraceae. The domesticated form of common sunflower is harvested for its edible seeds, which come in two types: oil and confectionary seeds.","img":"images/840.jpg","thumb":"images/t/840.jpg","file":"Helianthus annuus exposed 2004-05-22.jpg","ar":0.75,"py":"xiangrikui xrk","cr_by":"Jon Sullivan","cr_lic":"Public domain","cr_licurl":null,"habit":"草本","origin":null},{"id":841,"zh":"莴苣","en":"Lactuca sativa","sci":"Lactuca sativa","order_en":"Asterales","order_zh":"菊目","family_en":"Asteraceae","family_zh":"菊科","iucn":null,"langs":126,"desc_zh":"莴苣（学名：Lactuca sativa），又名生菜、莴菜、春菜，是菊科莴苣属之一年生或二年生草本植物，原产于地中海一带，因适应性佳而目前普及温带、亚热带地区。","desc_en":"Lettuce (Lactuca sativa) is an annual plant of the family Asteraceae mostly grown as a leaf vegetable. The leaves are most often used raw in green salads, although lettuce is also seen in other kinds of food, such as sandwiches, wraps and soups; it can also be…","img":"images/841.jpg","thumb":"images/t/841.jpg","file":"Iceberg lettuce in SB.jpg","ar":1.333,"py":"woju wj","cr_by":"en:User:Geographer","cr_lic":"CC BY 1.0","cr_licurl":"https://creativecommons.org/licenses/by/1.0","habit":"多肉","origin":null},{"id":842,"zh":"药用蒲公英","en":"common dandelion","sci":"Taraxacum officinale","order_en":"Asterales","order_zh":"菊目","family_en":"Asteraceae","family_zh":"菊科","iucn":null,"langs":97,"desc_zh":"西洋蒲公英（学名：Taraxacum officinale）又名药用蒲公英，菊科蒲公英属植物，因其繁殖能力强而在世界各地均被视为野草，在全球多个平原及温带地区均有其影踪。分布于北美洲、吉尔吉斯斯坦、哈萨克斯坦、欧洲以及中国大陆的新疆等地，生长于海拔700米至2,200米的地区，多生在低山草原、森林草甸以及田间与路边。此外也有人将其视为药草的一种。","desc_en":"Taraxacum officinale, the dandelion or common dandelion, is a herbaceous perennial flowering plant in the daisy family, Asteraceae. The common dandelion is well-known for its yellow flower heads that turn into round balls of many silver-tufted fruit, which dis…","img":"images/842.jpg","thumb":"images/t/842.jpg","file":"Maskros 2.jpg","ar":0.711,"py":"yaoyongpugongying yypgy","cr_by":null,"cr_lic":"CC BY-SA 3.0","cr_licurl":"http://creativecommons.org/licenses/by-sa/3.0/","habit":"草本","origin":["亚洲"]},{"id":843,"zh":"蓍","en":"Achillea millefolium","sci":"Achillea millefolium","order_en":"Asterales","order_zh":"菊目","family_en":"Asteraceae","family_zh":"菊科","iucn":"LC","langs":95,"desc_zh":"洋蓍草（学名：Achillea millefolium，拼音：shī ㄕ），又名欧蓍、千叶蓍、锯草、西洋蓍草、羽衣草、魔鬼荨麻，是菊科蓍属的多年生草本植物。分布在蒙古、伊朗、欧洲、俄罗斯、非洲以及中国大陆的东北、内蒙古、新疆等地，生长于海拔200米至2,300米的地区，见于湿草地、荒地和铁路沿线，目前已由人工引种栽培。","desc_en":"Achillea millefolium, commonly known as yarrow () or common yarrow, is a flowering plant in the family Asteraceae. Growing to 1 metre (3+1⁄3 feet) tall, it is characterized by small whitish flowers, a tall stem of fernlike leaves, and a pungent odor.","img":"images/843.jpg","thumb":"images/t/843.jpg","file":"Achillea millefolium vallee-de-grace-amiens 80 22062007 1.jpg","ar":0.669,"py":"shi s","cr_by":"O. Pichard","cr_lic":"CC BY-SA 3.0","cr_licurl":"https://creativecommons.org/licenses/by-sa/3.0","habit":null,"origin":["亚洲","北美洲"]},{"id":844,"zh":"菊苣","en":"Cichorium intybus","sci":"Cichorium intybus","order_en":"Asterales","order_zh":"菊目","family_en":"Asteraceae","family_zh":"菊科","iucn":null,"langs":94,"desc_zh":"菊苣（学名：Cichorium intybus），又称苦苣、苦菜，是一种灌木丛生的多年生草本植物，长出蓝色或薰衣草色的小花。原生于欧洲，但现时已自然生长于北美等地而成为路边物种。经烘焙及磨碎后的根部广泛用作咖啡代用品起源于地中海，但现在在全球，特别是美国南部的新奥尔良地区、印度及东南亚也广受欢迎。与此同时，它也是制作红眼肉汁的主要材料。 常见的菊苣有多个名称，包括blue sailors、succory、coffeeweed等。","desc_en":"Common chicory (Cichorium intybus) is a somewhat woody, perennial herbaceous plant of the family Asteraceae, usually with bright blue flowers, rarely white or pink.","img":"images/844.jpg","thumb":"images/t/844.jpg","file":"Illustration Cichorium intybus0 clean.jpg","ar":0.612,"py":"juju jj","cr_by":"Original book source: Prof. Dr. Otto Wilhelm Thomé Flora von Deutschland, Österreich und der Schweiz 1885, Gera, Germany","cr_lic":"Public domain","cr_licurl":null,"habit":"草本","origin":["亚洲","欧洲","非洲","大洋洲"]},{"id":845,"zh":"雏菊","en":"Bellis perennis","sci":"Bellis perennis","order_en":"Asterales","order_zh":"菊目","family_en":"Asteraceae","family_zh":"菊科","iucn":null,"langs":94,"desc_zh":"雏菊（学名：Bellis perennis）是菊科雏菊属的一种，别名长命菊、延命菊，原产于欧洲，原种被视为丛生的杂草，开花期在春季。 雏菊在原产地是多年生草本植物，学名的种加词perennis也含有「多年生的」的意思，但在日本由于夏季炎热，雏菊多半活不过夏季，通常被当作秋天播种的一年生植物。雏菊在能够渡夏的寒冷地区可以进行分枝繁殖。","desc_en":"Bellis perennis ( BEL-iss pə-REN-iss), the daisy, is a European species of the family Asteraceae, often considered the archetypal species of the name daisy.","img":"images/845.jpg","thumb":"images/t/845.jpg","file":"Belis peremnis - panoramio.jpg","ar":1.333,"py":"chuju cj","cr_by":"m.dolores paderne sa…","cr_lic":"CC BY-SA 3.0","cr_licurl":"https://creativecommons.org/licenses/by-sa/3.0","habit":null,"origin":["欧洲"]},{"id":846,"zh":"中亚苦蒿","en":"Artemisia absinthium","sci":"Artemisia absinthium","order_en":"Asterales","order_zh":"菊目","family_en":"Asteraceae","family_zh":"菊科","iucn":null,"langs":93,"desc_zh":"中亚苦蒿（学名：Artemisia absinthium）为菊科蒿属的植物。分布于欧洲、克什米尔、非洲、阿富汗、伊朗、俄罗斯、北美洲、印度、巴基斯坦以及中国大陆的新疆等地，生长于海拔1,100米至1,500米的地区，多生长于山坡、林缘、野果林、草原及灌丛地等）。是酿造苦艾酒的原料之一。","desc_en":"Artemisia absinthium, otherwise known as common wormwood, is a species of Artemisia native to North Africa and temperate regions of Eurasia, and widely naturalized in Canada and the northern United States.","img":"images/846.jpg","thumb":"images/t/846.jpg","file":"Artemisia absinthium P1210748.jpg","ar":0.75,"py":"zhongyakuhao zykh","cr_by":"David Monniaux","cr_lic":"CC BY-SA 3.0","cr_licurl":"http://creativecommons.org/licenses/by-sa/3.0/","habit":null,"origin":["亚洲","非洲","北美洲"]},{"id":847,"zh":"洋姜","en":"Helianthus tuberosus","sci":"Helianthus tuberosus","order_en":"Asterales","order_zh":"菊目","family_en":"Asteraceae","family_zh":"菊科","iucn":"LC","langs":91,"desc_zh":"菊芋（学名：Helianthus tuberosus，英语：Jerusalem artichoke）也称洋姜、鬼子姜、姜不辣、块茎向日葵，是一种菊科向日葵属宿根性草本植物。原产北美洲中部，十七世纪传入欧洲，后传入中国。","desc_en":"The Jerusalem artichoke (Helianthus tuberosus), also called sunroot, sunchoke, wild sunflower, topinambur, or earth apple, is a species of sunflower native to central North America.","img":"images/847.jpg","thumb":"images/t/847.jpg","file":"Sunroot top.jpg","ar":0.75,"py":"yangjiang yj","cr_by":null,"cr_lic":"CC BY-SA 3.0","cr_licurl":"http://creativecommons.org/licenses/by-sa/3.0/","habit":null,"origin":["北美洲"]},{"id":848,"zh":"款冬","en":"Tussilago farfara","sci":"Tussilago farfara","order_en":"Asterales","order_zh":"菊目","family_en":"Asteraceae","family_zh":"菊科","iucn":null,"langs":85,"desc_zh":"款冬（学名：Tussilago farfara），别名冬花、款冬蒲公英 多年生草本植物，广卵形至心脏形叶子丛生，边缘有波状疏锯齿，下面密被白色棉毛；冬季花茎先叶出现，顶生头状花序，周围为黄色舌状花，中央为管状花；细小瘦果。 原产于中国、欧洲和非洲北部，日本也有生长。","desc_en":"Tussilago farfara, commonly known as coltsfoot, is a plant in the tribe Senecioneae in the family Asteraceae, native to Europe and parts of western and central Asia.","img":"images/848.jpg","thumb":"images/t/848.jpg","file":"Coltsfoot.jpg","ar":1.321,"py":"kuandong kd","cr_by":"Andreas Trepte","cr_lic":"CC BY-SA 2.5","cr_licurl":"https://creativecommons.org/licenses/by-sa/2.5","habit":null,"origin":["亚洲","欧洲"]},{"id":849,"zh":"北艾","en":"Artemisia vulgaris","sci":"Artemisia vulgaris","order_en":"Asterales","order_zh":"菊目","family_en":"Asteraceae","family_zh":"菊科","iucn":null,"langs":85,"desc_zh":"北艾（学名：Artemisia vulgaris）为菊科蒿属的植物。分布在加拿大、蒙古、俄罗斯、北美洲、大西洋、欧洲、美国以及中国大陆的青海、新疆、四川、甘肃、陕西等地，生长于海拔1,500米至2,100米的地区，一般生于谷地、森林草原、亚高山地区的草原、林缘、荒坡和路旁等处，目前尚未由人工引种栽培。","desc_en":"Artemisia vulgaris, commonly known as mugwort, common mugwort, or wormwood, is a species of flowering plant in the daisy family Asteraceae. It is one of several species in the genus Artemisia commonly known as mugwort, although Artemisia vulgaris is the specie…","img":"images/849.jpg","thumb":"images/t/849.jpg","file":"Artemisia vulgaris - Köhler–s Medizinal-Pflanzen-016.jpg","ar":0.728,"py":"beiai ba","cr_by":"Franz Eugen Köhler, Köhler's Medizinal-Pflanzen","cr_lic":"Public domain","cr_licurl":null,"habit":null,"origin":null},{"id":850,"zh":"红花","en":"Carthamus tinctorius","sci":"Carthamus tinctorius","order_en":"Asterales","order_zh":"菊目","family_en":"Asteraceae","family_zh":"菊科","iucn":null,"langs":81,"desc_zh":"红花（学名：Carthamus tinctorius)，又名红蓝花，属菊科植物。原产于亚洲和非洲地区，在埃及已有四千年栽培历史。如今在全球都有栽培，其中印度栽培规模最大。","desc_en":"Safflower (Carthamus tinctorius), also false saffron, is a highly branched, herbaceous, thistle-like annual plant in the family Asteraceae. It is one of the world's oldest crops; today, it is commercially cultivated for vegetable oil extracted from the seeds.","img":"images/850.jpg","thumb":"images/t/850.jpg","file":"Safflower.jpg","ar":1.131,"py":"honghua hh","cr_by":null,"cr_lic":"Copyrighted free use","cr_licurl":null,"habit":"草本","origin":null},{"id":851,"zh":"龙蒿","en":"tarragon","sci":"Artemisia dracunculus","order_en":"Asterales","order_zh":"菊目","family_en":"Asteraceae","family_zh":"菊科","iucn":null,"langs":80,"desc_zh":"龙蒿（学名：Artemisia dracunculus）又称香艾菊、狭叶青蒿、蛇蒿、椒蒿、青蒿、他拉根香草，菊科多年生草本植物，原产于西伯利亚和西亚。阿拉伯人统治西班牙时期，才引入欧洲。中文圈里，俗误称为茵陈蒿。","desc_en":"Tarragon (Artemisia dracunculus), also known as estragon, is a species of perennial herb in the family Asteraceae. It is widespread in the wild across much of Eurasia and North America and is cultivated for culinary and medicinal purposes.","img":"images/851.jpg","thumb":"images/t/851.jpg","file":"Artemisia dracunculus1.jpg","ar":0.743,"py":"longhao lh","cr_by":"KENPEI","cr_lic":"CC BY-SA 3.0","cr_licurl":"http://creativecommons.org/licenses/by-sa/3.0/","habit":"草本","origin":["亚洲","北美洲"]},{"id":852,"zh":"矢车菊","en":"Centaurea cyanus","sci":"Centaurea cyanus","order_en":"Asterales","order_zh":"菊目","family_en":"Asteraceae","family_zh":"菊科","iucn":null,"langs":80,"desc_zh":"矢车菊（学名：Centaurea cyanus）是菊科矢车菊属植物，又名蓝芙蓉、车轮花，也称矢车草。","desc_en":"Centaurea cyanus, commonly known as cornflower or bachelor's button (among other names), is an annual flowering plant in the family Asteraceae native to Europe.","img":"images/852.jpg","thumb":"images/t/852.jpg","file":"CentaureaCyanus-bloem-kl.jpg","ar":1.333,"py":"shicheju scj","cr_by":"TeunSpaans","cr_lic":"CC BY-SA 3.0","cr_licurl":"http://creativecommons.org/licenses/by-sa/3.0/","habit":"草本","origin":["欧洲"]},{"id":853,"zh":"金盏花","en":"Calendula officinalis","sci":"Calendula officinalis","order_en":"Asterales","order_zh":"菊目","family_en":"Asteraceae","family_zh":"菊科","iucn":null,"langs":79,"desc_zh":"金盏花（学名：Calendula officinalis）又名金盏菊，为菊科金盏花属的一种，可能原产南欧，但在古代、近代就已引入世界各地，用于观赏、药用、染料及化妆品。","desc_en":"Calendula officinalis, Mary's gold, common marigold, the pot marigold, Scotch marigold, or ruddles, is a flowering plant in the daisy family, Asteraceae. It is probably native to southern Europe, but its long history of cultivation makes its precise origin unk…","img":"images/853.jpg","thumb":"images/t/853.jpg","file":"Calendula officinalis - Köhler–s Medizinal-Pflanzen-024.jpg","ar":0.706,"py":"jinzhanhua jzh","cr_by":"Franz Eugen Köhler, Köhler's Medizinal-Pflanzen","cr_lic":"Public domain","cr_licurl":null,"habit":null,"origin":["欧洲"]},{"id":854,"zh":"德国洋甘菊","en":"Matricaria chamomilla","sci":"Matricaria chamomilla","order_en":"Asterales","order_zh":"菊目","family_en":"Asteraceae","family_zh":"菊科","iucn":null,"langs":79,"desc_zh":"德国洋甘菊又名母菊（学名：Matricaria chamomilla or Matricaria recutita），其气味带著微甜的香辛料味，比罗马洋甘菊的气味柔和。可制作香料和精油。分布于亚洲、欧洲以及新疆等地，目前产地为埃及、法国、德国和摩洛哥。精油以水蒸气蒸馏法制取，外观呈深蓝色，具有浓厚香甜味，挥发度中等，中强度。","desc_en":"Matricaria chamomilla (synonym: Matricaria recutita), commonly known as chamomile (also spelled camomile), German chamomile, Hungarian chamomile (kamilla), wild chamomile, blue chamomile, or scented mayweed, is an annual plant of the composite family Asteracea…","img":"images/854.jpg","thumb":"images/t/854.jpg","file":"Matricaria recutita 0.1 R.jpg","ar":1.333,"py":"deguoyangganju dgygj","cr_by":"Rob Hille","cr_lic":"Public domain","cr_licurl":null,"habit":"草本","origin":null},{"id":855,"zh":"牛蒡","en":"Arctium lappa","sci":"Arctium lappa","order_en":"Asterales","order_zh":"菊目","family_en":"Asteraceae","family_zh":"菊科","iucn":null,"langs":73,"desc_zh":"牛蒡（学名：Arctium lappa；英语：greater burdock；gobō (日语：牛蒡／ゴボウ)；edible burdock；lappa；beggar's buttons；thorny burr；happy major）是菊科牛蒡属的植物。中国各地普遍分布。","desc_en":"Arctium lappa, commonly called greater burdock, gobō (牛蒡/ゴボウ), edible burdock, lappa, beggar's buttons, thorny burr, or happy major is a Eurasian species of plants in the family Asteraceae.","img":"images/855.jpg","thumb":"images/t/855.jpg","file":"ArctiumLappa1.jpg","ar":0.885,"py":"niubang nb","cr_by":"Christian Fischer","cr_lic":"CC BY-SA 3.0","cr_licurl":"https://creativecommons.org/licenses/by-sa/3.0","habit":null,"origin":["亚洲","北美洲","大洋洲"]},{"id":856,"zh":"高山火绒草","en":"edelweiss","sci":"Leontopodium nivale","order_en":"Asterales","order_zh":"菊目","family_en":"Asteraceae","family_zh":"菊科","iucn":null,"langs":66,"desc_zh":"高山火绒草（学名：Leontopodium alpinum）是菊科，火绒草属植物。又叫做高山薄雪草、雪绒花、小白花等。是欧洲著名的高山花卉。","desc_en":"Leontopodium nivale, commonly called edelweiss (lit. 'noble white') (English: AY-dəl-vyss; German: Edelweiß [ˈeːdl̩vaɪs] or Alpen-Edelweiß), is a mountain flower belonging to the daisy or sunflower family Asteraceae.","img":"images/856.jpg","thumb":"images/t/856.jpg","file":"Alpen Edelweiß, Leontopodium alpinum 2.JPG","ar":1.506,"py":"gaoshanhuorongcao gshrc","cr_by":"Böhringer Friedrich","cr_lic":"CC BY-SA 2.5","cr_licurl":"https://creativecommons.org/licenses/by-sa/2.5","habit":null,"origin":["欧洲"]},{"id":857,"zh":"丝路蓟","en":"Cirsium arvense","sci":"Cirsium arvense","order_en":"Asterales","order_zh":"菊目","family_en":"Asteraceae","family_zh":"菊科","iucn":null,"langs":62,"desc_zh":"丝路蓟（学名：Cirsium arvense），又名田蓟或加拿大蓟，是一种分布在欧洲及亚洲北部的蓟属，并且广泛引进到其他地方。虽然在北美洲一般称它为加拿大蓟，但是并非来自加拿大。 丝路蓟下有两个变种： Cirsium arvense var. arvense：分布在欧洲大部份地方。叶子下方没有毛。 Cirsium arvense var. incanum：分布在欧洲南部。叶子下方有厚毛。","desc_en":"Cirsium arvense is a perennial species of flowering plant in the family Asteraceae, native throughout Europe and western Asia, northern Africa and widely introduced elsewhere. The standard English name in its native area is creeping thistle.","img":"images/857.jpg","thumb":"images/t/857.jpg","file":"20200701Cirsium arvense1.jpg","ar":1.333,"py":"siluji slj","cr_by":"AnRo0002","cr_lic":"CC0","cr_licurl":"http://creativecommons.org/publicdomain/zero/1.0/deed.en","habit":"草本","origin":["亚洲","欧洲","非洲"]},{"id":858,"zh":"苦苣菜","en":"Sonchus oleraceus","sci":"Sonchus oleraceus","order_en":"Asterales","order_zh":"菊目","family_en":"Asteraceae","family_zh":"菊科","iucn":null,"langs":60,"desc_zh":"苦菜（学名：Sonchus oleraceus），又名苦苣菜、滇苦荬菜、苦滇菜，为菊科苦苣菜属的植物。原产于欧洲和西亚，后来扩散到全球，生长于海拔170米至3,200米的地区，多生长在林下、山坡、平地田间、空旷处、山谷林缘或近水处。","desc_en":"Sonchus oleraceus is a species of flowering plant in the tribe Cichorieae of the family Asteraceae, native to Europe and Western Asia. It has many common names including common sowthistle, sow thistle, smooth sow thistle, annual sow thistle, puha (in New Zeala…","img":"images/858.jpg","thumb":"images/t/858.jpg","file":"Sónchus oleraceus.jpg","ar":1.331,"py":"kujucai kjc","cr_by":"T.Voekler","cr_lic":"CC BY-SA 3.0","cr_licurl":"https://creativecommons.org/licenses/by-sa/3.0","habit":"草本","origin":["亚洲","欧洲"]},{"id":859,"zh":"法兰西菊","en":"Leucanthemum vulgare","sci":"Leucanthemum vulgare","order_en":"Asterales","order_zh":"菊目","family_en":"Asteraceae","family_zh":"菊科","iucn":null,"langs":59,"desc_zh":"法国菊（学名：Leucanthemum vulgare），又名法兰西菊、滨菊、春白菊、牛眼菊（英语：oxeye daisy）、玛格丽特（法语：Marguerite commune），是原产于欧洲及亚洲温带的菊科植物。 法国菊是多年生草本植物，在茎的顶端有细小的头状花序（不多于5厘米），由约20支白色舌状花及大量黄色心花所组成。茎多是没有分枝及从根上向侧生长。叶子两面均呈墨绿色。基生叶及中叶有柄，呈倒卵形至匙形，并有锯齿。","desc_en":"Leucanthemum vulgare, commonly known as the ox-eye daisy, oxeye daisy, dog daisy, marguerite (French: Marguerite commune, \"common marguerite\") and other common names, is a widespread flowering plant native to Europe and the temperate regions of Asia, and an in…","img":"images/859.jpg","thumb":"images/t/859.jpg","file":"Leucanthemum vulgare15.06.07.JPG","ar":1.333,"py":"falanxiju flxj","cr_by":"Victor M. Vicente Selvas","cr_lic":"Public domain","cr_licurl":null,"habit":null,"origin":["亚洲","欧洲","北美洲","大洋洲"]},{"id":860,"zh":"水飞蓟","en":"Silybum marianum","sci":"Silybum marianum","order_en":"Asterales","order_zh":"菊目","family_en":"Asteraceae","family_zh":"菊科","iucn":"LC","langs":58,"desc_zh":"水飞蓟（学名：Silybum marianum），又名乳蓟，为菊科水飞蓟属下的一个植物种，是种中药材和食材。","desc_en":"Silybum marianum is a species of thistle. It has various common names including milk thistle, blessed milkthistle, Marian thistle, Mary thistle, Saint Mary's thistle, Mediterranean milk thistle, variegated thistle and Scotch thistle (not to be confused with On…","img":"images/860.jpg","thumb":"images/t/860.jpg","file":"Milk thistle.jpg","ar":1.499,"py":"shuifeiji sfj","cr_by":"fir0002 flagstaffotos [at] gmail.com Canon 20D + Tamron 28-75mm f/2.8","cr_lic":"GFDL 1.2","cr_licurl":"http://www.gnu.org/licenses/old-licenses/fdl-1.2.html","habit":"草本","origin":["欧洲"]},{"id":861,"zh":"菊蒿","en":"Tanacetum vulgare","sci":"Tanacetum vulgare","order_en":"Asterales","order_zh":"菊目","family_en":"Asteraceae","family_zh":"菊科","iucn":null,"langs":58,"desc_zh":"菊蒿（学名：Tanacetum vulgare）为菊科菊蒿属的多年生草本开花植物，原产于温带欧洲和亚洲，生长于海拔250米至2,400米的地区，一般生长在山坡、草地、丘陵地、河滩和桦木林下。 它已被引入世界其他地区，包括北美，并且在某些地区已成为入侵性的。","desc_en":"Tansy (Tanacetum vulgare) is a perennial, herbaceous flowering plant in the genus Tanacetum in the family Asteraceae, native to temperate Europe and Asia. It has been introduced to other parts of the world, including Australia and North and South America, and…","img":"images/861.jpg","thumb":"images/t/861.jpg","file":"Tanacetum vulgare - harilik soolikarohi Keilas2.jpg","ar":0.667,"py":"juhao jh","cr_by":"Ivar Leidus","cr_lic":"CC BY-SA 3.0","cr_licurl":"https://creativecommons.org/licenses/by-sa/3.0","habit":"草本","origin":["亚洲","欧洲"]},{"id":862,"zh":"万寿菊","en":"Tagetes erecta","sci":"Tagetes erecta","order_en":"Asterales","order_zh":"菊目","family_en":"Asteraceae","family_zh":"菊科","iucn":null,"langs":55,"desc_zh":"万寿菊（学名：Tagetes erecta，为菊科万寿菊属的植物。原产墨西哥，在中国各地都有人栽培用于观赏，可生长在海拔1150米至1480米的地区，多生在路边草甸。万寿菊常于春天播种，因其花大、花期长，故常用于花坛布景。 现在万寿菊用来提炼食用色素E161b。","desc_en":"Tagetes erecta, the Aztec marigold, Mexican marigold, big marigold, cempaxochitl or cempasúchil, is a species of flowering plant in the genus Tagetes native to Mexico and Central America.","img":"images/862.jpg","thumb":"images/t/862.jpg","file":"Aztec Marigold Tagetes erecta.jpg","ar":1.059,"py":"wanshouju wsj","cr_by":"HitroMilanese","cr_lic":"CC BY-SA 3.0","cr_licurl":"https://creativecommons.org/licenses/by-sa/3.0","habit":null,"origin":["非洲","北美洲"]},{"id":863,"zh":"苦苣","en":"Cichorium endivia","sci":"Cichorium endivia","order_en":"Asterales","order_zh":"菊目","family_en":"Asteraceae","family_zh":"菊科","iucn":null,"langs":53,"desc_zh":"苦苣（学名：Cichorium endivia），又称苦菊、苦白菜，为菊科菊苣属的植物，是一种栽培菊苣。分布在南欧、北美及亚洲等地，目前已由人工引种栽培，基生叶有苦味，软化后苦味减少而柔软，性喜冷凉气候，初夏抽花茎，可生食凉拌，有抗菌、解热、消炎、明目等作用。","desc_en":"Cichorium endivia is a species of flowering plant belonging to the genus Cichorium. It is widely cultivated as one of the species of similar bitter-leafed vegetables known as endive and escarole. There is considerable confusion between the species and C.","img":"images/863.jpg","thumb":"images/t/863.jpg","file":"Friseesalat1 (fcm).jpg","ar":1.259,"py":"kuju kj","cr_by":"Photograph: Frank C. Müller , Baden-Baden","cr_lic":"CC BY-SA 3.0","cr_licurl":"https://creativecommons.org/licenses/by-sa/3.0","habit":null,"origin":null},{"id":864,"zh":"山金车","en":"Arnica montana","sci":"Arnica montana","order_en":"Asterales","order_zh":"菊目","family_en":"Asteraceae","family_zh":"菊科","iucn":"LC","langs":51,"desc_zh":"山金车（学名：Arnica Montana）是一种源于中欧以及西伯利亚高原地区的的菊科植物，在缓解肌肉和关节疼痛及炎症方面具有悠久历史。近年全球有多项针对山金车疗效的基础医学及临床研究，证实山金车除了有消炎镇痛的疗效外，更具有促进受伤组织痊愈的效能，因而受到科研及医药业界的注视。","desc_en":"Arnica montana, also known as leopard's bane, mountain tobacco and mountain arnica, is a moderately toxic European flowering plant in the daisy family Asteraceae that has a large yellow flower head.","img":"images/864.jpg","thumb":"images/t/864.jpg","file":"00 2245 Echte Arnika (Arnica montana).jpg","ar":1.499,"py":"shanjinche sjc","cr_by":"W. Bulach","cr_lic":"CC BY-SA 4.0","cr_licurl":"https://creativecommons.org/licenses/by-sa/4.0","habit":null,"origin":["欧洲"]},{"id":865,"zh":"翼蓟","en":"Cirsium vulgare","sci":"Cirsium vulgare","order_en":"Asterales","order_zh":"菊目","family_en":"Asteraceae","family_zh":"菊科","iucn":null,"langs":51,"desc_zh":"翼蓟（学名：Cirsium vulgare）是菊科蓟属的植物，又名欧洲蓟，分布在俄罗斯、欧洲、地中海地区、北非以及中国大陆的新疆等地，并在北美洲作为入侵生物存在，生长于海拔800米至1,800米的地区，多生长于田间或潮湿草地。它是苏格兰的国花。 该植物为传粉者提供了大量的花蜜。 在由英国昆虫传粉者计划支持的AgriLand项目进行的英国植物调查中，它被评为大多数花蜜产量（每年单位单位花蜜量）前十名。","desc_en":"Cirsium vulgare, commonly known as spear thistle, bull thistle, or common thistle, is a species of the Asteraceae genus Cirsium, native throughout most of Europe (north to 66°N, locally 68°N), Western Asia (east to the Yenisei Valley), and northwestern Africa…","img":"images/865.jpg","thumb":"images/t/865.jpg","file":"Cirsium vulgare Harthope.jpg","ar":0.832,"py":"yiji yj","cr_by":"Sciadopitys from UK","cr_lic":"CC BY-SA 2.0","cr_licurl":"https://creativecommons.org/licenses/by-sa/2.0","habit":null,"origin":["亚洲","欧洲","非洲","北美洲","大洋洲"]},{"id":866,"zh":"苣荬菜","en":"Sonchus arvensis","sci":"Sonchus arvensis","order_en":"Asterales","order_zh":"菊目","family_en":"Asteraceae","family_zh":"菊科","iucn":null,"langs":49,"desc_zh":"苣荬菜（学名：Sonchus arvensis）是菊科苦苣菜属的植物。分布在全球以及中国大陆的贵州、湖北、广西、福建、宁夏、新疆、云南、陕西、湖南、四川等地，生长于海拔300米至2,300米的地区，多生长在林间草地、山坡草地、潮湿地和近水旁，目前尚未由人工引种栽培。","desc_en":"Sonchus arvensis, the field milk thistle, field sowthistle, perennial sow-thistle, corn sow thistle, dindle, gutweed, swine thistle, or tree sow thistle, is a species of flowering plant in the family Asteraceae. S.","img":"images/866.jpg","thumb":"images/t/866.jpg","file":"Sonchus arvensis Unterfranken.jpg","ar":0.75,"py":"jumaicai jmc","cr_by":"Fornax","cr_lic":"CC BY-SA 3.0","cr_licurl":"https://creativecommons.org/licenses/by-sa/3.0","habit":"乔木","origin":null},{"id":867,"zh":"苍耳","en":"Xanthium strumarium","sci":"Xanthium strumarium","order_en":"Asterales","order_zh":"菊目","family_en":"Asteraceae","family_zh":"菊科","iucn":null,"langs":48,"desc_zh":"苍耳（学名：Xanthium strumarium）为一年生草本，属于菊科苍耳属。菓实为「苍耳子」，苍耳子又名葈耳实、羊负来、羊带来、道人头、胡寝子、胡苍子。","desc_en":"Xanthium strumarium (rough cocklebur, Noogoora burr, clotbur, common cocklebur, large cocklebur, woolgarie bur, Siberian cocklebur) is a species of annual plants in the flowering plant family Asteraceae.","img":"images/867.jpg","thumb":"images/t/867.jpg","file":"Xanthium strumarium L..jpg","ar":0.687,"py":"canger ce","cr_by":null,"cr_lic":"Public domain","cr_licurl":null,"habit":"草本","origin":["亚洲","欧洲"]},{"id":868,"zh":"大叶菜蓟","en":"Cynara cardunculus","sci":"Cynara cardunculus","order_en":"Asterales","order_zh":"菊目","family_en":"Asteraceae","family_zh":"菊科","iucn":null,"langs":47,"desc_zh":"刺苞菜蓟（学名：Cynara cardunculus）是菊科菜蓟属的植物，分布于地中海地区以及中国大陆的陕西等地，目前已由人工引种栽培。","desc_en":"The cardoon (Cynara cardunculus ), also called the artichoke thistle, is a thistle in the family Asteraceae. It is a naturally occurring species that also has many cultivated forms, including the globe artichoke.","img":"images/868.jpg","thumb":"images/t/868.jpg","file":"Cynara cardunculus0.jpg","ar":1.333,"py":"dayecaiji dycj","cr_by":"Kurt Stüber [1]","cr_lic":"CC BY-SA 3.0","cr_licurl":"http://creativecommons.org/licenses/by-sa/3.0/","habit":null,"origin":["欧洲"]},{"id":869,"zh":"毛果一枝黄花","en":"Solidago virgaurea","sci":"Solidago virgaurea","order_en":"Asterales","order_zh":"菊目","family_en":"Asteraceae","family_zh":"菊科","iucn":null,"langs":46,"desc_zh":"毛果一枝黄花（学名：Solidago virgaurea）为菊科一枝黄花属的植物。分布于欧洲、俄罗斯、蒙古以及中国大陆的新疆等地，生长于海拔1,200米至2,620米的地区，多生于林缘、林下以及灌丛中，目前已由人工引种栽培。","desc_en":"Solidago virgaurea, the European goldenrod or woundwort, is an herbaceous perennial plant of the family Asteraceae. It is widespread across most of Europe as well as North Africa and northern, central, and southwestern Asia (China, Russia, India, Turkey, Kazak…","img":"images/869.jpg","thumb":"images/t/869.jpg","file":"S. virgaurea2015-10-10.jpg","ar":0.549,"py":"maoguoyizhihuanghua mgyzhh","cr_by":"Victor M. Vicente Selvas","cr_lic":"CC BY-SA 4.0","cr_licurl":"https://creativecommons.org/licenses/by-sa/4.0","habit":"草本","origin":["亚洲","欧洲","非洲"]},{"id":870,"zh":"狼耙草","en":"Bidens tripartita","sci":"Bidens tripartita","order_en":"Asterales","order_zh":"菊目","family_en":"Asteraceae","family_zh":"菊科","iucn":"LC","langs":46,"desc_zh":"狼杷草（学名：Bidens tripartita）别称鬼刺、鬼针，是菊科鬼针草属的植物。","desc_en":"Bidens tripartita is a common and widespread species of flowering plant in the sunflower family, Asteraceae, commonly known as three-lobe beggarticks, three-part beggarticks, leafy-bracted beggarticks or trifid bur-marigold.","img":"images/870.jpg","thumb":"images/t/870.jpg","file":"Bidens tripartita1 eF.jpg","ar":0.707,"py":"langpacao lpc","cr_by":null,"cr_lic":"CC BY-SA 3.0","cr_licurl":"http://creativecommons.org/licenses/by-sa/3.0/","habit":null,"origin":["亚洲","非洲","北美洲","大洋洲"]},{"id":871,"zh":"黄花蒿","en":"Artemisia annua","sci":"Artemisia annua","order_en":"Asterales","order_zh":"菊目","family_en":"Asteraceae","family_zh":"菊科","iucn":null,"langs":46,"desc_zh":"黄花蒿（学名：Artemisia annua）俗名香蒿、臭蒿，为菊科蒿属的一年生草本植物。其植株地上部分干燥后，即为中药“青蒿”。 黄花蒿最高可达1.5米，全株黄绿色，有臭气。叶卵形，黄色两性花。","desc_en":"Artemisia annua, also known as sweet wormwood, sweet annie, sweet sagewort, annual mugwort or annual wormwood, is a common type of wormwood native to temperate Asia, but naturalized in many countries including scattered parts of North America.","img":"images/871.jpg","thumb":"images/t/871.jpg","file":"Artemisia annua.jpeg","ar":0.75,"py":"huanghuahao hhh","cr_by":"Kristian Peters -- Fabelfroh 11:39, 16 September 2007 (UTC)","cr_lic":"CC BY-SA 3.0","cr_licurl":"http://creativecommons.org/licenses/by-sa/3.0/","habit":"草本","origin":["亚洲","北美洲"]},{"id":872,"zh":"大翅蓟","en":"Onopordum acanthium","sci":"Onopordum acanthium","order_en":"Asterales","order_zh":"菊目","family_en":"Asteraceae","family_zh":"菊科","iucn":null,"langs":46,"desc_zh":"大翅蓟（学名：Onopordum acanthium）为菊科大翅蓟属的植物。分布在伊朗、俄罗斯、欧洲以及中国大陆的新疆自治区、陕西省等地，生长于海拔540米至1,050米的地区，多生长于荒地、山坡及水沟边，目前尚未由人工引种栽培。","desc_en":"Onopordum acanthium (cotton thistle, Scotch (or Scottish) thistle) is a flowering plant in the family Asteraceae. It is native to Europe and Western Asia from the Iberian Peninsula east to Kazakhstan, and north to central Scandinavia, and widely naturalised el…","img":"images/872.jpg","thumb":"images/t/872.jpg","file":"20150624Onopordum acanthium5.jpg","ar":1.333,"py":"dachiji dcj","cr_by":"AnRo0002","cr_lic":"CC0","cr_licurl":"http://creativecommons.org/publicdomain/zero/1.0/deed.en","habit":"草本","origin":["亚洲","欧洲","北美洲","大洋洲"]},{"id":873,"zh":"欧亚碱蒿","en":"Artemisia abrotanum","sci":"Artemisia abrotanum","order_en":"Asterales","order_zh":"菊目","family_en":"Asteraceae","family_zh":"菊科","iucn":null,"langs":45,"desc_zh":"碱蒿（学名：Artemisia anethifolia）是菊科蒿属的植物。分布于俄罗斯、蒙古以及中国大陆的新疆、黑龙江、内蒙古、陕西、河北、青海、宁夏、山西、甘肃等地，生长于海拔800米至2,300米的地区，一般生长在荒地、低湿、盐渍化草原附近、固定沙丘附近、干河谷、碱性滩地、干山坡以及盐渍化地常成区域性植物群落的主要伴生种，目前尚未由人工引种栽培。","desc_en":"Artemisia abrotanum, the southernwood, lad's love, or southern wormwood, is a species of flowering plant in the sunflower family. It is native to Eurasia and Africa but naturalized in scattered locations in North America.","img":"images/873.jpg","thumb":"images/t/873.jpg","file":"Artemisia abrotanum0.jpg","ar":1.333,"py":"ouyajianhao oyjh","cr_by":"Kurt Stüber [1]","cr_lic":"CC BY-SA 3.0","cr_licurl":"http://creativecommons.org/licenses/by-sa/3.0/","habit":"禾草","origin":["亚洲","非洲","北美洲"]},{"id":874,"zh":"欧洲千里光","en":"Senecio vulgaris","sci":"Senecio vulgaris","order_en":"Asterales","order_zh":"菊目","family_en":"Asteraceae","family_zh":"菊科","iucn":null,"langs":45,"desc_zh":"欧洲千里光（学名：Senecio vulgaris）是菊科千里光属的植物。分布于欧亚及北非洲以及中国大陆的辽宁、西藏、四川、吉林、云南、内蒙古、贵州等地，生长于海拔300米至2,300米的地区，多生长于草地、开旷山坡以及路旁。","desc_en":"Senecio vulgaris, often known by the common names groundsel and old-man-in-the-spring, is a flowering plant in the family Asteraceae. It is an annual herb, native to the Palaearctic and widely naturalised as a ruderal species in suitable disturbed habitats wor…","img":"images/874.jpg","thumb":"images/t/874.jpg","file":"Groundsel (Senecio vulgaris) (10171293746).jpg","ar":1.326,"py":"ouzhouqianliguang ozqlg","cr_by":"Peter O'Connor aka anemoneprojectors from Stevenage, United Kingdom","cr_lic":"CC BY-SA 2.0","cr_licurl":"https://creativecommons.org/licenses/by-sa/2.0","habit":"草本","origin":null},{"id":875,"zh":"土木香","en":"Inula helenium","sci":"Inula helenium","order_en":"Asterales","order_zh":"菊目","family_en":"Asteraceae","family_zh":"菊科","iucn":null,"langs":44,"desc_zh":"土木香（学名：Inula helenium）是菊科旋覆花属的植物。分布在俄罗斯、亚洲、 北美、欧洲以及中国大陆的新疆等地，生长于海拔1,800米至2,000米的地区，目前已由人工引种栽培。","desc_en":"Elecampane (Inula helenium), pronounced and also called horse-heal or elfdock, is a widespread plant species in the sunflower family Asteraceae. It is native to Eurasia from Spain to Xinjiang province in western China, and naturalized in parts of North America…","img":"images/875.jpg","thumb":"images/t/875.jpg","file":"Inula helenium Prague 2011 1.jpg","ar":0.642,"py":"tumuxiang tmx","cr_by":"Karelj","cr_lic":"CC BY-SA 3.0","cr_licurl":"https://creativecommons.org/licenses/by-sa/3.0","habit":null,"origin":["亚洲","欧洲","北美洲"]},{"id":876,"zh":"大麻叶泽兰","en":"Eupatorium cannabinum","sci":"Eupatorium cannabinum","order_en":"Asterales","order_zh":"菊目","family_en":"Asteraceae","family_zh":"菊科","iucn":null,"langs":44,"desc_zh":"大麻叶泽兰（学名：Eupatorium cannabinum）为菊科泽兰属的植物。分布于俄罗斯以及中国大陆的江苏、浙江等地，常生于山坡草丛、小山山顶或村落竹林内，目前尚未由人工引种栽培。","desc_en":"Eupatorium cannabinum, commonly known as hemp-agrimony, is a herbaceous plant in the family Asteraceae. It is a robust perennial native to Europe, Northwestern Africa, Turkey, Syria, Iran, Iraq, Jordan, the Caucasus and Central Asia, and grows in damp to wet h…","img":"images/876.jpg","thumb":"images/t/876.jpg","file":"Eupatorium cannabinum.jpg","ar":0.75,"py":"damayezelan dmyzl","cr_by":"Burkhard Mücke","cr_lic":"CC BY-SA 4.0","cr_licurl":"https://creativecommons.org/licenses/by-sa/4.0","habit":"草本","origin":["亚洲","欧洲","非洲","北美洲"]},{"id":877,"zh":"短舌匹菊","en":"Tanacetum parthenium","sci":"Tanacetum parthenium","order_en":"Asterales","order_zh":"菊目","family_en":"Asteraceae","family_zh":"菊科","iucn":null,"langs":43,"desc_zh":"短舌匹菊（学名：Tanacetum parthenium）是菊科菊蒿属的植物。原生长于欧亚大陆，特别是在巴尔干半岛、土耳其及高加索，已由人工引种栽培在中国、北美洲、智利等地。","desc_en":"Tanacetum parthenium, known as feverfew, is a flowering plant in the daisy family, Asteraceae. It may be grown as an ornament, and may be identified by its synonyms, Chrysanthemum parthenium and Pyrethrum parthenium.","img":"images/877.jpg","thumb":"images/t/877.jpg","file":"Feverfew.jpg","ar":1.333,"py":"duanshepiju dspj","cr_by":null,"cr_lic":"CC BY 2.5","cr_licurl":"https://creativecommons.org/licenses/by/2.5","habit":null,"origin":null},{"id":878,"zh":"甜叶菊","en":"candyleaf","sci":"Stevia rebaudiana","order_en":"Asterales","order_zh":"菊目","family_en":"Asteraceae","family_zh":"菊科","iucn":null,"langs":43,"desc_zh":"甜叶菊（学名：Stevia rebaudiana）又名甜菊，是菊科甜菊属的一种，原生于南美洲。是生产甜菊糖——一种重要的食用甜味剂及代糖的重要作物。","desc_en":"Stevia rebaudiana is a plant species in the genus Stevia of the family Asteraceae. It is commonly known as candyleaf, sweetleaf or sugarleaf. It is a small seasonal plant which grows to a height of 30–60 centimetres (1–2 feet).","img":"images/878.jpg","thumb":"images/t/878.jpg","file":"Stevia-rebaudiana-total.JPG","ar":0.686,"py":"tianyeju tyj","cr_by":"Sten Porse","cr_lic":"CC BY-SA 3.0","cr_licurl":"http://creativecommons.org/licenses/by-sa/3.0/","habit":"草本","origin":["南美洲"]},{"id":879,"zh":"小蓬草","en":"Erigeron canadensis","sci":"Erigeron canadensis","order_en":"Asterales","order_zh":"菊目","family_en":"Asteraceae","family_zh":"菊科","iucn":null,"langs":42,"desc_zh":"小蓬草（学名：Erigeron canadensis）又名加拿大蓬、飞蓬、小飞蓬，是菊科飞蓬属的植物。分布在北美洲以及中国大陆等地，生长于海拔350米至3,100米的地区，多生于荒地、田边、旷野和路旁，目前尚未由人工引种栽培。 其种加词“canadensis”意为“加拿大的”。","desc_en":"Erigeron canadensis (synonym Conyza canadensis) is an annual plant native throughout most of North America and Central America. It is also widely naturalized in Eurasia and Australia.","img":"images/879.jpg","thumb":"images/t/879.jpg","file":"2015.08.22 11.27.13 DSCN2872 - Flickr - andrey zharkikh.jpg","ar":0.75,"py":"xiaopengcao xpc","cr_by":"Andrey Zharkikh from Salt Lake City, USA","cr_lic":"CC BY 2.0","cr_licurl":"https://creativecommons.org/licenses/by/2.0","habit":"草本","origin":["亚洲","北美洲","大洋洲"]},{"id":880,"zh":"豚草","en":"Ambrosia artemisiifolia","sci":"Ambrosia artemisiifolia","order_en":"Asterales","order_zh":"菊目","family_en":"Asteraceae","family_zh":"菊科","iucn":null,"langs":41,"desc_zh":"豚草（学名：Ambrosia artemisiifolia），也叫猪草、“艾叶破布草”、瘤果菊，为菊科猪草属下的一个种。原产于北美洲，是一种适应力极强，生长旺盛的杂草，株高可达一米。每年7-8月份开花，同株但分雌雄花，放出黄色雾状花粉，可引发枯草热、花粉症及其他呼吸道疾病和过敏疾病等。每株每年可生7至10万枚种子，随风飘扬，种子具有30-40年的生命力，即使在贫瘠干旱的土地也能生长。","desc_en":"Ambrosia artemisiifolia, with the common names common ragweed, annual ragweed, and low ragweed, is a species of the genus Ambrosia native to regions of the Americas.","img":"images/880.jpg","thumb":"images/t/880.jpg","file":"Ambrosia artemisiifolia 1.JPG","ar":0.75,"py":"tuncao tc","cr_by":"Dalgial","cr_lic":"CC BY-SA 3.0","cr_licurl":"https://creativecommons.org/licenses/by-sa/3.0","habit":"草本","origin":null},{"id":881,"zh":"褐苞矢车菊","en":"Centaurea jacea","sci":"Centaurea jacea","order_en":"Asterales","order_zh":"菊目","family_en":"Asteraceae","family_zh":"菊科","iucn":null,"langs":41,"desc_zh":"褐苞矢车菊（学名：Centaurea jacea）是一种多年生草本植物 ，属于矢车菊属，原产于欧洲的干燥草地和疏林。该物种高度为10—80厘米（4—31英寸），开花时间为六月至九月。","desc_en":"Centaurea jacea, brown knapweed or brownray knapweed, is a species of herbaceous perennial plants in the genus Centaurea native to dry meadows and open woodland throughout Europe.","img":"images/881.jpg","thumb":"images/t/881.jpg","file":"Centaurée jacée.JPG","ar":1.335,"py":"hebaoshicheju hbscj","cr_by":"chelo Vechek / talk","cr_lic":"CC BY-SA 4.0","cr_licurl":"https://creativecommons.org/licenses/by-sa/4.0","habit":"禾草","origin":["欧洲"]},{"id":882,"zh":"茼蒿","en":"Glebionis coronaria","sci":"Glebionis coronaria","order_en":"Asterales","order_zh":"菊目","family_en":"Asteraceae","family_zh":"菊科","iucn":null,"langs":41,"desc_zh":"茼蒿（学名：Glebionis coronaria），别名茼莴、春菊、艾菜、打某菜、皇帝菜，菊科茼蒿属，原产地中海地区至西亚，在欧洲是庭园中的观赏花卉植物，宋朝时引进中国后成为蔬食食用。","desc_en":"Glebionis coronaria, formerly called Chrysanthemum coronarium, is a species of flowering plant in the family Asteraceae. It is native to the Mediterranean region. It is cultivated and naturalized in East Asia and in scattered locations in North America.","img":"images/882.jpg","thumb":"images/t/882.jpg","file":"Chrysanthemum coronarium re.jpg","ar":1.333,"py":"tonghao th","cr_by":"Retama","cr_lic":"CC BY-SA 3.0","cr_licurl":"http://creativecommons.org/licenses/by-sa/3.0/","habit":null,"origin":["欧洲"]},{"id":883,"zh":"松果菊","en":"Echinacea purpurea","sci":"Echinacea purpurea","order_en":"Asterales","order_zh":"菊目","family_en":"Asteraceae","family_zh":"菊科","iucn":null,"langs":40,"desc_zh":"松果菊（学名：Echinacea purpurea），又名紫锥菊、紫锥花，是松果菊属下的一种多年生草本植物，其种加词“purpurea”意为“紫色的”。原产于北美洲东部，是美国和加拿大安大略省常见的野外植物之一。","desc_en":"Echinacea purpurea, the eastern purple coneflower, purple coneflower, hedgehog coneflower, or Echinacea, is a North American species of flowering plant in the family Asteraceae.","img":"images/883.jpg","thumb":"images/t/883.jpg","file":".00 1682 Purpur-Sonnenhut (Echinacea purpurea).jpg","ar":1.501,"py":"songguoju sgj","cr_by":"W. Bulach","cr_lic":"CC BY-SA 4.0","cr_licurl":"https://creativecommons.org/licenses/by-sa/4.0","habit":null,"origin":["北美洲"]},{"id":884,"zh":"黑婆罗门参","en":"Scorzonera hispanica","sci":"Scorzonera hispanica","order_en":"Asterales","order_zh":"菊目","family_en":"Asteraceae","family_zh":"菊科","iucn":null,"langs":40,"desc_zh":"黑婆罗门参（学名：Scorzonera hispanica），别名洋牛蒡、鸦葱、黑根、蛇根，是一种菊科鸦葱属多年生草本植物，作为一、二年生蔬菜栽培，主要食用其根部，其嫩叶也可食用。原产欧洲南部，法国、比利时、荷兰普遍栽培，在轻度盐渍化土壤中也能生长。台湾、山东等地从欧洲引进栽培。新疆有来自土耳其的同类植物栽培。","desc_en":"Pseudopodospermum hispanicum, commonly known as black salsify or Spanish salsify, also known as black oyster plant, serpent root, viper's herb, viper's grass or scorzonera, is a perennial species of plant in the sunflower family (Asteraceae), cultivated as a r…","img":"images/884.jpg","thumb":"images/t/884.jpg","file":"Schorseneer plant Scorzonera hispanica.jpg","ar":0.75,"py":"heipoluomencan hplmc","cr_by":"Rasbak","cr_lic":"CC BY-SA 3.0","cr_licurl":"http://creativecommons.org/licenses/by-sa/3.0/","habit":"禾草","origin":["欧洲"]},{"id":885,"zh":"三叶鬼针草","en":"Bidens pilosa","sci":"Bidens pilosa","order_en":"Asterales","order_zh":"菊目","family_en":"Asteraceae","family_zh":"菊科","iucn":null,"langs":40,"desc_zh":"鬼针草（学名：Bidens pilosa），一年生草本植物。分布亚热带到热带气候地区，原产于美洲（北美洲和南美洲），地理分布欧亚大陆、非洲、澳洲、太平洋岛群等处。全草株可作为中药使用，药用植物。因其可改变土壤微生物群落结构，而成为一种入侵物种。","desc_en":"Bidens pilosa is an annual species of herbaceous flowering plant in the daisy family Asteraceae. Its many common names include hitch hikers, black-jack, beggarticks, farmer's friends and Spanish needle, but most commonly referred to as cobblers pegs.","img":"images/885.jpg","thumb":"images/t/885.jpg","file":"Bidens pilosa at Elmina West in Seksyen U15, Shah Alam 20231126 101332.jpg","ar":1.333,"py":"sanyeguizhencao sygzc","cr_by":"Wiki Farazi","cr_lic":"CC0","cr_licurl":"http://creativecommons.org/publicdomain/zero/1.0/deed.en","habit":"草本","origin":["亚洲","非洲","南美洲","大洋洲"]},{"id":886,"zh":"花叶滇苦菜","en":"Sonchus asper","sci":"Sonchus asper","order_en":"Asterales","order_zh":"菊目","family_en":"Asteraceae","family_zh":"菊科","iucn":null,"langs":39,"desc_zh":"花叶滇苦菜（学名：Sonchus asper），又名鬼苦苣菜、断续菊，是菊科苦苣菜属的植物。分布于西亚、乌兹别克斯坦、喜马拉雅山、欧洲、日本、俄罗斯、哈萨克斯坦以及中国大陆的西藏、山东、江西、安徽、四川、新疆、江苏、云南、湖北、浙江等地，生长于海拔550米至3,650米的地区，多生于林缘、山坡及水边，目前尚未由人工引种栽培。","desc_en":"Sonchus asper, the prickly sow-thistle, rough milk thistle, spiny sowthistle, sharp-fringed sow thistle, or spiny-leaved sow thistle, is a widespread flowering plant in the tribe Cichorieae within the family Asteraceae.","img":"images/886.jpg","thumb":"images/t/886.jpg","file":"(MHNT) Sonchus asper - Plant habit.jpg","ar":0.618,"py":"huayediankucai hydkc","cr_by":"Didier Descouens","cr_lic":"CC BY-SA 4.0","cr_licurl":"https://creativecommons.org/licenses/by-sa/4.0","habit":null,"origin":null},{"id":887,"zh":"稻槎菜属","en":"Lapsana communis","sci":"Lapsana communis","order_en":"Asterales","order_zh":"菊目","family_en":"Asteraceae","family_zh":"菊科","iucn":null,"langs":39,"desc_zh":"稻槎（chá）菜属（学名：Lapsana）是菊科下的一个属，为草本植物。该属共有9种，分布于东半球北温带。","desc_en":"Lapsana communis, the common nipplewort, is a species of flowering plant in the family Asteraceae. It is native to Europe and southwestern Asia, and it is widely naturalized in other regions including North America.","img":"images/887.jpg","thumb":"images/t/887.jpg","file":"Խարբուկ.jpg","ar":0.75,"py":"daochacaishu dccs","cr_by":"Արարատ Թրվանց","cr_lic":"CC BY-SA 4.0","cr_licurl":"https://creativecommons.org/licenses/by-sa/4.0","habit":null,"origin":["亚洲","欧洲","北美洲"]},{"id":888,"zh":"鳢肠","en":"Eclipta prostrata","sci":"Eclipta prostrata","order_en":"Asterales","order_zh":"菊目","family_en":"Asteraceae","family_zh":"菊科","iucn":"LC","langs":39,"desc_zh":"鳢（lǐ）肠（学名：Eclipta prostrata）是菊科鳢肠属的植物。","desc_en":"Eclipta prostrata, the false daisy, is a species of plant in the family Asteraceae. It is widespread across much of the world. This plant has cylindrical, grayish roots. Solid, circular, purplish stems with white fine hairs 0.8m.","img":"images/888.jpg","thumb":"images/t/888.jpg","file":"Starr 030807-0168 Eclipta prostrata.jpg","ar":1.333,"py":"lichang lc","cr_by":"Forest & Kim Starr","cr_lic":"CC BY 3.0","cr_licurl":"https://creativecommons.org/licenses/by/3.0","habit":null,"origin":["南美洲"]},{"id":889,"zh":"沙生蜡菊","en":"Helichrysum arenarium","sci":"Helichrysum arenarium","order_en":"Asterales","order_zh":"菊目","family_en":"Asteraceae","family_zh":"菊科","iucn":null,"langs":39,"desc_zh":"沙生蜡菊（学名：Helichrysum arenarium）是菊科拟蜡菊属的植物。分布在俄罗斯、欧洲、蒙古以及中国大陆的新疆等地，生长于海拔900米至2,400米的地区，多生长于土岗、半沙丘、湿盐土的山坡、砾质土、沙丘、草地上和松林下，目前尚未由人工引种栽培。","desc_en":"Helichrysum arenarium is also known as dwarf everlast, and as immortelle.","img":"images/889.jpg","thumb":"images/t/889.jpg","file":"Helichrysum arenarium.jpg","ar":0.75,"py":"shashenglaju sslj","cr_by":null,"cr_lic":"CC BY-SA 3.0","cr_licurl":"http://creativecommons.org/licenses/by-sa/3.0/","habit":null,"origin":null},{"id":890,"zh":"疆千里光","en":"Jacobaea vulgaris","sci":"Jacobaea vulgaris","order_en":"Asterales","order_zh":"菊目","family_en":"Asteraceae","family_zh":"菊科","iucn":null,"langs":39,"desc_zh":"新疆千里光（学名：Senecio jacobaea）是菊科千里光属的植物。分布在欧洲、蒙古、俄罗斯、中亚、高加索以及中国大陆的新疆等地，生长于海拔600米至1200米的地区，常生于疏林或草地，目前尚未由人工引种栽培。 新疆千里光在畜牧尤其是牧马业上是一种有害的植物，因为其含有肝毒性的生物碱。其花和全株均有毒性，马在短期内大量食用可致死亡。","desc_en":"Jacobaea vulgaris, synonym Senecio jacobaea, is a very common wild flower in the family Asteraceae that is native to northern Eurasia, usually in dry, open places, and has also been widely distributed as a weed elsewhere.","img":"images/890.jpg","thumb":"images/t/890.jpg","file":"Jacobaea vulgaris-3235.jpg","ar":1.227,"py":"jiangqianliguang jqlg","cr_by":"Julie Anne Workman","cr_lic":"CC BY-SA 3.0","cr_licurl":"https://creativecommons.org/licenses/by-sa/3.0","habit":null,"origin":["亚洲"]},{"id":891,"zh":"北疆风铃草","en":"Campanula glomerata","sci":"Campanula glomerata","order_en":"Asterales","order_zh":"菊目","family_en":"Campanulaceae","family_zh":"桔梗科","iucn":null,"langs":38,"desc_zh":"北疆风铃草（Campanula glomerata L.）为桔梗科风铃草属多年生草本植物。","desc_en":"Campanula glomerata, known by the common names clustered bellflower or Dane's blood, is a species of flowering plant in the genus Campanula, belonging to the family Campanulaceae. It is the county flower of Rutland, England.","img":"images/891.jpg","thumb":"images/t/891.jpg","file":"Campanula glomerata.JPG","ar":0.629,"py":"beijiangfenglingcao bjflc","cr_by":"Dag Lindgren","cr_lic":"CC BY-SA 3.0","cr_licurl":"http://creativecommons.org/licenses/by-sa/3.0/","habit":null,"origin":null},{"id":892,"zh":"圆叶风铃草","en":"Campanula rotundifolia","sci":"Campanula rotundifolia","order_en":"Asterales","order_zh":"菊目","family_en":"Campanulaceae","family_zh":"桔梗科","iucn":null,"langs":38,"desc_zh":"圆叶风铃草（学名：Campanula rotundifolia）为桔梗科风铃草属下的一个种，分布北半球温带，生长在草地及欧石南荒地。多年生草本，高约30公分，珠形纤巧，茎及花梗细长。叶片为暗绿或蓝绿的线形叶，先端渐尖，叶柄小或无，匍匐根著生有心型的基生叶。白色至深蓝色的钟形花有五枚尖端裂瓣，花初生直立，绽放后会弯垂。","desc_en":"Campanula rotundifolia, the harebell or common harebell, Scottish bluebell, or bluebell in Scotland, is a species of flowering plant in the bellflower family Campanulaceae.","img":"images/892.jpg","thumb":"images/t/892.jpg","file":"Campanula rotondifolia.jpg","ar":0.75,"py":"yuanyefenglingcao yyflc","cr_by":null,"cr_lic":"CC BY-SA 3.0","cr_licurl":"http://creativecommons.org/licenses/by-sa/3.0/","habit":"草本","origin":null},{"id":893,"zh":"长发公主桔梗","en":"rampion bellflower","sci":"Campanula rapunculus","order_en":"Asterales","order_zh":"菊目","family_en":"Campanulaceae","family_zh":"桔梗科","iucn":null,"langs":38,"desc_zh":null,"desc_en":"Campanula rapunculus, common name rampion bellflower, rampion, rover bellflower, or rapunzel, is a species of bellflower (Campanula) in the family Campanulaceae.","img":"images/893.jpg","thumb":"images/t/893.jpg","file":"Campanula rapunculus - Rampion Bellflower 06.jpg","ar":0.721,"py":"changfagongzhujiegeng cfgzjg","cr_by":"Zeynel Cebeci","cr_lic":"CC BY-SA 4.0","cr_licurl":"https://creativecommons.org/licenses/by-sa/4.0","habit":null,"origin":["欧洲"]},{"id":894,"zh":"宽钟风铃草","en":"Campanula trachelium","sci":"Campanula trachelium","order_en":"Asterales","order_zh":"菊目","family_en":"Campanulaceae","family_zh":"桔梗科","iucn":null,"langs":34,"desc_zh":null,"desc_en":"Campanula trachelium, the nettle-leaved bellflower, is a species of bellflower. It is native to Eurasia and parts of northwestern Africa and the Middle East.","img":"images/894.jpg","thumb":"images/t/894.jpg","file":".00 2908 Nesselblättrige Glockenblume (Campanula trachelium).jpg","ar":0.75,"py":"kuanzhongfenglingcao kzflc","cr_by":"W. Bulach","cr_lic":"CC BY-SA 4.0","cr_licurl":"https://creativecommons.org/licenses/by-sa/4.0","habit":null,"origin":["亚洲","非洲"]},{"id":895,"zh":"阔叶风铃草","en":"Campanula latifolia","sci":"Campanula latifolia","order_en":"Asterales","order_zh":"菊目","family_en":"Campanulaceae","family_zh":"桔梗科","iucn":null,"langs":34,"desc_zh":null,"desc_en":"Campanula latifolia, the giant bellflower, is a species of bellflower in the family Campanulaceae. It is also known as the large campanula and the wide-leaved bellflower. It is native to Europe and western Asia and is widely grown as an ornamental plant.","img":"images/895.jpg","thumb":"images/t/895.jpg","file":"Campanula latifolia1.jpg","ar":1.333,"py":"kuoyefenglingcao kyflc","cr_by":"Kurt Stüber [1]","cr_lic":"CC BY-SA 3.0","cr_licurl":"http://creativecommons.org/licenses/by-sa/3.0/","habit":null,"origin":["亚洲","欧洲"]},{"id":896,"zh":"六倍利","en":"Lobelia erinus","sci":"Lobelia erinus","order_en":"Asterales","order_zh":"菊目","family_en":"Campanulaceae","family_zh":"桔梗科","iucn":null,"langs":33,"desc_zh":"六倍利（学名：Lobelia erinus）为桔梗科半边莲属下的一个种。","desc_en":"Lobelia erinus (edging lobelia, garden lobelia or trailing lobelia) is a species of flowering plant in the bellflower family Campanulaceae, native to southern Africa.","img":"images/896.jpg","thumb":"images/t/896.jpg","file":"Lobelia close-up (aka).jpg","ar":1.094,"py":"liubeili lbl","cr_by":"André Karwath aka Aka","cr_lic":"CC BY-SA 2.5","cr_licurl":"https://creativecommons.org/licenses/by-sa/2.5","habit":null,"origin":["非洲"]},{"id":897,"zh":"草海桐","en":"Scaevola taccada","sci":"Scaevola taccada","order_en":"Asterales","order_zh":"菊目","family_en":"Goodeniaceae","family_zh":"草海桐科","iucn":null,"langs":19,"desc_zh":"草海桐（学名：Scaevola taccada）为草海桐科草海桐属下的一种多年生常绿灌木。台湾原生，分布于全岛沿海地带。具耐风、耐潮、耐盐及抗旱特质，即使在海风强大的海边岩石上也能生长，长期以来被视为沿海防风定砂植物。另因草海桐植株优美，已成为全岛各地普受喜爱的园艺观赏植物。草海桐具药用价值，嫩叶与果实亦可食。","desc_en":"Scaevola taccada, also known as beach cabbage, sea lettuce, or beach naupaka, is a flowering plant in the family Goodeniaceae found in mangrove swamps and rocky or sandy coastal locations in the tropical areas of the Indo-Pacific.","img":"images/897.jpg","thumb":"images/t/897.jpg","file":"Starr 010209-0286 Scaevola taccada.jpg","ar":1.333,"py":"caohaitong cht","cr_by":"Forest & Kim Starr","cr_lic":"CC BY 3.0","cr_licurl":"https://creativecommons.org/licenses/by/3.0","habit":"灌木","origin":["亚洲"]},{"id":898,"zh":"沙甘松","en":"Eremosyne pectinata","sci":"Eremosyne pectinata","order_en":"Escalloniales","order_zh":"南鼠刺目","family_en":"Escalloniaceae","family_zh":"南鼠刺科","iucn":null,"langs":13,"desc_zh":"寄奴花（学名：Eremosyne pectinata）又名柔毛小花草、旱生草或漠茸草，是寄奴花属的唯一已知物种，属于南鼠刺目南鼠刺科，曾被归类为单型的寄奴花科（Eremosynaceae），只生长在澳大利亚的西南部，是当地的特有种。","desc_en":"Eremosyne pectinata, the sole species in the genus Eremosyne, is an annual herb endemic to the south coast of Western Australia.","img":"images/898.jpg","thumb":"images/t/898.jpg","file":"Eremosyne pectinata - Flickr - Kevin Thiele (1).jpg","ar":0.882,"py":"shagansong sgs","cr_by":"Kevin Thiele from Perth, Australia","cr_lic":"CC BY 2.0","cr_licurl":"https://creativecommons.org/licenses/by/2.0","habit":"草本","origin":["大洋洲"]},{"id":899,"zh":"芫荽","en":"Coriandrum sativum","sci":"Coriandrum sativum","order_en":"Apiales","order_zh":"伞形目","family_en":"Apiaceae","family_zh":"伞形科","iucn":null,"langs":130,"desc_zh":"芫（yán）荽（suī）（学名：Coriandrum sativum），又名胡荽、香菜、盐须、香茜、臭菜，广东等地为避衰讳也称芫（）茜（）。芫荽属一年生草本植物。在中东、地中海、印度、拉丁美洲、中国和东南亚的烹调中经常出现，亦可作药用。","desc_en":"Coriander (), or Coriandrum sativum, is an annual herb in the family Apiaceae. The leaves are known as cilantro () in the US. Most people perceive the leaves as having a fresh, slightly citrus taste.","img":"images/899.jpg","thumb":"images/t/899.jpg","file":"Coriandrum sativum - Köhler–s Medizinal-Pflanzen-193.jpg","ar":0.794,"py":"yansui ys","cr_by":"Franz Eugen Köhler, Köhler's Medizinal-Pflanzen","cr_lic":"Public domain","cr_licurl":null,"habit":"草本","origin":["欧洲"]},{"id":900,"zh":"茴香","en":"Foeniculum vulgare","sci":"Foeniculum vulgare","order_en":"Apiales","order_zh":"伞形目","family_en":"Apiaceae","family_zh":"伞形科","iucn":null,"langs":123,"desc_zh":"茴香（学名：Foeniculum vulgare，英语：Fennel），也被称为甜茴香，汉药中的「小茴香」，古称蘹香。为伞形科茴香属的开花植物种。原产于地中海沿岸与东南亚的原生种，但目前已广泛被种植在世界许多地方，特别是在海岸附近干燥的土壤。","desc_en":"Fennel (Foeniculum vulgare) is a flowering plant species in the carrot family. It is a hardy, perennial herb with yellow flowers and feathery leaves. It is indigenous to the shores of the Mediterranean but has become widely naturalized in many parts of the wor…","img":"images/900.jpg","thumb":"images/t/900.jpg","file":"Fennel (Foeniculum vulgare) - Parc Natural de s'Albufera, Spain 2022-04-18 (02).jpg","ar":1.25,"py":"huixiang hx","cr_by":"Ryan Hodnett","cr_lic":"CC BY-SA 4.0","cr_licurl":"https://creativecommons.org/licenses/by-sa/4.0","habit":"草本","origin":["欧洲"]},{"id":901,"zh":"欧芹","en":"parsley","sci":"Petroselinum crispum","order_en":"Apiales","order_zh":"伞形目","family_en":"Apiaceae","family_zh":"伞形科","iucn":null,"langs":118,"desc_zh":"欧芹（学名：Petroselinum crispum），别称香芹、巴西利、巴西里、洋香菜、洋芫荽、番芫荽、荷兰芹，是伞形科欧芹属的二年生草本植物，原产地中海沿岸，为常见蔬菜和香草，具有清爽的香味和鲜绿色。古罗马时代起用于烹调，也是世界上用的最广的一种香草。对地质和气候的适应性高，栽培也容易，故世界各地都有栽培，但对干燥的适应性差。","desc_en":"Parsley, or garden parsley (Petroselinum crispum), is a species of flowering plant in the family Apiaceae that is native to Greece, the Balkans, Algeria and Morocco.","img":"images/901.jpg","thumb":"images/t/901.jpg","file":"Petroselinum crispum - Köhler–s Medizinal-Pflanzen-103.jpg","ar":0.697,"py":"ouqin oq","cr_by":"Franz Eugen Köhler, Köhler's Medizinal-Pflanzen","cr_lic":"Public domain","cr_licurl":null,"habit":"草本","origin":["欧洲"]},{"id":902,"zh":"莳萝","en":"Anethum graveolens","sci":"Anethum graveolens","order_en":"Apiales","order_zh":"伞形目","family_en":"Apiaceae","family_zh":"伞形科","iucn":null,"langs":112,"desc_zh":"莳（shí）萝（学名：Anethum graveolens，英语：dill），是伞形科莳萝属中唯一的一种植物，为一年生草本植物，原生于西亚，后西传至地中海沿岸及欧洲各地，现今地中海和东欧为主要的生产地，外形类似茴香，高度约为一至四英呎高，黄色小花呈伞状分布，叶为针状分针。台湾话称为「茴香仔」。","desc_en":"Dill (Anethum graveolens) is an annual herb in the celery family Apiaceae. Native to North Africa and West Asia, dill is grown widely in Eurasia, where its leaves and seeds are used as a herb or spice for flavouring food.","img":"images/902.jpg","thumb":"images/t/902.jpg","file":"Anethum graveolens 02.jpg","ar":0.75,"py":"shiluo sl","cr_by":"Tepeyac","cr_lic":"CC BY-SA 3.0","cr_licurl":"https://creativecommons.org/licenses/by-sa/3.0","habit":"草本","origin":["亚洲","非洲"]},{"id":903,"zh":"茴芹","en":"Pimpinella anisum","sci":"Pimpinella anisum","order_en":"Apiales","order_zh":"伞形目","family_en":"Apiaceae","family_zh":"伞形科","iucn":null,"langs":107,"desc_zh":"茴芹（学名：Pimpinella anisum，英语：Anise，Aniseed），又称作西洋茴香、洋茴香、欧洲大茴香，是原产于埃及和地中海东部的一种伞形科植物，有着带甜味的果实和类似甘草和茴香的香味，故常用于用于提炼精油、制造糖果和酿酒，也有一定的药用价值，自古便受到珍视。","desc_en":"Anise (; Pimpinella anisum), also called aniseed or rarely anix, is a flowering plant in the family Apiaceae native to the eastern Mediterranean region and Southwest Asia.","img":"images/903.jpg","thumb":"images/t/903.jpg","file":"Koehler1887-PimpinellaAnisum.jpg","ar":0.88,"py":"huiqin hq","cr_by":"Franz Eugen Köhler, Köhler's Medizinal-Pflanzen","cr_lic":"Public domain","cr_licurl":null,"habit":null,"origin":["亚洲","欧洲"]},{"id":904,"zh":"葛缕子","en":"Carum carvi","sci":"Carum carvi","order_en":"Apiales","order_zh":"伞形目","family_en":"Apiaceae","family_zh":"伞形科","iucn":null,"langs":106,"desc_zh":"葛缕子，伞形科两年生草本植物，原产于欧洲和西亚。其果实是一种香料，可用于烹调，也可以入药。","desc_en":"Caraway (Carum carvi), also known as meridian fennel, is a biennial plant in the family Apiaceae, native to western Asia, Europe, and North Africa.","img":"images/904.jpg","thumb":"images/t/904.jpg","file":"Carum carvi - Köhler–s Medizinal-Pflanzen-172.jpg","ar":0.839,"py":"gelzi glz","cr_by":"Franz Eugen Köhler, Köhler's Medizinal-Pflanzen","cr_lic":"Public domain","cr_licurl":null,"habit":"草本","origin":["亚洲","欧洲","非洲"]},{"id":905,"zh":"孜然","en":"Cuminum cyminum","sci":"Cuminum cyminum","order_en":"Apiales","order_zh":"伞形目","family_en":"Apiaceae","family_zh":"伞形科","iucn":null,"langs":105,"desc_zh":"孜然芹（学名：Cuminum cyminum），又名香旱芹，其果实作为香料时简称孜然（英语：cumin），又称阿拉伯茴香、安息茴香、枯茗，伞形科孜然芹属一年生草本植物。原产自中东至南亚一带。 孜然历史悠久。它主要用于调味、提取香精油等，是料理食品常用的上等佐料，口感风味独特且富有油性，气味芳香而浓烈，也是配制咖哩的主要原料之一。","desc_en":"Cumin ( , ; US also ; Cuminum cyminum) is a flowering plant in the family Apiaceae, native to the Irano-Turanian Region. Its seeds – each one contained within a fruit, which is dried – are used in the cuisines of many cultures in both whole and ground form.","img":"images/905.jpg","thumb":"images/t/905.jpg","file":"Cuminum cyminum - Köhler–s Medizinal-Pflanzen-198.jpg","ar":0.757,"py":"ziran zr","cr_by":"Franz Eugen Köhler, Köhler's Medizinal-Pflanzen","cr_lic":"Public domain","cr_licurl":null,"habit":null,"origin":null},{"id":906,"zh":"野胡萝卜","en":"Daucus carota","sci":"Daucus carota","order_en":"Apiales","order_zh":"伞形目","family_en":"Apiaceae","family_zh":"伞形科","iucn":"LC","langs":88,"desc_zh":"野胡萝卜（学名：Daucus carota），英文另叫（Queen Anne's lace）,为二年生草本植物。主根长，茎的上面有毛，叶为分裂状。花序为散形花序，花的颜色有淡紫色和白色。花心的颜色是紫色，花苞的苞片全裂。其中亚种“Daucus carota subsp. sativus”由于其根部富含胡萝卜素和维生素C，可用来提取咖啡代用品、糖浆和橙色染料。种子可以用来治疗宿醉，精油可以用来调制香水和利口酒。","desc_en":"Daucus carota, whose common names include wild carrot, European wild carrot, bird's nest, bishop's lace, carrot flower, and Queen Anne's lace (North America), is a flowering plant in the family Apiaceae.","img":"images/906.jpg","thumb":"images/t/906.jpg","file":"Daucus carota.jpg","ar":0.75,"py":"yehuluobo yhlb","cr_by":"User:Tigerente","cr_lic":"CC BY-SA 3.0","cr_licurl":"http://creativecommons.org/licenses/by-sa/3.0/","habit":null,"origin":null},{"id":907,"zh":"欧防风","en":"Pastinaca sativa","sci":"Pastinaca sativa","order_en":"Apiales","order_zh":"伞形目","family_en":"Apiaceae","family_zh":"伞形科","iucn":null,"langs":84,"desc_zh":"欧防风（学名：Pastinaca sativa）为伞形科欧防风属的植物，分布在欧洲等地，目前已由人工引种栽培。","desc_en":"The parsnip (Pastinaca sativa) is a root vegetable closely related to carrot and parsley, all belonging to the flowering plant family Apiaceae. It is a biennial plant usually grown as an annual.","img":"images/907.jpg","thumb":"images/t/907.jpg","file":"Pastinaca sativa vallee-de-grace-amiens 80 21072007 4.jpg","ar":0.669,"py":"oufangfeng off","cr_by":"Olivier Pichard","cr_lic":"CC BY-SA 3.0","cr_licurl":"https://creativecommons.org/licenses/by-sa/3.0","habit":"草本","origin":["亚洲"]},{"id":908,"zh":"旱芹","en":"Apium graveolens","sci":"Apium graveolens","order_en":"Apiales","order_zh":"伞形目","family_en":"Apiaceae","family_zh":"伞形科","iucn":"LC","langs":81,"desc_zh":"旱芹（学名：Apium graveolens），又称芹菜、药芹、富菜，是伞形科芹属的植物，原生于马卡罗尼西亚及爱尔兰，为双子叶植物，之后扩展至欧洲大陆，传入非洲及亚洲，并引入到美洲及大洋洲。芹菜可作为蔬菜，主要食用部分为叶柄，叶虽然略带苦味，但也可以食用。在中国菜中是一种常见的蔬菜，在义大利菜中也常用作爆香料。 芹菜的三个主要分支品种： 西洋芹 A. graveolens var. dulce，为目前最广泛可见的品种。","desc_en":"Apium graveolens, known in English as celery, is an Old World species of flowering plant in the family Apiaceae. It was first described by Carl Linnaeus in 1753.","img":"images/908.jpg","thumb":"images/t/908.jpg","file":"2023-06-22 Apium graveolens (Wild Celery), Elswick, Northumberland 4.jpg","ar":0.75,"py":"hanqin hq","cr_by":"MPF","cr_lic":"CC BY-SA 4.0","cr_licurl":"https://creativecommons.org/licenses/by-sa/4.0","habit":null,"origin":null},{"id":909,"zh":"毒参","en":"Conium maculatum","sci":"Conium maculatum","order_en":"Apiales","order_zh":"伞形目","family_en":"Apiaceae","family_zh":"伞形科","iucn":null,"langs":74,"desc_zh":"毒参（学名：Conium maculatum）是繖形科毒参属的植物。分布在欧洲、北非、北美洲、亚洲以及中国大陆的新疆等地，生长于海拔600米至1,700米的地区，常生长在林缘或农田边。毒性极强，具老鼠般的恶臭。在莎士比亚的剧作「马克白」中，为巫婆的药酒。","desc_en":"Conium maculatum, commonly known as hemlock (British English) or poison hemlock (in North America), is a highly poisonous flowering plant and a nitrophile weed species in the carrot family Apiaceae.","img":"images/909.jpg","thumb":"images/t/909.jpg","file":"Conium maculatum Cresswell 01.jpg","ar":0.74,"py":"ducan dc","cr_by":"MPF","cr_lic":"CC BY-SA 3.0","cr_licurl":"https://creativecommons.org/licenses/by-sa/3.0","habit":"草本","origin":["欧洲","非洲"]},{"id":910,"zh":"常春藤","en":"Hedera helix","sci":"Hedera helix","order_en":"Apiales","order_zh":"伞形目","family_en":"Araliaceae","family_zh":"五加科","iucn":null,"langs":75,"desc_zh":"洋常春藤（学名：Hedera helix），又名常春藤、长春藤、土鼓藤、木茑、百角蜈蚣，是常春藤属下的一种常绿攀援植物，在很多地区洋常春藤实际都属于入侵物种。","desc_en":"Hedera helix, simply ivy, or common ivy, English ivy, European ivy, King's choice ivy, is a species of flowering plant in the family Araliaceae. It is native to most of Europe and parts of western Asia.","img":"images/910.jpg","thumb":"images/t/910.jpg","file":"20121002Hedera helix1.jpg","ar":1.333,"py":"changchunteng cct","cr_by":"AnRo0002","cr_lic":"CC0","cr_licurl":"http://creativecommons.org/publicdomain/zero/1.0/deed.en","habit":"藤本","origin":["亚洲","欧洲"]},{"id":911,"zh":"高丽参","en":"Panax ginseng","sci":"Panax ginseng","order_en":"Apiales","order_zh":"伞形目","family_en":"Araliaceae","family_zh":"五加科","iucn":null,"langs":46,"desc_zh":"人参（学名：Panax ginseng）又称为人参、亚洲参、红参、生晒参、山晒山参、石柱参、朝鲜参、野山参、人衔、鬼盖、土精、神草，中国东北地区土名棒槌，是五加科人参属的一种，具有肉质的根，可药用，主要生长在东亚，特别是寒冷地区。 尽管人参已在传统医学中使用了多个世纪，现代临床研究对其仍有讨论。人参是亚洲常见药材，北中美洲也普遍使用花旗参(西洋参)，许多草药铺和超市都能找到各式人参饮片及萃取物保健产品。","desc_en":"Panax ginseng, ginseng, also known as Asian ginseng, Chinese ginseng or Korean ginseng, is a species of plant whose root is the original source of ginseng. It is a perennial plant that grows in the mountains of East Asia.","img":"images/911.jpg","thumb":"images/t/911.jpg","file":"Ginsengpflanze.jpg","ar":1,"py":"gaolishen gls","cr_by":"FloraFarm GmbH / Katharina Lohrie","cr_lic":"CC BY 3.0","cr_licurl":"https://creativecommons.org/licenses/by/3.0","habit":"草本","origin":["亚洲"]},{"id":912,"zh":"野天胡荽","en":"Hydrocotyle vulgaris","sci":"Hydrocotyle vulgaris","order_en":"Apiales","order_zh":"伞形目","family_en":"Araliaceae","family_zh":"五加科","iucn":"LC","langs":36,"desc_zh":"野天胡荽（学名：Hydrocotyle vulgaris）为五加科天胡荽属下的一个种。也可称为铜钱草、金钱草、钱币草、圆币草、少脉香菇草、香菇钱、盾叶天胡荽等，外观与南美天胡荽（Hydrocotyle verticillata）非常相近。","desc_en":"Hydrocotyle vulgaris, the marsh pennywort, common pennywort, water naval, money plant, lucky plant, dollarweed or copper coin, is a small creeping aquatic perennial plant native to North Africa, Europe, the Caucasus and parts of the Levant.","img":"images/912.jpg","thumb":"images/t/912.jpg","file":"HydrocotyleVulgaris.jpg","ar":1.449,"py":"yetianhusui yths","cr_by":null,"cr_lic":"CC BY-SA 3.0","cr_licurl":"http://creativecommons.org/licenses/by-sa/3.0/","habit":"草本","origin":["亚洲","欧洲","非洲"]},{"id":913,"zh":"刺五加","en":"Eleutherococcus senticosus","sci":"Eleutherococcus senticosus","order_en":"Apiales","order_zh":"伞形目","family_en":"Araliaceae","family_zh":"五加科","iucn":null,"langs":36,"desc_zh":"刺五加（学名：Eleutherococcus senticosus），五加科五加属的一种落叶灌木，又名五加参、俄国参、老虎参、西伯利亚人参，主要分布于亚洲东北部，西伯利亚一带。其根部和根状茎可入药，其主要成分有刺五加苷、新五加苷等。1950年代苏联学者曾对刺五加及刺五加苷进行过一系列研究，并开发了刺五加提取物制成的产品。具有清热解毒、镇痛止痒、消炎杀菌等功效，是中医常用的药材之一。","desc_en":"Eleutherococcus senticosus is a species of small, woody shrub in the family Araliaceae. It is native to Northeastern Asia. It may be colloquially called devil's bush, Siberian ginseng, taiga root, eleuthero, ciwujia, Devil's shrub, shigoka, touch-me-not, wild…","img":"images/913.jpg","thumb":"images/t/913.jpg","file":"Eleutherococcus senticosus.jpg","ar":0.972,"py":"ciwujia cwj","cr_by":"Stanislav Doronenko","cr_lic":"CC BY 2.5","cr_licurl":"https://creativecommons.org/licenses/by/2.5","habit":"灌木","origin":["亚洲"]},{"id":914,"zh":"辽东楤木","en":"Aralia elata","sci":"Aralia elata","order_en":"Apiales","order_zh":"伞形目","family_en":"Araliaceae","family_zh":"五加科","iucn":"LC","langs":30,"desc_zh":"辽东楤木（学名：Aralia elata；Chinese angelica-tree, Japanese angelica-tree, Korean angelica-tree）是五加科楤木属的植物。分布于日本、朝鲜、俄罗斯以及中国大陆的吉林、辽宁、黑龙江等地，生长于海拔100米至1,100米的地区，多生在森林中。在欧美已引进作为园艺植物。在日本和韩国作为野菜食用。","desc_en":"Aralia elata, also known as the Japanese angelica tree, Chinese angelica-tree, or Korean angelica-tree, is a species of woody plant in the family Araliaceae native to eastern Asia (in Russia, China, Taiwan, the Korean Peninsula, and Japan).","img":"images/914.jpg","thumb":"images/t/914.jpg","file":"Aralia elata en fleur4081.jpg","ar":1.333,"py":"liaodongsongmu ldsm","cr_by":"‘Uncle Carl’ (カールおじさん).","cr_lic":"CC BY-SA 3.0","cr_licurl":"http://creativecommons.org/licenses/by-sa/3.0/","habit":"乔木","origin":["亚洲"]},{"id":915,"zh":"缬草","en":"Valeriana officinalis","sci":"Valeriana officinalis","order_en":"Dipsacales","order_zh":"川续断目","family_en":"Caprifoliaceae","family_zh":"忍冬科","iucn":null,"langs":78,"desc_zh":"缬草（学名：Valeriana officinalis）是一种多年生耐寒开花植物，在北半球每年6月至9月是其花期，会开出芬芳的白色或粉红色花朵。当花朵被放在花瓶里时，其散发出来的香味因过于浓烈，会令人难以忍受。 缬草原产于亚洲部分地区和欧洲，现在已被栽培到北美洲。其茎叶被一些鳞翅目物种（蝴蝶及蛾）的幼虫当作食物。 缬草在药理学和本草疗法中是一种草药，其根部作为膳食补充剂使用。","desc_en":"Valerian (Valeriana officinalis) is an herbaceous perennial flowering plant in the family Caprifoliaceae, native to Europe and southwestern Asia. It is the type species of the genus Valeriana.","img":"images/915.jpg","thumb":"images/t/915.jpg","file":"Valeriana officinalis - Niitvälja.jpg","ar":0.714,"py":"xiecao xc","cr_by":"Ivar Leidus","cr_lic":"CC BY-SA 4.0","cr_licurl":"https://creativecommons.org/licenses/by-sa/4.0","habit":"草本","origin":["亚洲","欧洲"]},{"id":916,"zh":"莴苣缬草","en":"corn salad","sci":"Valerianella locusta","order_en":"Dipsacales","order_zh":"川续断目","family_en":"Caprifoliaceae","family_zh":"忍冬科","iucn":null,"langs":50,"desc_zh":"莴苣缬草（学名：Valerianella locusta），又名野苣、羊莴苣，是败酱科新缬草属的一种双子叶一年生或二年生植物，原产于欧洲、北非及西亚。","desc_en":"Valeriana locusta, commonly called mâche, cornsalad, or lamb's lettuce, a small, herbaceous, annual flowering plant in the honeysuckle family Caprifoliaceae. It is native to Europe, western Asia and north Africa, where it is eaten as a leaf vegetable.","img":"images/916.jpg","thumb":"images/t/916.jpg","file":"(MHNT) Valerianella locusta - inflorescences and Leaf.jpg","ar":1.203,"py":"wojuxiecao wjxc","cr_by":"Didier Descouens","cr_lic":"CC BY-SA 4.0","cr_licurl":"https://creativecommons.org/licenses/by-sa/4.0","habit":"草本","origin":["亚洲","欧洲","非洲"]},{"id":917,"zh":"田野孀草","en":"field scabious","sci":"Knautia arvensis","order_en":"Dipsacales","order_zh":"川续断目","family_en":"Caprifoliaceae","family_zh":"忍冬科","iucn":null,"langs":49,"desc_zh":"田野孀草（学名：Knautia arvensis）是忍冬科孀草属的一种多年生草本植物。","desc_en":"Knautia arvensis, commonly known as field scabious, is a herbaceous perennial species of flowering plant in the honeysuckle family Caprifoliaceae.","img":"images/917.jpg","thumb":"images/t/917.jpg","file":"Knautia arvensis flower (side view) - Keila.jpg","ar":0.667,"py":"tianyeshuangcao tysc","cr_by":"Ivar Leidus","cr_lic":"CC BY-SA 4.0","cr_licurl":"https://creativecommons.org/licenses/by-sa/4.0","habit":"草本","origin":null},{"id":918,"zh":"羊叶忍冬","en":"Lonicera caprifolium","sci":"Lonicera caprifolium","order_en":"Dipsacales","order_zh":"川续断目","family_en":"Caprifoliaceae","family_zh":"忍冬科","iucn":null,"langs":44,"desc_zh":null,"desc_en":"Lonicera caprifolium, the Italian woodbine, perfoliate honeysuckle, goat-leaf honeysuckle, Italian honeysuckle, or perfoliate woodbine, is a species of perennial flowering plants in the genus Lonicera of the family Caprifoliaceae.","img":"images/918.jpg","thumb":"images/t/918.jpg","file":"Dettaglio - Caprifoliaceae Lonicera caprifolium Lin. Erbario Frizzi Perugia n. 3641.jpg","ar":0.734,"py":"yangyerendong yyrd","cr_by":"Giuseppe Frizzi","cr_lic":"Public domain","cr_licurl":null,"habit":"藤本","origin":["欧洲","北美洲"]},{"id":919,"zh":"金银花","en":"Lonicera japonica","sci":"Lonicera japonica","order_en":"Dipsacales","order_zh":"川续断目","family_en":"Caprifoliaceae","family_zh":"忍冬科","iucn":null,"langs":41,"desc_zh":"忍冬（学名：Lonicera japonica），是忍冬科的一种植物，花称为金银花、也叫忍冬藤、金银藤､ 密银花､ 东银花､ 小山花､ 忍冬草､ 鸳鸯草、双花、毛金银花、二宝花、双宝花､ 二花。 “金银花”一名始载于宋代《苏沈内翰良方》，金银花指的是忍冬花朵因成熟度不同由白变黄的特性。而“忍冬”则得名于植物冬天不枯萎的特点。由于忍冬花初开为白色，后转为黄色，因此得名金银花。花芬芳，果实为黑色球形的浆果，直径是3—4毫米（0.12—0.","desc_en":"Lonicera japonica, known as Japanese honeysuckle and golden-and-silver honeysuckle, is a species of honeysuckle native to East Asia, including many parts of China.","img":"images/919.jpg","thumb":"images/t/919.jpg","file":"Honeysuckle 2.jpg","ar":0.75,"py":"jinyinhua jyh","cr_by":"William Rafti of the William Rafti Institute, aka Rafti Institute at en.wikipedia . Original watermark removed by Ms. ha","cr_lic":"Attribution","cr_licurl":null,"habit":null,"origin":["亚洲"]},{"id":920,"zh":"蓝靛果忍冬","en":"Lonicera caerulea","sci":"Lonicera caerulea","order_en":"Dipsacales","order_zh":"川续断目","family_en":"Caprifoliaceae","family_zh":"忍冬科","iucn":"LC","langs":40,"desc_zh":"蓝靛果忍冬（学名：Lonicera caerulea），又名蓝靛果、蓝果忍冬、杨乃子，忍冬科忍冬属落叶植物。原产于北半球温带地区。分布在亚洲、欧洲等地，生长于海拔300米至3,500米的地区。 果实可食用，营养丰富，富含维生素C、花青素、钙。","desc_en":"Lonicera caerulea, commonly known as honeyberry or by various honeysuckle names, is a non-climbing honeysuckle native throughout the cool temperate Northern Hemisphere regions of North America, Europe, and Asia.","img":"images/920.jpg","thumb":"images/t/920.jpg","file":"Lonicera coerulea a3.jpg","ar":1.333,"py":"landianguorendong ldgrd","cr_by":"Opioła Jerzy (Poland)","cr_lic":"CC BY 2.5","cr_licurl":"https://creativecommons.org/licenses/by/2.5","habit":"藤本","origin":["亚洲","欧洲","北美洲"]},{"id":921,"zh":"欧洲荚蒾","en":"Viburnum opulus","sci":"Viburnum opulus","order_en":"Dipsacales","order_zh":"川续断目","family_en":"Adoxaceae","family_zh":"五福花科","iucn":null,"langs":68,"desc_zh":"欧洲荚蒾（学名：Viburnum opulus，别名欧洲琼花、欧洲雪球）为五福花科荚蒾属的一种落叶灌木，高4—5米（13—16英尺），原产于欧洲、北非和中亚，后来作为观赏植物引入世界其他地区。","desc_en":"Viburnum opulus, commonly known as the guelder-rose, or guelder rose (), is an Old World species of flowering plant in the family Adoxaceae.","img":"images/921.jpg","thumb":"images/t/921.jpg","file":"Viburnum opulus bunched.jpg","ar":1.501,"py":"ouzhoujiami ozjm","cr_by":"Waitblock","cr_lic":"CC BY-SA 4.0","cr_licurl":"https://creativecommons.org/licenses/by-sa/4.0","habit":null,"origin":null},{"id":922,"zh":"黑果绣球","en":"Viburnum lantana","sci":"Viburnum lantana","order_en":"Dipsacales","order_zh":"川续断目","family_en":"Adoxaceae","family_zh":"五福花科","iucn":null,"langs":46,"desc_zh":null,"desc_en":"Viburnum lantana, the wayfarer or wayfaring tree, is a species of Viburnum, native to central, southern and western Europe (north to Yorkshire in England), northwest Africa, and southwestern Asia.","img":"images/922.jpg","thumb":"images/t/922.jpg","file":"Viburnum lantana a1.jpg","ar":1.336,"py":"heiguoxiuqiu hgxq","cr_by":"Opioła Jerzy","cr_lic":"CC BY 2.5","cr_licurl":"https://creativecommons.org/licenses/by/2.5","habit":"乔木","origin":["亚洲","欧洲","非洲"]},{"id":923,"zh":"苏铁","en":"Cycas revoluta","sci":"Cycas revoluta","order_en":"Cycadales","order_zh":"苏铁目","family_en":"Cycadaceae","family_zh":"苏铁科","iucn":"LC","langs":48,"desc_zh":"苏铁（学名：Cycas revoluta），又名琉球苏铁，同物异名台东苏铁，俗称铁树、凤尾蕉、凤尾松、避火树，属于苏铁科苏铁属的一种植物。","desc_en":"Cycas revoluta (Sotetsu [Japanese ソテツ], sago cycad, sago palm, king sago, Japanese sago palm) is a species of gymnosperm in the family Cycadaceae, native to southern Japan including the Ryukyu Islands.","img":"images/923.jpg","thumb":"images/t/923.jpg","file":"Cycas inflorescence.jpg","ar":0.75,"py":"sutie st","cr_by":null,"cr_lic":"CC BY-SA 3.0","cr_licurl":"https://creativecommons.org/licenses/by-sa/3.0","habit":null,"origin":["亚洲"]},{"id":924,"zh":"拳叶苏铁","en":"Cycas circinalis","sci":"Cycas circinalis","order_en":"Cycadales","order_zh":"苏铁目","family_en":"Cycadaceae","family_zh":"苏铁科","iucn":"EN","langs":24,"desc_zh":null,"desc_en":"Cycas circinalis, also known as the queen sago, is a species of cycad known in the wild only from southern India. Cycas circinalis is the only gymnosperm species found among native Sri Lankan flora.","img":"images/924.jpg","thumb":"images/t/924.jpg","file":"Cycas Circinalis - 200 Years Old in Prague - DSC 0068.jpg","ar":0.669,"py":"quanyesutie qyst","cr_by":"myself","cr_lic":"CC BY-SA 3.0","cr_licurl":"http://creativecommons.org/licenses/by-sa/3.0/","habit":null,"origin":["亚洲"]},{"id":925,"zh":"华南苏铁","en":"Cycas rumphii","sci":"Cycas rumphii","order_en":"Cycadales","order_zh":"苏铁目","family_en":"Cycadaceae","family_zh":"苏铁科","iucn":"NT","langs":22,"desc_zh":"华南苏铁（学名：Cycas rumphii）为苏铁科苏铁属的植物。分布于印度尼西亚、新几内亚和圣诞岛，多生长于山坡杂木林中，目前尚未由人工引种栽培。","desc_en":"Cycas rumphii, commonly known as queen sago or the queen sago palm, is a dioecious gymnosperm, a species of cycad in the genus Cycas native to Indonesia, New Guinea and Christmas Island. Although palm-like in appearance, it is not a palm.","img":"images/925.jpg","thumb":"images/t/925.jpg","file":"Cycas rumphii-IMG 9702.JPG","ar":1.501,"py":"huanansutie hnst","cr_by":"C T Johansson","cr_lic":"CC BY-SA 4.0","cr_licurl":"https://creativecommons.org/licenses/by-sa/4.0","habit":null,"origin":["亚洲","大洋洲"]},{"id":926,"zh":"光果苏铁","en":"Cycas thouarsii","sci":"Cycas thouarsii","order_en":"Cycadales","order_zh":"苏铁目","family_en":"Cycadaceae","family_zh":"苏铁科","iucn":"LC","langs":17,"desc_zh":"光果苏铁（学名：Cycas thouarsii），也称马达加斯加苏铁，属于苏铁科的一种植物，分布在马达加斯加及东非热带地区，可作为观赏及药用植物。","desc_en":"Cycas thouarsii, the Madagascar cycad, is an evergreen arborescent cycad in the genus Cycas. It is named after the French botanist Louis-Marie Aubert du Petit-Thouars (1758—1831).","img":"images/926.jpg","thumb":"images/t/926.jpg","file":"Cycas thouarsii01.jpg","ar":0.75,"py":"guangguosutie ggst","cr_by":null,"cr_lic":"CC BY-SA 3.0","cr_licurl":"http://creativecommons.org/licenses/by-sa/3.0/","habit":null,"origin":["非洲"]},{"id":927,"zh":"伍德苏铁","en":"Encephalartos woodii","sci":"Encephalartos woodii","order_en":"Cycadales","order_zh":"苏铁目","family_en":"Zamiaceae","family_zh":"泽米铁科","iucn":"EW","langs":24,"desc_zh":"伍德苏铁（学名Encephalartos woodii）是南非夸祖鲁-纳塔尔省特有的苏铁。它们是世界最稀有的植物之一，现已从野外灭绝，所有现存标本都是模式标本的克隆。 其学名为纪念发现此植物的德班植物园（Durban Botanic Garden）的约翰·梅德利·伍德。","desc_en":"Encephalartos woodii, Wood's cycad, is a rare cycad in the genus Encephalartos, and is endemic to the oNgoye Forest of KwaZulu-Natal, South Africa. It is one of the rarest plants in the world, being extinct in the wild with all specimens being clones of the ty…","img":"images/927.jpg","thumb":"images/t/927.jpg","file":"Encephalartos woodii original stem Durban Botanic Gardens 04 09 2010.JPG","ar":0.75,"py":"wudesutie wdst","cr_by":"Purves, M.","cr_lic":"CC BY-SA 3.0","cr_licurl":"https://creativecommons.org/licenses/by-sa/3.0","habit":null,"origin":["非洲"]},{"id":928,"zh":"双子苏铁","en":"Dioon edule","sci":"Dioon edule","order_en":"Cycadales","order_zh":"苏铁目","family_en":"Zamiaceae","family_zh":"泽米铁科","iucn":"NT","langs":20,"desc_zh":null,"desc_en":"Dioon edule, the chestnut dioon, is a cycad native to Mexico, also known as palma de la virgen. Cycads are among the oldest seed plants and even pre-date the dinosaurs. It belongs to the Zamiaceae plant family within the order Cycadales.","img":"images/928.jpg","thumb":"images/t/928.jpg","file":"Dioon edule05.jpg","ar":1.333,"py":"shuangzisutie szst","cr_by":null,"cr_lic":"CC BY-SA 2.5","cr_licurl":"https://creativecommons.org/licenses/by-sa/2.5","habit":null,"origin":["北美洲"]},{"id":929,"zh":"粉叶非洲铁","en":"Encephalartos horridus","sci":"Encephalartos horridus","order_en":"Cycadales","order_zh":"苏铁目","family_en":"Zamiaceae","family_zh":"泽米铁科","iucn":"EN","langs":19,"desc_zh":null,"desc_en":"Encephalartos horridus, commonly known as the Eastern Cape blue cycad, is a small, low-growing cycad up to 0.9 m (3.0 ft) high and 0.9 m (3.0 ft) wide. It is a native of Eastern Cape Province, South Africa, and found in arid shrublands, most commonly on ridges…","img":"images/929.jpg","thumb":"images/t/929.jpg","file":"Encephalartos horridus 03.jpg","ar":1.333,"py":"fenyefeizhoutie fyfzt","cr_by":"A. Barra","cr_lic":"CC BY-SA 3.0","cr_licurl":"http://creativecommons.org/licenses/by-sa/3.0/","habit":null,"origin":["非洲"]},{"id":930,"zh":"刺叶非洲苏铁","en":"Encephalartos ferox","sci":"Encephalartos ferox","order_en":"Cycadales","order_zh":"苏铁目","family_en":"Zamiaceae","family_zh":"泽米铁科","iucn":"NT","langs":18,"desc_zh":"刺叶非洲苏铁（学名：Encephalartos ferox）是泽米铁科非洲苏铁属的物种，原产于非洲东南沿岸地区。是非洲苏铁属最广为栽培的物种。","desc_en":"Encephalartos ferox, a member of the family Zamiaceae, is a small cycad with 35 cm wide subterranean trunk. It gets its name from the Latin word ferocious, likely from the spine-tipped lobes on the leaves of the plant.","img":"images/930.jpg","thumb":"images/t/930.jpg","file":"Encephalartos ferox-BU Greenhouse.jpg","ar":0.75,"py":"ciyefeizhousutie cyfzst","cr_by":"Salvatore Ingrassia","cr_lic":"Public domain","cr_licurl":null,"habit":null,"origin":["非洲"]},{"id":931,"zh":"银杏","en":"Ginkgo biloba","sci":"Ginkgo biloba","order_en":"Ginkgoales","order_zh":"银杏目","family_en":"Ginkgoaceae","family_zh":"银杏科","iucn":"EN","langs":95,"desc_zh":"银杏（学名：Ginkgo biloba），落叶乔木，寿命可达3000年以上。又名公孙树、鸭掌树、鸭脚树、鸭脚子等，其裸露的种子称为白果，叶称蒲扇。属裸子植物银杏门惟一现存物种，和它同门的其他所有物种都已灭绝，因此被称为植物界的“活化石”。已发现的化石可以追溯到2.7亿年前。银杏原产于中国，现广泛种植于全世界，常作为道路景观树种，并被早期引入人类历史。它有多种用途，可作为传统医学用途和食材。","desc_en":"Ginkgo biloba, commonly known as ginkgo ( GINK-oh, -⁠goh), also known as the maidenhair tree, and often misspelled \"gingko\" (see Taxonomy below) is a species of gymnosperm tree native to East Asia.","img":"images/931.jpg","thumb":"images/t/931.jpg","file":"GINKGOBAUM-2.jpg","ar":0.727,"py":"yinxing yx","cr_by":"EecherplazGinkgo06.jpg : Cayambe derivative work: Ginkgotree ( talk )","cr_lic":"CC BY-SA 3.0","cr_licurl":"https://creativecommons.org/licenses/by-sa/3.0","habit":"乔木","origin":["亚洲"]},{"id":932,"zh":"欧洲赤松","en":"Pinus sylvestris","sci":"Pinus sylvestris","order_en":"Pinales","order_zh":"松目","family_en":"Pinaceae","family_zh":"松科","iucn":"LC","langs":88,"desc_zh":"欧洲赤松（学名：Pinus sylvestris）是一种分布在西起大不列颠和伊比利亚半岛，东至东西伯利亚及高加索山脉，北达拉普兰之间，广大范围的树种。在北部，其生长高度为海平面至海拔1000公尺，在南方则以高山植物方式呈现 (1200-2500公尺)。 在英伦三岛中，目前只有苏格兰有原生的欧洲赤松，但最晚到三、四百年前，在英格兰、爱尔兰和威尔斯仍然能发现其踪影—后者由于伐木过度而消失，但近年又重新引进回来。","desc_en":"Pinus sylvestris is a species of tree in the pine family Pinaceae that is native to Eurasia. It is commonly known as the Scots pine in English; it is also known as the Scotch pine in the United States, and occasionally called the Baltic pine or European red pi…","img":"images/932.jpg","thumb":"images/t/932.jpg","file":"Pinus sylvestris Glenmuick.jpg","ar":0.77,"py":"ouzhouchisong ozcs","cr_by":"Hello, I am Bruce on Flickr","cr_lic":"CC BY-SA 2.0","cr_licurl":"https://creativecommons.org/licenses/by-sa/2.0","habit":"针叶树","origin":["亚洲"]},{"id":933,"zh":"欧洲云杉","en":"Picea abies","sci":"Picea abies","order_en":"Pinales","order_zh":"松目","family_en":"Pinaceae","family_zh":"松科","iucn":"LC","langs":81,"desc_zh":"欧洲云杉（学名：Picea abies；英语：Norway spruce、European spruce），或译作挪威云杉，是一种大型常绿针叶树，高达35-55公尺，树干直径可达 1-1.5 公尺。2008年，一株由瑞典于默奥大学科学家在瑞典达拉纳省境内的欧洲云杉Old Tjikko经碳-14定年法后核实其树龄高达9550岁，打破了一直以来在美国加利福尼亚州白山找到的一株刺果松4700岁的纪录足足一倍有多，所以是目前世界上已知寿命最长的…","desc_en":"Picea abies, the Norway spruce, Norway fir or European spruce, is a species of spruce native to Northern, Central and Eastern Europe. It has branchlets that typically hang downwards, and the longest cones of any spruce, 9–17 cm long.","img":"images/933.jpg","thumb":"images/t/933.jpg","file":"Kuusk Keila-Paldiski rdt ääres.jpg","ar":0.667,"py":"ouzhouyunshan ozys","cr_by":"Ivar Leidus","cr_lic":"CC BY-SA 3.0 ee","cr_licurl":"https://creativecommons.org/licenses/by-sa/3.0/ee/deed.en","habit":"针叶树","origin":["欧洲"]},{"id":934,"zh":"银冷杉","en":"Abies alba","sci":"Abies alba","order_en":"Pinales","order_zh":"松目","family_en":"Pinaceae","family_zh":"松科","iucn":"LC","langs":72,"desc_zh":"银冷杉（学名：Abies alba）为松科冷杉属的一种植物，又称欧洲银冷杉，欧洲冷杉，圣诞树。其种加词“alba”意为“白色的”。其外型呈现漂亮的绿色金字塔状，带略白色的枝枒，常被联想为传统的圣诞树；生于欧洲山区的原生植物，为常绿的松科植物，成树高50至60米，树干直径阔1.5米，树叶为针状，呈墨绿色。","desc_en":"Abies alba, the European silver fir or silver fir, is a fir native to the mountains of Europe, from the Pyrenees north to Normandy, east to the Alps and the Carpathians, Slovakia, Slovenia, Croatia, Bosnia and Herzegovina, Montenegro, Serbia, and south to Ital…","img":"images/934.jpg","thumb":"images/t/934.jpg","file":"Abies alba - Köhler–s Medizinal-Pflanzen-001.jpg","ar":0.783,"py":"yinlengshan yls","cr_by":"Franz Eugen Köhler, Köhler's Medizinal-Pflanzen","cr_lic":"Public domain","cr_licurl":null,"habit":"针叶树","origin":["欧洲"]},{"id":935,"zh":"黎巴嫩雪松","en":"Cedrus libani","sci":"Cedrus libani","order_en":"Pinales","order_zh":"松目","family_en":"Pinaceae","family_zh":"松科","iucn":"VU","langs":69,"desc_zh":"黎巴嫩雪松（学名：Cedrus libani）是东地中海盆地山区的本土雪松。它是常绿针叶树，可长至40米高。黎巴嫩雪松也是黎巴嫩的国家象征，在该国国旗上可以看见其图案。其在公园、花园等地广泛种植，用作观赏植物。","desc_en":"Cedrus libani, commonly known as cedar of Lebanon, Lebanon cedar, or Lebanese cedar (Arabic: أرز لبناني, romanized: ʾarz lubnāniyy), is a species of large evergreen conifer in the genus Cedrus, which belongs to the pine family and is native to the mountains of…","img":"images/935.jpg","thumb":"images/t/935.jpg","file":"Cèdre du Liban Barouk 2005.jpg","ar":1.333,"py":"libanenxuesong lbnxs","cr_by":"Olivier BEZES","cr_lic":"CC BY 2.5","cr_licurl":"https://creativecommons.org/licenses/by/2.5","habit":"针叶树","origin":["欧洲"]},{"id":936,"zh":"喜马拉雅雪松","en":"Cedrus deodara","sci":"Cedrus deodara","order_en":"Pinales","order_zh":"松目","family_en":"Pinaceae","family_zh":"松科","iucn":"LC","langs":67,"desc_zh":"喜马拉雅雪松（学名：Cedrus deodara）是雪松的一个物种，为阿富汗东部、巴基斯坦北部（特别是在开伯尔-普赫图赫瓦省境内）、印度（查谟-克什米尔邦、喜马偕尔邦、锡金、大吉岭、北阿坎德邦）、西藏地区西南端以及尼泊尔西部的本土植物，通常出现在海拔1,500—3,200米（4,921—10,499英尺）的地方。","desc_en":"Cedrus deodara, the deodar cedar, Himalayan cedar, or deodar, is a species of cedar native to the Himalayas.","img":"images/936.jpg","thumb":"images/t/936.jpg","file":"Cedrus deodara Manali 2.jpg","ar":0.75,"py":"ximalayaxuesong xmlyxs","cr_by":"Paul Evans from London, United Kingdom","cr_lic":"CC BY 2.0","cr_licurl":"https://creativecommons.org/licenses/by/2.0","habit":"针叶树","origin":["亚洲"]},{"id":937,"zh":"意大利笠松","en":"Pinus pinea","sci":"Pinus pinea","order_en":"Pinales","order_zh":"松目","family_en":"Pinaceae","family_zh":"松科","iucn":"LC","langs":62,"desc_zh":"笠松（学名：Pinus pinea），也被称为意大利石松、意大利伞松、意大利五针松。原产于地中海地区，分布在南欧，北非和地中海东部。笠松自史前时代已被用于种植食用松子。现代作为观赏树，在世界各地普遍种植在花园和公园。","desc_en":"Pinus pinea, the Italian stone pine or Mediterranean stone pine, is a tree from the pine family, Pinaceae. The tree is native to the Mediterranean region, occurring in Southern Europe and the Levant.","img":"images/937.jpg","thumb":"images/t/937.jpg","file":"Pinus pinea and ruins on Palatine Hill.jpg","ar":0.706,"py":"yidalilisong ydlls","cr_by":"Livioandronico2013","cr_lic":"CC BY-SA 4.0","cr_licurl":"https://creativecommons.org/licenses/by-sa/4.0","habit":"针叶树","origin":["亚洲","欧洲"]},{"id":938,"zh":"欧洲落叶松","en":"Larix decidua","sci":"Larix decidua","order_en":"Pinales","order_zh":"松目","family_en":"Pinaceae","family_zh":"松科","iucn":"LC","langs":61,"desc_zh":"欧洲落叶松（Larix decidua）是落叶松属下的一个物种，主要分布在欧洲中部的阿尔卑斯山脉和喀尔巴阡山脉。 欧洲落叶松是一种中型到大型的落叶松柏目树木，高度为25-45米，直径可达1米。幼年期树冠为圆锥形，随着树龄增长，渐渐变得宽阔。主干向上，支干通常下垂，枝平展，树冠呈不规则塔形；小枝平展，枝稍多少上升。树叶为针状，浅绿色，2-4厘米长，秋季变成黄色落下。","desc_en":"Larix decidua, the European larch, is a species of larch native to the mountains of central Europe, in the Alps and Carpathian Mountains, with small disjunct lowland populations in northern Poland.","img":"images/938.jpg","thumb":"images/t/938.jpg","file":"2014-07-03 Larix decidua cone & foliage, Valle di Cogne, Italian Alps.jpg","ar":1.501,"py":"ouzhouluoyesong ozlys","cr_by":"Fulvio Spada from Torino, Italy","cr_lic":"CC BY-SA 2.0","cr_licurl":"https://creativecommons.org/licenses/by-sa/2.0","habit":"针叶树","origin":["欧洲"]},{"id":939,"zh":"欧洲黑松","en":"Pinus nigra","sci":"Pinus nigra","order_en":"Pinales","order_zh":"松目","family_en":"Pinaceae","family_zh":"松科","iucn":"LC","langs":58,"desc_zh":"欧洲黑松（学名：Pinus nigra）为松科松属的植物。幼皮暗灰色，老则呈灰褐色，裂成鳞状厚片脱落。分布在小亚细亚半岛、欧洲等地，属中国原产的植物（非从国外引种）。 其种加词“nigra”意为“黑色的，暗色的”。","desc_en":"Pinus nigra, the Austrian pine or black pine, is a moderately variable species of pine, occurring across Southern Europe from the Iberian Peninsula and Lower Austria to the eastern Mediterranean, on the Anatolian peninsula of Turkey, Corsica and Cyprus, as wel…","img":"images/939.jpg","thumb":"images/t/939.jpg","file":"Schwarzkiefer.jpg","ar":1.512,"py":"ouzhouheisong ozhs","cr_by":"Karl Gruber","cr_lic":"CC BY-SA 3.0","cr_licurl":"http://creativecommons.org/licenses/by-sa/3.0/","habit":"针叶树","origin":["亚洲","欧洲","非洲"]},{"id":940,"zh":"地中海松","en":"Pinus halepensis","sci":"Pinus halepensis","order_en":"Pinales","order_zh":"松目","family_en":"Pinaceae","family_zh":"松科","iucn":"LC","langs":58,"desc_zh":"地中海松（学名：Pinus halepensis），或称阿勒颇松，是松属下的一种乔木，原产于地中海周边所有低海拔地区。","desc_en":"Pinus halepensis, commonly known as the Aleppo pine, also known as the Jerusalem pine, is a pine native to the Mediterranean region. It was officially named by the botanist Philip Miller in his 1768 book The Gardener's Dictionary; he probably never went to Ale…","img":"images/940.jpg","thumb":"images/t/940.jpg","file":"Calanques -- Calanque de Port Pin - Pinus halepensis.jpg","ar":1.501,"py":"dizhonghaisong dzhs","cr_by":"spacebirdy (also known as geimfyglið (:&gt; )=| made with Sternenlaus -spirit)","cr_lic":"CC BY-SA 3.0","cr_licurl":"https://creativecommons.org/licenses/by-sa/3.0","habit":"针叶树","origin":["欧洲"]},{"id":941,"zh":"欧洲山松","en":"Pinus mugo","sci":"Pinus mugo","order_en":"Pinales","order_zh":"松目","family_en":"Pinaceae","family_zh":"松科","iucn":"LC","langs":57,"desc_zh":"欧洲山松（学名：Pinus mugo），又称矮松，是松属下的一种松树，原产于欧洲中部和西南部海拔1,000—2,200米（3,300—7,200英尺）的高山地带。它共有三个亚种。此外作为受欢迎的观赏植物，它还有许多栽培种。","desc_en":"Pinus mugo, known as dwarf mountain pine, mountain pine, scrub mountain pine, Swiss mountain pine, bog pine, creeping pine, or mugo pine, is a species of conifer, native to high elevation habitats from southwestern to Central Europe and Southeast Europe.","img":"images/941.jpg","thumb":"images/t/941.jpg","file":"Kosodrzewina (Sosna górska) Pinus mugo mugo.jpg","ar":0.75,"py":"ouzhoushansong ozss","cr_by":null,"cr_lic":"CC BY-SA 3.0","cr_licurl":"http://creativecommons.org/licenses/by-sa/3.0/","habit":"针叶树","origin":["欧洲"]},{"id":942,"zh":"蓝叶云杉","en":"Picea pungens","sci":"Picea pungens","order_en":"Pinales","order_zh":"松目","family_en":"Pinaceae","family_zh":"松科","iucn":"LC","langs":54,"desc_zh":"蓝叶云杉（学名：Picea pungens）又称蓝云杉、科罗拉多蓝杉，是云杉属的一种植物，为美国科罗拉多州的州树。本种原产于北美洲西部的科罗拉多州、亚利桑那州、爱达荷州、新墨西哥州、犹他州与怀俄明州的洛矶山脉山区，常与花旗松、西黄松与白冷杉一起生长于山地针叶林中，且常生长于河岸带；虽在水分充足的环境下生长较好，但其耐旱能力优于同属其他树种，并能耐受摄氏零下40度的低温。","desc_en":"The blue spruce (Picea pungens), also commonly known as Colorado spruce or Colorado blue spruce, is a species of spruce tree native to North America in Arizona, Colorado, Idaho, New Mexico, Utah and Wyoming.","img":"images/942.jpg","thumb":"images/t/942.jpg","file":"Picea pungens Bryce Canyon NP 2.jpg","ar":0.67,"py":"lanyeyunshan lyys","cr_by":"Quinn Dombrowski from Chicago, USA","cr_lic":"CC BY-SA 2.0","cr_licurl":"https://creativecommons.org/licenses/by-sa/2.0","habit":"针叶树","origin":["北美洲"]},{"id":943,"zh":"刺柏","en":"Juniperus communis","sci":"Juniperus communis","order_en":"Pinales","order_zh":"松目","family_en":"Cupressaceae","family_zh":"柏科","iucn":"LC","langs":89,"desc_zh":"欧刺柏（学名：Juniperus communis）是一种小灌木，是柏科刺柏属的植物。分布于欧洲、北非、北美以及中国大陆的南京、上海、青岛、杭州等地，目前已由人工引种栽培。和亚洲的桧树亲缘关系较近，属于同一属。本属植物的松球和其他柏科植物不同，无翅并有著近似浆果的肉质，其味苦有清香。 自古以来，欧洲人一直使用欧刺柏种子作为煮肉时的调味料，作为利尿的药物使用，或在啤酒发酵的过程中添加刺柏种子作为苦味的来源。","desc_en":"Juniperus communis, the common juniper, is a species of small tree or shrub in the cypress family Cupressaceae. An evergreen conifer, it has the largest geographical range of any woody plant, with a Holarctic distribution throughout the cool temperate Northern…","img":"images/943.jpg","thumb":"images/t/943.jpg","file":"Juniperus communis fruits - Keila.jpg","ar":0.8,"py":"cibai cb","cr_by":"Ivar Leidus","cr_lic":"CC BY-SA 4.0","cr_licurl":"https://creativecommons.org/licenses/by-sa/4.0","habit":"针叶树","origin":null},{"id":944,"zh":"红杉","en":"Sequoia sempervirens","sci":"Sequoia sempervirens","order_en":"Pinales","order_zh":"松目","family_en":"Cupressaceae","family_zh":"柏科","iucn":"EN","langs":75,"desc_zh":"红杉（学名：Sequoia sempervirens），又称海岸红杉、北美红杉、美国红杉、长叶世界爷、加州红木、咖斗，是世界上最高的针叶树（位于第二高花旗松的变种海滨黄杉以及第三高的北美云杉之上）以及是世界上长的最高的植物之一，能长到115公尺高，主要分布于美国加利福尼亚州。目前已知最老的红杉约有2200岁。 红杉（Sequoia）据信为纪念切罗基文字发明者塞阔雅（Seguoyah）而命名。","desc_en":"Sequoia sempervirens () is the sole living species of the genus Sequoia in the cypress family Cupressaceae (formerly treated in Taxodiaceae). Common names include coast redwood, coastal redwood and California redwood.","img":"images/944.jpg","thumb":"images/t/944.jpg","file":"Sequoia sempervirens Big Basin Redwoods State Park 9.jpg","ar":0.667,"py":"hongshan hs","cr_by":"Allie_Caulfield from Germany","cr_lic":"CC BY 2.0","cr_licurl":"https://creativecommons.org/licenses/by/2.0","habit":"针叶树","origin":["北美洲"]},{"id":945,"zh":"巨杉","en":"Sequoiadendron giganteum","sci":"Sequoiadendron giganteum","order_en":"Pinales","order_zh":"松目","family_en":"Cupressaceae","family_zh":"柏科","iucn":"EN","langs":70,"desc_zh":"巨杉（学名：Sequoiadendron giganteum），俗称世界爷，为柏科巨杉属唯一的现生种。主要分布于美国加利福尼亚州内华达山脉西部。阳性树，生长快，而树龄极长。播种繁殖，但幼苗易生病害。巨杉是所有树中最粗大的一种。巨杉不仅是最大的红杉，而且也是地球上最庞大的并且尚存活着的生物。平均可长到50—85米（164—279英尺），直径约5—7米（16—23英尺）。纪录中树高最高可达93.","desc_en":"Sequoiadendron giganteum (also known as the giant sequoia, giant redwood, Sierra redwood or Wellingtonia) is a species of coniferous tree, classified in the family Cupressaceae in the subfamily Sequoioideae.","img":"images/945.jpg","thumb":"images/t/945.jpg","file":"Grizzly Giant Mariposa Grove.jpg","ar":0.541,"py":"jushan js","cr_by":"Mike Murphy ( talk · contribs )","cr_lic":"CC BY-SA 3.0","cr_licurl":"http://creativecommons.org/licenses/by-sa/3.0/","habit":"针叶树","origin":["北美洲"]},{"id":946,"zh":"水杉","en":"Metasequoia glyptostroboides","sci":"Metasequoia glyptostroboides","order_en":"Pinales","order_zh":"松目","family_en":"Cupressaceae","family_zh":"柏科","iucn":"EN","langs":62,"desc_zh":"水杉（学名：Metasequoia glyptostroboides）又名曙杉，落叶乔木，柏科水杉属唯一现存种，中国特产的孑遗珍贵树种，第一批列为中国国家一级保护植物的稀有种类，有植物界“活化石”之称。","desc_en":"Metasequoia glyptostroboides, the dawn redwood, is a fast-growing, endangered deciduous conifer. It is the sole living species of the genus Metasequoia, one of three genera in the subfamily Sequoioideae of the family Cupressaceae.","img":"images/946.jpg","thumb":"images/t/946.jpg","file":"Metasequoia Glyptostroboides2.jpg","ar":0.75,"py":"shuishan ss","cr_by":null,"cr_lic":"CC BY-SA 3.0","cr_licurl":"http://creativecommons.org/licenses/by-sa/3.0/","habit":"针叶树","origin":["亚洲"]},{"id":947,"zh":"地中海柏木","en":"Cupressus sempervirens","sci":"Cupressus sempervirens","order_en":"Pinales","order_zh":"松目","family_en":"Cupressaceae","family_zh":"柏科","iucn":"LC","langs":58,"desc_zh":"地中海柏木（学名：Cupressus sempervirens）为柏科柏木属下的一个种。又名丝柏、义大利柏、铅笔柏。","desc_en":"Cupressus sempervirens (also known as the Mediterranean cypress, Italian cypress, Tuscan cypress, or Persian cypress), is a species of cypress native to the eastern Mediterranean region and Iran.","img":"images/947.jpg","thumb":"images/t/947.jpg","file":"Cyprès.jpg","ar":1.333,"py":"dizhonghaibaimu dzhbm","cr_by":"Taoujouti Abdelmouhaïmen","cr_lic":"CC BY-SA 4.0","cr_licurl":"https://creativecommons.org/licenses/by-sa/4.0","habit":"针叶树","origin":["亚洲","欧洲"]},{"id":948,"zh":"日本柳杉","en":"Cryptomeria japonica","sci":"Cryptomeria japonica","order_en":"Pinales","order_zh":"松目","family_en":"Cupressaceae","family_zh":"柏科","iucn":"NT","langs":57,"desc_zh":"日本柳杉（学名：Cryptomeria japonica），松柏门柏科植物，原本分类于杉科，也是柳杉属中的唯一一种。是日本的特有种。在日本上直称的スギ（杉或杉木）就是指这个品种。英文则多称此树为 Japanese Cedar （中译日本香柏），但此树其实并不是香柏的一种。日本柳杉林占日本全国12%的土地，也是导致花粉症广泛出现的主要原因。 属名Cryptomeria源于希腊语kryptos（隐藏的）和meros（部分）的合成词。","desc_en":"Cryptomeria (literally \"hidden parts\") is a monotypic genus of conifer in the cypress family Cupressaceae. It includes only one species, Cryptomeria japonica (syn. Cupressus japonica L.f.).","img":"images/948.jpg","thumb":"images/t/948.jpg","file":"Jhomonsugi in Yaku Island Japan 001.JPG","ar":1.333,"py":"ribenliushan rbls","cr_by":"Yosemite","cr_lic":"CC BY-SA 3.0","cr_licurl":"http://creativecommons.org/licenses/by-sa/3.0/","habit":"针叶树","origin":["亚洲"]},{"id":949,"zh":"北美香柏","en":"Thuja occidentalis","sci":"Thuja occidentalis","order_en":"Pinales","order_zh":"松目","family_en":"Cupressaceae","family_zh":"柏科","iucn":"LC","langs":55,"desc_zh":"北美香柏（学名：Thuja occidentalis）是柏科崖柏属的植物。分布于原产北美，中国大陆的上海、庐山、南京、武汉、青岛等地目前已由人工引种栽培。","desc_en":"Thuja occidentalis, also known as northern white-cedar, eastern white-cedar, or arborvitae, is an evergreen coniferous tree, in the cypress family Cupressaceae, which is native to eastern Canada and much of the north-central and northeastern United States.","img":"images/949.jpg","thumb":"images/t/949.jpg","file":"2013-11-06 Lac Canards DDumais (21).jpg","ar":0.75,"py":"beimeixiangbai bmxb","cr_by":"Daniel Dumais","cr_lic":"CC BY-SA 4.0","cr_licurl":"https://creativecommons.org/licenses/by-sa/4.0","habit":"针叶树","origin":["北美洲"]},{"id":950,"zh":"侧柏","en":"Platycladus orientalis","sci":"Platycladus orientalis","order_en":"Pinales","order_zh":"松目","family_en":"Cupressaceae","family_zh":"柏科","iucn":"NT","langs":52,"desc_zh":"侧柏（学名：Platycladus orientalis），又名柏树、香柏（河北）、香树、香柯树（湖北宣恩、利川）、黄柏（华北）、扁柏（浙江、安徽）、扁桧（江苏扬州），属柏科。其种加词“orientalis”意为“东方的”。","desc_en":"Platycladus is a monotypic genus of evergreen coniferous trees in the cypress family Cupressaceae, containing only one species, Platycladus orientalis, also known as Chinese thuja, Oriental arborvitae, Chinese arborvitae, biota or Oriental thuja.","img":"images/950.jpg","thumb":"images/t/950.jpg","file":"Platycladus orientalis Simatai.jpg","ar":0.854,"py":"cebai cb","cr_by":"yeowatzup at Flickr","cr_lic":"CC BY 2.0","cr_licurl":"https://creativecommons.org/licenses/by/2.0","habit":"针叶树","origin":["亚洲"]},{"id":951,"zh":"落羽杉","en":"Taxodium distichum","sci":"Taxodium distichum","order_en":"Pinales","order_zh":"松目","family_en":"Cupressaceae","family_zh":"柏科","iucn":"LC","langs":50,"desc_zh":"落羽杉（学名：Taxodium distichum），又名落羽松，是柏科落羽杉属的植物，原产于美国东南部密西西比河下游，尤在湿地环境中形成森林。","desc_en":"Taxodium distichum (baldcypress, bald-cypress, bald cypress, swamp cypress; French: cyprès chauve; cipre in Louisiana) is a deciduous conifer in the family Cupressaceae. It is native to the Southeastern United States.","img":"images/951.jpg","thumb":"images/t/951.jpg","file":"Taxodium distichum NRCSMS01010.jpg","ar":0.714,"py":"luoyushan lys","cr_by":null,"cr_lic":"Public domain","cr_licurl":null,"habit":"针叶树","origin":["北美洲"]},{"id":952,"zh":"桃柘罗汉松","en":"Podocarpus totara","sci":"Podocarpus totara","order_en":"Pinales","order_zh":"松目","family_en":"Podocarpaceae","family_zh":"罗汉松科","iucn":"LC","langs":27,"desc_zh":"桃柘罗汉松（学名：Podocarpus totara；毛利语：Tōtara），也称作纽西兰罗汉松，是纽西兰特有的罗汉松。在整个北岛、南岛的东北部的低地、山地及亚高地上生长，最高生长环境可达海拔600米。 桃柘罗汉松常在土壤肥沃且水分充沛的地方中生长。","desc_en":"Podocarpus totara (), commonly known as the tōtara, is a species of podocarp tree endemic to New Zealand. Found across New Zealand, the tree can grow up to a height of 35 m (115 ft), and is known for its longevity.","img":"images/952.jpg","thumb":"images/t/952.jpg","file":"Giant lowland totara.jpg","ar":0.667,"py":"taozheluohansong tzlhs","cr_by":"Tomas Sobek","cr_lic":"CC BY-SA 4.0","cr_licurl":"https://creativecommons.org/licenses/by-sa/4.0","habit":"针叶树","origin":["大洋洲"]},{"id":953,"zh":"新西兰陆均松","en":"Dacrydium cupressinum","sci":"Dacrydium cupressinum","order_en":"Pinales","order_zh":"松目","family_en":"Podocarpaceae","family_zh":"罗汉松科","iucn":"LC","langs":26,"desc_zh":"纽西兰陆均松（学名：Dacrydium cupressinum）是一种大型的常绿树木，是纽西兰的特有种。过去曾广泛称作red pine（中译红松），但这个名字已慢慢由毛利语所起的名字rimu所取代。","desc_en":"Dacrydium cupressinum, commonly known as rimu, is an evergreen conifer native to New Zealand. A member of the Podocarpaceae, the tree usually reaches 35 metres (100 feet) in height, but may reach up to 60 metres (200 feet) and can have a stout trunk up to 2 m…","img":"images/953.jpg","thumb":"images/t/953.jpg","file":"Rimu-Waitakere.jpg","ar":0.667,"py":"xinxilanlujunsong xxlljs","cr_by":"Kahuroa","cr_lic":"Public domain","cr_licurl":null,"habit":"针叶树","origin":["大洋洲"]},{"id":954,"zh":"智利杉","en":"Saxegothaea conspicua","sci":"Saxegothaea conspicua","order_en":"Pinales","order_zh":"松目","family_en":"Podocarpaceae","family_zh":"罗汉松科","iucn":"NT","langs":24,"desc_zh":null,"desc_en":"Saxegothaea is a genus comprising a single species, Saxegothaea conspicua. It is a conifer in the podocarp family Podocarpaceae, native to southern South America.","img":"images/954.jpg","thumb":"images/t/954.jpg","file":"Saxegothea conspicua 3.jpg","ar":1.07,"py":"zhilishan zls","cr_by":"Stan Shebs","cr_lic":"CC BY-SA 3.0","cr_licurl":"https://creativecommons.org/licenses/by-sa/3.0","habit":"针叶树","origin":["南美洲"]},{"id":955,"zh":"纽西兰鸡毛松","en":"Dacrycarpus dacrydioides","sci":"Dacrycarpus dacrydioides","order_en":"Pinales","order_zh":"松目","family_en":"Podocarpaceae","family_zh":"罗汉松科","iucn":"LC","langs":24,"desc_zh":"纽西兰鸡毛松（学名：Dacrycarpus dacrydioides；毛利语：kahikatea），是罗汉松科鸡毛松属的一种，纽西兰的特有种。","desc_en":"Dacrycarpus dacrydioides, commonly known as kahikatea (from Māori) and white pine, is a coniferous tree endemic to New Zealand. A podocarp, it is New Zealand's tallest tree, gaining heights of 60 metres (200 feet) over a life span of 600 years.","img":"images/955.jpg","thumb":"images/t/955.jpg","file":"Kahikatea.jpg","ar":0.476,"py":"niuxilanjimaosong nxljms","cr_by":null,"cr_lic":"Public domain","cr_licurl":null,"habit":"针叶树","origin":["大洋洲"]},{"id":956,"zh":"智利南洋杉","en":"Araucaria araucana","sci":"Araucaria araucana","order_en":"Pinales","order_zh":"松目","family_en":"Araucariaceae","family_zh":"南洋杉科","iucn":"EN","langs":54,"desc_zh":"智利南洋杉（学名：Araucaria araucana）是最耐寒的南洋杉，原产于智利中部及阿根廷中西部，是常绿树，成年树高50米，树干直径可达2米。其寿命悠长，可达1300年以上。智利南洋杉是南洋杉科少数分布于大洋洲以外的物种，其演化历史相当悠久，故被称为活化石。智利南洋杉是智利的国树。","desc_en":"Araucaria araucana, commonly called the pewen, monkey-puzzle, pehuen or piñonero or Chile pine, is an evergreen tree belonging to the family Araucariaceae and growing to a height of 30–40 m (98–131 ft) and a trunk diameter of 1–1.5 m (3.3–4.9 ft).","img":"images/956.jpg","thumb":"images/t/956.jpg","file":"Araucaria en Parque Nacional Conguillio.jpg","ar":0.667,"py":"zhilinanyangshan zlnys","cr_by":"Vicente Fernández Rioja","cr_lic":"CC BY-SA 4.0","cr_licurl":"https://creativecommons.org/licenses/by-sa/4.0","habit":"针叶树","origin":["南美洲"]},{"id":957,"zh":"异叶南洋杉","en":"Araucaria heterophylla","sci":"Araucaria heterophylla","order_en":"Pinales","order_zh":"松目","family_en":"Araucariaceae","family_zh":"南洋杉科","iucn":"VU","langs":51,"desc_zh":"异叶南洋杉（学名：Araucaria heterophylla），又称小叶南洋杉、诺福克松（Norfolk pine）、诺福克岛松（Norfolk Island pine），是南洋杉属下的一个物种，原产澳洲诺福克岛，主要分布地亦有新喀里多尼亚。柱状南洋杉（Araucaria columnaris）在台湾普遍被误认成异叶南洋杉。","desc_en":"Araucaria heterophylla (synonym A. excelsa) is a species of conifer. As its vernacular name Norfolk Island pine (or Norfolk pine) implies, the tree is endemic to Norfolk Island, an external territory of Australia located in the Pacific Ocean between New Zealan…","img":"images/957.jpg","thumb":"images/t/957.jpg","file":"Araucaria heterophylla Norfolk Island 0.jpg","ar":0.667,"py":"yiyenanyangshan yynys","cr_by":"bertknot from scarborough, australia","cr_lic":"CC BY-SA 2.0","cr_licurl":"https://creativecommons.org/licenses/by-sa/2.0","habit":"针叶树","origin":["大洋洲"]},{"id":958,"zh":"欧洲红豆杉","en":"Taxus baccata","sci":"Taxus baccata","order_en":"Pinales","order_zh":"松目","family_en":"Taxaceae","family_zh":"红豆杉科","iucn":"LC","langs":81,"desc_zh":"欧洲红豆杉（学名：Taxus baccata），红豆杉科红豆杉属常绿乔木。植株高10-20m，胸径达2米。叶线形，深绿色，长1-4cm，螺旋状着生，基部扭转排成二列。假种皮肉质、杯状、红色；种子坚果状，位于假种皮中。原产欧洲及北非西部、伊拉克、亚洲西南部。这植物大部分有毒，食用其叶子可致死。欧洲红豆杉是雌雄异株的树，雄树的寿命天生要比雌树长得多，雄树能活5000多年。","desc_en":"Taxus baccata is an Old World species of evergreen tree in the family Taxaceae. It is the tree originally known as yew, though to distinguish it from related species it is sometimes called common yew, European yew, or, in North America, English yew.","img":"images/958.jpg","thumb":"images/t/958.jpg","file":"Taxus baccata tree.jpg","ar":0.75,"py":"ouzhouhongdoushan ozhds","cr_by":"Sitomon","cr_lic":"CC BY-SA 2.0","cr_licurl":"https://creativecommons.org/licenses/by-sa/2.0","habit":"针叶树","origin":["欧洲","北美洲"]},{"id":959,"zh":"东北红豆杉","en":"Taxus cuspidata","sci":"Taxus cuspidata","order_en":"Pinales","order_zh":"松目","family_en":"Taxaceae","family_zh":"红豆杉科","iucn":"LC","langs":30,"desc_zh":"东北红豆杉（学名：Taxus cuspidata），又称紫杉、日本红豆杉、赤柏松、紫柏松、朱树。其木材纹理细致、色泽美丽且具有香味，被视为良好的建筑及家俱用材，比重约为0.51，心材呈红褐色，在古日本被用来作为大官及神职人员的朝笏，因此又名「一位」。东北红豆杉可入药，药名为「紫杉」 ，大量服用会导致心跳停止。","desc_en":"Taxus cuspidata, the Japanese yew or spreading yew, is a member of the genus Taxus, native to Japan, Korea, northeast China and the extreme southeast of Russia.","img":"images/959.jpg","thumb":"images/t/959.jpg","file":"Taxus cuspidata 2.JPG","ar":1.501,"py":"dongbeihongdoushan dbhds","cr_by":"Dalgial","cr_lic":"CC BY-SA 3.0","cr_licurl":"https://creativecommons.org/licenses/by-sa/3.0","habit":"针叶树","origin":["亚洲"]},{"id":960,"zh":"日本金松","en":"Sciadopitys verticillata","sci":"Sciadopitys verticillata","order_en":"Pinales","order_zh":"松目","family_en":"Sciadopityaceae","family_zh":"金松科","iucn":"NT","langs":45,"desc_zh":"日本金松（学名：Sciadopitys verticillata），为金松科金松属唯一种，只生长在日本，是当地的特有种，目前已经被引种到世界各地，是一种比较珍贵的观赏植物。","desc_en":"Sciadopitys verticillata, the kōyamaki or Japanese umbrella-pine, is a unique conifer endemic to Japan. It is the sole living member of the family Sciadopityaceae and genus Sciadopitys, a living fossil with no close relatives.","img":"images/960.jpg","thumb":"images/t/960.jpg","file":"Sekiunji Koyamaki, Osaki.jpg","ar":0.75,"py":"ribenjinsong rbjs","cr_by":"Ty19080914","cr_lic":"CC BY-SA 4.0","cr_licurl":"https://creativecommons.org/licenses/by-sa/4.0","habit":"针叶树","origin":["亚洲"]},{"id":961,"zh":"灌状买麻藤","en":"Gnetum gnemon","sci":"Gnetum gnemon","order_en":"Gnetales","order_zh":"买麻藤目","family_en":"Gnetaceae","family_zh":"买麻藤科","iucn":"LC","langs":34,"desc_zh":"灌状买麻藤（Gnetum gnemon）是裸子植物门买麻藤属下的一种植物，其原产地从印度的米佐拉姆邦和阿萨姆邦向南延伸，经马来半岛、马来群岛及菲律宾群岛直至西太平洋诸岛。","desc_en":"Gnetum gnemon is a gymnosperm species of Gnetum. Its native area spans from Mizoram and Assam in India down south through Malay Peninsula, Malay Archipelago and the Philippines in southeast Asia to the western Pacific islands.","img":"images/961.jpg","thumb":"images/t/961.jpg","file":"Melinjo (Gnetum gnemon) (6863727669).jpg","ar":1.501,"py":"guanzhuangmaimateng gzmmt","cr_by":"gbohne from Berlin, Germany","cr_lic":"CC BY-SA 2.0","cr_licurl":"https://creativecommons.org/licenses/by-sa/2.0","habit":null,"origin":["亚洲","大洋洲"]},{"id":962,"zh":"双穗麻黄","en":"Ephedra distachya","sci":"Ephedra distachya","order_en":"Gnetales","order_zh":"买麻藤目","family_en":"Ephedraceae","family_zh":"麻黄科","iucn":"LC","langs":30,"desc_zh":null,"desc_en":"Ephedra distachya is a shrub in the family Ephedraceae that stands about 25 cm to 50 cm high. The shrub grows in many parts of the world, including southern and central Europe and western and central Asia. Its local names include somlatha.","img":"images/962.jpg","thumb":"images/t/962.jpg","file":"Ephedra distachya.jpg","ar":0.893,"py":"shuangsuimahuang ssmh","cr_by":null,"cr_lic":"CC BY-SA 3.0","cr_licurl":"http://creativecommons.org/licenses/by-sa/3.0/","habit":"灌木","origin":["亚洲","欧洲"]},{"id":963,"zh":"草麻黄","en":"Ephedra sinica","sci":"Ephedra sinica","order_en":"Gnetales","order_zh":"买麻藤目","family_en":"Ephedraceae","family_zh":"麻黄科","iucn":"LC","langs":24,"desc_zh":"草麻黄（学名：Ephedra sinica）为麻黄科麻黄属下的一个种。其种加词sinica，意为“中华的”。","desc_en":"Ephedra sinica (also known as Chinese ephedra or ma huang) is a species of Ephedra in the plant family Ephedraceae. Native to Mongolia, northern China, and Russia, it is a shrub found on arid highland slopes, dry river beds, steppes, fields or mountain sides.","img":"images/963.jpg","thumb":"images/t/963.jpg","file":"Ephedra sinica alexlomas.jpg","ar":0.752,"py":"caomahuang cmh","cr_by":"alexlomas on Flickr","cr_lic":"CC BY 2.0","cr_licurl":"https://creativecommons.org/licenses/by/2.0","habit":"灌木","origin":["亚洲"]},{"id":964,"zh":"百岁兰","en":"Welwitschia mirabilis","sci":"Welwitschia mirabilis","order_en":"Welwitschiales","order_zh":"百岁兰目","family_en":"Welwitschiaceae","family_zh":"百岁兰科","iucn":null,"langs":75,"desc_zh":"百岁兰（学名：Welwitschia mirabilis）是单种科百岁兰科百岁兰属的唯一物种。又称为百岁叶、千岁兰、奇想天外、二叶树。最早发现于1859年9月3日，由奥地利探险家Friedrich Martin Joseph Welwitsch发现于非洲安哥拉的沙漠之中。主要分布在安哥拉与纳米布沙漠。茎短，一生只长两片叶。雌雄异株。叶上的气孔会吸收大气中的水气，根极长，可达3米至10米，以吸收地下水。","desc_en":"Welwitschia is a monotypic genus of gnetophytes containing only the species Welwitschia mirabilis. It is named after the Austrian botanist Friedrich Welwitsch, who documented the plant in the 1850s. In common use, it is sometimes referred to as the tree tumbo.","img":"images/964.jpg","thumb":"images/t/964.jpg","file":"Welwitschia mirablis ^ Ragnhild-4657 - Flickr - Ragnhild & Neil Crawford.jpg","ar":1.501,"py":"baisuilan bsl","cr_by":"Ragnhild&Neil Crawford from Sweden","cr_lic":"CC BY-SA 2.0","cr_licurl":"https://creativecommons.org/licenses/by-sa/2.0","habit":"乔木","origin":["非洲"]},{"id":965,"zh":"银叶蕨","en":"Alsophila dealbata","sci":"Alsophila dealbata","order_en":"Cyatheales","order_zh":"桫椤目","family_en":"Cyatheaceae","family_zh":"桫椤科","iucn":null,"langs":32,"desc_zh":"银叶蕨（Cyathea dealbata）是一种生长于纽西兰的蕨类植物。纽西兰是蕨类植物的宝库，许多蕨类植物甚至可以生长为树木大小，银叶蕨就是其中之一。银叶蕨因其叶子为白色而成为毛利人的信仰对象，并且也是纽西兰的象征之一，是纽西兰国徽的组成图案。银叶蕨高度可达10米以上，但通常匍匐生长。其叶子长度可达4米，而背面呈银色，因而得名。","desc_en":"Alsophila dealbata (synonyms Alsophila tricolor and Cyathea dealbata), commonly known as the silver fern or silver tree-fern, or as ponga or punga (from Māori kaponga or ponga), is a species of medium-sized tree fern, endemic to New Zealand.","img":"images/965.jpg","thumb":"images/t/965.jpg","file":"Cyathea dealbata - Jon Sullivan - 1385477.jpeg","ar":0.721,"py":"yinyejue yyj","cr_by":"Jon Sullivan","cr_lic":"CC BY 4.0","cr_licurl":"https://creativecommons.org/licenses/by/4.0","habit":"蕨类","origin":["大洋洲"]},{"id":966,"zh":"Sphaeropteris medullaris","en":"Sphaeropteris medullaris","sci":"Sphaeropteris medullaris","order_en":"Cyatheales","order_zh":"桫椤目","family_en":"Cyatheaceae","family_zh":"桫椤科","iucn":null,"langs":14,"desc_zh":null,"desc_en":"Sphaeropteris medullaris, synonym Cyathea medullaris, commonly known as mamaku or black tree fern, is a large tree fern up to 20 m (66 ft) tall with a trunk up to 20 cm diameter at breast height.","img":"images/966.jpg","thumb":"images/t/966.jpg","file":"Cyathea medullaris.JPG","ar":0.75,"py":"","cr_by":"wikimedia user gerald.w","cr_lic":"CC BY 2.5","cr_licurl":"https://creativecommons.org/licenses/by/2.5","habit":"蕨类","origin":["大洋洲"]},{"id":967,"zh":"欧亚多足蕨","en":"Polypodium vulgare","sci":"Polypodium vulgare","order_en":"Polypodiales","order_zh":"水龙骨目","family_en":"Polypodiaceae","family_zh":"水龙骨科","iucn":null,"langs":45,"desc_zh":"欧亚多足蕨（学名：Polypodium vulgare）为水龙骨科多足蕨属下的一个种。","desc_en":"Polypodium vulgare, the common polypody, is an evergreen fern of the family Polypodiaceae. The name is derived from Greek poly- (\"many\") and pous, podos (\"foot\").","img":"images/967.jpg","thumb":"images/t/967.jpg","file":"Engelsüß HD.JPG","ar":0.75,"py":"ouyaduozujue oydzj","cr_by":"4028mdk09","cr_lic":"CC BY-SA 3.0","cr_licurl":"https://creativecommons.org/licenses/by-sa/3.0","habit":"蕨类","origin":null},{"id":968,"zh":"二歧鹿角蕨","en":"Platycerium bifurcatum","sci":"Platycerium bifurcatum","order_en":"Polypodiales","order_zh":"水龙骨目","family_en":"Polypodiaceae","family_zh":"水龙骨科","iucn":null,"langs":21,"desc_zh":"二歧鹿角蕨（学名：Platycerium bifurcatum）为鹿角蕨科鹿角蕨属下的一个种。","desc_en":"Platycerium bifurcatum, commonly known as the elkhorn fern or staghorn fern, is a species of plant in the fern family Polypodiaceae native to Java, Bali, New Guinea,andi in Australia ( New South Wales, Queensland and Lord Howe Island).","img":"images/968.jpg","thumb":"images/t/968.jpg","file":"Platycerium bifurcatum kz01.jpg","ar":1.501,"py":"erqilujiaojue eqljj","cr_by":"Krzysztof Ziarnek, Kenraiz","cr_lic":"CC BY-SA 4.0","cr_licurl":"https://creativecommons.org/licenses/by-sa/4.0","habit":"蕨类","origin":["大洋洲"]},{"id":969,"zh":"有翅星蕨","en":"Microsorum pteropus","sci":"Microsorum pteropus","order_en":"Polypodiales","order_zh":"水龙骨目","family_en":"Polypodiaceae","family_zh":"水龙骨科","iucn":null,"langs":20,"desc_zh":"有翅星蕨（学名：Microsorum pteropus）又名铁皇冠、三叉叶星蕨，为水龙骨科星蕨属下的一个种。","desc_en":"Leptochilus pteropus (synonym Microsorum pteropus) is a species of aquatic or semi-aquatic fern, commonly known as Java fern (after the Indonesian island of Java). It is predominantly known from Malaysia, Thailand, Northeastern India and parts of South China.","img":"images/969.jpg","thumb":"images/t/969.jpg","file":"Microsorum pteropus.jpg","ar":0.898,"py":"youchixingjue ycxj","cr_by":"Tsunamicarlos at English Wikipedia","cr_lic":"Public domain","cr_licurl":null,"habit":"蕨类","origin":null},{"id":970,"zh":"Polypodium cambricum","en":"Polypodium cambricum","sci":"Polypodium cambricum","order_en":"Polypodiales","order_zh":"水龙骨目","family_en":"Polypodiaceae","family_zh":"水龙骨科","iucn":null,"langs":19,"desc_zh":null,"desc_en":"Polypodium cambricum, the southern polypody, limestone polypody, or Welsh polypody, is a species of fern in the family Polypodiaceae, native to southern and western Europe where it grows on shady rocks, near the coasts of the Mediterranean Basin and in the mou…","img":"images/970.jpg","thumb":"images/t/970.jpg","file":"Polypodium cambricum 001.jpg","ar":1.333,"py":"","cr_by":"Johan N","cr_lic":"CC BY-SA 3.0","cr_licurl":"https://creativecommons.org/licenses/by-sa/3.0","habit":"蕨类","origin":["欧洲"]},{"id":971,"zh":"金水龙骨","en":"Phlebodium aureum","sci":"Phlebodium aureum","order_en":"Polypodiales","order_zh":"水龙骨目","family_en":"Polypodiaceae","family_zh":"水龙骨科","iucn":null,"langs":17,"desc_zh":null,"desc_en":"Phlebodium aureum (golden polypody, golden serpent fern, cabbage palm fern, gold-foot fern, blue-star fern, hare-foot fern; syn. Polypodium aureum, Polypodium leucotomos) is an epiphytic fern native to tropical and subtropical regions of the Americas.","img":"images/971.jpg","thumb":"images/t/971.jpg","file":"Starr 050107-2831 Phlebodium aureum.jpg","ar":1.336,"py":"jinshuilonggu jslg","cr_by":"Forest & Kim Starr","cr_lic":"CC BY 3.0","cr_licurl":"https://creativecommons.org/licenses/by/3.0","habit":"蕨类","origin":null},{"id":972,"zh":"Polypodium interjectum","en":"Polypodium interjectum","sci":"Polypodium interjectum","order_en":"Polypodiales","order_zh":"水龙骨目","family_en":"Polypodiaceae","family_zh":"水龙骨科","iucn":null,"langs":17,"desc_zh":null,"desc_en":"Polypodium interjectum is a species of fern.","img":"images/972.jpg","thumb":"images/t/972.jpg","file":"3970-Polypodium interjectum-Foresta Umbra-5.06.jpg","ar":1.215,"py":"","cr_by":"Vojtěch Zavadil","cr_lic":"CC BY-SA 4.0","cr_licurl":"https://creativecommons.org/licenses/by-sa/4.0","habit":"蕨类","origin":null},{"id":973,"zh":"南方铁线蕨","en":"Adiantum capillus-veneris","sci":"Adiantum capillus-veneris","order_en":"Polypodiales","order_zh":"水龙骨目","family_en":"Pteridaceae","family_zh":"凤尾蕨科","iucn":"LC","langs":57,"desc_zh":"铁线蕨（学名：Adiantum capillus-veneris），是凤尾蕨科铁线蕨属的一种植物，又名铁丝草、少女的发丝、铁线草、水猪毛土、银杏蕨、条裂铁线蕨。","desc_en":"Adiantum capillus-veneris, the maidenhair fern, southern maidenhair fern, black maidenhair fern and venus hair fern, is a species of ferns in the genus Adiantum and the family Pteridaceae with a subcosmopolitan worldwide distribution.","img":"images/973.jpg","thumb":"images/t/973.jpg","file":"Adiantum capillus-veneris 2601.jpg","ar":1.333,"py":"nanfangtiexianjue nftxj","cr_by":"Balles2601","cr_lic":"CC BY-SA 4.0","cr_licurl":"https://creativecommons.org/licenses/by-sa/4.0","habit":"蕨类","origin":null},{"id":974,"zh":"Cryptogramma crispa","en":"Cryptogramma crispa","sci":"Cryptogramma crispa","order_en":"Polypodiales","order_zh":"水龙骨目","family_en":"Pteridaceae","family_zh":"凤尾蕨科","iucn":null,"langs":26,"desc_zh":null,"desc_en":"Cryptogramma crispa, the parsley fern, is an Arctic–alpine species of fern native to Europe and parts of Asia. It produces separate sterile and fertile fronds, up to 30 cm (12 in) tall, and is a pioneer species on acidic screes.","img":"images/974.jpg","thumb":"images/t/974.jpg","file":"Cryptogramma crispa.jpg","ar":1.333,"py":"","cr_by":"Meneerke bloem","cr_lic":"CC BY-SA 4.0","cr_licurl":"https://creativecommons.org/licenses/by-sa/4.0","habit":"蕨类","origin":["亚洲","欧洲"]},{"id":975,"zh":"欧洲凤尾蕨","en":"Pteris cretica","sci":"Pteris cretica","order_en":"Polypodiales","order_zh":"水龙骨目","family_en":"Pteridaceae","family_zh":"凤尾蕨科","iucn":null,"langs":23,"desc_zh":"欧洲凤尾蕨（学名：Pteris cretica）也称井口边草，为凤尾蕨科凤尾蕨属下的一个植物变种。 别名 白玉凤尾蕨, 井口边草, 石化野鸡尾, 还阳草, 鸡爪凤尾草。","desc_en":"Pteris cretica, the Cretan brake, ribbon fern, or Cretan brake fern, is a species of evergreen fern in the family Pteridaceae, native to Europe, Asia and Africa.","img":"images/975.jpg","thumb":"images/t/975.jpg","file":"Pteris cretica 370560915.jpg","ar":0.75,"py":"ouzhoufengweijue ozfwj","cr_by":"naturewatchwidow","cr_lic":"CC BY 4.0","cr_licurl":"https://creativecommons.org/licenses/by/4.0","habit":"蕨类","origin":["亚洲","欧洲","非洲"]},{"id":976,"zh":"蜈蚣凤尾蕨","en":"Pteris vittata","sci":"Pteris vittata","order_en":"Polypodiales","order_zh":"水龙骨目","family_en":"Pteridaceae","family_zh":"凤尾蕨科","iucn":"LC","langs":22,"desc_zh":"鳞盖凤尾蕨（学名：Pteris vittata L.），常见于低海拔温暖潮湿之阔叶林，野外空旷山坡、道路边坡、水沟或砖墙上皆可发现。","desc_en":"Pteris vittata, the Chinese brake, Chinese ladder brake, or simply ladder brake, is a fern species in the Pteridoideae subfamily of the Pteridaceae. It is indigenous to Asia, southern Europe, tropical Africa, and Australia.","img":"images/976.jpg","thumb":"images/t/976.jpg","file":"Pteris vittata.jpg","ar":0.607,"py":"wugongfengweijue wgfwj","cr_by":"Franz Xaver","cr_lic":"CC BY-SA 3.0","cr_licurl":"http://creativecommons.org/licenses/by-sa/3.0/","habit":"蕨类","origin":["亚洲","欧洲","非洲","大洋洲"]},{"id":977,"zh":"卤蕨","en":"Acrostichum aureum","sci":"Acrostichum aureum","order_en":"Polypodiales","order_zh":"水龙骨目","family_en":"Pteridaceae","family_zh":"凤尾蕨科","iucn":"LC","langs":21,"desc_zh":"卤蕨（学名：Acrostichum aureum）为凤尾蕨科卤蕨属下的一个种。泛生于世界热带与亚热带滨海地段。卤蕨为台湾原生，1860至1880年代台北淡水曾有过采集记录，现今仅见于垦丁国家公园的佳洛水、花莲罗山与台东关山一带，族群以罗山较大。为台湾优先保育植物。于大湾区台山镇海湾国家湿地公园一带属保育植物。 卤蕨丛生，植株粗大直立，根部肥厚，为其主要特征。高可达2公尺。","desc_en":"Acrostichum aureum, the golden leather fern, is a large species of fern that grows in mangrove swamps and other wet locations. Other common names include swamp fern and mangrove fern.","img":"images/977.jpg","thumb":"images/t/977.jpg","file":"Acros aure 080627 0097 smlu.jpg","ar":0.804,"py":"lujue lj","cr_by":"Wibowo Djatmiko ( Wie146 )","cr_lic":"CC BY-SA 3.0","cr_licurl":"https://creativecommons.org/licenses/by-sa/3.0","habit":"蕨类","origin":null},{"id":978,"zh":"欧洲鳞毛蕨","en":"Dryopteris filix-mas","sci":"Dryopteris filix-mas","order_en":"Polypodiales","order_zh":"水龙骨目","family_en":"Dryopteridaceae","family_zh":"鳞毛蕨科","iucn":null,"langs":57,"desc_zh":"欧洲鳞毛蕨（学名：Dryopteris filix-mas）为鳞毛蕨科鳞毛蕨属下的一个种。","desc_en":"Dryopteris filix-mas, the male fern, is a common fern of the temperate Northern Hemisphere, native to much of Europe, Asia, and North America. It favours damp shaded areas in the understory of woodlands, but also shady places on hedge-banks, and rocks, and scr…","img":"images/978.jpg","thumb":"images/t/978.jpg","file":"Dryopteris filix mas nf.jpg","ar":0.677,"py":"ouzhoulinmaojue ozlmj","cr_by":"Carl Axel Magnus Lindman","cr_lic":"Public domain","cr_licurl":null,"habit":"蕨类","origin":["亚洲","欧洲","北美洲"]},{"id":979,"zh":"刺叶鳞毛蕨","en":"Dryopteris carthusiana","sci":"Dryopteris carthusiana","order_en":"Polypodiales","order_zh":"水龙骨目","family_en":"Dryopteridaceae","family_zh":"鳞毛蕨科","iucn":null,"langs":30,"desc_zh":"刺叶鳞毛蕨（学名：Dryopteris carthusiana）为鳞毛蕨科鳞毛蕨属下的一个种。","desc_en":"Dryopteris carthusiana is a perennial species of fern native to damp forests throughout the Holarctic Kingdom. It is known as the narrow buckler-fern in the United Kingdom, and as the spinulose woodfern in North America.","img":"images/979.jpg","thumb":"images/t/979.jpg","file":"Dryopteris carthusiana.jpg","ar":1.523,"py":"ciyelinmaojue cylmj","cr_by":"Franz Xaver","cr_lic":"CC BY-SA 3.0","cr_licurl":"https://creativecommons.org/licenses/by-sa/3.0","habit":"蕨类","origin":null},{"id":980,"zh":"欧洲耳蕨","en":"Polystichum aculeatum","sci":"Polystichum aculeatum","order_en":"Polypodiales","order_zh":"水龙骨目","family_en":"Dryopteridaceae","family_zh":"鳞毛蕨科","iucn":null,"langs":28,"desc_zh":"欧洲耳蕨（学名：Polystichum aculeatum）为鳞毛蕨科耳蕨属下的一个种。","desc_en":"Polystichum aculeatum, the hard shield-fern, is an evergreen fern native to Europe. It is most abundant in upland regions of the British Isles and western France, where it benefits from the combination of mild winters and moist summers, but also occurs more lo…","img":"images/980.jpg","thumb":"images/t/980.jpg","file":"Polystichum aculeatum.jpg","ar":0.75,"py":"ouzhouerjue ozej","cr_by":"MPF","cr_lic":"CC BY 2.5","cr_licurl":"https://creativecommons.org/licenses/by/2.5","habit":"蕨类","origin":["欧洲"]},{"id":981,"zh":"矛状耳蕨","en":"Polystichum lonchitis","sci":"Polystichum lonchitis","order_en":"Polypodiales","order_zh":"水龙骨目","family_en":"Dryopteridaceae","family_zh":"鳞毛蕨科","iucn":null,"langs":26,"desc_zh":"矛状耳蕨（学名：Polystichum lonchitis），为鳞毛蕨科耳蕨属下的一个种。","desc_en":"Polystichum lonchitis is a species of fern known by the common name northern hollyfern, or simply holly-fern. It is native to much of the Northern Hemisphere from Eurasia to Alaska to Greenland and south into mountainous central North America.","img":"images/981.jpg","thumb":"images/t/981.jpg","file":"Polystichum lonchitis 5579.JPG","ar":1.501,"py":"maozhuangerjue mzej","cr_by":"Walter Siegmund (talk)","cr_lic":"CC BY-SA 3.0","cr_licurl":"https://creativecommons.org/licenses/by-sa/3.0","habit":"蕨类","origin":["亚洲","北美洲"]},{"id":982,"zh":"广布鳞毛蕨","en":"Dryopteris expansa","sci":"Dryopteris expansa","order_en":"Polypodiales","order_zh":"水龙骨目","family_en":"Dryopteridaceae","family_zh":"鳞毛蕨科","iucn":null,"langs":26,"desc_zh":"广布鳞毛蕨（学名：Dryopteris expansa）为鳞毛蕨科鳞毛蕨属下的一个种。","desc_en":"Dryopteris expansa, the alpine buckler fern, northern buckler-fern or spreading wood fern, is a species of perennial fern native to cool temperate and subarctic regions of the Northern Hemisphere, south at high altitudes in mountains to Spain and Greece in sou…","img":"images/982.jpg","thumb":"images/t/982.jpg","file":"Dryopteris expansa.jpg","ar":1.495,"py":"guangbulinmaojue gblmj","cr_by":"Unknown author Unknown author","cr_lic":"Public domain","cr_licurl":null,"habit":"蕨类","origin":["亚洲","欧洲","北美洲"]},{"id":983,"zh":"欧洲对开蕨","en":"Asplenium scolopendrium","sci":"Asplenium scolopendrium","order_en":"Polypodiales","order_zh":"水龙骨目","family_en":"Aspleniaceae","family_zh":"铁角蕨科","iucn":null,"langs":44,"desc_zh":"阿尔泰铁角蕨（学名：Asplenium altajense）为铁角蕨科铁角蕨属下的一个种，分布于北半球。模式标本产地为俄罗斯阿尔泰山。","desc_en":"Asplenium scolopendrium, commonly known as the hart's-tongue fern, is an evergreen fern in the family Aspleniaceae native to the Northern Hemisphere.","img":"images/983.jpg","thumb":"images/t/983.jpg","file":"Asplenium scolopendrium ssp. scolopendrium 20150705 110346 (18816757464).jpg","ar":1.333,"py":"ouzhouduikaijue ozdkj","cr_by":"Erwin Gruber from Frohnleiten, Österreich, Steiermark","cr_lic":"CC BY-SA 2.0","cr_licurl":"https://creativecommons.org/licenses/by-sa/2.0","habit":"蕨类","origin":null},{"id":984,"zh":"铁角蕨","en":"Asplenium trichomanes","sci":"Asplenium trichomanes","order_en":"Polypodiales","order_zh":"水龙骨目","family_en":"Aspleniaceae","family_zh":"铁角蕨科","iucn":null,"langs":41,"desc_zh":"铁角蕨（学名：Asplenium trichomanes）为铁角蕨科铁角蕨属下的一个种，广泛分布于南极外各大洲。","desc_en":"Asplenium trichomanes, the maidenhair spleenwort (not to be confused with the similarly-named but very different maidenhair fern), is a small fern in the spleenwort genus Asplenium.","img":"images/984.jpg","thumb":"images/t/984.jpg","file":"Asplenium trichomanes subsp. trichomanes 001.jpg","ar":1.333,"py":"tiejiaojue tjj","cr_by":"Johan N","cr_lic":"CC BY-SA 3.0","cr_licurl":"https://creativecommons.org/licenses/by-sa/3.0","habit":"蕨类","origin":null},{"id":985,"zh":"银杏叶铁角蕨","en":"Asplenium ruta-muraria","sci":"Asplenium ruta-muraria","order_en":"Polypodiales","order_zh":"水龙骨目","family_en":"Aspleniaceae","family_zh":"铁角蕨科","iucn":null,"langs":35,"desc_zh":"卵叶铁角蕨（学名：Asplenium rutamuraria）也称银杏叶铁角蕨、疏羽铁角蕨，为铁角蕨科铁角蕨属下的一个种。","desc_en":"Asplenium ruta-muraria is a species of fern commonly known as wall-rue (but which, as a fern, is not by any means closely related to common rue). It is a very small epipetric species, growing exclusively on limestone and other calcareous rocks.","img":"images/985.jpg","thumb":"images/t/985.jpg","file":"505 Asplenium ruta muraria, Asplenium septentrionale.jpg","ar":0.706,"py":"yinxingyetiejiaojue yxytjj","cr_by":"Carl Axel Magnus Lindman","cr_lic":"Public domain","cr_licurl":null,"habit":"蕨类","origin":null},{"id":986,"zh":"深山铁角蕨","en":"Asplenium adiantum-nigrum","sci":"Asplenium adiantum-nigrum","order_en":"Polypodiales","order_zh":"水龙骨目","family_en":"Aspleniaceae","family_zh":"铁角蕨科","iucn":null,"langs":31,"desc_zh":"深山铁角蕨（学名：Asplenium adiantum-nigrum）为铁角蕨科铁角蕨属下的一个种。","desc_en":"Asplenium adiantum-nigrum is a common species of fern known by the common name black spleenwort. It is found mostly in Africa, Europe, and Eurasia, but is also native to a few locales in Mexico and the United States.","img":"images/986.jpg","thumb":"images/t/986.jpg","file":"Asplenium adiantum-nigrum 030208.jpg","ar":1.602,"py":"shenshantiejiaojue sstjj","cr_by":"Bernd Haynold","cr_lic":"CC BY-SA 3.0","cr_licurl":"https://creativecommons.org/licenses/by-sa/3.0","habit":"蕨类","origin":["北美洲"]},{"id":987,"zh":"欧洲蕨","en":"Pteridium aquilinum","sci":"Pteridium aquilinum","order_en":"Polypodiales","order_zh":"水龙骨目","family_en":"Dennstaedtiaceae","family_zh":"碗蕨科","iucn":null,"langs":50,"desc_zh":"欧洲蕨（学名：Pteridium aquilinum）是碗蕨科蕨属植物。","desc_en":"Pteridium aquilinum, commonly called bracken, brake, pasture brake, common bracken, and also known as eagle fern, is a species of fern occurring in temperate and subtropical regions in both hemispheres.","img":"images/987.jpg","thumb":"images/t/987.jpg","file":"DidzialapisSakys.JPG","ar":1.333,"py":"ouzhoujue ozj","cr_by":"Hugo.arg","cr_lic":"CC BY-SA 3.0","cr_licurl":"http://creativecommons.org/licenses/by-sa/3.0/","habit":"蕨类","origin":["亚洲","北美洲"]},{"id":988,"zh":"Dennstaedtia punctilobula","en":"Dennstaedtia punctilobula","sci":"Dennstaedtia punctilobula","order_en":"Polypodiales","order_zh":"水龙骨目","family_en":"Dennstaedtiaceae","family_zh":"碗蕨科","iucn":null,"langs":12,"desc_zh":null,"desc_en":"Sitobolium punctilobulum, the eastern hayscented fern or hay-scented fern, is a species of fern native to eastern North America, from Newfoundland west to Wisconsin and Arkansas, and south in the Appalachian Mountains to northern Alabama; it is most abundant i…","img":"images/988.jpg","thumb":"images/t/988.jpg","file":"Dennstaedtia punctilobula2.jpg","ar":1.34,"py":"","cr_by":"Jaknouse","cr_lic":"CC BY 3.0","cr_licurl":"https://creativecommons.org/licenses/by/3.0","habit":"蕨类","origin":["北美洲"]},{"id":989,"zh":"槐叶苹","en":"Salvinia natans","sci":"Salvinia natans","order_en":"Salviniales","order_zh":"槐叶蘋目","family_en":"Salviniaceae","family_zh":"槐叶蘋科","iucn":"LC","langs":35,"desc_zh":"槐叶苹（学名：Salvinia natans），又称蜈蚣苹（台湾话：Giâ-kang-phîng），日语称为山椒藻（サンショウモ），属于漂浮性的水生蕨类植物，通常在春夏时不长孢子囊，等入秋后方由繁殖器官出现，可做为药用，这种植物广布于中国长江以南及华北、东北各地，四川更为普遍；此外越南、印度、台湾、日本和欧洲也有 ，其生长在淡水的沼泽湿地，也是一种重要的环境指标生物，由于目前不少淡水的水域环境遭到过度开发或污染，则逐渐变成一种濒临绝种的…","desc_en":"Salvinia natans (commonly known as floating fern, floating watermoss, floating moss, or commercially, water butterfly wings) is an annual floating aquatic fern, which can appear superficially similar to moss.","img":"images/989.jpg","thumb":"images/t/989.jpg","file":"Salvinia natans (habitus) 1.jpg","ar":1.336,"py":"huaiyeping hyp","cr_by":"Le.Loup.Gris","cr_lic":"CC BY-SA 3.0","cr_licurl":"https://creativecommons.org/licenses/by-sa/3.0","habit":"蕨类","origin":["亚洲","欧洲","非洲"]},{"id":990,"zh":"苹","en":"Marsilea quadrifolia","sci":"Marsilea quadrifolia","order_en":"Salviniales","order_zh":"槐叶蘋目","family_en":"Marsileaceae","family_zh":"蘋科","iucn":"LC","langs":31,"desc_zh":"苹（学名：Marsilea quadrifolia）为苹科苹属下的一个种。其种加词“quadrifolia”意为“四叶的”。","desc_en":"Marsilea quadrifolia is a herbaceous plant found naturally in central and southern Europe, Caucasia, western Siberia, Afghanistan, south-west India, China, Japan, and Vietnam, though it is considered a weed in some parts of the United States, where it has been…","img":"images/990.jpg","thumb":"images/t/990.jpg","file":"Marsilea quadrifolia denjisou01.jpg","ar":1.333,"py":"ping p","cr_by":"No machine-readable author provided. Keisotyo assumed (based on copyright claims).","cr_lic":"CC BY-SA 3.0","cr_licurl":"http://creativecommons.org/licenses/by-sa/3.0/","habit":"蕨类","origin":["亚洲","欧洲","北美洲"]},{"id":991,"zh":"高贵紫萁","en":"Osmunda regalis","sci":"Osmunda regalis","order_en":"Osmundales","order_zh":"紫萁目","family_en":"Osmundaceae","family_zh":"紫萁科","iucn":"LC","langs":37,"desc_zh":null,"desc_en":"Osmunda regalis, or royal fern, is a species of deciduous fern, native to Europe, North Africa and West Asia, growing in woodland bogs and on the banks of streams. The species is sometimes known as flowering fern due to the appearance of its fertile fronds.","img":"images/991.jpg","thumb":"images/t/991.jpg","file":"OsmundaRegalis.jpg","ar":1.545,"py":"gaoguiziqi ggzq","cr_by":"Christian Fischer","cr_lic":"CC BY-SA 3.0","cr_licurl":"https://creativecommons.org/licenses/by-sa/3.0","habit":"蕨类","origin":["亚洲","欧洲","非洲"]},{"id":992,"zh":"问荆","en":"Equisetum arvense","sci":"Equisetum arvense","order_en":"Equisetales","order_zh":"木贼目","family_en":"Equisetaceae","family_zh":"木贼科","iucn":"LC","langs":77,"desc_zh":"问荆（学名：Equisetum arvense），又名杉菜，为木贼科木贼属下的一个种。","desc_en":"Equisetum arvense, commonly known as field horsetail or common horsetail, is a species of vascular plant in the horsetail family Equisetaceae. Like all horsetails, it is a type of fern.","img":"images/992.jpg","thumb":"images/t/992.jpg","file":"Equisetum arvense 126536963.jpg","ar":0.75,"py":"wenjing wj","cr_by":"botany08","cr_lic":"CC BY 4.0","cr_licurl":"https://creativecommons.org/licenses/by/4.0","habit":"蕨类","origin":null},{"id":993,"zh":"犬问荆","en":"Equisetum palustre","sci":"Equisetum palustre","order_en":"Equisetales","order_zh":"木贼目","family_en":"Equisetaceae","family_zh":"木贼科","iucn":"LC","langs":43,"desc_zh":"犬问荆（学名：Equisetum palustre）为木贼科木贼属下的一个种。","desc_en":"Equisetum palustre, the marsh horsetail, is a perennial herbaceous pteridophyte belonging to the subclass of horsetails (Equisetidae). It is widespread in cooler regions of Eurasia and North America.","img":"images/993.jpg","thumb":"images/t/993.jpg","file":"Equisetum palustre detail.jpeg","ar":1.333,"py":"quanwenjing qwj","cr_by":"Kristian Peters -- Fabelfroh 16:29, 12 August 2006 (UTC)","cr_lic":"CC BY-SA 3.0","cr_licurl":"http://creativecommons.org/licenses/by-sa/3.0/","habit":"蕨类","origin":["亚洲","北美洲"]},{"id":994,"zh":"瓶尔小草","en":"Ophioglossum vulgatum","sci":"Ophioglossum vulgatum","order_en":"Ophioglossales","order_zh":"瓶尔小草目","family_en":"Ophioglossaceae","family_zh":"瓶尔小草科","iucn":null,"langs":38,"desc_zh":"瓶尔小草（学名：Ophioglossum vulgatum），为瓶尔小草科瓶尔小草属下的一个植物种。根肥厚肉质，茎短而直立， 叶片单叶全缘肉质，有时叶片上同时著生孢子囊枝，地生型的蕨类，可见于台湾低海拔地区，有时公园中空旷的草地上也可见到。整个叶片汤匙状一片片挺出地面，因此又俗称为一叶草，是一种治疮的中药材，在公园或学校绿油油的草地上偶见有人弯腰采草药，他们多半就是在寻觅瓶尔小草。","desc_en":"Ophioglossum vulgatum, commonly known as adder's-tongue, southern adder's-tongue or adder's-tongue fern, is a species of fern in the family Ophioglossaceae. The chloroplast genome was reported to have a size of 138,562 base pairs.","img":"images/994.jpg","thumb":"images/t/994.jpg","file":"Ophioglossum vulgatum Saarland 01.jpg","ar":0.75,"py":"pingerxiaocao pexc","cr_by":"Orchi","cr_lic":"CC BY-SA 3.0","cr_licurl":"http://creativecommons.org/licenses/by-sa/3.0/","habit":"蕨类","origin":null},{"id":995,"zh":"东北石松","en":"Lycopodium clavatum","sci":"Lycopodium clavatum","order_en":"Lycopodiales","order_zh":"石松目","family_en":"Lycopodiaceae","family_zh":"石松科","iucn":null,"langs":53,"desc_zh":"东北石松（学名：Lycopodium clavatum）为石松科石松属下的一个种。台湾话称为石松仔（Tsio̍h-siông-á）、狮仔尾（Sai-á-bué），日语称为日阴蔓（ヒカゲノカズラ）。","desc_en":"Lycopodium clavatum (common clubmoss, stag's-horn clubmoss, running clubmoss, or ground pine) is the most widespread species in the genus Lycopodium in the clubmoss family.","img":"images/995.jpg","thumb":"images/t/995.jpg","file":"Lycopodium clavatum 151207.jpg","ar":0.885,"py":"dongbeishisong dbss","cr_by":"Bernd Haynold","cr_lic":"CC BY-SA 3.0","cr_licurl":"https://creativecommons.org/licenses/by-sa/3.0","habit":"蕨类","origin":null},{"id":996,"zh":"小杉兰","en":"Huperzia selago","sci":"Huperzia selago","order_en":"Lycopodiales","order_zh":"石松目","family_en":"Lycopodiaceae","family_zh":"石松科","iucn":null,"langs":45,"desc_zh":"小杉兰（学名：Huperzia selago，台湾话：Sió-sam-lân），又称小杉叶石松、小叶石杉，为石杉科石杉属下的一个种。","desc_en":"Huperzia selago, the northern firmoss or fir clubmoss, is a vascular plant in the family Lycopodiaceae. It is small-ish, sturdy, stiff and upright and densely scale-leaved. This plant is an evergreen, perennial pteridophyte.","img":"images/996.jpg","thumb":"images/t/996.jpg","file":"Huperzia selago.jpg","ar":1.333,"py":"xiaoshanlan xsl","cr_by":"User:Tigerente","cr_lic":"CC BY-SA 3.0","cr_licurl":"http://creativecommons.org/licenses/by-sa/3.0/","habit":"蕨类","origin":null},{"id":997,"zh":"Selaginella selaginoides","en":"Selaginella selaginoides","sci":"Selaginella selaginoides","order_en":"Selaginellales","order_zh":"卷柏目","family_en":"Selaginellaceae","family_zh":"卷柏科","iucn":null,"langs":27,"desc_zh":null,"desc_en":"Selaginella selaginoides is a non-flowering plant of the spikemoss genus Selaginella with a wide distribution around the Northern Hemisphere. It resembles a moss in appearance but is a vascular plant belonging to the division Lycopodiophyta.","img":"images/997.jpg","thumb":"images/t/997.jpg","file":"Lesser Clubmoss Selaginella selaginoides (6177389884).jpg","ar":0.75,"py":"","cr_by":"Len Worthington","cr_lic":"CC BY-SA 2.0","cr_licurl":"https://creativecommons.org/licenses/by-sa/2.0","habit":"蕨类","origin":null},{"id":998,"zh":"Selaginella lepidophylla","en":"Selaginella lepidophylla","sci":"Selaginella lepidophylla","order_en":"Selaginellales","order_zh":"卷柏目","family_en":"Selaginellaceae","family_zh":"卷柏科","iucn":null,"langs":25,"desc_zh":null,"desc_en":"Selaginella lepidophylla (syn. Lycopodium lepidophyllum), also known as a resurrection plant and sometimes as the rose of Jericho (although distinct from the true rose of Jericho) is a species of desert plant in the spikemoss family (Selaginellaceae).","img":"images/998.jpg","thumb":"images/t/998.jpg","file":"Selaginella lepidophylla gruen.jpeg","ar":1.333,"py":"","cr_by":null,"cr_lic":"CC BY-SA 3.0","cr_licurl":"http://creativecommons.org/licenses/by-sa/3.0/","habit":"蕨类","origin":["北美洲"]},{"id":999,"zh":"泥炭藓","en":"Sphagnum palustre","sci":"Sphagnum palustre","order_en":"Sphagnales","order_zh":"泥炭藓目","family_en":"Sphagnaceae","family_zh":"泥炭藓科","iucn":null,"langs":24,"desc_zh":"泥炭藓（学名：Sphagnum palustre）为泥炭藓科泥炭藓属下的一个种。像这种类型的其他苔藓它可以吸收的水可达自身干重量的30倍，这归功于其弹性螺旋纤维。","desc_en":"Sphagnum palustre (Syn. Sphagnum cymbifolium), the prairie sphagnum or blunt-leaved bogmoss, is a species of peat moss from the genus Sphagnum, in the family Sphagnaceae.","img":"images/999.jpg","thumb":"images/t/999.jpg","file":"Sphagnum.palustre.-.lindsey.jpg","ar":1.506,"py":"nitanxian ntx","cr_by":"James K. Lindsey","cr_lic":"CC BY-SA 3.0","cr_licurl":"https://creativecommons.org/licenses/by-sa/3.0","habit":"苔藓","origin":null},{"id":1000,"zh":"大金发藓","en":"Polytrichum commune","sci":"Polytrichum commune","order_en":"Polytrichales","order_zh":"金发藓目","family_en":"Polytrichaceae","family_zh":"金发藓科","iucn":null,"langs":33,"desc_zh":"土马騣（学名：Polytrichum commune），又名金发苔，为土马騣科金发苔属下的一个种。呈直立状藉著假根固定在土壤内，为苔藓植物。","desc_en":"Polytrichum commune (also known as common haircap, great golden maidenhair, great goldilocks, common haircap moss, or common hair moss) is a species of moss found in many regions with high humidity and rainfall.","img":"images/1000.jpg","thumb":"images/t/1000.jpg","file":"Polytrichum commune.jpeg","ar":1.333,"py":"dajinfaxian djfx","cr_by":"Kristian Peters -- Fabelfroh 14:35, 21 October 2007 (UTC)","cr_lic":"CC BY-SA 3.0","cr_licurl":"http://creativecommons.org/licenses/by-sa/3.0/","habit":"苔藓","origin":["北美洲","大洋洲"]},{"id":1001,"zh":"地钱","en":"Marchantia polymorpha","sci":"Marchantia polymorpha","order_en":"Marchantiales","order_zh":"地钱目","family_en":"Marchantiaceae","family_zh":"地钱科","iucn":null,"langs":32,"desc_zh":"地钱（学名：Marchantia polymorpha）是地钱纲下的一种叶状苔类植物。 地钱广布全球各地，形态多变，包含三个亚种。 本种为雌雄异株，有雌雄株之分。","desc_en":"Marchantia polymorpha is a species of large thalloid liverwort in the class Marchantiopsida. M. polymorpha is highly variable in appearance and contains several subspecies. This species is dioicous, having separate male and female plants. M.","img":"images/1001.jpg","thumb":"images/t/1001.jpg","file":"Moos 5772.jpg","ar":1.333,"py":"diqian dq","cr_by":"Manfred Morgner ( ka-em-zwei-ein )","cr_lic":"CC BY-SA 3.0","cr_licurl":"http://creativecommons.org/licenses/by-sa/3.0/","habit":"苔藓","origin":null}];
